# ── Wczesna detekcja NO_COLOR / TERM=dumb ────────────────────────────────────
# Wykonywana PRZED importem ANSI-kodów — by uniknąć "śmieciowych" sekwencji
# w terminalach bez obsługi kolorów (CI, pipe, dumb terminal, NO_COLOR=1)

def _boot_detect_no_color() -> bool:
    """
    Zwraca True jeśli kolor ANSI powinien być wyłączony.
    Respektuje standard https://no-color.org
    """
    if os.environ.get("NO_COLOR"):            return True
    if os.environ.get("TERMINALX_NO_COLOR"): return True
    term = os.environ.get("TERM", "")
    if term == "dumb":                         return True
    # Jeśli stdout nie jest TTY (pipe/redirect) — brak kolorów
    if not sys.stdout.isatty():               return True
    return False

_ANSI_DISABLED: bool = _boot_detect_no_color()

# ── Wczesna detekcja trybu offline ───────────────────────────────────────────
