# ── Wczesna detekcja frozen exe (PyInstaller / zipapp) ───────────────────────
def _boot_is_frozen() -> bool:
    """Zwraca True jeśli uruchomiony jako skompilowany/spakowany exe."""
    return (
        getattr(sys, "frozen", False) or          # PyInstaller
        getattr(sys, "_MEIPASS", None) is not None or
        sys.executable.endswith((".pyz", ".exe"))
    )

_IS_FROZEN: bool = _boot_is_frozen()

# ── Wczesna detekcja --portable / --data w argv ───────────────────────────────
_BOOT_FORCE_PORTABLE: bool = "--portable" in sys.argv
_BOOT_DATA_OVERRIDE:  str  = ""
for _i, _arg in enumerate(sys.argv):
    if _arg == "--data" and _i + 1 < len(sys.argv):
        _BOOT_DATA_OVERRIDE = sys.argv[_i + 1]
        break
    if _arg.startswith("--data="):
        _BOOT_DATA_OVERRIDE = _arg[7:]
        break

