# ── ShellState — centralny stan shella ───────────────────────────────────────
class ShellState:
    """
    Singleton przechowujący cały mutowalny stan shella w jednym miejscu.
    Zamiast dziesiątek luźnych zmiennych globalnych — jedno źródło prawdy.
    Aliasy poniżej zachowują pełną kompatybilność wsteczną.
    """
    __slots__ = (
        "is_root", "shell_pid", "last_exit", "shell_vars",
        "current_theme", "status_enabled", "current_profile",
        "shell_verbose", "shell_debug", "active_log_level",
        "wizard_auto_triggered",
        "history", "aliases",
        "loaded_plugins", "plugin_meta",
        "builtins", "builtins_prefix_tuple",
        "active_session", "session_counter",
        "sched_running", "sched_counter", "sched_thread",
        "watch_running", "watch_counter", "watch_thread",
        "macro_recording", "macro_buffer",
        "split_mode", "split_output", "split_active_pane",
        "recovery_active", "recovery_reason",
        "server_token", "online_mode",
        "plugin_repos", "plugin_repo_cache",
        "log_enabled", "log_buffer", "log_max_bytes_cache",
        "completion_cache", "cfg_prompt_cache",
        "trust_db", "trust_key",
    )

    def __init__(self):
        self.is_root              = False
        self.shell_pid            = os.getpid()
        self.last_exit            = 0
        self.shell_vars           = {
            "PS1":  "TerminalX",
            "SHELL":"TerminalX",
            "HOME": str(Path.home()),
            "LANG": os.environ.get("LANG", "pl_PL.UTF-8"),
        }
        self.current_theme        = "dark"
        self.status_enabled       = True
        self.current_profile      = "default"
        self.shell_verbose        = False
        self.shell_debug          = False
        self.active_log_level     = "DEBUG"
        self.wizard_auto_triggered= False
        self.history              = []
        self.aliases              = {}
        self.loaded_plugins       = {}
        self.plugin_meta          = {}
        self.builtins             = {}
        self.builtins_prefix_tuple= ()
        self.active_session       = ""
        self.session_counter      = 0
        self.sched_running        = False
        self.sched_counter        = 0
        self.sched_thread         = None
        self.watch_running        = False
        self.watch_counter        = 0
        self.watch_thread         = None
        self.macro_recording      = None
        self.macro_buffer         = []
        self.split_mode           = ""
        self.split_output         = []
        self.split_active_pane    = 0
        self.recovery_active      = False
        self.recovery_reason      = ""
        self.server_token         = ""
        self.online_mode          = False
        self.plugin_repos         = []
        self.plugin_repo_cache    = {}
        self.log_enabled          = not _BOOT_LOG_OFF
        self.log_buffer           = []
        self.log_max_bytes_cache  = -1
        self.completion_cache     = []
        self.cfg_prompt_cache     = {}
        self.trust_db             = {}
        self.trust_key            = b""


