# Bufor logów — zbiera wpisy, flush przy starcie/zamknięciu lub co _LOG_FLUSH_EVERY
_BUILTINS_PREFIX_TUPLE: tuple = _STATE.builtins_prefix_tuple
_RE_VAR_ASSIGN   = re.compile(r'^([A-Za-z_][A-Za-z0-9_]*)=(.*)$')  # hot-loop regex
_RE_CTRL_W       = re.compile(r'\S+\s*$')            # Ctrl+W w fuzzy search
_RE_DROP_SPLIT   = re.compile(r'\s{2,}|\t')              # drop daemon path split
_RE_LOG_LINE     = re.compile(r'^\[(\d{4}-\d{2}-\d{2} \d{2}:\d{2}:\d{2})\] \[(\w+)\] (.*)$')
_RE_PLUGIN_META  = re.compile(           # parsowanie metadanych pluginu (jeden pass)
    r'(?:"version"\s*:\s*"(?P<version>[^"]+)")' +
    r'|(?:"description"\s*:\s*"(?P<description>[^"]+)")' +
    r'|(?:"author"\s*:\s*"(?P<author>[^"]+)")'
)
# Skompilowane patterny dla JSON/JQ coloryzacji (używane per-linia w pętlach)
_RE_JSON_KEY    = re.compile(r'("(?:[^"\\]|\\.)*")(\s*:)')
_RE_JSON_STR    = re.compile(r'(?<!:)(\s)("(?:[^"\\]|\\.)*")')
_RE_JSON_NUM    = re.compile(r':\s*(-?\d+\.?\d*([eE][+-]?\d+)?)')
_RE_JSON_BOOL   = re.compile(r'(null|true|false)')
_RE_JSON_PATH   = re.compile(r'[.\[\]]')
_RE_JQ_KEY      = re.compile(r'^(\s*)("(?:[^"\\]|\\.)*")(\s*:)(.*)')
_RE_JQ_NUM      = re.compile(r':\s*(-?\d+\.?\d*)')
_LOG_BUFFER: list[str] = _STATE.log_buffer
_LOG_FLUSH_EVERY = 10          # flush co N wpisów CMD
_LOG_FLUSH_LEVELS = {"ERROR", "SECURITY"}  # natychmiastowy flush

_LOG_MAX_BYTES_CACHE: int = _STATE.log_max_bytes_cache

def _log_flush():
    """Zapisuje bufor logów do pliku jednym write()."""
    if not _LOG_BUFFER:
        return
    pending = _LOG_BUFFER[:]
    _STATE.log_buffer = []
    try:
        if _LOG_MAX_BYTES_CACHE < 0:
            _STATE.log_max_bytes_cache = int(cfg("log_max_mb", 5)) * 1024 * 1024
        if _LOG_MAX_BYTES_CACHE > 0 and LOG_FILE.exists():
            if LOG_FILE.stat().st_size > _LOG_MAX_BYTES_CACHE:
                backup = LOG_FILE.with_suffix(".log.1")
                try:
                    LOG_FILE.rename(backup)
                except Exception:  # ignorowane celowo
                    pass
        with LOG_FILE.open("a", encoding="utf-8") as f:
            f.write("".join(pending))
    except Exception:
        pass  # błąd logu nie może przerwać pracy shella

def _log(level: str, msg: str):
    """Buforowany zapis do lokalnego pliku logu (nigdy nie wysyła danych)."""
    if not _LOG_ENABLED:
        return
    if level == "CMD" and not cfg("log_commands", True):
        return
    ts = datetime.datetime.now().strftime("%Y-%m-%d %H:%M:%S")
    _LOG_BUFFER.append(f"[{ts}] [{level}] {msg}\n")
    # Natychmiastowy flush dla błędów i zdarzeń bezpieczeństwa
    if level in _LOG_FLUSH_LEVELS or len(_LOG_BUFFER) >= _LOG_FLUSH_EVERY:
        _log_flush()

def log_error(msg: str):    _log("ERROR",    msg)
def log_info(msg: str):     _log("INFO",     msg)
def log_cmd(cmd: str):      _log("CMD",      cmd)
def log_security(msg: str): _log("SECURITY", msg)

# CRASHLOG
#   Automatyczny zapis raportu bledu do CRASHLOG_FILE
#   przy nieobsluzonych wyjatkach oraz awariach modulow.
#
#   API:
#     write_crashlog(exc, context, cmd)  — zapis raportu
#     cmd_crashlog(args)                 — komenda 'crashlog'
#
#   Format raportu:
#     [timestamp] wersja, platforma, komenda
#     Typ bledu + czytelny komunikat
#     Traceback (ostatnie 20 ramek)
#     Hint co zrobic dalej

import traceback

# Limit historii crashlogow (najnowsze N wpisow)
_CRASHLOG_MAX_ENTRIES = 50
_CRASHLOG_MAX_KB      = 512   # rotacja jesli plik > 512 KB

def write_crashlog(exc: BaseException,
                   context: str = "",
                   cmd:     str = "") -> Path:
    """
    Zapisuje raport bledu do CRASHLOG_FILE.
    Zwraca sciezke do pliku.
    Nigdy nie rzuca wyjatku — blad crashlogu jest ignorowany cichutko.
    """
    try:
        # Rotacja crashlogu
        if (CRASHLOG_FILE.exists()
                and CRASHLOG_FILE.stat().st_size > _CRASHLOG_MAX_KB * 1024):
            bak = CRASHLOG_FILE.with_suffix(".txt.1")
            try:
                CRASHLOG_FILE.rename(bak)
            except Exception:  # ignorowane celowo
                pass

        ts       = datetime.datetime.now().strftime("%Y-%m-%d %H:%M:%S")
        exc_type = type(exc).__name__
        exc_msg  = str(exc)

        # Pobierz traceback jako tekst (max 20 ostatnich ramek)
        tb_lines = traceback.format_exception(type(exc), exc, exc.__traceback__)
        tb_text  = "".join(tb_lines[-20:]).strip()

        # Czytelna porada dla znanych typow bledow
        _hints = {
            "FileNotFoundError":  "Sprawdz sciezke pliku lub nazwe komendy.",
            "PermissionError":    "Uruchom z sudo lub sprawdz uprawnienia.",
            "UnicodeDecodeError": "Plik moze nie byc w kodowaniu UTF-8.",
            "ModuleNotFoundError":"Brakujacy modul — sprobuj pip install.",
            "RecursionError":     "Zbyt gleboka rekurencja — sprawdz pluginy.",
            "MemoryError":        "Brak pamieci RAM — zamknij inne programy.",
            "KeyboardInterrupt":  "Przerwano przez uzytkownika (Ctrl+C).",
            "SystemExit":         "Shell zakonczyl dzialanie.",
            "JSONDecodeError":    "Uszkodzony plik konfiguracyjny — sprawdz JSON.",
            "OSError":            "Blad systemu operacyjnego — sprawdz dysk/uprawnienia.",
            "ValueError":         "Nieprawidlowa wartosc — sprawdz argumenty komendy.",
        }
        hint = _hints.get(exc_type, "Wyslij ten raport do autora lub sprawdz logi.")

        # Zbierz kontekst srodowiska (bez danych wrazliwych)
        try:
            _ver   = SHELL_VERSION  # type: ignore[name-defined]
        except NameError:
            _ver   = "?"
        try:
            _cwd   = str(Path.cwd())
        except Exception:
            _cwd   = "?"

        sep = "=" * 72
        report = (
            f"\n{sep}\n"
            f"TERMINALX CRASHLOG  [{ts}]\n"
            f"{sep}\n"
            f"Wersja    : TerminalX v{_ver}\n"
            f"Platforma : {sys.platform}  Python {sys.version.split()[0]}\n"
            f"Katalog   : {_cwd}\n"
            f"Kontekst  : {context or '(brak)'}\n"
            f"Komenda   : {cmd or '(brak)'}\n"
            f"{'-' * 72}\n"
            f"Typ bledu : {exc_type}\n"
            f"Komunikat : {exc_msg}\n"
            f"Porada    : {hint}\n"
            f"{'-' * 72}\n"
            f"Traceback (ostatnie ramki):\n"
            f"{tb_text}\n"
            f"{sep}\n"
        )

        with CRASHLOG_FILE.open("a", encoding="utf-8") as f:
            f.write(report)

        return CRASHLOG_FILE

    except Exception:
        # crashlog nie moze sam sie posypac
        return CRASHLOG_FILE

def _crashlog_user_msg(exc: BaseException, context: str = "", cmd: str = "") -> None:
    """
    Wyswietla uzytkownikowi czytelny komunikat o awarii
    i informuje gdzie zapisano raport.
    """
    exc_type = type(exc).__name__
    exc_msg  = str(exc) or "(brak komunikatu)"
    path     = write_crashlog(exc, context=context, cmd=cmd)

    # Czytelna linia bledu (bez rawego traceback)
    _human = {
        "FileNotFoundError":   "Nie znaleziono pliku lub komendy",
        "PermissionError":     "Brak uprawnien dostepu",
        "UnicodeDecodeError":  "Blad kodowania pliku (nie UTF-8)",
        "ModuleNotFoundError": "Brakujacy modul Pythona",
        "RecursionError":      "Przepelnienie stosu wywolan",
        "MemoryError":         "Brak pamieci RAM",
        "JSONDecodeError":     "Uszkodzony plik JSON",
        "OSError":             "Blad systemu plikow lub OS",
        "ValueError":          "Nieprawidlowa wartosc argumentu",
        "TypeError":           "Nieoczekiwany typ danych",
        "AttributeError":      "Brak atrybutu obiektu",
        "ImportError":         "Blad importu modulu",
        "ZeroDivisionError":   "Dzielenie przez zero",
    }
    human_msg = _human.get(exc_type, exc_type)

    # Drukuj czytelny komunikat, nie surowy traceback
    print(f"\n  {C.ERROR}✖ AWARIA{C.RESET}  {human_msg}")  # type: ignore[name-defined]
    print(f"  {C.DIM}  Szczegoly : {exc_msg[:120]}{C.RESET}")  # type: ignore[name-defined]
    if context:
        print(f"  {C.DIM}  Kontekst  : {context}{C.RESET}")  # type: ignore[name-defined]
    print(f"  {C.DIM}  Raport    : {path}{C.RESET}")  # type: ignore[name-defined]
    print(f"  {C.DIM}  Podglad   : crashlog  |  crashlog clear{C.RESET}\n")  # type: ignore[name-defined]
