# NETWORK / ONLINE-OFFLINE MODE
#   Tryb offline  — bez dostepu do sieci (domyslnie wykrywany automatycznie)
#   Tryb online   — dostep do sieci; umozliwia pkg install --url, wget itp.
#   Komenda: mode             — pokaz biezacy tryb
#            mode online      — przelacz na online  (wymaga sieci)
#            mode offline     — przelacz na offline  (wymaga sieci)
#            mode check       — ponownie sprawdz polaczenie

_ONLINE_MODE: bool = _STATE.online_mode

_NETWORK_TEST_HOSTS = [
    ("8.8.8.8",    53),   # Google DNS
    ("1.1.1.1",    53),   # Cloudflare DNS
    ("9.9.9.9",    53),   # Quad9 DNS
]

def _detect_network(timeout: float = 2.0) -> bool:
    """
    Sprawdza dostepnosc sieci probujac TCP do znanych hostow DNS.
    Nie wysyla zadnych danych — tylko nawiazuje i natychmiast zamyka polaczenie.
    Zwraca True jesli co najmniej jeden host jest osiagalny.
    """
    import socket as _sock_test
    for host, port in _NETWORK_TEST_HOSTS:
        try:
            s = _sock_test.socket(_sock_test.AF_INET, _sock_test.SOCK_STREAM)
            s.settimeout(timeout)
            err = s.connect_ex((host, port))
            s.close()
            if err == 0:
                return True
        except Exception:  # ignorowane celowo
            pass
    return False

def network_init():
    """
    Wykrywa tryb sieci przy starcie shella i ustawia _ONLINE_MODE.
    Jeśli TERMINALX_OFFLINE=1 — pomija detekcję i ustawia offline.
    """
    if _BOOT_FORCE_OFFLINE:
        _STATE.online_mode = False
        return
    _STATE.online_mode = _detect_network()

def is_online() -> bool:
    """Zwraca True jesli shell jest w trybie online."""
    return _ONLINE_MODE

