_CURRENT_THEME = _STATE.current_theme

class C:
    """
    Klasa kolorow — dynamicznie pobiera wartosci z aktywnego motywu.
    Uzycie: C.PROMPT, C.ERROR itp. — zawsze zwraca kolor biezacego motywu.
    Fallback: nieznany atrybut → RESET (nigdy nie rzuca AttributeError).
    Jeśli _ANSI_DISABLED=True (NO_COLOR / TERM=dumb / stdout pipe) — zwraca ''.
    """
    def __class_getitem__(cls, key):
        if _ANSI_DISABLED:
            return ""
        return _THEMES[_CURRENT_THEME].get(key, "\033[0m")

    def __init_subclass__(cls, **kw):
        super().__init_subclass__(**kw)

    @classmethod
    def __getattr__(cls, key):           # fallback dla nieznanych C.XYZ
        if _ANSI_DISABLED:
            return ""
        return _THEMES.get(_CURRENT_THEME, {}).get(key, "\033[0m")

    @classmethod
    def _apply(cls):
        """Aktualizuje atrybuty klasy z biezacego motywu (lub puste przy NO_COLOR)."""
        if _ANSI_DISABLED:
            # Wyczyść wszystkie atrybuty kolorów
            t = _THEMES.get(_CURRENT_THEME, {})
            for k in t:
                setattr(cls, k, "")
            return
        t = _THEMES.get(_CURRENT_THEME, _THEMES.get("dark", {}))
        for k, v in t.items():
            setattr(cls, k, v)

# Inicjalne przypisanie atrybutow z motywu dark
C._apply()

