# Aktywna konfiguracja (wypelniana przez load_config)
_CONFIG: dict = {}

# Wykrywanie aktywnego pliku konfiguracyjnego
# Priorytet: .json > .yaml > .yml > .ini
def _detect_config_file() -> Path:
    """Zwraca istniejacy plik konfiguracyjny lub domyslny JSON."""
    for ext in (".json", ".yaml", ".yml", ".ini"):
        candidate = CONFIG_FILE.parent / (CONFIG_FILE.stem + ext)
        if candidate.exists():
            return candidate
    return CONFIG_FILE   # domyslny .json (moze nie istnieje — zostanie stworzony)

def _active_config_file() -> Path:
    return _detect_config_file()

# ── Mini-parser YAML (stdlib-only, bez pyyaml) ───────────────
# Obsluguje prosty YAML: klucz: wartosc, listy - item, komentarze #
# Wystarczajacy dla pliku konfiguracyjnego TerminalXa.

def _parse_yaml_value(raw: str):
    """Konwertuje string YAML na Python: bool, int, float, str, None."""
    s = raw.strip().strip('"\'')
    if s.lower() in ("true", "yes"):   return True
    if s.lower() in ("false", "no"):   return False
    if s.lower() in ("null", "~", ""): return None
    try: return int(s)
    except ValueError: pass
    try: return float(s)
    except ValueError: pass
    return s   # string

def _parse_yaml(text: str) -> dict:
    """
    Mini-parser YAML -> dict.
    Obsluguje:
      klucz: wartosc
      klucz:
        - item1
        - item2
      # komentarze
    """
    result  = {}
    current_key  = None
    current_list = None

    for raw_line in text.splitlines():
        # Usun komentarze inline i trailing whitespace
        line = raw_line.split("#")[0].rstrip() if "#" in raw_line else raw_line.rstrip()
        if not line:
            continue

        # Element listy
        if line.lstrip().startswith("- "):
            if current_key is not None:
                if current_list is None:
                    current_list = []
                    result[current_key] = current_list
                current_list.append(_parse_yaml_value(line.lstrip()[2:]))
            continue

        # Klucz: wartosc
        if ":" in line:
            current_list = None   # koniec poprzedniej listy
            key, _, val_raw = line.partition(":")
            key = key.strip()
            val_raw = val_raw.strip()
            if val_raw:
                result[key] = _parse_yaml_value(val_raw)
                current_key = key
            else:
                # Klucz bez wartosci — moze nastapic lista
                result[key] = None
                current_key = key

    return result

def _dump_yaml(data: dict) -> str:
    """Serializuje dict do prostego YAML."""
    lines = ["# TerminalX v16.0 — konfiguracja (format YAML)",
             "# Edytuj recznie lub przez: config set <klucz> <wartosc>", ""]
    for k, v in data.items():
        if isinstance(v, bool):
            lines.append(f"{k}: {'true' if v else 'false'}")
        elif isinstance(v, list):
            lines.append(f"{k}:")
            for item in v:
                lines.append(f"  - {item}")
        elif isinstance(v, str) and (" " in v or ":" in v or not v):
            lines.append(f'{k}: "{v}"')
        elif v is None:
            lines.append(f"{k}: null")
        else:
            lines.append(f"{k}: {v}")
    return "\n".join(lines) + "\n"

# ── INI parser / writer (stdlib configparser) ────────────────

def _parse_ini(text: str) -> dict:
    """Parsuje plik INI (sekcja [TerminalX]) do dict."""
    cp = _get_configparser().ConfigParser()
    cp.read_string(text)
    result = {}
    section = "TerminalX"
    if cp.has_section(section):
        for k, v in cp.items(section):
            result[k] = _parse_yaml_value(v)   # reuse konwerter
    elif cp.has_section("DEFAULT") or cp.defaults():
        for k, v in cp.defaults().items():
            result[k] = _parse_yaml_value(v)
    return result

def _dump_ini(data: dict) -> str:
    """Serializuje dict do INI (sekcja [TerminalX])."""
    cp = _get_configparser().ConfigParser()
    cp["TerminalX"] = {}
    for k, v in data.items():
        if isinstance(v, list):
            cp["TerminalX"][k] = json.dumps(v)
        elif isinstance(v, bool):
            cp["TerminalX"][k] = "true" if v else "false"
        else:
            cp["TerminalX"][k] = str(v) if v is not None else ""
    import io
    buf = io.StringIO()
    buf.write("# TerminalX v15.0 — konfiguracja (format INI)\n")
    buf.write("# Edytuj recznie lub przez: config set <klucz> <wartosc>\n\n")
    cp.write(buf)
    return buf.getvalue()

# ── Glowne funkcje load/save (wykrywa format automatycznie) ──

def _read_config_file(path: Path) -> dict:
    """Wczytuje plik konfiguracyjny wg rozszerzenia."""
    text = path.read_text(encoding="utf-8")
    ext  = path.suffix.lower()
    if ext == ".json":
        return json.loads(text)
    elif ext in (".yaml", ".yml"):
        return _parse_yaml(text)
    elif ext == ".ini":
        return _parse_ini(text)
    else:
        # Sprobuj JSON jako fallback
        return json.loads(text)

def _write_config_file(path: Path, data: dict):
    """Zapisuje dict do pliku wg rozszerzenia."""
    ext = path.suffix.lower()
    if ext == ".json":
        text = json.dumps(data, indent=2, ensure_ascii=False)
    elif ext in (".yaml", ".yml"):
        text = _dump_yaml(data)
    elif ext == ".ini":
        text = _dump_ini(data)
    else:
        text = json.dumps(data, indent=2, ensure_ascii=False)
    path.write_text(text, encoding="utf-8")

def cfg(key: str, default=None):
    """Pobierz wartosc z konfiguracji. Fallback do _CONFIG_DEFAULTS, potem default."""
    if key in _CONFIG:
        return _CONFIG[key]
    return _CONFIG_DEFAULTS.get(key, default)

# Cache wartości konfiguracji używanych w hot-loop
_CFG_PROMPT_CACHE: dict = _STATE.cfg_prompt_cache

def cfg_set(key: str, value, save: bool = True):
    """Ustaw wartosc w konfiguracji i opcjonalnie zapisz do pliku."""
    _CONFIG[key] = value
    _CFG_PROMPT_CACHE.clear()  # unieważnij cache promptu
    if key == "log_max_mb":
        _STATE.log_max_bytes_cache = -1  # unieważnij cache log_max_mb
    if save:
        save_config()

def load_config() -> dict:
    """
    Wczytuje plik konfiguracyjny (JSON / YAML / INI).
    Wykrywa format automatycznie wg rozszerzenia.
    Jesli brak pliku — tworzy ~/.terminalx.json z domyslna konfiguracja.
    """
    global _CONFIG
    active = _active_config_file()
    if active.exists():
        try:
            data   = _read_config_file(active)
            merged = {**_CONFIG_DEFAULTS, **data}
            _CONFIG = merged
            return _CONFIG
        except Exception as e:
            backup = active.with_suffix(active.suffix + ".bak")
            try:
                active.rename(backup)
            except Exception:  # ignorowane celowo
                pass
            _log("ERROR", f"Uszkodzony config ({active.name}): {e}  backup: {backup}")

    _CONFIG = dict(_CONFIG_DEFAULTS)
    save_config()
    return _CONFIG

def save_config():
    """Zapisuje konfiguracje do aktywnego pliku (zachowuje format)."""
    try:
        active = _active_config_file()
        _write_config_file(active, _CONFIG)
    except Exception as e:
        _log("ERROR", f"save_config: {e}")

def config_apply():
    """
    Stosuje ustawienia z _CONFIG do zmiennych globalnych shella.
    Wywolywana po load_config() i po kazdej zmianie przez 'config set'.
    """

    # Motyw
    theme = cfg("theme", "dark")
    if theme in _THEMES:
        _STATE.current_theme = theme
        C._apply()

    # Pasek statusu
    _STATE.status_enabled = bool(cfg("status_bar", True))

    # Log
    _STATE.log_enabled = bool(cfg("log_enabled", True))

    # Historia max
    # (stosowana przy zapisie historii)


