# COMMAND_SYSTEM

class CommandDef:
    """
    Deskryptor komendy. Przechowuje funkcje, opis, aliasy, podkomendy i flagi.
    Rejestruje sie w BUILTINS automatycznie przez dekorator @command().
    """
    def __init__(self, func, name: str, description: str = "",
                 aliases: list = None, flags: list = None):
        self.func        = func
        self.name        = name
        self.description = description
        self.aliases     = aliases or []
        self.flags       = flags or []          # lista stringow, np. ["-r", "-i"]
        self.subcommands: dict = {}             # name -> CommandDef

    def __call__(self, args):
        return self.func(args)

    def subcommand(self, name: str, description: str = "", flags: list = None):
        """Dekorator do rejestrowania podkomend."""
        def decorator(func):
            sub = CommandDef(func, name, description, flags=flags)
            self.subcommands[name] = sub
            return sub
        return decorator

    def usage(self) -> str:
        lines = []
        lines.append(f"{C.BOLD}{self.name}{C.RESET}  —  {self.description}")
        if self.aliases:
            lines.append(f"  Aliasy   : {', '.join(self.aliases)}")
        if self.flags:
            lines.append(f"  Flagi    : {' '.join(self.flags)}")
        if self.subcommands:
            lines.append(f"  Podkomendy:")
            for sname, sub in self.subcommands.items():
                lines.append(f"    {C.INFO}{sname:12}{C.RESET} {sub.description}")
        if self.func.__doc__:
            doc = textwrap.dedent(self.func.__doc__).strip()
            lines.append("")
            for dline in doc.splitlines():
                lines.append("  " + dline)
        return "\n".join(lines)

def command(name: str, description: str = "",
            aliases: list = None, flags: list = None):
    """
    Dekorator rejestrujacy funkcje jako komende shella.

    Przyklad:
        @command("hello", "Przywitaj uzytkownika", aliases=["hi"], flags=["-u"])
        def cmd_hello(args):
            ...
    """
    def decorator(func):
        cdef = CommandDef(func, name, description, aliases=aliases, flags=flags)
        BUILTINS[name] = cdef
        for alias in (aliases or []):
            BUILTINS[alias] = cdef
        _STATE.builtins_prefix_tuple = tuple(BUILTINS.keys())
        return cdef
    return decorator

def dispatch(cmd: str, args: list):
    """Wywoluje komende lub jej podkomende, jesli podana."""
    cdef = BUILTINS.get(cmd)
    if cdef is None:
        return False

    # Hooki before_cmd — jesli zwroci False, przerwij wykonanie
    for _hfn in list(PLUGIN_HOOKS.get("before_cmd", [])):
        try:
            if _hfn(cmd, args) is False:
                return True
        except Exception:  # ignorowane celowo
            pass

    # Jesli pierwszy arg to znana podkomenda — przekaz do niej
    _ec = 0
    try:
        if args and args[0] in cdef.subcommands:
            sub = cdef.subcommands[args[0]]
            sub(args[1:])
        else:
            cdef(args)
    except Exception:
        _ec = 1
        raise
    finally:
        for _hfn in list(PLUGIN_HOOKS.get("after_cmd", [])):
            try:    _hfn(cmd, args, _ec)
            except Exception:
                pass  # ignorowane celowo

    return True

# UTILS

def is_windows():
    return os.name == "nt"

def clear_screen():
    os.system("cls" if is_windows() else "clear")

def print_error(msg: str, hint: str = ""):
    """Czytelny blad z opcjonalna podpowiedzia co zrobic dalej."""
    print(f"{C.ERROR}✖ BŁĄD{C.RESET}  {msg}")
    if hint:
        print(f"  {C.DIM}↳ {hint}{C.RESET}")
    log_error(msg)

def print_warn(msg: str, hint: str = ""):
    """Ostrzezenie — nie przerywa dzialania."""
    print(f"{C.WARN}⚠ UWAGA{C.RESET}  {msg}")
    if hint:
        print(f"  {C.DIM}↳ {hint}{C.RESET}")

def print_hint(hint: str):
    """Sama podpowiedz (bez tagu bledu)."""
    print(f"  {C.DIM}↳ {hint}{C.RESET}")

def print_info(msg: str):
    """Komunikat informacyjny (neutralny)."""
    print(f"{C.INFO}ℹ INFO{C.RESET}   {msg}")

def print_ok(msg: str):
    """Potwierdzenie sukcesu operacji."""
    print(f"{C.OK}✔ OK{C.RESET}     {msg}")
    log_info(f"OK: {msg}")

def smart_error(exc: Exception, context: str = "", path: str = ""):
    """
    Zamienia wyjatki systemowe na czytelne komunikaty po polsku z podpowiedzia.
    """
    e = exc
    name = type(e).__name__
    p    = f" '{path}'" if path else ""

    if isinstance(e, FileNotFoundError):
        if path:
            print_error(f"Nie znaleziono{p}",
                        f"Sprawdz czy sciezka istnieje: ls {path!r}")
        else:
            print_error(f"Nie znaleziono pliku/programu",
                        "Sprawdz nazwe i sciezke, uzyj TAB do uzupelniania")
    elif isinstance(e, PermissionError):
        print_error(f"Brak uprawnien{p}",
                    "Sprobuj z sudo lub sprawdz prawa dostepu: ls -l")
    elif isinstance(e, IsADirectoryError):
        print_error(f"{p} jest katalogiem, nie plikiem",
                    "Uzyj rmdir aby usunac katalog lub cat -r dla rekurencji")
    elif isinstance(e, NotADirectoryError):
        print_error(f"{p} nie jest katalogiem",
                    "Sprawdz sciezke — moze to plik, nie katalog")
    elif isinstance(e, FileExistsError):
        print_error(f"Plik/katalog juz istnieje{p}",
                    "Uzyj innej nazwy lub usun istniejacy plik najpierw")
    elif isinstance(e, OSError) and hasattr(e, 'errno'):
        import errno as _errno
        codes = {
            _errno.ENOSPC: ("Brak miejsca na dysku", "Zwolnij miejsce lub zmien dysk"),
            _errno.EROFS:  ("System plikow tylko do odczytu", "Sprawdz montowanie lub uprawnienia"),
            _errno.EACCES: ("Odmowa dostepu", "Sprobuj z sudo lub zmien uprawnienia"),
            _errno.ENOTEMPTY: (f"Katalog{p} nie jest pusty", "Uzyj rmdir (usuwa rekurencyjnie)"),
            _errno.ENAMETOOLONG: ("Nazwa pliku zbyt dluga", "Skroc nazwe pliku"),
        }
        msg, hint = codes.get(e.errno, (str(e), ""))
        print_error(msg, hint)
    elif isinstance(e, UnicodeDecodeError):
        print_error(f"Nie mozna odczytac pliku{p} jako UTF-8",
                    "Sprobuj: cat -A (tryb raw) lub sprawdz kodowanie pliku")
    elif isinstance(e, KeyboardInterrupt):
        print_warn("Przerwano przez uzytkownika (Ctrl+C)")
    else:
        # Fallback — pokaz typ bledu + tresc + zapisz crashlog
        print_error(f"[{name}] {e}",
                    f"Kontekst: {context}" if context else "")
        write_crashlog(exc, context=context)

def terminal_width() -> int:
    try:
        cols = os.get_terminal_size().columns
        return max(40, cols)   # nigdy nie zwracaj mniej niż 40 — zabezpieczenie przed ujemnymi wynikami
    except Exception:
        return 80

# UI_BOX
#
#  Spójny system ramek z 5 stylami wizualnymi:
#    single  — klasyczny Unicode ┌─┐  (domyślny)
#    round   — zaokraglone narozniki ╭─╮
#    double  — podwojne linie ╔═╗
#    heavy   — grube linie ┏━┓
#    ascii   — bez Unicode +--+  (dla terminali bez UTF-8)
#
#  Styl aktywny: cfg("box_style", "single")
#  Zmiana: config set box_style round

# Definicje zestawów znaków dla każdego stylu ramki
# Klucze: TL TR BL BR H V SH SEP_L SEP_R SEP_H
#   TL/TR/BL/BR — narożniki, H — pozioma, V — pionowa
#   SEP_L/R — lewy/prawy connector separatora, SEP_H — pozioma separatora
_BOX_CHARS: dict[str, dict[str, str]] = {
    "single": {"TL":"┌","TR":"┐","BL":"└","BR":"┘",
               "H":"─","V":"│","SEP_L":"├","SEP_R":"┤","SEP_H":"─"},
    "round":  {"TL":"╭","TR":"╮","BL":"╰","BR":"╯",
               "H":"─","V":"│","SEP_L":"├","SEP_R":"┤","SEP_H":"─"},
    "double": {"TL":"╔","TR":"╗","BL":"╚","BR":"╝",
               "H":"═","V":"║","SEP_L":"╠","SEP_R":"╣","SEP_H":"═"},
    "heavy":  {"TL":"┏","TR":"┓","BL":"┗","BR":"┛",
               "H":"━","V":"┃","SEP_L":"┣","SEP_R":"┫","SEP_H":"━"},
    "ascii":  {"TL":"+","TR":"+","BL":"+","BR":"+",
               "H":"-","V":"|","SEP_L":"+","SEP_R":"+","SEP_H":"-"},
}

def _bc() -> dict[str, str]:
    """Zwraca aktywny zestaw znaków ramki (wg config)."""
    style = cfg("box_style", "single") if "_CONFIG" in globals() else "single"
    return _BOX_CHARS.get(style, _BOX_CHARS["single"])

def box_top(title: str = "", width: int = 0, color: str = "") -> str:
    """Górna krawędź ramki z opcjonalnym tytułem."""
    w     = width or terminal_width() - 2
    color = color or C.DIM
    c     = _bc()
    if title:
        title_str  = f" {title} "
        title_vis  = _visual_width(title_str)   # prawdziwa szerokość z emoji
        fill = max(2, w - 2 - title_vis)
        bar  = c["H"] * 2 + title_str + c["H"] * fill
        # Upewnij się że bar ma dokładnie w kolumn wizualnych
        bar_vis = _visual_width(bar)
        if bar_vis > w:
            bar = bar[:w]   # przytnij (proste zabezpieczenie)
        elif bar_vis < w:
            bar += c["H"] * (w - bar_vis)
    else:
        bar = c["H"] * w
    return f"{color}{c['TL']}{bar}{c['TR']}{C.RESET}"

def box_bottom(width: int = 0, color: str = "") -> str:
    """Dolna krawędź ramki."""
    w     = width or terminal_width() - 2
    color = color or C.DIM
    c     = _bc()
    return f"{color}{c['BL']}{c['H'] * w}{c['BR']}{C.RESET}"

def _visual_width(s: str) -> int:
    """Zwraca wizualną szerokość stringa w kolumnach terminala.
    Emoji i znaki CJK zajmują 2 kolumny, zwykłe ASCII — 1.
    Kody ANSI są ignorowane (szerokość 0).
    Obsługuje variation selector U+FE0F (wymusza emoji = 2 kol).
    """
    import unicodedata as _ud
    clean = re.sub(r"\033\[[0-9;]*m", "", s)
    width = 0
    chars = list(clean)
    i = 0
    while i < len(chars):
        ch = chars[i]
        cp = ord(ch)

        # Variation selector FE0F — wymusza emoji presentation (2 kol).
        # Poprzedni znak mógł być liczony jako 1 (eaw=N/A) → dokładamy 1.
        if cp == 0xFE0F:
            width += 1
            i += 1
            continue

        # Zero-width: łączniki, ZWJ, znaki kontrolne
        if cp < 32 or (0x7F <= cp <= 0x9F) or cp in (0x200B, 0x200C, 0x200D, 0xFEFF):
            i += 1
            continue

        eaw = _ud.east_asian_width(ch)
        if eaw in ('W', 'F'):
            # Wide / Fullwidth — zawsze 2 kolumny
            width += 2
        elif eaw == 'A':
            # Ambiguous — emoji bloki traktuj jako 2, resztę jako 1
            if (0x2300 <= cp <= 0x27BF or   # Misc Technical / Dingbats (❓=0x2753)
                0x2B00 <= cp <= 0x2BFF or   # Misc Symbols & Arrows
                0x25A0 <= cp <= 0x25FF):    # Geometric Shapes (▶=0x25B6)
                width += 2
            else:
                width += 1
        else:
            # Narrow / Neutral / Halfwidth → 1
            width += 1
        i += 1
    return width

def box_row(text: str, width: int = 0, color: str = "", fill: bool = True) -> str:
    """Wiersz wewnątrz ramki.
    Jeśli tekst wizualny jest dłuższy niż dostępna przestrzeń,
    zostaje ucięty z '…' — zapobiega zawijaniu linii przez terminal
    które niszczy ciągłość lewej krawędzi ramki.
    Poprawnie obsługuje emoji i znaki wide (2 kolumny).
    """
    w       = width or terminal_width() - 2
    color   = color or C.DIM
    c       = _bc()
    visible = re.sub(r"\033\[[0-9;]*m", "", text)
    inner_w = w - 2   # dostępna szerokość między | a |  (odejmujemy 2 spacje-bordera)
    vis_w   = _visual_width(visible)   # prawdziwa szerokość z uwzględnieniem emoji

    if vis_w > inner_w:
        # Utnij tekst razem z kodami ANSI — rekonstruuj znak po znaku
        truncated = ""
        vis_count = 0
        i = 0
        while i < len(text):
            if text[i] == "\033":
                # Pochłoń cały kod ANSI
                j = i + 1
                while j < len(text) and text[j] not in "m":
                    j += 1
                ansi_seq = text[i:j+1]
                truncated += ansi_seq
                i = j + 1
            else:
                ch_w = _visual_width(text[i])
                if vis_count + ch_w > inner_w - 1:
                    truncated += "…"
                    break
                truncated += text[i]
                vis_count += ch_w
                i += 1
        truncated += C.RESET   # zamknij wszystkie otwarte sekwencje
        visible_new = re.sub(r"\033\[[0-9;]*m", "", truncated)
        pad = max(0, inner_w - _visual_width(visible_new))
        return f"{color}{c['V']}{C.RESET} {truncated}{' ' * pad} {color}{c['V']}{C.RESET}"

    pad = max(0, inner_w - vis_w) if fill else 0
    return f"{color}{c['V']}{C.RESET} {text}{' ' * pad} {color}{c['V']}{C.RESET}"

def box_sep(width: int = 0, color: str = "") -> str:
    """Separator poziomy wewnątrz ramki."""
    w     = width or terminal_width() - 2
    color = color or C.DIM
    c     = _bc()
    return f"{color}{c['SEP_L']}{c['SEP_H'] * w}{c['SEP_R']}{C.RESET}"

def section_header(title: str, color: str = "", width: int = 0) -> str:
    """Jednolinijkowy nagłówek sekcji bez ramki."""
    w     = width or terminal_width()
    color = color or C.BOLD
    c     = _bc()
    bar   = c["H"] * max(0, w - _visual_width(title) - 3)
    return f"{color} {title} {C.DIM}{bar}{C.RESET}"

def kv_row(key: str, value: str, key_w: int = 16,
           key_color: str = "", val_color: str = "") -> str:
    """Sformatowany wiersz klucz: wartosc."""
    kc = key_color or C.DIM
    vc = val_color or C.RESET
    return f"  {kc}{key:<{key_w}}{C.RESET} {vc}{value}{C.RESET}"

# HISTORY_IO

def load_history():
    if HISTORY_FILE.exists():
        try:
            with HISTORY_FILE.open("r", encoding="utf-8") as f:
                for line in f:
                    entry = line.rstrip("\n")
                    HISTORY.append(entry)
                    if readline:
                        readline.add_history(entry)
        except Exception:
            print_error("Nie udalo sie odczytac historii.")

def save_history():
    try:
        max_entries = int(cfg("history_max", 500))
        with HISTORY_FILE.open("w", encoding="utf-8") as f:
            for cmd in HISTORY[-max_entries:]:
                f.write(cmd + "\n")
    except Exception:
        print_error("Nie udalo sie zapisac historii.")

# ALIASES_IO

def load_aliases():
    if not ALIASES_FILE.exists():
        return
    try:
        with ALIASES_FILE.open("r", encoding="utf-8") as f:
            for line in f:
                if "=" in line:
                    name, value = line.strip().split("=", 1)
                    ALIASES[name] = value
    except Exception:
        print_error("Nie udalo sie odczytac aliasow.")

def save_aliases():
    try:
        with ALIASES_FILE.open("w", encoding="utf-8") as f:
            for name, value in ALIASES.items():
                f.write(f"{name}={value}\n")
    except Exception:
        print_error("Nie udalo sie zapisac aliasow.")

# LS_COLOR

def ls_icon(path: Path) -> str:
    if not cfg("use_emoji_icons", True):
        return ""      # bez ikon — czysty tekst
    if path.is_dir():
        return "📁"
    if path.is_symlink():
        return "🔗"
    return EXT_ICONS.get(path.suffix.lower(), "📄")

def ls_color(path: Path) -> str:
    if path.is_dir():
        return C.DIR
    if path.is_symlink():
        return C.LINK
    if os.access(path, os.X_OK):
        return C.EXEC
    return ext_color(path.suffix.lower())

def ls_format_entry(path: Path) -> str:
    icon  = ls_icon(path)
    color = ls_color(path)
    name  = path.name + ("/" if path.is_dir() else "")
    return f"{icon} {color}{name}{C.RESET}"

def cmd_ls_impl(args):
    """
    ls [-l] [-a] [-s] [<katalog>]

    Opcje:
      -l   format szczegolowy (uprawnienia, rozmiar, data)
      -a   pokaz ukryte pliki (zaczynajace sie od .)
      -s   sortuj wg rozmiaru (malejaco)
    """
    long_fmt  = "-l" in args
    show_all  = "-a" in args
    sort_size = "-s" in args
    path_args = [a for a in args if not a.startswith("-")]

    target = Path(path_args[0]).expanduser() if path_args else Path.cwd()
    if not target.exists():
        print_error(f"Sciezka nie istnieje: {target}")
        return

    try:
        entries = list(target.iterdir())
    except PermissionError:
        print_error(f"Brak uprawnien: {target}")
        return

    if not show_all:
        entries = [e for e in entries if not e.name.startswith(".")]

    if sort_size:
        entries.sort(key=lambda p: p.stat().st_size if p.is_file() else 0, reverse=True)
    else:
        entries.sort(key=lambda p: (not p.is_dir(), p.name.lower()))

    if long_fmt:
        _ls_long(entries)
    elif not cfg("ls_columns", True):
        # Tryb jednokolumnowy (ls_columns=false w configu)
        for p in entries:
            print(ls_format_entry(p))
    else:
        _ls_columns(entries)

def _ls_long(entries):
    import stat as stat_mod
    for p in entries:
        try:
            st   = p.stat()
            size = st.st_size
            mtime = datetime.datetime.fromtimestamp(st.st_mtime).strftime("%Y-%m-%d %H:%M")
            # uprawnienia
            mode = stat_mod.filemode(st.st_mode)
            size_str = _human_size(size) if p.is_file() else "     -"
            icon  = ls_icon(p)
            color = ls_color(p)
            name  = p.name + ("/" if p.is_dir() else "")
            print(f"{C.DIM}{mode}{C.RESET}  {size_str:>7}  {C.DIM}{mtime}{C.RESET}  "
                  f"{icon} {color}{name}{C.RESET}")
        except Exception:
            print(f"  {p.name}")

def _ls_columns(entries):
    if not entries:
        return
    width   = terminal_width()
    labels  = [ls_format_entry(p) for p in entries]
    # Szacuj szerokosc bez kodow ANSI
    visible = [re.sub(r"\033\[[0-9;]*m", "", l) for l in labels]
    max_w   = max((len(v) for v in visible), default=0) + 2

    cols = max(1, width // max_w)
    rows = (len(labels) + cols - 1) // cols

    for row in range(rows):
        line = ""
        for col in range(cols):
            idx = row + col * rows
            if idx >= len(labels):
                break
            vis_len = len(visible[idx])
            pad     = max_w - vis_len
            line   += labels[idx] + " " * pad
        print(line)

def _human_size(size: int) -> str:
    for unit in ("B", "K", "M", "G", "T"):
        if size < 1024:
            return f"{size:.0f}{unit}"
        size /= 1024
    return f"{size:.0f}P"

# CAT_SYNTAX

PY_KEYWORDS = {
    "def","class","return","import","from","if","elif","else","for","while",
    "try","except","finally","with","as","pass","break","continue","lambda",
    "yield","global","nonlocal","assert","raise","in","is","not","and","or",
    "True","False","None","async","await","match","case"
}
PY_BUILTINS = {
    "print","len","range","type","str","int","float","list","dict","set",
    "tuple","open","input","super","self","cls","enumerate","zip","map",
    "filter","sorted","reversed","any","all","min","max","sum","abs","repr"
}
JS_KEYWORDS = {
    "const","let","var","function","return","if","else","for","while","do",
    "class","import","export","from","async","await","new","this","typeof",
    "null","undefined","true","false","switch","case","break","continue",
    "try","catch","finally","throw","instanceof","of","in","default","extends"
}
SH_KEYWORDS = {
    "if","then","else","elif","fi","for","while","do","done","case","esac",
    "function","return","local","export","source","echo","exit","shift",
    "test","read","unset","trap","exec","eval"
}
SQL_KEYWORDS = {
    "SELECT","FROM","WHERE","JOIN","LEFT","RIGHT","INNER","OUTER","ON",
    "INSERT","INTO","VALUES","UPDATE","SET","DELETE","CREATE","TABLE",
    "DROP","ALTER","INDEX","VIEW","AS","AND","OR","NOT","IN","IS","NULL",
    "ORDER","BY","GROUP","HAVING","LIMIT","OFFSET","DISTINCT","COUNT",
    "SUM","AVG","MIN","MAX","UNION","ALL"
}

# Placeholder bezpieczny — nie moze wystapic w kodzie ani kolidowac z regexem liczb
_PH_START = "\x02"   # STX
_PH_END   = "\x03"   # ETX

def _protect_strings(line: str) -> tuple:
    """Zastepuje stringi placeholderami, zwraca (linia, lista_stringow)."""
    strings = []
    result  = []
    i = 0
    while i < len(line):
        if line[i] in ('"', "'"):
            q   = line[i]
            end = i + 1
            while end < len(line):
                if line[end] == "\\" and end + 1 < len(line):
                    end += 2
                    continue
                if line[end] == q:
                    end += 1
                    break
                end += 1
            raw = line[i:end]
            strings.append(f"{C.STRING}{raw}{C.RESET}")
            result.append(f"{_PH_START}{len(strings)-1}{_PH_END}")
            i = end
        else:
            result.append(line[i])
            i += 1
    return "".join(result), strings

def _restore_strings(line: str, strings: list) -> str:
    def replacer(m):
        return strings[int(m.group(1))]
    return re.sub(rf"{re.escape(_PH_START)}(\d+){re.escape(_PH_END)}",
                  replacer, line)

def _kw_replace(keywords: set, color: str, line: str) -> str:
    """Zastepuje slowa kluczowe kolorowymi wersjami (stringi juz schowane)."""
    for kw in keywords:
        line = re.sub(rf'\b{re.escape(kw)}\b',
                      f"{color}{kw}{C.RESET}", line)
    return line

def colorize_line(line: str, ext: str = "") -> str:
    """
    Koloruje jedna linie kodu. Kolejnosc operacji jest bezpieczna:
    1. Wytnij komentarz (reszta linii)
    2. Schowaj stringi pod placeholderami
    3. Pokoloruj liczby i slowa kluczowe (nie dotykaja stringow)
    4. Przywroc stringi (juz pokolorowane)
    """
    ext = ext.lower()

    # --- 1. KOMENTARZE ---
    # C/C++/Java/Go/Rust/JS/TS: // komentarz (tylko poza stringami)
    if ext in (".js",".ts",".jsx",".tsx",".c",".cpp",".h",".java",".go",".rs",".cs"):
        # Szukamy // poza stringami
        in_str = False
        q_char = None
        for ci, ch in enumerate(line):
            if not in_str and ch in ('"', "'"):
                in_str = True
                q_char = ch
            elif in_str and ch == q_char and (ci == 0 or line[ci-1] != "\\"):
                in_str = False
            elif not in_str and line[ci:ci+2] == "//":
                code    = line[:ci]
                comment = line[ci:]
                return colorize_line(code, ext) + C.COMMENT + comment + C.RESET
        # /* ... */ jednoliniowy
        m = re.match(r'^(.*?)(\/\*.*?\*\/)(.*)$', line)
        if m:
            return (colorize_line(m.group(1), ext)
                    + C.COMMENT + m.group(2) + C.RESET
                    + colorize_line(m.group(3), ext))

    # HTML komentarz
    if ext in (".html", ".htm", ".xml"):
        m = re.match(r'^(.*?)(<!--.*?-->)(.*)$', line)
        if m:
            return (colorize_line(m.group(1), ext)
                    + C.COMMENT + m.group(2) + C.RESET
                    + colorize_line(m.group(3), ext))

    # CSS komentarz
    if ext == ".css":
        m = re.match(r'^(.*?)(\/\*.*?\*\/)(.*)$', line)
        if m:
            return (colorize_line(m.group(1), ext)
                    + C.COMMENT + m.group(2) + C.RESET
                    + colorize_line(m.group(3), ext))

    # # komentarz (Python, Bash, Ruby, YAML, TOML, ...)
    if ext in (".py",".sh",".bash",".zsh",".rb",".yaml",".yml",".toml",
               ".env",".cfg",".conf",".ini",".r"):
        # Szukamy # poza stringami
        in_str = False
        q_char = None
        for ci, ch in enumerate(line):
            if not in_str and ch in ('"', "'"):
                in_str = True
                q_char = ch
            elif in_str and ch == q_char and (ci == 0 or line[ci-1] != "\\"):
                in_str = False
            elif not in_str and ch == "#":
                code    = line[:ci]
                comment = line[ci:]
                return colorize_line(code, ext) + C.COMMENT + comment + C.RESET

    # SQL: -- komentarz
    if ext in (".sql",):
        if "--" in line:
            idx = line.index("--")
            return colorize_line(line[:idx], ext) + C.COMMENT + line[idx:] + C.RESET

    # Markdown: naglowki #
    if ext == ".md":
        if re.match(r'^#{1,6}\s', line):
            return f"{C.KEYWORD}{line}{C.RESET}"
        if re.match(r'^(\*{3}|-{3}|_{3})', line):
            return f"{C.DIM}{line}{C.RESET}"
        # **bold** i *italic*
        line = re.sub(r'\*\*(.+?)\*\*', f"{C.BOLD}\\1{C.RESET}", line)
        line = re.sub(r'\*(.+?)\*',     f"{C.STRING}\\1{C.RESET}", line)
        # `inline code`
        line = re.sub(r'`(.+?)`', f"{C.BUILTIN}\\1{C.RESET}", line)
        # linki [tekst](url)
        line = re.sub(r'\[(.+?)\]\((.+?)\)',
                      f"{C.KEYWORD}[\\1]{C.RESET}{C.DIM}(\\2){C.RESET}", line)
        return line

    # --- 2. SCHOWAJ STRINGI ---
    safe, strings = _protect_strings(line)

    # --- 3. LICZBY (nie dotykaj cyfr wewnatrz placeholderow \x02N\x03) ---
    # Negatywny lookbehind na \x02 i lookahead na \x03 zapobiega kolorowania indeksow
    safe = re.sub(r'(?<!\x02)\b(0x[0-9a-fA-F]+|\d+\.?\d*(?:[eE][+-]?\d+)?)\b(?!\x03)',
                  lambda m: f"{C.NUMBER}{m.group(1)}{C.RESET}", safe)

    # --- 4. SLOWA KLUCZOWE wg jezyka ---
    if ext == ".py":
        safe = _kw_replace(PY_KEYWORDS, C.KEYWORD, safe)
        safe = _kw_replace(PY_BUILTINS, C.BUILTIN, safe)
        # dekoratory @
        safe = re.sub(r'(@\w+)', f"{C.BUILTIN}\\1{C.RESET}", safe)
        # Pogrub nazwy funkcji/klas: def NAZWA / class NAZWA
        safe = re.sub(r'\b(def|class)\b\s+(\w+)',
                      lambda m: (f"{C.KEYWORD}{m.group(1)}{C.RESET} "
                                 f"{C.BOLD}{m.group(2)}{C.RESET}"), safe)

    elif ext in (".js",".ts",".jsx",".tsx"):
        safe = _kw_replace(JS_KEYWORDS, C.KEYWORD, safe)
        # Pogrub nazwy wywolywanych funkcji: foo( — tylko po spacji/operatorze/poczatku
        safe = re.sub(r'(?:(?<=\s)|(?<=\=)|(?<=\()|(?<=,)|^)([a-zA-Z_]\w*)(?=\s*\()',
                      lambda m: (f"{C.BUILTIN}{m.group(1)}{C.RESET}"
                                 if m.group(1) not in JS_KEYWORDS else m.group(0)),
                      safe)

    elif ext in (".sh",".bash",".zsh"):
        safe = _kw_replace(SH_KEYWORDS, C.KEYWORD, safe)
        # zmienne $VAR ${VAR}
        safe = re.sub(r'(\$\{?\w+\}?)', f"{C.BUILTIN}\\1{C.RESET}", safe)

    elif ext in (".sql",):
        safe = _kw_replace(SQL_KEYWORDS, C.KEYWORD, safe)
        safe = _kw_replace({k.lower() for k in SQL_KEYWORDS}, C.KEYWORD, safe)

    elif ext in (".json",):
        # klucze JSON "key":
        safe = re.sub(r'(\"[^\"]+\")(\s*:)',
                      f"{C.KEYWORD}\\1{C.RESET}\\2", safe)
        # wartosci true/false/null
        safe = re.sub(r'\b(true|false|null)\b',
                      f"{C.BUILTIN}\\1{C.RESET}", safe)

    elif ext in (".html",".htm"):
        # tagi <tag attr>
        safe = re.sub(r'(<\/?\w[\w\-]*)',  f"{C.KEYWORD}\\1{C.RESET}", safe)
        safe = re.sub(r'(\w+)(\s*=\s*)',   f"{C.BUILTIN}\\1{C.RESET}\\2", safe)

    elif ext in (".css",):
        # selektory, wlasciwosci
        safe = re.sub(r'([\.\#]?\w[\w\-]*)(\s*\{)',
                      f"{C.KEYWORD}\\1{C.RESET}\\2", safe)
        safe = re.sub(r'(\w[\w\-]*)(\s*:)',
                      f"{C.BUILTIN}\\1{C.RESET}\\2", safe)

    # --- 5. PRZYWROC STRINGI ---
    return _restore_strings(safe, strings)

# PIPES

#   PARSER BASH-LIKE
#
#  Hierarchia parsowania (od najnizszego priorytetu):
#    1. Lista: cmd1 ; cmd2 ; cmd3
#    2. AND/OR: cmd1 && cmd2 || cmd3
#    3. Pipeline: cmd1 | cmd2 | cmd3
#    4. Komenda z przekierowaniami: cmd > out 2>&1 < in
#    5. Rozwijanie zmiennych: $VAR ${VAR} $? $$ $(subshell)
#
# ============================================================

def _var_expand(text: str) -> str:
    """
    Rozwija zmienne w tekscie:
      $VAR  ${VAR}  $?  $$  $0  $(komenda)  `komenda`
    Kolejnosc: subshell -> zmienne specjalne -> SHELL_VARS -> os.environ
    """

    # $(komenda) i `komenda` — subshell
    def _subshell(m):
        cmd_str = m.group(1) or m.group(2)
        try:
            result = subprocess.run(
                cmd_str, shell=True, capture_output=True, text=True,
                env=_build_env()
            )
            return result.stdout.rstrip("\n")
        except Exception:
            return ""

    text = re.sub(r'\$\((.+?)\)', _subshell, text)
    text = re.sub(r'`(.+?)`',       _subshell, text)

    # Zmienne specjalne
    text = text.replace("$$", str(_SHELL_PID))
    text = text.replace("$?", str(_LAST_EXIT))
    text = text.replace("$0", "TerminalX")

    # ${VAR} i $VAR
    def _lookup(m):
        name = m.group(1) or m.group(2)
        # Domyslna wartosc ${VAR:-default}
        if ":-" in name:
            var, default = name.split(":-", 1)
            return _get_var(var) or default
        return _get_var(name)

    text = re.sub(r'\$\{([^}]+)\}', _lookup, text)
    text = re.sub(r'\$([A-Za-z_][A-Za-z0-9_]*)', _lookup, text)
    return text

def _get_var(name: str) -> str:
    """Pobiera wartosc zmiennej: SHELL_VARS > os.environ."""
    return SHELL_VARS.get(name, os.environ.get(name, ""))

def _set_var(name: str, value: str, export: bool = False):
    """Ustawia zmienna w SHELL_VARS i opcjonalnie w os.environ."""
    SHELL_VARS[name] = value
    if export:
        os.environ[name] = value

def _build_env() -> dict:
    """Srodowisko dla subprocess: os.environ + SHELL_VARS."""
    env = os.environ.copy()
    env.update(SHELL_VARS)
    return env

def _tokenize_operators(line: str) -> list:
    """
    Tokenizuje linie na fragmenty i operatory, respektujac cytowania.
    Zwraca liste par (typ, wartosc):
      ("cmd",  "ls -la")
      ("pipe", "|")
      ("and",  "&&")
      ("or",   "||")
      ("semi", ";")
    """
    tokens = []
    buf    = []
    i      = 0
    n      = len(line)

    while i < n:
        c = line[i]

        # Cytowania — caly zawartosc traktuj jako literal
        if c in ('"\'"'):
            q   = c
            buf.append(c)
            i  += 1
            while i < n:
                buf.append(line[i])
                if line[i] == q:
                    i += 1
                    break
                if line[i] == "\\" and i + 1 < n:
                    i += 1
                    buf.append(line[i])
                i += 1
            continue

        # Dwuznakowe operatory
        two = line[i:i+2]
        if two == "&&":
            if buf:
                tokens.append(("cmd", "".join(buf).strip()))
                buf = []
            tokens.append(("and", "&&"))
            i += 2
            continue
        if two == "||":
            if buf:
                tokens.append(("cmd", "".join(buf).strip()))
                buf = []
            tokens.append(("or",  "||"))
            i += 2
            continue

        # Jednoznakowe operatory (poza > >> ktore sa czescia komendy)
        if c == "|" and (i + 1 >= n or line[i+1] != "|"):
            if buf:
                tokens.append(("cmd", "".join(buf).strip()))
                buf = []
            tokens.append(("pipe", "|"))
            i += 1
            continue
        if c == ";":
            if buf:
                tokens.append(("cmd", "".join(buf).strip()))
                buf = []
            tokens.append(("semi", ";"))
            i += 1
            continue

        buf.append(c)
        i += 1

    if buf:
        s = "".join(buf).strip()
        if s:
            tokens.append(("cmd", s))

    return tokens

def _split_pipeline(token_list: list) -> list:
    """
    Ze splaszczonej listy tokenow wydziela grupy polaczone pipe'ami.
    Zwraca liste list stringow (komend w pipeline).
    """
    pipelines = []
    current   = []
    for typ, val in token_list:
        if typ == "pipe":
            pipelines.append(current)
            current = []
        else:
            current.append((typ, val))
    pipelines.append(current)
    return pipelines

def _parse_redirects(cmd_str: str) -> tuple:
    """
    Parsuje przekierowania z napisu komendy.
    Zwraca (tokens_bez_redirect, stdin_file, stdout_file, stdout_append, stderr_to_stdout).
    Obsluguje: > >> < 2>&1 2>plik
    """
    try:
        raw = shlex.split(cmd_str)
    except ValueError:
        raw = cmd_str.split()

    out_tokens   = []
    stdin_file   = None
    stdout_file  = None
    stdout_append = False
    stderr_merge  = False
    i = 0
    while i < len(raw):
        t = raw[i]
        if t == ">>" and i + 1 < len(raw):
            stdout_file   = raw[i+1]; stdout_append = True;  i += 2
        elif t == ">" and i + 1 < len(raw):
            stdout_file   = raw[i+1]; stdout_append = False; i += 2
        elif t == "<" and i + 1 < len(raw):
            stdin_file    = raw[i+1]; i += 2
        elif t == "2>&1":
            stderr_merge  = True; i += 1
        elif t.startswith("2>") and len(t) > 2:
            # 2>plik (bez spacji)
            stdout_file   = t[2:]; stderr_merge = True; i += 1
        elif t.endswith(">>") and i + 1 < len(raw):
            stdout_file   = raw[i+1]; stdout_append = True; i += 2
        else:
            out_tokens.append(t)
            i += 1

    return out_tokens, stdin_file, stdout_file, stdout_append, stderr_merge

def _run_single_cmd(cmd_str: str, stdin_data: bytes = None,
                    capture_stdout: bool = False) -> tuple:
    """
    Uruchamia pojedyncza komende (po rozwinieciu zmiennych i redirectow).
    Zwraca (exit_code, stdout_bytes|None).
    """

    # Rozwin zmienne
    cmd_str = _var_expand(cmd_str)

    # Parsuj przekierowania
    tokens, stdin_f, stdout_f, stdout_app, stderr_merge = _parse_redirects(cmd_str)

    if not tokens:
        return 0, None

    # Sprawdz VAR=wartosc (bez komendy)
    if len(tokens) == 1 and "=" in tokens[0] and not tokens[0].startswith("-"):
        name, _, value = tokens[0].partition("=")
        if re.match(r'[A-Za-z_][A-Za-z0-9_]*', name):
            _set_var(name, value)
            _STATE.last_exit = 0
            return 0, None

    tokens = expand_aliases(tokens)
    cmd    = tokens[0]
    args   = tokens[1:]

    # Budownictwo stdin/stdout/stderr
    stdin_src  = None
    stdout_dst = subprocess.PIPE if capture_stdout else None
    stderr_dst = subprocess.STDOUT if stderr_merge else None

    if stdin_data is not None:
        stdin_src = subprocess.PIPE
    elif stdin_f:
        try:
            stdin_src = open(stdin_f, "rb")
        except Exception as e:
            print_error(str(e)); _LAST_EXIT = 1; return 1, None

    out_file_handle = None
    if stdout_f:
        try:
            out_file_handle = open(stdout_f, "ab" if stdout_app else "wb")
            stdout_dst      = out_file_handle
        except Exception as e:
            print_error(str(e)); _LAST_EXIT = 1; return 1, None

    # Komenda wbudowana
    if cmd == "exit":
        # Obsluga exit w kontekscie _run_single_cmd
        _STATE.last_exit = int(args[0]) if args else 0
        raise SystemExit(_LAST_EXIT)

    if cmd in BUILTINS:
        # Builtiny uruchamiamy w procesie — capture przez redirect stdout
        import io
        if capture_stdout or out_file_handle:
            old_stdout = sys.stdout
            buf = io.StringIO()
            sys.stdout = buf
            try:
                dispatch(cmd, args)
                code = 0
            except SystemExit as e:
                code = e.code or 0
            except Exception as e:
                print_error(str(e)); code = 1
            finally:
                sys.stdout = old_stdout
            output = buf.getvalue().encode()
            if out_file_handle:
                out_file_handle.write(output)
                out_file_handle.close()
            _STATE.last_exit = code
            return code, output if capture_stdout else None
        else:
            try:
                dispatch(cmd, args)
                code = 0
            except SystemExit as e:
                code = e.code or 0
            except Exception as e:
                print_error(str(e)); code = 1
            _STATE.last_exit = code
            return code, None

    # Komenda zewnetrzna
    try:
        stdin_input = stdin_data if stdin_data else None
        p = subprocess.run(
            tokens,
            input=stdin_input,
            stdin=None if stdin_input is not None else (stdin_src or None),
            stdout=stdout_dst,
            stderr=stderr_dst,
            env=_build_env(),
        )
        if out_file_handle:
            out_file_handle.close()
        _STATE.last_exit = p.returncode
        if capture_stdout and p.stdout:
            return p.returncode, p.stdout
        return p.returncode, None
    except FileNotFoundError:
        print_error(f"Nie znaleziono programu: '{tokens[0]}'",
                    f"Sprawdz czy program jest zainstalowany: which {tokens[0]}")
        _STATE.last_exit = 127
        return 127, None
    except Exception as e:
        smart_error(e, f"wykonanie: {tokens[0]}")
        _STATE.last_exit = 1
        return 1, None

def execute_pipeline(cmd_strings: list) -> tuple:
    """
    Wykonuje pipeline komend polaczonych pipe'ami.
    cmd_strings: lista napisow (np. ["ls -la", "grep py", "wc -l"])
    Zwraca (exit_code, None).
    """

    if len(cmd_strings) == 1:
        code, _ = _run_single_cmd(cmd_strings[0])
        return code, None

    # Zbierz wyniki pipeline'u przekazujac stdout jako stdin kolejnej komendy
    data = None
    code = 0
    for i, cmd_str in enumerate(cmd_strings):
        is_last = (i == len(cmd_strings) - 1)
        code, output = _run_single_cmd(
            cmd_str,
            stdin_data=data,
            capture_stdout=not is_last
        )
        data = output

    # Ostatni stdout wyswietl
    if data:
        sys.stdout.write(data.decode(errors="replace"))
    _STATE.last_exit = code
    return code, None

def execute_line(line: str) -> int:
    """
    Glowna funkcja wykonujaca linie wejscia z pelnym parserem:
      - rozwijanie zmiennych
      - ; && || pipe >  >> < 2>&1
      - VAR=wartosc (przypisanie)
    Zwraca kod wyjscia ostatniej komendy.
    """

    token_list = _tokenize_operators(line)
    if not token_list:
        return 0

    # Grupuj po operatorach sekwencji (; && ||)
    # Reprezentacja: lista grup, kazda grupa to pipeline
    # Wykonujemy kolejno respektujac && i ||
    groups = []    # [(operator_przed, [cmd_strings])]
    current_pipe  = []
    prev_op       = "semi"   # pierwszy segment zawsze wykonywany

    for typ, val in token_list:
        if typ == "cmd":
            current_pipe.append(val)
        elif typ == "pipe":
            pass  # pozostaje w current_pipe — rozdzielone pozniej
        elif typ in ("and", "or", "semi"):
            # Zamknij biezacy segment
            # Odbuduj pipeline — current_pipe to lista komend oddzielonych pipe
            # Ale token_list juz zawiera pipe jako osobne tokeny — musimy je zebrać razem
            groups.append((prev_op, current_pipe[:]))
            current_pipe = []
            prev_op = typ

    groups.append((prev_op, current_pipe[:]))

    # Teraz wykonaj grupy
    # Ale powyzej stracimy pipe'y bo je wrzucilismy do current_pipe jako cmd
    # Przebuduj: przejdz przez token_list zbierajac pipeline segments
    return _execute_token_list(token_list)

def _execute_token_list(token_list: list) -> int:
    """
    Wykonuje splaszczona liste tokenow respektujac priorytety operatorow.
    ; — bezwarunkowy separator
    && — wykonaj jesli poprzedni sukces (exit 0)
    || — wykonaj jesli poprzedni blad (exit != 0)
    |  — pipe (laczy stdout->stdin)
    """

    # Zbierz biezacy pipeline
    pipeline_cmds = []
    pending_op    = "semi"   # operator przed biezacym segmentem
    code          = 0

    def _flush_pipeline():
        nonlocal code
        if not pipeline_cmds:
            return
        # Sprawdz warunek
        should_run = True
        if pending_op == "and" and code != 0:
            should_run = False
        elif pending_op == "or" and code == 0:
            should_run = False

        if should_run:
            code, _ = execute_pipeline(pipeline_cmds[:])
        pipeline_cmds.clear()

    for typ, val in token_list:
        if typ == "cmd":
            pipeline_cmds.append(val)
        elif typ == "pipe":
            pass   # cmd'y po obu stronach pipe beda w pipeline_cmds
        elif typ in ("and", "or", "semi"):
            _flush_pipeline()
            pending_op = typ

    _flush_pipeline()
    _STATE.last_exit = code
    SHELL_VARS["_LAST_EXIT_DISPLAY"] = str(code)
    return code

