@command("cd", "Zmien biezacy katalog")
def cmd_cd(args):
    target = Path(args[0]).expanduser() if args else Path.home()
    try:
        os.chdir(target)
    except FileNotFoundError:
        print_error(f"Katalog nie istnieje: '{target}'",
                    f"Uzyj 'ls' aby sprawdzic dostepne katalogi")
    except PermissionError:
        print_error(f"Brak uprawnien do katalogu: '{target}'",
                    "Sprawdz prawa dostepu: ls -l")
    except NotADirectoryError:
        print_error(f"'{target}' nie jest katalogiem",
                    "Podaj sciezke do katalogu, nie pliku")
    except Exception as e:
        smart_error(e, "cd", str(target))

