# Mapa rozszerzen -> nazwa jezyka (do naglowka)
EXT_LANG = {
    ".py": "Python", ".js": "JavaScript", ".ts": "TypeScript",
    ".jsx": "React/JSX", ".tsx": "React/TSX", ".c": "C", ".cpp": "C++",
    ".h": "C/C++ Header", ".java": "Java", ".go": "Go", ".rs": "Rust",
    ".rb": "Ruby", ".php": "PHP", ".sh": "Shell", ".bash": "Bash",
    ".zsh": "Zsh", ".ps1": "PowerShell", ".cs": "C#",
    ".json": "JSON", ".yaml": "YAML", ".yml": "YAML", ".toml": "TOML",
    ".xml": "XML", ".html": "HTML", ".htm": "HTML", ".css": "CSS",
    ".sql": "SQL", ".md": "Markdown", ".r": "R",
    ".env": "Env", ".cfg": "Config", ".conf": "Config", ".ini": "INI",
}

@command("cat", "Wyswietl zawartosc pliku z kolorowaniem skladni",
         aliases=["type"], flags=["-n", "-A"])
def cmd_cat(args):
    """
    cat <plik>      - wyswietla plik z kolorowaniem (Python, JS, Bash, JSON, HTML, CSS, SQL, MD, ...)
    cat -n <plik>   - wyswietla z numerami linii
    cat -A <plik>   - wyswietla bez kolorowania (raw)

    Obslugiwane jezyki:
      Python, JavaScript/TypeScript, C/C++, Java, Go, Rust, Ruby, PHP,
      Shell/Bash/Zsh, JSON, YAML, TOML, XML, HTML, CSS, SQL, Markdown
    """
    show_nums = "-n" in args
    raw_mode  = "-A" in args
    path_args = [a for a in args if not a.startswith("-")]

    if not path_args:
        print_error("Uzycie: cat [-n] [-A] <plik>")
        return
    path = Path(path_args[0]).expanduser()
    if not path.exists():
        print_error(f"Plik nie istnieje: {path}")
        return

    ext  = path.suffix.lower()
    lang = EXT_LANG.get(ext, "")
    if lang:
        print(f"{C.DIM}── {path.name}  [{lang}] ──{C.RESET}")

    try:
        with path.open("r", encoding="utf-8", errors="replace") as f:
            for lineno, line in enumerate(f, 1):
                content = line.rstrip("\n")
                use_hl  = cfg("syntax_highlight_cat", True)
                if not raw_mode and use_hl:
                    content = colorize_line(content, ext)
                if show_nums:
                    print(f"{C.DIM}{lineno:4d}{C.RESET}  {content}")
                else:
                    print(content)
    except PermissionError:
        print_error(f"Brak uprawnien do odczytu: '{path}'",
                    "Sprawdz prawa: ls -l, lub uzyj sudo")
    except UnicodeDecodeError:
        print_error(f"Plik '{path.name}' nie jest tekstem UTF-8",
                    "Sprobuj: cat -A (tryb raw bez kolorowania)")
    except Exception as e:
        smart_error(e, "cat", str(path))

