@command("rm", "Usun plik", aliases=["del"])
def cmd_rm(args):
    """rm <plik> — usuwa plik. W trybie root pyta o potwierdzenie."""
    if not args:
        print_error("Brak nazwy pliku", "Uzycie: rm <plik>")
        return
    target = args[0]
    if not _root_guard("rm", target):
        print_info("Anulowano.")
        return
    p = Path(target).expanduser()
    if not p.exists():
        print_error(f"Plik nie istnieje: '{target}'",
                    "Uzyj 'ls' aby sprawdzic dostepne pliki")
        return
    if p.is_dir():
        print_error(f"'{target}' jest katalogiem",
                    "Uzyj 'rmdir' aby usunac katalog")
        return
    # Potwierdzenie jesli confirm_rm=true lub jestesmy w trybie root
    need_confirm = cfg("confirm_rm", True) or (IS_ROOT and cfg("confirm_rm_root", True))
    if need_confirm and not _root_guard("rm", target):
        print_info("Anulowano.")
        return
    try:
        p.unlink()
    except PermissionError:
        print_error(f"Brak uprawnien do usuniecia: '{target}'",
                    "Sprobuj z sudo lub sprawdz wlasciciela: ls -l")
    except Exception as e:
        smart_error(e, "rm", target)

@command("rmdir", "Usun katalog rekurencyjnie", aliases=["rd"])
def cmd_rmdir(args):
    """rmdir <katalog> — usuwa katalog ze wszystkimi plikami. W trybie root pyta o potwierdzenie."""
    if not args:
        print_error("Brak nazwy katalogu", "Uzycie: rmdir <katalog>")
        return
    target = args[0]
    if not _root_guard("rmdir -rf", target):
        print_info("Anulowano.")
        return
    p = Path(target).expanduser()
    if not p.exists():
        print_error(f"Katalog nie istnieje: '{target}'",
                    "Uzyj 'ls' aby sprawdzic dostepne katalogi")
        return
    if not p.is_dir():
        print_error(f"'{target}' nie jest katalogiem",
                    "Uzyj 'rm' aby usunac plik")
        return
    try:
        shutil.rmtree(p)
    except PermissionError:
        print_error(f"Brak uprawnien do usuniecia: '{target}'",
                    "Sprobuj z sudo lub sprawdz wlasciciela: ls -l")
    except Exception as e:
        smart_error(e, "rmdir", target)

@command("cp", "Kopiuj plik lub katalog", aliases=["copy"], flags=["-r","-v","-f","-n"])
def cmd_cp(args):
    """
    cp <src> <dst>        - kopiuj plik
    cp -r <src> <dst>     - kopiuj katalog rekurencyjnie
    cp -v <src> <dst>     - verbose
    cp -n <src> <dst>     - nie nadpisuj istniejacych
    cp plik1 plik2 kat/   - wiele zrodel do katalogu
    """
    flags   = {a for a in args if a.startswith("-")}
    paths   = [a for a in args if not a.startswith("-")]
    recurse = "-r" in flags or "-R" in flags
    verbose = "-v" in flags
    no_over = "-n" in flags
    if len(paths) < 2:
        print_error("Za malo argumentow", "Uzycie: cp [-r] [-v] <src> [src2...] <dst>")
        return
    dst  = Path(paths[-1]).expanduser()
    srcs = [Path(p).expanduser() for p in paths[:-1]]
    if len(srcs) > 1 and not dst.is_dir():
        print_error(f"Cel '{dst}' musi byc katalogiem przy wielu zrodlach")
        return
    for src in srcs:
        if not src.exists():
            print_error(f"Zrodlo nie istnieje: '{src}'", "Sprawdz: ls"); continue
        target = dst / src.name if dst.is_dir() else dst
        if no_over and target.exists():
            if verbose: print_warn(f"Pomijam (istnieje): {target}")
            continue
        try:
            if src.is_dir():
                if not recurse:
                    print_error(f"'{src}' jest katalogiem", "Uzyj cp -r"); continue
                if target.exists(): shutil.rmtree(target)
                shutil.copytree(str(src), str(target))
            else:
                target.parent.mkdir(parents=True, exist_ok=True)
                shutil.copy2(str(src), str(target))
            if verbose: print_ok(f"Skopiowano: {src}  →  {target}")
            log_info(f"cp: {src} -> {target}")
        except PermissionError:
            print_error(f"Brak uprawnien: '{src}'", "Sprawdz prawa: ls -l")
        except Exception as e:
            smart_error(e, "cp", str(src))

@command("mv", "Przesun lub zmien nazwe pliku/katalogu", aliases=["move"], flags=["-v","-n"])
def cmd_mv(args):
    """
    mv <src> <dst>        - przesun/zmien nazwe
    mv -v <src> <dst>     - verbose
    mv -n <src> <dst>     - nie nadpisuj
    mv f1 f2 kat/         - wiele plikow do katalogu
    """
    flags   = {a for a in args if a.startswith("-")}
    paths   = [a for a in args if not a.startswith("-")]
    verbose = "-v" in flags
    no_over = "-n" in flags
    if len(paths) < 2:
        print_error("Za malo argumentow", "Uzycie: mv [-v] <src> [src2...] <dst>")
        return
    dst  = Path(paths[-1]).expanduser()
    srcs = [Path(p).expanduser() for p in paths[:-1]]
    if len(srcs) > 1 and not dst.is_dir():
        print_error(f"Cel '{dst}' musi byc katalogiem przy wielu zrodlach")
        return
    for src in srcs:
        if not src.exists():
            print_error(f"Zrodlo nie istnieje: '{src}'"); continue
        target = dst / src.name if dst.is_dir() else dst
        if no_over and target.exists():
            if verbose: print_warn(f"Pomijam (istnieje): {target}")
            continue
        try:
            shutil.move(str(src), str(target))
            if verbose: print_ok(f"Przeniesiono: {src}  →  {target}")
            log_info(f"mv: {src} -> {target}")
        except PermissionError:
            print_error(f"Brak uprawnien: '{src}'", "Sprawdz prawa: ls -l")
        except Exception as e:
            smart_error(e, "mv", str(src))

