# HISTORY_CMD

def _history_add(line: str):
    """
    Dodaje wpis do HISTORY i readline.
    Respektuje history_dedup i history_timestamps z konfiguracji.
    """
    if not line.strip():
        return
    if cfg("history_dedup", True) and HISTORY and HISTORY[-1] == line:
        return
    if cfg("history_timestamps", False):
        ts = datetime.datetime.now().strftime("%Y-%m-%d %H:%M:%S")
        entry = f"# {ts}\n{line}"
    else:
        entry = line
    HISTORY.append(entry)
    if readline:
        readline.add_history(line)

def _history_expand(line: str) -> str | None:
    """
    Rozwija rozwinięcia historii bash-style:
      !!         - ostatnia komenda
      !n         - komenda nr n (1-based)
      !-n        - n-ta od konca (!-1 == !!)
      !prefix    - ostatnia komenda zaczynajaca sie od prefix
      !?substr   - ostatnia komenda zawierajaca substr
    Zwraca rozwiniety string lub None jesli brak dopasowania.
    Wyrzuca ValueError z komunikatem jesli nie znaleziono.
    """
    s = line.strip()
    if not s.startswith("!"):
        return s

    # !! — ostatnia
    if s == "!!":
        if not HISTORY:
            raise ValueError("Historia jest pusta")
        return HISTORY[-1]

    # !n lub !-n — numer
    rest = s[1:]
    try:
        n = int(rest)
        if n > 0:
            if n > len(HISTORY):
                raise ValueError(f"Brak wpisu {n} w historii")
            return HISTORY[n - 1]
        else:  # ujemny
            idx = len(HISTORY) + n
            if idx < 0:
                raise ValueError(f"Brak wpisu {n} w historii")
            return HISTORY[idx]
    except (ValueError, IndexError) as e:
        if "Brak" in str(e):
            raise
        pass

    # !?substr — zawiera
    if rest.startswith("?"):
        substr = rest[1:]
        for cmd in reversed(HISTORY):
            if substr in cmd:
                return cmd
        raise ValueError(f"Nie znaleziono komendy zawierajacej: {substr!r}")

    # !prefix — zaczyna sie od
    for cmd in reversed(HISTORY):
        if cmd.startswith(rest):
            return cmd
    raise ValueError(f"Nie znaleziono komendy zaczynajaca sie od: {rest!r}")

@command("history", "Wyswietl i przeszukuj historie komend",
         flags=["-c", "-s", "-d", "-r", "-g", "-n", "--export", "--stats"])
def cmd_history(args):
    """
    history                  - wyswietl wszystkie wpisy (z numerami)
    history <n>              - wyswietl ostatnie n wpisow
    history -c               - wyczysc cala historie
    history -s <cmd>         - dodaj <cmd> do historii bez wykonywania
    history -d <n>           - usun wpis numer n
    history -r               - wyszukaj interaktywnie (jak Ctrl+R)
    history /query           - wyswietl pasujace do query
    history -g <pattern>     - grep w historii (regex)
    history --export [plik]  - eksportuj historie do pliku (domyslnie history.txt)
    history --stats          - statystyki (najczesciej uzywane komendy)
    !!                       - wykonaj ostatnia komende
    !n                       - wykonaj komende nr n
    !prefix                  - wykonaj ostatnia komende zaczynajaca sie od prefix
    """
    if not args:
        _history_print_all()
        return

    flag = args[0]

    if flag == "-c":
        HISTORY.clear()
        if readline:
            readline.clear_history()
        save_history()
        print_info("Historia wyczyszczona i plik nadpisany.")

    elif flag == "-s":
        if len(args) < 2:
            print_error("Uzycie: history -s <komenda>"); return
        entry = " ".join(args[1:])
        _history_add(entry)
        print_info(f"Dodano do historii: {entry}")

    elif flag == "-d":
        if len(args) < 2:
            print_error("Uzycie: history -d <numer>"); return
        try:
            n = int(args[1]) - 1
            if 0 <= n < len(HISTORY):
                removed = HISTORY.pop(n)
                if readline:
                    readline.clear_history()
                    for e in HISTORY:
                        readline.add_history(e)
                print_info(f"Usunieto wpis {n+1}: {removed}")
            else:
                print_error(f"Numer poza zakresem: {n+1}")
        except ValueError:
            print_error("Uzycie: history -d <numer>")

    elif flag == "-r":
        result = history_search_interactive()
        if result:
            print(f"{C.DIM}Wybrano:{C.RESET} {result}")
            if readline:
                readline.set_startup_hook(lambda: readline.insert_text(result))
                try:
                    line = input(prompt_current())
                    readline.set_startup_hook(None)
                    if line.strip():
                        _history_add(line)
                        execute_line(line)
                except (EOFError, KeyboardInterrupt):
                    readline.set_startup_hook(None)
                    print()
            else:
                print_info(f"Skopiuj i wykonaj: {result}")

    elif flag == "-g":
        # Grep w historii — regex
        if len(args) < 2:
            print_error("Uzycie: history -g <wzorzec>"); return
        pattern = " ".join(args[1:])
        try:
            rx = re.compile(pattern, re.IGNORECASE)
        except re.error as e:
            print_error(f"Nieprawidlowy regex: {e}"); return
        matches = [(i+1, cmd) for i, cmd in enumerate(HISTORY) if rx.search(cmd)]
        if not matches:
            print_info(f"Brak wynikow dla wzorca: {pattern!r}")
        else:
            print(f"\n{C.BOLD}Historia grep / {pattern!r} "
                  f"({len(matches)} wynikow):{C.RESET}\n")
            for n, cmd in matches[-50:]:
                hi = rx.sub(lambda m: f"{C.MATCH}{m.group()}{C.RESET}", cmd)
                print(f"  {C.DIM}{n:4d}{C.RESET}  {hi}")
            print()

    elif flag == "--export":
        _history_export(args[1] if len(args) > 1 else None)

    elif flag == "--stats":
        _history_stats()

    elif flag.startswith("/"):
        query = flag[1:]
        matches = [(i+1, cmd) for i, cmd in enumerate(HISTORY)
                   if query.lower() in cmd.lower()]
        if not matches:
            print_info(f"Brak pasujacych do: {query!r}")
        else:
            print(f"\n{C.BOLD}Historia / {query!r} ({len(matches)} wynikow):{C.RESET}\n")
            for n, cmd in matches[-30:]:
                hi = cmd.replace(query, f"{C.MATCH}{query}{C.RESET}")
                print(f"  {C.DIM}{n:4d}{C.RESET}  {hi}")
            print()

    else:
        try:
            limit = int(flag)
            _history_print_all(limit)
        except ValueError:
            print_error(f"Nieznana flaga: {flag}  "
                        f"(dostepne: -c/-s/-d/-r/-g/--export/--stats/liczba)")

def _history_print_all(limit: int = 0):
    """Drukuje historie (ostatnie limit wpisow lub wszystkie)."""
    entries = HISTORY[-limit:] if limit > 0 else HISTORY
    start   = max(1, len(HISTORY) - limit + 1) if limit > 0 else 1
    show_ts = cfg("history_timestamps", False)
    for i, cmd in enumerate(entries, start):
        if show_ts and "\t" in cmd:
            ts, _, raw = cmd.partition("\t")
            print(f"  {C.DIM}{i:4d}  {ts}{C.RESET}  {raw}")
        else:
            print(f"  {C.DIM}{i:4d}{C.RESET}  {cmd}")

def _history_export(dest: str | None = None):
    """Eksportuje historię do pliku tekstowego."""
    save_path = cfg("save_path_exports", "") or cfg("save_path_default", "")
    if dest:
        out_path = Path(dest).expanduser()
    elif save_path:
        out_path = Path(save_path).expanduser() / "terminalx_history_export.txt"
    else:
        out_path = Path("terminalx_history_export.txt")

    ts_now = datetime.datetime.now().strftime("%Y-%m-%d %H:%M:%S")
    try:
        with out_path.open("w", encoding="utf-8") as f:
            f.write(f"# TerminalX historia  —  eksport {ts_now}\n")
            f.write(f"# Wpisow: {len(HISTORY)}\n\n")
            for i, cmd in enumerate(HISTORY, 1):
                f.write(f"{i:4d}  {cmd}\n")
        print_info(f"Historia ({len(HISTORY)} wpisow) zapisana: {out_path}")
    except Exception as e:
        print_error(f"Blad eksportu historii: {e}")

def _history_stats():
    """Wyswietla statystyki historii — najczesciej uzywane komendy."""
    if not HISTORY:
        print_info("Historia jest pusta.")
        return

    from collections import Counter
    # Zlicz pierwsze slowo komendy (nazwa komendy)
    cmd_counts: Counter = Counter()
    for entry in HISTORY:
        raw = entry.partition("\t")[2] if "\t" in entry else entry
        first = raw.strip().split()[0] if raw.strip().split() else ""
        if first:
            cmd_counts[first] += 1

    total = len(HISTORY)
    top   = cmd_counts.most_common(15)
    w     = min(terminal_width() - 2, 56)
    print()
    print(box_top(f"Statystyki historii  ({total} wpisow)", width=w, color=C.INFO))
    for rank, (cmd, count) in enumerate(top, 1):
        bar_len = int(count / top[0][1] * 20)
        bar     = "█" * bar_len + "░" * (20 - bar_len)
        pct     = count / total * 100
        print(box_row(
            f"  {C.DIM}{rank:2d}.{C.RESET} {C.INFO}{cmd:<16}{C.RESET} "
            f"{C.DIM}{bar}{C.RESET}  {count:4d} ({pct:.1f}%)",
            width=w, color=C.INFO))
    print(box_bottom(width=w, color=C.INFO))
    print()

def prompt_current() -> str:
    """Zwraca aktualny prompt (uzywany przy Ctrl+R re-exec)."""
    prefix = "TerminalX(root)" if IS_ROOT else "TerminalX"
    symbol = "#" if IS_ROOT else "$"
    return (f"{C.PROMPT}{prefix}{C.RESET}"
            f":{C.PATH}{Path.cwd()}{C.RESET}"
            f"{symbol} ")

@command("alias", "Zarzadzaj aliasami")
def cmd_alias(args):
    """
    alias              - lista wszystkich aliasow
    alias nazwa=cmd    - ustaw alias
    """
    if not args:
        for name, value in ALIASES.items():
            print(f"{C.INFO}{name}{C.RESET}='{value}'")
        return
    for spec in args:
        if "=" not in spec:
            print_error("Uzycie: alias nazwa=komenda")
            continue
        name, value = spec.split("=", 1)
        ALIASES[name.strip()] = value.strip()
        print_info(f"Alias ustawiony: {name}='{value}'")

@command("unalias", "Usun alias")
def cmd_unalias(args):
    if not args:
        print_error("Uzycie: unalias <nazwa>")
        return
    for name in args:
        if ALIASES.pop(name, None) is None:
            print_error(f"Brak aliasu: {name}")
        else:
            print_info(f"Usunieto alias: {name}")

@command("grep", "Przeszukaj pliki wg wzorca (regex)",
         flags=["-r", "-i", "-n", "-l"])
def cmd_grep(args):
    """
    grep [-r] [-i] [-n] [-l] <wzorzec> [<plik/katalog> ...]

    Opcje:
      -r   przeszukuj rekurencyjnie
      -i   ignoruj wielkosc liter
      -n   wyswietl numery linii
      -l   wyswietl tylko nazwy plikow z dopasowaniami
    """
    if not args:
        print_error("Uzycie: grep [-r] [-i] [-n] [-l] <wzorzec> [<plik> ...]")
        return

    recursive = ignore_case = show_lineno = files_only = False
    positional = []

    i = 0
    while i < len(args):
        a = args[i]
        if a in ("-r","--recursive"):   recursive   = True
        elif a in ("-i","--ignore-case"): ignore_case = True
        elif a in ("-n","--line-number"): show_lineno = True
        elif a in ("-l","--files-with-matches"): files_only = True
        elif a.startswith("-") and not a.startswith("--"):
            for ch in a[1:]:
                if ch == "r": recursive   = True
                elif ch == "i": ignore_case = True
                elif ch == "n": show_lineno = True
                elif ch == "l": files_only  = True
                else:
                    print_error(f"Nieznana flaga: -{ch}"); return
        else:
            positional.append(a)
        i += 1

    if not positional:
        print_error("Brak wzorca.")
        return

    pattern_str = positional[0]
    targets     = positional[1:] if len(positional) > 1 else ["."]
    flags_re    = re.IGNORECASE if ignore_case else 0

    try:
        pattern = re.compile(pattern_str, flags_re)
    except re.error as e:
        print_error(f"Nieprawidlowy regex: {e}")
        return

    def highlight(line):
        return re.sub(pattern_str,
                      lambda m: f"{C.MATCH}{m.group(0)}{C.RESET}",
                      line, flags=flags_re)

    def search_file(fp: Path, show_fname: bool):
        try:
            with fp.open("r", encoding="utf-8", errors="replace") as f:
                lines = f.readlines()
        except Exception as e:
            print_error(f"{fp}: {e}")
            return
        for lineno, line in enumerate(lines, 1):
            if pattern.search(line):
                if files_only:
                    print(f"{C.DIR}{fp}{C.RESET}")
                    return
                prefix = (f"{C.DIR}{fp}{C.RESET}:" if show_fname else "") + \
                         (f"{C.INFO}{lineno}{C.RESET}:" if show_lineno else "")
                print(prefix + highlight(line.rstrip("\n")))

    def collect(t):
        p = Path(t).expanduser()
        if p.is_file():   return [p]
        if p.is_dir():
            return list(p.rglob("*") if recursive else
                        [f for f in p.iterdir() if f.is_file()])
        return list(Path(".").glob(t))

    all_files = []
    for t in targets:
        all_files.extend(collect(t))
    all_files = [f for f in all_files if f.is_file()]

    for fp in all_files:
        search_file(fp, len(all_files) > 1)

@command("find", "Przeszukaj drzewo katalogow",
         flags=["-name", "-type", "-mtime", "-size"])
def cmd_find(args):
    """
    find [<katalog>] [-name <wzorzec>] [-type f|d] [-mtime <dni>] [-size <bajty>]

    Przyklad:
      find . -name "*.py" -type f
      find /var/log -mtime 7
    """
    start    = Path.cwd()
    name_pat = type_f = mtime_days = min_size = None
    remaining = list(args)

    if remaining and not remaining[0].startswith("-"):
        start = Path(remaining.pop(0)).expanduser()

    i = 0
    while i < len(remaining):
        a = remaining[i]
        if a == "-name"  and i+1 < len(remaining): name_pat   = remaining[i+1]; i += 2
        elif a == "-type"  and i+1 < len(remaining): type_f     = remaining[i+1]; i += 2
        elif a == "-mtime" and i+1 < len(remaining):
            try: mtime_days = int(remaining[i+1])
            except ValueError: print_error("-mtime wymaga liczby"); return
            i += 2
        elif a == "-size"  and i+1 < len(remaining):
            try: min_size = int(remaining[i+1])
            except ValueError: print_error("-size wymaga liczby (bajty)"); return
            i += 2
        else: print_error(f"Nieznana opcja: {a}"); return

    if not start.exists():
        print_error(f"Katalog nie istnieje: {start}"); return

    now = datetime.datetime.now().timestamp()
    for entry in start.rglob("*"):
        if type_f == "f" and not entry.is_file(): continue
        if type_f == "d" and not entry.is_dir():  continue
        if name_pat and not fnmatch.fnmatch(entry.name, name_pat): continue
        if mtime_days is not None:
            if (now - entry.stat().st_mtime) / 86400 > mtime_days: continue
        if min_size is not None:
            if not entry.is_file() or entry.stat().st_size < min_size: continue
        color = C.DIR if entry.is_dir() else (C.EXEC if os.access(entry,os.X_OK) else ext_color(entry.suffix))
        print(f"{color}{entry}{C.RESET}")

@command("help", "Wyswietl pomoc", aliases=["?"])
def cmd_help(args):
    """
    help          - lista wszystkich komend
    help <cmd>    - szczegolowa pomoc dla komendy
    """
    if args:
        name = args[0]
        cdef = BUILTINS.get(name)
        if cdef is None:
            print_error(f"Nieznana komenda: {name}")
            return
        print(cdef.usage())
        return

    # Grupowanie: eliminuj aliasy (pokaz tylko glowna nazwe)
    seen   = set()
    groups = {}
    for name, cdef in sorted(BUILTINS.items()):
        if id(cdef) in seen:
            continue
        seen.add(id(cdef))
        groups.setdefault(name[0].upper(), []).append(cdef)

    w = terminal_width() - 2
    print()
    print(box_top("Dostepne komendy  ·  help <cmd> = szczegoly", width=w, color=C.PROMPT))
    for letter in sorted(groups):
        print(box_sep(width=w, color=C.PROMPT))
        print(box_row(f"{C.BOLD}{letter}{C.RESET}", width=w, color=C.PROMPT))
        for cdef in groups[letter]:
            aliases = f" {C.DIM}[{', '.join(cdef.aliases)}]{C.RESET}" if cdef.aliases else ""
            row = f"  {C.INFO}{cdef.name:<14}{C.RESET} {cdef.description}{aliases}"
            print(box_row(row, width=w, color=C.PROMPT))
    print(box_bottom(width=w, color=C.PROMPT))
    print()

# SUDO

ROOT_LOG: list = []   # historia komend wykonanych jako root

def _root_guard(op: str, target: str) -> bool:
    """Pyta o potwierdzenie dla operacji niszczacych w trybie root."""
    if not IS_ROOT:
        return True
    try:
        ans = input(f"{C.ERROR}[ROOT]{C.RESET} {op} {C.BOLD}{target}{C.RESET} — na pewno? [t/N] ").strip().lower()
        return ans in ("t", "tak", "y", "yes")
    except (EOFError, KeyboardInterrupt):
        return False

@command("sudo", "Uruchom komende jako root lub przelacz do trybu root",
         flags=["-s", "-l", "-u"])
def cmd_sudo(args):
    """
    sudo -s              - przelacz do trybu root (do exit aby powrocic)
    sudo -l              - pokaz log komend wykonanych jako root
    sudo <komenda>       - wykonaj jedna komende z uprawnieniami root
    """
    if not args:
        print_error("Uzycie: sudo <komenda> | sudo -s | sudo -l")
        return

    if args[0] == "-s":
        _STATE.is_root = True
        print(f"{C.ERROR}[ROOT]{C.RESET} Przelaczono do trybu root. "
              f"Wpisz {C.BOLD}exit{C.RESET} aby powrocic.")
        return

    if args[0] == "-l":
        if not ROOT_LOG:
            print_info("Brak wpisow w logu root.")
        else:
            print(f"{C.BOLD}Log komend root ({len(ROOT_LOG)} wpisow):{C.RESET}")
            for ts, cmd_str in ROOT_LOG:
                print(f"  {C.DIM}{ts}{C.RESET}  {cmd_str}")
        return

    # Jednorazowe sudo: tymczasowo ustaw IS_ROOT, wykonaj, przywroc
    was_root = IS_ROOT
    _STATE.is_root = True
    ts = datetime.datetime.now().strftime("%Y-%m-%d %H:%M:%S")
    ROOT_LOG.append((ts, " ".join(args)))
    try:
        tokens = expand_aliases(list(args))
        if not dispatch(tokens[0], tokens[1:]):
            run_external(tokens)
    finally:
        _STATE.is_root = was_root

@command("whoami", "Wyswietl biezacego uzytkownika")
def cmd_whoami(args):
    """Wyswietla 'root' w trybie root, 'user' w trybie normalnym."""
    if IS_ROOT:
        print(f"{C.ERROR}root{C.RESET}")
    else:
        import getpass
        try:
            print(getpass.getuser())
        except Exception:
            print("user")

# PLUGINS

class ShellAPI:
    """
    API przekazywane do pluginow.

    Przyklad pluginu (~/.terminalx_plugins/hello.py):

        def register(api):
            @api.command("hello", "Przywitaj uzytkownika")
            def cmd_hello(args):
                name = args[0] if args else "swiecie"
                api.print_info(f"Czesc, {name}!")

        def unregister(api):
            api.unregister_command("hello")
    """

    # --- rejestracja komend ---

    def register_command(self, name: str, func,
                         description: str = "", aliases: list = None,
                         flags: list = None):
        """Rejestruje funkcje jako komende shella (stary styl)."""
        cdef = CommandDef(func, name, description, aliases=aliases, flags=flags)
        BUILTINS[name] = cdef
        for a in (aliases or []):
            BUILTINS[a] = cdef
        return cdef

    def command(self, name: str, description: str = "",
                aliases: list = None, flags: list = None):
        """Dekorator do rejestrowania komend (nowy styl ZSH-like).

        Przyklad:
            @api.command("hello", "Przywitaj")
            def cmd(args):
                print("Czesc!")
        """
        return command(name, description=description,
                       aliases=aliases, flags=flags)

    def unregister_command(self, name: str):
        """Usuwa komende z BUILTINS (uzywaj w unregister())."""
        cdef = BUILTINS.pop(name, None)
        if cdef and cdef.aliases:
            for a in cdef.aliases:
                BUILTINS.pop(a, None)

    # --- dostep do stanu shella ---

    @property
    def is_root(self) -> bool:
        return IS_ROOT

    @property
    def cwd(self) -> Path:
        return Path.cwd()

    @property
    def history(self) -> list:
        return HISTORY

    @property
    def aliases(self) -> dict:
        return ALIASES

    @property
    def builtins(self) -> dict:
        return BUILTINS

    # --- wyjscie ---

    def print_error(self, msg: str, hint: str = ""):   print_error(msg, hint)
    def print_info(self, msg: str):                    print_info(msg)
    def print_raw(self, msg):     print(msg)

    # --- hooki ---

    @property
    def plugin_api_version(self) -> tuple:
        return PLUGIN_API_VERSION

    @property
    def shell_version(self) -> str:
        return SHELL_VERSION

    def add_hook(self, event: str, fn) -> bool:
        """
        Rejestruje funkcje-hook na zdarzenie shella.
        Zdarzenia: before_cmd, after_cmd, on_load, on_unload, on_start
        Zwraca True jesli zarejestrowano, False jesli nieznane zdarzenie.
        """
        if event not in PLUGIN_HOOKS:
            return False
        if fn not in PLUGIN_HOOKS[event]:
            PLUGIN_HOOKS[event].append(fn)
        return True

    def remove_hook(self, event: str, fn) -> bool:
        """Usuwa wczesniej zarejestrowany hook."""
        if event in PLUGIN_HOOKS and fn in PLUGIN_HOOKS[event]:
            PLUGIN_HOOKS[event].remove(fn)
            return True
        return False

# PLUGIN_SECURITY
#
#  Trzy filary bezpieczenstwa systemu pluginow:
#
#  1. SANDBOX — izolowane srodowisko uruchomieniowe
#     Kazdy plugin wykonuje sie z ograniczonym zestawem builtins.
#     Poziomy: off | warn | strict
#       off    — bez ograniczen (domyslne dla wstecznej kompatybilnosci)
#       warn   — pelny dostep ale ostrzezenia o ryzykownych operacjach
#       strict — wyłączone: exec/eval/compile/__import__/open (poza .TerminalX_*)
#
#  2. PODPISY CYFROWE (HMAC-SHA256)
#     Kazdy plugin moze miec plik .sig z podpisem HMAC-SHA256.
#     Klucz jest generowany lokalnie przy pierwszym uzyciu (nie opuszcza urzadzenia).
#     Stany: trusted | unsigned | tampered | revoked
#
#  3. REPOZYTORIUM PLUGINOW
#     Lokalne i zdalne repozytoria z indeksem JSON.
#     plugin repo add <url|sciezka>  — dodaj repo
#     plugin repo list               — lista repo
#     plugin repo fetch              — odswiez indeksy
#     plugin repo search <query>     — szukaj pluginow
#     plugin repo install <nazwa>    — pobierz i zainstaluj plugin z repo
#

# ─── Poziomy sandboxu ────────────────────────────────────────────────────────
_SANDBOX_LEVELS = ("off", "warn", "strict")

# Niebezpieczne builtins blokowane w trybie strict
_SANDBOX_BLOCKED_BUILTINS = frozenset([
    "exec", "eval", "compile", "__import__", "open",
    "breakpoint", "memoryview", "vars", "globals",
])

# Ostrzezenia w trybie warn (nie blokowane, tylko logowane)
_SANDBOX_WARN_BUILTINS = frozenset([
    "exec", "eval", "compile", "__import__", "open",
])

# Nazwy modulow systemowych — ostrzezenie jesli plugin je importuje
_SANDBOX_RISKY_MODULES = frozenset([
    "subprocess", "socket", "ctypes", "multiprocessing",
    "threading", "os", "sys", "shutil", "pty", "signal",
])

def _sandbox_level() -> str:
    """Zwraca aktywny poziom piaskownicy z konfiguracji."""
    lvl = cfg("plugin_sandbox", "warn") if "_CONFIG" in globals() else "warn"
    return lvl if lvl in _SANDBOX_LEVELS else "warn"

def _sandbox_make_builtins(plugin_name: str) -> dict | None:
    """
    Buduje slownik builtins dla danego poziomu sandboxu.
    Zwraca None jesli poziom 'off' (brak ograniczen).
    """
    lvl = _sandbox_level()
    if lvl == "off":
        return None

    import builtins as _builtins_mod
    safe = dict(vars(_builtins_mod))

    if lvl == "strict":
        for name in _SANDBOX_BLOCKED_BUILTINS:
            safe.pop(name, None)
        # Zastap __import__ wersja logujaca
        _original_import = safe.get("__import__", __builtins__.__class__.__import__
                                    if hasattr(__builtins__, "__class__") else __import__)

        def _blocked_import(name, *a, **kw):
            # Zezwól na stdlib jeśli plugin_name jest zaufany przez whitelist
            log_security(f"sandbox:strict blok import '{name}' przez plugin '{plugin_name}'")
            raise ImportError(
                f"[sandbox:strict] Plugin '{plugin_name}' probowal importowac '{name}'. "
                f"Oryginalny __import__: {getattr(_original_import, '__module__', '?')}. "
                f"Zezwol w konfiguracji: config set plugin_sandbox warn")
        safe["__import__"] = _blocked_import

        # Zastap open wersja ograniczona do katalogu pluginow
        def _safe_open(file, mode="r", *a, **kw):
            p = Path(str(file)).resolve()
            allowed_roots = [PLUGINS_DIR.resolve(), PLUGIN_REPO_DIR.resolve(), _BASE.resolve()]
            if not any(str(p).startswith(str(root)) for root in allowed_roots):
                raise PermissionError(
                    f"[sandbox:strict] Plugin '{plugin_name}' probowal otworzyc plik "
                    f"poza katalogiem pluginow: {p}")
            import builtins as _b
            return _b.open(file, mode, *a, **kw)
        safe["open"] = _safe_open

    elif lvl == "warn":
        # Owijamy ryzykowne builtins w logujace wrappers
        orig_import = safe.get("__import__", __import__)

        def _warn_import(name, *a, **kw):
            if name in _SANDBOX_RISKY_MODULES:
                log_info(f"[sandbox:warn] Plugin '{plugin_name}' importuje ryzykowny modul: {name}")
                _log("WARN", f"plugin '{plugin_name}' import '{name}'")
            return orig_import(name, *a, **kw)
        safe["__import__"] = _warn_import

    return safe

def _sandbox_scan_source(source: str, plugin_name: str) -> list[str]:
    """
    Skanuje zrodlo pluginu i zwraca liste ostrzezen.
    Nie blokuje — tylko informuje.
    """
    warnings = []
    risky_patterns = [
        (r'\bsubprocess\s*\.\s*(run|Popen|call|check_output)',
         "uruchamia zewnetrzne procesy"),
        (r'\bsocket\s*\.\s*socket\b',
         "tworzy polaczenie sieciowe"),
        (r'\bos\s*\.\s*(system|popen|execv|execle|execvp)',
         "wykonuje polecenia systemowe"),
        (r'\bopen\s*\(.*[\'\"](w|a|wb|ab)',
         "zapisuje pliki"),
        (r'\bctypes\b',
         "uzywa ctypes (dostep do pamieci)"),
        (r'\beval\s*\(',
         "uzywa eval()"),
        (r'\bexec\s*\(',
         "uzywa exec()"),
        (r'__import__\s*\(',
         "uzywa __import__()"),
        (r'urllib|requests|http\.client',
         "wykonuje zadania sieciowe"),
    ]
    for pattern, description in risky_patterns:
        if re.search(pattern, source):
            warnings.append(description)
    return warnings

# ─── Podpisy cyfrowe pluginow (HMAC-SHA256) ──────────────────────────────────

_TRUST_DB: dict   = _STATE.trust_db
_TRUST_KEY: bytes = _STATE.trust_key

_TRUST_KEY_FILE = _BASE / ".terminalx_plugin_key"   # 256-bit klucz lokalny

def _trust_key_load() -> bytes:
    """
    Laduje lub generuje lokalny klucz podpisywania HMAC-SHA256.
    Klucz jest generowany raz i trzymany w pliku (chmod 600).
    Nigdy nie opuszcza urzadzenia — sluzy do weryfikacji lokalnych pluginow.
    """
    if _TRUST_KEY:
        return _TRUST_KEY
    try:
        if _TRUST_KEY_FILE.exists():
            _STATE.trust_key = bytes.fromhex(_TRUST_KEY_FILE.read_text().strip())
        else:
            import secrets
            _STATE.trust_key = secrets.token_bytes(32)
            _TRUST_KEY_FILE.write_text(_TRUST_KEY.hex())
            try:
                _TRUST_KEY_FILE.chmod(0o600)
            except Exception:
                pass   # Windows nie wspiera chmod — ignoruj
            log_info("Wygenerowano nowy klucz podpisywania pluginow.")
    except Exception as e:
        log_error(f"_trust_key_load: {e} — generuje klucz tymczasowy")
        import secrets
        _STATE.trust_key = secrets.token_bytes(32)
    return _TRUST_KEY

def _trust_db_load():
    """Wczytuje baze zaufanych pluginow z PLUGIN_TRUST_DB."""
    if PLUGIN_TRUST_DB.exists():
        try:
            _STATE.trust_db = json.loads(PLUGIN_TRUST_DB.read_text(encoding="utf-8"))
        except Exception:
            _STATE.trust_db = {}

def _trust_db_save():
    """Zapisuje baze zaufanych pluginow."""
    try:
        PLUGIN_TRUST_DB.write_text(
            json.dumps(_TRUST_DB, indent=2, ensure_ascii=False), encoding="utf-8")
    except Exception as e:
        log_error(f"_trust_db_save: {e}")

def _plugin_hash(file: Path) -> str:
    """Oblicza SHA-256 pliku pluginu."""
    h = hashlib.sha256()
    try:
        with file.open("rb") as f:
            for chunk in iter(lambda: f.read(65536), b""):
                h.update(chunk)
    except Exception:
        return ""
    return h.hexdigest()

def _plugin_sign(file: Path) -> str:
    """
    Tworzy podpis HMAC-SHA256 pliku pluginu i zapisuje go do <plik>.sig.
    Zwraca hex podpisu lub "" przy bledzie.
    """
    key = _trust_key_load()
    try:
        data = file.read_bytes()
        sig  = _get_hmac().new(key, data, hashlib.sha256).hexdigest()
        sig_file = file.with_suffix(file.suffix + ".sig")
        sig_file.write_text(sig)
        return sig
    except Exception as e:
        log_error(f"_plugin_sign {file.name}: {e}")
        return ""

def _plugin_verify(file: Path) -> str:
    """
    Weryfikuje podpis pluginu.
    Zwraca status: 'trusted' | 'unsigned' | 'tampered' | 'revoked'
    """
    name = file.stem
    # Sprawdz czy odwolany
    entry = _TRUST_DB.get(name, {})
    if entry.get("status") == "revoked":
        return "revoked"

    sig_file = file.with_suffix(file.suffix + ".sig")
    if not sig_file.exists():
        return "unsigned"

    key = _trust_key_load()
    try:
        data     = file.read_bytes()
        stored   = sig_file.read_text().strip()
        expected = _get_hmac().new(key, data, hashlib.sha256).hexdigest()
        if _get_hmac().compare_digest(stored, expected):
            return "trusted"
        else:
            return "tampered"
    except Exception:
        return "unsigned"

def _plugin_trust(file: Path, sign: bool = True) -> bool:
    """
    Oznacza plugin jako zaufany: podpisuje i zapisuje w bazie.
    """
    name = file.stem
    sig  = _plugin_sign(file) if sign else _TRUST_DB.get(name, {}).get("sig", "")
    fhash = _plugin_hash(file)
    _TRUST_DB[name] = {
        "status":    "trusted",
        "hash":      fhash,
        "sig":       sig,
        "signed_at": datetime.datetime.now().isoformat(timespec="seconds"),
        "file":      str(file.resolve()),
    }
    _trust_db_save()
    return bool(sig)

def _plugin_revoke(name: str) -> bool:
    """Odwoluje zaufanie do pluginu (status 'revoked')."""
    if name not in _TRUST_DB:
        return False
    _TRUST_DB[name]["status"]    = "revoked"
    _TRUST_DB[name]["revoked_at"] = datetime.datetime.now().isoformat(timespec="seconds")
    _trust_db_save()
    return True

def _plugin_security_check(file: Path, silent: bool = False) -> bool:
    """
    Kompleksowy audyt bezpieczenstwa pluginu przed zaladowaniem.
    Zwraca True jezeli mozna ladowac, False jezeli nalezy przerwac.

    Logika:
      - strict sandbox + tampered/revoked → blokuj
      - strict sandbox + unsigned         → pytaj o zaufanie
      - warn sandbox  + tampered/revoked  → ostrzez, pytaj
      - warn sandbox  + unsigned          → info, kontynuuj
      - off sandbox                       → zawsze True
    """
    lvl = _sandbox_level()
    if lvl == "off":
        return True

    # Weryfikacja podpisu
    status = _plugin_verify(file)

    # Skan zrodla
    try:
        source   = file.read_text(encoding="utf-8", errors="replace")
        scan_w   = _sandbox_scan_source(source, file.stem)
    except Exception:
        scan_w = []

    if status == "trusted" and not scan_w:
        return True   # szybka sciezka — zaufany i czysty

    w = min(terminal_width() - 2, 70)

    # Status ikon
    status_icons = {
        "trusted":  f"{C.PATH}✔ zaufany{C.RESET}",
        "unsigned": f"{C.INFO}? niepodpisany{C.RESET}",
        "tampered": f"{C.ERROR}✘ zmodyfikowany (UWAGA!){C.RESET}",
        "revoked":  f"{C.ERROR}✘ odwolany{C.RESET}",
    }

    # Zawsze blokuj odwolane
    if status == "revoked":
        print()
        print(box_top(f"[SANDBOX] Zablokowano plugin: {file.name}", width=w, color=C.ERROR))
        print(box_row(f"  Status: {status_icons['revoked']}", width=w, color=C.ERROR))
        print(box_row(f"  {C.DIM}Plugin jest na liscie odwolanych. Uzyj: plugin trust {file.stem} --force{C.RESET}",
                      width=w, color=C.ERROR))
        print(box_bottom(width=w, color=C.ERROR))
        print()
        log_security(f"[sandbox] Zablokowano odwolany plugin: {file.name}")
        return False

    # Blokuj zmodyfikowane w trybie strict
    if status == "tampered":
        print()
        print(box_top(f"[SANDBOX] Ostrzezenie: {file.name}", width=w, color=C.ERROR))
        print(box_row(f"  Status: {status_icons['tampered']}", width=w, color=C.ERROR))
        print(box_row(f"  {C.DIM}Plik zmieniony od ostatniego podpisania!{C.RESET}",
                      width=w, color=C.ERROR))
        if lvl == "strict":
            print(box_row(f"  {C.DIM}Tryb strict: ladowanie zablokowane.{C.RESET}",
                          width=w, color=C.ERROR))
            print(box_row(f"  {C.DIM}Podpisz ponownie: plugin trust {file.stem}{C.RESET}",
                          width=w, color=C.ERROR))
            print(box_bottom(width=w, color=C.ERROR))
            print()
            log_security(f"[sandbox:strict] Zablokowano zmodyfikowany plugin: {file.name}")
            return False
        # warn — ostrzez i pytaj
        print(box_row(f"  {C.DIM}Tryb warn: mozesz zaladowac na wlasna odpowiedzialnosc.{C.RESET}",
                      width=w, color=C.ERROR))
        print(box_bottom(width=w, color=C.ERROR))
        print()
        if silent:
            return False
        try:
            ans = input(f"  Zaladowac mimo to? [t/N] ").strip().lower()
        except (EOFError, KeyboardInterrupt):
            ans = "n"
        return ans in ("t", "tak", "y", "yes")

    # Nieoznaczone ostrzezenia skanu
    if scan_w:
        color = C.ERROR if lvl == "strict" else C.INFO
        print()
        print(box_top(f"[SANDBOX] Skan pluginu: {file.name}", width=w, color=color))
        print(box_row(f"  Status: {status_icons.get(status, status)}", width=w, color=color))
        print(box_row(f"  {C.BOLD}Wykryte ryzykowne operacje:{C.RESET}", width=w, color=color))
        for warn in scan_w:
            print(box_row(f"    {C.DIM}• {warn}{C.RESET}", width=w, color=color))
        if lvl == "strict" and status != "trusted":
            print(box_row(f"  {C.DIM}Tryb strict: wymagane podpisanie. plugin trust {file.stem}{C.RESET}",
                          width=w, color=color))
            print(box_bottom(width=w, color=color))
            print()
            return False
        print(box_row(f"  {C.DIM}Aby oznaczyc jako zaufany: plugin trust {file.stem}{C.RESET}",
                      width=w, color=color))
        print(box_bottom(width=w, color=color))
        print()

    # Unsigned w strict — wymagaj potwierdzenia
    if status == "unsigned" and lvl == "strict":
        print()
        print(box_top(f"[SANDBOX:strict] Plugin niepodpisany: {file.name}", width=w, color=C.ERROR))
        print(box_row(f"  {C.DIM}Podpisz: plugin trust {file.stem}{C.RESET}", width=w, color=C.ERROR))
        print(box_bottom(width=w, color=C.ERROR))
        print()
        return False

    return True

# ─── Ladowanie bazy zaufania przy starcie ────────────────────────────────────
_trust_db_load()
_trust_key_load()

# ─── Repozytorium pluginow ───────────────────────────────────────────────────

_PLUGIN_REPOS: list[dict] = _STATE.plugin_repos
_PLUGIN_REPO_CACHE: dict  = _STATE.plugin_repo_cache

_BUILTIN_REPOS = [
    {
        "name":       "local",
        "url":        str(PLUGINS_DIR),
        "type":       "local",
        "description":"Lokalne pluginy z katalogu ~/.terminalx_plugins/",
        "last_fetch": None,
    },
]

def _repo_config_path() -> Path:
    return PLUGIN_REPO_DIR / "repos.json"

def _repo_load():
    """Wczytuje liste repozytoriow z pliku konfiguracyjnego."""
    PLUGIN_REPO_DIR.mkdir(parents=True, exist_ok=True)
    cfg_path = _repo_config_path()
    if cfg_path.exists():
        try:
            _STATE.plugin_repos = json.loads(cfg_path.read_text(encoding="utf-8"))
        except Exception:
            _STATE.plugin_repos = []
    # Zawsze upewnij sie ze 'local' jest na liscie
    names = {r["name"] for r in _PLUGIN_REPOS}
    for br in _BUILTIN_REPOS:
        if br["name"] not in names:
            _PLUGIN_REPOS.insert(0, dict(br))

def _repo_save():
    """Zapisuje liste repozytoriow."""
    try:
        _repo_config_path().write_text(
            json.dumps(_PLUGIN_REPOS, indent=2, ensure_ascii=False), encoding="utf-8")
    except Exception as e:
        log_error(f"_repo_save: {e}")

def _repo_fetch_one(repo: dict) -> list[dict]:
    """
    Pobiera indeks jednego repozytorium.
    Zwraca liste pluginow: [{name, version, description, url, author, tags}]
    """
    rtype = repo.get("type", "local")
    url   = repo.get("url", "")

    if rtype == "local":
        # Indeks z lokalnego katalogu
        plugins = []
        p = Path(url)
        if p.is_dir():
            for f in sorted(p.glob("*.py")):
                if f.name.startswith("_"):
                    continue
                entry = {
                    "name":        f.stem,
                    "version":     "?",
                    "description": "",
                    "url":         str(f.resolve()),
                    "author":      "",
                    "tags":        [],
                    "type":        "local",
                    "repo":        repo["name"],
                }
                # Parsuj metadane pluginu jednym przejściem (skompilowany wzorzec)
                try:
                    _psrc = f.read_text(encoding="utf-8", errors="replace")
                    for _pm in _RE_PLUGIN_META.finditer(_psrc):
                        if _pm.group("version"):
                            entry["version"] = _pm.group("version")
                        elif _pm.group("description"):
                            entry["description"] = _pm.group("description")
                        elif _pm.group("author"):
                            entry["author"] = _pm.group("author")
                except Exception:  # ignorowane celowo
                    pass
                plugins.append(entry)
        return plugins

    elif rtype in ("http", "https", "remote"):
        # Zdalny indeks JSON
        if not is_online():
            log_info(f"_repo_fetch_one: pominieto repo '{repo.get('name','')}' — tryb offline")
            return []
        index_url = url.rstrip("/") + "/index.json"
        try:
            req = _get_urllib_request().Request(
                index_url,
                headers={"User-Agent": f"TerminalX/{SHELL_VERSION}"},
            )
            with _get_urllib_request().urlopen(req, timeout=10) as resp:
                data = json.loads(resp.read().decode("utf-8"))
            plugins = data.get("plugins", [])
            # Normalizuj — uzupelnij pole 'repo'
            for p in plugins:
                p.setdefault("repo", repo["name"])
                p.setdefault("type", "remote")
            return plugins
        except _get_urllib_error().URLError as e:
            print_error(f"Repo '{repo['name']}': blad sieci — {e}")
        except Exception as e:
            print_error(f"Repo '{repo['name']}': {e}")
        return []

    return []

def _repo_fetch_all(silent: bool = False) -> int:
    """Odswieza indeks wszystkich repozytoriow. Zwraca liczbe pluginow."""
    # Nie wysylaj zadnych zapytan gdy shell jest w trybie offline
    if not is_online():
        if not silent:
            print_error("Tryb OFFLINE — aktualizacja repozytoriow niedostepna.",
                        "Uruchom 'mode online' aby wlaczyc tryb online.")
        log_info("_repo_fetch_all: pominieto — tryb offline")
        return 0
    _repo_load()
    total = 0
    for repo in _PLUGIN_REPOS:
        if not silent:
            print_info(f"Fetching repo: {repo['name']} ({repo.get('url','')})")
        plugins = _repo_fetch_one(repo)
        _PLUGIN_REPO_CACHE[repo["name"]] = plugins
        repo["last_fetch"] = datetime.datetime.now().isoformat(timespec="seconds")
        total += len(plugins)
    _repo_save()
    # Zapisz scalony indeks
    try:
        all_plugins = []
        for plist in _PLUGIN_REPO_CACHE.values():
            all_plugins.extend(plist)
        PLUGIN_REPO_INDEX.write_text(
            json.dumps({"plugins": all_plugins,
                        "updated": datetime.datetime.now().isoformat()},
                       indent=2, ensure_ascii=False),
            encoding="utf-8")
    except Exception:  # ignorowane celowo
        pass
    return total

def _repo_search(query: str) -> list[dict]:
    """Przeszukuje cache repozytoriow. Zwraca pasujace pluginy."""
    q = query.lower()
    results = []
    for plist in _PLUGIN_REPO_CACHE.values():
        for p in plist:
            if (q in p.get("name", "").lower() or
                    q in p.get("description", "").lower() or
                    any(q in t.lower() for t in p.get("tags", []))):
                results.append(p)
    return results

def _repo_install(plugin_entry: dict, api) -> bool:
    """
    Instaluje plugin z repozytorium do katalogu pluginow.
    Lokalne: symlink lub kopia. Zdalne: pobierz i sprawdz.
    """
    ptype  = plugin_entry.get("type", "local")
    pname  = plugin_entry.get("name", "unknown")
    purl   = plugin_entry.get("url", "")
    dest   = PLUGINS_DIR / f"{pname}.py"

    if dest.exists():
        print_error(f"Plugin '{pname}' juz istnieje: {dest}",
                    "Uzyj 'plugin unload' + 'plugin repo install' aby zaktualizowac.")
        return False

    if ptype == "local":
        src = Path(purl)
        if not src.exists():
            print_error(f"Zrodlo nie istnieje: {src}")
            return False
        try:
            shutil.copy2(src, dest)
            print_info(f"Zainstalowano plugin '{pname}' z lokalnego repo.")
        except Exception as e:
            print_error(f"Blad instalacji: {e}")
            return False

    elif ptype in ("remote", "http", "https"):
        # Sprawdz tryb offline przed pobraniem
        if not is_online():
            print_error(
                f"Nie mozna pobrac pluginu '{pname}' — shell dziala w trybie offline.",
                "Uruchom 'mode online' aby wlaczyc dostep do sieci.")
            log_info(f"_repo_install: zablokowano pobieranie '{pname}' — tryb offline")
            return False
        try:
            print_info(f"Pobieranie: {purl}")
            req = _get_urllib_request().Request(
                purl,
                headers={"User-Agent": f"TerminalX/{SHELL_VERSION}"},
            )
            with _get_urllib_request().urlopen(req, timeout=15) as resp:
                raw = resp.read()
            # Weryfikacja rozmiaru (max 512 KB)
            if len(raw) > 512 * 1024:
                print_error(f"Plugin '{pname}' jest za duzy (>{512}KB) — odmowa instalacji.")
                return False
            dest.write_bytes(raw)
            print_info(f"Pobrano plugin '{pname}' ({len(raw)} B)")
        except _get_urllib_error().URLError as e:
            print_error(f"Blad pobierania: {e}")
            return False
        except Exception as e:
            print_error(f"Blad: {e}")
            return False

    # Podpisz swiezego pluginu lokalnym kluczem
    _plugin_trust(dest, sign=True)
    # Zaladuj
    return _load_single_plugin(dest, api)

# Inicjalne ladowanie repo-listy (bez fetcha — leniwie)
_repo_load()

def _extract_plugin_meta(module, file: Path, name: str) -> dict:
    """
    Wyciaga metadane pluginu.
    Priorytet:
      1. Slownik PLUGIN_META w module (zalecane)
      2. Zmienne modulowe __version__, __author__ itp.
      3. Docstring modulu
    """
    # Najpierw sprawdz slownik PLUGIN_META
    declared = getattr(module, "PLUGIN_META", None)
    meta: dict = {}
    if isinstance(declared, dict):
        meta.update(declared)

    # Uzupelnij brakujace pola ze zmiennych modulowych
    _fallbacks = {
        "name":        ("__plugin_name__",   name),
        "version":     ("__version__",       "0.0.0"),
        "author":      ("__author__",        ""),
        "description": ("__description__",   (module.__doc__ or "").strip().splitlines()[0]
                        if module.__doc__ else ""),
        "tags":        ("__tags__",          []),
        "requires_api":("__requires_api__",  (1, 0)),
        "homepage":    ("__homepage__",      ""),
        "license":     ("__license__",       ""),
    }
    for key, (attr, default) in _fallbacks.items():
        if key not in meta:
            meta[key] = getattr(module, attr, default)

    # Zawsze ustawiaj te pola systemowe
    meta["_name"]    = name
    meta["_file"]    = str(file.resolve())
    meta["_loaded"]  = datetime.datetime.now().isoformat(timespec="seconds")
    meta["_ok"]      = True
    return meta

def _check_plugin_api(meta: dict, name: str) -> bool:
    """Sprawdza czy plugin jest zgodny z biezaca wersja API."""
    req = meta.get("requires_api", (1, 0))
    if not isinstance(req, (tuple, list)) or len(req) < 2:
        return True
    if req[0] > PLUGIN_API_VERSION[0]:
        print_error(
            f"Plugin '{name}' wymaga API v{req[0]}.x, "
            f"dostepne v{PLUGIN_API_VERSION[0]}.{PLUGIN_API_VERSION[1]}",
            "Zaktualizuj TerminalXa lub uzyj starszej wersji pluginu.")
        return False
    return True

def _load_single_plugin(file: Path, api, silent: bool = False) -> bool:
    """
    Laduje jeden plik pluginu z kontrola bezpieczenstwa (sandbox + podpis).
    Przeplywy:
      1. _plugin_security_check() — weryfikacja podpisu i skan zrodla
      2. _sandbox_make_builtins() — izolowane builtins wg poziomu sandboxu
      3. exec_module() w izolowanym namespace
      4. rejestracja metadanych i hookow
    """
    # ── 1. Audyt bezpieczenstwa PRZED zaladowaniem ────────────────────────
    if not _plugin_security_check(file, silent=silent):
        return False

    # ── 2. Przygotowanie izolowanego srodowiska ───────────────────────────
    sandbox_builtins = _sandbox_make_builtins(file.stem)

    spec   = importlib.util.spec_from_file_location(file.stem, str(file))
    module = importlib.util.module_from_spec(spec)
    module.__file__ = str(file.resolve())

    # Wstrzyknij izolowane builtins jesli sandbox aktywny
    if sandbox_builtins is not None:
        module.__builtins__ = sandbox_builtins   # type: ignore[attr-defined]

    # Rejestruj w sys.modules
    sys.modules[f"_terminalx_plugin_{file.stem}"] = module

    try:
        spec.loader.exec_module(module)

        # ── 3. Walidacja metadanych i API ─────────────────────────────────
        meta = _extract_plugin_meta(module, file, file.stem)
        if not _check_plugin_api(meta, file.stem):
            sys.modules.pop(f"_terminalx_plugin_{file.stem}", None)
            return False

        # Zapisz info o sandboxie do metadanych
        meta["_sandbox_level"] = _sandbox_level()
        meta["_trust_status"]  = _plugin_verify(file)

        if hasattr(module, "register"):
            module.register(api)
        LOADED_PLUGINS[file.stem] = module
        PLUGIN_META[file.stem]    = meta

        # ── 4. Hooki on_load ──────────────────────────────────────────────
        for hook_fn in PLUGIN_HOOKS["on_load"]:
            try:    hook_fn(file.stem)
            except Exception:
                pass  # ignorowane celowo

        if not silent:
            ver      = meta.get("version", "")
            ver_str  = f" v{ver}" if ver and ver != "0.0.0" else ""
            author   = meta.get("author", "")
            auth_str = f"  {C.DIM}by {author}{C.RESET}" if author else ""
            trust    = meta["_trust_status"]
            trust_icons = {
                "trusted":  f" {C.PATH}[✔ zaufany]{C.RESET}",
                "unsigned": f" {C.INFO}[? niepodpisany]{C.RESET}",
                "tampered": f" {C.ERROR}[! zmieniony]{C.RESET}",
                "revoked":  f" {C.ERROR}[✘ odwolany]{C.RESET}",
            }
            trust_str = trust_icons.get(trust, "")
            print_info(f"Zaladowano plugin: {file.name}{ver_str}{auth_str}{trust_str}")
        return True

    except Exception as e:
        print_error(f"Blad pluginu {file.name}: {e}")
        write_crashlog(e, context=f"_load_single_plugin: {file.name}")
        sys.modules.pop(f"_terminalx_plugin_{file.stem}", None)
        return False

_EXAMPLE_PLUGIN = '''\
"""
Przykladowy plugin TerminalXa z pelna specyfikacja metadanych.
Umieszcz plik .py w ~/.terminalx_plugins/ — zostanie zaladowany automatycznie.
"""

# ── Metadane pluginu (zalecane) ───────────────────────────────────────────────
# Slownik PLUGIN_META jest odczytywany przez system pluginow TerminalXa.
# Wszystkie pola sa opcjonalne, ale zalecane dla dobrego 'plugin info'.

PLUGIN_META = {
    "name":         "example",           # krotka nazwa (bez spacji)
    "version":      "1.0.0",             # semver
    "author":       "Autor Pluginu",     # imie/nick
    "description":  "Przykladowy plugin pokazujacy mozliwosci API shella",
    "tags":         ["przyklad", "demo"],# dowolne tagi
    "requires_api": (2, 0),              # minimalna wersja API TerminalXa
    "homepage":     "",                  # URL repo/docs (opcjonalne)
    "license":      "MIT",               # licencja
}

# Alternatywnie mozna uzyc zmiennych modulowych (niższy priorytet niz PLUGIN_META):
# __version__     = "1.0.0"
# __author__      = "Autor"
# __description__ = "Opis"
# __tags__        = ["tag1"]
# __requires_api__= (2, 0)

def register(api):
    """
    Wywoływana przy ladowaniu pluginu.
    api — obiekt ShellAPI z metodami: command(), print_info(), print_error(),
          unregister_command(), is_root, cwd, history, aliases, builtins,
          add_hook(), shell_version, plugin_api_version
    """

    @api.command("hello", "Przywitaj uzytkownika [plugin przykladowy]",
                 aliases=["hi"])
    def cmd_hello(args):
        """
        hello [imie]   - wyswietla powitanie
        hello          - pyta o imie interaktywnie
        """
        name = " ".join(args) if args else input("Podaj imie: ").strip()
        api.print_info(f"Czesc, {name or 'swiecie\'}! (root={api.is_root})")

    @api.command("shellinfo", "Informacje o biezacym stanie shella")
    def cmd_shellinfo(args):
        api.print_raw(f"  Katalog    : {api.cwd}")
        api.print_raw(f"  Tryb root  : {api.is_root}")
        api.print_raw(f"  Komendy    : {len(api.builtins)}")
        api.print_raw(f"  Historia   : {len(api.history)} wpisow")
        api.print_raw(f"  Aliasy     : {len(api.aliases)}")
        api.print_raw(f"  API wersja : {api.plugin_api_version}")

    # Przyklad rejestracji hooka — wywolywany przed kazda komenda
    def my_before_hook(cmd_name, args):
        # Zwroc False zeby przerwac wykonanie komendy, True/None zeby kontynuowac
        pass  # mozna tu logowac, audytowac, walidowac, itp.

    api.add_hook("before_cmd", my_before_hook)

def unregister(api):
    """Wywoływana przy plugin unload / reload — posprzataj po sobie."""
    api.unregister_command("hello")
    api.unregister_command("shellinfo")
    # Usun hooki jesli zostaly zarejestrowane (opcjonalne — shell sam sprząta)
'''

def _ensure_plugins_dir():
    """Tworzy ~/.terminalx_plugins/ z przykladowym pluginem jesli nie istnieje."""
    PLUGINS_DIR.mkdir(parents=True, exist_ok=True)
    example = PLUGINS_DIR / "_example_plugin.py"
    if not example.exists():
        example.write_text(_EXAMPLE_PLUGIN, encoding="utf-8")
        print_info(f"Utworzono przykladowy plugin: {example}")

def load_plugins():
    if not cfg("autoload_plugins", True):
        return   # autoload wylaczony w konfiguracji
    _ensure_plugins_dir()
    api    = ShellAPI()
    silent = cfg("plugin_silent", False)
    loaded = 0
    for file in sorted(PLUGINS_DIR.glob("*.py")):
        if _load_single_plugin(file, api, silent=silent):
            loaded += 1
    if not silent and loaded > 0:
        log_info(f"load_plugins: zaladowano {loaded} plugin(ow)")

@command("plugin", "Zarzadzaj pluginami — sandbox, podpisy, repozytorium")
def cmd_plugin(args):
    """
    plugin list                      - zaladowane pluginy (z statusem zaufania)
    plugin info <nazwa>              - szczegoly, metadane, hooki, komendy
    plugin load <plik.py>            - zaladuj plugin z dowolnej sciezki
    plugin unload <nazwa>            - wyladuj plugin
    plugin reload [nazwa]            - hot-reload jednego lub wszystkich
    plugin dir                       - otworz katalog pluginow
    plugin meta [nazwa]              - surowe metadane jako JSON

    Bezpieczenstwo:
    plugin trust <nazwa> [--force]   - podpisz i oznacz jako zaufany
    plugin revoke <nazwa>            - odwolaj zaufanie do pluginu
    plugin verify [nazwa]            - sprawdz status podpisu (wszystkie jesli brak nazwy)
    plugin audit                     - pelny raport bezpieczenstwa wszystkich pluginow
    plugin sandbox [off|warn|strict] - pokaz lub zmien poziom sandboxu

    Repozytorium:
    plugin repo list                 - lista skonfigurowanych repozytoriow
    plugin repo add <url> [--name X] - dodaj repozytorium (lokalne lub zdalne URL)
    plugin repo remove <nazwa>       - usun repozytorium
    plugin repo fetch                - odswiez indeksy wszystkich repo
    plugin repo search <query>       - szukaj pluginow w repozytoriach
    plugin repo install <nazwa>      - pobierz i zainstaluj plugin z repo
    plugin repo info <nazwa>         - szczegoly pluginu w repo (jesli dostepne)
    """
    if not args:
        print_error("Uzycie: plugin list|info|load|unload|reload|dir|trust|verify|audit|sandbox|repo")
        return
    subcmd = args[0]
    api    = ShellAPI()

    # ── list ──────────────────────────────────────────────────────────────
    if subcmd == "list":
        if not LOADED_PLUGINS:
            print_info(f"Brak zaladowanych pluginow. Katalog: {PLUGINS_DIR}")
            return
        w = min(terminal_width() - 2, 76)
        print()
        print(box_top(f"Zaladowane pluginy  ({len(LOADED_PLUGINS)})  "
                      f"[sandbox: {_sandbox_level()}]", width=w, color=C.EXEC))
        trust_icons = {
            "trusted":  f"{C.PATH}✔{C.RESET}",
            "unsigned": f"{C.INFO}?{C.RESET}",
            "tampered": f"{C.ERROR}!{C.RESET}",
            "revoked":  f"{C.ERROR}✘{C.RESET}",
        }
        for pname, mod in LOADED_PLUGINS.items():
            src    = getattr(mod, "__file__", "?")
            meta   = PLUGIN_META.get(pname, {})
            trust  = meta.get("_trust_status", _plugin_verify(Path(src)) if src != "?" else "unsigned")
            ticon  = trust_icons.get(trust, "?")
            ver    = meta.get("version", "")
            ver_s  = f" v{ver}" if ver and ver != "0.0.0" else ""
            print(box_row(
                f" {ticon} {C.EXEC}{pname:<20}{C.RESET}{ver_s:<8} {C.DIM}{src}{C.RESET}",
                width=w, color=C.EXEC))
        print(box_sep(width=w, color=C.EXEC))
        print(box_row(
            f"  {C.DIM}✔ zaufany  ? niepodpisany  ! zmieniony  ✘ odwolany"
            f"   plugin verify — szczegoly{C.RESET}",
            width=w, color=C.EXEC))
        print(box_bottom(width=w, color=C.EXEC))
        print()

    # ── info ──────────────────────────────────────────────────────────────
    elif subcmd == "info":
        if len(args) < 2:
            print_error("Uzycie: plugin info <nazwa>"); return
        pname = args[1]
        if pname not in LOADED_PLUGINS:
            print_error(f"Plugin nie jest zaladowany: {pname}"); return
        mod  = LOADED_PLUGINS[pname]
        meta = PLUGIN_META.get(pname, {})
        w    = min(terminal_width() - 2, 72)
        print()
        print(box_top(f"Plugin: {pname}", width=w, color=C.EXEC))
        _mfields = [
            ("Nazwa",        meta.get("name", pname)),
            ("Wersja",       meta.get("version", "?")),
            ("Autor",        meta.get("author", "")),
            ("Opis",         meta.get("description",
                             (mod.__doc__ or "").strip().splitlines()[0] if mod.__doc__ else "")),
            ("Tagi",         ", ".join(meta.get("tags", []))),
            ("Licencja",     meta.get("license", "")),
            ("Homepage",     meta.get("homepage", "")),
            ("Wymaga API",   f">= {meta.get('requires_api',(1,0))[0]}.{meta.get('requires_api',(1,0))[1]}"),
            ("Plik",         meta.get("_file", getattr(mod, "__file__", "?"))),
            ("Zaladowano",   meta.get("_loaded", "")),
            ("Sandbox",      meta.get("_sandbox_level", _sandbox_level())),
            ("Zaufanie",     meta.get("_trust_status", "?")),
        ]
        for label, val in _mfields:
            if val and str(val).strip():
                print(box_row(kv_row(label, str(val), key_color=C.DIM), width=w, color=C.EXEC))
        # Hooki
        plugin_hooks = []
        for evt, hooks in PLUGIN_HOOKS.items():
            for hfn in hooks:
                hmod = getattr(hfn, "__module__", "")
                if f"_terminalx_plugin_{pname}" in hmod or pname in hmod:
                    plugin_hooks.append(f"{evt}:{hfn.__name__}")
        if plugin_hooks:
            print(box_sep(width=w, color=C.EXEC))
            print(box_row(f"  {C.BOLD}Hooki ({len(plugin_hooks)}){C.RESET}", width=w, color=C.EXEC))
            for hk in plugin_hooks:
                print(box_row(f"    {C.DIM}{hk}{C.RESET}", width=w, color=C.EXEC))
        # Komendy
        plugin_cmds = []
        seen = set()
        for cname, cdef in BUILTINS.items():
            if not isinstance(cdef, CommandDef): continue
            if id(cdef) in seen: continue
            func_mod = getattr(cdef.func, "__module__", "")
            plug_mod = f"_terminalx_plugin_{pname}"
            if func_mod == plug_mod or func_mod == pname:
                seen.add(id(cdef))
                plugin_cmds.append(cdef)
        if plugin_cmds:
            print(box_sep(width=w, color=C.EXEC))
            print(box_row(f"  {C.BOLD}Komendy ({len(plugin_cmds)}){C.RESET}", width=w, color=C.EXEC))
            for cdef in plugin_cmds:
                al = f"  {C.DIM}[{', '.join(cdef.aliases)}]{C.RESET}" if cdef.aliases else ""
                print(box_row(f"    {C.INFO}{cdef.name:<14}{C.RESET} {cdef.description}{al}",
                              width=w, color=C.EXEC))
        print(box_bottom(width=w, color=C.EXEC))
        print()

    # ── meta ──────────────────────────────────────────────────────────────
    elif subcmd == "meta":
        if len(args) < 2:
            out = {}
            for pn, pm in PLUGIN_META.items():
                safe = {k: str(v) if not isinstance(v, (str, int, float, bool, list, type(None)))
                        else v for k, v in pm.items()}
                out[pn] = safe
            print(json.dumps(out, indent=2, ensure_ascii=False))
        else:
            pn = args[1]
            if pn not in PLUGIN_META:
                print_error(f"Brak metadanych dla: {pn}"); return
            pm   = PLUGIN_META[pn]
            safe = {k: str(v) if not isinstance(v, (str, int, float, bool, list, type(None)))
                    else v for k, v in pm.items()}
            print(json.dumps(safe, indent=2, ensure_ascii=False))

    # ── hooks ─────────────────────────────────────────────────────────────
    elif subcmd == "hooks":
        w = min(terminal_width() - 2, 66)
        print()
        print(box_top("Hooki pluginow", width=w, color=C.INFO))
        any_hooks = False
        for evt, hooks in PLUGIN_HOOKS.items():
            if not hooks: continue
            any_hooks = True
            print(box_row(f"  {C.BOLD}{evt}{C.RESET}  {C.DIM}({len(hooks)} funkcji){C.RESET}",
                          width=w, color=C.INFO))
            for hfn in hooks:
                hmod = getattr(hfn, "__module__", "?")
                print(box_row(f"    {C.DIM}{hfn.__name__}  [{hmod}]{C.RESET}",
                              width=w, color=C.INFO))
        if not any_hooks:
            print(box_row(f"  {C.DIM}Brak zarejestrowanych hookow.{C.RESET}", width=w, color=C.INFO))
        print(box_bottom(width=w, color=C.INFO))
        print()

    # ── load ──────────────────────────────────────────────────────────────
    elif subcmd == "load":
        if len(args) < 2:
            print_error("Uzycie: plugin load <sciezka.py>"); return
        file = Path(args[1]).expanduser()
        if not file.exists():
            print_error(f"Plik nie istnieje: {file}"); return
        _load_single_plugin(file, api)

    # ── unload ────────────────────────────────────────────────────────────
    elif subcmd == "unload":
        if len(args) < 2:
            print_error("Uzycie: plugin unload <nazwa>"); return
        pname = args[1]
        if pname not in LOADED_PLUGINS:
            print_error(f"Plugin nie jest zaladowany: {pname}"); return
        mod = LOADED_PLUGINS.pop(pname)
        sys.modules.pop(f"_terminalx_plugin_{pname}", None)
        if hasattr(mod, "unregister"):
            try: mod.unregister(api)
            except Exception as e: print_error(f"Blad unregister {pname}: {e}")
        PLUGIN_META.pop(pname, None)
        print_info(f"Wyladowano plugin: {pname}")

    # ── reload ────────────────────────────────────────────────────────────
    elif subcmd == "reload":
        targets = ([args[1]] if len(args) >= 2 else list(LOADED_PLUGINS.keys()))
        for pname in targets:
            if pname not in LOADED_PLUGINS:
                print_error(f"Plugin nie jest zaladowany: {pname}"); continue
            mod  = LOADED_PLUGINS.pop(pname)
            file = Path(getattr(mod, "__file__", ""))
            sys.modules.pop(f"_terminalx_plugin_{pname}", None)
            PLUGIN_META.pop(pname, None)
            if hasattr(mod, "unregister"):
                try: mod.unregister(api)
                except Exception:
                    pass  # ignorowane celowo
            if file.exists():
                _load_single_plugin(file, api)
            else:
                print_error(f"Nie mozna znalezc pliku: {file}")
        if len(targets) > 1:
            print_info("Przeladowano wszystkie pluginy.")

    # ── dir ───────────────────────────────────────────────────────────────
    elif subcmd == "dir":
        print_info(f"Katalog pluginow: {PLUGINS_DIR}")
        run_external(["ls", str(PLUGINS_DIR)] if not is_windows()
                     else ["dir", str(PLUGINS_DIR)])

    # ══ BEZPIECZENSTWO ══════════════════════════════════════════════════════

    # ── trust ─────────────────────────────────────────────────────────────
    elif subcmd == "trust":
        if len(args) < 2:
            # Lista zaufanych
            w = min(terminal_width() - 2, 70)
            print()
            print(box_top("Baza zaufanych pluginow", width=w, color=C.PATH))
            if not _TRUST_DB:
                print(box_row(f"  {C.DIM}Baza pusta. Uzyj: plugin trust <nazwa>{C.RESET}",
                              width=w, color=C.PATH))
            for tname, tdata in _TRUST_DB.items():
                status    = tdata.get("status", "?")
                signed_at = tdata.get("signed_at", "")[:10]
                color     = C.PATH if status == "trusted" else C.ERROR
                print(box_row(
                    f"  {color}{tname:<22}{C.RESET} {C.DIM}{status:<10} {signed_at}{C.RESET}",
                    width=w, color=C.PATH))
            print(box_bottom(width=w, color=C.PATH))
            print()
            return
        pname  = args[1]
        force  = "--force" in args
        # Znajdz plik pluginu
        file = PLUGINS_DIR / f"{pname}.py"
        if not file.exists():
            # Szukaj wsrod zaladowanych
            if pname in LOADED_PLUGINS:
                file = Path(getattr(LOADED_PLUGINS[pname], "__file__", ""))
        if not file.exists():
            print_error(f"Nie znaleziono pliku pluginu: {pname}.py")
            return
        # Sprawdz czy to nie juz odwolany (wymaga --force)
        if _TRUST_DB.get(pname, {}).get("status") == "revoked" and not force:
            print_error(f"Plugin '{pname}' jest odwolany. Uzyj: plugin trust {pname} --force")
            return
        if _plugin_trust(file, sign=True):
            print_info(f"Plugin '{pname}' podpisany i oznaczony jako zaufany.")
            print_info(f"Plik podpisu: {file.with_suffix(file.suffix + '.sig')}")
            # Aktualizuj metadane jesli zaladowany
            if pname in PLUGIN_META:
                PLUGIN_META[pname]["_trust_status"] = "trusted"
        else:
            print_error(f"Nie udalo sie podpisac pluginu '{pname}'.")

    # ── revoke ────────────────────────────────────────────────────────────
    elif subcmd == "revoke":
        if len(args) < 2:
            print_error("Uzycie: plugin revoke <nazwa>"); return
        pname = args[1]
        if _plugin_revoke(pname):
            print_info(f"Zaufanie do pluginu '{pname}' zostalo odwolane.")
            # Wyladuj plugin jesli zaladowany
            if pname in LOADED_PLUGINS:
                mod = LOADED_PLUGINS.pop(pname)
                sys.modules.pop(f"_terminalx_plugin_{pname}", None)
                if hasattr(mod, "unregister"):
                    try: mod.unregister(api)
                    except Exception:
                        pass  # ignorowane celowo
                PLUGIN_META.pop(pname, None)
                print_info(f"Plugin '{pname}' wyladowany (odwolany).")
        else:
            print_error(f"Plugin '{pname}' nie jest w bazie zaufania. Brak akcji.")

    # ── verify ────────────────────────────────────────────────────────────
    elif subcmd == "verify":
        targets = [args[1]] if len(args) >= 2 else None
        w = min(terminal_width() - 2, 74)
        print()
        print(box_top("Weryfikacja podpisow pluginow", width=w, color=C.INFO))
        status_colors = {
            "trusted":  C.PATH,
            "unsigned": C.INFO,
            "tampered": C.ERROR,
            "revoked":  C.ERROR,
        }
        status_icons = {
            "trusted":  "✔",
            "unsigned": "?",
            "tampered": "!",
            "revoked":  "✘",
        }
        files_checked = 0
        for f in sorted(PLUGINS_DIR.glob("*.py")):
            if targets and f.stem not in targets:
                continue
            status = _plugin_verify(f)
            color  = status_colors.get(status, C.DIM)
            icon   = status_icons.get(status, "?")
            in_db  = f.stem in _TRUST_DB
            db_str = f"  {C.DIM}[w bazie]{C.RESET}" if in_db else ""
            print(box_row(
                f"  {color}{icon}{C.RESET}  {f.name:<30} {color}{status}{C.RESET}{db_str}",
                width=w, color=C.INFO))
            files_checked += 1
        if files_checked == 0:
            print(box_row(f"  {C.DIM}Brak pluginow do weryfikacji.{C.RESET}", width=w, color=C.INFO))
        print(box_sep(width=w, color=C.INFO))
        print(box_row(
            f"  {C.DIM}plugin trust <nazwa> — podpisz  |  plugin revoke <nazwa> — odwolaj{C.RESET}",
            width=w, color=C.INFO))
        print(box_bottom(width=w, color=C.INFO))
        print()

    # ── audit ─────────────────────────────────────────────────────────────
    elif subcmd == "audit":
        w = min(terminal_width() - 2, 78)
        print()
        print(box_top("Raport bezpieczenstwa pluginow", width=w, color=C.ERROR))
        print(box_row(
            f"  {C.BOLD}Sandbox:{C.RESET}  {C.INFO}{_sandbox_level()}{C.RESET}"
            f"   {C.DIM}(config set plugin_sandbox off|warn|strict){C.RESET}",
            width=w, color=C.ERROR))
        print(box_sep(width=w, color=C.ERROR))

        issues = []
        for f in sorted(PLUGINS_DIR.glob("*.py")):
            status = _plugin_verify(f)
            try:
                source = f.read_text(encoding="utf-8", errors="replace")
                scan_w = _sandbox_scan_source(source, f.stem)
            except Exception:
                scan_w = []

            loaded  = f.stem in LOADED_PLUGINS
            color   = C.PATH if status == "trusted" and not scan_w else (
                      C.ERROR if status in ("tampered", "revoked") else C.INFO)
            loaded_s = f"{C.DIM}[zaladowany]{C.RESET}" if loaded else ""
            print(box_row(
                f"  {color}{f.name:<32}{C.RESET} {color}{status:<12}{C.RESET} {loaded_s}",
                width=w, color=C.ERROR))
            for sw in scan_w:
                print(box_row(f"    {C.DIM}▸ {sw}{C.RESET}", width=w, color=C.ERROR))
                issues.append((f.stem, sw))

        print(box_sep(width=w, color=C.ERROR))
        if issues:
            print(box_row(
                f"  {C.ERROR}Znaleziono {len(issues)} potencjalnych problemow.{C.RESET}",
                width=w, color=C.ERROR))
        else:
            print(box_row(
                f"  {C.PATH}Brak wykrytych problemow.{C.RESET}",
                width=w, color=C.ERROR))
        print(box_row(
            f"  {C.DIM}plugin trust <nazwa>  |  plugin revoke <nazwa>  |  plugin sandbox strict{C.RESET}",
            width=w, color=C.ERROR))
        print(box_bottom(width=w, color=C.ERROR))
        print()

    # ── sandbox ───────────────────────────────────────────────────────────
    elif subcmd == "sandbox":
        if len(args) < 2:
            cur = _sandbox_level()
            print_info(f"Aktywny poziom sandboxu: {C.BOLD}{cur}{C.RESET}")
            print_info(f"Dostepne: off | warn | strict")
            print_info(f"Zmiana: plugin sandbox <poziom>  lub  config set plugin_sandbox <poziom>")
            return
        lvl = args[1].lower()
        if lvl not in _SANDBOX_LEVELS:
            print_error(f"Nieznany poziom: '{lvl}'", f"Dostepne: {', '.join(_SANDBOX_LEVELS)}")
            return
        cfg_set("plugin_sandbox", lvl, save=True)
        print_info(f"Sandbox ustawiony na: {C.BOLD}{lvl}{C.RESET}  (aktywny dla nowych ladowan)")

    # ══ REPOZYTORIUM ════════════════════════════════════════════════════════

    elif subcmd == "repo":
        if len(args) < 2:
            print_error("Uzycie: plugin repo list|add|remove|fetch|search|install|info"); return
        rsub = args[1]

        # ── repo list ─────────────────────────────────────────────────────
        if rsub == "list":
            w = min(terminal_width() - 2, 74)
            print()
            print(box_top(f"Repozytoria pluginow  ({len(_PLUGIN_REPOS)})", width=w, color=C.PROMPT))
            for r in _PLUGIN_REPOS:
                last = r.get("last_fetch", "")
                last = last[:10] if last else "nigdy"
                rtype = r.get("type", "?")
                color = C.PATH if rtype == "local" else C.KEYWORD
                print(box_row(
                    f"  {color}{r['name']:<18}{C.RESET}"
                    f" {C.DIM}{rtype:<8}{C.RESET}"
                    f" {r.get('url','')[:32]}"
                    f"  {C.DIM}fetch: {last}{C.RESET}",
                    width=w, color=C.PROMPT))
            print(box_sep(width=w, color=C.PROMPT))
            print(box_row(
                f"  {C.DIM}plugin repo add <url>  |  plugin repo fetch  |  plugin repo search <query>{C.RESET}",
                width=w, color=C.PROMPT))
            print(box_bottom(width=w, color=C.PROMPT))
            print()

        # ── repo add ──────────────────────────────────────────────────────
        elif rsub == "add":
            if len(args) < 3:
                print_error("Uzycie: plugin repo add <url|sciezka> [--name <nazwa>]")
                return
            url   = args[2]
            # Szukaj --name
            name  = None
            if "--name" in args:
                idx = args.index("--name")
                if idx + 1 < len(args):
                    name = args[idx + 1]
            if name is None:
                # Wygeneruj nazwe z URL
                name = re.sub(r'[^a-z0-9_-]', '_', url.split("/")[-1].lower())[:20] or "repo"
            # Sprawd czy nazwa juz istnieje
            if any(r["name"] == name for r in _PLUGIN_REPOS):
                print_error(f"Repozytorium '{name}' juz istnieje. Uzyj innej nazwy lub usun je najpierw.")
                return
            rtype = "local" if (Path(url).exists() or not url.startswith("http")) else "remote"
            repo  = {
                "name":       name,
                "url":        url,
                "type":       rtype,
                "description": "",
                "last_fetch": None,
            }
            _PLUGIN_REPOS.append(repo)
            _repo_save()
            print_info(f"Repozytorium '{name}' dodane ({rtype}: {url})")
            print_info(f"Odswiezenie indeksu: plugin repo fetch")

        # ── repo remove ───────────────────────────────────────────────────
        elif rsub == "remove":
            if len(args) < 3:
                print_error("Uzycie: plugin repo remove <nazwa>"); return
            rname  = args[2]
            if rname == "local":
                print_error("Nie mozna usunac wbudowanego repozytorium 'local'."); return
            before = len(_PLUGIN_REPOS)
            _PLUGIN_REPOS[:] = [r for r in _PLUGIN_REPOS if r["name"] != rname]
            if len(_PLUGIN_REPOS) < before:
                _repo_save()
                _PLUGIN_REPO_CACHE.pop(rname, None)
                print_info(f"Repozytorium '{rname}' usuniete.")
            else:
                print_error(f"Repozytorium '{rname}' nie istnieje.")

        # ── repo fetch ────────────────────────────────────────────────────
        elif rsub == "fetch":
            total = _repo_fetch_all(silent=False)
            print_info(f"Odswiezono. Dostepnych pluginow: {total}")

        # ── repo search ───────────────────────────────────────────────────
        elif rsub == "search":
            if len(args) < 3:
                print_error("Uzycie: plugin repo search <query>"); return
            # Jesli cache pusty — zrob fetch
            if not _PLUGIN_REPO_CACHE:
                print_info("Ladowanie indeksow...")
                _repo_fetch_all(silent=True)
            query   = " ".join(args[2:])
            results = _repo_search(query)
            w = min(terminal_width() - 2, 78)
            print()
            if not results:
                print_info(f"Brak wynikow dla '{query}'. Sprobuj: plugin repo fetch")
                return
            print(box_top(f"Wyniki dla '{query}'  ({len(results)} pluginow)", width=w, color=C.INFO))
            for p in results[:20]:
                installed = (PLUGINS_DIR / f"{p['name']}.py").exists()
                inst_mark = f" {C.PATH}[zainstalowany]{C.RESET}" if installed else ""
                print(box_row(
                    f"  {C.INFO}{p['name']:<22}{C.RESET}"
                    f" {C.DIM}v{p.get('version','?'):<8}{C.RESET}"
                    f" {p.get('description','')[:28]}{inst_mark}",
                    width=w, color=C.INFO))
            print(box_sep(width=w, color=C.INFO))
            print(box_row(
                f"  {C.DIM}plugin repo install <nazwa>  |  plugin repo info <nazwa>{C.RESET}",
                width=w, color=C.INFO))
            print(box_bottom(width=w, color=C.INFO))
            print()

        # ── repo install ──────────────────────────────────────────────────
        elif rsub == "install":
            if len(args) < 3:
                print_error("Uzycie: plugin repo install <nazwa>"); return
            pname = args[2]
            if not _PLUGIN_REPO_CACHE:
                print_info("Ladowanie indeksow...")
                _repo_fetch_all(silent=True)
            # Znajdz plugin w cache
            entry = None
            for plist in _PLUGIN_REPO_CACHE.values():
                for p in plist:
                    if p.get("name") == pname:
                        entry = p
                        break
                if entry:
                    break
            if entry is None:
                print_error(f"Plugin '{pname}' nie znaleziony w repozytoriach.",
                            "Sprobuj: plugin repo fetch && plugin repo search <nazwa>")
                return
            _repo_install(entry, api)

        # ── repo info ─────────────────────────────────────────────────────
        elif rsub == "info":
            if len(args) < 3:
                print_error("Uzycie: plugin repo info <nazwa>"); return
            pname = args[2]
            if not _PLUGIN_REPO_CACHE:
                _repo_fetch_all(silent=True)
            entry = None
            for plist in _PLUGIN_REPO_CACHE.values():
                for p in plist:
                    if p.get("name") == pname:
                        entry = p
                        break
                if entry:
                    break
            if entry is None:
                print_error(f"Plugin '{pname}' nie znaleziony w repozytoriach."); return
            w = min(terminal_width() - 2, 66)
            print()
            print(box_top(f"Plugin w repo: {pname}", width=w, color=C.INFO))
            for k, v in entry.items():
                if v and str(v).strip():
                    print(box_row(kv_row(k, str(v), key_color=C.DIM), width=w, color=C.INFO))
            print(box_bottom(width=w, color=C.INFO))
            print()

        else:
            print_error(f"Nieznana podkomenda: plugin repo {rsub}",
                        "Dostepne: list add remove fetch search install info")

    # ── fallback ──────────────────────────────────────────────────────────
    else:
        print_error(f"Nieznane polecenie: plugin {subcmd}",
                    "Dostepne: list info load unload reload dir trust revoke verify audit sandbox repo")

# ALIAS_EXPAND

def expand_aliases(tokens):
    if tokens and tokens[0] in ALIASES:
        try:
            return shlex.split(ALIASES[tokens[0]]) + tokens[1:]
        except Exception:  # ignorowane celowo
            pass
    return tokens

# EXTERNAL

def run_external(tokens):
    try:
        subprocess.run(tokens)
    except FileNotFoundError:
        print_error(f"Nie znaleziono programu: {tokens[0]}")
    except Exception as e:
        print_error(str(e))

# COMPLETION

# Komendy wymagajace sciezki jako argument
PATH_COMMANDS = {
    "cd", "ls", "dir", "cat", "type", "rm", "rmdir", "cp", "copy",
    "mv", "move", "touch", "mkdir", "grep", "find", "plugin",
    "nano", "source", "pysh", "run",
}
# Komendy z podkomendami - uzupelniaj druga pozycje jako podkomende
SUBCOMMAND_COMPLETIONS = {
    "plugin":  ["list", "load", "unload", "reload", "info", "dir",
                "trust", "revoke", "verify", "audit", "sandbox", "repo",
                "meta", "hooks"],
    "git":     ["status","add","commit","push","pull","log","diff",
                "checkout","branch","merge","rebase","fetch","stash","tag"],
    "config":  ["get","set","reset","edit","reload","path","show","export",
                "convert","font","window","paths","keybind","tui"],
    "history": ["-c","-s","-d","-r"],
    "profile": ["list","switch","create","save","delete","show","diff",
                "import","export","reset"],
    "pkg":     ["install","remove","list","info","search","create",
                "enable","disable"],
    "logs":    ["tail","filter","clear","export","level"],
    "pysh":    ["run","load","list","reload","info","unload"],
    "verbose": ["on","off","status"],
    "debug":   ["on","off","status","trace"],
    "set":     ["-x","+x"],
}
# Flagi dla komend
FLAG_COMPLETIONS = {
    "ls":      ["-l", "-a", "-s", "-la", "-al", "--color"],
    "grep":    ["-r", "-i", "-n", "-l", "-ri", "-rn", "-rl",
                "-v", "-c", "-E", "-F", "--include"],
    "find":    ["-name", "-type", "-mtime", "-size", "-maxdepth",
                "-mindepth", "-exec", "-not", "-iname"],
    "history": ["-c", "-s", "-d", "-r"],
    "cat":     ["-n", "-A"],
    "rm":      ["-r", "-f", "-rf", "-v"],
    "cp":      ["-r", "-v", "-n", "-u"],
    "mv":      ["-v", "-n", "-u"],
    "mkdir":   ["-p", "-v"],
    "plugin":  ["--force", "--pip"],
    "pysh":    ["--verbose", "--debug", "--no-sandbox"],
    "nano":    ["-n", "-A"],
}

# ── Uzupelnianie plikow .pysh ─────────────────────────────────
def _pysh_completions(prefix: str) -> list:
    """Zwraca pliki .pysh pasujace do prefix (cwd + PYSH_PATH)."""
    results = []
    search_dirs = [Path(".")]
    pysh_path_cfg = cfg("pysh_module_path", "")
    if pysh_path_cfg:
        for d in pysh_path_cfg.split(os.pathsep):
            p = Path(d).expanduser()
            if p.is_dir():
                search_dirs.append(p)
    for d in search_dirs:
        try:
            for f in d.iterdir():
                if f.suffix == ".pysh" and f.stem.startswith(prefix.lstrip("/")):
                    candidate = str(f) if d != Path(".") else f.name
                    results.append(candidate)
        except Exception:  # ignorowane celowo
            pass
    return sorted(results)

# ── Uzupelnianie wartosci config set ─────────────────────────
def _config_value_completions(key: str) -> list:
    """Podpowiada dozwolone wartosci dla danego klucza config."""
    _value_hints = {
        "theme":          ["dark", "light"],
        "prompt_style":   ["full", "short", "minimal"],
        "box_style":      ["single", "round", "double", "heavy", "ascii"],
        "plugin_sandbox": ["off", "warn", "strict"],
        "font_family":    list(_FONT_PRESETS.values()) if "_FONT_PRESETS" in globals() else [],
    }
    return _value_hints.get(key, [])

def _path_completions(prefix: str) -> list:
    """Zwraca liste sciezek pasujacych do prefix."""
    results = []
    try:
        if os.sep in prefix or prefix.startswith("~") or prefix.startswith("."):
            p    = Path(prefix).expanduser()
            base = str(p.parent) if not prefix.endswith(os.sep) else prefix
            stub = p.name        if not prefix.endswith(os.sep) else ""
            directory = Path(base).expanduser()
            if directory.is_dir():
                for entry in directory.iterdir():
                    if entry.name.startswith(stub):
                        candidate = str(Path(base) / entry.name)
                        if entry.is_dir():
                            candidate += os.sep
                        results.append(candidate)
        else:
            for entry in Path(".").iterdir():
                name = entry.name
                if name.startswith(prefix):
                    results.append(name + (os.sep if entry.is_dir() else ""))
    except Exception:  # ignorowane celowo
        pass
    return sorted(results)

def _build_completion_list(line_buffer: str, text: str) -> list:
    """
    Kontekstowe uzupelnianie TAB:
    - puste / pierwsza pozycja  -> komendy + aliasy + pliki .pysh
    - po 'config set'           -> klucze konfiguracji
    - po 'config set <key>'     -> wartosci konfiguracji
    - po 'pysh run/load'        -> pliki .pysh
    - po 'plugin load'          -> pliki .py
    - druga+ pozycja ze znana subkomenda -> podkomendy
    - text zaczyna sie od -     -> flagi komendy
    - po zmiennej $             -> zmienne SHELL_VARS + os.environ
    - inne                      -> sciezki + flagi komendy
    """
    try:
        tokens = shlex.split(line_buffer)
    except ValueError:
        tokens = line_buffer.split()

    # Uzupelnianie zmiennych $VAR
    if text.startswith("$"):
        prefix = text[1:]
        all_vars = list(SHELL_VARS.keys()) + list(os.environ.keys())
        return ["$" + v for v in sorted(set(all_vars)) if v.startswith(prefix)]

    # Pierwsza pozycja (lub puste)
    if not tokens or (len(tokens) == 1 and not line_buffer.endswith(" ")):
        candidates  = list(BUILTINS.keys()) + list(ALIASES.keys())
        candidates += _path_completions(text)
        candidates += [f.name for f in Path(".").glob("*.pysh")
                       if f.name.startswith(text)]
        return sorted(set(c for c in candidates if c.startswith(text)))

    cmd = tokens[0]
    pos = len(tokens) - (0 if line_buffer.endswith(" ") else 1)

    # ── config set <klucz> → wartosci ─────────────────────────
    if cmd == "config" and len(tokens) >= 2 and tokens[1] == "set":
        if pos == 2:   # uzupelniaj klucze
            return [k for k in _CONFIG_DEFAULTS if k.startswith(text)]
        if pos == 3:   # uzupelniaj wartosci dla konkretnego klucza
            key = tokens[2] if len(tokens) > 2 else ""
            hints = _config_value_completions(key)
            return [h for h in hints if str(h).startswith(text)]

    # ── config get → klucze ────────────────────────────────────
    if cmd == "config" and len(tokens) >= 2 and tokens[1] == "get" and pos == 2:
        return [k for k in _CONFIG_DEFAULTS if k.startswith(text)]

    # ── config reset → klucze ──────────────────────────────────
    if cmd == "config" and len(tokens) >= 2 and tokens[1] == "reset" and pos == 2:
        return [k for k in _CONFIG_DEFAULTS if k.startswith(text)]

    # ── pysh run/load → pliki .pysh ───────────────────────────
    if cmd == "pysh" and len(tokens) >= 2 and tokens[1] in ("run", "load") and pos == 2:
        return _pysh_completions(text)

    # ── source → pliki .pysh + .sh ────────────────────────────
    if cmd in ("source", ".") and pos == 1:
        return (_pysh_completions(text) +
                [f.name for f in Path(".").glob("*.sh") if f.name.startswith(text)])

    # ── plugin load → pliki .py ───────────────────────────────
    if cmd == "plugin" and len(tokens) >= 2 and tokens[1] == "load" and pos == 2:
        return [p for p in _path_completions(text) if p.endswith(".py") or "/" in p]

    # ── plugin unload/info/reload/trust → zaladowane pluginy ──
    if (cmd == "plugin" and len(tokens) >= 2
            and tokens[1] in ("unload","info","reload","trust","revoke","verify")
            and pos == 2):
        return [n for n in LOADED_PLUGINS if n.startswith(text)]

    # Podkomendy (pozycja 1)
    if pos == 1 and cmd in SUBCOMMAND_COMPLETIONS:
        subs = SUBCOMMAND_COMPLETIONS[cmd]
        return [s for s in subs if s.startswith(text)]

    # Flagi (jesli text zaczyna sie od -)
    if text.startswith("-"):
        flags = FLAG_COMPLETIONS.get(cmd, [])
        cdef = BUILTINS.get(cmd)
        if isinstance(cdef, CommandDef):
            flags = flags + list(cdef.flags)
        return sorted(set(f for f in flags if f.startswith(text)))

    # Sciezki dla komend plikowych lub pozycja >= 1
    if cmd in PATH_COMMANDS or pos >= 1:
        return _path_completions(text)

    return []

_completion_cache: list = _STATE.completion_cache

def completer(text: str, state: int) -> str | None:
    if state == 0:
        if readline:
            line_buffer = readline.get_line_buffer()
        else:
            line_buffer = text
        _STATE.completion_cache = _build_completion_list(line_buffer, text)
    if state < len(_completion_cache):
        return _completion_cache[state]
    return None

# HISTORY_SEARCH

def history_search_interactive(initial: str = "") -> str | None:
    """
    Własna implementacja incremental history search (reverse-i-search).
    Działa bez curses, czysto terminalowo — wszędzie (Linux/Mac/Windows).

    Zwraca wybraną komendę lub None jesli anulowano.
    Sterowanie:
      Wpisywanie    - zawęża wyniki
      Backspace     - usuń ostatni znak zapytania
      Enter         - zatwierdź
      Ctrl+R        - następne dopasowanie (starsze)
      Ctrl+S        - poprzednie dopasowanie (nowsze)
      Ctrl+G / ESC  - anuluj
      Strzalki G/D  - przewijaj listę dopasowań
    """
    import sys, tty, termios, os

    # Na Windows bez tty — tryb tekstowy
    if os.name == 'nt' or not hasattr(termios, 'tcgetattr'):
        return _history_search_line_mode(initial)

    # Zapisz oryginalne ustawienia terminala
    fd = sys.stdin.fileno()
    try:
        old_settings = termios.tcgetattr(fd)
    except Exception:
        return _history_search_line_mode(initial)

    RESET  = "\033[0m"
    BOLD   = "\033[1m"
    CYAN   = "\033[96m"
    YELLOW = "\033[93m"
    DIM    = "\033[2m"
    RED    = "\033[91m"
    UP     = "\033[1A"
    CLR    = "\r\033[K"   # powrót do początku + kasowanie linii

    query      = initial
    match_idx  = 0           # który wynik (0 = najnowszy)
    result     = None

    def _matches(q: str) -> list:
        """Zwraca listę (numer_1based, cmd) pasujących do q, od końca."""
        q_lo = q.lower()
        out  = []
        for i, cmd in reversed(list(enumerate(HISTORY, 1))):
            if q_lo in cmd.lower():
                out.append((i, cmd))
        return out

    def _highlight(cmd: str, q: str) -> str:
        """Podświetla q w cmd."""
        if not q:
            return cmd
        lo  = cmd.lower()
        idx = lo.find(q.lower())
        if idx == -1:
            return cmd
        return (cmd[:idx]
                + f"{BOLD}{YELLOW}{cmd[idx:idx+len(q)]}{RESET}"
                + cmd[idx+len(q):])

    def _render(q: str, matches: list, m_idx: int, msg: str = ""):
        """Rysuje pasek wyszukiwania i listę wyników."""
        # Linia 1: pasek
        count  = len(matches)
        status = f"{CYAN}(reverse-i-search){RESET}" if not msg else f"{RED}{msg}{RESET}"
        bar    = f"{status}  `{BOLD}{q}{RESET}\':"
        if count:
            cur_n, cur_cmd = matches[m_idx % count]
            bar += f"  {DIM}[{m_idx % count + 1}/{count}]{RESET}  {_highlight(cur_cmd, q)}"
        else:
            bar += f"  {DIM}(brak dopasowania){RESET}"
        # Wyczysc linię i wydrukuj
        sys.stdout.write(CLR + bar)
        sys.stdout.flush()

    def _getch() -> bytes:
        """Czyta jeden bajt z raw stdin."""
        return sys.stdin.buffer.read(1)

    try:
        tty.setraw(fd)
        matches = _matches(query)
        _render(query, matches, match_idx)

        while True:
            ch = _getch()

            # Enter — zatwierdź
            if ch in (b'\r', b'\n'):
                if matches:
                    result = matches[match_idx % len(matches)][1]
                break

            # ESC lub Ctrl+G — anuluj
            if ch in (b'\x1b', b'\x07'):
                # Sprawdz czy to sekwencja escape (strzalka)
                if ch == b'\x1b':
                    sys.stdin.buffer.read(0)   # nie blokuj
                    # Peek kolejny bajt
                    import select
                    r, _, _ = select.select([sys.stdin], [], [], 0.05)
                    if r:
                        nxt = sys.stdin.buffer.read(1)
                        if nxt == b'[':
                            arrow = sys.stdin.buffer.read(1)
                            if arrow == b'A':   # strzałka góra — starsze
                                match_idx = (match_idx + 1) % max(1, len(matches))
                            elif arrow == b'B': # strzałka dół — nowsze
                                match_idx = max(0, match_idx - 1)
                            _render(query, matches, match_idx)
                            continue
                        # Inna sekwencja — anuluj
                result = None
                break

            # Ctrl+R — następne (starsze) dopasowanie
            if ch == b'\x12':
                match_idx = (match_idx + 1) % max(1, len(matches))
                _render(query, matches, match_idx)
                continue

            # Ctrl+S — poprzednie (nowsze) dopasowanie
            if ch == b'\x13':
                match_idx = max(0, match_idx - 1)
                _render(query, matches, match_idx)
                continue

            # Backspace
            if ch in (b'\x7f', b'\x08'):
                if query:
                    query     = query[:-1]
                    match_idx = 0
                    matches   = _matches(query)
                    _render(query, matches, match_idx)
                continue

            # Ctrl+C — anuluj
            if ch == b'\x03':
                result = None
                break

            # Ctrl+W — usuń słowo
            if ch == b'\x17':
                query = _RE_CTRL_W.sub('', query)
                match_idx = 0
                matches   = _matches(query)
                _render(query, matches, match_idx)
                continue

            # Zwykły znak
            if 32 <= ch[0] <= 126:
                query    += chr(ch[0])
                match_idx = 0
                matches   = _matches(query)
                _render(query, matches, match_idx,
                        "" if matches else "brak dopasowania")
                continue

    finally:
        termios.tcsetattr(fd, termios.TCSADRAIN, old_settings)
        sys.stdout.write("\r\033[K")   # wyczyść pasek
        sys.stdout.flush()

    return result

def _history_search_line_mode(initial: str = "") -> str | None:
    """
    Tekstowy fallback Ctrl+R dla Windows i terminali bez tty.
    Wyświetla 10 ostatnich wpisów i pyta o wybór.
    """
    print(f"\n{C.BOLD}Historia wyszukiwanie{C.RESET}  (Enter = wyjdz bez wyboru)\n")
    query = initial
    while True:
        matches = [(i+1, cmd) for i, cmd in enumerate(HISTORY)
                   if query.lower() in cmd.lower()]
        matches_r = list(reversed(matches))[:15]

        for j, (n, cmd) in enumerate(matches_r, 1):
            hi = cmd.replace(query, f"{C.MATCH}{query}{C.RESET}") if query else cmd
            print(f"  {C.DIM}{j:2d}. [{n:3d}]{C.RESET} {hi}")

        if not matches_r:
            print(f"  {C.DIM}(brak wynikow dla: {query!r}){C.RESET}")

        try:
            ans = input(f"\n{C.PROMPT}Szukaj (numer/tekst/Enter): {C.RESET}").strip()
        except (EOFError, KeyboardInterrupt):
            print(); return None

        if not ans:
            return None

        try:
            n = int(ans)
            if 1 <= n <= len(matches_r):
                return matches_r[n-1][1]
            print_error(f"Numer poza zakresem: 1-{len(matches_r)}")
        except ValueError:
            query = ans   # kolejne zawężenie

def _ctrl_r_hook():
    """readline pre_input_hook — przechwytuje Ctrl+R przed readline."""
    if not readline:
        return
    buf = readline.get_line_buffer()
    if "\x12" in buf:
        readline.replace_line("")
        try:
            readline.redisplay()
        except Exception:  # ignorowane celowo
            pass
        result = history_search_interactive()
        if result:
            readline.insert_text(result)
            try:
                readline.redisplay()
            except Exception:  # ignorowane celowo
                pass

def enable_tab_completion():
    if not readline:
        return
    readline.parse_and_bind("tab: complete")
    readline.set_completer(completer)
    readline.set_completer_delims(" \t\n;|&")
    # Rejestruj własny Ctrl+R przez pre_input_hook (CPython readline)
    try:
        if hasattr(readline, "set_pre_input_hook"):
            readline.set_pre_input_hook(_ctrl_r_hook)
    except Exception:  # ignorowane celowo
        pass

# VAR_CMDS

@command("export", "Ustaw i eksportuj zmienna srodowiskowa do procesow potomnych",
         aliases=["setenv"])
def cmd_export(args):
    """
    export VAR=wartosc   - ustaw i eksportuj do os.environ
    export VAR           - eksportuj istniejaca zmienna shella
    export               - wyswietl wszystkie eksportowane zmienne
    export -n VAR        - cofnij eksport (zostaje w SHELL_VARS)
    """
    if not args:
        # Wyswietl zmienne eksportowane (wspolne SHELL_VARS i os.environ)
        merged = {**os.environ, **SHELL_VARS}
        for k, v in sorted(merged.items()):
            print(f"export {k}={shlex.quote(v)}")
        return

    if args[0] == "-n":
        for name in args[1:]:
            os.environ.pop(name, None)
            print_info(f"Cofnieto eksport: {name}")
        return

    for spec in args:
        if "=" in spec:
            name, _, value = spec.partition("=")
            value = _var_expand(value)
            _set_var(name, value, export=True)
            print_info(f"export {name}={shlex.quote(value)}")
        else:
            # Eksportuj istniejaca
            value = SHELL_VARS.get(spec, "")
            if value:
                os.environ[spec] = value
                print_info(f"export {spec}")
            else:
                print_error(f"Zmienna nie istnieje: {spec}")

@command("unset", "Usun zmienna shella lub srodowiskowa")
def cmd_unset(args):
    """
    unset VAR [VAR2 ...]  - usuwa z SHELL_VARS i os.environ
    """
    if not args:
        print_error("Uzycie: unset <VAR> [VAR2 ...]")
        return
    for name in args:
        removed = False
        if name in SHELL_VARS:
            del SHELL_VARS[name]
            removed = True
        if name in os.environ:
            del os.environ[name]
            removed = True
        if not removed:
            print_error(f"Zmienna nie istnieje: {name}")

@command("set", "Wyswietl lub ustaw zmienne shella",
         flags=["-x", "+x"])
def cmd_set(args):
    """
    set              - lista wszystkich zmiennych SHELL_VARS
    set -x           - wlacz tryb debug (echo komend przed wykonaniem)
    set +x           - wylacz tryb debug
    set VAR=wartosc  - ustaw zmienna (bez eksportu)
    """
    if not args:
        if SHELL_VARS:
            print(f"{C.BOLD}Zmienne shella:{C.RESET}")
            for k, v in sorted(SHELL_VARS.items()):
                in_env = " (eksportowana)" if k in os.environ else ""
                print(f"  {C.INFO}{k}{C.RESET}={shlex.quote(v)}{C.DIM}{in_env}{C.RESET}")
        else:
            print_info("Brak zmiennych shella.")
        return

    if args[0] == "-x":
        SHELL_VARS["_DEBUG"] = "1"
        print_info("Tryb debug wlaczony (set -x)")
        return
    if args[0] == "+x":
        SHELL_VARS.pop("_DEBUG", None)
        print_info("Tryb debug wylaczony (set +x)")
        return

    for spec in args:
        if "=" in spec:
            name, _, value = spec.partition("=")
            _set_var(name, _var_expand(value), export=False)
        else:
            print_error(f"Uzycie: set VAR=wartosc  lub set -x  lub set +x")

@command("env", "Wyswietl srodowisko lub uruchom komende ze zmodyfikowanym srodowiskiem")
def cmd_env(args):
    """
    env                    - wyswietl os.environ + SHELL_VARS
    env VAR=val komenda    - uruchom komende z tymczasowym VAR=val
    env -i komenda         - uruchom z czystym srodowiskiem
    """
    clean = False
    extra = {}
    cmd_start = 0

    for i, a in enumerate(args):
        if a == "-i":
            clean = True
        elif "=" in a and not a.startswith("-"):
            name, _, value = a.partition("=")
            extra[name] = _var_expand(value)
        else:
            cmd_start = i
            break
    else:
        cmd_start = len(args)

    cmd_args = args[cmd_start:]

    if not cmd_args:
        # Wyswietl srodowisko
        merged = ({} if clean else {**os.environ}) | SHELL_VARS | extra
        for k, v in sorted(merged.items()):
            print(f"{C.INFO}{k}{C.RESET}={v}")
        return

    # Uruchom komende z modyfikowanym srodowiskiem
    env = ({} if clean else os.environ.copy())
    env.update(SHELL_VARS)
    env.update(extra)
    try:
        subprocess.run(cmd_args, env=env)
    except FileNotFoundError:
        print_error(f"Nie znaleziono: {cmd_args[0]}")

@command("printenv", "Wyswietl wartosc zmiennej srodowiskowej")
def cmd_printenv(args):
    """
    printenv           - wszystkie zmienne (jak env)
    printenv VAR       - wartosc jednej zmiennej
    printenv VAR1 VAR2 - wartosci wielu zmiennych
    """
    if not args:
        merged = {**os.environ, **SHELL_VARS}
        for k, v in sorted(merged.items()):
            print(f"{k}={v}")
        return
    for name in args:
        val = _get_var(name)
        if val:
            print(val)
        else:
            # printenv konwencja: exit 1 jesli nie znaleziono
            _STATE.last_exit = 1

# ============================
#   GLOWNA PETLA
# ============================

# UAC

def _check_uac() -> dict:
    """
    Wykrywa czy shell wymaga/moze podniesc uprawnienia.
    Zwraca slownik z informacjami o biezacych uprawnieniach.
    """
    info = {
        "platform":   os.name,
        "elevated":   False,
        "can_elevate": False,
        "method":     "none",
    }
    if os.name == "nt":
        # Windows — sprawdz przez ctypes czy jestesmy adminem
        try:
            import ctypes
            info["elevated"]   = bool(ctypes.windll.shell32.IsUserAnAdmin())
            info["can_elevate"] = not info["elevated"]
            info["method"]     = "UAC (Windows)"
        except Exception:  # ignorowane celowo
            pass
    else:
        # Unix — sprawdz UID
        try:
            uid = os.getuid()
            info["elevated"]   = (uid == 0)
            info["can_elevate"] = (uid != 0 and shutil.which("sudo") is not None)
            info["method"]     = "sudo" if info["can_elevate"] else ("root" if info["elevated"] else "user")
        except AttributeError:
            pass
    return info

def _request_elevation_windows():
    """
    Na Windows: prosi o ponowne uruchomienie skryptu z UAC (jako Administrator).
    Wywolywane tylko gdy uzytkownik jawnie tego zada.
    """
    try:
        import ctypes
        script = Path(__file__).resolve()
        ctypes.windll.shell32.ShellExecuteW(
            None, "runas", sys.executable, str(script), None, 1)
        sys.exit(0)
    except Exception as e:
        print_error(f"Nie udalo sie podniesc uprawnien: {e}")

def _detect_sandbox() -> str:
    """
    Wykrywa czy shell dziala w srodowisku izolowanym (kontener, sandbox).
    Zwraca opis lub pusty string.
    """
    hints = []
    # Docker / kontener
    if Path("/.dockerenv").exists():
        hints.append("Docker")
    cgroup = Path("/proc/1/cgroup")
    if cgroup.exists():
        try:
            txt = cgroup.read_text(errors="ignore")
            if "docker" in txt or "lxc" in txt or "kubepods" in txt:
                hints.append("kontener Linux")
        except Exception:  # ignorowane celowo
            pass
    # Windows Sandbox
    if os.name == "nt":
        try:
            import ctypes
            # Brak praw admina + brak dostepu do pewnych kluczy = sandbox/VM
            # Prosty heurystyk: sprawdz USERDOMAIN
            domain = os.environ.get("USERDOMAIN", "")
            if domain in ("WORKGROUP", "WDAGUtilityAccount"):
                hints.append("Windows Sandbox / izolowany")
        except Exception:  # ignorowane celowo
            pass
    # Wirtualizacja (sprawdz /proc/cpuinfo)
    cpuinfo = Path("/proc/cpuinfo")
    if cpuinfo.exists():
        try:
            txt = cpuinfo.read_text(errors="ignore").lower()
            if "hypervisor" in txt or "vmware" in txt or "virtualbox" in txt:
                hints.append("VM/hypervisor")
        except Exception:  # ignorowane celowo
            pass
    return ", ".join(hints) if hints else ""

# THEME_CMD
#   Przelaczanie motywu ciemny/jasny + zapis do profilu

# ── System własnych motywów ───────────────────────────────────────────────────
THEMES_FILE = _BASE / ".terminalx_themes.json"   # plik z własnymi motywami
_BUILTIN_THEME_NAMES = frozenset(["dark", "light", "neon", "pixel-art", "symbolic"])

def _load_custom_themes():
    """Wczytuje własne motywy z THEMES_FILE i wstrzykuje do _THEMES."""
    if not THEMES_FILE.exists():
        return
    try:
        data = json.loads(THEMES_FILE.read_text(encoding="utf-8"))
        for name, theme_dict in data.items():
            if isinstance(theme_dict, dict) and name not in _BUILTIN_THEME_NAMES:
                _THEMES[name] = theme_dict
    except Exception:  # ignorowane celowo
        pass

def _save_custom_themes():
    """Zapisuje wszystkie niestandardowe motywy do THEMES_FILE."""
    custom = {k: v for k, v in _THEMES.items() if k not in _BUILTIN_THEME_NAMES}
    try:
        THEMES_FILE.write_text(
            json.dumps(custom, indent=2, ensure_ascii=False), encoding="utf-8"
        )
    except Exception as e:
        print_error(f"Błąd zapisu motywów: {e}")

def _apply_theme(name: str) -> bool:
    """Ustawia motyw i aktualizuje klase C."""
    if name not in _THEMES:
        print_error(f"Nieznany motyw: '{name}'",
                    f"Dostepne: {', '.join(_THEMES.keys())}")
        return False
    _STATE.current_theme = name
    C._apply()
    SHELL_VARS["MINI_THEME"] = name
    return True

def _theme_preview(name: str, width: int = 50):
    """Drukuje próbki kolorów dla podanego motywu."""
    if name not in _THEMES:
        print_error(f"Nieznany motyw: '{name}'")
        return
    t   = _THEMES[name]
    rst = t.get("RESET", "\033[0m")
    is_custom = name not in _BUILTIN_THEME_NAMES
    lbl = f"  {C.INFO}[własny]{C.RESET}" if is_custom else ""
    print()
    print(box_top(f"Motyw: {name.upper()}{lbl}", width=width, color=C.PROMPT))
    for key, desc in [
        ("PROMPT",  "prompt / nagłówki"),
        ("PATH",    "ścieżki / sukces"),
        ("INFO",    "informacje"),
        ("ERROR",   "błędy"),
        ("WARN",    "ostrzeżenia"),
        ("DIM",     "przygaszone"),
        ("KEYWORD", "słowa kluczowe"),
        ("STRING",  "łańcuchy"),
        ("NUMBER",  "liczby"),
        ("COMMENT", "komentarze"),
    ]:
        color  = t.get(key, "\033[0m")
        swatch = f"{color}████{rst}"
        print(box_row(f"  {swatch}  {C.DIM}{key:<10}{rst} {desc}",
                      width=width, color=C.PROMPT))
    print(box_sep(width=width, color=C.PROMPT))
    avail = "  ".join(
        f"{C.BOLD if n == _CURRENT_THEME else ''}{n}{rst}" for n in _THEMES
    )
    print(box_row(f"  Dostępne: {avail}", width=width, color=C.PROMPT))
    print(box_row(
        f"  {C.DIM}theme list  |  theme create <nazwa>  |  theme save{rst}",
        width=width, color=C.PROMPT))
    print(box_bottom(width=width, color=C.PROMPT))
    print()

@command("theme", "Przełącz / twórz / zarządzaj motywami kolorystycznymi",
         aliases=["motyw"])
def cmd_theme(args):
    """
    theme                        — podgląd aktywnego motywu
    theme <nazwa>                — przełącz motyw (dark / light / własny)
    theme list                   — lista wszystkich motywów z próbkami
    theme save                   — zapisz motyw do ~/.terminalxrc
    theme create <nazwa>         — utwórz własny motyw (kopia aktywnego)
    theme clone <źródło> <cel>   — sklonuj dowolny motyw pod nową nazwą
    theme edit <nazwa> <klucz> <sekwencja_ANSI>  — zmień jeden kolor
    theme delete <nazwa>         — usuń własny motyw
    theme show <nazwa>           — podgląd konkretnego motywu
    theme export <nazwa> [plik]  — eksportuj motyw do JSON
    theme import <plik.json>     — importuj motywy z pliku JSON

    Klucze kolorów (używaj sekwencji ANSI, np. \\033[95m):
      PROMPT  PATH  INFO  ERROR  WARN  DIM  BOLD  RESET
      KEYWORD STRING NUMBER COMMENT BUILTIN MATCH
      SB_BG SB_FG SB_HL SB_ERR SB_OK
    """
    sub  = args[0].lower() if args else "show"
    w    = min(terminal_width() - 2, 52)

    # ── show (domyślne / bez argumentu) ──────────────────────────────────
    if not args or sub == "show":
        target = args[1] if len(args) > 1 else _CURRENT_THEME
        _theme_preview(target, w)
        return

    # ── list ──────────────────────────────────────────────────────────────
    if sub == "list":
        print()
        print(box_top(f"Motywy kolorystyczne  ({len(_THEMES)})", width=w, color=C.PROMPT))
        for name, t in _THEMES.items():
            active  = name == _CURRENT_THEME
            builtin = name in _BUILTIN_THEME_NAMES
            a_mark  = f" {C.PATH}◄{C.RESET}" if active else ""
            t_label = f"{C.DIM}wbudowany{C.RESET}" if builtin else f"{C.INFO}własny{C.RESET}"
            swatch  = "".join(
                f"{t.get(k,'')}▌{t.get('RESET','')}"
                for k in ("PROMPT", "PATH", "INFO", "ERROR", "KEYWORD")
            )
            print(box_row(
                f"  {C.BOLD}{name:<14}{C.RESET} {t_label:<20} {swatch}{a_mark}",
                width=w, color=C.PROMPT))
        print(box_sep(width=w, color=C.PROMPT))
        print(box_row(
            f"  {C.DIM}theme create <nazwa>  ·  theme show <nazwa>{C.RESET}",
            width=w, color=C.PROMPT))
        print(box_bottom(width=w, color=C.PROMPT))
        print()
        return

    # ── save ──────────────────────────────────────────────────────────────
    if sub == "save":
        try:
            lines = RC_FILE.read_text(encoding="utf-8").splitlines() if RC_FILE.exists() else []
            lines = [l for l in lines if not l.startswith("theme ")]
            lines.append(f"theme {_CURRENT_THEME}")
            RC_FILE.write_text("\n".join(lines) + "\n", encoding="utf-8")
            print_info(f"Motyw '{_CURRENT_THEME}' zapisany do {RC_FILE}")
        except Exception as e:
            smart_error(e, "theme save")
        return

    # ── create ────────────────────────────────────────────────────────────
    if sub == "create":
        if len(args) < 2:
            print_error("Uzycie: theme create <nazwa>"); return
        new_name = args[1].lower().strip()
        if not re.match(r'^[a-z0-9_-]+$', new_name):
            print_error("Nazwa może zawierać tylko: a-z 0-9 _ -"); return
        if new_name in _THEMES:
            print_error(f"Motyw '{new_name}' już istnieje"); return
        _THEMES[new_name] = dict(_THEMES.get(_CURRENT_THEME, _THEMES.get("dark", {})))
        _save_custom_themes()
        print_info(f"Utworzono motyw '{new_name}' (kopia '{_CURRENT_THEME}')")
        print(f"  {C.DIM}Edytuj: theme edit {new_name} PROMPT '\\033[95m'{C.RESET}")
        print(f"  {C.DIM}Włącz:  theme {new_name}{C.RESET}")
        return

    # ── clone ─────────────────────────────────────────────────────────────
    if sub == "clone":
        if len(args) < 3:
            print_error("Uzycie: theme clone <źródło> <cel>"); return
        src, dst = args[1].lower(), args[2].lower()
        if src not in _THEMES:
            print_error(f"Nieznany motyw źródłowy: '{src}'"); return
        if dst in _THEMES:
            print_error(f"Motyw '{dst}' już istnieje"); return
        _THEMES[dst] = dict(_THEMES[src])
        _save_custom_themes()
        print_info(f"Sklonowano: '{src}' → '{dst}'")
        return

    # ── edit ──────────────────────────────────────────────────────────────
    if sub == "edit":
        if len(args) < 4:
            print_error("Uzycie: theme edit <nazwa> <klucz> <sekwencja_ANSI>"); return
        t_name = args[1].lower()
        key    = args[2].upper()
        value  = " ".join(args[3:]).replace("\\033", "\033").replace("\\e", "\033")
        if t_name not in _THEMES:
            print_error(f"Nieznany motyw: '{t_name}'"); return
        if t_name in _BUILTIN_THEME_NAMES:
            print_error("Nie można edytować wbudowanych motywów dark/light",
                        f"Sklonuj najpierw: theme clone {t_name} moj_{t_name}"); return
        _THEMES[t_name][key] = value
        _save_custom_themes()
        if t_name == _CURRENT_THEME:
            C._apply()
        print_info(f"Zaktualizowano '{t_name}'.{key}")
        print(f"  {C.DIM}Podgląd: theme show {t_name}{C.RESET}")
        return

    # ── delete ────────────────────────────────────────────────────────────
    if sub == "delete":
        if len(args) < 2:
            print_error("Uzycie: theme delete <nazwa>"); return
        t_name = args[1].lower()
        if t_name in _BUILTIN_THEME_NAMES:
            print_error("Nie można usunąć wbudowanych motywów dark/light"); return
        if t_name not in _THEMES:
            print_error(f"Motyw nie istnieje: '{t_name}'"); return
        if t_name == _CURRENT_THEME:
            _apply_theme("dark")
            print_info("Przełączono na motyw 'dark' przed usunięciem")
        del _THEMES[t_name]
        _save_custom_themes()
        print_info(f"Usunięto motyw: '{t_name}'")
        return

    # ── export ────────────────────────────────────────────────────────────
    if sub == "export":
        if len(args) < 2:
            print_error("Uzycie: theme export <nazwa> [plik.json]"); return
        t_name = args[1].lower()
        if t_name not in _THEMES:
            print_error(f"Nieznany motyw: '{t_name}'"); return
        export_dir  = Path(cfg("save_path_exports", "") or ".")
        export_path = Path(args[2]) if len(args) > 2 else export_dir / f"theme_{t_name}.json"
        try:
            export_path.write_text(
                json.dumps({t_name: _THEMES[t_name]}, indent=2, ensure_ascii=False),
                encoding="utf-8"
            )
            print_info(f"Wyeksportowano '{t_name}': {export_path}")
        except Exception as e:
            print_error(f"Błąd eksportu: {e}")
        return

    # ── import ────────────────────────────────────────────────────────────
    if sub == "import":
        if len(args) < 2:
            print_error("Uzycie: theme import <plik.json>"); return
        import_path = Path(args[1]).expanduser()
        if not import_path.exists():
            print_error(f"Plik nie istnieje: {import_path}"); return
        try:
            data = json.loads(import_path.read_text(encoding="utf-8"))
        except Exception as e:
            print_error(f"Błąd odczytu: {e}"); return
        imported = []
        for t_name, t_data in data.items():
            if t_name in _BUILTIN_THEME_NAMES:
                print_error(f"Pominięto '{t_name}' — nazwa zarezerwowana"); continue
            if isinstance(t_data, dict):
                _THEMES[t_name] = t_data
                imported.append(t_name)
        if imported:
            _save_custom_themes()
            print_info(f"Zaimportowano motywy: {', '.join(imported)}")
        else:
            print_info("Brak nowych motywów do zaimportowania.")
        return

    # ── przełączenie po nazwie (fallback) ─────────────────────────────────
    if _apply_theme(sub):
        print_info(f"Motyw przełączony: {C.BOLD}{sub.upper()}{C.RESET}  "
                   f"(theme save — aby zapisac trwale)")

# STATUS_BAR
#   Pasek statusu wyswietlany w petli glownej (ANSI, bez curses)
#   Format: [motyw] [katalog] [gałaz git?] [last_exit] [czas] [user]

_STATUS_ENABLED = _STATE.status_enabled

def _git_branch() -> str:
    """Zwraca biezaca galaz git lub '' jesli nie w repozytorium."""
    try:
        r = subprocess.run(
            ["git", "rev-parse", "--abbrev-ref", "HEAD"],
            capture_output=True, text=True, timeout=1
        )
        if r.returncode == 0:
            return r.stdout.strip()
    except Exception:  # ignorowane celowo
        pass
    return ""

def render_status_bar() -> str:
    """
    Buduje jednolinijkowy pasek statusu ANSI.
    Wywolywany przed kazda petla promptu.
    """
    if not _STATUS_ENABLED:
        return ""

    sb  = _THEMES.get(_CURRENT_THEME, _THEMES.get("dark", {}))
    BG  = sb["SB_BG"]
    FG  = sb["SB_FG"]
    HL  = sb["SB_HL"]
    ERR = sb["SB_ERR"]
    OK  = sb["SB_OK"]
    RST = "\033[0m"

    w     = terminal_width()
    parts = []

    # Motyw
    # 🌙 zajmuje 2 kolumny terminala, ☀️  1 — kompensujemy spacją
    if _CURRENT_THEME == "dark":
        parts.append(f"{BG}{HL} 🌙{_CURRENT_THEME} {RST}")   # 1 spacja przed + 0 po emoji
    else:
        parts.append(f"{BG}{HL} ☀️  {_CURRENT_THEME} {RST}")  # 1 spacja przed + 2 po emoji

    # Katalog (skrocony)
    cwd = Path.cwd()
    home = Path.home()
    try:
        rel = "~/" + str(cwd.relative_to(home))
    except ValueError:
        rel = str(cwd)
    if len(rel) > 30:
        rel = "…" + rel[-28:]
    parts.append(f"{BG}{FG} 📂 {HL}{rel}{RST}")

    # Galaz git
    branch = _git_branch()
    if branch:
        parts.append(f"{BG}{FG}  {HL}{branch}{RST}")

    # Ostatni exit code
    from_exit = SHELL_VARS.get("_LAST_EXIT_DISPLAY", "0")
    if from_exit != "0":
        parts.append(f"{BG}{ERR} ✖ exit:{from_exit} {RST}")
    else:
        parts.append(f"{BG}{OK} ✔ {RST}")

    # Czas
    now = datetime.datetime.now().strftime("%H:%M:%S")
    parts.append(f"{BG}{FG} 🕐 {now} {RST}")

    # User / root
    user_label = f"{ERR}ROOT{RST}" if IS_ROOT else FG + "user"
    parts.append(f"{BG} {user_label} {RST}")

    # Sklej i wypelnij do szerokosci terminala
    bar_raw = "  ".join(parts)
    visible_len = len(re.sub(r"\033\[[0-9;]*m|\033\[48;5;\d+m|\033\[38;5;\d+m", "", bar_raw))
    pad = max(0, w - visible_len - 1)
    return bar_raw + f"{BG}{FG}{' ' * pad}{RST}"

@command("status", "Przelacz / pokaz pasek statusu",
         aliases=["sb"])
def cmd_status(args):
    """
    status        - pokaz stan paska statusu
    status on     - wlacz pasek statusu
    status off    - wylacz pasek statusu
    status show   - wymusz jednorazowe wyswietlenie paska
    """
    if not args:
        # Tylko informacja o stanie — pasek jest juz drukowany przez petle glowna,
        # wypisanie go tu drugi raz powodowaloby duplikacje.
        stan = f"{C.OK}wlaczony{C.RESET}" if _STATUS_ENABLED else f"{C.DIM}wylaczony{C.RESET}"
        print(f"  Pasek statusu: {stan}")
        print(f"  {C.DIM}Uzycie: status on | status off | status show{C.RESET}")
        return
    sub = args[0].lower()
    if sub == "show":
        # Jawne jednorazowe wyswietlenie (np. gdy pasek jest wylaczony)
        bar = render_status_bar()
        if bar:
            print(bar)
        else:
            print(f"  {C.DIM}(Pasek statusu jest wylaczony — uzyj: status on){C.RESET}")
    elif sub == "on":
        _STATE.status_enabled = True
        print_info("Pasek statusu wlaczony")
    elif sub == "off":
        _STATE.status_enabled = False
        print_info("Pasek statusu wylaczony")
    else:
        print_error(f"Nieznana opcja: '{args[0]}'",
                    "Uzycie: status on | status off | status show")

# SHORTCUTS
#   Czytelna lista skrotow klawiszowych

