@command("tui", "Interaktywne menu TUI (tekstowe)",
         aliases=["menu", "m"])
def cmd_tui(args):
    """
    tui   - otwiera interaktywne menu główne

    Nowe sekcje:
      📂  Pliki → przeglądarka plików (nav)
      🖥️  System → monitor procesów (procmon) + logi na żywo (logtail)

    Sterowanie:
      Strzałki Góra/Dół  lub  j/k  — poruszanie
      Enter lub spacja              — wybór
      /                             — szybkie wyszukiwanie
      q / ESC                       — wyjdź / wstecz
    """
    _tui_main_menu_v2()

# NAV — PRZEGLĄDARKA PLIKÓW TUI
#
#   nav [ścieżka]    — interaktywna przeglądarka katalogów (ANSI, bez curses)
#   Sterowanie:
#     ↑/↓ lub j/k   — poruszanie po liście
#     Enter          — wejdź do katalogu / podgląd pliku (cat)
#     Backspace/h    — katalog nadrzędny (..)
#     e              — edytuj plik w nano-lite
#     d              — usuń plik (z potwierdzeniem)
#     r              — zmień nazwę pliku
#     n              — nowy plik
#     N              — nowy katalog
#     /              — szybkie wyszukiwanie w bieżącym katalogu
#     q/ESC          — wyjście

# Stałe sortowania nav
_NAV_SORT_MODES  = ["name", "size", "date", "ext"]
_NAV_SORT_LABELS = {"name": "nazwa", "size": "rozmiar", "date": "data", "ext": "typ"}

# Globalne zakładki nav (per-sesja)
_NAV_BOOKMARKS: list = []

def _nav_list_dir(path: Path) -> list:
    """Zwraca listę wpisów katalogu (bez sortowania — sortuje _nav_sort)."""
    entries = []
    try:
        for p in path.iterdir():
            entries.append(p)
    except PermissionError:
        pass
    return entries

def _nav_file_icon(p: Path) -> str:
    if p.is_dir():
        return "📁"
    return EXT_ICONS.get(p.suffix.lower(), "📄")

def _nav_file_size(p: Path) -> str:
    try:
        s = p.stat().st_size
        for unit in ("B", "K", "M", "G"):
            if s < 1024:
                return f"{s:.0f}{unit}"
            s /= 1024
        return f"{s:.1f}T"
    except Exception:
        return "?"

def _nav_sort(entries: list, mode: str, reverse: bool = False) -> list:
    """Sortuje listę Path wg wybranego trybu (katalogi zawsze pierwsze)."""
    def key(p: Path):
        is_dir = p.is_dir()
        if mode == "name":
            return (not is_dir, p.name.lower())
        if mode == "size":
            try:
                sz = p.stat().st_size if p.is_file() else 0
            except Exception:
                sz = 0
            return (not is_dir, sz if not reverse else -sz)
        if mode == "date":
            try:
                mt = p.stat().st_mtime
            except Exception:
                mt = 0
            return (not is_dir, -mt if not reverse else mt)
        if mode == "ext":
            return (not is_dir, p.suffix.lower(), p.name.lower())
        return (not is_dir, p.name.lower())
    return sorted(entries, key=key, reverse=False)  # katalogi zawsze pierwsze

def _nav_perms(p: Path) -> str:
    """Zwraca string uprawnień rwxrwxrwx lub '' na Windows."""
    if os.name == "nt":
        return ""
    try:
        import stat as _stat
        mode = p.stat().st_mode
        r = lambda m, b: b if mode & m else "-"
        return (r(_stat.S_IRUSR, "r") + r(_stat.S_IWUSR, "w") + r(_stat.S_IXUSR, "x") +
                r(_stat.S_IRGRP, "r") + r(_stat.S_IWGRP, "w") + r(_stat.S_IXGRP, "x") +
                r(_stat.S_IROTH, "r") + r(_stat.S_IWOTH, "w") + r(_stat.S_IXOTH, "x"))
    except Exception:
        return "?????????"

def _nav_mtime(p: Path) -> str:
    try:
        mt  = p.stat().st_mtime
        t   = datetime.datetime.fromtimestamp(mt)
        now = datetime.datetime.now()
        if t.date() == now.date():
            return t.strftime("dzisiaj %H:%M")
        if (now - t).days < 7:
            return t.strftime("%a %H:%M")
        return t.strftime("%d.%m.%y")
    except Exception:
        return ""

def _nav_breadcrumb(cwd: Path) -> str:
    home = Path.home()
    try:
        rel   = cwd.relative_to(home)
        parts = ["~"] + list(rel.parts)
    except ValueError:
        parts = list(cwd.parts)
    if len(parts) > 4:
        parts = parts[:1] + ["…"] + parts[-2:]
    return " / ".join(parts)

def _nav_preview(p: Path, max_lines: int = 20) -> list:
    try:
        text  = p.read_text(encoding="utf-8", errors="replace")
        lines = text.splitlines()[:max_lines]
        return lines if lines else ["(pusty plik)"]
    except Exception:
        return [f"(binarny: {_nav_file_size(p)})"]

def _nav_render(cwd: Path, entries: list, idx: int, filt: str, msg: str, w: int):
    """Wrapper kompatybilności — wywołuje nowy _nav_render_v2."""
    return _nav_render_v2(cwd, entries, idx, filt, msg, w,
                          show_hidden=False, sort_mode="name",
                          bookmarks=[], preview_on=False)

def _nav_render_v2(cwd: Path, entries: list, idx: int, filt: str, msg: str,
                   w: int, show_hidden: bool, sort_mode: str,
                   bookmarks: list, preview_on: bool) -> int:
    """Renderuje interfejs nav z podglądem, breadcrumb, uprawnieniami, datą."""
    visible = [e for e in entries
               if (show_hidden or not e.name.startswith("."))
               and (not filt or filt.lower() in e.name.lower())]

    do_preview = preview_on and w >= 110
    left_w     = (w // 2 - 1) if do_preview else w

    bc       = _nav_breadcrumb(cwd)
    sort_lbl = _NAV_SORT_LABELS.get(sort_mode, sort_mode)
    hid_lbl  = f"  {C.INFO}·ukryte{C.RESET}" if show_hidden else ""
    title    = f" 📂 {C.BOLD}{bc}{C.RESET}  {C.DIM}[sort:{sort_lbl}]{C.RESET}{hid_lbl}"

    lines_drawn = 0
    print(box_top(title, width=w, color=C.PATH))
    lines_drawn += 1

    if filt:
        cnt = len(visible)
        fc  = (f"  {C.DIM}Filtr:{C.RESET} {C.INFO}{filt}{C.RESET}"
               f"  {C.DIM}{cnt} wyników{C.RESET}")
        print(box_row(fc, width=w, color=C.PATH))
        print(box_sep(width=w, color=C.PATH))
        lines_drawn += 2

    # Nagłówek kolumn
    if do_preview:
        hdr = f" {C.DIM}{'Nazwa':<{left_w - 20}} {'Rozm':>5}  {'Data':<12}  Podgląd{C.RESET}"
    else:
        hdr = f" {C.DIM}{'Nazwa':<{w - 30}} {'Rozm':>5}  {'Data':<12}  Upraw.{C.RESET}"
    print(box_row(hdr, width=w, color=C.PATH))
    print(box_sep(width=w, color=C.PATH))
    lines_drawn += 2

    # Wiersz ".."
    print(box_row(f"  {C.DIM}↩  ..  (katalog nadrzędny){C.RESET}", width=w, color=C.PATH))
    lines_drawn += 1

    if not visible:
        msg_txt = f"  {C.DIM}(brak wyników{' dla: ' + repr(filt) if filt else ''}){C.RESET}"
        print(box_row(msg_txt, width=w, color=C.PATH))
        lines_drawn += 1
    else:
        sel_idx   = idx % max(1, len(visible))
        sel_path  = visible[sel_idx] if visible else None

        preview_lines: list = []
        if do_preview and sel_path and sel_path.is_file():
            preview_lines = _nav_preview(sel_path, max_lines=len(visible) + 4)

        for i, p in enumerate(visible):
            is_sel   = (i == sel_idx)
            icon     = _nav_file_icon(p)
            name     = p.name + ("/" if p.is_dir() else "")
            size_str = "" if p.is_dir() else f"{_nav_file_size(p):>5}"
            date_str = _nav_mtime(p)
            perms    = _nav_perms(p) if not do_preview else ""

            if p.is_dir():
                ncol = C.PATH
            elif p.suffix in (".py", ".js", ".ts", ".sh", ".bash"):
                ncol = C.CODE
            else:
                ncol = ext_color(p.suffix)

            name_max  = left_w - 22 if do_preview else w - 30
            name_disp = name if len(name) <= name_max else name[:name_max - 1] + "…"

            if is_sel:
                marker    = f"{C.PATH}▶{C.RESET}"
                left_cell = (f" {marker} {icon} {ncol}{C.BOLD}{name_disp}{C.RESET}"
                             f"  {C.DIM}{size_str:>5}  {date_str:<12}{C.RESET}")
            else:
                left_cell = (f"   {icon} {ncol}{name_disp}{C.RESET}"
                             f"  {C.DIM}{size_str:>5}  {date_str:<12}{C.RESET}")

            if not do_preview:
                left_cell += f"  {C.DIM}{perms}{C.RESET}"
                print(box_row(left_cell, width=w, color=C.PATH))
            else:
                right_w  = w - left_w - 3
                pv_raw   = preview_lines[i] if i < len(preview_lines) else ""
                if len(pv_raw) > right_w:
                    pv_raw = pv_raw[:right_w - 1] + "…"
                pv_line  = f"{C.DIM}{pv_raw}{C.RESET}" if pv_raw else ""
                row_txt  = left_cell + f"  {C.DIM}│{C.RESET} " + pv_line
                print(box_row(row_txt, width=w, color=C.PATH))

        lines_drawn += len(visible)

    # Zakładki
    if bookmarks:
        print(box_sep(width=w, color=C.PATH))
        bm_labels = "  ".join(
            f"{C.INFO}[{i+1}]{C.RESET} {C.DIM}{b.name}{C.RESET}"
            for i, b in enumerate(bookmarks[:5])
        )
        print(box_row(f"  📌 {C.DIM}Zakładki:{C.RESET}  {bm_labels}", width=w, color=C.PATH))
        lines_drawn += 2

    # Info o zaznaczonym pliku
    if visible:
        sel       = visible[idx % max(1, len(visible))]
        perms_str = _nav_perms(sel)
        sz_str    = _nav_file_size(sel) if sel.is_file() else "katalog"
        date_str  = _nav_mtime(sel)
        info_line = (f"  {C.DIM}{perms_str}  {sz_str}  {date_str}"
                     f"  {sel.suffix or '—'}{C.RESET}")
        print(box_sep(width=w, color=C.PATH))
        print(box_row(info_line, width=w, color=C.PATH))
        lines_drawn += 2
    else:
        print(box_sep(width=w, color=C.PATH))
        lines_drawn += 1

    if msg:
        print(box_row(f"  {C.INFO}✓ {msg}{C.RESET}", width=w, color=C.PATH))
        lines_drawn += 1

    hint1 = (f"  {C.DIM}↑↓ j/k ruch  PgUp/PgDn  Enter wejdź  h/← wróć"
             f"  e edytuj  d usuń  r zmień  n plik  N katalog{C.RESET}")
    hint2 = (f"  {C.DIM}/ filtr  s sortuj  . ukryte  v podgląd"
             f"  y kopiuj ścieżkę  b zakładka  B skocz  q wyjdź{C.RESET}")
    print(box_row(hint1, width=w, color=C.PATH))
    print(box_row(hint2, width=w, color=C.PATH))
    print(box_bottom(width=w, color=C.PATH))
    lines_drawn += 3

    return lines_drawn


def _nav_run(start: Path):
    """Główna pętla przeglądarki plików TUI — v35.3."""
    if os.name == "nt" or not sys.stdin.isatty():
        print_info("nav: tryb interaktywny wymaga TTY.")
        execute_line(f"ls {start}")
        return

    try:
        import tty, termios, select
    except ImportError:
        print_info("nav: brak modułów tty/termios — tryb uproszczony.")
        execute_line(f"ls {start}")
        return

    cwd         = start.resolve()
    idx         = 0
    filt        = ""
    msg         = ""
    drawn       = 0
    sort_idx    = 0
    show_hidden = False
    preview_on  = True
    bookmarks   = list(_NAV_BOOKMARKS)

    def sort_mode() -> str:
        return _NAV_SORT_MODES[sort_idx % len(_NAV_SORT_MODES)]

    def getch():
        fd  = sys.stdin.fileno()
        old = termios.tcgetattr(fd)
        try:
            tty.setraw(fd)
            ch = sys.stdin.buffer.read(1)
            if ch == b"\x1b":
                r, _, _ = select.select([sys.stdin], [], [], 0.08)
                if r:
                    nxt = sys.stdin.buffer.read(1)
                    ch += nxt
                    if nxt == b"[":
                        r2, _, _ = select.select([sys.stdin], [], [], 0.05)
                        if r2:
                            ch += sys.stdin.buffer.read(4)
            return ch
        finally:
            termios.tcsetattr(fd, termios.TCSADRAIN, old)

    def clear(n):
        for _ in range(n):
            print("\033[A\033[2K", end="")

    def get_visible(entries):
        return [e for e in entries
                if (show_hidden or not e.name.startswith("."))
                and (not filt or filt.lower() in e.name.lower())]

    def copy_to_clipboard(text: str):
        for tool, args in [
            ("xclip",  ["xclip", "-selection", "clipboard"]),
            ("xsel",   ["xsel", "--clipboard", "--input"]),
            ("pbcopy", ["pbcopy"]),
        ]:
            if shutil.which(tool):
                try:
                    subprocess.run(args, input=text.encode(), check=True)
                    return tool
                except Exception:
                    pass
        if os.name == "nt":
            try:
                subprocess.run(["clip"], input=text.encode("utf-16-le"), check=True)
                return "clip"
            except Exception:
                pass
        return None

    _w = min(terminal_width() - 2, 120)

    while True:
        all_entries = _nav_list_dir(cwd)
        all_entries = _nav_sort(all_entries, sort_mode())
        visible     = get_visible(all_entries)

        _new_w = min(terminal_width() - 2, 120)
        if _new_w != _w:
            _w = _new_w

        if drawn:
            clear(drawn)

        drawn = _nav_render_v2(
            cwd, all_entries, idx, filt, msg, _w,
            show_hidden, sort_mode(), bookmarks, preview_on
        )
        msg = ""

        ch = getch()

        if ch in (b"q", b"Q", b"\x1b", b"\x03"):
            clear(drawn)
            break

        elif ch in (b"\x1b[A", b"k"):
            idx = (idx - 1) % max(1, len(visible))

        elif ch in (b"\x1b[B", b"j"):
            idx = (idx + 1) % max(1, len(visible))

        elif ch in (b"\x1b[5~", b"u"):
            idx = max(0, idx - 10)

        elif ch in (b"\x1b[6~", b"d"):
            idx = min(max(0, len(visible) - 1), idx + 10)

        elif ch == b"\x1b[H":
            idx = 0

        elif ch == b"\x1b[F":
            idx = max(0, len(visible) - 1)

        elif ch in (b"h", b"\x1b[D", b"\x7f", b"\x08"):
            cwd  = cwd.parent
            idx  = 0
            filt = ""

        elif ch in (b"\r", b"\n"):
            if visible:
                sel = visible[idx % max(1, len(visible))]
                if sel.is_dir():
                    cwd  = sel.resolve()
                    idx  = 0
                    filt = ""
                else:
                    clear(drawn); drawn = 0
                    print(f"\n  {C.INFO}── Podgląd: {sel.name} ──{C.RESET}\n")
                    execute_line(f"cat {shlex.quote(str(sel))}")
                    print(f"\n  {C.DIM}[Naciśnij dowolny klawisz]{C.RESET}")
                    getch()

        elif ch == b"e":
            if visible:
                sel = visible[idx % max(1, len(visible))]
                if not sel.is_dir():
                    clear(drawn); drawn = 0
                    execute_line(f"nano {shlex.quote(str(sel))}")

        elif ch == b"d":
            if visible:
                sel = visible[idx % max(1, len(visible))]
                clear(drawn); drawn = 0
                try:
                    ans = input(
                        f"  {C.ERROR}Usunąć '{sel.name}'? [t/n]: {C.RESET}"
                    ).strip().lower()
                except (EOFError, KeyboardInterrupt):
                    ans = "n"
                if ans in ("t", "y", "tak", "yes"):
                    try:
                        if sel.is_dir():
                            shutil.rmtree(sel)
                        else:
                            sel.unlink()
                        msg = f"Usunięto: {sel.name}"
                        idx = max(0, idx - 1)
                    except Exception as e:
                        msg = f"Błąd: {e}"
                else:
                    msg = "Anulowano."

        elif ch == b"r":
            if visible:
                sel = visible[idx % max(1, len(visible))]
                clear(drawn); drawn = 0
                try:
                    new_name = input(f"  Nowa nazwa dla '{sel.name}': ").strip()
                except (EOFError, KeyboardInterrupt):
                    new_name = ""
                if new_name:
                    try:
                        sel.rename(cwd / new_name)
                        msg = f"Zmieniono: {sel.name} → {new_name}"
                    except Exception as e:
                        msg = f"Błąd: {e}"

        elif ch == b"n":
            clear(drawn); drawn = 0
            try:
                fname = input("  Nazwa nowego pliku: ").strip()
            except (EOFError, KeyboardInterrupt):
                fname = ""
            if fname:
                try:
                    (cwd / fname).touch()
                    msg = f"Utworzono plik: {fname}"
                except Exception as e:
                    msg = f"Błąd: {e}"

        elif ch == b"N":
            clear(drawn); drawn = 0
            try:
                dname = input("  Nazwa nowego katalogu: ").strip()
            except (EOFError, KeyboardInterrupt):
                dname = ""
            if dname:
                try:
                    (cwd / dname).mkdir(parents=True, exist_ok=True)
                    msg = f"Katalog utworzony: {dname}"
                except Exception as e:
                    msg = f"Błąd: {e}"

        elif ch == b"/":
            clear(drawn); drawn = 0
            try:
                filt = input(f"  {C.INFO}Filtr:{C.RESET} ").strip()
                idx  = 0
            except (EOFError, KeyboardInterrupt):
                filt = ""

        elif ch == b"s":
            sort_idx = (sort_idx + 1) % len(_NAV_SORT_MODES)
            msg = f"Sortowanie: {_NAV_SORT_LABELS[sort_mode()]}"

        elif ch == b".":
            show_hidden = not show_hidden
            idx = 0
            msg = "Ukryte: widoczne" if show_hidden else "Ukryte: schowane"

        elif ch == b"v":
            preview_on = not preview_on
            msg = "Podgląd: włączony" if preview_on else "Podgląd: wyłączony"

        elif ch == b"y":
            if visible:
                sel  = visible[idx % max(1, len(visible))]
                tool = copy_to_clipboard(str(sel))
                if tool:
                    msg = f"Skopiowano ścieżkę ({tool})"
                else:
                    clear(drawn); drawn = 0
                    print(f"\n  {C.INFO}Ścieżka:{C.RESET}  {sel}\n"
                          f"  {C.DIM}(brak narzędzi schowka — zainstaluj xclip/xsel/pbcopy){C.RESET}\n")
                    print(f"  {C.DIM}[Naciśnij dowolny klawisz]{C.RESET}")
                    getch()

        elif ch == b"b":
            if cwd not in bookmarks:
                bookmarks.append(cwd)
                _NAV_BOOKMARKS.append(cwd)
                msg = f"Zakładka dodana: {cwd.name}"
            else:
                bookmarks.remove(cwd)
                if cwd in _NAV_BOOKMARKS:
                    _NAV_BOOKMARKS.remove(cwd)
                msg = f"Zakładka usunięta: {cwd.name}"

        elif ch == b"B":
            if bookmarks:
                clear(drawn); drawn = 0
                bm_menu = TuiMenu(
                    "Skocz do zakładki",
                    [(str(b), None) for b in bookmarks],
                    color=C.INFO
                )
                choice = bm_menu.run()
                if choice and choice != "__exit__":
                    target = Path(choice)
                    if target.is_dir():
                        cwd  = target
                        idx  = 0
                        filt = ""
            else:
                msg = "Brak zakładek — naciśnij b aby dodać bieżący katalog"


@command("nav", "Interaktywna przeglądarka plików TUI",
         aliases=["fb", "fm", "browse", "files"],
         flags=[])
def cmd_nav(args):
    """
    nav [ścieżka]   — otwiera przeglądarkę plików TUI

    Sterowanie:
      ↑↓ / j k      — poruszanie po liście
      Enter          — wejdź do katalogu lub podgląd pliku
      h / ←          — katalog nadrzędny
      e              — edytuj plik (nano-lite)
      d              — usuń plik/katalog (z potwierdzeniem)
      r              — zmień nazwę
      n / N          — nowy plik / nowy katalog
      /              — filtruj po nazwie
      q / ESC        — wyjście
    """
    start = Path(args[0]).expanduser() if args else Path.cwd()
    if not start.exists():
        print_error(f"Ścieżka nie istnieje: {start}")
        return
    if not start.is_dir():
        start = start.parent
    _nav_run(start)

# LOGTAIL — PODGLĄD LOGÓW W CZASIE RZECZYWISTYM
#
#   logtail [plik]       — śledź plik logu na żywo (jak tail -f z kolorowaniem)
#   logtail --shell      — śledź wewnętrzny log TerminalXa
#   logtail --crash      — śledź crashlog
#   Sterowanie: q/ESC/Ctrl+C — wyjście

def _logtail_colorize(line: str) -> str:
    """Koloruje linię logu wg poziomu."""
    ll = line.upper()
    if any(k in ll for k in ("ERROR", "CRITICAL", "EXCEPTION", "TRACEBACK", "FATAL")):
        return f"{C.ERROR}{line}{C.RESET}"
    if any(k in ll for k in ("WARN", "WARNING")):
        return f"{C.WARN}{line}{C.RESET}"
    if any(k in ll for k in ("INFO", "OK", "SUCCESS", "DONE")):
        return f"{C.OK}{line}{C.RESET}"
    if any(k in ll for k in ("DEBUG", "CMD", "EXEC")):
        return f"{C.DIM}{line}{C.RESET}"
    return line

def _logtail_run(path: Path, label: str):
    """Śledzi plik na żywo — drukuje nowe linie, odświeża co 0.5s."""
    import time, select as _select

    w = min(terminal_width() - 2, 76)
    print(box_top(f"  📜 logtail  {label}  ", width=w, color=C.INFO))
    print(box_row(f"  {C.DIM}Ctrl+C / q + Enter — wyjście{C.RESET}", width=w, color=C.INFO))
    print(box_bottom(width=w, color=C.INFO))
    print()

    # Pokaż ostatnie 15 linii na start
    try:
        if path.exists():
            lines = path.read_text(encoding="utf-8", errors="replace").splitlines()
            for ln in lines[-15:]:
                print(f"  {_logtail_colorize(ln)}")
    except Exception:  # ignorowane celowo
        pass

    # Ustaw stdin w tryb non-blocking (do detekcji 'q')
    use_select = (os.name != "nt" and sys.stdin.isatty())
    if use_select:
        import tty, termios
        fd  = sys.stdin.fileno()
        old = termios.tcgetattr(fd)
        tty.setcbreak(fd)

    try:
        last_size = path.stat().st_size if path.exists() else 0
        print(f"  {C.DIM}[następuje na bieżąco…]{C.RESET}", flush=True)

        while True:
            # Sprawdź klawisz 'q'
            if use_select:
                r, _, _ = _select.select([sys.stdin], [], [], 0.4)
                if r:
                    ch = sys.stdin.read(1)
                    if ch.lower() in ("q", "\x1b", "\x03"):
                        break
            else:
                time.sleep(0.5)

            # Sprawdź nową zawartość pliku
            try:
                cur_size = path.stat().st_size if path.exists() else 0
            except Exception:
                cur_size = last_size

            if cur_size > last_size:
                try:
                    with open(path, "r", encoding="utf-8", errors="replace") as f:
                        f.seek(last_size)
                        new_content = f.read()
                    for ln in new_content.splitlines():
                        if ln:
                            ts = datetime.datetime.now().strftime("%H:%M:%S")
                            print(f"  {C.DIM}{ts}{C.RESET}  {_logtail_colorize(ln)}")
                    last_size = cur_size
                except Exception as e:
                    print(f"  {C.ERROR}Błąd odczytu: {e}{C.RESET}")
            elif cur_size < last_size:
                # Plik skrócony (rotacja)
                last_size = 0
                print(f"  {C.WARN}[plik zrotowany — reset]{C.RESET}")

    except KeyboardInterrupt:
        pass
    finally:
        if use_select:
            termios.tcsetattr(fd, termios.TCSADRAIN, old)

    print(f"\n  {C.DIM}logtail zakończony.{C.RESET}\n")

@command("logtail", "Podgląd logów w czasie rzeczywistym",
         aliases=["logfollow", "tailf"],
         flags=["--shell", "--crash", "-n"])
def cmd_logtail(args):
    """
    logtail <plik>       — śledź dowolny plik logu na żywo
    logtail --shell      — wewnętrzny log TerminalXa (~/.terminalx.log)
    logtail --crash      — crashlog TerminalXa
    logtail --shell -n   — pokaż ostatnie N linii (domyślnie 15)

    Sterowanie:
      q / ESC / Ctrl+C   — wyjście
    """
    if "--shell" in args or not args:
        path  = LOG_FILE
        label = "TerminalX.log"
    elif "--crash" in args:
        path  = CRASHLOG_FILE
        label = "crashlog"
    else:
        path  = Path(args[0]).expanduser()
        label = path.name
        if not path.exists():
            print_error(f"Plik nie istnieje: {path}")
            return

    _logtail_run(path, label)

# PROCMON — MONITOR PROCESÓW (MINI TASK MANAGER)
#
#   procmon              — interaktywny podgląd procesów (odświeżanie co 2s)
#   procmon -n <N>       — pokaż N procesów (domyślnie 20)
#   procmon -s cpu|mem   — sortuj wg CPU lub pamięci
#   procmon -f <wzorzec> — filtruj po nazwie procesu
#   procmon kill <PID>   — wyślij SIGTERM do procesu
#   Sterowanie: q/ESC — wyjście, r — odśwież, k — zabij, s — przełącz sort

def _procmon_get_procs(sort_by: str = "cpu", filt: str = "") -> list[dict]:
    """
    Pobiera listę procesów przez 'ps' (cross-platform).
    Zwraca listę dicts: {pid, name, cpu, mem, user, cmd}.
    """
    procs = []

    # Próba przez psutil (jeśli dostępny)
    try:
        import psutil
        for p in psutil.process_iter(["pid", "name", "username", "cpu_percent",
                                       "memory_percent", "cmdline", "status"]):
            try:
                info = p.info
                name = info.get("name") or "?"
                if filt and filt.lower() not in name.lower():
                    continue
                cmd  = " ".join(info.get("cmdline") or [name])[:60]
                procs.append({
                    "pid":  info["pid"],
                    "name": name,
                    "cpu":  info.get("cpu_percent") or 0.0,
                    "mem":  info.get("memory_percent") or 0.0,
                    "user": (info.get("username") or "?")[:10],
                    "cmd":  cmd,
                    "status": info.get("status", "?"),
                })
            except (psutil.NoSuchProcess, psutil.AccessDenied):
                pass
    except ImportError:
        # Fallback: ps aux (Unix)
        try:
            out = subprocess.check_output(
                ["ps", "aux"], stderr=subprocess.DEVNULL,
                encoding="utf-8", errors="replace"
            )
            for line in out.splitlines()[1:]:
                parts = line.split(None, 10)
                if len(parts) < 11:
                    continue
                name = Path(parts[10].split()[0]).name if parts[10].strip() else "?"
                if filt and filt.lower() not in name.lower():
                    continue
                try:
                    procs.append({
                        "pid":  int(parts[1]),
                        "name": name[:20],
                        "cpu":  float(parts[2]),
                        "mem":  float(parts[3]),
                        "user": parts[0][:10],
                        "cmd":  parts[10][:60],
                        "status": "?",
                    })
                except (ValueError, IndexError):
                    pass
        except Exception:  # ignorowane celowo
            pass

    # Sortowanie
    key = "mem" if sort_by == "mem" else "cpu"
    procs.sort(key=lambda x: x.get(key, 0), reverse=True)
    return procs

def _procmon_render(procs: list, sort_by: str, filt: str,
                    sel: int, msg: str, w: int, limit: int):
    """Rysuje tabelę procesów."""
    sort_label = "CPU%" if sort_by == "cpu" else "MEM%"
    filt_label = f"  filtr:{C.INFO}{filt}{C.RESET}" if filt else ""
    title = f"  🖥️  procmon  {sort_label}↓{filt_label}  "
    print(box_top(title, width=w, color=C.EXEC))

    # Nagłówek kolumn
    hdr = (f"  {C.BOLD}{'PID':>6}  {'USER':<10}  {'CPU%':>5}  "
           f"{'MEM%':>5}  {'STATUS':<8}  NAZWA / KOMENDA{C.RESET}")
    print(box_row(hdr, width=w, color=C.EXEC))
    print(box_sep(width=w, color=C.EXEC))

    visible = procs[:limit]
    if not visible:
        print(box_row(f"  {C.DIM}Brak procesów{' dla filtra: ' + filt if filt else ''}{C.RESET}",
                      width=w, color=C.EXEC))
    else:
        for i, p in enumerate(visible):
            is_sel = (i == sel % max(1, len(visible)))
            cpu_c  = C.ERROR if p["cpu"] > 50 else (C.WARN if p["cpu"] > 10 else C.OK)
            mem_c  = C.ERROR if p["mem"] > 50 else (C.WARN if p["mem"] > 10 else C.OK)
            name   = p["name"][:18]
            cmd    = p["cmd"][:w - 58] if w > 58 else ""
            row = (f"  {C.INFO}{p['pid']:>6}{C.RESET}  "
                   f"{C.DIM}{p['user']:<10}{C.RESET}  "
                   f"{cpu_c}{p['cpu']:>5.1f}{C.RESET}  "
                   f"{mem_c}{p['mem']:>5.1f}{C.RESET}  "
                   f"{C.DIM}{p.get('status','?'):<8}{C.RESET}  "
                   f"{'▶ ' if is_sel else '  '}"
                   f"{C.BOLD if is_sel else ''}{name}{C.RESET}"
                   f"  {C.DIM}{cmd}{C.RESET}")
            print(box_row(row, width=w, color=C.EXEC))

    print(box_sep(width=w, color=C.EXEC))
    if msg:
        print(box_row(f"  {C.INFO}{msg}{C.RESET}", width=w, color=C.EXEC))

    now = datetime.datetime.now().strftime("%H:%M:%S")
    hint = (f"  {C.DIM}↑↓ wybierz  k zabij  s sort  r odśwież"
            f"  / filtr  q wyjdź  {now}{C.RESET}")
    print(box_row(hint, width=w, color=C.EXEC))
    print(box_bottom(width=w, color=C.EXEC))
    return len(visible) + 6 + (1 if msg else 0)

def _procmon_run(limit: int = 20, sort_by: str = "cpu", filt: str = ""):
    """Główna pętla monitora procesów."""
    import time

    if os.name == "nt" or not sys.stdin.isatty():
        # Tryb jednorazowy bez interakcji
        procs = _procmon_get_procs(sort_by, filt)
        w = min(terminal_width() - 2, 90)
        _procmon_render(procs, sort_by, filt, -1, "", w, limit)
        return

    try:
        import tty, termios, select as _select
    except ImportError:
        procs = _procmon_get_procs(sort_by, filt)
        w = min(terminal_width() - 2, 90)
        _procmon_render(procs, sort_by, filt, -1, "", w, limit)
        return

    fd  = sys.stdin.fileno()
    old = termios.tcgetattr(fd)
    tty.setcbreak(fd)

    sel   = 0
    msg   = ""
    drawn = 0
    last_refresh = 0.0
    w     = min(terminal_width() - 2, 90)   # raz przed pętlą — procmon odświeża co 2s

    try:
        while True:
            now_t = time.monotonic()
            # Odśwież co 2 sekundy lub na żądanie
            if now_t - last_refresh >= 2.0:
                procs = _procmon_get_procs(sort_by, filt)
                last_refresh = now_t

            # w obliczone poza pętlą — terminal nie zmienia się dynamicznie
            if drawn:
                for _ in range(drawn):
                    print("\033[A\033[2K", end="")
            drawn = _procmon_render(procs, sort_by, filt, sel, msg, w, limit)
            msg = ""

            # Czekaj na klawisz maks 2s
            r, _, _ = _select.select([sys.stdin], [], [], 2.0)
            if not r:
                continue

            ch = sys.stdin.read(1)

            if ch in ("q", "Q", "\x1b", "\x03"):
                break

            # Nawigacja
            elif ch in ("\x1b[A", "k"):
                sel = (sel - 1) % max(1, min(limit, len(procs)))
            elif ch in ("\x1b[B", "j"):
                sel = (sel + 1) % max(1, min(limit, len(procs)))

            # Odśwież
            elif ch in ("r", "R"):
                procs = _procmon_get_procs(sort_by, filt)
                last_refresh = time.monotonic()
                msg = "Odświeżono."

            # Przełącz sortowanie
            elif ch == "s":
                sort_by = "mem" if sort_by == "cpu" else "cpu"
                procs.sort(key=lambda x: x.get(sort_by, 0), reverse=True)
                msg = f"Sortowanie: {'MEM%' if sort_by == 'mem' else 'CPU%'}"

            # Zabij proces
            elif ch == "k":
                if procs and 0 <= sel < len(procs):
                    pid  = procs[sel]["pid"]
                    name = procs[sel]["name"]
                    # Przejdź do trybu blokującego na chwilę potwierdzenia
                    termios.tcsetattr(fd, termios.TCSADRAIN, old)
                    try:
                        ans = input(f"\n  {C.ERROR}Zabić proces {pid} ({name})? [t/n]: {C.RESET}").strip().lower()
                    except (EOFError, KeyboardInterrupt):
                        ans = "n"
                    tty.setcbreak(fd)
                    if ans in ("t", "y", "tak", "yes"):
                        try:
                            import signal as _signal
                            os.kill(pid, _signal.SIGTERM)
                            msg = f"SIGTERM → {pid} ({name})"
                            procs = _procmon_get_procs(sort_by, filt)
                            last_refresh = time.monotonic()
                        except Exception as e:
                            msg = f"Błąd: {e}"
                    else:
                        msg = "Anulowano."

            # Filtr
            elif ch == "/":
                termios.tcsetattr(fd, termios.TCSADRAIN, old)
                try:
                    filt = input(f"\n  {C.INFO}Filtr nazwy procesu:{C.RESET} ").strip()
                    sel  = 0
                    procs = _procmon_get_procs(sort_by, filt)
                    last_refresh = time.monotonic()
                except (EOFError, KeyboardInterrupt):
                    filt = ""
                tty.setcbreak(fd)

    except KeyboardInterrupt:
        pass
    finally:
        termios.tcsetattr(fd, termios.TCSADRAIN, old)
        if drawn:
            for _ in range(drawn):
                print("\033[A\033[2K", end="")

    print(f"\n  {C.DIM}procmon zakończony.{C.RESET}\n")

@command("procmon", "Monitor procesów — mini Task Manager TUI",
         aliases=["top", "procs", "tasks", "taskman"],
         flags=["-n", "-s", "-f", "kill"])
def cmd_procmon(args):
    """
    procmon              — interaktywny monitor procesów (odświeżanie co 2s)
    procmon -n <N>       — pokaż N procesów (domyślnie 20)
    procmon -s cpu|mem   — sortuj wg CPU% lub MEM%
    procmon -f <wzorzec> — filtruj po nazwie procesu
    procmon kill <PID>   — wyślij SIGTERM do procesu i wyjdź

    Sterowanie (tryb interaktywny):
      ↑↓ / j k           — nawigacja
      k                  — zabij zaznaczony proces
      s                  — przełącz sortowanie CPU/MEM
      r                  — ręczne odświeżenie
      /                  — filtr nazwy
      q / ESC / Ctrl+C   — wyjście
    """
    # Tryb kill bez TUI
    if args and args[0] == "kill":
        if len(args) < 2:
            print_error("Podaj PID: procmon kill <PID>")
            return
        try:
            import signal as _signal
            pid = int(args[1])
            os.kill(pid, _signal.SIGTERM)
            print_info(f"Wysłano SIGTERM do PID {pid}.")
        except ValueError:
            print_error(f"Nieprawidłowy PID: {args[1]}")
        except ProcessLookupError:
            print_error(f"Brak procesu o PID {args[1]}.")
        except PermissionError:
            print_error(f"Brak uprawnień do zabicia PID {args[1]}.")
        except Exception as e:
            print_error(str(e))
        return

    limit   = 20
    sort_by = "cpu"
    filt    = ""

    i = 0
    while i < len(args):
        if args[i] == "-n" and i + 1 < len(args):
            try:
                limit = int(args[i + 1])
            except ValueError:
                pass
            i += 2
            continue
        if args[i] == "-s" and i + 1 < len(args):
            sort_by = args[i + 1] if args[i + 1] in ("cpu", "mem") else "cpu"
            i += 2
            continue
        if args[i] == "-f" and i + 1 < len(args):
            filt = args[i + 1]
            i += 2
            continue
        i += 1

    _procmon_run(limit=limit, sort_by=sort_by, filt=filt)

