@command("logview", "Wyswietl lokalny log shella",
         aliases=["log"], flags=["-n", "-c", "-e"])
def cmd_logview(args):
    """
    logview           - ostatnie 20 wpisow logu
    logview -n <N>    - ostatnie N wpisow
    logview -e        - tylko bledy (ERROR)
    logview -c        - wyczysc plik logu
    logview --path    - pokaz sciezke do pliku logu
    """
    if "--path" in args:
        print(str(LOG_FILE))
        return

    if "-c" in args:
        try:
            LOG_FILE.write_text("", encoding="utf-8")
            print_info(f"Wyczyszczono log: {LOG_FILE}")
        except Exception as e:
            print_error(f"Blad czyszczenia logu: {e}")
        return

    if not LOG_FILE.exists():
        print_info(f"Brak pliku logu: {LOG_FILE}")
        return

    errors_only = "-e" in args
    limit = 20
    for i, a in enumerate(args):
        if a == "-n" and i + 1 < len(args):
            try: limit = int(args[i + 1])
            except ValueError: pass

    try:
        lines = LOG_FILE.read_text(encoding="utf-8", errors="replace").splitlines()
    except Exception as e:
        print_error(str(e)); return

    if errors_only:
        lines = [l for l in lines if "[ERROR]" in l]

    shown = lines[-limit:]
    w = min(terminal_width() - 2, 90)
    filter_label = "  [tylko ERROR]" if errors_only else ""
    print()
    print(box_top(f"Log TerminalXa{filter_label}  [{len(shown)}/{len(lines)}]", width=w, color=C.DIM))
    print(box_row(f"{C.DIM}{LOG_FILE}{C.RESET}", width=w, color=C.DIM))
    print(box_sep(width=w, color=C.DIM))
    for l in shown:
        if "[ERROR]" in l:
            color, lcolor = C.DIM, C.ERROR
        elif "[CMD]" in l:
            color, lcolor = C.DIM, C.DIM
        else:
            color, lcolor = C.DIM, C.INFO
        print(box_row(f"{lcolor}{l}{C.RESET}", width=w, color=color))
    print(box_bottom(width=w, color=C.DIM))
    print()

