def _show_gui_splash() -> bool:
    """
    Próbuje wyświetlić graficzny splash screen (okno tkinter) z ikoną .ico.
    Zwraca True jeśli się powiodło, False jeśli tkinter niedostępny lub brak DISPLAY.
    Okno jest małe (~420×260 px), wycentrowane, bez ramki, z animowanym paskiem postępu.
    """
    import os as _os

    # Sprawdź czy jest środowisko graficzne
    if sys.platform.startswith("linux") and not _os.environ.get("DISPLAY") and not _os.environ.get("WAYLAND_DISPLAY"):
        return False

    try:
        import tkinter as _tk
        import tkinter.ttk as _ttk
    except ImportError:
        return False

    # ── Stałe wizualne ────────────────────────────────────────────────────
    WIN_W, WIN_H   = 440, 270
    BG             = "#0a0f1e"        # bardzo ciemny granat
    ACCENT         = "#00d4ff"        # neon cyan
    ACCENT2        = "#0055cc"        # głęboki niebieski
    TEXT_MAIN      = "#e8f4ff"        # prawie biały
    TEXT_DIM       = "#5a7a9a"        # przyciemniony szary-niebieski
    FONT_TITLE     = ("Segoe UI", 18, "bold")
    FONT_SUB       = ("Segoe UI", 9)
    FONT_STATUS    = ("Consolas", 8)
    FONT_VERSION   = ("Segoe UI", 10, "bold")

    # ── Lokalizacja ikony ─────────────────────────────────────────────────
    # Szukamy .ico obok pliku wykonywalnego, potem w CWD, potem skrypt dir
    _ico_candidates = []
    try:
        _ico_candidates.append(_os.path.join(_os.path.dirname(_os.path.abspath(__file__)), "Icon_for_a_program_n-removebg-preview.ico"))
    except Exception:  # ignorowane celowo
        pass
    _ico_candidates += [
        _os.path.join(_os.getcwd(), "Icon_for_a_program_n-removebg-preview.ico"),
        _os.path.join(_os.getcwd(), "icon.ico"),
        _os.path.join(_os.path.expanduser("~"), ".config", "terminalx", "icon.ico"),
    ]

    try:
        root = _tk.Tk()
        root.withdraw()   # ukryj główne okno — splash będzie Toplevel

        splash = _tk.Toplevel(root)
        splash.overrideredirect(True)          # brak dekoracji systemu
        splash.configure(bg=BG)
        splash.resizable(False, False)
        splash.attributes("-topmost", True)    # zawsze na wierzchu

        # Wyśrodkuj na ekranie
        sw = root.winfo_screenwidth()
        sh = root.winfo_screenheight()
        x  = (sw - WIN_W) // 2
        y  = (sh - WIN_H) // 2
        splash.geometry(f"{WIN_W}x{WIN_H}+{x}+{y}")

        # ── Cienka ramka akcentowa ────────────────────────────────────────
        _outer = _tk.Frame(splash, bg=ACCENT2, padx=1, pady=1)
        _outer.pack(fill="both", expand=True)
        _inner = _tk.Frame(_outer, bg=BG, padx=0, pady=0)
        _inner.pack(fill="both", expand=True)

        # ── Ikona programu ────────────────────────────────────────────────
        _icon_img = None
        for _ico_path in _ico_candidates:
            if _os.path.isfile(_ico_path):
                try:
                    # Ustaw ikonę okna (pasek zadań / alt-tab)
                    splash.iconbitmap(_ico_path)
                except Exception:  # ignorowane celowo
                    pass
                try:
                    # Załaduj ikonę jako obraz do wyświetlenia w splash
                    from PIL import Image as _PILImage, ImageTk as _PILImageTk
                    _pil = _PILImage.open(_ico_path).convert("RGBA")
                    _pil = _pil.resize((80, 80), _PILImage.LANCZOS)
                    # Ciemne tło pod ikoną z przezroczystością
                    _bg_img = _PILImage.new("RGBA", (80, 80), (10, 15, 30, 255))
                    _bg_img.paste(_pil, (0, 0), _pil)
                    _icon_img = _PILImageTk.PhotoImage(_bg_img)
                except Exception:  # ignorowane celowo
                    pass
                break

        # ── Górna sekcja: ikona + tytuł ──────────────────────────────────
        _top = _tk.Frame(_inner, bg=BG)
        _top.pack(fill="x", padx=18, pady=(18, 6))

        if _icon_img:
            _lbl_ico = _tk.Label(_top, image=_icon_img, bg=BG, bd=0)
            _lbl_ico.image = _icon_img   # zapobiegaj GC
            _lbl_ico.pack(side="left", padx=(0, 16))

        _title_frame = _tk.Frame(_top, bg=BG)
        _title_frame.pack(side="left", fill="both", expand=True)

        _lbl_name = _tk.Label(
            _title_frame,
            text=SHELL_NAME,
            font=FONT_TITLE,
            fg=ACCENT,
            bg=BG,
            anchor="w",
        )
        _lbl_name.pack(anchor="w")

        _lbl_ver = _tk.Label(
            _title_frame,
            text=f"v{SHELL_VERSION}  ·  polsoft.ITS™",
            font=FONT_VERSION,
            fg=TEXT_DIM,
            bg=BG,
            anchor="w",
        )
        _lbl_ver.pack(anchor="w")

        _lbl_tag = _tk.Label(
            _title_frame,
            text=SHELL_TAGLINE,
            font=FONT_SUB,
            fg=TEXT_DIM,
            bg=BG,
            anchor="w",
        )
        _lbl_tag.pack(anchor="w", pady=(2, 0))

        # ── Cienka linia separatora ───────────────────────────────────────
        _sep = _tk.Frame(_inner, bg=ACCENT2, height=1)
        _sep.pack(fill="x", padx=18, pady=6)

        # ── Informacje: autor / platforma ─────────────────────────────────
        _info_frame = _tk.Frame(_inner, bg=BG)
        _info_frame.pack(fill="x", padx=22, pady=(0, 4))

        for _label, _val in [
            ("Autor",    SHELL_AUTHOR),
            ("Licencja", SHELL_LICENSE),
            ("Python",   sys.version.split()[0]),
        ]:
            _row = _tk.Frame(_info_frame, bg=BG)
            _row.pack(anchor="w")
            _tk.Label(_row, text=f"{_label}:", font=FONT_STATUS, fg=TEXT_DIM, bg=BG, width=8, anchor="w").pack(side="left")
            _tk.Label(_row, text=_val,          font=FONT_STATUS, fg=TEXT_MAIN, bg=BG, anchor="w").pack(side="left")

        # ── Pasek postępu ─────────────────────────────────────────────────
        _pb_frame = _tk.Frame(_inner, bg=BG)
        _pb_frame.pack(fill="x", padx=18, pady=(8, 4))

        _status_var = _tk.StringVar(value="Inicjalizacja...")
        _lbl_status = _tk.Label(
            _pb_frame,
            textvariable=_status_var,
            font=FONT_STATUS,
            fg=ACCENT,
            bg=BG,
            anchor="w",
        )
        _lbl_status.pack(anchor="w", pady=(0, 4))

        _style = _ttk.Style(splash)
        _style.theme_use("default")
        _style.configure(
            "Splash.Horizontal.TProgressbar",
            troughcolor=ACCENT2,
            background=ACCENT,
            bordercolor=BG,
            lightcolor=ACCENT,
            darkcolor=ACCENT2,
            thickness=6,
        )

        _pb = _ttk.Progressbar(
            _pb_frame,
            orient="horizontal",
            length=WIN_W - 36,
            mode="determinate",
            maximum=100,
            style="Splash.Horizontal.TProgressbar",
        )
        _pb.pack(fill="x")

        # ── Stopka ────────────────────────────────────────────────────────
        _footer = _tk.Label(
            _inner,
            text=SHELL_HOMEPAGE,
            font=FONT_STATUS,
            fg=TEXT_DIM,
            bg=BG,
        )
        _footer.pack(pady=(4, 10))

        # ── Animacja paska postępu ────────────────────────────────────────
        _loading_steps = [
            ("Wczytywanie konfiguracji...",   18),
            ("Ładowanie historii...",          36),
            ("Rejestrowanie aliasów...",       52),
            ("Ładowanie pluginów...",          68),
            ("Konfigurowanie środowiska...",   84),
            ("Gotowy!",                       100),
        ]

        import time as _t

        def _animate(step_idx: int = 0) -> None:
            if step_idx >= len(_loading_steps):
                splash.destroy()
                root.destroy()
                return
            _label, _pct = _loading_steps[step_idx]
            _status_var.set(_label)
            _pb["value"] = _pct
            splash.update_idletasks()
            delay_ms = 60 if step_idx < len(_loading_steps) - 1 else 180
            splash.after(delay_ms, _animate, step_idx + 1)

        splash.after(80, _animate, 0)
        splash.update()

        # Czekaj aż animacja się skończy (splash.destroy() niszczy okno)
        root.wait_window(splash)

    except Exception:
        try:
            root.destroy()
        except Exception:  # ignorowane celowo
            pass
        return False

    return True


def show_splash_screen():
    """
    Wyświetla ekran powitalny przy starcie TerminalX.
    Jeśli dostępny tkinter + środowisko graficzne → małe okno GUI z ikoną .ico.
    W przeciwnym razie → animowany splash w terminalu (ANSI).
    """
    import time as _t

    # ── Próba splash GUI ───────────────────────────────────────────────────
    if _show_gui_splash():
        return   # GUI splash się powiodło — nie wyświetlamy terminalowego

    # ── Fallback: splash terminalowy (ANSI) ───────────────────────────────
    w = terminal_width()
    clear_screen()

    grad = [
        "\033[38;5;17m", "\033[38;5;18m", "\033[38;5;19m", "\033[38;5;20m",
        "\033[38;5;27m", "\033[38;5;33m", "\033[38;5;39m", "\033[38;5;45m",
        "\033[38;5;51m", "\033[38;5;87m",
    ]

    art_lines = [l for l in BANNER_ART.splitlines() if l.strip()]
    print("\n")
    for i, line in enumerate(art_lines):
        col = grad[min(i, len(grad) - 1)]
        print(f"{col}\033[1m{line.center(w)}\033[0m")
        _t.sleep(0.025)
    print()

    info_lines = [
        f"\033[1;36m  {SHELL_NAME}  \033[0m\033[38;5;87mv{SHELL_VERSION}\033[0m",
        f"\033[2m  {SHELL_TAGLINE}\033[0m",
        f"",
        f"\033[38;5;75m  Autor:    \033[0m{SHELL_AUTHOR}",
        f"\033[38;5;75m  Licencja: \033[0m{SHELL_LICENSE}",
        f"\033[38;5;75m  Strona:   \033[0m\033[2m{SHELL_HOMEPAGE}\033[0m",
        f"",
        f"\033[38;5;75m  Platform: \033[0m\033[2m{sys.platform}  Python {sys.version.split()[0]}\033[0m",
    ]
    icon_lines = [l for l in PROGRAM_ICON_ART.splitlines() if l]
    max_rows = max(len(icon_lines), len(info_lines))
    icon_w = max((len(l) for l in icon_lines), default=0) + 2
    for row in range(max_rows):
        icon_part = icon_lines[row] if row < len(icon_lines) else " " * icon_w
        info_part = info_lines[row] if row < len(info_lines) else ""
        left_pad = max(0, (w - icon_w - 50) // 2)
        print(f"{' ' * left_pad}\033[38;5;75m{icon_part:<{icon_w}}\033[0m  {info_part}")
    print()

    bar_width = min(50, w - 20)
    bar_left  = max(0, (w - bar_width - 40) // 2)
    loading_steps = [
        ("Inicjalizacja konfiguracji",  0.04),
        ("Ładowanie historii komend",   0.03),
        ("Rejestrowanie aliasów",       0.03),
        ("Ładowanie pluginów",          0.05),
        ("Konfigurowanie środowiska",   0.03),
        ("Gotowy",                      0.02),
    ]
    print(f"{' ' * bar_left}\033[2mŁadowanie systemu\033[0m")
    total = len(loading_steps)
    for idx, (name, delay) in enumerate(loading_steps):
        filled = int((idx + 1) / total * bar_width)
        bar = ""
        for b in range(filled):
            t = b / max(1, bar_width - 1)
            bar += ("\033[38;5;27m" if t < 0.5 else "\033[38;5;39m" if t < 0.75 else "\033[38;5;51m") + "█"
        bar += "\033[38;5;240m" + "░" * (bar_width - filled) + "\033[0m"
        print(f"\r{' ' * bar_left}\033[38;5;240m[\033[0m{bar}\033[38;5;240m]\033[0m  \033[2m{name:<35}\033[0m", end="", flush=True)
        _t.sleep(delay)
    print("\n")

    welcome = f"  Witaj w {SHELL_NAME}!  Wpisz 'help' aby zobaczyć dostępne komendy."
    print(f"\033[1;36m{welcome.center(w)}\033[0m")
    print(f"\033[38;5;27m{'═' * w}\033[0m\n")
    _t.sleep(0.3)


def print_banner():
    """Wyświetla kolorowy banner z tożsamością shella przy starcie."""
    width = terminal_width()
    c     = _bc()

    # Linia ozdobna przed banerem
    accent_line = c["H"] * width
    print(f"{C.DIM}{accent_line}{C.RESET}")

    # ASCII art — z gradientem kolorów (ciemny → jasny przez zmianę jasności)
    art_lines = [l for l in BANNER_ART.splitlines() if l.strip()]
    grad_colors = [
        "\033[38;5;27m",   # ciemny niebieski
        "\033[38;5;33m",
        "\033[38;5;39m",
        "\033[38;5;45m",
        "\033[38;5;51m",   # jasny cyan
    ]
    for i, line in enumerate(art_lines):
        col = grad_colors[min(i, len(grad_colors) - 1)]
        print(f"{col}{C.BOLD}{line.center(width)}{C.RESET}")

    # Podtytuł z wersją
    subtitle = _banner_subtitle()
    print(f"\n{C.BOLD}{C.PROMPT}{subtitle.center(width)}{C.RESET}")

    # Meta — autor, licencja, homepage
    meta = _banner_meta()
    print(f"{C.DIM}{meta.center(width)}{C.RESET}")

    # Linia ozdobna pod banerem
    print(f"{C.DIM}{accent_line}{C.RESET}\n")

def load_rc():
    """Wczytaj i wykonaj profil startowy ~/.terminalxrc jesli istnieje."""
    if not RC_FILE.exists():
        return
    try:
        with RC_FILE.open("r", encoding="utf-8") as f:
            lines = f.readlines()
        for lineno, raw in enumerate(lines, 1):
            line = raw.strip()
            if not line or line.startswith("#"):
                continue
            try:
                execute_line(line)
            except SystemExit:
                pass
            except Exception as e:
                print_error(f"~/.terminalxrc:{lineno}: {e}")
    except Exception as e:
        print_error(f"Nie udalo sie wczytac ~/.terminalxrc: {e}")

def main():
    global _SHELL_VERBOSE, _SHELL_DEBUG

    # ── Splash screen — pokazuj przed wszystkim innym ────────────────────────
    if "--no-splash" not in sys.argv:
        try:
            show_splash_screen()
        except Exception as _e:
            write_crashlog(_e, context="show_splash_screen przy starcie")

    # ── Wczytaj konfiguracje jako pierwsze — osobny blok try/catch ──────────
    try:
        load_config()
    except Exception as _e:
        print_warn("Nie udalo sie wczytac konfiguracji — uzywam domyslnej.")
        write_crashlog(_e, context="load_config przy starcie")
        recovery_record_crash(_e, context="load_config przy starcie")

    # ── Historia ─────────────────────────────────────────────────────────────
    try:
        load_history()
    except Exception as _e:
        print_warn("Nie udalo sie wczytac historii komend.")
        write_crashlog(_e, context="load_history przy starcie")

    # ── Aliasy ───────────────────────────────────────────────────────────────
    try:
        load_aliases()
    except Exception as _e:
        print_warn("Nie udalo sie wczytac aliasow.")
        write_crashlog(_e, context="load_aliases przy starcie")

    # ── Pluginy ──────────────────────────────────────────────────────────────
    try:
        load_plugins()
    except Exception as _e:
        print_warn("Nie udalo sie zaladowac pluginow — shell dziala bez nich.")
        write_crashlog(_e, context="load_plugins przy starcie")

    # ── Moduły .pysh — auto-ładowanie ────────────────────────────────────────
    try:
        _pysh_autoload()
    except Exception as _e:
        write_crashlog(_e, context="_pysh_autoload przy starcie")

    # ── Verbose / Debug — inicjalizacja z konfiguracji ───────────────────────
    try:
        _init_verbose_debug()
    except Exception as _e:
        write_crashlog(_e, context="_init_verbose_debug przy starcie")

    # ── Profil użytkownika ───────────────────────────────────────────────────
    try:
        _auto_apply_saved_profile()
    except Exception as _e:
        write_crashlog(_e, context="_auto_apply_saved_profile przy starcie")

    # ── Autouzupelnianie TAB ─────────────────────────────────────────────────
    try:
        enable_tab_completion()
    except Exception as _e:
        print_warn("Autouzupelnianie TAB niedostepne.")
        write_crashlog(_e, context="enable_tab_completion przy starcie")

    # Temat jest ladowany przez config_apply() wywolywane po load_rc()

    # ── Banner i RC ──────────────────────────────────────────────────────────
    try:
        print_banner()
    except Exception as _e:
        print_warn("Banner niedostepny.")
        write_crashlog(_e, context="print_banner przy starcie")

    try:
        load_rc()
    except Exception as _e:
        print_warn(f"Nie udalo sie wczytac pliku RC ({RC_FILE}).")
        write_crashlog(_e, context="load_rc przy starcie")

    # ── Konfiguracja ─────────────────────────────────────────────────────────
    try:
        config_apply()
    except Exception as _e:
        print_warn("Blad stosowania konfiguracji — uzywam domyslnej.")
        write_crashlog(_e, context="config_apply przy starcie")

    # Uruchom komendy startowe z konfiguracji
    for _sc in cfg("startup_commands", []):
        if isinstance(_sc, str) and _sc.strip():
            try:
                execute_line(_sc)
            except Exception as _e:
                print_warn(f"Blad komendy startowej: {_sc!r}")
                write_crashlog(_e, context="startup_command", cmd=_sc)

    # Zaladuj motyw z konfiguracji (moze byc nadpisany przez rc)
    # Wczytaj własne motywy (zanim zaaplikujemy zapisany)
    try:
        _load_custom_themes()
    except Exception as _e:
        write_crashlog(_e, context="_load_custom_themes przy starcie")

    # ── Env-var overrides (TERMINALX_*) — stosowane PO konfiguracji ─────────
    # TERMINALX_THEME → nadpisz motyw
    if _BOOT_THEME:
        try:
            _apply_theme(_BOOT_THEME)
        except Exception:  # ignorowane celowo
            pass
    else:
        saved_theme = cfg("theme", "dark")
        _apply_theme(saved_theme)

    # TERMINALX_VERBOSE / TERMINALX_DEBUG → nadpisz tryb verbose
    if _BOOT_VERBOSE or _BOOT_DEBUG:
        try:
            if _BOOT_VERBOSE: _SHELL_VERBOSE = True
            if _BOOT_DEBUG:   _SHELL_DEBUG = True; _SHELL_VERBOSE = True
        except Exception:  # ignorowane celowo
            pass

    # TERMINALX_OFFLINE → wymuś offline przed network_init
    if _BOOT_FORCE_OFFLINE:
        _STATE.online_mode = False

    # TERMINALX_PROFILE → nadpisz profil (po _auto_apply_saved_profile)
    if _BOOT_PROFILE:
        try:
            _prof_data = _profile_load_data(_BOOT_PROFILE)
            if _prof_data:
                _profile_apply(_prof_data, silent=True)
                _STATE.current_profile = _BOOT_PROFILE
        except Exception:  # ignorowane celowo
            pass

    if _PORTABLE_MODE:
        print_info(f"Tryb PORTABLE — dane: {_BASE}")

    _uac = _check_uac()
    if _uac["elevated"]:
        print_info(f"Uruchomiono z podwyszonymi uprawnieniami ({_uac['method']})")
        log_security(f"Start z podwyszonymi uprawnieniami: {_uac['method']}")

    _sb = _detect_sandbox()
    if _sb:
        print_info(f"Wykryto srodowisko izolowane: {_sb}")
        log_security(f"Sandbox/izolacja: {_sb}")

    log_info(f"Start TerminalXa v{SHELL_VERSION}  base={_BASE}  platform={sys.platform}  "
             f"theme={_CURRENT_THEME}  portable={_PORTABLE_MODE}")

    # Wykryj tryb sieci (offline/online) — nie blokuje startu
    network_init()
    net_status = (f"{C.PATH}ONLINE{C.RESET}" if is_online()
                  else f"{C.DIM}OFFLINE{C.RESET}")

    # Powitanie — custom lub domyslne
    greeting = cfg("custom_greeting", "")
    if greeting:
        print_info(greeting)
    else:
        # Liczba unikalnych komend (bez aliasów)
        _unique_cmds = len({id(v) for v in BUILTINS.values()})
        print_info(f"{SHELL_NAME} v{SHELL_VERSION} — wpisz 'help', 'about' lub 'tui' aby zobaczyc menu.  "
                   f"{C.DIM}Dostepnych komend: {C.RESET}{C.BOLD}{_unique_cmds}{C.RESET}")
        print_info(f"Motyw: {C.BOLD}{_CURRENT_THEME.upper()}{C.RESET}  "
                   f"Siec: {net_status}  "
                   f"{C.DIM}(theme dark|light  |  mode online/offline  |  config){C.RESET}")

    while True:
        try:
            # ── Tryb awaryjny: uproszczony prompt ────────────────────────
            if recovery_is_active():
                prompt = _recovery_main_prompt()
            else:
                # Pasek statusu nad promptem
                if _STATUS_ENABLED:
                    print(render_status_bar())

                # Styl promptu wg prompt_style — czytaj raz z cache
                if "prompt_style" not in _CFG_PROMPT_CACHE:
                    _CFG_PROMPT_CACHE["prompt_style"]         = cfg("prompt_style", "full")
                    _CFG_PROMPT_CACHE["custom_prompt_prefix"] = cfg("custom_prompt_prefix", "")
                    _CFG_PROMPT_CACHE["auto_cd"]              = cfg("auto_cd", False)
                style      = _CFG_PROMPT_CACHE["prompt_style"]
                prefix_txt = _CFG_PROMPT_CACHE["custom_prompt_prefix"]
                if style == "minimal":
                    symbol = f"{C.ERROR}#{C.RESET}" if IS_ROOT else f"{C.PROMPT}${C.RESET}"
                    prompt = f"{prefix_txt}{symbol} "
                elif style == "short":
                    cwd_short = Path.cwd().name or "/"
                    symbol    = f"{C.ERROR}#{C.RESET}" if IS_ROOT else f"{C.PROMPT}$"
                    prompt    = (f"{prefix_txt}{C.PROMPT}~/{cwd_short}{C.RESET} {symbol}{C.RESET} ")
                else:  # full (domyslny)
                    prefix = "TerminalX(root)" if IS_ROOT else "TerminalX"
                    symbol = f"{C.ERROR}#{C.RESET}" if IS_ROOT else f"{C.PROMPT}${C.RESET}"
                    prompt = (f"{prefix_txt}{C.BOLD}{C.PROMPT}{prefix}{C.RESET}"
                              f"{C.DIM}:{C.RESET}{C.PATH}{Path.cwd()}{C.RESET}"
                              f" {symbol} ")
            line = input(prompt).strip()
        except (EOFError, KeyboardInterrupt):
            print()
            break

        if not line:
            continue

        # auto_cd: wpisana sciezka bez komendy = cd do niej
        if _CFG_PROMPT_CACHE.get("auto_cd", False) and not line.startswith(_BUILTINS_PREFIX_TUPLE):
            _acd = Path(line).expanduser()
            if _acd.is_dir():
                try:
                    os.chdir(_acd)
                    continue
                except Exception:
                    pass   # nie jest to katalog dostepny — traktuj jako komende

        # Rozwinięcia historii: !!, !n, !-n, !prefix, !?substr
        if line.startswith("!") and not line.startswith("!#"):
            try:
                expanded = _history_expand(line)
                if expanded != line:
                    print(f"{C.DIM}{expanded}{C.RESET}")
                line = expanded
            except ValueError as e:
                print_error(str(e))
                continue

        _history_add(line)

        # Loguj komendy root
        if IS_ROOT:
            ts = datetime.datetime.now().strftime("%Y-%m-%d %H:%M:%S")
            ROOT_LOG.append((ts, line))

        # Loguj do pliku (wszystkie komendy)
        log_cmd(line)

        # Tryb debug (set -x) — oryginalna obsługa
        if SHELL_VARS.get("_DEBUG"):
            print(f"{C.DIM}+ {line}{C.RESET}", file=sys.stderr)

        # Tryb verbose (nowy) — wypisz przed wykonaniem, jeśli nie już przez set -x
        if _SHELL_VERBOSE and not SHELL_VARS.get("_DEBUG"):
            _verbose_print(line)

        # Sprawdz czy to VAR=wartosc (przypisanie bez komendy)
        # Np: MY_VAR="hello world"
        _assign_m = _RE_VAR_ASSIGN.match(line.strip())
        if _assign_m and " " not in _assign_m.group(1):
            _set_var(_assign_m.group(1), _var_expand(_assign_m.group(2)))
            continue

        # Sprawdz czy to "exit" (specjalny przypadek — przerywa petle)
        _stripped = line.strip()
        if _stripped == "exit" or _stripped.startswith("exit "):
            _parts = _stripped.split(None, 1)
            if IS_ROOT:
                _STATE.is_root = False
                print(f"{C.INFO}[INFO]{C.RESET} Powrot z trybu root.")
                continue
            # Kod wyjscia
            if len(_parts) > 1:
                try:
                    sys.exit(int(_parts[1]))
                except ValueError:
                    pass
            break

        # ── Blokowanie komend w trybie awaryjnym ────────────────────────
        if recovery_is_active():
            # Wyciągnij pierwszą nazwę komendy
            try:
                _first_tok = shlex.split(line)[0] if line else ""
            except Exception:
                _first_tok = line.split()[0] if line.split() else ""
            if not recovery_check_command(_first_tok):
                _recovery_block_msg(_first_tok)
                continue

        # Przekaz do pelnego parsera bash-like
        try:
            execute_line(line)
        except SystemExit as _:
            if IS_ROOT:
                _STATE.is_root = False
                print(f"{C.INFO}[INFO]{C.RESET} Powrot z trybu root.")
            else:
                break
        except KeyboardInterrupt:
            print()
        except Exception as _exc:
            # Nieoczekiwany blad w trakcie wykonania komendy — crashlog + czytelny komunikat
            _crashlog_user_msg(_exc, context="execute_line", cmd=line)
            # Zarejestruj w recovery — może wyzwolić tryb awaryjny
            recovery_record_crash(_exc, context=f"cmd: {line[:60]}")

    # ── Sprzatanie przy wyjsciu ──────────────────────────────────────────────
    try:
        save_history()
    except Exception as _e:
        write_crashlog(_e, context="save_history przy wyjsciu")

    try:
        save_aliases()
    except Exception as _e:
        write_crashlog(_e, context="save_aliases przy wyjsciu")

    log_info("Zamkniecie TerminalXa")
    _log_flush()   # wypisz pozostałe wpisy przed wyjściem
    print_info("Zamykanie TerminalXa.")

#   NANO-LITE — wbudowany edytor tekstu (curses)

class NanoEditor:
    """
    Wbudowany edytor tekstu inspirowany nano.
    Skroty klawiszowe:
      Ctrl+S  - zapisz          Ctrl+X  - wyjdz (pyta o zapis)
      Ctrl+F  - szukaj          Ctrl+N  - nastepne dopasowanie
      Ctrl+K  - wytnij linie    Ctrl+U  - wklej linie
      Ctrl+G  - pomoc           Ctrl+L  - przerysuj ekran
      Strzalki, Home, End, PgUp, PgDn, Delete, Backspace
    """

    HELP_TEXT = [
        "=== NANO-LITE  pomoc ===",
        "",
        "Ctrl+S   Zapisz plik (pyta o nazwe jesli nowy)",
        "Ctrl+X   Wyjdz (pyta o zapis jesli niezapisany)",
        "Ctrl+F   Szukaj tekstu (do przodu)",
        "Ctrl+N   Nastepne dopasowanie wyszukiwania",
        "Ctrl+R   Znajdz i ZAMIEN tekst w pliku",
        "Ctrl+K   Wytnij biezaca linie (do schowka)",
        "Ctrl+U   Wklej linie ze schowka",
        "Ctrl+Z   Cofnij ostatnia zmiane (undo, do 50 krokow)",
        "Ctrl+W   Usun slowo przed kursorem",
        "Ctrl+D   Usun cala linie (bez schowka)",
        "Ctrl+A   Poczatek linii (jak Home)",
        "Ctrl+E   Koniec linii (jak End)",
        "Ctrl+G   Ta pomoc (nacisnij dowolny klawisz by zamknac)",
        "Ctrl+L   Przerysuj ekran",
        "",
        "Strzalki    Poruszanie sie",
        "Home / End  Poczatek / koniec linii",
        "PgUp / PgDn Przewijanie strony",
        "Delete      Usun znak pod kursorem",
        "Backspace   Usun znak przed kursorem",
        "Enter       Nowa linia (z autoindent)",
        "Tab         Wstaw 4 spacje (smart indent)",
    ]

    def __init__(self, filepath: str):
        self.path      = Path(filepath).expanduser()
        self.lines     = []
        self.cx        = 0          # kolumna kursora w linii
        self.cy        = 0          # wiersz kursora (w buforze)
        self.scroll_y  = 0          # pierwszy widoczny wiersz
        self.scroll_x  = 0          # przesuniecie poziome
        self.modified  = False
        self.clipboard = []         # wyciety tekst (lista linii)
        self.search_term  = ""
        self.search_idx   = 0       # indeks ostatniego dopasowania (cy)
        self.message   = ""         # pasek statusu — tymczasowa wiadomosc
        self.stdscr    = None
        self._undo_stack: list = [] # stos undo: (lines_snapshot, cx, cy)
        self._undo_max  = 50        # max glebokosci undo

    # -------- I/O --------

    def load(self):
        if self.path.exists():
            try:
                text = self.path.read_text(encoding="utf-8", errors="replace")
                self.lines = text.splitlines()
            except Exception as e:
                self.lines = [f"[ERROR reading file: {e}]"]
        if not self.lines:
            self.lines = [""]

    def save(self, ask_name: bool = False):
        # Jesli plik nie ma nazwy — zapytaj
        if ask_name or self.path.name in ("noname.txt", "") or not str(self.path.parent).strip("/"):
            if self.stdscr:
                new_name = self._ask("Zapisz jako: ")
                if new_name.strip():
                    self.path = Path(new_name.strip()).expanduser()
        try:
            self.path.parent.mkdir(parents=True, exist_ok=True)
            self.path.write_text("\n".join(self.lines) + "\n", encoding="utf-8")
            self.modified = False
            self.message  = f"Zapisano: {self.path}"
            return True
        except Exception as e:
            self.message = f"BLAD ZAPISU: {e}"
            return False

    # -------- Rozmiar terminala --------

    @property
    def rows(self):
        return self.stdscr.getmaxyx()[0]

    @property
    def cols(self):
        return self.stdscr.getmaxyx()[1]

    @property
    def edit_rows(self):
        return self.rows - 3   # 1 naglowek + 1 status + 1 pasek skrotow

    # -------- Rysowanie --------

    def _draw_header(self):
        title = f" NANO-LITE  |  {self.path.name}"
        if self.modified:
            title += "  [*]"
        title = title[:self.cols - 1]
        try:
            self.stdscr.attron(curses.color_pair(1) | curses.A_BOLD)
            self.stdscr.addstr(0, 0, title.ljust(self.cols - 1))
            self.stdscr.attroff(curses.color_pair(1) | curses.A_BOLD)
        except curses.error:
            pass

    def _draw_statusbar(self):
        row = self.rows - 2
        total = len(self.lines)
        info  = f" Ln {self.cy+1}/{total}  Col {self.cx+1}  "
        msg   = self.message[:self.cols - len(info) - 2]
        bar   = (msg + " " * (self.cols - len(info) - len(msg) - 1) + info)
        try:
            self.stdscr.attron(curses.color_pair(2))
            self.stdscr.addstr(row, 0, bar[:self.cols - 1])
            self.stdscr.attroff(curses.color_pair(2))
        except curses.error:
            pass

    def _draw_shortcuts(self):
        row  = self.rows - 1
        keys = "^S Zapisz  ^X Wyjdz  ^F Szukaj  ^K Wytnij  ^U Wklej  ^G Pomoc"
        try:
            self.stdscr.attron(curses.color_pair(3))
            self.stdscr.addstr(row, 0, keys[:self.cols - 1])
            self.stdscr.attroff(curses.color_pair(3))
        except curses.error:
            pass

    def _draw_lines(self):
        ext = self.path.suffix.lower()
        # Wybór pary kolorów na podstawie rozszerzenia pliku
        _code_exts = {'.py', '.js', '.ts', '.c', '.cpp', '.h', '.rs', '.go',
                      '.sh', '.bash', '.zsh', '.json', '.yaml', '.yml',
                      '.toml', '.xml', '.html', '.css', '.md'}
        _use_syntax = ext in _code_exts
        for screen_row in range(self.edit_rows):
            buf_row = screen_row + self.scroll_y
            y = screen_row + 1   # wiersz 0 to naglowek

            # Numer linii (4 cyfry + spacja)
            lineno_str = f"{buf_row+1:4d} " if buf_row < len(self.lines) else "     "
            try:
                self.stdscr.attron(curses.color_pair(4))
                self.stdscr.addstr(y, 0, lineno_str)
                self.stdscr.attroff(curses.color_pair(4))
            except curses.error:
                pass

            if buf_row < len(self.lines):
                line = self.lines[buf_row]
                # Poziome przewijanie
                visible = line[self.scroll_x : self.scroll_x + self.cols - 6]
                # Podswietl dopasowanie wyszukiwania
                if (self.search_term and self.search_term.lower() in line.lower()):
                    self._draw_line_with_highlight(y, 5, visible, self.search_term)
                elif _use_syntax and visible.strip().startswith(('#', '//', '--')):
                    try:
                        self.stdscr.attron(curses.color_pair(4))
                        self.stdscr.addstr(y, 5, visible[:self.cols - 6])
                        self.stdscr.attroff(curses.color_pair(4))
                    except curses.error:
                        pass
                else:
                    try:
                        self.stdscr.addstr(y, 5, visible[:self.cols - 6])
                    except curses.error:
                        pass
            # Czyszczenie reszty wiersza (zawsze, niezaleznie od zawartosci)
            try:
                self.stdscr.move(y, 5 + (len(self.lines[buf_row][self.scroll_x:self.scroll_x+self.cols-6])
                                         if buf_row < len(self.lines) else 0))
                self.stdscr.clrtoeol()
            except (curses.error, IndexError):
                pass

    def _draw_line_with_highlight(self, y, x_start, text, term):
        lo   = text.lower()
        tlo  = term.lower()
        pos  = 0
        col  = x_start
        while pos < len(text) and col < self.cols - 1:
            idx = lo.find(tlo, pos)
            if idx == -1:
                # reszta bez podswietlenia
                try:
                    self.stdscr.addstr(y, col, text[pos:pos + self.cols - col - 1])
                except curses.error:
                    pass
                break
            # przed dopasowaniem
            before = text[pos:idx]
            try:
                self.stdscr.addstr(y, col, before[:self.cols - col - 1])
            except curses.error:
                pass
            col += len(before)
            # dopasowanie
            match_text = text[idx:idx+len(term)]
            try:
                self.stdscr.attron(curses.color_pair(5) | curses.A_BOLD)
                self.stdscr.addstr(y, col, match_text[:self.cols - col - 1])
                self.stdscr.attroff(curses.color_pair(5) | curses.A_BOLD)
            except curses.error:
                pass
            col += len(term)
            pos  = idx + len(term)

    def _refresh(self):
        self.stdscr.erase()
        self._draw_header()
        self._draw_lines()
        self._draw_statusbar()
        self._draw_shortcuts()
        # Pozycja kursora
        screen_row = self.cy - self.scroll_y + 1
        screen_col = self.cx - self.scroll_x + 5
        try:
            self.stdscr.move(
                max(1, min(screen_row, self.edit_rows)),
                max(5, min(screen_col, self.cols - 1))
            )
        except curses.error:
            pass
        self.stdscr.refresh()

    # -------- Scrolling --------

    def _ensure_visible(self):
        # Pionowe
        if self.cy < self.scroll_y:
            self.scroll_y = self.cy
        elif self.cy >= self.scroll_y + self.edit_rows:
            self.scroll_y = self.cy - self.edit_rows + 1
        # Poziome (z marginesem 5)
        if self.cx < self.scroll_x:
            self.scroll_x = max(0, self.cx - 5)
        elif self.cx >= self.scroll_x + (self.cols - 6):
            self.scroll_x = self.cx - (self.cols - 6) + 5

    # -------- Nawigacja --------

    def _clamp_cx(self):
        """Upewnij sie ze cx nie wychodzi poza linie."""
        if self.cy < len(self.lines):
            self.cx = min(self.cx, len(self.lines[self.cy]))
        else:
            self.cx = 0

    def move_up(self):
        if self.cy > 0:
            self.cy -= 1
            self._clamp_cx()

    def move_down(self):
        if self.cy < len(self.lines) - 1:
            self.cy += 1
            self._clamp_cx()

    def move_left(self):
        if self.cx > 0:
            self.cx -= 1
        elif self.cy > 0:
            self.cy -= 1
            self.cx = len(self.lines[self.cy])

    def move_right(self):
        line = self.lines[self.cy]
        if self.cx < len(line):
            self.cx += 1
        elif self.cy < len(self.lines) - 1:
            self.cy += 1
            self.cx = 0

    def move_home(self):
        # Pierwsza niebiala, potem absolutny poczatek
        line = self.lines[self.cy]
        first_nonws = len(line) - len(line.lstrip())
        self.cx = 0 if self.cx == first_nonws else first_nonws

    def move_end(self):
        self.cx = len(self.lines[self.cy])

    def page_up(self):
        self.cy = max(0, self.cy - self.edit_rows)
        self.scroll_y = max(0, self.scroll_y - self.edit_rows)
        self._clamp_cx()

    def page_down(self):
        self.cy = min(len(self.lines) - 1, self.cy + self.edit_rows)
        self._clamp_cx()

    # -------- Edycja --------

    def insert_char(self, ch: str):
        self._push_undo()
        line = self.lines[self.cy]
        self.lines[self.cy] = line[:self.cx] + ch + line[self.cx:]
        self.cx      += 1
        self.modified = True

    def insert_newline(self):
        self._push_undo()
        line = self.lines[self.cy]
        # Autoindent: zachowaj wciec biezacej linii
        indent = len(line) - len(line.lstrip())
        rest   = line[self.cx:]
        self.lines[self.cy] = line[:self.cx]
        self.lines.insert(self.cy + 1, " " * indent + rest)
        self.cy      += 1
        self.cx       = indent
        self.modified = True

    def insert_tab(self):
        spaces = 4 - (self.cx % 4)
        for _ in range(spaces):
            self.insert_char(" ")

    def backspace(self):
        self._push_undo()
        if self.cx > 0:
            line = self.lines[self.cy]
            self.lines[self.cy] = line[:self.cx-1] + line[self.cx:]
            self.cx     -= 1
            self.modified = True
        elif self.cy > 0:
            prev = self.lines[self.cy - 1]
            curr = self.lines.pop(self.cy)
            self.cy -= 1
            self.cx  = len(prev)
            self.lines[self.cy] = prev + curr
            self.modified = True

    def _push_undo(self):
        """Zapisuje aktualny stan do stosu undo."""
        snapshot = (self.lines[:], self.cx, self.cy)
        if self._undo_stack and self._undo_stack[-1][0] == self.lines:
            return
        self._undo_stack.append(snapshot)
        if len(self._undo_stack) > self._undo_max:
            self._undo_stack.pop(0)

    def undo(self):
        """Cofnij ostatnia operacje edycji."""
        if not self._undo_stack:
            self.message = "Brak operacji do cofniecia"
            return
        lines, cx, cy = self._undo_stack.pop()
        self.lines    = lines
        self.cx       = cx
        self.cy       = cy
        self.modified = True
        self.message  = f"Cofnieto (undo, {len(self._undo_stack)} pozostalo)"

    def delete_char(self):
        self._push_undo()
        line = self.lines[self.cy]
        if self.cx < len(line):
            self.lines[self.cy] = line[:self.cx] + line[self.cx+1:]
            self.modified = True
        elif self.cy < len(self.lines) - 1:
            next_line = self.lines.pop(self.cy + 1)
            self.lines[self.cy] = line + next_line
            self.modified = True

    def cut_line(self):
        self._push_undo()
        if len(self.lines) == 1:
            self.clipboard = [self.lines[0]]
            self.lines[0]  = ""
            self.cx = 0
        else:
            self.clipboard = [self.lines.pop(self.cy)]
            if self.cy >= len(self.lines):
                self.cy = len(self.lines) - 1
            self.cx = 0
        self.modified = True
        self.message  = "Wycięto linie do schowka"

    def paste_line(self):
        if not self.clipboard:
            self.message = "Schowek pusty"
            return
        for i, cl in enumerate(self.clipboard):
            self.lines.insert(self.cy + i, cl)
        self.cy      += len(self.clipboard)
        self.modified = True
        self.message  = "Wklejono ze schowka"

    # -------- Szukanie --------

    def _ask(self, prompt: str) -> str:
        """Mini input w dolnym pasku statusu."""
        row = self.rows - 2
        try:
            self.stdscr.attron(curses.color_pair(2))
            self.stdscr.addstr(row, 0, f" {prompt}"[:self.cols-1])
            self.stdscr.clrtoeol()
            self.stdscr.attroff(curses.color_pair(2))
            curses.echo()
            curses.curs_set(1)
            ans_bytes = self.stdscr.getstr(row, len(prompt) + 2, self.cols - len(prompt) - 4)
            return ans_bytes.decode(errors="replace")
        except Exception:
            return ""
        finally:
            curses.noecho()

    def search_forward(self, new_search: bool = True):
        if new_search:
            term = self._ask("Szukaj: ")
            if not term:
                self.message = "Anulowano"
                return
            self.search_term = term
            self.search_idx  = self.cy

        term = self.search_term
        if not term:
            return

        n     = len(self.lines)
        start = (self.search_idx + (0 if new_search else 1)) % n

        for offset in range(n):
            row = (start + offset) % n
            if term.lower() in self.lines[row].lower():
                # Znajdz kolumne
                col = self.lines[row].lower().find(term.lower())
                self.cy          = row
                self.cx          = col
                self.search_idx  = row
                self.message     = f'Znaleziono: "{term}" w linii {row+1}'
                return

        self.message = f'Nie znaleziono: "{term}"'

    # -------- Pomoc --------

    def show_help(self):
        self.stdscr.erase()
        for i, line in enumerate(self.HELP_TEXT):
            if i >= self.rows - 2:
                break
            try:
                self.stdscr.addstr(i + 1, 2, line[:self.cols - 3])
            except curses.error:
                pass
        try:
            self.stdscr.attron(curses.color_pair(2))
            self.stdscr.addstr(self.rows - 1, 0,
                               " Nacisnij dowolny klawisz aby powrocic..."[:self.cols-1])
            self.stdscr.attroff(curses.color_pair(2))
        except curses.error:
            pass
        self.stdscr.refresh()
        self.stdscr.getch()

    # -------- Pytanie o zapis --------

    def _confirm_exit(self) -> bool:
        """Zwraca True jesli mozna wyjsc."""
        if not self.modified:
            return True
        row = self.rows - 2
        msg = " Niezapisane zmiany! Zapisac? [t/n/Anuluj]: "
        try:
            self.stdscr.attron(curses.color_pair(5) | curses.A_BOLD)
            self.stdscr.addstr(row, 0, msg[:self.cols-1])
            self.stdscr.clrtoeol()
            self.stdscr.attroff(curses.color_pair(5) | curses.A_BOLD)
            self.stdscr.refresh()
        except curses.error:
            pass
        while True:
            k = self.stdscr.getch()
            if k in (ord('t'), ord('T'), ord('y'), ord('Y')):
                self.save()
                return True
            if k in (ord('n'), ord('N')):
                return True
            if k in (27, ord('a'), ord('A')):   # ESC lub Anuluj
                self.message = "Anulowano wyjscie"
                return False

    # -------- Kolory curses --------

    @staticmethod
    def _init_colors():
        curses.start_color()
        curses.use_default_colors()
        # 1: naglowek  (bialy na niebieskim)
        curses.init_pair(1, curses.COLOR_WHITE,  curses.COLOR_BLUE)
        # 2: status    (czarny na cyjanowym)
        curses.init_pair(2, curses.COLOR_BLACK,  curses.COLOR_CYAN)
        # 3: skroty    (bialy na ciemnoszarym)
        curses.init_pair(3, curses.COLOR_WHITE,  curses.COLOR_BLACK)
        # 4: numery    (zolty na domyslnym)
        curses.init_pair(4, curses.COLOR_YELLOW, -1)
        # 5: highlight (czarny na zoltym)
        curses.init_pair(5, curses.COLOR_BLACK,  curses.COLOR_YELLOW)

    # -------- Glowna petla --------

    def run(self, stdscr):
        self.stdscr = stdscr
        self._init_colors()
        curses.curs_set(1)
        curses.noecho()
        stdscr.keypad(True)

        while True:
            self._ensure_visible()
            self._refresh()
            self.message = ""

            try:
                key = stdscr.getch()
            except KeyboardInterrupt:
                if self._confirm_exit():
                    break
                continue

            # --- Ctrl shortcuts ---
            if key == curses.ascii.ctrl(ord('x')):
                if self._confirm_exit():
                    break

            elif key == curses.ascii.ctrl(ord('s')):
                self.save()

            elif key == curses.ascii.ctrl(ord('f')):
                self.search_forward(new_search=True)

            elif key == curses.ascii.ctrl(ord('n')):
                if self.search_term:
                    self.search_forward(new_search=False)
                else:
                    self.message = "Brak aktywnego wyszukiwania (Ctrl+F)"

            elif key == curses.ascii.ctrl(ord('k')):
                self.cut_line()

            elif key == curses.ascii.ctrl(ord('u')):
                self.paste_line()

            elif key == curses.ascii.ctrl(ord('g')):
                self.show_help()

            elif key == curses.ascii.ctrl(ord('l')):
                stdscr.clear()

            elif key == curses.ascii.ctrl(ord('z')):   # Ctrl+Z — undo
                self.undo()

            elif key == curses.ascii.ctrl(ord('w')):   # Ctrl+W — usun slowo wstecz
                self._push_undo()
                line = self.lines[self.cy]
                # Cofnij przez biale znaki, potem przez slowo
                i = self.cx
                while i > 0 and line[i-1] == ' ':
                    i -= 1
                while i > 0 and line[i-1] != ' ':
                    i -= 1
                self.lines[self.cy] = line[:i] + line[self.cx:]
                self.cx = i
                self.modified = True

            elif key == curses.ascii.ctrl(ord('d')):   # Ctrl+D — usun linie (bez schowka)
                self._push_undo()
                if len(self.lines) > 1:
                    self.lines.pop(self.cy)
                    if self.cy >= len(self.lines):
                        self.cy = len(self.lines) - 1
                else:
                    self.lines[0] = ""
                self.cx = 0
                self.modified = True
                self.message = "Usunieto linie"

            elif key == curses.ascii.ctrl(ord('a')):   # Ctrl+A — poczatek linii
                self.move_home()

            elif key == curses.ascii.ctrl(ord('e')):   # Ctrl+E — koniec linii
                self.move_end()

            elif key == curses.ascii.ctrl(ord('r')):   # Ctrl+R — znajdz i zamien
                self._find_replace()

            # --- Nawigacja ---
            elif key == curses.KEY_UP:
                self.move_up()
            elif key == curses.KEY_DOWN:
                self.move_down()
            elif key == curses.KEY_LEFT:
                self.move_left()
            elif key == curses.KEY_RIGHT:
                self.move_right()
            elif key == curses.KEY_HOME:
                self.move_home()
            elif key == curses.KEY_END:
                self.move_end()
            elif key == curses.KEY_PPAGE:
                self.page_up()
            elif key == curses.KEY_NPAGE:
                self.page_down()

            # --- Edycja ---
            elif key in (curses.KEY_BACKSPACE, 127, 8):
                self.backspace()
            elif key == curses.KEY_DC:
                self.delete_char()
            elif key in (curses.KEY_ENTER, 10, 13):
                self.insert_newline()
            elif key == 9:   # Tab
                self.insert_tab()
            elif 32 <= key <= 126:
                self.insert_char(chr(key))
            # znaki UTF-8 (> 127)
            elif key > 127:
                try:
                    self.insert_char(chr(key))
                except (ValueError, OverflowError):
                    pass

    # -------- Znajdz i zamien --------

    def _find_replace(self):
        """Ctrl+R — interaktywne znajdz i zamien w calym pliku."""
        term    = self._ask("Znajdz: ")
        if not term:
            self.message = "Anulowano"; return
        replace = self._ask(f"Zamien '{term}' na: ")
        if replace is None:
            self.message = "Anulowano"; return

        count = 0
        self._push_undo()
        for i, line in enumerate(self.lines):
            if term in line:
                new_line = line.replace(term, replace)
                self.lines[i] = new_line
                count += line.count(term)

        if count:
            self.modified = True
            self.message  = f"Zamieniono {count} wystapien '{term}' -> '{replace}'"
        else:
            self.message  = f"Nie znaleziono: '{term}'"

    # -------- Tryb liniowy (fallback dla Windows bez curses) --------

    def run_line_mode(self):
        """
        Uproszczony edytor liniowy — dziala wsedzie bez curses.
        Komendy: :w zapisz, :q wyjdz, :wq zapisz i wyjdz,
                 :p wyswietl, :N idz do linii N, :/ szukaj,
                 :d usun linie, :i N wstaw przed linia N,
                 :a dopisz na koncu, :h pomoc
        """
        print(f"{C.INFO}[nano-lite basic  |  {self.path}]{C.RESET}")
        print(f"{C.DIM}Komendy: :w zapis  :q wyjdz  :wq  :p wyswietl  :N idz do linii"
              f"  :/ szukaj  :d usun  :i N wstaw  :a dopisz  :h pomoc{C.RESET}")
        print(f"{C.DIM}Linie: {len(self.lines)}{C.RESET}")

        while True:
            try:
                ln_info = f"L{self.cy+1}/{len(self.lines)}"
                raw = input(f"{C.PROMPT}[{ln_info}]{C.RESET} ").rstrip("\n")
            except (EOFError, KeyboardInterrupt):
                print()
                if self.modified:
                    try:
                        ans = input(f"{C.INFO}Niezapisane zmiany. Zapisac? [t/n]: {C.RESET}").strip().lower()
                        if ans in ("t","y","tak"):
                            self.save()
                    except (EOFError, KeyboardInterrupt):
                        pass
                break

            # --- polecenia : ---
            if raw.startswith(":"):
                cmd = raw[1:].strip()

                # :w [plik] — zapis z opcjonalna nowa nazwa
                if cmd == "w" or cmd == "write":
                    self.save()
                    print_info(self.message)
                    continue
                elif cmd.startswith("w "):
                    new_name = cmd[2:].strip()
                    if new_name:
                        old_path = self.path
                        self.path = Path(new_name).expanduser()
                        self.save()
                        print_info(self.message)
                        self.path = old_path   # nie zmieniaj aktywnej sciezki
                    continue

                if cmd in ("q", "quit"):
                    if self.modified:
                        try:
                            ans = input(f"{C.INFO}Niezapisane zmiany. Wyjsc? [t/n]: {C.RESET}").strip().lower()
                            if ans not in ("t","y","tak"):
                                continue
                        except (EOFError, KeyboardInterrupt):
                            pass
                    break

                elif cmd in ("wq", "x"):
                    self.save()
                    print_info(self.message)
                    break

                elif cmd in ("p", "print"):
                    for i, l in enumerate(self.lines, 1):
                        marker = f"{C.INFO}>>{C.RESET}" if i == self.cy+1 else "  "
                        print(f"{C.DIM}{i:4d}{C.RESET}{marker} {l}")

                elif cmd in ("h", "help"):
                    print(f"{C.BOLD}Komendy nano-lite basic:{C.RESET}")
                    cmds = [
                        (":w",          "Zapisz plik"),
                        (":w plik",     "Zapisz jako nowy plik"),
                        (":q",          "Wyjdz (pyta o zapis)"),
                        (":wq / :x",    "Zapisz i wyjdz"),
                        (":p",          "Wyswietl caly plik z numerami linii"),
                        (":N",          "Idz do linii N  (np. :5)"),
                        (":/txt",       "Szukaj tekstu (nastepne: ://)"),
                        (":s/old/new",  "Zamien w biezacej linii"),
                        (":S/old/new",  "Zamien we wszystkich liniach"),
                        (":d / :d N",   "Usun biezaca / linie N"),
                        (":i N",        "Wstaw nowa linie PRZED linia N"),
                        (":a",          "Dopisz linie na koniec pliku"),
                        (":u",          "Cofnij ostatnia zmiane (undo)"),
                        (":r plik",     "Wczytaj i wstaw plik pod kursorem"),
                        ("tekst",       "Zastap biezaca linie (Enter zatwierdza)"),
                    ]
                    for k, v in cmds:
                        print(f"  {C.INFO}{k:<8}{C.RESET} {v}")

                elif cmd.startswith("/"):
                    term = cmd[1:]
                    found = False
                    for i, l in enumerate(self.lines):
                        if term.lower() in l.lower():
                            self.cy = i
                            print(f"{C.INFO}Znaleziono w linii {i+1}:{C.RESET} {l}")
                            found = True
                            break
                    if not found:
                        print_error(f"Nie znaleziono: {term}")

                elif cmd.startswith("d"):
                    rest = cmd[1:].strip()
                    try:
                        target = int(rest) - 1 if rest else self.cy
                        if 0 <= target < len(self.lines):
                            removed = self.lines.pop(target)
                            if not self.lines:
                                self.lines = [""]
                            self.cy = min(self.cy, len(self.lines)-1)
                            self.modified = True
                            print_info(f"Usunieto linie {target+1}: {removed[:60]}")
                        else:
                            print_error(f"Linia poza zakresem: {target+1}")
                    except ValueError:
                        print_error("Uzycie: :d lub :d N")

                elif cmd.startswith("s/") or cmd.startswith("S/"):
                    # :s/old/new  lub :S/old/new (wszystkie linie)
                    global_replace = cmd[0] == "S"
                    parts = cmd[1:].split("/")
                    if len(parts) >= 3:
                        _, old_t, new_t = parts[0], parts[1], parts[2]
                        count = 0
                        if global_replace:
                            for li in range(len(self.lines)):
                                if old_t in self.lines[li]:
                                    count += self.lines[li].count(old_t)
                                    self.lines[li] = self.lines[li].replace(old_t, new_t)
                            self.modified = bool(count)
                            print_info(f"Zamieniono {count} wystapien w pliku")
                        else:
                            if old_t in self.lines[self.cy]:
                                count = self.lines[self.cy].count(old_t)
                                self.lines[self.cy] = self.lines[self.cy].replace(old_t, new_t)
                                self.modified = True
                                print_info(f"Zamieniono {count} wystapien w linii {self.cy+1}")
                            else:
                                print_error(f"Nie znaleziono '{old_t}' w linii {self.cy+1}")
                    else:
                        print_error("Uzycie: :s/stary/nowy  lub :S/stary/nowy")

                elif cmd == "u":
                    # Undo
                    self.undo()
                    print_info(self.message)

                elif cmd.startswith("r "):
                    # :r plik — wczytaj i wstaw pod kursorem
                    fname = cmd[2:].strip()
                    fpath = Path(fname).expanduser()
                    if not fpath.exists():
                        print_error(f"Plik nie istnieje: {fname}")
                    else:
                        try:
                            inserted = fpath.read_text(encoding="utf-8", errors="replace").splitlines()
                            for i, l in enumerate(inserted):
                                self.lines.insert(self.cy + 1 + i, l)
                            self.cy += len(inserted)
                            self.modified = True
                            print_info(f"Wstawiono {len(inserted)} linii z {fname}")
                        except Exception as e:
                            print_error(str(e))

                elif cmd.startswith("i"):
                    rest = cmd[1:].strip()
                    try:
                        target = int(rest) - 1 if rest else self.cy
                        target = max(0, min(target, len(self.lines)))
                        try:
                            new_line = input(f"  Nowa linia [{target+1}]: ")
                        except (EOFError, KeyboardInterrupt):
                            continue
                        self.lines.insert(target, new_line)
                        self.cy = target
                        self.modified = True
                        print_info(f"Wstawiono przed linia {target+1}")
                    except ValueError:
                        print_error("Uzycie: :i lub :i N")

                elif cmd == "a":
                    try:
                        new_line = input(f"  Nowa linia [{len(self.lines)+1}]: ")
                    except (EOFError, KeyboardInterrupt):
                        continue
                    self.lines.append(new_line)
                    self.cy = len(self.lines) - 1
                    self.modified = True

                else:
                    # Probuj jako numer linii
                    try:
                        n = int(cmd) - 1
                        if 0 <= n < len(self.lines):
                            self.cy = n
                            print(f"{C.DIM}{n+1:4d}{C.RESET}  {self.lines[n]}")
                        else:
                            print_error(f"Linia poza zakresem: {n+1} (max {len(self.lines)})")
                    except ValueError:
                        print_error(f"Nieznane polecenie: :{cmd}  (wpisz :h po pomoc)")

            else:
                # Zwykly tekst — zastep biezaca linie
                if self.cy >= len(self.lines):
                    self.lines.append(raw)
                else:
                    self.lines[self.cy] = raw
                self.modified = True
                self.cy = min(self.cy + 1, len(self.lines) - 1)

@command("nano", "Wbudowany edytor tekstu (nano-lite)",
         aliases=["edit", "ed"], flags=["-r"])
def cmd_nano(args):
    """
    nano <plik>    - otwiera plik w edytorze
    nano           - otwiera nowy plik bez nazwy (pytanie przy zapisie)

    Skroty:
      Ctrl+S  Zapisz          Ctrl+X  Wyjdz
      Ctrl+F  Szukaj          Ctrl+N  Nastepne dopasowanie
      Ctrl+K  Wytnij linie    Ctrl+U  Wklej linie
      Ctrl+G  Pomoc           Strzalki / Home / End / PgUp / PgDn
    """
    # Jesli brak argumentu — zapytaj o nazwe
    if not args or args[0].startswith("-"):
        try:
            name = input(f"{C.INFO}Nazwa pliku (Enter = nowy): {C.RESET}").strip()
        except (EOFError, KeyboardInterrupt):
            return
        filepath = name if name else "noname.txt"
    else:
        filepath = args[0]

    editor = NanoEditor(filepath)
    editor.load()

    if not CURSES_OK:
        print_error("Brak modulu curses (Windows).")
        print_info("Instalacja: pip install windows-curses")
        print_info("Uruchamiam tryb liniowy (nano-lite basic)...")
        editor.run_line_mode()
        return

    try:
        curses.wrapper(editor.run)
    except Exception as e:
        print_error(f"Blad edytora: {e}")
        print_info("Proba trybu liniowego...")
        editor.run_line_mode()
    finally:
        print(C.RESET, end="", flush=True)

#   MINI-PIP — wlasny system pakietow
#
#  Format pakietu (.minipkg) — archiwum ZIP zawierajace:
#    manifest.json  - metadane pakietu
#    commands/*.py  - pliki z komendami (kazdy moze miec register())
#    data/          - pliki pomocnicze
#
#  manifest.json:
#  {
#    "name":        "hello",
#    "version":     "1.0.0",
#    "description": "Przykladowy pakiet",
#    "author":      "Seb",
#    "commands":    ["hello"],
#    "requires":    [],
#    "entry":       "commands/hello.py"
#  }
# ============================================================

PKG_INSTALL_DIR = PKG_DIR / "installed"   # rozpakowane pakiety

def _pkg_ensure_dirs():
    PKG_DIR.mkdir(parents=True, exist_ok=True)
    PKG_REPO.mkdir(parents=True, exist_ok=True)
    PKG_INSTALL_DIR.mkdir(parents=True, exist_ok=True)

def _pkg_load_db() -> dict:
    """Wczytuje baze zainstalowanych pakietow."""
    if PKG_DB.exists():
        try:
            return json.loads(PKG_DB.read_text(encoding="utf-8"))
        except Exception:  # ignorowane celowo
            pass
    return {}

def _pkg_save_db(db: dict):
    PKG_DB.write_text(json.dumps(db, indent=2, ensure_ascii=False), encoding="utf-8")

def _pkg_load_manifest(pkg_path: Path) -> dict | None:
    """Wczytuje manifest.json z pliku .minipkg (ZIP)."""
    try:
        with _get_zipfile().ZipFile(pkg_path, "r") as z:
            if "manifest.json" not in z.namelist():
                print_error("Brak manifest.json w pakiecie")
                return None
            return json.loads(z.read("manifest.json").decode("utf-8"))
    except Exception as e:
        print_error(f"Blad odczytu pakietu: {e}")
        return None

def _pkg_install_from_file(pkg_path: Path, db: dict, api) -> bool:
    """Instaluje pakiet z pliku .minipkg."""
    manifest = _pkg_load_manifest(pkg_path)
    if not manifest:
        return False

    name    = manifest.get("name", "")
    version = manifest.get("version", "0.0.0")
    entry   = manifest.get("entry", "")

    if not name:
        print_error("Manifest nie zawiera nazwy pakietu (name)")
        return False

    if name in db:
        print_info(f"Pakiet juz zainstalowany: {name} v{db[name]['version']}. Uzyj pkg update.")
        return False

    # Wypakuj do PKG_INSTALL_DIR/<name>/
    dest = PKG_INSTALL_DIR / name
    dest.mkdir(parents=True, exist_ok=True)
    try:
        with _get_zipfile().ZipFile(pkg_path, "r") as z:
            z.extractall(dest)
    except Exception as e:
        print_error(f"Blad wypakowania: {e}")
        return False

    # Zaladuj entry point jako plugin
    if entry:
        entry_file = dest / entry
        if entry_file.exists():
            _load_single_plugin(entry_file, api, silent=True)

    # Zapisz w bazie
    db[name] = {
        "version":     version,
        "description": manifest.get("description", ""),
        "author":      manifest.get("author", ""),
        "commands":    manifest.get("commands", []),
        "path":        str(dest),
        "installed":   datetime.datetime.now().isoformat(),
    }
    _pkg_save_db(db)
    print_info(f"Zainstalowano: {C.BOLD}{name}{C.RESET} v{version}")
    return True

def _pkg_create_scaffold(name: str, dest_dir: Path):
    """Tworzy scaffold nowego pakietu .minipkg."""
    manifest = {
        "name":        name,
        "version":     "1.0.0",
        "description": f"Pakiet {name}",
        "author":      "autor",
        "commands":    [name],
        "requires":    [],
        "entry":       f"commands/{name}.py",
    }
    entry_code = (
        f"# Komenda: {name}\n"
        f"# Pakiet mini-pip: {name} v1.0.0\n"
        "\n"
        "def register(api):\n"
        f'    @api.command("{name}", "Komenda z pakietu {name}")\n'
        f'    def cmd_{name}(args):\n'
        '        # opis komendy\n'
        f'        api.print_info(f"Czesc z pakietu {name}! args={{args}}")\n'
        "\n"
        "def unregister(api):\n"
        f'    api.unregister_command("{name}")\n'
    )
    pkg_tmp = dest_dir / f"{name}_src"
    (pkg_tmp / "commands").mkdir(parents=True, exist_ok=True)
    (pkg_tmp / "data").mkdir(parents=True, exist_ok=True)

    (pkg_tmp / "manifest.json").write_text(
        json.dumps(manifest, indent=2), encoding="utf-8")
    (pkg_tmp / "commands" / f"{name}.py").write_text(entry_code, encoding="utf-8")

    # Spakuj do .minipkg
    pkg_file = dest_dir / f"{name}.minipkg"
    with _get_zipfile().ZipFile(pkg_file, "w", _get_zipfile().ZIP_DEFLATED) as z:
        for f in pkg_tmp.rglob("*"):
            if f.is_file():
                z.write(f, f.relative_to(pkg_tmp))
    shutil.rmtree(pkg_tmp)

    print_info(f"Utworzono pakiet: {pkg_file}")
    print_info(f"Edytuj: {pkg_tmp.parent}/{name}_src/commands/{name}.py")
    print_info(f"Instalacja: pkg install {pkg_file}")
    return pkg_file

@command("pkg", "Menedzer pakietow mini-pip",
         aliases=["terminalx-pip"])
def cmd_pkg(args):
    """
    pkg list                   - zainstalowane pakiety
    pkg install <plik.minipkg>  - zainstaluj pakiet lokalny
    pkg install <plik> --pip    - zainstaluj + zaleznosci pip
    pkg install --url <url>     - pobierz i zainstaluj z URL (tryb online)
    pkg remove <nazwa>          - odinstaluj pakiet
    pkg update <nazwa> [plik]   - aktualizuj do nowej wersji
    pkg upgrade                 - aktualizuj wszystkie z repo
    pkg info <nazwa>            - szczegoly pakietu
    pkg search [query]          - przeszukaj repo
    pkg create <nazwa>          - wygeneruj szkielet pakietu
    pkg pack <katalog>          - spakuj katalog do .minipkg
    pkg enable <nazwa>          - zaladuj zainstalowany pakiet
    pkg disable <nazwa>         - wyladuj bez odinstalowania

    Format pakietu (.minipkg):
      Archiwum ZIP zawierajace manifest.json i pliki .py z komendami.
      pkg create <nazwa>  generuje szkielet,  pkg pack  spakuje go.
    """
    _pkg_ensure_dirs()
    api = ShellAPI()
    db  = _pkg_load_db()

    if not args:
        print_error("Uzycie: pkg <list|install|remove|info|search|create|enable|disable>")
        return

    subcmd = args[0]

    # ---- list ----
    if subcmd == "list":
        if not db:
            print_info(f"Brak zainstalowanych pakietow. Repo: {PKG_REPO}")
            return
        w = min(terminal_width() - 2, 78)
        print()
        print(box_top(f"Zainstalowane pakiety  ({len(db)})", width=w, color=C.INFO))
        print(box_row(f"  {C.BOLD}{'Nazwa':<18} {'Wersja':<10} {'Opis':<35} Status{C.RESET}", width=w, color=C.INFO))
        print(box_sep(width=w, color=C.INFO))
        for pname, meta in sorted(db.items()):
            loaded = pname in LOADED_PLUGINS
            status = f"{C.PATH}aktywny{C.RESET}" if loaded else f"{C.DIM}nieaktywny{C.RESET}"
            row = (f"  {C.INFO}{pname:<18}{C.RESET}"
                   f" v{meta['version']:<9}"
                   f" {meta['description'][:33]:<33}"
                   f" [{status}]")
            print(box_row(row, width=w, color=C.INFO))
        print(box_bottom(width=w, color=C.INFO))
        print()

    # ---- install ----
    elif subcmd == "install":
        if len(args) < 2:
            print_error("Uzycie: pkg install <plik.minipkg>"); return

        # Opcja --url: pobierz pakiet z internetu (tylko w trybie online)
        if "--url" in args:
            url_idx = args.index("--url")
            if url_idx + 1 >= len(args):
                print_error("Podaj URL po --url", "Uzycie: pkg install --url <url>"); return
            pkg_url = args[url_idx + 1]
            if not is_online():
                print_error(
                    "Tryb OFFLINE — pobieranie z URL jest niedostepne.",
                    "Uruchom 'mode online' aby wlaczyc tryb online.")
                return
            import urllib.request as _ureq, urllib.error as _uerr
            fname = pkg_url.split("/")[-1].split("?")[0]
            if not fname.endswith(".minipkg"):
                fname += ".minipkg"
            tmp_path = PKG_REPO / fname
            print_info(f"Pobieranie pakietu: {pkg_url}")
            try:
                req = _ureq.Request(pkg_url,
                    headers={"User-Agent": f"TerminalX/{SHELL_VERSION}"})
                with _ureq.urlopen(req, timeout=30) as resp:
                    tmp_path.write_bytes(resp.read())
                print_info(f"Pobrano: {tmp_path}  ({_human_size(tmp_path.stat().st_size)})")
                log_info(f"pkg install --url: {pkg_url} -> {tmp_path}")
            except _uerr.URLError as e:
                print_error(f"Blad pobierania: {e.reason}",
                            "Sprawdz URL i polaczenie sieciowe."); return
            except Exception as e:
                smart_error(e, "pkg install --url", pkg_url); return
            _pkg_install_from_file(tmp_path, db, api)
            return

        pkg_path = Path(args[1]).expanduser()

        # Jesli nie podano sciezki — szukaj w repo
        if not pkg_path.exists():
            candidate = PKG_REPO / (args[1] if args[1].endswith(".minipkg")
                                    else args[1] + ".minipkg")
            if candidate.exists():
                pkg_path = candidate
            else:
                print_error(f"Plik nie istnieje: {pkg_path}")
                print_info(f"Sprawdz tez repo: {PKG_REPO}")
                return

        # Opcja --pip: doinstaluj zaleznosci pip
        if "--pip" in args:
            manifest = _pkg_load_manifest(pkg_path)
            requires = manifest.get("requires", []) if manifest else []
            if requires:
                print_info(f"Instalowanie zaleznosci pip: {requires}")
                try:
                    subprocess.run(
                        [sys.executable, "-m", "pip", "install",
                         "--break-system-packages"] + requires,
                        check=True)
                except subprocess.CalledProcessError as e:
                    print_error(f"pip install nie powiodl sie: {e}")
                    return

        _pkg_install_from_file(pkg_path, db, api)

    # ---- remove ----
    elif subcmd == "remove":
        if len(args) < 2:
            print_error("Uzycie: pkg remove <nazwa>"); return
        name = args[1]
        if name not in db:
            print_error(f"Pakiet nie jest zainstalowany: {name}"); return

        # Wyladuj jesli aktywny
        if name in LOADED_PLUGINS:
            mod = LOADED_PLUGINS.pop(name)
            if hasattr(mod, "unregister"):
                try: mod.unregister(api)
                except Exception:
                    pass  # ignorowane celowo
            sys.modules.pop(f"_terminalx_plugin_{name}", None)

        # Usun pliki
        dest = Path(db[name]["path"])
        if dest.exists():
            shutil.rmtree(dest)

        del db[name]
        _pkg_save_db(db)
        print_info(f"Odinstalowano: {name}")

    # ---- info ----
    elif subcmd == "info":
        if len(args) < 2:
            print_error("Uzycie: pkg info <nazwa>"); return
        name = args[1]

        # Szukaj w zainstalowanych
        if name in db:
            meta = db[name]
            loaded = name in LOADED_PLUGINS
            w = min(terminal_width() - 2, 60)
            print()
            print(box_top(f"Pakiet: {name}", width=w, color=C.INFO))
            print(box_row(kv_row("Wersja",       meta['version'],          key_color=C.DIM), width=w, color=C.INFO))
            print(box_row(kv_row("Opis",         meta['description'],      key_color=C.DIM), width=w, color=C.INFO))
            print(box_row(kv_row("Autor",        meta['author'],           key_color=C.DIM), width=w, color=C.INFO))
            print(box_row(kv_row("Zainstalowany",meta['installed'][:19],   key_color=C.DIM), width=w, color=C.INFO))
            print(box_row(kv_row("Sciezka",      meta['path'],             key_color=C.DIM), width=w, color=C.INFO))
            cmds = meta.get("commands", [])
            print(box_row(kv_row("Komendy",      ', '.join(cmds) if cmds else 'brak', key_color=C.DIM), width=w, color=C.INFO))
            st_str = f"{C.PATH}aktywny{C.RESET}" if loaded else f"{C.DIM}nieaktywny{C.RESET}"
            print(box_row(kv_row("Status",       st_str,                   key_color=C.DIM), width=w, color=C.INFO))
            print(box_bottom(width=w, color=C.INFO))
            print()
            return

        # Szukaj w repo (plik .minipkg)
        candidate = PKG_REPO / f"{name}.minipkg"
        if candidate.exists():
            manifest = _pkg_load_manifest(candidate)
            if manifest:
                w = min(terminal_width() - 2, 60)
                print()
                print(box_top(f"Pakiet w repo: {name}", width=w, color=C.DIM))
                for k, v in manifest.items():
                    print(box_row(kv_row(k, str(v), key_color=C.DIM), width=w, color=C.DIM))
                print(box_bottom(width=w, color=C.DIM))
                print()
                return

        print_error(f"Pakiet nie znaleziony: {name}")

    # ---- search ----
    elif subcmd == "search":
        query = args[1].lower() if len(args) > 1 else ""
        results = []

        # Szukaj w repo
        for f in PKG_REPO.glob("*.minipkg"):
            manifest = _pkg_load_manifest(f)
            if manifest:
                name = manifest.get("name", f.stem)
                desc = manifest.get("description", "")
                if not query or query in name.lower() or query in desc.lower():
                    results.append((name, manifest.get("version","?"),
                                    desc, str(f), name in db))

        if not results:
            q = f" dla '{query}'" if query else ""
            print_info(f"Brak wynikow{q} w {PKG_REPO}")
            print_info(f"Dodaj pliki .minipkg do {PKG_REPO} aby rozszerzyc repo.")
            return

        title = f"Wyniki wyszukiwania{f' · {query}' if query else ''}  ({len(results)})"
        w = min(terminal_width() - 2, 78)
        print()
        print(box_top(title, width=w, color=C.DIM))
        for name, ver, desc, path, installed in results:
            inst_mark = f" {C.PATH}[zainstalowany]{C.RESET}" if installed else ""
            row = f"  {C.INFO}{name:<18}{C.RESET} v{ver:<8} {desc[:43]}{inst_mark}"
            print(box_row(row, width=w, color=C.DIM))
        print(box_bottom(width=w, color=C.DIM))
        print()

    # ---- create ----
    elif subcmd == "create":
        if len(args) < 2:
            print_error("Uzycie: pkg create <nazwa>"); return
        name = args[1].lower().replace(" ", "_")
        if not re.match(r"^[a-z][a-z0-9_-]*$", name):
            print_error("Nazwa pakietu: tylko litery, cyfry, _ i -"); return
        _pkg_create_scaffold(name, PKG_REPO)

    # ---- update ----
    elif subcmd == "update":
        if len(args) < 2:
            print_error("Uzycie: pkg update <nazwa> [plik.minipkg]"); return
        name = args[1]
        if name not in db:
            print_error(f"Pakiet nie jest zainstalowany: {name}"); return

        # Znajdz nowy plik .minipkg
        if len(args) >= 3:
            pkg_path = Path(args[2]).expanduser()
        else:
            pkg_path = PKG_REPO / f"{name}.minipkg"

        if not pkg_path.exists():
            print_error(f"Nie znaleziono nowej wersji: {pkg_path}")
            print_info(f"Uzycie: pkg update {name} <nowy_plik.minipkg>")
            return

        manifest = _pkg_load_manifest(pkg_path)
        if not manifest:
            return
        new_ver = manifest.get("version", "?")
        old_ver = db[name].get("version", "?")

        if old_ver == new_ver:
            print_info(f"Pakiet {name} jest juz w wersji {old_ver}. Uzyj --force aby wymusic.")
            if "--force" not in args:
                return

        print_info(f"Aktualizacja: {name}  {old_ver} -> {new_ver}")

        # Wyladuj stary jesli aktywny
        if name in LOADED_PLUGINS:
            mod = LOADED_PLUGINS.pop(name)
            if hasattr(mod, "unregister"):
                try: mod.unregister(api)
                except Exception:
                    pass  # ignorowane celowo
            sys.modules.pop(f"_terminalx_plugin_{name}", None)

        # Usun stare pliki
        dest = Path(db[name]["path"])
        if dest.exists():
            shutil.rmtree(dest)
        del db[name]

        # Zainstaluj nowa wersje
        _pkg_install_from_file(pkg_path, db, api)

    # ---- upgrade ----
    elif subcmd == "upgrade":
        # Aktualizuj wszystkie pakiety z repo
        updated = 0
        for pname in list(db.keys()):
            pkg_path = PKG_REPO / f"{pname}.minipkg"
            if not pkg_path.exists():
                continue
            manifest = _pkg_load_manifest(pkg_path)
            if not manifest:
                continue
            new_ver = manifest.get("version", "?")
            old_ver = db[pname].get("version", "?")
            if old_ver == new_ver:
                continue
            print_info(f"Aktualizacja: {pname}  {old_ver} -> {new_ver}")
            if pname in LOADED_PLUGINS:
                mod = LOADED_PLUGINS.pop(pname)
                if hasattr(mod, "unregister"):
                    try: mod.unregister(api)
                    except Exception:
                        pass  # ignorowane celowo
                sys.modules.pop(f"_terminalx_plugin_{pname}", None)
            dest = Path(db[pname]["path"])
            if dest.exists():
                shutil.rmtree(dest)
            del db[pname]
            _pkg_install_from_file(pkg_path, db, api)
            updated += 1
        if updated == 0:
            print_info("Wszystkie pakiety sa aktualne.")
        else:
            print_info(f"Zaktualizowano {updated} pakiet(ow).")

    # ---- pack ----
    elif subcmd == "pack":
        # pkg pack <katalog_zrodlowy>  ->  tworzy .minipkg
        if len(args) < 2:
            print_error("Uzycie: pkg pack <katalog_zrodlowy> [wyjscie.minipkg]"); return
        src_dir = Path(args[1]).expanduser()
        if not src_dir.is_dir():
            print_error(f"Nie jest katalogiem: {src_dir}"); return
        manifest_f = src_dir / "manifest.json"
        if not manifest_f.exists():
            print_error(f"Brak manifest.json w {src_dir}")
            print_info("Struktura: katalog/manifest.json + katalog/commands/nazwa.py")
            return
        try:
            manifest = json.loads(manifest_f.read_text(encoding="utf-8"))
        except Exception as e:
            print_error(f"Blad odczytu manifest.json: {e}"); return

        pkg_name = manifest.get("name", src_dir.name)
        pkg_ver  = manifest.get("version", "1.0.0")

        if len(args) >= 3:
            out_path = Path(args[2]).expanduser()
        else:
            out_path = PKG_REPO / f"{pkg_name}.minipkg"

        try:
            with _get_zipfile().ZipFile(out_path, "w", _get_zipfile().ZIP_DEFLATED) as z:
                for fpath in src_dir.rglob("*"):
                    if fpath.is_file() and "__pycache__" not in str(fpath):
                        z.write(fpath, fpath.relative_to(src_dir))
            size_kb = out_path.stat().st_size // 1024
            print_info(f"Spakowano: {out_path}  ({size_kb} KB)  [{pkg_name} v{pkg_ver}]")
            print_info(f"Instalacja: pkg install {out_path}")
        except Exception as e:
            print_error(f"Blad pakowania: {e}")

    # ---- enable ----
    elif subcmd == "enable":
        if len(args) < 2:
            print_error("Uzycie: pkg enable <nazwa>"); return
        name = args[1]
        if name not in db:
            print_error(f"Pakiet nie jest zainstalowany: {name}"); return
        if name in LOADED_PLUGINS:
            print_info(f"Pakiet juz aktywny: {name}"); return
        entry = db[name].get("entry", "")
        path  = Path(db[name]["path"])
        # Odtworz entry z manifestu
        manifest_f = path / "manifest.json"
        if manifest_f.exists():
            manifest = json.loads(manifest_f.read_text(encoding="utf-8"))
            entry = manifest.get("entry", "")
        if entry:
            _load_single_plugin(path / entry, api)
        else:
            print_error(f"Brak entry point dla pakietu: {name}")

    # ---- disable ----
    elif subcmd == "disable":
        if len(args) < 2:
            print_error("Uzycie: pkg disable <nazwa>"); return
        name = args[1]
        if name not in LOADED_PLUGINS:
            print_info(f"Pakiet nie jest aktywny: {name}"); return
        mod = LOADED_PLUGINS.pop(name)
        if hasattr(mod, "unregister"):
            try: mod.unregister(api)
            except Exception as e: print_error(f"Blad unregister: {e}")
        sys.modules.pop(f"_terminalx_plugin_{name}", None)
        print_info(f"Wyladowano pakiet: {name} (dane zachowane, pkg enable aby przywrocic)")

    else:
        print_error(f"Nieznane polecenie: pkg {subcmd}")
        print_info("Dostepne: list, install, remove, update, upgrade, info, search, create, pack, enable, disable")

# DIAG
#   Diagnostyka systemu: CPU, RAM, dyski, siec, procesy
#   Czysto stdlib — /proc na Linux, ctypes na Windows

import socket as _socket

def _read_proc(path: str, default: str = "") -> str:
    try:
        return Path(path).read_text(errors="ignore")
    except Exception:
        return default

def _diag_cpu() -> dict:
    import platform
    info = {"model": "nieznany", "cores": os.cpu_count() or 1,
            "arch": platform.machine(), "freq_mhz": 0}
    if os.name == "nt":
        info["model"] = os.environ.get("PROCESSOR_IDENTIFIER", "Windows CPU")
        return info
    txt = _read_proc("/proc/cpuinfo")
    for line in txt.splitlines():
        if "model name" in line:
            info["model"] = line.split(":", 1)[-1].strip()
        if "cpu MHz" in line:
            try: info["freq_mhz"] = float(line.split(":", 1)[-1].strip())
            except ValueError: pass
    info["cores"] = max(1, txt.count("processor\t:"))
    return info

def _diag_cpu_usage_pct(interval: float = 0.3) -> float:
    if os.name == "nt":
        return 0.0
    import time as _time
    def _stat():
        line = _read_proc("/proc/stat").splitlines()[0]
        vals = list(map(int, line.split()[1:]))
        return sum(vals), vals[3]
    t1, i1 = _stat()
    _time.sleep(interval)
    t2, i2 = _stat()
    dt = t2 - t1
    return round((1.0 - (i2 - i1) / dt) * 100, 1) if dt else 0.0

def _diag_ram() -> dict:
    info = {"total": 0, "available": 0, "used": 0, "pct": 0.0}
    if os.name == "nt":
        try:
            import ctypes
            class MS(ctypes.Structure):
                _fields_ = [("dwLength", ctypes.c_ulong), ("dwMemoryLoad", ctypes.c_ulong),
                             ("ullTotalPhys", ctypes.c_ulonglong), ("ullAvailPhys", ctypes.c_ulonglong),
                             ("ullTotalPageFile", ctypes.c_ulonglong), ("ullAvailPageFile", ctypes.c_ulonglong),
                             ("ullTotalVirtual", ctypes.c_ulonglong), ("ullAvailVirtual", ctypes.c_ulonglong),
                             ("sullAvailExtendedVirtual", ctypes.c_ulonglong)]
            ms = MS(); ms.dwLength = ctypes.sizeof(MS)
            ctypes.windll.kernel32.GlobalMemoryStatusEx(ctypes.byref(ms))
            info.update({"total": ms.ullTotalPhys, "available": ms.ullAvailPhys,
                         "used": ms.ullTotalPhys - ms.ullAvailPhys, "pct": float(ms.dwMemoryLoad)})
        except Exception:
            pass  # ignorowane celowo
        return info
    vals = {}
    for line in _read_proc("/proc/meminfo").splitlines():
        if ":" in line:
            k, _, v = line.partition(":")
            try: vals[k.strip()] = int(v.split()[0]) * 1024
            except (ValueError, IndexError): pass
    total = vals.get("MemTotal", 0)
    avail = vals.get("MemAvailable", vals.get("MemFree", 0))
    used  = total - avail
    info.update({"total": total, "available": avail, "used": used,
                 "pct": round(used / total * 100, 1) if total else 0.0})
    return info

def _diag_disks() -> list:
    disks = []
    if os.name == "nt":
        import ctypes, string
        for d in [f"{c}:\\" for c in string.ascii_uppercase if Path(f"{c}:\\").exists()]:
            try:
                free = ctypes.c_ulonglong(0); total = ctypes.c_ulonglong(0)
                ctypes.windll.kernel32.GetDiskFreeSpaceExW(d, None, ctypes.byref(total), ctypes.byref(free))
                used = total.value - free.value
                disks.append({"mount": d, "total": total.value, "used": used,
                               "free": free.value, "pct": round(used/total.value*100,1) if total.value else 0, "fstype":"NTFS"})
            except Exception:
                pass  # ignorowane celowo
        return disks
    skip = {"tmpfs","devtmpfs","sysfs","proc","cgroup","devpts","pstore",
            "securityfs","debugfs","hugetlbfs","mqueue","fusectl","bpf"}
    seen = set()
    for line in _read_proc("/proc/mounts").splitlines():
        parts = line.split()
        if len(parts) < 3: continue
        mount, fstype = parts[1], parts[2]
        if mount in seen or fstype in skip: continue
        seen.add(mount)
        try:
            st = os.statvfs(mount)
            total = st.f_blocks * st.f_frsize
            free  = st.f_bavail * st.f_frsize
            used  = (st.f_blocks - st.f_bfree) * st.f_frsize
            if not total: continue
            disks.append({"mount": mount, "total": total, "used": used,
                           "free": free, "pct": round(used/total*100,1), "fstype": fstype})
        except Exception:
            pass  # ignorowane celowo
    return disks

def _diag_net_ifaces() -> list:
    ifaces = []
    if os.name == "nt":
        try:
            r = subprocess.run(["ipconfig"], capture_output=True, text=True, timeout=5)
            cur = {}
            for line in r.stdout.splitlines():
                l = line.strip()
                if l.lower().startswith("adapter") or (l.endswith(":") and "adapter" in l.lower()):
                    if cur: ifaces.append(cur)
                    cur = {"name": l.rstrip(":"), "ipv4": "", "ipv6": ""}
                elif "IPv4" in l: cur["ipv4"] = l.split(":",1)[-1].strip()
                elif "IPv6" in l: cur["ipv6"] = l.split(":",1)[-1].strip()
            if cur: ifaces.append(cur)
        except Exception:
            pass  # ignorowane celowo
        return ifaces
    names = [l.split(":")[0].strip() for l in _read_proc("/proc/net/dev").splitlines()[2:] if ":" in l]
    try:
        import fcntl
        SIOCGIFADDR = 0x8915
        for name in names:
            ipv4 = ""
            try:
                s = _socket.socket(_socket.AF_INET, _socket.SOCK_DGRAM)
                ifreq = name.encode()[:15].ljust(16, b'\x00') + b'\x00'*24
                res = fcntl.ioctl(s.fileno(), SIOCGIFADDR, ifreq)
                s.close()
                ipv4 = _socket.inet_ntoa(res[20:24])
            except Exception:
                pass  # ignorowane celowo
            ifaces.append({"name": name, "ipv4": ipv4, "ipv6": ""})
    except ImportError:
        ifaces = [{"name": n, "ipv4": "", "ipv6": ""} for n in names]
    return ifaces

def _diag_net_stats() -> dict:
    stats = {}
    for line in _read_proc("/proc/net/dev").splitlines()[2:]:
        if ":" not in line: continue
        name, data = line.split(":", 1)
        parts = data.split()
        if len(parts) >= 9:
            stats[name.strip()] = {"rx_bytes": int(parts[0]), "tx_bytes": int(parts[8])}
    return stats

def _diag_processes(n: int = 10) -> list:
    procs = []
    if os.name == "nt":
        try:
            r = subprocess.run(["tasklist","/fo","csv","/nh"], capture_output=True, text=True, timeout=5)
            for line in r.stdout.splitlines()[:n]:
                p = [x.strip('"') for x in line.split('","')]
                if len(p) >= 5:
                    procs.append({"pid": p[1], "name": p[0], "mem": p[4], "cpu_ticks": 0})
        except Exception:
            pass  # ignorowane celowo
        return procs
    for pid_dir in sorted(Path("/proc").iterdir()):
        if not pid_dir.name.isdigit(): continue
        try:
            name = (pid_dir/"comm").read_text().strip()
            stat = (pid_dir/"stat").read_text().split()
            cpu  = int(stat[13]) + int(stat[14])
            status_txt = (pid_dir/"status").read_text(errors="ignore")
            mem_kb = 0
            if "VmRSS:" in status_txt:
                try: mem_kb = int(status_txt.split("VmRSS:")[1].split()[0])
                except Exception:
                    pass  # ignorowane celowo
            procs.append({"pid": pid_dir.name, "name": name, "cpu_ticks": cpu, "mem_kb": mem_kb})
        except Exception:
            pass  # ignorowane celowo
    procs.sort(key=lambda p: p.get("cpu_ticks", 0), reverse=True)
    return procs[:n]

def _bar(pct: float, width: int = 20, color_hi: str = "", color_lo: str = "") -> str:
    filled = round(pct / 100 * width)
    color  = (color_hi or C.ERROR) if pct > 80 else (C.INFO if pct > 50 else (color_lo or C.PATH))
    return f"{color}{'█'*filled}{'░'*(width-filled)}{C.RESET} {pct:5.1f}%"

@command("diag", "Diagnostyka systemu: CPU, RAM, dyski, siec, procesy",
         aliases=["sysstat"], flags=["-c","-m","-d","-n","-p","-a"])
def cmd_diag(args):
    """
    diag       - CPU + RAM + dyski + siec
    diag -c    - CPU           diag cpu
    diag -m    - RAM           diag mem
    diag -d    - dyski         diag disk
    diag -n    - siec          diag net
    diag -p    - procesy       diag proc
    diag -a    - wszystko + procesy
    """
    subcmd   = args[0] if args else "all"
    flags    = {a for a in args if a.startswith("-")}
    show_all = "-a" in flags or subcmd == "all"
    show_cpu  = "-c" in flags or subcmd == "cpu"  or show_all
    show_mem  = "-m" in flags or subcmd == "mem"  or show_all
    show_disk = "-d" in flags or subcmd == "disk" or show_all
    show_net  = "-n" in flags or subcmd == "net"  or show_all
    show_proc = "-p" in flags or subcmd == "proc" or "-a" in flags
    w = min(terminal_width() - 2, 70)

    if show_cpu:
        cpu = _diag_cpu()
        print()
        print(box_top("CPU", width=w, color=C.INFO))
        print(box_row(kv_row("Model",   cpu["model"],         key_color=C.DIM), width=w, color=C.INFO))
        print(box_row(kv_row("Rdzenie", str(cpu["cores"]),    key_color=C.DIM), width=w, color=C.INFO))
        print(box_row(kv_row("Arch",    cpu["arch"],          key_color=C.DIM), width=w, color=C.INFO))
        if cpu["freq_mhz"]:
            print(box_row(kv_row("Czestotliwosc", f"{cpu['freq_mhz']:.0f} MHz", key_color=C.DIM), width=w, color=C.INFO))
        print_info("Mierzenie uzycia CPU (0.3s)...")
        pct = _diag_cpu_usage_pct()
        print(box_row(kv_row("Uzycie CPU", _bar(pct), key_color=C.DIM), width=w, color=C.INFO))
        print(box_bottom(width=w, color=C.INFO))

    if show_mem:
        ram = _diag_ram()
        print()
        print(box_top("RAM / Pamiec", width=w, color=C.PROMPT))
        print(box_row(kv_row("Calkowita",  _human_size(ram["total"]),     key_color=C.DIM), width=w, color=C.PROMPT))
        print(box_row(kv_row("Uzyta",      _human_size(ram["used"]),      key_color=C.DIM), width=w, color=C.PROMPT))
        print(box_row(kv_row("Dostepna",   _human_size(ram["available"]), key_color=C.DIM), width=w, color=C.PROMPT))
        print(box_row(kv_row("Uzycie RAM", _bar(ram["pct"]),              key_color=C.DIM), width=w, color=C.PROMPT))
        print(box_bottom(width=w, color=C.PROMPT))

    if show_disk:
        disks = _diag_disks()
        print()
        print(box_top(f"Dyski  ({len(disks)} woluminow)", width=w, color=C.PATH))
        for d in disks:
            print(box_row(f"  {C.BOLD}{d['mount']}{C.RESET}  {C.DIM}{d['fstype']}{C.RESET}", width=w, color=C.PATH))
            print(box_row(kv_row("  Zapelnienie", _bar(d["pct"]),    key_color=C.DIM), width=w, color=C.PATH))
            print(box_row(f"  {C.DIM}uzyte {_human_size(d['used'])} / {_human_size(d['total'])}  wolne {_human_size(d['free'])}{C.RESET}", width=w, color=C.PATH))
            print(box_sep(width=w, color=C.PATH))
        if not disks:
            print(box_row(f"  {C.DIM}Brak danych{C.RESET}", width=w, color=C.PATH))
        print(box_bottom(width=w, color=C.PATH))

    if show_net:
        ifaces = _diag_net_ifaces()
        stats  = _diag_net_stats()
        print()
        print(box_top(f"Siec  ({len(ifaces)} interfejsow)", width=w, color=C.EXEC))
        for iface in ifaces:
            name = iface["name"]
            ipv4 = iface["ipv4"] or f"{C.DIM}(brak IPv4){C.RESET}"
            st   = stats.get(name, {})
            rx   = _human_size(st.get("rx_bytes", 0)) if st else "?"
            tx   = _human_size(st.get("tx_bytes", 0)) if st else "?"
            print(box_row(f"  {C.BOLD}{name:<12}{C.RESET} {C.EXEC}{ipv4:<18}{C.RESET} {C.DIM}RX:{rx}  TX:{tx}{C.RESET}", width=w, color=C.EXEC))
        print(box_bottom(width=w, color=C.EXEC))

    if show_proc:
        procs = _diag_processes(12)
        print()
        print(box_top("Procesy (top 12 CPU)", width=w, color=C.DIM))
        print(box_row(f"  {C.BOLD}{'PID':<8}{'Nazwa':<22}{'RAM':>8}{'CPU ticks':>12}{C.RESET}", width=w, color=C.DIM))
        print(box_sep(width=w, color=C.DIM))
        for p in procs:
            mem_str = _human_size(p.get("mem_kb",0)*1024) if "mem_kb" in p else p.get("mem","?")
            cpu_str = str(p.get("cpu_ticks", p.get("cpu","?")))
            print(box_row(f"  {C.DIM}{p['pid']:<8}{C.RESET}{C.INFO}{p['name']:<22}{C.RESET}{C.DIM}{mem_str:>8}{cpu_str:>12}{C.RESET}", width=w, color=C.DIM))
        print(box_bottom(width=w, color=C.DIM))
    print()

# FILES_EXT
#   Archiwizacja (tar.gz/zip), du, tree, stat

import tarfile as _tarfile

@command("archive", "Tworzenie i rozpakowywanie archiwow",
         aliases=["tar", "untar", "unzip"], flags=["-c","-x","-l","-v"])
def cmd_archive(args):
    """
    archive -c <archiwum.tar.gz> <src> ...  - utwórz
    archive -x <archiwum> [dest]            - rozpakuj
    archive -l <archiwum>                   - lista zawartosci
    archive -v                              - verbose
    Formaty: .tar.gz .tgz .tar.bz2 .tar.xz .tar .zip
    """
    if not args:
        print_error("Brak argumentow", "Uzycie: archive -c|-x|-l <archiwum> [pliki...]"); return
    flags   = {a for a in args if a.startswith("-")}
    paths   = [a for a in args if not a.startswith("-")]
    verbose = "-v" in flags
    if not paths:
        print_error("Podaj nazwe archiwum"); return
    arch  = Path(paths[0]).expanduser()
    ext   = "".join(arch.suffixes).lower()

    if "-c" in flags:
        srcs = [Path(p).expanduser() for p in paths[1:]]
        if not srcs:
            print_error("Podaj pliki/katalogi do spakowania"); return
        for s in srcs:
            if not s.exists():
                print_error(f"Nie istnieje: '{s}'"); return
        try:
            if ext.endswith(".zip"):
                with _get_zipfile().ZipFile(arch, "w", _get_zipfile().ZIP_DEFLATED) as zf:
                    for src in srcs:
                        if src.is_dir():
                            for f in src.rglob("*"):
                                if f.is_file():
                                    zf.write(f, f.relative_to(src.parent))
                                    if verbose: print(f"  + {f}")
                        else:
                            zf.write(src, src.name)
                            if verbose: print(f"  + {src}")
            else:
                mode_map = {".tar.gz":"w:gz",".tgz":"w:gz",".tar.bz2":"w:bz2",".tar.xz":"w:xz",".tar":"w"}
                mode = next((v for k,v in mode_map.items() if ext.endswith(k.lstrip("."))), "w:gz")
                with _tarfile.open(arch, mode) as tf:
                    for src in srcs:
                        tf.add(src, arcname=src.name)
                        if verbose: print(f"  + {src}")
            print_ok(f"Utworzono: {arch}  ({_human_size(arch.stat().st_size)})")
            log_info(f"archive create: {arch}")
        except Exception as e:
            smart_error(e, "archive create", str(arch))

    elif "-x" in flags:
        dest = Path(paths[1]).expanduser() if len(paths) > 1 else Path.cwd()
        if not arch.exists():
            print_error(f"Archiwum nie istnieje: '{arch}'"); return
        dest.mkdir(parents=True, exist_ok=True)
        try:
            if ext.endswith(".zip"):
                with _get_zipfile().ZipFile(arch, "r") as zf:
                    if verbose:
                        for n in zf.namelist(): print(f"  x {n}")
                    zf.extractall(dest)
            elif _tarfile.is_tarfile(arch):
                with _tarfile.open(arch, "r:*") as tf:
                    if verbose:
                        for m in tf.getmembers(): print(f"  x {m.name}")
                    tf.extractall(dest)
            else:
                print_error(f"Nieznany format: '{arch.suffix}'"); return
            print_ok(f"Rozpakowano do: {dest}")
            log_info(f"archive extract: {arch} -> {dest}")
        except Exception as e:
            smart_error(e, "archive extract", str(arch))

    elif "-l" in flags:
        if not arch.exists():
            print_error(f"Archiwum nie istnieje: '{arch}'"); return
        try:
            w2 = min(terminal_width()-2, 72)
            print(); print(box_top(f"Zawartosc: {arch.name}", width=w2, color=C.DIM))
            total_size = 0; count = 0
            if ext.endswith(".zip"):
                with _get_zipfile().ZipFile(arch, "r") as zf:
                    for info in zf.infolist():
                        total_size += info.file_size; count += 1
                        print(box_row(f"  {_human_size(info.file_size):>8}  {info.filename}", width=w2, color=C.DIM))
            elif _tarfile.is_tarfile(arch):
                with _tarfile.open(arch, "r:*") as tf:
                    for m in tf.getmembers():
                        total_size += m.size; count += 1
                        print(box_row(f"  {_human_size(m.size):>8}  {m.name}", width=w2, color=C.DIM))
            print(box_sep(width=w2, color=C.DIM))
            print(box_row(f"  {count} elementow  razem: {_human_size(total_size)}", width=w2, color=C.DIM))
            print(box_bottom(width=w2, color=C.DIM))
        except Exception as e:
            smart_error(e, "archive list", str(arch))
    else:
        print_error("Podaj flage: -c (tworz) | -x (rozpakuj) | -l (lista)")

@command("du", "Rozmiar katalogu i plikow", aliases=["diskusage"])
def cmd_du(args):
    """
    du [katalog]   - rozmiar podkatalogow
    du -s [kat]    - tylko suma
    """
    show_sum = "-s" in args
    paths    = [a for a in args if not a.startswith("-")]
    target   = Path(paths[0]).expanduser() if paths else Path.cwd()
    if not target.exists():
        print_error(f"Sciezka nie istnieje: '{target}'"); return

    def _size(p: Path) -> int:
        if p.is_file():
            try: return p.stat().st_size
            except Exception: return 0
        t = 0
        try:
            for c in p.rglob("*"):
                try: t += c.stat().st_size if c.is_file() else 0
                except Exception:
                    pass  # ignorowane celowo
        except Exception:
            pass  # ignorowane celowo
        return t

    if show_sum or target.is_file():
        print(f"  {_human_size(_size(target)):>8}  {target}"); return

    entries = []
    try:
        for child in sorted(target.iterdir()):
            entries.append((_size(child), child))
    except PermissionError:
        print_error(f"Brak uprawnien: '{target}'"); return
    entries.sort(reverse=True)
    total = sum(s for s, _ in entries)
    w2 = min(terminal_width()-2, 60)
    print(); print(box_top(f"Rozmiar: {target}", width=w2, color=C.PATH))
    for sz, p in entries[:30]:
        icon = "📁" if p.is_dir() else "📄"
        print(box_row(f"  {_human_size(sz):>8}  {icon} {p.name}", width=w2, color=C.PATH))
    if len(entries) > 30:
        print(box_row(f"  ...i {len(entries)-30} wiecej", width=w2, color=C.PATH))
    print(box_sep(width=w2, color=C.PATH))
    print(box_row(f"  {C.BOLD}Razem: {_human_size(total)}{C.RESET}", width=w2, color=C.PATH))
    print(box_bottom(width=w2, color=C.PATH)); print()

@command("tree", "Drzewo katalogow", flags=["--depth","-a","-f"])
def cmd_tree(args):
    """
    tree [kat]          - drzewo (max 3 poziomy)
    tree -a [kat]       - z ukrytymi
    tree --depth N [kat]
    """
    show_all  = "-a" in args
    full_path = "-f" in args
    max_depth = 3
    paths     = [a for a in args if not a.startswith("-")]
    for i, a in enumerate(args):
        if a == "--depth" and i+1 < len(args):
            try: max_depth = int(args[i+1])
            except ValueError: pass
    paths   = [a for a in paths if not a.isdigit()]
    target  = Path(paths[0]).expanduser() if paths else Path.cwd()
    if not target.is_dir():
        print_error(f"Katalog nie istnieje: '{target}'"); return
    counts = [0, 0]
    print(f"\n{C.BOLD}{target}{C.RESET}")
    def _render(path: Path, prefix: str, depth: int):
        if depth > max_depth: return
        try:
            entries = sorted(path.iterdir(), key=lambda p: (not p.is_dir(), p.name.lower()))
        except PermissionError:
            print(f"{prefix}└── {C.ERROR}[odmowa dostepu]{C.RESET}"); return
        if not show_all:
            entries = [e for e in entries if not e.name.startswith(".")]
        for i, entry in enumerate(entries):
            is_last = (i == len(entries)-1)
            conn    = "└── " if is_last else "├── "
            ext_    = "    " if is_last else "│   "
            name_str = str(entry) if full_path else entry.name
            if entry.is_dir():
                counts[0] += 1
                print(f"{prefix}{conn}{C.DIR}{name_str}/{C.RESET}")
                _render(entry, prefix+ext_, depth+1)
            else:
                counts[1] += 1
                color = ls_color(entry)
                icon  = ls_icon(entry)+" " if cfg("use_emoji_icons",True) else ""
                print(f"{prefix}{conn}{icon}{color}{name_str}{C.RESET}")
    _render(target, "", 1)
    print(f"\n{C.DIM}{counts[0]} katalogow, {counts[1]} plikow{C.RESET}\n")

@command("stat", "Szczegolowe informacje o pliku/katalogu")
def cmd_stat(args):
    """stat <plik>  - rozmiar, uprawnienia, daty, inode"""
    if not args:
        print_error("Podaj nazwe pliku","Uzycie: stat <plik>"); return
    import stat as _stat_mod
    path = Path(args[0]).expanduser()
    if not path.exists():
        print_error(f"Nie istnieje: '{path}'"); return
    try:
        st = path.stat()
        w2 = min(terminal_width()-2, 62)
        fmt = "%Y-%m-%d %H:%M:%S"
        print(); print(box_top(f"stat: {path.name}", width=w2, color=C.DIM))
        print(box_row(kv_row("Sciezka",     str(path.resolve()),       key_color=C.DIM), width=w2, color=C.DIM))
        print(box_row(kv_row("Rozmiar",     _human_size(st.st_size),   key_color=C.DIM), width=w2, color=C.DIM))
        print(box_row(kv_row("Bajty",       str(st.st_size),           key_color=C.DIM), width=w2, color=C.DIM))
        print(box_row(kv_row("Typ",         "katalog" if path.is_dir() else "plik", key_color=C.DIM), width=w2, color=C.DIM))
        print(box_row(kv_row("Uprawnienia", _stat_mod.filemode(st.st_mode), key_color=C.DIM), width=w2, color=C.DIM))
        try: print(box_row(kv_row("Inode", str(st.st_ino), key_color=C.DIM), width=w2, color=C.DIM))
        except Exception:
            pass  # ignorowane celowo
        print(box_sep(width=w2, color=C.DIM))
        print(box_row(kv_row("Modyfikacja", datetime.datetime.fromtimestamp(st.st_mtime).strftime(fmt), key_color=C.DIM), width=w2, color=C.DIM))
        print(box_row(kv_row("Dostep",      datetime.datetime.fromtimestamp(st.st_atime).strftime(fmt), key_color=C.DIM), width=w2, color=C.DIM))
        try: print(box_row(kv_row("Zmiana",datetime.datetime.fromtimestamp(st.st_ctime).strftime(fmt), key_color=C.DIM), width=w2, color=C.DIM))
        except Exception:
            pass  # ignorowane celowo
        print(box_bottom(width=w2, color=C.DIM)); print()
    except Exception as e:
        smart_error(e, "stat", str(path))

# LOGS_CMD
#   tail, head, logrotate, logscan

@command("tail", "Wyswietl koniec pliku (live follow -f)", flags=["-f","-n"])
def cmd_tail(args):
    """
    tail <plik>        - ostatnie 10 linii
    tail -n N <plik>   - ostatnie N linii
    tail -f <plik>     - live follow (Ctrl+C aby zatrzymac)
    """
    import time as _time
    follow = "-f" in args
    n = 10
    for i, a in enumerate(args):
        if a == "-n" and i+1 < len(args):
            try: n = int(args[i+1])
            except ValueError: pass
    path_args = [a for a in args if not a.startswith("-") and not a.isdigit()]
    if not path_args:
        print_error("Podaj nazwe pliku","Uzycie: tail [-f] [-n N] <plik>"); return
    path = Path(path_args[0]).expanduser()
    if not path.exists():
        print_error(f"Plik nie istnieje: '{path}'"); return

    def _tail_lines(p, count):
        try:
            with p.open("rb") as f:
                f.seek(0,2); size = f.tell()
                blocks = []; pos = size; found = 0
                while pos > 0 and found < count+1:
                    rs = min(8192, pos); pos -= rs; f.seek(pos)
                    block = f.read(rs); blocks.append(block); found += block.count(b"\n")
                content = b"".join(reversed(blocks))
                return content.decode(errors="replace").splitlines()[-count:]
        except Exception as e:
            smart_error(e, "tail", str(p)); return []

    for line in _tail_lines(path, n):
        print(line)
    if not follow: return
    print(f"{C.DIM}--- {path.name} (Ctrl+C aby zatrzymac) ---{C.RESET}")
    last_size = path.stat().st_size
    try:
        while True:
            _time.sleep(0.5)
            try: new_size = path.stat().st_size
            except Exception: break
            if new_size > last_size:
                with path.open("rb") as f:
                    f.seek(last_size)
                    new_data = f.read(new_size - last_size)
                for line in new_data.decode(errors="replace").splitlines():
                    print(line)
                last_size = new_size
            elif new_size < last_size:
                print(f"{C.INFO}[Plik zostal zrotowany]{C.RESET}"); last_size = new_size
    except KeyboardInterrupt:
        print()

@command("head", "Wyswietl poczatek pliku", flags=["-n"])
def cmd_head(args):
    """head <plik> | head -n N <plik>"""
    n = 10
    for i, a in enumerate(args):
        if a == "-n" and i+1 < len(args):
            try: n = int(args[i+1])
            except ValueError: pass
    path_args = [a for a in args if not a.startswith("-") and not a.isdigit()]
    if not path_args:
        print_error("Podaj nazwe pliku","Uzycie: head [-n N] <plik>"); return
    path = Path(path_args[0]).expanduser()
    if not path.exists():
        print_error(f"Nie istnieje: '{path}'"); return
    try:
        with path.open(encoding="utf-8", errors="replace") as f:
            for i, line in enumerate(f):
                if i >= n: break
                print(line, end="")
    except Exception as e:
        smart_error(e, "head", str(path))

@command("logrotate", "Rotuj plik logu", aliases=["rotatelog"], flags=["-k","-s"])
def cmd_logrotate(args):
    """
    logrotate [plik]     - rotuj (domyslnie ~/.terminalx.log)
    logrotate -k N       - zachowaj N kopii (domyslnie 5)
    logrotate -s MB      - rotuj tylko jesli rozmiar > MB
    """
    paths = [a for a in args if not a.startswith("-") and not a.isdigit()]
    path  = Path(paths[0]).expanduser() if paths else LOG_FILE
    keep  = 5; max_mb = 0.0
    for i, a in enumerate(args):
        if a == "-k" and i+1 < len(args):
            try: keep = int(args[i+1])
            except ValueError: pass
        if a == "-s" and i+1 < len(args):
            try: max_mb = float(args[i+1])
            except ValueError: pass
    if not path.exists():
        print_error(f"Plik nie istnieje: '{path}'"); return
    size_mb = path.stat().st_size / (1024*1024)
    if max_mb > 0 and size_mb < max_mb:
        print_info(f"Rozmiar {size_mb:.2f} MB < limit {max_mb} MB — pominieto"); return
    try:
        for i in range(keep-1, 0, -1):
            old = path.with_suffix(path.suffix+f".{i}")
            new = path.with_suffix(path.suffix+f".{i+1}")
            if old.exists(): old.rename(new)
        bak = path.with_suffix(path.suffix+".1")
        path.rename(bak)
        path.write_text("", encoding="utf-8")
        print_info(f"Zrotowano: {path}  (kopia: {bak.name},  bylo: {size_mb:.2f} MB)")
        log_info(f"logrotate: {path}")
    except Exception as e:
        smart_error(e, "logrotate", str(path))

@command("logscan", "Skanuj plik logu w poszukiwaniu bledow/wzorcow",
         aliases=["logerr","logfilter"])
def cmd_logscan(args):
    """
    logscan [plik] [wzorzec]   - szukaj wzorca (domyslnie ERROR)
    logscan -l N               - ostatnie N pasujacych linii
    logscan                    - skanuj domyslny ~/.terminalx.log
    """
    paths   = [a for a in args if not a.startswith("-")]
    path    = Path(paths[0]).expanduser() if paths else LOG_FILE
    pattern = paths[1] if len(paths) > 1 else "ERROR"
    limit   = 50
    for i, a in enumerate(args):
        if a == "-l" and i+1 < len(args):
            try: limit = int(args[i+1])
            except ValueError: pass
    if not path.exists():
        print_info(f"Brak pliku logu: {path}"); return
    try:
        regex = re.compile(pattern, re.IGNORECASE)
    except re.error as e:
        print_error(f"Zly wyrazenie regularne: {e}"); return
    try:
        lines = path.read_text(encoding="utf-8", errors="replace").splitlines()
    except Exception as e:
        smart_error(e, "logscan", str(path)); return
    matches = [l for l in lines if regex.search(l)]
    shown   = matches[-limit:]
    w2 = min(terminal_width()-2, 80)
    print(); print(box_top(f"logscan: {path.name}  '{pattern}'  [{len(shown)}/{len(matches)}/{len(lines)}]", width=w2, color=C.ERROR))
    if not shown:
        print(box_row(f"  {C.PATH}Brak dopasowan — log czysty{C.RESET}", width=w2, color=C.ERROR))
    for line in shown:
        colored = regex.sub(lambda m: f"{C.MATCH}{m.group()}{C.RESET}", line)
        print(box_row(f"  {colored}", width=w2, color=C.ERROR))
    print(box_bottom(width=w2, color=C.ERROR)); print()

# NET
#   ping, traceroute, netstat, dns, portscan, wget
#   Systemowy fallback + wbudowana implementacja stdlib

def _net_try_system(cmd: list, timeout: int = 10) -> tuple:
    try:
        r = subprocess.run(cmd, capture_output=True, text=True,
                           timeout=timeout, errors="replace")
        return True, r.stdout + r.stderr
    except FileNotFoundError:
        return False, ""
    except subprocess.TimeoutExpired:
        return False, "[timeout]"
    except Exception as e:
        return False, str(e)

# ── Komenda ssh ───────────────────────────────────────────────────────────────
# Wrapper nad systemowym klientem SSH z zarządzaniem profilami połączeń.
# Nie wymaga paramiko — używa subprocess do wywołania ssh z PATH.
#
#   ssh <user@host>            — połącz (przez systemowe ssh)
#   ssh <user@host> -p <port>  — niestandardowy port
#   ssh save <nazwa> <user@host> [-p port] [-i klucz]  — zapisz profil
#   ssh list                   — lista zapisanych profili
#   ssh connect <nazwa>        — połącz przez zapisany profil
#   ssh remove <nazwa>         — usuń profil
#   ssh keygen [nazwa]         — wygeneruj parę kluczy RSA (ssh-keygen)

_SSH_PROFILES_FILE_NAME = ".terminalx_ssh_profiles.json"

def _ssh_profiles_file() -> Path:
    return _BASE / _SSH_PROFILES_FILE_NAME

def _ssh_load_profiles() -> dict:
    f = _ssh_profiles_file()
    if not f.exists():
        return {}
    try:
        return json.loads(f.read_text(encoding="utf-8"))
    except Exception:
        return {}

def _ssh_save_profiles(profiles: dict):
    try:
        _ssh_profiles_file().write_text(
            json.dumps(profiles, ensure_ascii=False, indent=2), encoding="utf-8"
        )
    except Exception as e:
        print_error(f"Błąd zapisu profili SSH: {e}")

def _ssh_which() -> str | None:
    import shutil as _sh
    return _sh.which("ssh")

@command("ssh", "Połącz z hostem przez SSH lub zarządzaj profilami połączeń",
         aliases=["ssh-connect"],
         flags=["list", "save", "connect", "remove", "keygen"])
def cmd_ssh(args):
    """
    Użycie: ssh <podkomenda|user@host> [opcje]

    Bezpośrednie połączenie:
      ssh user@host               — połącz przez systemowe ssh
      ssh user@host -p 2222       — niestandardowy port
      ssh user@host -i ~/.ssh/id  — niestandardowy klucz

    Zarządzanie profilami:
      ssh list                          — lista zapisanych profili
      ssh save <nazwa> <user@host> [-p port] [-i klucz]  — zapisz profil
      ssh connect <nazwa>               — połącz przez profil
      ssh remove <nazwa>                — usuń profil

    Klucze:
      ssh keygen [nazwa]                — generuj parę kluczy RSA (4096 bit)
    """
    import shutil as _sh

    w = min(terminal_width() - 2, 68)

    if not args:
        print_error("Podaj host lub podkomendę.", "Użycie: ssh user@host  lub  ssh list")
        return

    sub = args[0].lower()

    # ── list ─────────────────────────────────────────────────────────────────
    if sub == "list":
        profiles = _ssh_load_profiles()
        print()
        print(box_top(f"Profile SSH  ({len(profiles)})", width=w, color=C.PROMPT))
        if not profiles:
            print(box_row(f"  {C.DIM}Brak profili. Dodaj: ssh save <nazwa> user@host{C.RESET}",
                          width=w, color=C.PROMPT))
        else:
            for name, prof in profiles.items():
                host  = prof.get("host", "?")
                port  = prof.get("port", "")
                key   = prof.get("key", "")
                extra = f"  port={port}" if port else ""
                extra += f"  key={key}" if key else ""
                row = (f"  {C.BOLD}{name:16}{C.RESET} "
                       f"{C.PATH}{host}{C.RESET}"
                       f"{C.DIM}{extra}{C.RESET}")
                print(box_row(row, width=w, color=C.PROMPT))
        print(box_sep(width=w, color=C.PROMPT))
        print(box_row(f"  {C.DIM}ssh connect <nazwa>  |  ssh save <nazwa> user@host{C.RESET}",
                      width=w, color=C.PROMPT))
        print(box_bottom(width=w, color=C.PROMPT))
        print()
        return

    # ── save ─────────────────────────────────────────────────────────────────
    if sub == "save":
        # ssh save <nazwa> <user@host> [-p port] [-i klucz]
        if len(args) < 3:
            print_error("Użycie: ssh save <nazwa> user@host [-p port] [-i klucz]")
            return
        name = args[1]
        host = args[2]
        rest = args[3:]
        port = ""
        key  = ""
        i = 0
        while i < len(rest):
            if rest[i] == "-p" and i + 1 < len(rest):
                port = rest[i + 1]; i += 2
            elif rest[i] == "-i" and i + 1 < len(rest):
                key = rest[i + 1]; i += 2
            else:
                i += 1
        profiles = _ssh_load_profiles()
        profiles[name] = {"host": host, "port": port, "key": key}
        _ssh_save_profiles(profiles)
        print_info(f"Profil '{name}' zapisany → {host}" + (f":{port}" if port else ""))
        return

    # ── remove ───────────────────────────────────────────────────────────────
    if sub == "remove":
        if len(args) < 2:
            print_error("Podaj nazwę profilu: ssh remove <nazwa>")
            return
        profiles = _ssh_load_profiles()
        name = args[1]
        if name not in profiles:
            print_error(f"Profil '{name}' nie istnieje.", "Sprawdź: ssh list")
            return
        del profiles[name]
        _ssh_save_profiles(profiles)
        print_info(f"Profil '{name}' usunięty.")
        return

    # ── connect (przez profil) ────────────────────────────────────────────────
    if sub == "connect":
        if len(args) < 2:
            print_error("Podaj nazwę profilu: ssh connect <nazwa>")
            return
        profiles = _ssh_load_profiles()
        name = args[1]
        if name not in profiles:
            print_error(f"Profil '{name}' nie istnieje.", "Sprawdź: ssh list")
            return
        prof = profiles[name]
        host = prof.get("host", "")
        port = prof.get("port", "")
        key  = prof.get("key", "")
        cmd_args_build = [host]
        if port:
            cmd_args_build += ["-p", port]
        if key:
            cmd_args_build += ["-i", key]
        # Przekieruj do bezpośredniego połączenia
        cmd_ssh(cmd_args_build)
        return

    # ── keygen ───────────────────────────────────────────────────────────────
    if sub == "keygen":
        kg = _sh.which("ssh-keygen")
        if not kg:
            print_error("ssh-keygen nie znaleziono w PATH.")
            return
        key_name = args[1] if len(args) > 1 else "id_rsa_polsoft"
        key_path = Path.home() / ".ssh" / key_name
        key_path.parent.mkdir(mode=0o700, exist_ok=True)
        print_info(f"Generuję klucz RSA 4096-bit: {key_path}")
        subprocess.run([
            kg, "-t", "rsa", "-b", "4096",
            "-f", str(key_path),
            "-C", f"polsoft@{sys.platform}",
        ])
        if key_path.exists():
            print_info(f"Klucz publiczny: {key_path}.pub")
            print(f"  {C.DIM}Skopiuj na serwer: ssh-copy-id -i {key_path}.pub user@host{C.RESET}")
        return

    # ── bezpośrednie połączenie: ssh user@host [-p port] [-i klucz] ──────────
    ssh_bin = _ssh_which()
    if not ssh_bin:
        print_error(
            "Systemowe 'ssh' nie znaleziono w PATH.",
            "Zainstaluj: OpenSSH (Linux: openssh-client, Windows: opcja systemowa)"
        )
        return

    # Pierwszy argument = user@host (lub sam host)
    target = args[0]
    extra_flags = args[1:]   # -p, -i, etc.

    print_info(f"Łączę: {target}" + (f"  {' '.join(extra_flags)}" if extra_flags else ""))
    try:
        subprocess.run([ssh_bin, target] + extra_flags)
    except KeyboardInterrupt:
        print(f"\n  {C.DIM}Połączenie SSH przerwane.{C.RESET}")
    except Exception as e:
        print_error(f"Błąd SSH: {e}")

@command("ping", "Testuj polaczenie (systemowe lub TCP fallback)", flags=["-c","-t"])
def cmd_ping(args):
    """
    ping <host>       - 4 probki
    ping -c N <host>  - N probek
    ping -t <host>    - tylko TCP connect test
    """
    import time as _time
    force_tcp = "-t" in args
    count = 4
    for i, a in enumerate(args):
        if a == "-c" and i+1 < len(args):
            try: count = int(args[i+1])
            except ValueError: pass
    hosts = [a for a in args if not a.startswith("-") and not a.isdigit()]
    if not hosts:
        print_error("Podaj adres hosta","Uzycie: ping [-c N] <host>"); return
    host = hosts[0]
    print(f"\n{C.INFO}Pinguje:{C.RESET} {host}\n")
    if not force_tcp:
        cmd = (["ping","-n",str(count),host] if os.name=="nt" else ["ping","-c",str(count),host])
        ok, out = _net_try_system(cmd, timeout=count*3+5)
        if ok and out and "unreachable" not in out.lower()[:100]:
            print(out); return
    # TCP connect fallback
    try: ip = _socket.gethostbyname(host)
    except _socket.gaierror as e:
        print_error(f"Nie mozna rozwiazac '{host}': {e}"); return
    print(f"PING {host} ({ip})  [TCP connect port 80]")
    for seq in range(count):
        start = _time.monotonic()
        try:
            s = _socket.socket(_socket.AF_INET, _socket.SOCK_STREAM)
            s.settimeout(2); err = s.connect_ex((ip, 80)); s.close()
            ms = (_time.monotonic()-start)*1000
            ok_str = f"{C.PATH}czas={ms:.1f}ms{C.RESET}" if err in (0,111) else f"{C.DIM}timeout{C.RESET}"
            print(f"  Od {ip}: seq={seq+1}  {ok_str}")
        except Exception: print(f"  Od {ip}: seq={seq+1}  {C.DIM}blad{C.RESET}")
        _time.sleep(0.3)
    print()

@command("traceroute", "Trasa pakietow do hosta", aliases=["tracert","trace"])
def cmd_traceroute(args):
    """traceroute <host>  — systemowy traceroute/tracert lub DNS fallback"""
    hosts = [a for a in args if not a.startswith("-")]
    if not hosts:
        print_error("Podaj adres hosta","Uzycie: traceroute <host>"); return
    host = hosts[0]
    print(f"\n{C.INFO}Traceroute:{C.RESET} {host}\n")
    cmd = (["tracert","-h","20",host] if os.name=="nt" else ["traceroute","-m","20",host])
    ok, out = _net_try_system(cmd, timeout=60)
    if ok and out.strip():
        print(out); return
    print(f"{C.DIM}[systemowy traceroute niedostepny — DNS fallback]{C.RESET}\n")
    try:
        ip = _socket.gethostbyname(host)
        print(f"  Hostname : {host}\n  IP       : {ip}")
        try:
            rev = _socket.gethostbyaddr(ip)[0]
            print(f"  Reverse  : {rev}")
        except Exception:
            pass  # ignorowane celowo
        try:
            s = _socket.socket(_socket.AF_INET, _socket.SOCK_DGRAM)
            s.connect((ip, 80)); local = s.getsockname()[0]; s.close()
            print(f"  Lokalne IP: {local}")
        except Exception:
            pass  # ignorowane celowo
    except _socket.gaierror as e:
        print_error(f"DNS: nie mozna rozwiazac '{host}': {e}")
    print()

@command("netstat", "Statystyki sieci i aktywne polaczenia",
         aliases=["nstat","connections"], flags=["-l","-a"])
def cmd_netstat(args):
    """
    netstat     - aktywne polaczenia TCP
    netstat -l  - tylko nasluchujace
    netstat -a  - wszystkie
    """
    show_listen = "-l" in args
    show_all    = "-a" in args
    print(f"\n{C.INFO}Statystyki sieci{C.RESET}\n")
    for cmd in [["ss","-tulpn"],["netstat","-tulpn"],["netstat","-an"],["ss","-an"]]:
        ok, out = _net_try_system(cmd, timeout=5)
        if ok and out.strip():
            print(out[:4000]); return
    if os.name == "nt":
        print_info("Sprobuj: netstat -an w cmd.exe"); return
    def _parse(path):
        entries = []
        for line in _read_proc(path).splitlines()[1:]:
            parts = line.split()
            if len(parts) < 4: continue
            def _hex(h):
                try:
                    addr, port = h.split(":")
                    ip = _socket.inet_ntoa(bytes.fromhex(addr)[::-1])
                    return f"{ip}:{int(port,16)}"
                except Exception: return h
            state_map = {"01":"ESTABLISHED","02":"SYN_SENT","0A":"LISTEN",
                         "06":"TIME_WAIT","08":"CLOSE_WAIT","00":"FREE"}
            entries.append((_hex(parts[1]), _hex(parts[2]),
                            state_map.get(parts[3].upper(), parts[3])))
        return entries
    all_e = _parse("/proc/net/tcp") + _parse("/proc/net/tcp6")
    if show_listen: all_e = [(l,r,s) for l,r,s in all_e if s=="LISTEN"]
    elif not show_all: all_e = [(l,r,s) for l,r,s in all_e if s in ("ESTABLISHED","LISTEN","SYN_SENT")]
    w2 = min(terminal_width()-2, 76)
    print(box_top(f"Polaczenia TCP  ({len(all_e)})", width=w2, color=C.EXEC))
    print(box_row(f"  {C.BOLD}{'Lokalny':<25}{'Zdalny':<25}{'Stan'}{C.RESET}", width=w2, color=C.EXEC))
    print(box_sep(width=w2, color=C.EXEC))
    for local, remote, state in all_e[:40]:
        sc = C.PATH if state=="ESTABLISHED" else (C.INFO if state=="LISTEN" else C.DIM)
        print(box_row(f"  {C.DIM}{local:<25}{remote:<25}{C.RESET}{sc}{state}{C.RESET}", width=w2, color=C.EXEC))
    if len(all_e) > 40:
        print(box_row(f"  ...i {len(all_e)-40} wiecej (-a)", width=w2, color=C.EXEC))
    print(box_bottom(width=w2, color=C.EXEC)); print()

@command("wget", "Pobierz plik z URL (stdlib urllib)",
         aliases=["fetch","download"], flags=["-o","-q"])
def cmd_wget(args):
    """
    wget <url>           - pobierz do biezacego katalogu
    wget <url> -o <plik> - zapisz pod podana nazwa
    wget -q <url>        - cichy tryb
    """
    import urllib.request, urllib.error, time as _time
    quiet = "-q" in args
    urls  = [a for a in args if not a.startswith("-")]
    out_name = None
    for i, a in enumerate(args):
        if a == "-o" and i+1 < len(args): out_name = args[i+1]
    if not urls:
        print_error("Podaj URL","Uzycie: wget <url> [-o <plik>]"); return
    url = urls[0]
    # Sprawdz tryb offline — wget wymaga dostepu do sieci
    if not is_online():
        print_error(
            "Pobieranie niedostepne — shell dziala w trybie offline.",
            "Uruchom 'mode online' aby wlaczyc dostep do sieci.")
        return
    filename = out_name or url.split("/")[-1].split("?")[0] or "pobrany_plik"
    dest = Path(filename)
    print_info(f"Pobieranie: {url}\n→ {dest}")
    try:
        req = _get_urllib_request().Request(url, headers={"User-Agent":f"TerminalX/{SHELL_VERSION}"})
        start = _time.monotonic()
        with _get_urllib_request().urlopen(req, timeout=30) as resp:
            total = int(resp.headers.get("Content-Length", 0))
            downloaded = 0
            with dest.open("wb") as f:
                while True:
                    chunk = resp.read(8192)
                    if not chunk: break
                    f.write(chunk); downloaded += len(chunk)
                    if not quiet and total:
                        pct = downloaded/total*100
                        print(f"\r  {_bar(pct, 25)}  {_human_size(downloaded)}/{_human_size(total)} ",
                              end="", flush=True)
        elapsed = _time.monotonic() - start
        if not quiet: print()
        speed = _human_size(int(downloaded/max(elapsed,0.01)))+"/s"
        print_ok(f"Zapisano: {dest}  ({_human_size(dest.stat().st_size)})  {speed}")
        log_info(f"wget: {url} -> {dest}")
    except _get_urllib_error().URLError as e:
        print_error(f"Blad pobierania: {e.reason}","Sprawdz URL i polaczenie sieciowe")
    except Exception as e:
        smart_error(e, "wget", url)

