@command("pathping", "Laczone ping + traceroute (Windows pathping / mtr Linux)",
         aliases=["mtr"])
def cmd_pathping(args):
    """
    pathping <host>   — analiza trasy z utratą pakietów (Windows)
    mtr <host>        — odpowiednik na Linux/macOS
    """
    if not args:
        print_error("Podaj adres hosta", "Uzycie: pathping <host>")
        return
    host = args[0]
    print(f"\n{C.INFO}PathPing / MTR:{C.RESET} {host}\n")
    if is_windows():
        r = subprocess.run(["pathping", host], capture_output=True, text=True, timeout=120)
        print(r.stdout)
    else:
        mtr = shutil.which("mtr")
        if mtr:
            subprocess.run([mtr, "--report", "--report-cycles", "3", host], timeout=60)
        else:
            # Fallback: traceroute
            r = subprocess.run(
                ["traceroute", "-m", "20", host], capture_output=True, text=True, timeout=60
            )
            print(r.stdout or "mtr i traceroute niedostepne")

@command("sfc", "Skan plikow systemowych (Windows sfc / Linux debsums/rpm-verify)",
         aliases=["scannow"])
def cmd_sfc(args):
    """
    sfc /scannow    — skanuj i napraw pliki systemowe (Windows, wymaga admina)
    (Linux: debsums -c / rpm -Va w zależności od dystrybucji)
    """
    if is_windows():
        print(f"  {C.INFO}Uruchamianie sfc /scannow...{C.RESET}")
