@command("format", "Formatowanie dysku / partycji",
         aliases=["fmt-disk"])
def cmd_format(args):
    """
    format <litera>: /fs:ntfs /q   — szybkie formatowanie (Windows)
    format /fs:fat32 <litera>:     — formatuj jako FAT32
    (Linux/macOS: mkfs.ext4 / mkfs.fat)
    """
    if not args:
        print_error("Podaj dysk do formatowania", "Uzycie: format <dysk> [/fs:ntfs|fat32] [/q]")
        return

    print(f"\n  {C.ERROR}⚠ OSTRZEŻENIE: Formatowanie nieodwracalnie usuwa dane!{C.RESET}\n")
    try:
        confirm = input("  Wpisz FORMATUJ aby potwierdzić: ").strip()
    except (EOFError, KeyboardInterrupt):
        print("\n  Anulowano."); return
    if confirm != "FORMATUJ":
        print(f"  {C.DIM}Anulowano.{C.RESET}"); return

    if is_windows():
        r = subprocess.run(["format"] + args, capture_output=True, text=True, timeout=300)
        print(r.stdout)
        if r.returncode != 0: print_error(r.stderr.strip())
        return

    # Linux
    device = args[0]
    fs_type = "ext4"
    for a in args:
        if a.lower().startswith("/fs:"):
            fs_type = a[4:].lower()

    mkfs_map = {"ntfs": "mkntfs", "fat32": "mkfs.fat", "fat": "mkfs.fat",
                "ext4": "mkfs.ext4", "ext3": "mkfs.ext3", "btrfs": "mkfs.btrfs"}
    mkfs_bin = shutil.which(mkfs_map.get(fs_type, f"mkfs.{fs_type}"))
    if mkfs_bin:
        r = subprocess.run([mkfs_bin, device], capture_output=True, text=True, timeout=300)
        print(r.stdout)
        if r.returncode != 0: print_error(r.stderr.strip())
    else:
        print_error(f"Nie znaleziono mkfs dla {fs_type}")

@command("cipher", "Szyfrowanie EFS (Windows) / bezpieczne czyszczenie wolnego miejsca",
         aliases=["efs"])
def cmd_cipher(args):
    """
    cipher /w:C:/       — bezpieczne czyszczenie wolnego miejsca na C:
    cipher /e <plik>    — zaszyfruj (EFS)
    cipher /d <plik>    — odszyfruj (EFS)
    cipher /c <plik>    — pokaż info o szyfrowaniu
    (Linux/macOS: shred / wipe)
    """
    if is_windows():
        r = subprocess.run(["cipher"] + args, capture_output=True, text=True, timeout=300)
        print(r.stdout)
        if r.returncode != 0: print_error(r.stderr.strip())
        return

    # Linux/macOS
    if "/w" in args or "-w" in args:
        # Bezpieczne czyszczenie wolnego miejsca
        path_idx = next((i+1 for i, a in enumerate(args) if a in ("/w","-w")), -1)
        target = args[path_idx] if path_idx > 0 and path_idx < len(args) else "."
        print(f"  {C.INFO}Bezpieczne czyszczenie wolnego miejsca:{C.RESET} {target}")
        shred_bin = shutil.which("shred") or shutil.which("wipe")
        if shred_bin:
            tmpf = Path(target) / ".cipher_wipe_tmp"
            try:
                r = subprocess.run(
                    [shred_bin, "-vfz", "-n", "3", str(tmpf)] if "shred" in shred_bin
                    else [shred_bin, str(tmpf)],
                    capture_output=True, text=True, timeout=300
                )
                print(r.stdout[:1000])
            finally:
                tmpf.unlink(missing_ok=True)
        else:
            print(f"  {C.DIM}Uzyj: shred -vfz -n 3 <plik>  lub  wipe <plik>{C.RESET}")
    else:
        print(f"  {C.DIM}cipher: szyfrowanie EFS dostepne tylko na Windows{C.RESET}")
        print(f"  Linux: gpg --encrypt <plik>  /  openssl enc -aes-256-cbc -in <plik>{C.RESET}")

@command("clip", "Kopiuj stdin lub plik do schowka systemowego",
         aliases=["clipboard", "pbcopy", "xclip"])
def cmd_clip(args):
    """
    echo "tekst" | clip         — kopiuj z pipe do schowka
    clip < plik.txt              — kopiuj zawartość pliku
    clip <plik>                  — kopiuj plik
    clip --paste                 — wklej ze schowka (drukuj)
    """
    # Sprawdź dostępne narzędzie schowka
    def _get_clip_tool():
        if is_windows():       return ["clip"], ["powershell","-command","Get-Clipboard"]
        if sys.platform == "darwin": return ["pbcopy"], ["pbpaste"]
        # Linux — xclip lub xsel lub wl-copy (Wayland)
        if shutil.which("xclip"):   return ["xclip","-selection","clipboard"], ["xclip","-selection","clipboard","-o"]
        if shutil.which("xsel"):    return ["xsel","--clipboard","--input"],    ["xsel","--clipboard","--output"]
        if shutil.which("wl-copy"): return ["wl-copy"], ["wl-paste"]
        return None, None

    copy_cmd, paste_cmd = _get_clip_tool()

    if "--paste" in args or "-p" in args:
        if not paste_cmd:
            print_error("Brak narzedzia schowka (xclip/xsel/wl-paste/pbpaste)")
            return
        r = subprocess.run(paste_cmd, capture_output=True, text=True, timeout=5)
        print(r.stdout, end="")
        return

    if not copy_cmd:
        print_error("Brak narzedzia schowka",
                    "Zainstaluj: apt install xclip  lub  apt install xsel")
        return

    # Pobierz dane: z pliku lub stdin
    if args and not args[0].startswith("-"):
        fpath = Path(args[0])
        if fpath.exists():
            data = fpath.read_bytes()
        else:
            print_error(f"Nie znaleziono pliku: '{args[0]}'"); return
    else:
        import select as _sel
        if sys.stdin.isatty():
            print(f"  {C.DIM}Wpisz tekst (Ctrl+D aby zakończyć):{C.RESET}")
        data = sys.stdin.buffer.read()

    r = subprocess.run(copy_cmd, input=data, timeout=5)
    if r.returncode == 0:
        lines = data.count(b"\n")
        size  = len(data)
        print(f"  {C.OK}Skopiowano do schowka:{C.RESET} {size} bajtow, {lines} linii")
    else:
        print_error("Nie mozna skopiowac do schowka")

@command("schtasks", "Harmonogram zadan Windows (schtasks / cron Linux)",
         aliases=["scheduled-tasks"], flags=["/query","/create","/delete","/run","/end"])
def cmd_schtasks(args):
    """
    schtasks /query                              — lista zadań
    schtasks /query /tn <nazwa>                  — konkretne zadanie
    schtasks /create /tn <nazwa> /tr <cmd> /sc daily /st 12:00
    schtasks /delete /tn <nazwa> /f             — usuń zadanie
    schtasks /run /tn <nazwa>                   — uruchom teraz
    (Linux/macOS: crontab / at)
    """
    if is_windows():
        r = subprocess.run(["schtasks"] + args, capture_output=True, text=True, timeout=30)
        print(r.stdout)
        if r.returncode != 0: print_error(r.stderr.strip())
        return

    # Linux/macOS — crontab
    if not args or (len(args) == 1 and args[0].upper() == "/QUERY"):
        cron = shutil.which("crontab")
        if cron:
            r = subprocess.run([cron, "-l"], capture_output=True, text=True)
            if r.returncode == 0 and r.stdout.strip():
                print(f"\n  {C.BOLD}Zaplanowane zadania (crontab):{C.RESET}\n")
                print(r.stdout)
            else:
                print(f"  {C.DIM}Brak zaplanowanych zadan w crontab{C.RESET}")
        else:
            print_error("crontab niedostepny")
        return

    # Wskazówka dla /create
    if "/create" in [a.upper() for a in args]:
        print(f"\n  {C.INFO}Tworzenie zadan na Linux — crontab:{C.RESET}")
        print(f"  {C.PATH}crontab -e{C.RESET}  — edytuj crontab")
        print(f"\n  Format: MIN GODZ DZIEN MIES DZIEN_TYG komenda")
        print(f"  Przyklad: 0 12 * * * /sciezka/do/komendy")
        print(f"\n  Lub uzyj wbudowanej komendy: {C.PATH}sched{C.RESET}")
    else:
        r = subprocess.run(["crontab"] + args, capture_output=True, text=True)
        print(r.stdout)

@command("fsutil", "Narzedzia systemu plikow (Windows fsutil / stat Linux)",
         aliases=["fileutil"])
def cmd_fsutil(args):
    """
    fsutil file createnew <plik> <rozmiar>   — utwórz plik o podanym rozmiarze
    fsutil volume diskfree <litera>:         — wolne miejsce
    fsutil fsinfo drives                     — lista dysków
    (Linux/macOS: fallocate / dd / df / stat)
    """
    if not args:
        print_error("Podaj podkomende", "Uzycie: fsutil file|volume|fsinfo <opcje>")
        return

    if is_windows():
        r = subprocess.run(["fsutil"] + args, capture_output=True, text=True, timeout=15)
        print(r.stdout)
        if r.returncode != 0: print_error(r.stderr.strip())
        return

    # Linux/macOS — implementacja najczęstszych operacji
    sub = args[0].lower()
    rest = args[1:]

    if sub == "file" and rest and rest[0].lower() == "createnew":
        # fsutil file createnew <plik> <rozmiar>
        if len(rest) < 3:
            print_error("Uzycie: fsutil file createnew <plik> <rozmiar_bajtow>"); return
        fname, size_str = rest[1], rest[2]
        try:
            size = int(size_str)
        except ValueError:
            print_error(f"Nieprawidlowy rozmiar: '{size_str}'"); return
        # fallocate lub dd
        fallocate = shutil.which("fallocate")
        if fallocate:
            r = subprocess.run([fallocate, "-l", str(size), fname],
                               capture_output=True, text=True)
        else:
            r = subprocess.run(
                ["dd", "if=/dev/zero", f"of={fname}", "bs=1", f"count={size}"],
                capture_output=True, text=True
            )
        if r.returncode == 0:
            print(f"  {C.OK}Utworzono plik:{C.RESET} {fname}  ({size} bajtow)")
        else:
            print_error(r.stderr.strip())

    elif sub in ("volume", "fsinfo"):
        # Wolne miejsce / info o systemie plików
        r = subprocess.run(["df", "-h", rest[0] if rest else "/"],
                           capture_output=True, text=True)
        print(r.stdout)
    else:
        print(f"  {C.DIM}fsutil {sub}: brak implementacji na {sys.platform}{C.RESET}")
        print(f"  {C.DIM}Dostepne: file createnew, volume, fsinfo{C.RESET}")

@command("setx", "Trwale ustaw zmienna srodowiskowa (Windows setx / export Linux)",
         aliases=["setenv-perm"])
def cmd_setx(args):
    """
    setx <NAZWA> <wartosc>          — trwała zmienna dla bieżącego użytkownika
    setx <NAZWA> <wartosc> /M       — trwała zmienna systemowa (wymaga admina)
    (Linux/macOS: dodaje do ~/.bashrc lub ~/.zshrc)
    """
    if not args or len(args) < 2:
        print_error("Podaj nazwe i wartosc", "Uzycie: setx <NAZWA> <wartosc> [/M]")
        return

    name  = args[0]
    value = args[1]
    system_wide = "/M" in args or "-M" in args

    if is_windows():
        cmd_args = ["setx", name, value]
        if system_wide: cmd_args.append("/M")
        r = subprocess.run(cmd_args, capture_output=True, text=True)
        if r.returncode == 0:
            print(f"  {C.OK}Ustawiono (trwale): {name} = {value}{C.RESET}")
            print(f"  {C.DIM}(Wymagane ponowne otwarcie terminala){C.RESET}")
        else:
            print_error(r.stderr.strip())
        return

    # Linux/macOS — dodaj do pliku RC
    shell = os.environ.get("SHELL", "")
    if "zsh" in shell:
        rc_file = Path.home() / ".zshrc"
    elif "fish" in shell:
        rc_file = Path.home() / ".config/fish/config.fish"
    else:
        rc_file = Path.home() / ".bashrc"

    export_line = f'\nexport {name}="{value}"  # dodane przez TerminalX setx\n'
    try:
        with rc_file.open("a", encoding="utf-8") as f:
            f.write(export_line)
        # Ustaw też w bieżącej sesji
        os.environ[name] = value
        SHELL_VARS[name]  = value
        print(f"  {C.OK}Ustawiono (trwale):{C.RESET} {name} = {value}")
        print(f"  {C.DIM}Dodano do: {rc_file}{C.RESET}")
        print(f"  {C.DIM}Aktywuj: source {rc_file}{C.RESET}")
    except Exception as e:
        print_error(f"Nie mozna zapisac do {rc_file}: {e}")

@command("start", "Uruchom program lub plik w nowym oknie / procesie",
         aliases=["launch", "open"], flags=["--wait", "--min", "--max"])
def cmd_start(args):
    """
    start <plik|program>      — otwórz plik lub program
    start http://...          — otwórz URL w przeglądarce
    start <plik.txt>          — otwórz w domyślnej aplikacji
    start --wait <program>    — czekaj na zakończenie
    (Windows: start, Linux: xdg-open, macOS: open)
    """
    if not args:
        print_error("Podaj plik lub program do uruchomienia")
        return

    wait   = "--wait" in args
    target_args = [a for a in args if not a.startswith("--")]
    if not target_args:
        print_error("Podaj plik lub komende"); return
    target = target_args[0]
    rest   = target_args[1:]

    if is_windows():
        cmd_list = ["start"]
        if wait: cmd_list.append("/wait")
        cmd_list += [target] + rest
        subprocess.run(cmd_list, shell=True)
        return

    # Linux/macOS
    if target.startswith(("http://", "https://", "www.")):
        import webbrowser as _wb
        _wb.open(target)
        print(f"  {C.OK}Otwarto w przegladarce:{C.RESET} {target}")
        return

    opener = "open" if sys.platform == "darwin" else (shutil.which("xdg-open") or "")
    if opener:
        if wait:
            subprocess.run([opener, target])
        else:
            subprocess.Popen([opener, target],
                             stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL)
        print(f"  {C.OK}Uruchomiono:{C.RESET} {target}")
    else:
        # Ostatnia opcja: uruchom jako subprocess
        try:
            if wait:
                subprocess.run([target] + rest)
            else:
                subprocess.Popen([target] + rest,
                                 stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL)
            print(f"  {C.OK}Uruchomiono:{C.RESET} {target}")
        except FileNotFoundError:
            print_error(f"Nie znaleziono: '{target}'")

@command("call", "Wywolaj plik wsadowy / skrypt shella",
         aliases=["batch", "run-script"])
def cmd_call(args):
    """
    call <plik.bat>           — uruchom skrypt wsadowy (Windows)
    call <plik.sh>            — uruchom skrypt bash (Linux/macOS)
    call <plik.msh>           — uruchom skrypt TerminalXa (source)
    """
    if not args:
        print_error("Podaj plik do uruchomienia", "Uzycie: call <plik.bat|.sh|.msh>")
        return

    fpath = Path(args[0]).expanduser()
    if not fpath.exists():
        print_error(f"Nie znaleziono pliku: '{fpath}'"); return

    ext = fpath.suffix.lower()

    # Pliki TerminalXa — użyj source
    if ext in (".msh", ".mini", ".rc"):
        return cmd_source(args)

    if is_windows() and ext in (".bat", ".cmd"):
        subprocess.run(["cmd", "/c", str(fpath)] + args[1:])
        return

    if ext == ".bat" and not is_windows():
        print_warn(f"Plik .bat '{fpath.name}' — uruchamianie przez wine (jesli dostepne)")
        wine = shutil.which("wine")
        if wine:
            subprocess.run([wine, "cmd", "/c", str(fpath)] + args[1:])
        else:
            print_error("wine niedostepny", "Zainstaluj wine lub uzyj pliku .sh")
        return

    # .sh lub inne — uruchom przez shell
    if ext in (".sh", ".bash", ".zsh"):
        shell_bin = shutil.which("bash") or shutil.which("sh") or "/bin/sh"
        subprocess.run([shell_bin, str(fpath)] + args[1:])
        return

    # Domyślnie — spróbuj wykonać bezpośrednio
    try:
        subprocess.run([str(fpath)] + args[1:])
    except PermissionError:
        # Dodaj bit wykonywalności i spróbuj ponownie
        fpath.chmod(fpath.stat().st_mode | 0o111)
        subprocess.run([str(fpath)] + args[1:])
    except Exception as e:
        print_error(f"Nie mozna uruchomic '{fpath}': {e}")

@command("eventvwr", "Podglad zdarzen systemowych (Windows Event Viewer / journalctl Linux)",
         aliases=["eventlog", "events"])
def cmd_eventvwr(args):
    """
    eventvwr              — otwórz Event Viewer (Windows GUI) lub journalctl
    eventvwr --list       — ostatnie 20 zdarzeń
    eventvwr --errors     — tylko błędy i ostrzeżenia
    eventvwr -n <liczba>  — ostatnie N zdarzeń
    """
    if is_windows() and not args:
        subprocess.Popen(["eventvwr.msc"], shell=True)
        print(f"  {C.OK}Uruchomiono Event Viewer{C.RESET}")
        return

    if is_windows():
        # PowerShell Get-EventLog
        count = "20"
        errors_only = "--errors" in args
        for i, a in enumerate(args):
            if a == "-n" and i+1 < len(args): count = args[i+1]
        ps_cmd = (
            f"Get-EventLog -LogName System -Newest {count}"
            + (" -EntryType Error,Warning" if errors_only else "")
            + " | Format-Table -AutoSize"
        )
        r = subprocess.run(["powershell", "-command", ps_cmd],
                           capture_output=True, text=True, timeout=30)
        print(r.stdout[:4000])
        return

    # Linux — journalctl
    jctl = shutil.which("journalctl")
    if jctl:
        count = "20"
        errors_only = "--errors" in args
        for i, a in enumerate(args):
            if a == "-n" and i+1 < len(args): count = args[i+1]
        cmd_args = [jctl, "-n", count, "--no-pager"]
        if errors_only:
            cmd_args += ["-p", "err"]
        r = subprocess.run(cmd_args, capture_output=True, text=True, timeout=15)
        print(r.stdout[:4000])
    else:
        # Fallback: /var/log/syslog lub /var/log/messages
        for logfile in ["/var/log/syslog", "/var/log/messages", "/var/log/system.log"]:
            lp = Path(logfile)
            if lp.exists():
                lines = lp.read_text(errors="replace").splitlines()[-20:]
                print(f"\n  {C.BOLD}Ostatnie zdarzenia ({logfile}):{C.RESET}\n")
                for l in lines: print(f"  {l}")
                print()
                return
        print(f"  {C.DIM}Brak dostepnych logow systemowych{C.RESET}")

@command("perfmon", "Monitor wydajnosci (Windows perfmon / vmstat-top Linux)",
         aliases=["perf", "performance"])
def cmd_perfmon(args):
    """
    perfmon      — otwórz Performance Monitor (Windows GUI) lub vmstat (Linux)
    perfmon -l   — bieżące liczniki (CPU/RAM/Dysk)
    """
    if is_windows() and not args:
        subprocess.Popen(["perfmon.msc"], shell=True)
        print(f"  {C.OK}Uruchomiono Performance Monitor{C.RESET}")
        return

    if is_windows():
        ps_cmd = (
            "Get-Counter '\\Processor(_Total)\\% Processor Time',"
            "'\\Memory\\Available MBytes',"
            "'\\PhysicalDisk(_Total)\\Disk Reads/sec',"
            "'\\PhysicalDisk(_Total)\\Disk Writes/sec'"
            " | Select-Object -ExpandProperty CounterSamples | Format-Table -AutoSize"
        )
        r = subprocess.run(["powershell", "-command", ps_cmd],
                           capture_output=True, text=True, timeout=15)
        print(r.stdout)
        return

    # Linux/macOS — vmstat + wolne miejsce
    print(f"\n{C.BOLD}  Monitor wydajnosci:{C.RESET}\n")
    vmstat = shutil.which("vmstat")
    if vmstat:
        r = subprocess.run([vmstat, "1", "3"], capture_output=True, text=True, timeout=10)
        print(f"  {C.BOLD}vmstat:{C.RESET}")
        print(r.stdout)

    # Uptime + load
    uptime_f = Path("/proc/uptime")
    if uptime_f.exists():
        loadavg = Path("/proc/loadavg").read_text().split()[:3]
        print(f"  {C.BOLD}Load average:{C.RESET}  {' '.join(loadavg)}  (1/5/15 min)")

    # Skieruj do procmon
    print(f"\n  {C.DIM}Tip: uzyj 'procmon' dla interaktywnego TUI monitora procesow{C.RESET}")

@command("resmon", "Monitor zasobow (Windows resmon / htop Linux)",
         aliases=["resource-monitor"])
def cmd_resmon(args):
    """
    resmon   — otwórz Resource Monitor (Windows GUI) lub htop/top (Linux)
    """
    if is_windows():
        subprocess.Popen(["resmon.exe"], shell=True)
        print(f"  {C.OK}Uruchomiono Resource Monitor{C.RESET}")
        return

    # Linux/macOS — htop lub top
    htop = shutil.which("htop")
    top  = shutil.which("top")
    if htop:
        subprocess.run([htop])
    elif top:
        subprocess.run([top])
    else:
        # Fallback: wbudowany procmon
        print(f"  {C.DIM}htop/top niedostepne — uruchamiam procmon{C.RESET}")
        dispatch("procmon", [])

@command("dxdiag", "Diagnostyka DirectX (Windows) / info OpenGL/GPU Linux",
         aliases=["gpu-info", "directx"])
def cmd_dxdiag(args):
    """
    dxdiag         — uruchom DirectX Diagnostic Tool (Windows GUI)
    dxdiag /t plik — zapisz raport do pliku tekstowego
    (Linux/macOS: glxinfo / nvidia-smi / lspci)
    """
    if is_windows():
        if args:
            r = subprocess.run(["dxdiag"] + args, capture_output=True, text=True, timeout=60)
            print(r.stdout[:5000])
        else:
            subprocess.Popen(["dxdiag"], shell=True)
            print(f"  {C.OK}Uruchomiono DxDiag{C.RESET}")
        return

    # Linux/macOS — zbierz info o GPU
    print(f"\n{C.BOLD}  {'─'*52}{C.RESET}")
    print(f"  {C.INFO}Informacje o GPU / grafice:{C.RESET}")
    print(f"{C.BOLD}  {'─'*52}{C.RESET}\n")

    # nvidia-smi
    nvidia = shutil.which("nvidia-smi")
    if nvidia:
        r = subprocess.run([nvidia, "--query-gpu=name,memory.total,driver_version",
                            "--format=csv,noheader"], capture_output=True, text=True)
        if r.returncode == 0:
            print(f"  {C.BOLD}NVIDIA GPU:{C.RESET} {r.stdout.strip()}")

    # lspci
    lspci = shutil.which("lspci")
    if lspci:
        r = subprocess.run([lspci], capture_output=True, text=True)
        gpu_lines = [l for l in r.stdout.splitlines()
                     if any(k in l.lower() for k in ("vga","display","3d","gpu"))]
        for l in gpu_lines[:5]:
            print(f"  {C.PATH}{l}{C.RESET}")

    # glxinfo
    glx = shutil.which("glxinfo")
    if glx:
        r = subprocess.run([glx, "-B"], capture_output=True, text=True, timeout=10)
        for l in r.stdout.splitlines()[:10]:
            if any(k in l.lower() for k in ("renderer","vendor","version","opengl")):
                print(f"  {l}")

    if not nvidia and not lspci and not glx:
        import platform as _plt
        print(f"  {C.DIM}Brak narzedzi diagnostyki GPU (lspci/glxinfo/nvidia-smi){C.RESET}")
        print(f"  System: {_plt.system()} {_plt.machine()}")
    print()

@command("for-loop", "Petla FOR w TerminalXu (odpowiednik FOR w CMD)",
         aliases=["for", "loop"])
def cmd_for_loop(args):
    """
    for-loop range 1 10 "echo {i}"       — zakres liczb (1..10)
    for-loop range 1 10 2 "echo {i}"     — z krokiem
    for-loop files *.py "echo {f}"       — pliki pasujące do wzorca
    for-loop lines plik.txt "echo {l}"   — linie z pliku
    for-loop args a b c "echo {x}"       — lista wartości
    {i} / {f} / {l} / {x} — zmienna iteracji w komendzie
    """
    if not args or len(args) < 2:
        print(f"  Uzycie: for-loop <range|files|lines|args> <parametry> \"komenda\"")
        print(f"  Przyklady:")
        print(f"    for-loop range 1 5 \"echo {'{i}'}\"")
        print(f"    for-loop files *.txt \"cat {'{f}'}\"")
        print(f"    for-loop lines lista.txt \"echo {'{l}'}\"")
        return

    mode = args[0].lower()
    # Ostatni arg to komenda z {} placeholder
    cmd_template = args[-1]
    mid = args[1:-1]

    iterations = []

    if mode == "range":
        try:
            if len(mid) == 2:
                start, end = int(mid[0]), int(mid[1])
                step = 1
            elif len(mid) == 3:
                start, end, step = int(mid[0]), int(mid[1]), int(mid[2])
            else:
                print_error("range wymaga: start end [krok]"); return
            iterations = list(range(start, end + 1, step))
            var = "i"
        except ValueError as e:
            print_error(f"Bledne liczby: {e}"); return

    elif mode == "files":
        pattern = mid[0] if mid else "*"
        iterations = [str(p) for p in Path(".").glob(pattern)]
        var = "f"

    elif mode == "lines":
        if not mid:
            print_error("Podaj plik: for-loop lines <plik> \"komenda\""); return
        fpath = Path(mid[0])
        if not fpath.exists():
            print_error(f"Nie znaleziono: '{mid[0]}'"); return
        iterations = [l.strip() for l in fpath.read_text(encoding="utf-8",
                      errors="replace").splitlines() if l.strip()]
        var = "l"

    elif mode == "args":
        iterations = list(mid)
        var = "x"

    else:
        print_error(f"Nieznany tryb: '{mode}'", "Dostepne: range, files, lines, args")
        return

    if not iterations:
        print(f"  {C.DIM}Brak elementow do przetworzenia{C.RESET}")
        return

    print(f"  {C.DIM}for-loop [{mode}]: {len(iterations)} iteracji{C.RESET}\n")
    errors = 0
    for item in iterations:
        cmd_str = cmd_template.replace(f"{{{var}}}", str(item))
        # Zastąp też generyczne {0}
        cmd_str = cmd_str.replace("{0}", str(item))
        try:
            code, _ = _run_single_cmd(cmd_str)
            if code != 0:
                errors += 1
        except Exception as e:
            print_warn(f"Blad iteracji '{item}': {e}")
            errors += 1

    print(f"\n  {C.DIM}Zakonczono: {len(iterations)} iteracji"
          + (f", {errors} bledow" if errors else "") + f"{C.RESET}")

# ── Alias: 'for' jako skrót do for-loop ──────────────────────────────────────
# (zarejestrowane przez aliases=["for"] w dekoratorze powyżej)

# ██ BRAKUJĄCE KOMENDY — DODANE v30.1 ████████████████████████
# clear, cls, which, where, date, rename/ren, curl, kill, ps,
# chmod, chown, pip, free, df, uname, uptime, hostname, id

@command("clear", "Wyczysc ekran terminala", aliases=["cls"])
def cmd_clear(args):
    """clear / cls  — czyści ekran terminala"""
    clear_screen()

@command("which", "Znajdz sciezke programu w PATH", aliases=["where"])
def cmd_which(args):
    """
    which <program>   — znajdź program w PATH (Linux/macOS)
    where <program>   — znajdź program w PATH (Windows)
    """
    if not args:
        print_error("Podaj nazwe programu", "Uzycie: which <program>")
        return
    found_any = False
    for prog in args:
        path = shutil.which(prog)
        if path:
            print(f"{C.PATH}{path}{C.RESET}")
            found_any = True
        else:
            print(f"{C.ERROR}Nie znaleziono:{C.RESET} {prog}")
    if not found_any:
        _LAST_EXIT if False else None  # suppress

@command("date", "Wyswietl lub ustaw date i czas systemowy", aliases=["time"])
def cmd_date(args):
    """
    date              — bieżąca data i czas
    date +FORMAT      — własny format (np. date +%Y-%m-%d)
    date --utc        — czas UTC
    """
    use_utc = "--utc" in args or "-u" in args
    fmt_arg = next((a for a in args if a.startswith("+")), None)

    now = datetime.datetime.utcnow() if use_utc else datetime.datetime.now()
    tz_label = "UTC" if use_utc else "LCL"

    if fmt_arg:
        # Konwertuj format strftime-style (+ poprzedza token)
        fmt = fmt_arg[1:]  # usuń '+'
        # Proste mapowanie tokenów uniksowych → Python strftime
        _map = {
            "%Y": now.strftime("%Y"), "%m": now.strftime("%m"),
            "%d": now.strftime("%d"), "%H": now.strftime("%H"),
            "%M": now.strftime("%M"), "%S": now.strftime("%S"),
            "%A": now.strftime("%A"), "%a": now.strftime("%a"),
            "%B": now.strftime("%B"), "%b": now.strftime("%b"),
            "%j": now.strftime("%j"), "%Z": tz_label,
        }
        result = fmt
        for token, val in _map.items():
            result = result.replace(token, val)
        print(result)
    else:
        weekday = now.strftime("%A")
        print(f"\n  {C.BOLD}{weekday}{C.RESET}  "
              f"{C.INFO}{now.strftime('%Y-%m-%d')}{C.RESET}  "
              f"{C.PATH}{now.strftime('%H:%M:%S')}{C.RESET}  "
              f"{C.DIM}[{tz_label}]{C.RESET}\n")

@command("rename", "Zmien nazwe pliku lub katalogu", aliases=["ren"])
def cmd_rename(args):
    """
    rename <stara_nazwa> <nowa_nazwa>
    ren    <stara_nazwa> <nowa_nazwa>
    Obsługuje wzorce (* i ?) dla zbiorczej zmiany nazw.
    """
    if len(args) < 2:
        print_error("Podaj stara i nowa nazwe", "Uzycie: rename <stara> <nowa>")
        return
    src_pat, dst = args[0], args[1]
    # Zbiorczy rename z wildcard
    matches = list(Path(".").glob(src_pat)) if any(c in src_pat for c in "*?") else []
    if matches:
        renamed = 0
        for p in matches:
            # Prosta zamiana: jeśli dst zawiera *, zastąp część
            new_name = dst.replace("*", p.stem) if "*" in dst else dst
            target = p.parent / new_name
            try:
                p.rename(target)
                print(f"  {C.OK}OK{C.RESET}  {p.name}  →  {target.name}")
                renamed += 1
            except Exception as e:
                print_error(f"Nie mozna zmienic '{p.name}': {e}")
        print(f"\n{C.DIM}Zmieniono nazwy: {renamed} plik(ow){C.RESET}\n")
    else:
        src = Path(src_pat)
        if not src.exists():
            print_error(f"Nie znaleziono: '{src_pat}'"); return
        target = src.parent / dst
        try:
            src.rename(target)
            print(f"  {C.OK}OK{C.RESET}  {src_pat}  →  {dst}")
        except Exception as e:
            print_error(f"Nie mozna zmienic nazwy: {e}")

@command("curl", "Pobierz lub wysylaj dane HTTP/HTTPS (stdlib urllib)",
         aliases=["fetch-url"], flags=["-o", "-X", "-H", "-d", "-I", "-s", "-v"])
def cmd_curl(args):
    """
    curl <url>                    — wyświetl odpowiedź
    curl -o <plik> <url>          — zapisz do pliku
    curl -X POST -d <dane> <url>  — wyślij POST
    curl -H "Header: val" <url>   — dodaj nagłówek
    curl -I <url>                 — tylko nagłówki (HEAD)
    curl -s <url>                 — cichy tryb (bez paska)
    curl -v <url>                 — verbose (nagłówki żądania/odpowiedzi)
    """
    import urllib.request as _urllib_req
    import urllib.error   as _urllib_err

    if not args:
        print_error("Podaj URL", "Uzycie: curl [-o plik] [-X METHOD] <url>")
        return

    # Parsowanie argumentów
    out_file  = None
    method    = "GET"
    headers   = {}
    data_str  = None
    head_only = False
    silent    = False
    verbose   = False
    url       = None

    i = 0
    while i < len(args):
        a = args[i]
        if a == "-o" and i+1 < len(args):
            i += 1; out_file = args[i]
        elif a == "-X" and i+1 < len(args):
            i += 1; method = args[i].upper()
        elif a == "-H" and i+1 < len(args):
            i += 1
            k, _, v = args[i].partition(":")
            headers[k.strip()] = v.strip()
        elif a == "-d" and i+1 < len(args):
            i += 1; data_str = args[i]
        elif a == "-I":
            head_only = True; method = "HEAD"
        elif a == "-s":
            silent = True
        elif a == "-v":
            verbose = True
        elif not a.startswith("-"):
            url = a
        i += 1

    if not url:
        print_error("Podaj URL", "Uzycie: curl <url>")
        return
    if not url.startswith(("http://", "https://")):
        url = "https://" + url

    body_bytes = data_str.encode() if data_str else None
    if data_str and "Content-Type" not in headers:
        headers["Content-Type"] = "application/x-www-form-urlencoded"

    req = _urllib_req.Request(url, data=body_bytes, headers=headers, method=method)

    if verbose:
        print(f"{C.DIM}> {method} {url}{C.RESET}")
        for k, v in headers.items():
            print(f"{C.DIM}> {k}: {v}{C.RESET}")

    try:
        with _urllib_req.urlopen(req, timeout=30) as resp:
            status = resp.status
            resp_headers = dict(resp.headers)
            content = resp.read()

        if verbose or head_only:
            print(f"{C.INFO}< HTTP {status}{C.RESET}")
            for k, v in list(resp_headers.items())[:20]:
                print(f"{C.DIM}< {k}: {v}{C.RESET}")
            if head_only:
                return

        if out_file:
            Path(out_file).write_bytes(content)
            if not silent:
                print(f"{C.OK}Zapisano {len(content)} bajtow → {out_file}{C.RESET}")
        else:
            try:
                text = content.decode("utf-8", errors="replace")
            except Exception:
                text = repr(content)
            print(text)

    except _urllib_err.HTTPError as e:
        print_error(f"HTTP {e.code}: {e.reason}", url)
    except _urllib_err.URLError as e:
        print_error(f"Blad URL: {e.reason}", url)
    except Exception as e:
        smart_error(e, "curl", url)

@command("kill", "Zakoncz proces po PID lub nazwie",
         aliases=["killproc"], flags=["-9", "-15", "-SIGKILL", "-SIGTERM"])
def cmd_kill(args):
    """
    kill <PID>        — SIGTERM (graceful stop)
    kill -9 <PID>     — SIGKILL (wymuś zamknięcie)
    kill <nazwa>      — zamknij procesy po nazwie (psutil lub taskkill/pkill)
    """
    import signal as _sig

    if not args:
        print_error("Podaj PID lub nazwe procesu", "Uzycie: kill [-9] <PID|nazwa>")
        return

    force = "-9" in args or "-SIGKILL" in args
    sig   = _sig.SIGKILL if (force and hasattr(_sig, "SIGKILL")) else _sig.SIGTERM
    targets = [a for a in args if not a.startswith("-")]

    for target in targets:
        if target.isdigit():
            pid = int(target)
            try:
                os.kill(pid, sig)
                label = "SIGKILL" if force else "SIGTERM"
                print(f"  {C.OK}Wyslano {label}{C.RESET} do PID {pid}")
            except ProcessLookupError:
                print_error(f"Nie znaleziono procesu PID {pid}")
            except PermissionError:
                print_error(f"Brak uprawnien do zamkniecia PID {pid}",
                            "Sprobuj: sudo kill " + target)
            except Exception as e:
                print_error(f"Blad kill PID {pid}: {e}")
        else:
            # Zabij po nazwie przez systemowe narzędzia
            if is_windows():
                r = subprocess.run(
                    ["taskkill", "/F" if force else "", "/IM", target + ".exe"],
                    capture_output=True, text=True
                )
                if r.returncode == 0:
                    print(f"  {C.OK}Zamknieto:{C.RESET} {target}")
                else:
                    print_error(f"Nie mozna zamknac '{target}'", r.stderr.strip())
            else:
                sig_flag = "-9" if force else "-15"
                r = subprocess.run(
                    ["pkill", sig_flag, target],
                    capture_output=True, text=True
                )
                if r.returncode == 0:
                    print(f"  {C.OK}Zamknieto:{C.RESET} {target}")
                else:
                    print_error(f"Nie znaleziono procesu '{target}'")

@command("ps", "Lista procesow systemowych",
         aliases=["proc", "procs-list"], flags=["-a", "-u", "-x", "--sort"])
def cmd_ps(args):
    """
    ps              — procesy bieżącego użytkownika
    ps -a           — wszystkie procesy
    ps -u <user>    — procesy danego użytkownika
    ps --sort cpu   — sortuj wg CPU
    ps --sort mem   — sortuj wg RAM
    """
    show_all = "-a" in args or "-ax" in args or "-aux" in args
    sort_by  = "pid"
    filter_user = None

    for i, a in enumerate(args):
        if a == "--sort" and i+1 < len(args):
            sort_by = args[i+1].lower()
        if a == "-u" and i+1 < len(args):
            filter_user = args[i+1]

    if is_windows():
        r = subprocess.run(
            ["tasklist", "/fo", "csv", "/nh"],
            capture_output=True, text=True, timeout=10
        )
        if r.returncode != 0:
            print_error("Nie mozna pobrac listy procesow"); return
        import csv, io
        rows = []
        for row in csv.reader(io.StringIO(r.stdout)):
            if len(row) >= 5:
                rows.append({"name": row[0], "pid": row[1],
                             "mem": row[4].replace("\xa0","").replace(",","").replace(" K","")})
        print(f"\n  {C.BOLD}{'NAZWA':<30} {'PID':>7} {'RAM (KB)':>12}{C.RESET}")
        print(f"  {C.DIM}{'─'*52}{C.RESET}")
        for p in rows[:40]:
            try:
                mem_kb = int(p["mem"].replace(",","").replace(".",""))
                mem_str = f"{mem_kb:,}"
            except Exception:
                mem_str = p["mem"]
            print(f"  {p['name']:<30} {p['pid']:>7} {mem_str:>12}")
        print(f"\n  {C.DIM}Pokazano: {min(40,len(rows))} z {len(rows)} procesow{C.RESET}\n")
    else:
        cmd_args = ["ps"]
        if show_all:
            cmd_args += ["aux"]
        else:
            cmd_args += ["-u", filter_user or os.getenv("USER","")]
        r = subprocess.run(cmd_args, capture_output=True, text=True, timeout=10)
        if r.returncode != 0:
            print_error("Nie mozna pobrac listy procesow"); return
        lines = r.stdout.splitlines()
        if not lines:
            print(f"{C.DIM}Brak procesow{C.RESET}"); return
        print(f"\n  {C.BOLD}{lines[0]}{C.RESET}")
        print(f"  {C.DIM}{'─'*80}{C.RESET}")
        # Sortowanie
        data_lines = lines[1:]
        if sort_by in ("cpu", "%cpu"):
            try: data_lines.sort(key=lambda l: float(l.split()[2]), reverse=True)
            except Exception:
                pass  # ignorowane celowo
        elif sort_by in ("mem", "%mem"):
            try: data_lines.sort(key=lambda l: float(l.split()[3]), reverse=True)
            except Exception:
                pass  # ignorowane celowo
        for line in data_lines[:50]:
            print(f"  {line}")
        if len(data_lines) > 50:
            print(f"  {C.DIM}... i {len(data_lines)-50} wiecej (uzyj ps -a --sort cpu){C.RESET}")
        print()

@command("chmod", "Zmien uprawnienia pliku (Linux/macOS) lub wyswietl info (Windows)",
         flags=["-R"])
def cmd_chmod(args):
    """
    chmod <tryb> <plik>      — np. chmod 755 skrypt.sh
    chmod +x <plik>          — dodaj wykonywalność
    chmod -R <tryb> <folder> — rekurencyjnie
    (Windows: wyświetla atrybuty, zmiana uprawnień wymaga icacls)
    """
    if not args or len(args) < 2:
        print_error("Podaj tryb i plik", "Uzycie: chmod [tryb] <plik>")
        return

    recursive = "-R" in args
    clean_args = [a for a in args if a != "-R"]
    mode_str, *targets = clean_args

    if not targets:
        print_error("Podaj plik/katalog")
        return

    if is_windows():
        # Na Windows: informacyjny tryb — pokaż atrybuty
        for t in targets:
            p = Path(t)
            if not p.exists():
                print_error(f"Nie znaleziono: '{t}'"); continue
            attrs = []
            if not os.access(t, os.W_OK): attrs.append("tylko-do-odczytu")
            if os.access(t, os.X_OK):     attrs.append("wykonywalny")
            attrs_str = ", ".join(attrs) if attrs else "normalny"
            print(f"  {C.PATH}{t}{C.RESET}  [{attrs_str}]")
            print(f"  {C.DIM}Windows: uzyj 'icacls {t}' dla pelnej kontroli uprawnien{C.RESET}")
        return

    import stat as _stat
    def _apply_chmod(path_obj: Path, mode: str):
        try:
            current = path_obj.stat().st_mode
            # Tryb numeryczny
            if mode.isdigit() or (len(mode) <= 4 and all(c in "01234567" for c in mode)):
                new_mode = int(mode, 8)
                path_obj.chmod(new_mode)
            else:
                # Symboliczny: [ugoa][+-=][rwx]
                new_mode = current
                for clause in mode.split(","):
                    m = re.match(r'^([ugoa]*)([+\-=])([rwxXst]*)$', clause)
                    if not m:
                        print_warn(f"Nieznany format trybu: '{clause}'"); continue
                    who, op, perms = m.group(1) or "a", m.group(2), m.group(3)
                    bits = 0
                    if "r" in perms: bits |= 0o444
                    if "w" in perms: bits |= 0o222
                    if "x" in perms or "X" in perms: bits |= 0o111
                    if "u" not in who and "g" not in who and "o" not in who:
                        who = "ugo"
                    mask = 0
                    if "u" in who: mask |= 0o700
                    if "g" in who: mask |= 0o070
                    if "o" in who: mask |= 0o007
                    bits &= mask
                    if op == "+": new_mode |= bits
                    elif op == "-": new_mode &= ~bits
                    elif op == "=": new_mode = (new_mode & ~mask) | bits
                path_obj.chmod(new_mode)
            new = path_obj.stat().st_mode
            mode_oct = oct(new)[-3:]
            print(f"  {C.OK}OK{C.RESET}  {path_obj}  →  {mode_oct}")
        except PermissionError:
            print_error(f"Brak uprawnien: '{path_obj}'", "Sprobuj z sudo")
        except Exception as e:
            print_error(f"Blad chmod '{path_obj}': {e}")

    for t in targets:
        p = Path(t)
        if not p.exists():
            print_error(f"Nie znaleziono: '{t}'"); continue
        if recursive and p.is_dir():
            for sub in p.rglob("*"):
                _apply_chmod(sub, mode_str)
            _apply_chmod(p, mode_str)
        else:
            _apply_chmod(p, mode_str)

@command("chown", "Zmien wlasciciela pliku (Linux/macOS)",
         flags=["-R"])
def cmd_chown(args):
    """
    chown <user>:<group> <plik>   — zmień właściciela i grupę
    chown <user> <plik>           — zmień tylko właściciela
    chown -R <user>:<group> <dir> — rekurencyjnie
    (Windows: wyświetla właściciela, zmiana wymaga icacls/takeown)
    """
    if not args or len(args) < 2:
        print_error("Podaj wlasciciela i plik", "Uzycie: chown [user][:group] <plik>")
        return

    recursive = "-R" in args
    clean_args = [a for a in args if a != "-R"]
    owner_str, *targets = clean_args

    if not targets:
        print_error("Podaj plik/katalog"); return

    if is_windows():
        for t in targets:
            p = Path(t)
            if not p.exists():
                print_error(f"Nie znaleziono: '{t}'"); continue
            r = subprocess.run(
                ["icacls", str(p)], capture_output=True, text=True
            )
            print(f"  {C.PATH}{t}{C.RESET}")
            for line in r.stdout.splitlines()[:5]:
                print(f"  {C.DIM}{line}{C.RESET}")
            print(f"  {C.DIM}Windows: uzyj 'icacls' lub 'takeown' dla zmiany wlasciciela{C.RESET}")
        return

    user_part, _, group_part = owner_str.partition(":")
    import pwd as _pwd
    import grp as _grp

    def _resolve_uid_gid(user: str, group: str):
        uid = -1; gid = -1
        if user:
            try: uid = _pwd.getpwnam(user).pw_uid
            except KeyError: print_error(f"Uzytkownik nie istnieje: '{user}'"); return None, None
        if group:
            try: gid = _grp.getgrnam(group).gr_gid
            except KeyError: print_error(f"Grupa nie istnieje: '{group}'"); return None, None
        return uid, gid

    uid, gid = _resolve_uid_gid(user_part, group_part)
    if uid is None: return

    def _apply(p: Path):
        try:
            os.chown(str(p), uid, gid)
            owner_label = owner_str
            print(f"  {C.OK}OK{C.RESET}  {p}  →  {owner_label}")
        except PermissionError:
            print_error(f"Brak uprawnien: '{p}'", "Sprobuj z sudo")
        except Exception as e:
            print_error(f"Blad chown '{p}': {e}")

    for t in targets:
        p = Path(t)
        if not p.exists():
            print_error(f"Nie znaleziono: '{t}'"); continue
        if recursive and p.is_dir():
            for sub in p.rglob("*"):
                _apply(sub)
            _apply(p)
        else:
            _apply(p)

@command("pip", "Wrapper systemowego pip / mini-pip shella",
         aliases=["pip3"], flags=["install", "uninstall", "list", "show", "search"])
def cmd_pip(args):
    """
    pip install <pakiet>      — instaluj przez systemowy pip
    pip uninstall <pakiet>    — odinstaluj
    pip list                  — lista zainstalowanych pakietow
    pip show <pakiet>         — info o pakiecie
    Alternatywa: komenda 'pkg' (mini-pip wbudowany)
    """
    if not args:
        print(f"  {C.INFO}pip{C.RESET} — wrapper systemowego pip\n")
        print(f"  Uzycie: pip <install|uninstall|list|show> [pakiet]\n")
        print(f"  {C.DIM}Tip: 'pkg' to wbudowany mini-pip shella (bez wymaganego Python){C.RESET}\n")
        return

    # Sprawdź dostępność systemowego pip
    pip_bin = shutil.which("pip3") or shutil.which("pip")
    if not pip_bin:
        print_error("Nie znaleziono pip w PATH",
                    "Zainstaluj pip: https://pip.pypa.io lub uzyj komendy 'pkg'")
        return

    # Przekaż do systemowego pip
    try:
        result = subprocess.run(
            [pip_bin] + args,
            env=_build_env()
        )
        _LAST_EXIT if False else None
    except Exception as e:
        smart_error(e, "pip")

@command("free", "Informacje o pamieci RAM (cross-platform)",
         aliases=["meminfo"], flags=["-h", "-m", "-g"])
def cmd_free(args):
    """
    free       — RAM w bajtach
    free -h    — czytelny format (MB/GB)
    free -m    — megabajty
    free -g    — gigabajty
    """
    human  = "-h" in args
    in_mb  = "-m" in args
    in_gb  = "-g" in args

    def _fmt(b: int) -> str:
        if human:
            if b >= 1024**3: return f"{b/1024**3:.1f}G"
            if b >= 1024**2: return f"{b/1024**2:.1f}M"
            if b >= 1024:    return f"{b/1024:.1f}K"
            return f"{b}B"
        if in_gb: return str(round(b/1024**3, 2))
        if in_mb: return str(round(b/1024**2, 2))
        return str(b)

    if is_windows():
        r = subprocess.run(
            ["wmic", "OS", "get", "TotalVisibleMemorySize,FreePhysicalMemory", "/value"],
            capture_output=True, text=True, timeout=8
        )
        total = free_mem = 0
        for line in r.stdout.splitlines():
            if "TotalVisibleMemorySize" in line:
                try: total = int(line.split("=")[1].strip()) * 1024
                except Exception:
                    pass  # ignorowane celowo
            if "FreePhysicalMemory" in line:
                try: free_mem = int(line.split("=")[1].strip()) * 1024
                except Exception:
                    pass  # ignorowane celowo
        used = total - free_mem
    else:
        # Próbuj /proc/meminfo (Linux)
        meminfo = Path("/proc/meminfo")
        if meminfo.exists():
            data = {}
            for line in meminfo.read_text().splitlines():
                parts = line.split()
                if len(parts) >= 2:
                    data[parts[0].rstrip(":")] = int(parts[1]) * 1024
            total    = data.get("MemTotal", 0)
            free_mem = data.get("MemFree",  0)
            buffers  = data.get("Buffers",  0)
            cached   = data.get("Cached",   0)
            used = total - free_mem - buffers - cached
        else:
            # macOS / BSD fallback
            r = subprocess.run(["vm_stat"], capture_output=True, text=True, timeout=5)
            ps_r = subprocess.run(["sysctl", "-n", "hw.memsize"],
                                  capture_output=True, text=True, timeout=5)
            total = int(ps_r.stdout.strip()) if ps_r.returncode == 0 else 0
            page_size = 4096
            free_pages = 0
            for line in r.stdout.splitlines():
                if "Pages free" in line:
                    try: free_pages = int(line.split(":")[1].strip().rstrip("."))
                    except Exception:
                        pass  # ignorowane celowo
            free_mem = free_pages * page_size
            used = total - free_mem

    unit_label = "G" if in_gb else ("M" if in_mb else ("" if not human else ""))
    print(f"\n  {'':30} {'TOTAL':>10} {'UZYTE':>10} {'WOLNE':>10}")
    print(f"  {C.DIM}{'─'*62}{C.RESET}")
    print(f"  {'RAM':<30} {_fmt(total):>10} {_fmt(used):>10} {_fmt(free_mem):>10}")
    print()

@command("df", "Informacje o dyskach i przestrzeni (cross-platform)",
         aliases=["diskfree"], flags=["-h"])
def cmd_df(args):
    """
    df      — wolne miejsce na dyskach
    df -h   — format czytelny dla człowieka
    df <sciezka> — info o konkretnym dysku/katalogu
    """
    human = "-h" in args
    paths_arg = [a for a in args if not a.startswith("-")]

    def _fmt(b: int) -> str:
        if not human: return str(b)
        if b >= 1024**3: return f"{b/1024**3:.1f}G"
        if b >= 1024**2: return f"{b/1024**2:.1f}M"
        if b >= 1024:    return f"{b/1024:.1f}K"
        return f"{b}B"

    if is_windows():
        r = subprocess.run(
            ["wmic", "logicaldisk", "get", "Caption,Size,FreeSpace,FileSystem", "/format:csv"],
            capture_output=True, text=True, timeout=10
        )
        print(f"\n  {C.BOLD}{'DYSK':<10} {'ROZMIAR':>12} {'WOLNE':>12} {'UZYTE':>12} {'SYSTEM':>8}{C.RESET}")
        print(f"  {C.DIM}{'─'*58}{C.RESET}")
        for line in r.stdout.splitlines():
            parts = [p.strip() for p in line.split(",")]
            if len(parts) < 5 or not parts[1]: continue
            try:
                cap = parts[1]
                free_s = int(parts[2]) if parts[2].isdigit() else 0
                fs     = parts[3]
                size_s = int(parts[4]) if parts[4].isdigit() else 0
                used_s = size_s - free_s
                print(f"  {cap:<10} {_fmt(size_s):>12} {_fmt(free_s):>12} {_fmt(used_s):>12} {fs:>8}")
            except Exception:
                continue
        print()
    else:
        check_paths = paths_arg if paths_arg else ["/"]
        print(f"\n  {C.BOLD}{'PUNKT MONTOWANIA':<22} {'ROZMIAR':>10} {'UZYTE':>10} {'WOLNE':>10} {'%':>5}{C.RESET}")
        print(f"  {C.DIM}{'─'*60}{C.RESET}")
        seen = set()
        for target in check_paths:
            try:
                st = os.statvfs(target)
                total = st.f_blocks * st.f_frsize
                free_space = st.f_bavail * st.f_frsize
                used_space = (st.f_blocks - st.f_bfree) * st.f_frsize
                pct = f"{100*used_space//total}%" if total > 0 else "?"
                key = (total, free_space)
                if key in seen: continue
                seen.add(key)
                label = target[:22]
                print(f"  {label:<22} {_fmt(total):>10} {_fmt(used_space):>10} {_fmt(free_space):>10} {pct:>5}")
            except Exception:
                # Fallback: systemowy df
                r = subprocess.run(
                    ["df", "-h" if human else "-k", target],
                    capture_output=True, text=True, timeout=5
                )
                if r.returncode == 0:
                    for line in r.stdout.splitlines()[1:]:
                        print(f"  {line}")
        print()

@command("uname", "Informacje o systemie operacyjnym",
         aliases=["sysname"], flags=["-a", "-s", "-r", "-m", "-n"])
def cmd_uname(args):
    """
    uname      — nazwa systemu
    uname -a   — wszystkie informacje
    uname -s   — nazwa systemu (kernel)
    uname -r   — wersja systemu
    uname -m   — architektura
    uname -n   — hostname
    """
    import platform as _plt

    show_all = "-a" in args or not args
    show_sys  = "-s" in args or show_all
    show_rel  = "-r" in args or show_all
    show_mach = "-m" in args or show_all
    show_node = "-n" in args or show_all

    parts = []
    if show_sys:  parts.append(_plt.system() or "Unknown")
    if show_node: parts.append(_plt.node())
    if show_rel:  parts.append(_plt.release())
    if show_mach: parts.append(_plt.machine())

    if show_all:
        print(f"\n  {C.BOLD}System:{C.RESET}       {_plt.system()} {_plt.release()}")
        print(f"  {C.BOLD}Node:{C.RESET}         {_plt.node()}")
        print(f"  {C.BOLD}Architektura:{C.RESET} {_plt.machine()}")
        print(f"  {C.BOLD}Python:{C.RESET}       {_plt.python_version()}")
        print(f"  {C.BOLD}Procesor:{C.RESET}     {_plt.processor() or 'brak info'}")
        print()
    else:
        print(" ".join(parts))

@command("uptime", "Czas pracy systemu i srednie obciazenie")
def cmd_uptime(args):
    """uptime  — czas pracy systemu + load average (jeśli dostępne)"""
    import time as _time

    if is_windows():
        r = subprocess.run(
            ["wmic", "OS", "get", "LastBootUpTime", "/value"],
            capture_output=True, text=True, timeout=8
        )
        for line in r.stdout.splitlines():
            if "LastBootUpTime" in line:
                raw = line.split("=")[1].strip()
                try:
                    # Format: YYYYMMDDHHmmss.xxxxxx+ZZZ
                    dt_str = raw[:14]
                    boot = datetime.datetime.strptime(dt_str, "%Y%m%d%H%M%S")
                    delta = datetime.datetime.now() - boot
                    h, rem = divmod(int(delta.total_seconds()), 3600)
                    m = rem // 60
                    print(f"\n  {C.INFO}Czas pracy:{C.RESET}  {h}h {m}m")
                    print(f"  {C.INFO}Uruchomiono:{C.RESET} {boot.strftime('%Y-%m-%d %H:%M')}\n")
                except Exception:
                    print(f"  Boot: {raw}")
                break
    else:
        # Linux: /proc/uptime
        uptime_file = Path("/proc/uptime")
        if uptime_file.exists():
            seconds_up = float(uptime_file.read_text().split()[0])
            h, rem = divmod(int(seconds_up), 3600)
            m = rem // 60
            print(f"\n  {C.INFO}Czas pracy:{C.RESET}  {h}h {m}m")
            # Load average z /proc/loadavg
            loadavg = Path("/proc/loadavg")
            if loadavg.exists():
                parts = loadavg.read_text().split()
                print(f"  {C.INFO}Load avg:{C.RESET}    {parts[0]} {parts[1]} {parts[2]}  (1/5/15 min)")
            print()
        else:
            # macOS: systemowy uptime
            r = subprocess.run(["uptime"], capture_output=True, text=True, timeout=5)
            if r.returncode == 0:
                print(f"  {r.stdout.strip()}")
            else:
                print_error("Nie mozna pobrac czasu pracy systemu")

@command("hostname", "Wyswietl lub zmien nazwe hosta",
         aliases=["host"], flags=["--set"])
def cmd_hostname(args):
    """
    hostname          — wyświetl nazwę hosta
    hostname --set <nazwa>  — zmień nazwę (wymaga uprawnień)
    """
    import platform as _plt
    if "--set" in args:
        idx = args.index("--set")
        if idx + 1 >= len(args):
            print_error("Podaj nowa nazwe hosta", "Uzycie: hostname --set <nazwa>")
            return
        new_name = args[idx + 1]
        if is_windows():
            r = subprocess.run(
                ["wmic", "computersystem", "where", "name='%COMPUTERNAME%'",
                 "call", "rename", f"name={new_name}"],
                capture_output=True, text=True
            )
        else:
            r = subprocess.run(["hostname", new_name], capture_output=True, text=True)
        if r.returncode == 0:
            print(f"  {C.OK}Zmieniono hostname na: {new_name}{C.RESET}")
        else:
            print_error(f"Nie mozna zmienic hostname: {r.stderr.strip()}",
                        "Sprobuj z sudo / jako administrator")
    else:
        import socket as _sock
        print(_plt.node() or _sock.gethostname())

@command("id", "Wyswietl ID uzytkownika i grupy (Linux/macOS)")
def cmd_id(args):
    """
    id        — UID, GID i grupy bieżącego użytkownika
    id <user> — informacje o danym użytkowniku
    """
    if is_windows():
        # Windows: whoami /all
        r = subprocess.run(
            ["whoami", "/all"], capture_output=True, text=True, timeout=5
        )
        if r.returncode == 0:
            for line in r.stdout.splitlines()[:15]:
                print(f"  {line}")
        else:
            import getpass as _gp
            print(f"  Uzytkownik: {_gp.getuser()}")
        return

    target = args[0] if args else None
    try:
        import pwd as _pwd, grp as _grp
        if target:
            pw = _pwd.getpwnam(target)
        else:
            pw = _pwd.getpwuid(os.getuid())
        uid  = pw.pw_uid
        gid  = pw.pw_gid
        name = pw.pw_name
        try:
            grp_name = _grp.getgrgid(gid).gr_name
        except Exception:
            grp_name = str(gid)
        # Grupy dodatkowe
        groups = [g for g in _grp.getgrall() if name in g.gr_mem]
        grp_str = ",".join(f"{g.gr_gid}({g.gr_name})" for g in groups[:10])
        print(f"uid={uid}({name}) gid={gid}({grp_name}) grupy={gid}({grp_name})"
              + (f",{grp_str}" if grp_str else ""))
    except ImportError:
        r = subprocess.run(["id"] + ([target] if target else []),
                           capture_output=True, text=True, timeout=5)
        print(r.stdout.strip())
    except KeyError:
        print_error(f"Uzytkownik nie istnieje: '{target}'")

@command("source", "Wczytaj i wykonaj skrypt TerminalXa (.msh / .rc)",
         aliases=[".", "exec-script"])
def cmd_source(args):
    """
    source <plik>   — wykonaj plik jako sekwencję komend shella
    . <plik>        — skrót (bash-style)
    Obsługuje: aliasy, zmienne, komendy wbudowane, komentarze #
    """
    if not args:
        print_error("Podaj plik do wczytania", "Uzycie: source <plik.msh>")
        return
    path = Path(args[0]).expanduser()
    if not path.exists():
        print_error(f"Nie znaleziono: '{path}'")
        return
    lines = path.read_text(encoding="utf-8", errors="replace").splitlines()
    executed = 0
    errors   = 0
    for lineno, raw_line in enumerate(lines, 1):
        line = raw_line.strip()
        if not line or line.startswith("#"):
            continue
        try:
            code, _ = _run_single_cmd(line)
            if code != 0:
                errors += 1
        except Exception as e:
            print_warn(f"[source:{lineno}] Blad: {e}")
            errors += 1
        executed += 1
    print(f"\n  {C.DIM}source: wykonano {executed} komend"
          + (f", {errors} bledow" if errors else "") + f"  [{path.name}]{C.RESET}\n")

@command("deactivate", "Dezaktywuj wirtualne srodowisko Python (venv)")
def cmd_deactivate(args):
    """
    deactivate  — usuwa VIRTUAL_ENV z środowiska shella
    Tip: aktywacja venv: source venv/bin/activate  (Linux/macOS)
                         source venv\\Scripts\\activate  (Windows)
    """
    venv = os.environ.get("VIRTUAL_ENV") or SHELL_VARS.get("VIRTUAL_ENV")
    if venv:
        # Usuń VIRTUAL_ENV z obu słowników
        SHELL_VARS.pop("VIRTUAL_ENV", None)
        os.environ.pop("VIRTUAL_ENV", None)
        # Przywróć oryginalny PATH (usuń <venv>/bin z przodu)
        path_sep = ";" if is_windows() else ":"
        bin_dir  = "Scripts" if is_windows() else "bin"
        venv_bin = str(Path(venv) / bin_dir)
        cur_path = os.environ.get("PATH", "")
        new_path = path_sep.join(
            p for p in cur_path.split(path_sep)
            if p != venv_bin
        )
        os.environ["PATH"] = new_path
        SHELL_VARS["PATH"] = new_path
        print(f"  {C.OK}Dezaktywowano venv:{C.RESET} {venv}")
    else:
        print(f"  {C.DIM}Brak aktywnego wirtualnego srodowiska.{C.RESET}")
        print(f"  {C.DIM}Aktywacja: source venv/bin/activate{C.RESET}")

# ── Dodatkowe aliasy systemowe — przekazują do OS z komunikatem ──────────────

@command("attrib", "Atrybuty pliku — Windows attrib lub Linux stat",
         aliases=["attr"])
def cmd_attrib(args):
    """
    attrib <plik>       — pokaż/zmień atrybuty (Windows) lub uprawnienia (Linux)
    attrib +R <plik>    — ustaw tylko-do-odczytu
    attrib -R <plik>    — usuń tylko-do-odczytu
    attrib +H <plik>    — ukryj plik (Windows)
    """
    if not args:
        print_error("Podaj plik", "Uzycie: attrib [+/-R|H|S|A] <plik>")
        return

    if is_windows():
        # Przekaż do systemowego attrib.exe
        r = subprocess.run(["attrib"] + args, capture_output=True, text=True)
        if r.stdout: print(r.stdout)
        if r.stderr: print_error(r.stderr.strip())
        return

    # Linux/macOS: pokaż uprawnienia przez stat
    import stat as _stat
    flags = [a for a in args if a.startswith(("+", "-"))]
    targets = [a for a in args if not a.startswith(("+", "-"))]

    for t in targets:
        p = Path(t)
        if not p.exists():
            print_error(f"Nie znaleziono: '{t}'"); continue
        st = p.stat()
        mode = st.st_mode
        mode_str = _stat.filemode(mode)
        is_hidden = p.name.startswith(".")
        print(f"  {C.PATH}{t}{C.RESET}")
        print(f"    Uprawnienia: {mode_str}  ({oct(mode)[-3:]})")
        print(f"    Ukryty:      {'tak' if is_hidden else 'nie'} (nazwa zaczyna sie od '.')")
        print(f"    Zapisywalny: {'nie' if not os.access(t, os.W_OK) else 'tak'}")

        # Obsługa +R / -R
        for flag in flags:
            op, attr = flag[0], flag[1:].upper()
            if attr == "R":
                new_mode = mode & ~0o222 if op == "+" else mode | 0o200
                p.chmod(new_mode)
                print(f"    {C.OK}Ustawiono {'tylko-do-odczytu' if op=='+' else 'zapisywalny'}{C.RESET}")

# ██ CRASHLOG COMMAND ████████████████████████████████████████

@command("crashlog", "Wyswietl i zarzadzaj raportem bledow (crashlog)",
         aliases=["crash", "errors"])
def cmd_crashlog(args):
    """
    crashlog            - ostatnie 20 wpisow raportu bledow
    crashlog -n <N>     - ostatnie N wpisow
    crashlog -a         - wszystkie wpisy
    crashlog clear      - wyczysc plik crashlogu
    crashlog path       - pokaz sciezke do pliku
    """
    sub = args[0].lower() if args else ""

    if sub == "path":
        print_info(f"Plik crashlogu: {CRASHLOG_FILE}")
        if CRASHLOG_FILE.exists():
            size = CRASHLOG_FILE.stat().st_size
            print_info(f"Rozmiar: {_human_size(size)}")
        else:
            print_info("Plik nie istnieje — brak bledow do tej pory.")
        return

    if sub == "clear":
        if CRASHLOG_FILE.exists():
            try:
                CRASHLOG_FILE.unlink()
                print_info("Crashlog wyczyszczony.")
                log_info("Crashlog wyczyszczony przez uzytkownika")
            except Exception as e:
                print_error(f"Nie mozna usunac pliku crashlogu: {e}")
        else:
            print_info("Crashlog jest juz pusty.")
        return

    if not CRASHLOG_FILE.exists():
        print_info("Brak zapisanych bledow — crashlog jest pusty.")
        return

    # Parsuj limit -n
    show_all = sub == "-a" or "-a" in args
    limit    = None
    if "-n" in args:
        idx = args.index("-n")
        if idx + 1 < len(args):
            try:
                limit = int(args[idx + 1])
            except ValueError:
                print_error("Wartosc -n musi byc liczba calkowita"); return
    if limit is None and not show_all:
        limit = 20   # domyslnie ostatnie 20 wpisow

    try:
        text = CRASHLOG_FILE.read_text(encoding="utf-8", errors="replace")
    except Exception as e:
        print_error(f"Nie mozna odczytac crashlogu: {e}"); return

    # Podziel na sekcje wg separatora "====..."
    SEP = "=" * 72
    sections = [s.strip() for s in text.split(SEP) if s.strip()]

    if not sections:
        print_info("Crashlog jest pusty lub nie zawiera wpisow.")
        return

    # Limit od konca
    if not show_all and limit:
        sections = sections[-limit:]

    w = min(terminal_width() - 2, 76)
    total = len(sections)
    print()
    print(box_top(f"Crashlog  ({total} wpisow)  {CRASHLOG_FILE}", width=w, color=C.ERROR))

    for i, sec in enumerate(sections, 1):
        lines = sec.splitlines()
        for ln in lines[:18]:  # max 18 linii na wpis
            stripped = ln.strip()
            if stripped.startswith("TERMINALX CRASHLOG"):
                print(box_row(f"  {C.BOLD}{C.ERROR}{stripped}{C.RESET}", width=w, color=C.ERROR))
            elif stripped.startswith("Typ bledu"):
                print(box_row(f"  {C.ERROR}{stripped}{C.RESET}", width=w, color=C.ERROR))
            elif stripped.startswith("Porada"):
                print(box_row(f"  {C.INFO}{stripped}{C.RESET}", width=w, color=C.ERROR))
            elif stripped.startswith("Traceback"):
                print(box_row(f"  {C.DIM}{stripped}{C.RESET}", width=w, color=C.ERROR))
                break   # nie drukuj calego traceback — tylko nagłówek
            else:
                print(box_row(f"  {C.DIM}{stripped}{C.RESET}", width=w, color=C.ERROR))
        if i < total:
            print(box_sep(width=w, color=C.ERROR))

    print(box_bottom(width=w, color=C.ERROR))
    size = _human_size(CRASHLOG_FILE.stat().st_size)
    print(f"  {C.DIM}Rozmiar: {size}  |  crashlog clear — wyczysc  |  crashlog -a — wszystkie{C.RESET}")
    print()

# ██ CHANGELOG ████████████████████████████████████████████████

@command("changelog", "Historia zmian TerminalXa", aliases=["changes","history-log"])
def cmd_changelog(args):
    """
    changelog           - pelna historia zmian
    changelog <wersja>  - zmiany dla konkretnej wersji (np. changelog 15.0)
    """
    filter_ver = args[0] if args else None
    w = min(terminal_width()-2, 72)
    print()
    print(box_top(f"TerminalX  Changelog", width=w, color=C.INFO))
    found = False
    for entry in CHANGELOG:
        ver   = entry.get("version", "?")
        date  = entry.get("date", "")
        items = entry.get("changes", [])
        if filter_ver and ver != filter_ver:
            continue
        found = True
        print(box_row(
            f"  {C.BOLD}v{ver}{C.RESET}  {C.DIM}{date}{C.RESET}",
            width=w, color=C.INFO))
        print(box_sep(width=w, color=C.INFO))
        for item in items:
            print(box_row(f"    {C.DIM}•{C.RESET} {item}", width=w, color=C.INFO))
        print(box_sep(width=w, color=C.INFO))
    if not found:
        if filter_ver:
            print(box_row(f"  Brak wpisu dla wersji {filter_ver}", width=w, color=C.INFO))
        else:
            print(box_row("  Brak wpisow w changelogu.", width=w, color=C.INFO))
    print(box_bottom(width=w, color=C.INFO))
    print()

# ██ ONLINE / OFFLINE MODE ████████████████████████████████████

@command("mode", "Tryb online/offline — zarzadzaj dostepem do sieci",
         aliases=["network","netmode"])
def cmd_mode(args):
    """
    mode            - pokaz biezacy tryb (online/offline)
    mode check      - ponownie sprawdz polaczenie
    mode online     - przelacz na tryb online  (wymaga polaczenia)
    mode offline    - przelacz na tryb offline (zawsze dostepne)
    """
    sub = args[0].lower() if args else ""

    if sub == "check" or sub == "":
        detected = _detect_network()
        if sub == "check":
            _STATE.online_mode = detected
        status_str  = (f"{C.PATH}ONLINE{C.RESET}"  if _ONLINE_MODE
                       else f"{C.DIM}OFFLINE{C.RESET}")
        detect_str  = (f"{C.PATH}dostepna{C.RESET}" if detected
                       else f"{C.ERROR}niedostepna{C.RESET}")
        w = min(terminal_width()-2, 56)
        print()
        print(box_top("Tryb sieci", width=w, color=C.EXEC))
        print(box_row(kv_row("Biezacy tryb",  status_str,  key_color=C.DIM), width=w, color=C.EXEC))
        if sub == "check":
            print(box_row(kv_row("Siec fizyczna", detect_str, key_color=C.DIM), width=w, color=C.EXEC))
        print(box_row(
            f"  {C.DIM}mode online | mode offline | mode check{C.RESET}",
            width=w, color=C.EXEC))
        print(box_bottom(width=w, color=C.EXEC))
        print()

    elif sub == "online":
        if _detect_network():
            _STATE.online_mode = True
            print_info(f"Tryb sieci: {C.PATH}ONLINE{C.RESET}  — pobieranie pakietow aktywne.")
            log_info("Przelaczono na tryb online")
        else:
            print_error("Brak polaczenia z internetem — nie mozna wlaczyc trybu online.",
                        "Sprawdz polaczenie i sprobuj ponownie (mode check).")

    elif sub == "offline":
        _STATE.online_mode = False
        print_info(f"Tryb sieci: {C.DIM}OFFLINE{C.RESET}  — pobieranie pakietow wylaczone.")
        log_info("Przelaczono na tryb offline")

    else:
        print_error(f"Nieznana opcja: {sub}", "Uzycie: mode [check|online|offline]")

