#
#  Narzędzia developerskie dostępne jako wbudowane komendy:
#
#   json      — formatowanie, walidacja, zapytania (mini-jq)
#   yaml      — parsowanie i formatowanie YAML (stdlib, bez pyyaml)
#   jq        — mini jq: zapytania ścieżkowe do JSON (key.sub[0])
#   calc      — kalkulator wyrażeń matematycznych (Python eval sandbox)
#   hash      — sumy kontrolne plików i tekstu (md5/sha1/sha256/sha512)
#   base64    — kodowanie / dekodowanie base64
#   hexdump   — podgląd binarny pliku
#   diff      — porównanie dwóch plików (unified diff)
#   timeit    — pomiar czasu wykonania komendy shella
#   pyrepl    — mini interaktywny REPL Pythona
#
# Wszystko stdlib — zero pip, działa offline.

# ── JSON ─────────────────────────────────────────────────────────────────────

@command("json", "Parser / formatter / walidator JSON",
         aliases=["jsonformat", "jsonlint", "jsonpp"],
         flags=["-c", "-s", "-q", "-k"])
def cmd_json(args):
    """
    json <plik>           — sformatuj plik JSON (pretty-print)
    json -c <plik>        — kompaktuj JSON (minify)
    json -s <plik> <key>  — wypisz wartosc klucza (key.sub[0].field)
    json -q <plik> <q>    — filtruj tablice: key=wartosc
    json -k <plik>        — wypisz wszystkie klucze (pierwsze poziomy)
    json                  — czytaj ze stdin jesli brak pliku
    json --validate <plik>— tylko walidacja (exit 0 OK, 1 blad)

    Kolorowanie: klucze na niebiesko, stringi zielono, liczby zolto.
    """
    _json = json   # json zaimportowany na poziomie modułu

    def _color_json(text: str) -> str:
        """Koloruje sformatowany JSON (linia po linii) — używa skompilowanych patternów."""
        _kw  = C.KEYWORD; _rs = C.RESET; _pa = C.PATH
        _nu  = C.NUMBER;  _in = C.INFO
        out = []
        for line in text.splitlines():
            line = _RE_JSON_KEY.sub(
                lambda m: f"{_kw}{m.group(1)}{_rs}{m.group(2)}", line)
            line = _RE_JSON_STR.sub(
                lambda m: f"{m.group(1)}{_pa}{m.group(2)}{_rs}", line)
            line = _RE_JSON_NUM.sub(
                lambda m: f": {_nu}{m.group(1)}{_rs}", line)
            line = _RE_JSON_BOOL.sub(
                lambda m: f"{_in}{m.group(1)}{_rs}", line)
            out.append(line)
        return "\n".join(out)

    def _resolve_path(obj, path: str):
        """Rozwiazuje sciezke 'a.b[2].c' w strukturze JSON."""
        for part in _RE_JSON_PATH.split(path):
            if not part:
                continue
            if isinstance(obj, dict):
                obj = obj.get(part, obj.get(int(part) if part.isdigit() else part))
            elif isinstance(obj, list):
                try:
                    obj = obj[int(part)]
                except (ValueError, IndexError):
                    return None
            else:
                return None
        return obj

    # Zbierz flagi
    compact   = "-c" in args
    get_path  = "-s" in args
    query     = "-q" in args
    keys_only = "-k" in args
    validate  = "--validate" in args

    clean_args = [a for a in args if not a.startswith("-")]

    # Zrodlo danych
    src_text = ""
    if clean_args:
        try:
            src_text = Path(clean_args[0]).expanduser().read_text(encoding="utf-8")
        except FileNotFoundError:
            print_error(f"Plik nie istnieje: {clean_args[0]}"); return
        except Exception as e:
            print_error(f"Blad odczytu: {e}"); return
    else:
        try:
            import sys as _sys
            src_text = _sys.stdin.read()
        except KeyboardInterrupt:
            return

    if not src_text.strip():
        print_error("Brak danych wejsciowych (pusty plik lub stdin)"); return

    # Parsuj
    try:
        data = _json.loads(src_text)
    except _json.JSONDecodeError as e:
        if validate:
            print_error(f"JSON NIEPRAWIDLOWY: {e}")
            return
        # Spróbuj wskazac linie bledu
        lines = src_text.splitlines()
        bad   = lines[e.lineno - 1] if 0 < e.lineno <= len(lines) else ""
        print_error(f"Nieprawidlowy JSON  (linia {e.lineno}, kol {e.colno}): {e.msg}")
        if bad:
            print(f"  {C.DIM}{bad.rstrip()}{C.RESET}")
            print(f"  {C.ERROR}{'~' * (e.colno - 1)}^{C.RESET}")
        return

    if validate:
        print_info(f"JSON prawidlowy  ({len(src_text)} bajtow, typ: {type(data).__name__})"); return

    # ------ akcje ------
    if keys_only:
        if isinstance(data, dict):
            for k in data.keys():
                print(f"  {C.KEYWORD}{k}{C.RESET}  {C.DIM}({type(data[k]).__name__}){C.RESET}")
        elif isinstance(data, list):
            print_info(f"Tablica: {len(data)} elementow  (typ: {type(data[0]).__name__ if data else '?'})")
        return

    if get_path and len(clean_args) >= 2:
        result = _resolve_path(data, clean_args[1])
        if result is None:
            print_error(f"Sciezka '{clean_args[1]}' nie istnieje w dokumencie")
            return
        if isinstance(result, (dict, list)):
            print(_color_json(_json.dumps(result, indent=2, ensure_ascii=False)))
        else:
            print(f"{C.PATH}{result}{C.RESET}")
        return

    if query and len(clean_args) >= 2:
        qstr = clean_args[1]
        if "=" in qstr:
            qk, qv = qstr.split("=", 1)
            if isinstance(data, list):
                found = [item for item in data
                         if isinstance(item, dict) and str(item.get(qk, "")) == qv]
                print(_color_json(_json.dumps(found, indent=2, ensure_ascii=False)))
            else:
                print_error("Filtrowanie (-q) działa tylko dla tablic JSON")
        else:
            print_error("Format zapytania: klucz=wartosc")
        return

    # Pretty-print lub minify
    indent = None if compact else 2
    result_text = _json.dumps(data, indent=indent, ensure_ascii=False)
    if compact:
        print(result_text)
    else:
        print(_color_json(result_text))

    # Podsumowanie
    if not compact:
        kb = len(result_text.encode()) / 1024
        t  = type(data).__name__
        n  = len(data) if isinstance(data, (dict, list)) else "-"
        print(f"\n  {C.DIM}typ: {t}  |  elementow: {n}  |  {kb:.1f} KB{C.RESET}")

# ── YAML ──────────────────────────────────────────────────────────────────────

@command("yaml", "Parser / formatter YAML (stdlib, bez pyyaml)",
         aliases=["yamlformat", "yamllint", "yamlpp"],
         flags=["--to-json", "--validate"])
def cmd_yaml(args):
    """
    yaml <plik>            — sformatuj i wyswietl YAML
    yaml --to-json <plik>  — konwertuj YAML → JSON (pretty)
    yaml --validate <plik> — walidacja (exit 0 OK, 1 blad)
    yaml                   — czytaj ze stdin
    """
    to_json  = "--to-json"  in args
    validate = "--validate" in args
    clean    = [a for a in args if not a.startswith("-")]

    # Odczytaj zrodlo
    src_text = ""
    if clean:
        try:
            src_text = Path(clean[0]).expanduser().read_text(encoding="utf-8")
        except FileNotFoundError:
            print_error(f"Plik nie istnieje: {clean[0]}"); return
        except Exception as e:
            print_error(f"Blad odczytu: {e}"); return
    else:
        try:
            src_text = sys.stdin.read()
        except KeyboardInterrupt:
            return

    if not src_text.strip():
        print_error("Brak danych wejsciowych"); return

    # _parse_yaml pochodzi z modulu CONFIG (linia ~407)
    try:
        data = _parse_yaml(src_text)
    except Exception as e:
        print_error(f"Blad parsowania YAML: {e}"); return

    if validate:
        print_info(f"YAML prawidlowy  ({len(data)} kluczy na poziomie glownym)"); return

    if to_json:
        import json as _json
        print(_json.dumps(data, indent=2, ensure_ascii=False))
        return

    # Pretty-print YAML z kolorowaniem
    w = min(terminal_width() - 2, 78)
    print()
    print(box_top(f"YAML  {clean[0] if clean else 'stdin'}", width=w, color=C.KEYWORD))
    for k, v in data.items():
        if isinstance(v, list):
            print(box_row(f"  {C.KEYWORD}{k}:{C.RESET}", width=w, color=C.KEYWORD))
            for item in v:
                print(box_row(f"    {C.DIM}• {C.PATH}{item}{C.RESET}", width=w, color=C.KEYWORD))
        elif isinstance(v, bool):
            col = C.PATH if v else C.ERROR
            print(box_row(f"  {C.KEYWORD}{k}:{C.RESET}  {col}{str(v).lower()}{C.RESET}",
                          width=w, color=C.KEYWORD))
        elif isinstance(v, (int, float)):
            print(box_row(f"  {C.KEYWORD}{k}:{C.RESET}  {C.NUMBER}{v}{C.RESET}",
                          width=w, color=C.KEYWORD))
        elif v is None:
            print(box_row(f"  {C.KEYWORD}{k}:{C.RESET}  {C.DIM}null{C.RESET}",
                          width=w, color=C.KEYWORD))
        else:
            print(box_row(f"  {C.KEYWORD}{k}:{C.RESET}  {C.PATH}{v}{C.RESET}",
                          width=w, color=C.KEYWORD))
    print(box_bottom(width=w, color=C.KEYWORD))
    print(f"  {C.DIM}{len(data)} kluczy  |  yaml --to-json <plik> — eksport do JSON{C.RESET}\n")

# ── JQ (mini) ────────────────────────────────────────────────────────────────

@command("jq", "Mini jq — zapytania JSON (stdlib, bez binarki jq)",
         aliases=["jsonquery", "jsonpath"])
def cmd_jq(args):
    """
    jq <wyrazenie> <plik>   — zapytanie do JSON
    jq <wyrazenie>          — czytaj ze stdin
    jq . <plik>             — pretty-print (jak jq .)
    jq .klucz <plik>        — wartosc klucza
    jq .tablica[2] <plik>   — element tablicy
    jq .a.b.c <plik>        — zagniezdzone klucze
    jq 'keys' <plik>        — lista kluczy
    jq 'length' <plik>      — liczba elementow
    jq 'type' <plik>        — typ wartosci
    jq '.[] | .pole' <plik> — iteracja tablicy, wypisz pole

    Skladnia: podzbior jq — .klucz  .klucz[N]  .a.b  keys  length  type  .[]
    """
    _json = json   # json importowany na poziomie modułu

    if not args:
        print_error("Uzycie: jq <wyrazenie> [plik]"); return

    expr      = args[0]
    src_text  = ""
    if len(args) >= 2:
        fpath = Path(args[1]).expanduser()
        try:
            src_text = fpath.read_text(encoding="utf-8")
        except FileNotFoundError:
            print_error(f"Plik nie istnieje: {args[1]}"); return
        except Exception as e:
            print_error(f"Blad odczytu: {e}"); return
    else:
        try:
            src_text = sys.stdin.read()
        except KeyboardInterrupt:
            return

    try:
        data = _json.loads(src_text)
    except _json.JSONDecodeError as e:
        print_error(f"Nieprawidlowy JSON: {e}"); return

    def _jq_eval(expr: str, obj):
        """Ewaluuje prosty wyrazenie jq na obiekcie."""
        expr = expr.strip()

        if expr in (".", ""):
            return obj

        if expr == "keys":
            if isinstance(obj, dict):   return list(obj.keys())
            if isinstance(obj, list):   return list(range(len(obj)))
            return []

        if expr == "length":
            if isinstance(obj, (dict, list, str)): return len(obj)
            return 0

        if expr == "type":
            return {dict:"object", list:"array", str:"string",
                    int:"number", float:"number", bool:"boolean",
                    type(None):"null"}.get(type(obj), "unknown")

        if expr == "values":
            if isinstance(obj, dict): return list(obj.values())
            if isinstance(obj, list): return obj
            return []

        if expr == ".[]":
            if isinstance(obj, (dict, list)):
                return list(obj.values()) if isinstance(obj, dict) else obj
            return []

        # Pipe: .[] | .pole
        if " | " in expr:
            parts = expr.split(" | ", 1)
            left  = _jq_eval(parts[0], obj)
            if isinstance(left, list):
                results = []
                for item in left:
                    r = _jq_eval(parts[1], item)
                    if r is not None:
                        results.append(r)
                return results
            return _jq_eval(parts[1], left)

        # Sciezka: .a.b[2].c
        if expr.startswith("."):
            path = expr[1:]
            cur  = obj
            for part in _RE_JSON_PATH.split(path):
                if not part: continue
                if isinstance(cur, dict):
                    cur = cur.get(part)
                elif isinstance(cur, list):
                    try:   cur = cur[int(part)]
                    except (ValueError, IndexError): return None
                else:
                    return None
            return cur

        return None

    result = _jq_eval(expr, data)

    def _pretty(val):
        if val is None:
            print(f"{C.DIM}null{C.RESET}")
        elif isinstance(val, (dict, list)):
            txt = _json.dumps(val, indent=2, ensure_ascii=False)
            # Prosta koloryzacja
            for line in txt.splitlines():
                m = _RE_JQ_KEY.match(line)
                if m:
                    print(f"{m.group(1)}{C.KEYWORD}{m.group(2)}{C.RESET}{m.group(3)}{m.group(4)}")
                else:
                    line2 = _RE_JSON_BOOL.sub(
                        lambda x: f"{C.INFO}{x.group()}{C.RESET}", line)
                    line2 = _RE_JQ_NUM.sub(
                        lambda x: f": {C.NUMBER}{x.group(1)}{C.RESET}", line2)
                    print(line2)
        elif isinstance(val, str):
            print(f"{C.PATH}\"{val}\"{C.RESET}")
        elif isinstance(val, bool):
            print(f"{C.INFO}{str(val).lower()}{C.RESET}")
        elif isinstance(val, (int, float)):
            print(f"{C.NUMBER}{val}{C.RESET}")
        else:
            print(val)

    _pretty(result)

