@command("base64", "Kodowanie / dekodowanie base64",
         aliases=["b64", "b64encode", "b64decode"],
         flags=["-d", "-f"])
def cmd_base64_tool(args):
    """
    base64 <tekst>         — zakoduj tekst do base64
    base64 -d <tekst>      — dekoduj z base64
    base64 -f <plik>       — zakoduj plik
    base64 -d -f <plik>    — dekoduj plik base64
    base64 -f -o <plik>    — zakoduj i zapisz do pliku
    """
    import base64 as _b64

    decode   = "-d" in args
    from_file = "-f" in args
    out_file  = None
    if "-o" in args:
        idx = args.index("-o")
        if idx + 1 < len(args):
            out_file = Path(args[idx + 1])

    clean = [a for a in args if not a.startswith("-") and a != (out_file.name if out_file else "")]

    raw = b""
    if from_file:
        if not clean:
            print_error("Podaj nazwe pliku po -f"); return
        fpath = Path(clean[0]).expanduser()
        try:
            raw = fpath.read_bytes()
        except FileNotFoundError:
            print_error(f"Plik nie istnieje: {fpath}"); return
        except Exception as e:
            print_error(f"Blad odczytu: {e}"); return
    elif clean:
        raw = " ".join(clean).encode("utf-8")
    else:
        try:
            raw = sys.stdin.buffer.read()
        except KeyboardInterrupt:
            return

    if not raw:
        print_error("Brak danych wejsciowych"); return

    try:
        if decode:
            # Napraw padding jesli brakuje
            padded = raw.rstrip() + b"=" * (-len(raw.rstrip()) % 4)
            result = _b64.b64decode(padded)
            if out_file:
                out_file.write_bytes(result)
                print_info(f"Zdekodowano → {out_file}  ({_human_size(len(result))})")
            else:
                try:
                    print(result.decode("utf-8"))
                except UnicodeDecodeError:
                    print(f"{C.DIM}(dane binarne — {len(result)} bajtow){C.RESET}")
                    print(result.hex())
        else:
            result = _b64.b64encode(raw)
            if out_file:
                out_file.write_bytes(result)
                print_info(f"Zakodowano → {out_file}  ({_human_size(len(result))})")
            else:
                # Zawijaj co 76 znakow (RFC 2045)
                encoded_str = result.decode("ascii")
                for i in range(0, len(encoded_str), 76):
                    print(encoded_str[i:i+76])
    except Exception as e:
        print_error(f"Blad base64: {e}")

# ── HEXDUMP ───────────────────────────────────────────────────────────────────

@command("hexdump", "Podglad binarny pliku (hex + ASCII)",
         aliases=["xxd", "hd", "hexview"],
         flags=["-n", "-s", "-C"])
def cmd_hexdump(args):
    """
    hexdump <plik>          — pierwsze 256 bajtow
    hexdump -n 512 <plik>   — pierwsze N bajtow
    hexdump -s 128 <plik>   — zacznij od offsetu N
    hexdump -C <plik>       — format jak xxd (offset + hex + ASCII)
    hexdump --strings <plik>— wypisz drukowalne stringi (min. 4 znaki)
    """
    offset = 0
    count  = 256
    clean  = []
    strings_mode = "--strings" in args

    i = 0
    while i < len(args):
        a = args[i]
        if a == "-n" and i + 1 < len(args):
            try:    count  = int(args[i+1]); i += 1
            except ValueError: pass
        elif a == "-s" and i + 1 < len(args):
            try:    offset = int(args[i+1]); i += 1
            except ValueError: pass
        elif not a.startswith("-"):
            clean.append(a)
        i += 1

    if not clean:
        print_error("Podaj nazwe pliku"); return

    fpath = Path(clean[0]).expanduser()
    if not fpath.exists():
        print_error(f"Plik nie istnieje: {fpath}"); return

    try:
        with fpath.open("rb") as f:
            f.seek(offset)
            data = f.read(count)
    except Exception as e:
        print_error(f"Blad odczytu: {e}"); return

    if not data:
        print_info("Plik pusty lub offset poza koncem pliku"); return

    if strings_mode:
        # Wypisz drukowalne stringi dluzsze niz 3 znaki
        current = []
        for byte in data:
            ch = chr(byte)
            if ch.isprintable() and byte >= 0x20:
                current.append(ch)
            else:
                if len(current) >= 4:
                    print("".join(current))
                current = []
        if len(current) >= 4:
            print("".join(current))
        return

    # Format hex + ASCII (jak xxd / hexdump -C)
    BYTES_PER_ROW = 16
    w = min(terminal_width() - 2, 78)
    fname = fpath.name
    size  = fpath.stat().st_size
    print()
    print(box_top(f"hexdump  {fname}  ({_human_size(size)})", width=w, color=C.CODE))
    print(box_row(
        f"  {C.DIM}{'OFFSET':<10} {'HEX (16 bajtow)':<50} {'ASCII':<16}{C.RESET}",
        width=w, color=C.CODE))
    print(box_sep(width=w, color=C.CODE))

    for row_start in range(0, len(data), BYTES_PER_ROW):
        chunk = data[row_start:row_start + BYTES_PER_ROW]
        off   = offset + row_start

        hex_parts = []
        for j, b in enumerate(chunk):
            hex_parts.append(f"{b:02x}")
            if j == 7:
                hex_parts.append(" ")   # separator w polowie
        hex_str = " ".join(hex_parts).ljust(49)

        ascii_str = "".join(
            chr(b) if 0x20 <= b < 0x7f else "."
            for b in chunk
        )

        print(box_row(
            f"  {C.DIM}{off:08x}{C.RESET}  {C.CODE}{hex_str}{C.RESET}  {C.DIM}|{ascii_str}|{C.RESET}",
            width=w, color=C.CODE))

    total_shown = len(data)
    remaining   = size - offset - total_shown
    print(box_sep(width=w, color=C.CODE))
    info_parts = [f"{total_shown} bajtow pokazanych"]
    if remaining > 0:
        info_parts.append(f"{remaining} pozostalych (hexdump -n {total_shown + remaining} aby zobaczyc wiecej)")
    print(box_row(f"  {C.DIM}{' | '.join(info_parts)}{C.RESET}", width=w, color=C.CODE))
    print(box_bottom(width=w, color=C.CODE))
    print()

# ── DIFF ──────────────────────────────────────────────────────────────────────

@command("diff", "Porownanie dwoch plikow (unified diff)",
         aliases=["compare", "cmp"],
         flags=["-u", "-n", "--stat"])
def cmd_diff(args):
    """
    diff <plik1> <plik2>      — unified diff (domyslnie 3 linie kontekstu)
    diff -n 5 <plik1> <plik2> — N linii kontekstu
    diff --stat <p1> <p2>     — tylko statystyki (bez treści)
    diff --side <p1> <p2>     — widok side-by-side (jesli terminal >= 100 kol)

    Kodowanie kolorow:
      Zielony (+)  — dodane linie
      Czerwony (-) — usuniete linie
      Niebieski    — naglowki hunka
    """
    import difflib as _diff

    context   = 3
    stat_only    = "--stat" in args
    side_by_side = "--side" in args
    clean        = []

    i = 0
    while i < len(args):
        a = args[i]
        if a == "-n" and i + 1 < len(args):
            try:    context = int(args[i+1]); i += 1
            except ValueError: pass
        elif not a.startswith("-"):
            clean.append(a)
        i += 1

    if len(clean) < 2:
        print_error("Podaj dwa pliki: diff <plik1> <plik2>"); return

    paths = [Path(clean[0]).expanduser(), Path(clean[1]).expanduser()]
    texts = []
    for p in paths:
        if not p.exists():
            print_error(f"Plik nie istnieje: {p}"); return
        try:
            texts.append(p.read_text(encoding="utf-8", errors="replace").splitlines(keepends=True))
        except Exception as e:
            print_error(f"Blad odczytu {p}: {e}"); return

    a_lines, b_lines = texts

    if stat_only:
        # Szybkie podsumowanie
        sm = _diff.SequenceMatcher(None, a_lines, b_lines)
        ratio = sm.ratio()
        adds = dels = 0
        for tag, i1, i2, j1, j2 in sm.get_opcodes():
            if tag == "replace":
                dels += i2 - i1; adds += j2 - j1
            elif tag == "insert":
                adds += j2 - j1
            elif tag == "delete":
                dels += i2 - i1
        changed = adds + dels
        print()
        w = min(terminal_width() - 2, 60)
        print(box_top(f"diff  {paths[0].name}  vs  {paths[1].name}", width=w, color=C.DIM))
        print(box_row(kv_row("Podobienstwo", f"{ratio*100:.1f}%", key_color=C.DIM), width=w, color=C.DIM))
        print(box_row(kv_row("Dodane linie",  f"{C.PATH}+{adds}{C.RESET}",  key_color=C.DIM), width=w, color=C.DIM))
        print(box_row(kv_row("Usuniete linie",f"{C.ERROR}-{dels}{C.RESET}", key_color=C.DIM), width=w, color=C.DIM))
        print(box_row(kv_row("Zmienionych",   str(changed), key_color=C.DIM), width=w, color=C.DIM))
        print(box_bottom(width=w, color=C.DIM))
        print()
        return

    # Side-by-side diff
    if side_by_side:
        tw = terminal_width()
        if tw < 100:
            print_warn(f"Terminal za wąski ({tw} kol) dla --side. Potrzeba >= 100. Wyświetlam unified.")
            side_by_side = False
        else:
            sm = _diff.SequenceMatcher(None, a_lines, b_lines)
            half = (tw - 5) // 2
            print()
            header_l = f"{paths[0].name}"[:half].ljust(half)
            header_r = f"{paths[1].name}"[:half].ljust(half)
            print(f"  {C.BOLD}{header_l}{C.RESET}  {C.DIM}│{C.RESET}  {C.BOLD}{header_r}{C.RESET}")
            print(f"  {C.DIM}{'─'*half}─┼─{'─'*half}{C.RESET}")
            adds = dels = 0
            for tag, i1, i2, j1, j2 in sm.get_opcodes():
                block_a = a_lines[i1:i2]
                block_b = b_lines[j1:j2]
                for la, lb in zip(block_a + [""]*max(0,len(block_b)-len(block_a)),
                                  block_b + [""]*max(0,len(block_a)-len(block_b))):
                    la = la.rstrip("\n"); lb = lb.rstrip("\n")
                    if tag == "equal":
                        cl = cr = C.DIM
                    elif tag == "replace":
                        cl = cr = C.INFO; adds += 1; dels += 1
                    elif tag == "insert":
                        cl = C.DIM; cr = C.PATH; adds += 1
                    else:  # delete
                        cl = C.ERROR; cr = C.DIM; dels += 1
                    la_d = la[:half].ljust(half)
                    lb_d = lb[:half].ljust(half)
                    print(f"  {cl}{la_d}{C.RESET}  {C.DIM}│{C.RESET}  {cr}{lb_d}{C.RESET}")
            print(f"\n  {C.DIM}{C.PATH}+{adds}{C.RESET}  {C.ERROR}-{dels}{C.RESET}\n")
            return

    # Unified diff z kolorowaniem
    udiff = list(_diff.unified_diff(
        a_lines, b_lines,
        fromfile=str(paths[0]),
        tofile=str(paths[1]),
        n=context))

    if not udiff:
        print_info(f"Pliki sa identyczne: {paths[0].name}  ==  {paths[1].name}")
        return

    adds = sum(1 for l in udiff if l.startswith("+") and not l.startswith("+++"))
    dels = sum(1 for l in udiff if l.startswith("-") and not l.startswith("---"))

    print()
    for line in udiff:
        line_stripped = line.rstrip("\n")
        if line_stripped.startswith("+++") or line_stripped.startswith("---"):
            print(f"{C.BOLD}{line_stripped}{C.RESET}")
        elif line_stripped.startswith("@@"):
            print(f"{C.KEYWORD}{line_stripped}{C.RESET}")
        elif line_stripped.startswith("+"):
            print(f"{C.PATH}{line_stripped}{C.RESET}")
        elif line_stripped.startswith("-"):
            print(f"{C.ERROR}{line_stripped}{C.RESET}")
        else:
            print(f"{C.DIM}{line_stripped}{C.RESET}")

    print(f"\n  {C.DIM}{C.PATH}+{adds} linii{C.RESET}  {C.ERROR}-{dels} linii{C.RESET}  "
          f"{C.DIM}| diff --stat aby zobaczyc tylko podsumowanie{C.RESET}\n")

# ── TIMEIT ────────────────────────────────────────────────────────────────────

@command("timeit", "Pomiar czasu wykonania komendy shella",
         aliases=["time", "benchmark", "bench"],
         flags=["-r"])
def cmd_timeit(args):
    """
    timeit <komenda>          — zmierz czas komendy (1 powtorzenie)
    timeit -r 5 <komenda>     — powtorz N razy i podaj srednia
    timeit -r 10 ls -la       — przyklad: 10 pomiarow ls

    Mierzy: real (elapsed), user CPU, sys CPU.
    Wyswietla min/max/srednia przy wiecej niz 1 powtorzeniu.
    """
    import time as _time

    repeats = 1
    clean   = list(args)

    if "-r" in clean:
        idx = clean.index("-r")
        if idx + 1 < len(clean):
            try:
                repeats = max(1, int(clean[idx + 1]))
                del clean[idx:idx + 2]
            except ValueError:
                pass

    if not clean:
        print_error("Podaj komende do zmierzenia: timeit [-r N] <komenda>"); return

    cmd_str = " ".join(clean)
    times   = []
    print_info(f"Mierzenie: {cmd_str}  ({repeats}x)")
    print()

    for i in range(repeats):
        t_start  = _time.monotonic()
        cpu_start = _time.process_time()
        try:
            execute_line(cmd_str)
        except SystemExit:
            pass
        except Exception as e:
            print_error(f"Blad komendy: {e}"); return
        t_end    = _time.monotonic()
        cpu_end  = _time.process_time()
        elapsed  = t_end  - t_start
        cpu_used = cpu_end - cpu_start
        times.append((elapsed, cpu_used))
        if repeats > 1:
            print(f"  {C.DIM}[{i+1}/{repeats}]  real: {elapsed*1000:.2f}ms  "
                  f"cpu: {cpu_used*1000:.2f}ms{C.RESET}")

    w = min(terminal_width() - 2, 60)
    print()
    print(box_top(f"timeit  {cmd_str[:40]}", width=w, color=C.EXEC))

    reals = [t[0] for t in times]
    cpus  = [t[1] for t in times]

    def _fmt(s: float) -> str:
        if s >= 1.0:    return f"{s:.3f} s"
        if s >= 0.001:  return f"{s*1000:.2f} ms"
        return f"{s*1e6:.1f} µs"

    if repeats == 1:
        print(box_row(kv_row("real (elapsed)", _fmt(reals[0]), key_color=C.DIM), width=w, color=C.EXEC))
        print(box_row(kv_row("CPU (process)",  _fmt(cpus[0]),  key_color=C.DIM), width=w, color=C.EXEC))
    else:
        import statistics as _stat
        print(box_row(kv_row("Powtorzenia", str(repeats), key_color=C.DIM), width=w, color=C.EXEC))
        print(box_sep(width=w, color=C.EXEC))
        print(box_row(kv_row("Min real",  _fmt(min(reals)),           key_color=C.DIM), width=w, color=C.EXEC))
        print(box_row(kv_row("Max real",  _fmt(max(reals)),           key_color=C.DIM), width=w, color=C.EXEC))
        print(box_row(kv_row("Srednia",   _fmt(_stat.mean(reals)),    key_color=C.DIM), width=w, color=C.EXEC))
        if repeats > 2:
            print(box_row(kv_row("Odch.std", _fmt(_stat.stdev(reals)), key_color=C.DIM), width=w, color=C.EXEC))
        print(box_sep(width=w, color=C.EXEC))
        print(box_row(kv_row("Lacznie",   _fmt(sum(reals)),           key_color=C.DIM), width=w, color=C.EXEC))

    print(box_bottom(width=w, color=C.EXEC))
    print()

# ── PYREPL ────────────────────────────────────────────────────────────────────

@command("pyrepl", "Mini interaktywny REPL Pythona (wbudowany)",
         aliases=["python", "py", "repl", "pyconsole"])
def cmd_pyrepl(args):
    """
    pyrepl            — uruchom mini REPL Pythona
    pyrepl <plik.py>  — wykonaj plik Python i wejdz w REPL z jego przestrzenia
    pyrepl -c <kod>   — wykonaj jednorazowo wyrazenie lub instrukcje
    pyrepl -e <plik>  — edytuj plik w nano-lite i wykonaj

    Dostepne: wszystkie moduły stdlib, zmienna 'shell' z API TerminalXa.
    Historia: strzalki gora/dol (jesli readline dostepne).
    Wyjscie: exit() / quit() / Ctrl+D / Ctrl+C dwukrotnie.

    Zmienne shella dostepne jako: shell.SHELL_VARS, shell.cfg(), shell.Path
    """
    import code as _code
    import traceback as _tb

    # Budujemy przestrzen nazw dla REPL
    repl_ns: dict = {
        "__name__":    "__pyrepl__",
        "__doc__":     "TerminalX pyrepl",
        "shell":       type("ShellNS", (), {
            "SHELL_VARS": SHELL_VARS,
            "cfg":        cfg,
            "Path":       Path,
            "execute":    execute_line,
            "print_info":    print_info,
            "print_ok":      print_ok,
            "print_warn":    print_warn,
            "print_error":   print_error,
            "print_hint":    print_hint,
            "section_header":section_header,
            "box_top":       box_top,
            "box_row":       box_row,
            "box_bottom":    box_bottom,
            "box_sep":       box_sep,
            "SHELL_VERSION": SHELL_VERSION,
            "BASE":       _BASE,
        })(),
        "Path":        Path,
        "os":          os,
        "sys":         sys,
        "re":          re,
        "json":        __import__("json"),
        "datetime":    datetime,
    }

    # Jednorazowe wykonanie kodu
    if "-c" in args:
        idx = args.index("-c")
        code_args = args[idx + 1:]
        if not code_args:
            print_error("Podaj kod po -c: pyrepl -c \"print(1+1)\""); return
        code_str = " ".join(code_args)
        try:
            exec(compile(code_str, "<pyrepl -c>", "exec"), repl_ns)  # noqa: S102
        except Exception:
            _tb.print_exc()
        return

    # Wczytaj plik jesli podany
    run_file = None
    if args and not args[0].startswith("-"):
        run_file = Path(args[0]).expanduser()
        if not run_file.exists():
            print_error(f"Plik nie istnieje: {run_file}"); return
        try:
            src = run_file.read_text(encoding="utf-8")
            print_info(f"Wykonuje: {run_file}")
            exec(compile(src, str(run_file), "exec"), repl_ns)  # noqa: S102
        except SystemExit:
            return
        except Exception:
            _tb.print_exc()

    # Opcja -e: edytuj i wykonaj
    if "-e" in args:
        idx = args.index("-e")
        edit_args = args[idx + 1:]
        if not edit_args:
            print_error("Podaj plik po -e"); return
        epath = Path(edit_args[0]).expanduser()
        execute_line(f"nano {epath}")
        if epath.exists():
            try:
                src = epath.read_text(encoding="utf-8")
                exec(compile(src, str(epath), "exec"), repl_ns)  # noqa: S102
                print_info(f"Wykonano: {epath}")
            except Exception:
                _tb.print_exc()
        return

    # Interaktywny REPL
    banner = (
        f"\n  {C.BOLD}{C.PATH}TerminalX pyrepl{C.RESET}  "
        f"{C.DIM}Python {sys.version.split()[0]}  |  exit() = wyjdz{C.RESET}\n"
        f"  {C.DIM}Dostepne: os, sys, re, json, datetime, Path, shell.*{C.RESET}\n"
        f"  {C.DIM}shell.execute('ls')  —  wywoluj komendy shella z poziomu REPL{C.RESET}\n"
    )

    console = _code.InteractiveConsole(locals=repl_ns)
    try:
        console.interact(banner=banner, exitmsg=f"\n  {C.DIM}Wyjscie z pyrepl.{C.RESET}")
    except SystemExit:
        pass
    except KeyboardInterrupt:
        print()

# MINI-DEBUGGER

#
#  Mini-debugger dla skryptów TerminalXa (pliki .sh z komendami shella).
#
#  Tryby:
#    debug <plik>          — wykonaj krok po kroku (step mode)
#    debug -r <plik>       — wykonaj bez przerw, ale loguj kazda linie
#    debug -b <N> <plik>   — ustaw breakpoint na linii N
#    debug -w <ZMIENNA>    — watchpoint: zatrzymaj gdy zmienna sie zmieni
#    debug --trace <plik>  — tylko trace (bez interakcji, wynik do stdout)
#
#  Komendy interaktywne (w trybie step):
#    n / next    — nastepna linia
#    s / skip    — pomin biezaca linie
#    r / run     — wykonaj bez zatrzymywania do konca
#    b <N>       — dodaj breakpoint na linii N
#    rb <N>      — usun breakpoint
#    lb          — lista breakpointow
#    w <VAR>     — dodaj watchpoint
#    rw <VAR>    — usun watchpoint
#    p <VAR>     — wypisz wartosc zmiennej shella
#    vars        — wszystkie zmienne shella
#    q / quit    — przerwij debug
#    h / help    — pomoc

class MiniDebugger:
    """
    Krokowy debugger skryptów TerminalXa.
    Obsluguje pliki .sh zawierajace komendy shella (jeden na linie).
    """

    PROMPT_STEP  = None   # ustawiany w __init__ z kolorow
    PROMPT_BREAK = None

    def __init__(self, script_path: Path):
        self.script_path = script_path
        self.lines:       list[str]  = []
        self.breakpoints: set[int]   = set()
        self.watchpoints: set[str]   = set()
        self._watch_vals: dict       = {}
        self.step_mode   = True
        self.running     = False
        self.current_line = 0
        self._exec_log:   list[tuple] = []   # (lineno, line, result)

        self.PROMPT_STEP  = f"  {C.NUMBER}dbg>{C.RESET} "
        self.PROMPT_BREAK = f"  {C.ERROR}BRK>{C.RESET} "

    def load(self) -> bool:
        try:
            raw = self.script_path.read_text(encoding="utf-8", errors="replace")
            self.lines = raw.splitlines()
            return True
        except Exception as e:
            print_error(f"Nie mozna wczytac skryptu: {e}")
            return False

    def _banner(self):
        w = min(terminal_width() - 2, 72)
        print()
        print(box_top(f"mini-debugger  {self.script_path.name}  ({len(self.lines)} linii)",
                      width=w, color=C.ERROR))
        print(box_row(
            f"  {C.DIM}Komendy: n=krok  s=pomin  r=uruchom  b N=breakpoint  "
            f"p VAR=wartosc  q=koniec  h=pomoc{C.RESET}",
            width=w, color=C.ERROR))
        print(box_bottom(width=w, color=C.ERROR))
        print()

    def _show_context(self, lineno: int, context: int = 2):
        """Wyswietla aktualna linie + kontekst."""
        w = min(terminal_width() - 2, 72)
        start = max(0, lineno - context)
        end   = min(len(self.lines), lineno + context + 1)
        print(box_top(f"Linia {lineno + 1}/{len(self.lines)}", width=w, color=C.DIM))
        for i in range(start, end):
            line_text = self.lines[i]
            is_current = (i == lineno)
            is_break   = (i + 1) in self.breakpoints
            marker = ""
            if is_current and is_break:
                marker = f"{C.ERROR}►B{C.RESET}"
            elif is_current:
                marker = f"{C.PATH}► {C.RESET}"
            elif is_break:
                marker = f"{C.ERROR} B{C.RESET}"
            else:
                marker = f"  "
            # Kolor linii
            if is_current:
                text_col = C.BOLD
            elif is_break:
                text_col = C.INFO
            else:
                text_col = C.DIM
            skip_mark = ""
            if line_text.strip().startswith("#") or not line_text.strip():
                skip_mark = f" {C.DIM}(pomijam){C.RESET}"
            print(box_row(
                f" {marker} {C.DIM}{i+1:3d}{C.RESET}  {text_col}{line_text.rstrip()}{C.RESET}{skip_mark}",
                width=w, color=C.DIM))
        print(box_bottom(width=w, color=C.DIM))

    def _check_watchpoints(self):
        """Sprawdza czy wartosc zmiennych watchpoint sie zmienila."""
        triggered = []
        for var in self.watchpoints:
            new_val = SHELL_VARS.get(var, os.environ.get(var, "<niezdefiniowana>"))
            old_val = self._watch_vals.get(var, "<niezdefiniowana>")
            if str(new_val) != str(old_val):
                triggered.append((var, old_val, new_val))
                self._watch_vals[var] = new_val
        return triggered

    def _init_watchpoints(self):
        for var in self.watchpoints:
            self._watch_vals[var] = SHELL_VARS.get(var, os.environ.get(var, "<niezdefiniowana>"))

    def _exec_line(self, line: str, lineno: int) -> int:
        """Wykonuje jedna linie skryptu. Zwraca exit code."""
        stripped = line.strip()
        if not stripped or stripped.startswith("#"):
            return 0
        print(f"  {C.DIM}[{lineno+1}] {C.RESET}{C.EXEC}{stripped}{C.RESET}")
        try:
            execute_line(stripped)
            self._exec_log.append((lineno + 1, stripped, "OK"))
            return 0
        except SystemExit as e:
            code = e.code if isinstance(e.code, int) else 0
            self._exec_log.append((lineno + 1, stripped, f"exit({code})"))
            return code
        except Exception as e:
            self._exec_log.append((lineno + 1, stripped, f"ERR:{e}"))
            print_error(f"Blad w linii {lineno+1}: {e}")
            return 1

    def _interactive_prompt(self, lineno: int) -> str:
        """Czeka na komende uzytkownika."""
        is_break = (lineno + 1) in self.breakpoints
        prompt   = self.PROMPT_BREAK if is_break else self.PROMPT_STEP
        try:
            return input(prompt).strip()
        except (EOFError, KeyboardInterrupt):
            return "q"

    def _show_help(self):
        w = min(terminal_width() - 2, 66)
        print()
        print(box_top("mini-debugger — pomoc", width=w, color=C.INFO))
        cmds = [
            ("n, next",     "Wykonaj biezaca linie i przejdz do nastepnej"),
            ("s, skip",     "Pomin biezaca linie bez wykonania"),
            ("r, run",      "Wykonaj do konca bez zatrzymywania"),
            ("q, quit",     "Przerwij debugowanie"),
            ("b <N>",       "Dodaj breakpoint na linii N"),
            ("rb <N>",      "Usun breakpoint z linii N"),
            ("lb",          "Lista wszystkich breakpointow"),
            ("w <ZMN>",     "Watchpoint — zatrzymaj gdy zmienna sie zmieni"),
            ("rw <ZMN>",    "Usun watchpoint"),
            ("p <ZMN>",     "Wypisz wartosc zmiennej shella"),
            ("vars",        "Wyswietl wszystkie zmienne SHELL_VARS"),
            ("log",         "Wyswietl log wykonanych linii"),
            ("g <N>",       "Skocz do linii N (goto — bez wykonania linii posrednich)"),
            ("h, help",     "Ta pomoc"),
        ]
        for cmd_name, desc in cmds:
            print(box_row(f"  {C.KEYWORD}{cmd_name:<12}{C.RESET}  {C.DIM}{desc}{C.RESET}",
                          width=w, color=C.INFO))
        print(box_bottom(width=w, color=C.INFO))
        print()

    def run_step(self, start_line: int = 0):
        """Wykonuje skrypt w trybie krokowym."""
        self._banner()
        self._init_watchpoints()
        i = start_line

        while i < len(self.lines):
            line = self.lines[i]
            stripped = line.strip()

            # Sprawdz watchpointy
            wt = self._check_watchpoints()
            for var, old, new in wt:
                print(f"  {C.ERROR}WATCHPOINT{C.RESET}  "
                      f"{C.KEYWORD}{var}{C.RESET}: "
                      f"{C.DIM}{old!r}{C.RESET} → {C.PATH}{new!r}{C.RESET}")

            # Breakpoint
            at_break = (i + 1) in self.breakpoints
            if at_break:
                print(f"\n  {C.ERROR}● BREAKPOINT  linia {i+1}{C.RESET}")

            # Pokaz kontekst jesli linia nie jest pusta/komentarzem lub jest breakpoint
            if stripped and not stripped.startswith("#"):
                self._show_context(i)
            else:
                print(f"  {C.DIM}{i+1:3d}  (pusta/komentarz — pomijam){C.RESET}")
                i += 1
                continue

            # Jesli step_mode lub breakpoint — czekaj na komende
            if self.step_mode or at_break:
                while True:
                    cmd_raw = self._interactive_prompt(i)
                    parts   = cmd_raw.split()
                    cmd0    = parts[0].lower() if parts else ""

                    if cmd0 in ("n", "next", ""):
                        self._exec_line(line, i)
                        i += 1
                        break
                    elif cmd0 in ("s", "skip"):
                        print(f"  {C.DIM}Pominieto linie {i+1}{C.RESET}")
                        i += 1
                        break
                    elif cmd0 in ("r", "run"):
                        self.step_mode = False
                        self._exec_line(line, i)
                        i += 1
                        break
                    elif cmd0 in ("q", "quit"):
                        print_info("Debugowanie przerwane przez uzytkownika.")
                        return
                    elif cmd0 == "b" and len(parts) >= 2:
                        try:
                            bp = int(parts[1])
                            self.breakpoints.add(bp)
                            print_info(f"Breakpoint dodany: linia {bp}")
                        except ValueError:
                            print_error("Podaj numer linii: b <N>")
                    elif cmd0 == "rb" and len(parts) >= 2:
                        try:
                            bp = int(parts[1])
                            self.breakpoints.discard(bp)
                            print_info(f"Breakpoint usuniety: linia {bp}")
                        except ValueError:
                            print_error("Podaj numer linii: rb <N>")
                    elif cmd0 == "lb":
                        if self.breakpoints:
                            print_info(f"Breakpointy: {sorted(self.breakpoints)}")
                        else:
                            print_info("Brak breakpointow.")
                    elif cmd0 == "w" and len(parts) >= 2:
                        var = parts[1]
                        self.watchpoints.add(var)
                        self._watch_vals[var] = SHELL_VARS.get(var, os.environ.get(var, "<niezdefiniowana>"))
                        print_info(f"Watchpoint: {var} = {self._watch_vals[var]!r}")
                    elif cmd0 == "rw" and len(parts) >= 2:
                        self.watchpoints.discard(parts[1])
                        print_info(f"Watchpoint usuniety: {parts[1]}")
                    elif cmd0 == "p" and len(parts) >= 2:
                        var = parts[1]
                        val = SHELL_VARS.get(var, os.environ.get(var, "<niezdefiniowana>"))
                        print(f"  {C.KEYWORD}{var}{C.RESET} = {C.PATH}{val!r}{C.RESET}")
                    elif cmd0 == "vars":
                        if SHELL_VARS:
                            for k, v in sorted(SHELL_VARS.items()):
                                print(f"  {C.KEYWORD}{k:<18}{C.RESET} = {C.PATH}{v!r}{C.RESET}")
                        else:
                            print_info("Brak zmiennych SHELL_VARS.")
                    elif cmd0 == "log":
                        if self._exec_log:
                            for ln, lc, res in self._exec_log[-20:]:
                                col = C.PATH if res == "OK" else C.ERROR
                                print(f"  {C.DIM}{ln:3d}{C.RESET}  {lc[:50]:<50}  {col}{res}{C.RESET}")
                        else:
                            print_info("Log jest pusty.")
                    elif cmd0 == "g" and len(parts) >= 2:
                        try:
                            goto = int(parts[1]) - 1
                            if 0 <= goto < len(self.lines):
                                i = goto
                                break
                            else:
                                print_error(f"Linia {parts[1]} poza zakresem (1-{len(self.lines)})")
                        except ValueError:
                            print_error("Podaj numer linii: g <N>")
                    elif cmd0 in ("h", "help"):
                        self._show_help()
                    elif cmd_raw:
                        # Sprobuj wykonac jako komende shella inline
                        print(f"  {C.DIM}[inline]{C.RESET} {cmd_raw}")
                        try:
                            execute_line(cmd_raw)
                        except Exception as e:
                            print_error(str(e))
            else:
                # Tryb uruchom bez zatrzymywania — sprawdzaj tylko breakpointy
                if at_break:
                    self.step_mode = True   # breakpoint przywraca step mode
                self._exec_line(line, i)
                i += 1

        # Podsumowanie
        w = min(terminal_width() - 2, 64)
        print()
        print(box_top(f"Koniec skryptu  {self.script_path.name}", width=w, color=C.PATH))
        print(box_row(
            kv_row("Wykonano linii", str(len(self._exec_log)), key_color=C.DIM),
            width=w, color=C.PATH))
        errors = [e for _, _, r in self._exec_log if r.startswith("ERR")]
        if errors:
            print(box_row(
                kv_row("Bledy", str(len(errors)), key_color=C.DIM),
                width=w, color=C.PATH))
        print(box_bottom(width=w, color=C.PATH))
        print()

    def run_trace(self):
        """Wykonuje caly skrypt z logowaniem (bez interakcji)."""
        print_info(f"Trace: {self.script_path.name}  ({len(self.lines)} linii)")
        print()
        for i, line in enumerate(self.lines):
            stripped = line.strip()
            if not stripped or stripped.startswith("#"):
                print(f"  {C.DIM}{i+1:3d}  {line.rstrip()}{C.RESET}")
                continue
            print(f"  {C.INFO}{i+1:3d}{C.RESET}  {C.EXEC}{stripped}{C.RESET}")
            code = self._exec_line(line, i)
            if code != 0:
                print(f"       {C.ERROR}exit_code={code}{C.RESET}")
        print()
        print_info(f"Trace zakończony. Wykonano {len(self._exec_log)} linii.")

@command("debug", "Mini-debugger dla skryptow TerminalXa",
         aliases=["dbg", "debugger"],
         flags=["-r", "-b", "-w", "--trace"])
def cmd_debug(args):
    """
    debug <plik.sh>          — debugowanie krokowe
    debug -r <plik.sh>       — wykonaj ze szczegolowym logowaniem
    debug --trace <plik.sh>  — trace (bez interakcji)
    debug -b <N> <plik.sh>   — zacznij z breakpointem na linii N
    debug -w <ZMN> <plik.sh> — zacznij z watchpointem na zmiennej

    Komendy w trybie krokowym:
      n/next  — nastepna linia    s/skip  — pomin
      r/run   — wykonaj do konca  q/quit  — przerwij
      b <N>   — breakpoint        p <ZMN> — wypisz wartosc zmiennej
      vars    — wszystkie zmienne  log    — historia wykonania
      h/help  — pelna pomoc

    Skrypt moze zawierac dowolne komendy TerminalXa (po jednej na linie).
    Linie zaczynajace sie od # sa ignorowane (komentarze).
    """
    if not args:
        print_error("Podaj plik skryptu: debug <plik.sh>"); return

    trace_mode = "--trace" in args
    run_mode   = "-r" in args or trace_mode
    clean      = [a for a in args if not a.startswith("-")]

    if not clean:
        print_error("Podaj plik skryptu: debug [-b N] [-w ZMN] <plik.sh>"); return

    script = Path(clean[0]).expanduser()
    if not script.exists():
        print_error(f"Plik nie istnieje: {script}",
                    "Skrypt moze byc dowolnym plikiem tekstowym z komendami shella")
        return

    dbg = MiniDebugger(script)
    if not dbg.load():
        return

    # Wstepne breakpointy z -b
    i = 0
    while i < len(args):
        if args[i] == "-b" and i + 1 < len(args):
            try:
                dbg.breakpoints.add(int(args[i + 1]))
            except ValueError:
                pass
            i += 2
            continue
        if args[i] == "-w" and i + 1 < len(args):
            dbg.watchpoints.add(args[i + 1])
            i += 2
            continue
        i += 1

    try:
        if trace_mode:
            dbg.run_trace()
        elif run_mode:
            dbg.step_mode = False
            dbg.run_step()
        else:
            dbg.run_step()
    except KeyboardInterrupt:
        print()
        print_info("Debugowanie przerwane (Ctrl+C).")

# FINFO — METADANE PLIKU

#
#  finfo <plik>    — pełne metadane pliku: typ, MIME, kodowanie, hash,
#                    uprawnienia, właściciel, daty, linie/słowa/znaki

@command("finfo", "Pelne metadane pliku (typ, MIME, kodowanie, hash, statystyki)",
         aliases=["fileinfo", "meta", "about"],
         flags=["--json", "--hash"])
def cmd_finfo(args):
    """
    finfo <plik>          — pelne metadane
    finfo --json <plik>   — wynik jako JSON
    finfo --hash <plik>   — dodaj sumy kontrolne (md5+sha256)
    finfo <p1> <p2> ...   — wiele plikow naraz

    Wyswietlane informacje:
      Sciezka bezwzgledna, rozmiar, typ (plik/katalog/link),
      rozszerzenie, MIME (heurystycznie), kodowanie tekstu,
      uprawnienia (rwxrwxrwx), wlasciciel (Linux),
      daty: modyfikacja / dostep / zmiana metadanych,
      dla plikow tekstowych: liczba linii / slow / znakow,
      hash SHA-256 i MD5 (opcjonalnie --hash).
    """
    import stat as _stat_mod
    import json as _json

    as_json  = "--json" in args
    do_hash  = "--hash" in args
    clean    = [a for a in args if not a.startswith("-")]

    if not clean:
        print_error("Podaj nazwe pliku: finfo <plik>"); return

    # MIME heurystyczna na podstawie rozszerzenia
    _MIME = {
        ".py": "text/x-python", ".js": "text/javascript", ".ts": "text/typescript",
        ".html": "text/html", ".css": "text/css", ".xml": "text/xml",
        ".json": "application/json", ".yaml": "text/yaml", ".yml": "text/yaml",
        ".md": "text/markdown", ".txt": "text/plain", ".csv": "text/csv",
        ".sh": "application/x-sh", ".bash": "application/x-sh",
        ".c": "text/x-c", ".cpp": "text/x-c++", ".h": "text/x-c",
        ".rs": "text/x-rust", ".go": "text/x-go", ".java": "text/x-java",
        ".pdf": "application/pdf", ".zip": "application/zip",
        ".tar": "application/x-tar", ".gz": "application/gzip",
        ".jpg": "image/jpeg", ".jpeg": "image/jpeg", ".png": "image/png",
        ".gif": "image/gif", ".svg": "image/svg+xml", ".webp": "image/webp",
        ".mp3": "audio/mpeg", ".wav": "audio/wav", ".mp4": "video/mp4",
        ".mkv": "video/x-matroska", ".exe": "application/x-executable",
        ".dll": "application/x-sharedlib", ".so": "application/x-sharedlib",
        ".log": "text/plain", ".sql": "application/sql",
        ".toml": "application/toml", ".ini": "text/plain",
        ".docx": "application/vnd.openxmlformats-officedocument.wordprocessingml.document",
        ".xlsx": "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
    }

    def _detect_encoding(raw: bytes) -> str:
        """Heurystyczne wykrywanie kodowania na podstawie BOM i analizy bajtow."""
        if raw[:3] == b'\xef\xbb\xbf':   return "utf-8-bom"
        if raw[:2] == b'\xff\xfe':        return "utf-16-le"
        if raw[:2] == b'\xfe\xff':        return "utf-16-be"
        if raw[:4] == b'\x00\x00\xfe\xff':return "utf-32-be"
        # Sprobuj zdekodowac jako utf-8
        try:
            raw.decode("utf-8"); return "utf-8"
        except UnicodeDecodeError: pass
        # Sprawdz czy tylko ASCII
        if all(b < 128 for b in raw[:1024]): return "ascii"
        return "binary/unknown"

    def _is_text(raw: bytes) -> bool:
        """Czy plik wyglada na tekstowy (max 30% bajtow niedrukowanych)."""
        if not raw: return True
        sample = raw[:4096]
        non_text = sum(1 for b in sample if b < 9 or (14 <= b < 32) or b == 127)
        return non_text / len(sample) < 0.30

    all_results = []

    for fname in clean:
        fpath = Path(fname).expanduser().resolve()
        entry: dict = {"path": str(fpath), "_ok": False}

        if not fpath.exists():
            entry["error"] = f"Nie istnieje: {fpath}"
            all_results.append(entry)
            if not as_json:
                print_error(f"Nie istnieje: {fpath}")
            continue

        try:
            st      = fpath.stat()
            is_dir  = fpath.is_dir()
            is_link = fpath.is_symlink()
            suffix  = fpath.suffix.lower()

            # Typ pliku
            if is_link:
                ftype = "symlink"
            elif is_dir:
                ftype = "katalog"
            elif _stat_mod.S_ISFIFO(st.st_mode):
                ftype = "pipe"
            elif _stat_mod.S_ISSOCK(st.st_mode):
                ftype = "socket"
            elif _stat_mod.S_ISBLK(st.st_mode):
                ftype = "urzadzenie-blokowe"
            elif _stat_mod.S_ISCHR(st.st_mode):
                ftype = "urzadzenie-znakowe"
            else:
                ftype = "plik"

            mime    = _MIME.get(suffix, "application/octet-stream")
            perms   = _stat_mod.filemode(st.st_mode)
            fmt_dt  = "%Y-%m-%d %H:%M:%S"
            mtime   = datetime.datetime.fromtimestamp(st.st_mtime).strftime(fmt_dt)
            atime   = datetime.datetime.fromtimestamp(st.st_atime).strftime(fmt_dt)
            ctime   = datetime.datetime.fromtimestamp(st.st_ctime).strftime(fmt_dt)

            # Wlasciciel (Unix)
            owner = ""
            group = ""
            try:
                import pwd as _pwd, grp as _grp
                owner = _pwd.getpwuid(st.st_uid).pw_name
                group = _grp.getgrgid(st.st_gid).gr_name
            except Exception:
                owner = str(st.st_uid)
                group = str(st.st_gid)

            entry.update({
                "_ok":       True,
                "name":      fpath.name,
                "path":      str(fpath),
                "type":      ftype,
                "extension": suffix or "(brak)",
                "mime":      mime,
                "size_bytes":st.st_size,
                "size_human":_human_size(st.st_size),
                "permissions":perms,
                "owner":     owner,
                "group":     group,
                "inode":     st.st_ino,
                "links":     st.st_nlink,
                "mtime":     mtime,
                "atime":     atime,
                "ctime":     ctime,
            })

            # Symlink target
            if is_link:
                try:
                    entry["symlink_target"] = str(fpath.readlink()
                                                  if hasattr(fpath, "readlink")
                                                  else os.readlink(fpath))
                except Exception:  # ignorowane celowo
                    pass

            # Analiza zawartosci (pliki, nie katalogi)
            if ftype == "plik" and st.st_size > 0:
                try:
                    raw = fpath.read_bytes()[:1024 * 512]   # max 512KB
                    encoding = _detect_encoding(raw)
                    entry["encoding"] = encoding

                    if _is_text(raw):
                        # Tekstowe — policz linie/slowa/znaki
                        try:
                            text_full = fpath.read_text(encoding="utf-8", errors="replace")
                            lines_n   = text_full.count("\n") + (1 if text_full and not text_full.endswith("\n") else 0)
                            words_n   = len(text_full.split())
                            chars_n   = len(text_full)
                            entry["lines"] = lines_n
                            entry["words"] = words_n
                            entry["chars"] = chars_n
                        except Exception:  # ignorowane celowo
                            pass
                    else:
                        entry["encoding"] = "binary"

                    # Hash (opcjonalnie lub dla malych plikow)
                    if do_hash or st.st_size <= 50 * 1024 * 1024:
                        full_raw = fpath.read_bytes()
                        if do_hash:
                            entry["md5"]    = hashlib.md5(full_raw).hexdigest()
                            entry["sha256"] = hashlib.sha256(full_raw).hexdigest()
                        else:
                            entry["sha256"] = hashlib.sha256(full_raw).hexdigest()

                except Exception as read_err:
                    entry["read_error"] = str(read_err)

            elif is_dir:
                try:
                    children = list(fpath.iterdir())
                    entry["children"] = len(children)
                    entry["subdirs"]  = sum(1 for c in children if c.is_dir())
                    entry["files"]    = sum(1 for c in children if c.is_file())
                except PermissionError:
                    entry["children"] = "brak uprawnien"

        except Exception as e:
            entry["error"] = str(e)

        all_results.append(entry)

    if as_json:
        print(_json.dumps(all_results if len(all_results) > 1 else all_results[0],
                          indent=2, ensure_ascii=False))
        return

    # Wyswietl ladnie — terminal_width() raz przed pętlą
    _w_finfo = min(terminal_width() - 2, 72)
    for entry in all_results:
        w = _w_finfo
        print()
        name  = entry.get("name", entry.get("path", "?"))
        ftype = entry.get("type", "?")
        icon  = {"plik": "📄", "katalog": "📁", "symlink": "🔗",
                 "pipe": "⟿", "socket": "🔌"}.get(ftype, "❓")
        print(box_top(f"{icon} {name}  ({ftype})", width=w, color=C.EXEC))

        if "error" in entry:
            print(box_row(f"  {C.ERROR}BLAD: {entry['error']}{C.RESET}", width=w, color=C.EXEC))
            print(box_bottom(width=w, color=C.EXEC))
            continue

        rows = [
            ("Sciezka",      entry.get("path", "")),
            ("Rozmiar",      f"{entry.get('size_human','')}  ({entry.get('size_bytes','')} B)"),
            ("MIME",         entry.get("mime", "")),
            ("Rozszerzenie", entry.get("extension", "")),
            ("Kodowanie",    entry.get("encoding", "")),
            ("Uprawnienia",  f"{entry.get('permissions','')}  "
                             f"{C.DIM}wlasciciel: {entry.get('owner','')}:{entry.get('group','')}{C.RESET}"),
            ("Inode",        str(entry.get("inode", ""))),
            ("Dowiazania",   str(entry.get("links", ""))),
        ]
        if "symlink_target" in entry:
            rows.append(("Wskazuje na", entry["symlink_target"]))
        if "children" in entry:
            rows += [
                ("Zawiera",  f"{entry['children']} elementow  "
                             f"({entry.get('subdirs',0)} katalogów, {entry.get('files',0)} plikow)"),
            ]

        print(box_sep(width=w, color=C.EXEC))
        for label, val in rows:
            if val and str(val).strip():
                print(box_row(kv_row(label, val, key_color=C.DIM), width=w, color=C.EXEC))

        # Daty
        print(box_sep(width=w, color=C.EXEC))
        for label, key in [("Modyfikacja", "mtime"), ("Dostep", "atime"), ("Zmiana meta", "ctime")]:
            if entry.get(key):
                print(box_row(kv_row(label, entry[key], key_color=C.DIM), width=w, color=C.EXEC))

        # Statystyki tekstu
        if any(k in entry for k in ("lines", "words", "chars")):
            print(box_sep(width=w, color=C.EXEC))
            stats = (f"{entry.get('lines','?')} linii  "
                     f"{entry.get('words','?')} slow  "
                     f"{entry.get('chars','?')} znakow")
            print(box_row(kv_row("Statystyki", stats, key_color=C.DIM), width=w, color=C.EXEC))

        # Sumy kontrolne
        if "sha256" in entry:
            print(box_sep(width=w, color=C.EXEC))
            print(box_row(kv_row("SHA-256", entry["sha256"], key_color=C.DIM), width=w, color=C.EXEC))
        if "md5" in entry:
            print(box_row(kv_row("MD5", entry["md5"], key_color=C.DIM), width=w, color=C.EXEC))

        print(box_bottom(width=w, color=C.EXEC))

    print()

# VISUAL IDENTITY — about, version, credits, boxstyle

# ── ABOUT ────────────────────────────────────────────────────────────────────

@command("about", "Informacje o autorze, wersji i licencji TerminalXa",
         aliases=["info", "credits"])
def cmd_about(args):
    """
    about            — pelna karta informacyjna shella
    about --short    — jedna linia: nazwa, wersja, autor, licencja
    about --json     — wynik jako JSON
    about --license  — pelny tekst licencji MIT

    Wyswietla: wersja, autor, opis, licencja, homepage, changelog,
    platforma, Python, liczba komend, pluginy, motyw, styl ramek.
    """
    import json as _json

    short   = "--short"   in args
    as_json = "--json"    in args
    lic     = "--license" in args

    if lic:
        _print_license()
        return

    # Zbierz dane
    data = {
        "name":        SHELL_NAME,
        "version":     SHELL_VERSION,
        "tagline":     SHELL_TAGLINE,
        "author":      SHELL_AUTHOR,
        "author_url":  SHELL_AUTHOR_URL,
        "homepage":    SHELL_HOMEPAGE,
        "license":     SHELL_LICENSE,
        "license_url": SHELL_LICENSE_URL,
        "copyright":   SHELL_COPYRIGHT,
        "description": SHELL_DESCRIPTION,
        "python":      sys.version.split()[0],
        "platform":    sys.platform,
        "commands":    len(set(id(v) for v in BUILTINS.values() if isinstance(v, CommandDef))),
        "plugins":     len(LOADED_PLUGINS),
        "theme":       _CURRENT_THEME,
        "box_style":   cfg("box_style", "single"),
        "base_dir":    str(_BASE),
        "portable":    _PORTABLE_MODE,
        "api_version": f"{PLUGIN_API_VERSION[0]}.{PLUGIN_API_VERSION[1]}",
    }

    if as_json:
        print(_json.dumps(data, indent=2, ensure_ascii=False))
        return

    if short:
        print(f"  {C.BOLD}{SHELL_NAME}{C.RESET} v{SHELL_VERSION}  "
              f"{C.DIM}by {SHELL_AUTHOR}  ·  {SHELL_LICENSE}{C.RESET}  "
              f"{C.PATH}{SHELL_HOMEPAGE}{C.RESET}")
        return

    w = min(terminal_width() - 2, 74)
    print()

    # ── Nagłówek z logo inline ──────────────────────────────────────────────
    c = _bc()
    accent = "\033[38;5;39m"   # cyan — spójny z banerem
    print(f"{accent}{c['TL']}{c['H'] * w}{c['TR']}{C.RESET}")
    # Logo skrócone w jednej linii
    logo_line = (f"  {C.BOLD}{accent}{SHELL_NAME.upper()}{C.RESET}  "
                 f"v{C.BOLD}{SHELL_VERSION}{C.RESET}  "
                 f"{C.DIM}·  {SHELL_TAGLINE}{C.RESET}")
    visible = re.sub(r"\033\[[0-9;]*m", "", logo_line)
    pad = max(0, w - len(visible) - 2)
    print(f"{accent}{c['V']}{C.RESET} {logo_line}{' ' * pad} {accent}{c['V']}{C.RESET}")
    print(f"{accent}{c['SEP_L']}{c['SEP_H'] * w}{c['SEP_R']}{C.RESET}")

    # ── Sekcja: tożsamość ────────────────────────────────────────────────────
    _about_row = lambda label, val: print(
        box_row(kv_row(label, val, key_color=C.DIM, key_w=18), width=w, color=accent))

    _about_row("Autor",       f"{SHELL_AUTHOR}  {C.DIM}({SHELL_AUTHOR_URL}){C.RESET}")
    _about_row("Copyright",   SHELL_COPYRIGHT)
    _about_row("Licencja",    f"{SHELL_LICENSE}  {C.DIM}{SHELL_LICENSE_URL}{C.RESET}")
    _about_row("Homepage",    SHELL_HOMEPAGE)
    print(f"{accent}{c['SEP_L']}{c['SEP_H'] * w}{c['SEP_R']}{C.RESET}")

    # ── Sekcja: opis ─────────────────────────────────────────────────────────
    import textwrap as _tw
    for chunk in _tw.wrap(SHELL_DESCRIPTION, width=w - 4):
        print(box_row(f"  {C.DIM}{chunk}{C.RESET}", width=w, color=accent))
    print(f"{accent}{c['SEP_L']}{c['SEP_H'] * w}{c['SEP_R']}{C.RESET}")

    # ── Sekcja: środowisko ────────────────────────────────────────────────────
    _about_row("Python",      data["python"])
    _about_row("Platforma",   data["platform"])
    _about_row("Komendy",     f"{data['commands']} wbudowanych")
    _about_row("Pluginy",     f"{data['plugins']} zaladowanych")
    _about_row("Plugin API",  f"v{data['api_version']}")
    _about_row("Motyw",       data["theme"])
    _about_row("Styl ramek",  data["box_style"])
    _about_row("Tryb",        "portable" if data["portable"] else "standardowy")
    _about_row("Dane w",      data["base_dir"])
    print(f"{accent}{c['SEP_L']}{c['SEP_H'] * w}{c['SEP_R']}{C.RESET}")

    # ── Stopka ────────────────────────────────────────────────────────────────
    foot = f"  {C.DIM}about --license  ·  about --json  ·  changelog  ·  version{C.RESET}"
    visible_f = re.sub(r"\033\[[0-9;]*m", "", foot)
    pad_f = max(0, w - len(visible_f) - 2)
    print(f"{accent}{c['V']}{C.RESET}{foot}{' ' * pad_f}  {accent}{c['V']}{C.RESET}")
    print(f"{accent}{c['BL']}{c['H'] * w}{c['BR']}{C.RESET}")
    print()

def _print_license():
    """Wyswietla pelny tekst licencji MIT."""
    w = min(terminal_width() - 2, 72)
    year = datetime.datetime.now().year
    mit_text = f"""\
MIT License

Copyright (c) 2024–{year} {SHELL_AUTHOR}  (polsoft.ITS™)

Permission is hereby granted, free of charge, to any person obtaining a copy
of this software and associated documentation files (the "Software"), to deal
in the Software without restriction, including without limitation the rights
to use, copy, modify, merge, publish, distribute, sublicense, and/or sell
copies of the Software, and to permit persons to whom the Software is
furnished to do so, subject to the following conditions:

The above copyright notice and this permission notice shall be included in all
copies or substantial portions of the Software.

THE SOFTWARE IS PROVIDED "AS IS", WITHOUT WARRANTY OF ANY KIND, EXPRESS OR
IMPLIED, INCLUDING BUT NOT LIMITED TO THE WARRANTIES OF MERCHANTABILITY,
FITNESS FOR A PARTICULAR PURPOSE AND NONINFRINGEMENT. IN NO EVENT SHALL THE
AUTHORS OR COPYRIGHT HOLDERS BE LIABLE FOR ANY CLAIM, DAMAGES OR OTHER
LIABILITY, WHETHER IN AN ACTION OF CONTRACT, TORT OR OTHERWISE, ARISING FROM,
OUT OF OR IN CONNECTION WITH THE SOFTWARE OR THE USE OR OTHER DEALINGS IN THE
SOFTWARE.
"""
    import textwrap as _tw
    print()
    print(box_top(f"Licencja {SHELL_LICENSE}  —  {SHELL_NAME} v{SHELL_VERSION}", width=w, color=C.INFO))
    for line in mit_text.splitlines():
        if line.strip():
            for chunk in _tw.wrap(line, w - 4) or [line]:
                print(box_row(f"  {C.DIM}{chunk}{C.RESET}", width=w, color=C.INFO))
        else:
            print(box_row("", width=w, color=C.INFO))
    print(box_bottom(width=w, color=C.INFO))
    print()

# ── VERSION ───────────────────────────────────────────────────────────────────

@command("version", "Wyswietl wersje TerminalXa",
         aliases=["ver", "--version", "-V"])
def cmd_version(args):
    """
    version           — pelna informacja o wersji
    version --short   — tylko numer wersji (do skryptow)
    version --check   — sprawdz czy dostepna nowsza wersja (tryb online)
    """
    if "--short" in args or "-s" in args:
        print(SHELL_VERSION)
        return

    if "--check" in args:
        if not is_online():
            print_error("Tryb OFFLINE — sprawdzanie aktualizacji niedostepne.",
                        "Uruchom 'mode online' aby wlaczyc tryb online.")
            return
        # Próba pobrania najnowszej wersji z GitHub releases API
        try:
            import urllib.request as _ur
            url = "https://api.github.com/repos/polsoft/TerminalX/releases/latest"
            req = _ur.Request(url, headers={
                "User-Agent":  f"TerminalX/{SHELL_VERSION}",
                "Accept":      "application/vnd.github+json",
            })
            with _ur.urlopen(req, timeout=8) as resp:
                import json as _json
                data = _json.loads(resp.read())
            latest = data.get("tag_name", "").lstrip("v")
            if latest:
                current_parts = [int(x) for x in SHELL_VERSION.split(".")]
                latest_parts  = [int(x) for x in latest.split(".")]
                if latest_parts > current_parts:
                    print_info(f"Dostepna nowsza wersja: {C.PATH}v{latest}{C.RESET}  "
                               f"(biezaca: v{SHELL_VERSION})")
                    print_info(f"Pobierz: {SHELL_HOMEPAGE}/releases")
                else:
                    print_info(f"Masz najnowsza wersje: v{SHELL_VERSION}")
            else:
                print_info("Nie udalo sie ustalic najnowszej wersji.")
        except Exception as e:
            print_error(f"Blad sprawdzania wersji: {e}",
                        "Sprawdz recznie: " + SHELL_HOMEPAGE)
        return

    # Pelna informacja
    w = min(terminal_width() - 2, 60)
    print()
    print(box_top(f"{SHELL_NAME}  Informacja o wersji", width=w, color=C.PROMPT))
    rows = [
        ("Wersja",       f"{C.BOLD}v{SHELL_VERSION}{C.RESET}"),
        ("Nazwa",        SHELL_NAME),
        ("Tagline",      SHELL_TAGLINE),
        ("Autor",        SHELL_AUTHOR),
        ("Licencja",     SHELL_LICENSE),
        ("Python",       f"{sys.version.split()[0]}  ({sys.executable})"),
        ("Platforma",    f"{sys.platform}  ({'64bit' if sys.maxsize > 2**32 else '32bit'})"),
        ("Plugin API",   f"v{PLUGIN_API_VERSION[0]}.{PLUGIN_API_VERSION[1]}"),
        ("Styl ramek",   cfg("box_style", "single")),
    ]
    for label, val in rows:
        print(box_row(kv_row(label, val, key_color=C.DIM, key_w=14), width=w, color=C.PROMPT))
    print(box_sep(width=w, color=C.PROMPT))
    print(box_row(
        f"  {C.DIM}about  ·  about --license  ·  changelog  ·  version --check{C.RESET}",
        width=w, color=C.PROMPT))
    print(box_bottom(width=w, color=C.PROMPT))
    print()

# ── BOXSTYLE ──────────────────────────────────────────────────────────────────

@command("boxstyle", "Zmien styl ramek UI (single/round/double/heavy/ascii)",
         aliases=["box", "framestyle"])
def cmd_boxstyle(args):
    """
    boxstyle                  — pokaz biezacy styl i demo wszystkich
    boxstyle single           — klasyczny Unicode  ┌─┐
    boxstyle round            — zaokraglone narozniki  ╭─╮
    boxstyle double           — podwojne linie  ╔═╗
    boxstyle heavy            — grube linie  ┏━┓
    boxstyle ascii            — bez Unicode  +--+  (dla starych terminali)

    Zmiana jest zapisywana do konfiguracji (config set box_style <styl>).
    """
    styles = list(_BOX_CHARS.keys())

    if not args or args[0] == "list":
        current = cfg("box_style", "single")
        w = min(terminal_width() - 2, 64)
        print()
        print(box_top("Dostepne style ramek", width=w, color=C.INFO))
        for style_name, chars in _BOX_CHARS.items():
            # Demo ramki dla każdego stylu
            tl, tr, bl, br = chars["TL"], chars["TR"], chars["BL"], chars["BR"]
            h, v           = chars["H"],  chars["V"]
            demo = f"{tl}{h*4}{tr} {v}demo{v} {bl}{h*4}{br}"
            mark = f"  {C.PATH}◄ aktywny{C.RESET}" if style_name == current else ""
            row  = (f"  {C.BOLD}{style_name:<8}{C.RESET}  "
                    f"{C.DIM}{demo}{C.RESET}{mark}")
            print(box_row(row, width=w, color=C.INFO))
        print(box_sep(width=w, color=C.INFO))
        print(box_row(
            f"  {C.DIM}Uzycie: boxstyle <nazwa>  |  config set box_style <nazwa>{C.RESET}",
            width=w, color=C.INFO))
        print(box_bottom(width=w, color=C.INFO))
        print()
        return

    new_style = args[0].lower()
    if new_style not in _BOX_CHARS:
        print_error(f"Nieznany styl: {new_style}",
                    f"Dostepne: {', '.join(styles)}")
        return

    cfg_set("box_style", new_style)
    save_config()

    # Pokaż demo nowego stylu
    w = min(terminal_width() - 2, 52)
    print()
    print(box_top(f"Styl ramek: {new_style}", width=w, color=C.PATH))
    print(box_row(f"  Nowy styl zostal zastosowany.", width=w, color=C.PATH))
    print(box_sep(width=w, color=C.PATH))
    print(box_row(
        f"  {C.DIM}Aby zresetowac: boxstyle single{C.RESET}",
        width=w, color=C.PATH))
    print(box_bottom(width=w, color=C.PATH))
    print()
    print_info(f"Styl ramek zmieniony na: {C.BOLD}{new_style}{C.RESET}")

# INTEGRATIONS

#
#  Trzy tryby serwera — wszystkie stdlib, zero pip, działają offline:
#
#  1. REST API (HTTP/JSON)  — http.server + threading
#     serve start [port]    — uruchom serwer REST na localhost
#     serve stop            — zatrzymaj
#     serve status          — status + lista endpointów
#     serve log             — ostatnie requesty
#
#     Endpointy:
#       GET  /api/v1/status          — status shella
#       GET  /api/v1/commands        — lista komend
#       POST /api/v1/exec            — {"cmd":"ls -la"}
#       GET  /api/v1/env             — zmienne środowiskowe
#       POST /api/v1/env             — {"key":"X","value":"Y"}
#       GET  /api/v1/history         — historia komend
#       GET  /api/v1/files?path=.    — listowanie pliku/katalogu
#       GET  /api/v1/read?path=file  — odczyt pliku
#       POST /api/v1/write           — {"path":"f","content":"..."}
#       GET  /api/v1/plugins         — załadowane pluginy
#       POST /api/v1/plugin/reload   — {"name":"plugin"}
#       GET  /api/v1/version         — wersja shella
#
#  2. WebSocket serwer  — socket + threading (RFC 6455 handshake)
#     wss start [port]   — uruchom serwer WebSocket
#     wss stop           — zatrzymaj
#     wss status         — status + podłączeni klienci
#     wss broadcast <msg>— wyślij do wszystkich klientów
#
#     Protokół WS (JSON frames):
#       { "type": "exec",    "cmd":  "ls" }          → wynik komendy
#       { "type": "event",   "name": "cmd_done" }     ← zdarzenie
#       { "type": "ping" }                            → { "type": "pong" }
#       { "type": "status" }                          → stan shella
#       { "type": "subscribe", "events": ["cmd_done"] } → subskrypcja zdarzeń
#
#  3. GUI backend (IPC przez Unix socket / named pipe)
#     gui start [socket]  — uruchom IPC backend
#     gui stop            — zatrzymaj
#     gui status          — status
#     gui send <json>     — wyślij wiadomość do podłączonego GUI
#
#     Protokół: newline-delimited JSON (NDJSON)
#       Klient → shell: { "id": 1, "cmd": "ls" }
#       Shell  → klient: { "id": 1, "stdout": "...", "exit": 0, "done": true }
#       Zdarzenia: { "event": "prompt_ready", "cwd": "/home/..." }
#

import threading  as _threading
import socket     as _sock
import http.server as _http_server
import base64     as _b64_mod
import hashlib    as _hashlib_mod
import struct     as _struct
import io         as _io
import queue      as _queue
import time       as _time_mod

# ── Wspólny rejestr działających serwerów ────────────────────────────────────

_SERVERS: dict = {
    "rest":      None,   # _RestServer | None
    "websocket": None,   # _WsServer   | None
    "gui":       None,   # _GuiServer  | None
    "remote":    None,   # _RemoteServer | None  (TCP remote shell)
}

# Globalny log requestów (max 200 wpisów)
_SERVER_LOG: list[dict] = []
_SERVER_LOG_MAX = 200

def _slog(server: str, msg: str, level: str = "INFO"):
    ts = datetime.datetime.now().strftime("%H:%M:%S")
    entry = {"ts": ts, "server": server, "level": level, "msg": msg}
    _SERVER_LOG.append(entry)
    if len(_SERVER_LOG) > _SERVER_LOG_MAX:
        del _SERVER_LOG[0]

# ██  1. REST API SERVER  █████████████████████████████████████████████████████

class _RestHandler(_http_server.BaseHTTPRequestHandler):
    """HTTP request handler — obsługuje REST API TerminalXa."""

    # Wyłącz domyślne logowanie do stderr
    def log_message(self, fmt, *args):
        _slog("rest", fmt % args)

    def log_error(self, fmt, *args):
        _slog("rest", fmt % args, "ERROR")

    # ── helpers ──────────────────────────────────────────────────────────────

    def _send_json(self, data: dict, code: int = 200):
        body = json.dumps(data, ensure_ascii=False, default=str).encode("utf-8")
        self.send_response(code)
        self.send_header("Content-Type",  "application/json; charset=utf-8")
        self.send_header("Content-Length", str(len(body)))
        self.send_header("Access-Control-Allow-Origin", "*")
        self.send_header("Access-Control-Allow-Methods", "GET, POST, OPTIONS")
        self.send_header("Access-Control-Allow-Headers", "Content-Type, Authorization")
        self.send_header("X-Shell",  f"{SHELL_NAME}/{SHELL_VERSION}")
        self.end_headers()
        self.wfile.write(body)

    def _send_error_json(self, msg: str, code: int = 400):
        self._send_json({"error": msg, "code": code}, code)

    def _read_json_body(self) -> dict | None:
        length = int(self.headers.get("Content-Length", 0))
        if not length:
            return {}
        try:
            return json.loads(self.rfile.read(length))
        except Exception:
            return None

    def _check_token(self) -> bool:
        """Sprawdza Bearer token jeśli serwer ma ustawiony klucz."""
        token = getattr(self.server, "_auth_token", None)
        if not token:
            return True
        auth = self.headers.get("Authorization", "")
        return auth == f"Bearer {token}"

    def _capture_exec(self, cmd_str: str) -> dict:
        """Wykonuje komendę shella, przechwytuje stdout/stderr."""
        import io as _sio
        old_stdout = sys.stdout
        old_stderr = sys.stderr
        buf_out = _sio.StringIO()
        buf_err = _sio.StringIO()
        exit_code = 0
        try:
            sys.stdout = buf_out
            sys.stderr = buf_err
            execute_line(cmd_str)
        except SystemExit as e:
            exit_code = int(e.code) if isinstance(e.code, int) else 0
        except Exception as e:
            buf_err.write(str(e))
            exit_code = 1
        finally:
            sys.stdout = old_stdout
            sys.stderr = old_stderr
        return {
            "stdout":    buf_out.getvalue(),
            "stderr":    buf_err.getvalue(),
            "exit_code": exit_code,
            "cmd":       cmd_str,
        }

    # ── router ───────────────────────────────────────────────────────────────

    def do_OPTIONS(self):
        self.send_response(204)
        self.send_header("Access-Control-Allow-Origin",  "*")
        self.send_header("Access-Control-Allow-Methods", "GET, POST, OPTIONS")
        self.send_header("Access-Control-Allow-Headers", "Content-Type, Authorization")
        self.end_headers()

    def do_GET(self):
        if not self._check_token():
            self._send_error_json("Unauthorized", 401); return
        path  = self.path.split("?")[0].rstrip("/")
        query = {}
        if "?" in self.path:
            for part in self.path.split("?", 1)[1].split("&"):
                if "=" in part:
                    k, v = part.split("=", 1)
                    query[k] = v
        self._route_get(path, query)

    def do_POST(self):
        if not self._check_token():
            self._send_error_json("Unauthorized", 401); return
        path = self.path.rstrip("/")
        body = self._read_json_body()
        if body is None:
            self._send_error_json("Invalid JSON body"); return
        self._route_post(path, body)

    # ── GET routes ───────────────────────────────────────────────────────────

    def _route_get(self, path: str, q: dict):
        # Root / dokumentacja
        if path in ("", "/", "/api", "/api/v1"):
            self._send_json({
                "shell":   f"{SHELL_NAME} v{SHELL_VERSION}",
                "author":  SHELL_AUTHOR,
                "license": SHELL_LICENSE,
                "endpoints": [
                    "GET  /api/v1/status",
                    "GET  /api/v1/commands",
                    "GET  /api/v1/env",
                    "GET  /api/v1/history",
                    "GET  /api/v1/plugins",
                    "GET  /api/v1/version",
                    "GET  /api/v1/files?path=.",
                    "GET  /api/v1/read?path=<file>",
                    "POST /api/v1/exec",
                    "POST /api/v1/env",
                    "POST /api/v1/write",
                    "POST /api/v1/plugin/reload",
                ]
            }); return

        if path == "/api/v1/status":
            self._send_json({
                "status":    "running",
                "shell":     SHELL_NAME,
                "version":   SHELL_VERSION,
                "cwd":       str(Path.cwd()),
                "is_root":   IS_ROOT,
                "theme":     _CURRENT_THEME,
                "online":    is_online(),
                "plugins":   len(LOADED_PLUGINS),
                "commands":  len(BUILTINS),
                "uptime":    getattr(self.server, "_uptime", "?"),
            }); return

        if path == "/api/v1/version":
            self._send_json({
                "name":    SHELL_NAME,
                "version": SHELL_VERSION,
                "author":  SHELL_AUTHOR,
                "license": SHELL_LICENSE,
                "homepage":SHELL_HOMEPAGE,
                "python":  sys.version.split()[0],
                "platform":sys.platform,
            }); return

        if path == "/api/v1/commands":
            seen = set()
            cmds = []
            for name, cdef in sorted(BUILTINS.items()):
                if not isinstance(cdef, CommandDef): continue
                if id(cdef) in seen: continue
                seen.add(id(cdef))
                cmds.append({
                    "name":        cdef.name,
                    "description": cdef.description,
                    "aliases":     cdef.aliases,
                })
            self._send_json({"commands": cmds, "count": len(cmds)}); return

        if path == "/api/v1/env":
            self._send_json({
                "shell_vars":  dict(SHELL_VARS),
                "environ":     dict(os.environ),
            }); return

        if path == "/api/v1/history":
            limit = int(q.get("limit", 50))
            self._send_json({
                "history": HISTORY[-limit:],
                "total":   len(HISTORY),
            }); return

        if path == "/api/v1/plugins":
            result = {}
            for name, mod in LOADED_PLUGINS.items():
                meta = PLUGIN_META.get(name, {})
                result[name] = {
                    "version":     meta.get("version", "?"),
                    "author":      meta.get("author",  ""),
                    "description": meta.get("description", ""),
                    "file":        getattr(mod, "__file__", ""),
                }
            self._send_json({"plugins": result, "count": len(result)}); return

        if path == "/api/v1/files":
            target = Path(q.get("path", ".")).expanduser()
            try:
                if target.is_file():
                    st = target.stat()
                    self._send_json({
                        "path": str(target.resolve()),
                        "type": "file",
                        "size": st.st_size,
                        "mtime": datetime.datetime.fromtimestamp(st.st_mtime).isoformat(),
                    }); return
                entries = []
                for child in sorted(target.iterdir()):
                    try:
                        st = child.stat()
                        entries.append({
                            "name":  child.name,
                            "type":  "dir" if child.is_dir() else "file",
                            "size":  st.st_size,
                            "mtime": datetime.datetime.fromtimestamp(st.st_mtime).isoformat(),
                        })
                    except Exception:  # ignorowane celowo
                        pass
                self._send_json({"path": str(target.resolve()),
                                 "entries": entries, "count": len(entries)}); return
            except PermissionError:
                self._send_error_json("Permission denied", 403); return
            except Exception as e:
                self._send_error_json(str(e)); return

        if path == "/api/v1/read":
            fpath = q.get("path", "")
            if not fpath:
                self._send_error_json("Missing ?path="); return
            target = Path(fpath).expanduser()
            if not target.exists():
                self._send_error_json("File not found", 404); return
            try:
                content = target.read_text(encoding="utf-8", errors="replace")
                self._send_json({
                    "path":    str(target.resolve()),
                    "content": content,
                    "lines":   content.count("\n"),
                    "size":    target.stat().st_size,
                }); return
            except Exception as e:
                self._send_error_json(str(e)); return

        self._send_error_json(f"Unknown endpoint: {path}", 404)

    # ── POST routes ──────────────────────────────────────────────────────────

    def _route_post(self, path: str, body: dict):
        if path == "/api/v1/exec":
            cmd_str = body.get("cmd", "").strip()
            if not cmd_str:
                self._send_error_json("Missing 'cmd' field"); return
            _slog("rest", f"exec: {cmd_str}")
            result = self._capture_exec(cmd_str)
            # Powiadom WebSocket klientów o zdarzeniu
            _ws_broadcast_event("cmd_done", {"cmd": cmd_str,
                                              "exit_code": result["exit_code"]})
            self._send_json(result); return

        if path == "/api/v1/env":
            key   = body.get("key",   "")
            value = body.get("value", "")
            if not key:
                self._send_error_json("Missing 'key' field"); return
            SHELL_VARS[key] = value
            _slog("rest", f"env set: {key}={value!r}")
            self._send_json({"ok": True, "key": key, "value": value}); return

        if path == "/api/v1/write":
            fpath   = body.get("path", "")
            content = body.get("content", "")
            if not fpath:
                self._send_error_json("Missing 'path' field"); return
            try:
                target = Path(fpath).expanduser()
                target.write_text(content, encoding="utf-8")
                _slog("rest", f"write: {target}  ({len(content)} chars)")
                self._send_json({"ok": True, "path": str(target.resolve()),
                                 "bytes": len(content.encode())}); return
            except Exception as e:
                self._send_error_json(str(e)); return

        if path == "/api/v1/plugin/reload":
            name = body.get("name", "")
            if not name:
                self._send_error_json("Missing 'name' field"); return
            if name not in LOADED_PLUGINS:
                self._send_error_json(f"Plugin not loaded: {name}", 404); return
            api  = ShellAPI()
            mod  = LOADED_PLUGINS.pop(name)
            file = Path(getattr(mod, "__file__", ""))
            sys.modules.pop(f"_terminalx_plugin_{name}", None)
            if hasattr(mod, "unregister"):
                try: mod.unregister(api)
                except Exception:
                    pass  # ignorowane celowo
            ok = _load_single_plugin(file, api) if file.exists() else False
            self._send_json({"ok": ok, "plugin": name}); return

        self._send_error_json(f"Unknown endpoint: {path}", 404)

class _RestServer:
    """Wrapper wokół HTTPServer z obsługą wątku."""

    def __init__(self, host: str = "127.0.0.1", port: int = 7700,
                 auth_token: str = ""):
        self.host        = host
        self.port        = port
        self.auth_token  = auth_token
        self._server: _http_server.HTTPServer | None = None
        self._thread: _threading.Thread | None = None
        self._start_time = None

    def start(self) -> bool:
        try:
            self._server = _http_server.HTTPServer(
                (self.host, self.port), _RestHandler)
            self._server._auth_token = self.auth_token
            self._server._uptime     = datetime.datetime.now().isoformat()
            self._thread = _threading.Thread(
                target=self._server.serve_forever,
                daemon=True, name="TerminalX-rest")
            self._thread.start()
            self._start_time = datetime.datetime.now()
            _slog("rest", f"Uruchomiono na http://{self.host}:{self.port}")
            return True
        except OSError as e:
            _slog("rest", f"Blad startu: {e}", "ERROR")
            return False

    def stop(self):
        if self._server:
            self._server.shutdown()
            self._server = None
        _slog("rest", "Zatrzymano")

    @property
    def running(self) -> bool:
        return self._server is not None and (
            self._thread is not None and self._thread.is_alive())

    @property
    def uptime(self) -> str:
        if not self._start_time: return "—"
        delta = datetime.datetime.now() - self._start_time
        s = int(delta.total_seconds())
        return f"{s//3600:02d}:{(s%3600)//60:02d}:{s%60:02d}"

# ██  2. WEBSOCKET SERVER  ████████████████████████████████████████████████████

_WS_MAGIC  = "258EAFA5-E914-47DA-95CA-C5AB0DC85B11"
_WS_CLIENTS: list = []           # aktywne połączenia _WsClient
_WS_CLIENTS_LOCK = _threading.Lock()

def _ws_handshake(conn: _sock.socket, request: bytes) -> bool:
    """Wykonuje RFC 6455 WebSocket handshake."""
    try:
        headers = {}
        lines   = request.decode("utf-8", errors="replace").split("\r\n")
        for line in lines[1:]:
            if ": " in line:
                k, v = line.split(": ", 1)
                headers[k.lower()] = v
        key = headers.get("sec-websocket-key", "")
        if not key:
            return False
        accept = _b64_mod.b64encode(
            _hashlib_mod.sha1((key + _WS_MAGIC).encode()).digest()
        ).decode()
        resp = (
            "HTTP/1.1 101 Switching Protocols\r\n"
            "Upgrade: websocket\r\n"
            "Connection: Upgrade\r\n"
            f"Sec-WebSocket-Accept: {accept}\r\n"
            "\r\n"
        )
        conn.sendall(resp.encode())
        return True
    except Exception:
        return False

def _ws_recv_frame(conn: _sock.socket) -> bytes | None:
    """Odbiera jeden WebSocket frame (RFC 6455). Zwraca payload lub None."""
    try:
        header = b""
        while len(header) < 2:
            chunk = conn.recv(2 - len(header))
            if not chunk:
                return None
            header += chunk
        b0, b1 = header
        opcode = b0 & 0x0F
        if opcode == 0x8:     # close frame
            return None
        if opcode == 0x9:     # ping
            _ws_send_frame(conn, b'{"type":"pong"}')
            return b""
        masked = bool(b1 & 0x80)
        length = b1 & 0x7F
        if length == 126:
            length = _struct.unpack(">H", conn.recv(2))[0]
        elif length == 127:
            length = _struct.unpack(">Q", conn.recv(8))[0]
        mask_key = conn.recv(4) if masked else b""
        data = b""
        while len(data) < length:
            chunk = conn.recv(min(4096, length - len(data)))
            if not chunk:
                return None
            data += chunk
        if masked:
            data = bytes(b ^ mask_key[i % 4] for i, b in enumerate(data))
        return data
    except Exception:
        return None

def _ws_send_frame(conn: _sock.socket, data: bytes) -> bool:
    """Wysyła WebSocket text frame."""
    try:
        length = len(data)
        if length < 126:
            header = _struct.pack("BB", 0x81, length)
        elif length < 65536:
            header = _struct.pack("BBH", 0x81, 126, length)
        else:
            header = _struct.pack("BBQ", 0x81, 127, length)
        conn.sendall(header + data)
        return True
    except Exception:
        return False

def _ws_broadcast_event(event_name: str, data: dict):
    """Rozgłasza zdarzenie do wszystkich subskrybujących klientów WS."""
    msg = json.dumps({"type": "event", "name": event_name, "data": data,
                      "ts": datetime.datetime.now().isoformat()},
                     ensure_ascii=False)
    payload = msg.encode("utf-8")
    with _WS_CLIENTS_LOCK:
        for client in list(_WS_CLIENTS):
            if event_name in client.subscriptions or "*" in client.subscriptions:
                try:
                    _ws_send_frame(client.conn, payload)
                except Exception:  # ignorowane celowo
                    pass

class _WsClient:
    """Reprezentuje jedno połączenie WebSocket."""

    def __init__(self, conn: _sock.socket, addr):
        self.conn          = conn
        self.addr          = addr
        self.subscriptions: set[str] = {"*"}
        self._connected    = True
        self._connected_at = datetime.datetime.now()

    @property
    def uptime(self) -> str:
        delta = datetime.datetime.now() - self._connected_at
        s = int(delta.total_seconds())
        return f"{s//60:02d}:{s%60:02d}"

    def _capture_exec(self, cmd_str: str) -> dict:
        import io as _sio2
        old_o, old_e = sys.stdout, sys.stderr
        bo, be = _sio2.StringIO(), _sio2.StringIO()
        code = 0
        try:
            sys.stdout, sys.stderr = bo, be
            execute_line(cmd_str)
        except SystemExit as e:
            code = int(e.code) if isinstance(e.code, int) else 0
        except Exception as ex:
            be.write(str(ex)); code = 1
        finally:
            sys.stdout, sys.stderr = old_o, old_e
        return {"stdout": bo.getvalue(), "stderr": be.getvalue(),
                "exit_code": code, "cmd": cmd_str}

    def handle(self):
        """Pętla obsługi klienta (w osobnym wątku)."""
        try:
            while self._connected:
                raw = _ws_recv_frame(self.conn)
                if raw is None:
                    break
                if not raw:
                    continue
                try:
                    msg = json.loads(raw.decode("utf-8"))
                except Exception:
                    _ws_send_frame(self.conn,
                        b'{"type":"error","msg":"invalid JSON"}')
                    continue
                self._dispatch(msg)
        except Exception:  # ignorowane celowo
            pass
        finally:
            self._connected = False
            with _WS_CLIENTS_LOCK:
                if self in _WS_CLIENTS:
                    _WS_CLIENTS.remove(self)
            try:
                self.conn.close()
            except Exception:  # ignorowane celowo
                pass
            _slog("ws", f"Klient rozłączony: {self.addr}")

    def _dispatch(self, msg: dict):
        mtype = msg.get("type", "")
        req_id = msg.get("id")

        def _reply(data: dict):
            if req_id is not None:
                data["id"] = req_id
            _ws_send_frame(self.conn,
                           json.dumps(data, ensure_ascii=False,
                                      default=str).encode("utf-8"))

        if mtype == "ping":
            _reply({"type": "pong",
                    "ts": datetime.datetime.now().isoformat()})

        elif mtype == "exec":
            cmd_str = msg.get("cmd", "").strip()
            if not cmd_str:
                _reply({"type": "error", "msg": "Missing 'cmd'"}); return
            _slog("ws", f"exec: {cmd_str}")
            result = self._capture_exec(cmd_str)
            result["type"] = "exec_result"
            _reply(result)
            _ws_broadcast_event("cmd_done", {"cmd": cmd_str,
                                             "exit_code": result["exit_code"]})

        elif mtype == "status":
            _reply({
                "type":    "status",
                "shell":   SHELL_NAME,
                "version": SHELL_VERSION,
                "cwd":     str(Path.cwd()),
                "is_root": IS_ROOT,
                "online":  is_online(),
                "clients": len(_WS_CLIENTS),
            })

        elif mtype == "subscribe":
            events = msg.get("events", ["*"])
            self.subscriptions = set(events)
            _reply({"type": "subscribed", "events": list(self.subscriptions)})

        elif mtype == "env_get":
            key = msg.get("key")
            if key:
                _reply({"type": "env", "key": key,
                        "value": SHELL_VARS.get(key, os.environ.get(key))})
            else:
                _reply({"type": "env", "vars": dict(SHELL_VARS)})

        elif mtype == "env_set":
            key   = msg.get("key", "")
            value = str(msg.get("value", ""))
            if key:
                SHELL_VARS[key] = value
                _reply({"type": "ok", "key": key, "value": value})
            else:
                _reply({"type": "error", "msg": "Missing 'key'"})

        elif mtype == "history":
            limit = int(msg.get("limit", 50))
            _reply({"type": "history", "history": HISTORY[-limit:]})

        else:
            _reply({"type": "error", "msg": f"Unknown type: {mtype!r}"})

class _WsServer:
    """WebSocket server (RFC 6455) — czysty stdlib."""

    def __init__(self, host: str = "127.0.0.1", port: int = 7701):
        self.host        = host
        self.port        = port
        self._sock: _sock.socket | None = None
        self._thread: _threading.Thread | None = None
        self._start_time = None

    def start(self) -> bool:
        try:
            self._sock = _sock.socket(_sock.AF_INET, _sock.SOCK_STREAM)
            self._sock.setsockopt(_sock.SOL_SOCKET, _sock.SO_REUSEADDR, 1)
            self._sock.bind((self.host, self.port))
            self._sock.listen(10)
            self._sock.settimeout(1.0)
            self._thread = _threading.Thread(
                target=self._accept_loop, daemon=True,
                name="TerminalX-ws")
            self._thread.start()
            self._start_time = datetime.datetime.now()
            _slog("ws", f"Uruchomiono na ws://{self.host}:{self.port}")
            return True
        except OSError as e:
            _slog("ws", f"Blad startu: {e}", "ERROR")
            return False

    def _accept_loop(self):
        while self._sock:
            try:
                conn, addr = self._sock.accept()
            except _sock.timeout:
                continue
            except Exception:
                break
            # Odbierz HTTP upgrade request
            try:
                req = b""
                conn.settimeout(5.0)
                while b"\r\n\r\n" not in req:
                    chunk = conn.recv(1024)
                    if not chunk:
                        break
                    req += chunk
                conn.settimeout(None)
                if not _ws_handshake(conn, req):
                    conn.close()
                    continue
            except Exception:
                try: conn.close()
                except Exception:
                    pass  # ignorowane celowo
                continue

            client = _WsClient(conn, addr)
            with _WS_CLIENTS_LOCK:
                _WS_CLIENTS.append(client)
            _slog("ws", f"Klient podłączony: {addr}")
            t = _threading.Thread(target=client.handle, daemon=True,
                                  name=f"ws-client-{addr}")
            t.start()

    def stop(self):
        s = self._sock
        self._sock = None
        if s:
            try: s.close()
            except Exception:
                pass  # ignorowane celowo
        with _WS_CLIENTS_LOCK:
            for client in list(_WS_CLIENTS):
                try: client.conn.close()
                except Exception:
                    pass  # ignorowane celowo
            _WS_CLIENTS.clear()
        _slog("ws", "Zatrzymano")

    @property
    def running(self) -> bool:
        return (self._sock is not None and
                self._thread is not None and self._thread.is_alive())

    @property
    def uptime(self) -> str:
        if not self._start_time: return "—"
        delta = datetime.datetime.now() - self._start_time
        s = int(delta.total_seconds())
        return f"{s//3600:02d}:{(s%3600)//60:02d}:{s%60:02d}"

# ██  3. GUI BACKEND (IPC — Unix socket / named pipe)  ████████████████████████

_GUI_CLIENTS: list = []
_GUI_CLIENTS_LOCK = _threading.Lock()

class _GuiClient:
    """Jedno połączenie GUI przez IPC socket."""

    def __init__(self, conn: _sock.socket, addr):
        self.conn = conn
        self.addr = addr
        self._buf  = b""
        self._connected = True

    def send(self, data: dict):
        try:
            msg = json.dumps(data, ensure_ascii=False, default=str) + "\n"
            self.conn.sendall(msg.encode("utf-8"))
        except Exception:
            self._connected = False

    def _capture_exec(self, cmd_str: str) -> dict:
        import io as _sio3
        old_o, old_e = sys.stdout, sys.stderr
        bo, be = _sio3.StringIO(), _sio3.StringIO()
        code = 0
        try:
            sys.stdout, sys.stderr = bo, be
            execute_line(cmd_str)
        except SystemExit as e:
            code = int(e.code) if isinstance(e.code, int) else 0
        except Exception as ex:
            be.write(str(ex)); code = 1
        finally:
            sys.stdout, sys.stderr = old_o, old_e
        return {"stdout": bo.getvalue(), "stderr": be.getvalue(),
                "exit_code": code, "cmd": cmd_str}

    def handle(self):
        """Pętla obsługi NDJSON — newline-delimited JSON."""
        # Wyślij "prompt_ready" przy połączeniu
        self.send({"event": "connected", "shell": SHELL_NAME,
                   "version": SHELL_VERSION,
                   "cwd": str(Path.cwd()), "is_root": IS_ROOT})
        try:
            while self._connected:
                try:
                    chunk = self.conn.recv(4096)
                except Exception:
                    break
                if not chunk:
                    break
                self._buf += chunk
                while b"\n" in self._buf:
                    line, self._buf = self._buf.split(b"\n", 1)
                    line = line.strip()
                    if not line:
                        continue
                    try:
                        msg = json.loads(line.decode("utf-8"))
                    except Exception:
                        self.send({"event": "error", "msg": "invalid JSON"})
                        continue
                    self._dispatch(msg)
        except Exception:  # ignorowane celowo
            pass
        finally:
            self._connected = False
            with _GUI_CLIENTS_LOCK:
                if self in _GUI_CLIENTS:
                    _GUI_CLIENTS.remove(self)
            try: self.conn.close()
            except Exception:
                pass  # ignorowane celowo
            _slog("gui", f"GUI klient rozłączony: {self.addr}")

    def _dispatch(self, msg: dict):
        req_id = msg.get("id")
        action = msg.get("cmd") or msg.get("action") or msg.get("type", "")

        def _reply(data: dict):
            if req_id is not None:
                data["id"] = req_id
            data["done"] = True
            self.send(data)

        if action in ("ping", "hello"):
            _reply({"event": "pong",
                    "ts": datetime.datetime.now().isoformat()})

        elif action == "exec":
            cmd_str = msg.get("cmd", action).strip()
            if not cmd_str or cmd_str == "exec":
                cmd_str = msg.get("args", "")
            _slog("gui", f"exec: {cmd_str}")
            # Wyślij "running" przed wykonaniem
            self.send({"event": "running", "cmd": cmd_str, "id": req_id})
            result = self._capture_exec(cmd_str)
            result["event"] = "exec_result"
            _reply(result)
            # Wyślij nowy prompt po wykonaniu
            self.send({"event": "prompt_ready", "cwd": str(Path.cwd()),
                       "is_root": IS_ROOT, "exit_code": result["exit_code"]})

        elif action in ("status", "state"):
            _reply({
                "event":   "status",
                "shell":   SHELL_NAME,
                "version": SHELL_VERSION,
                "cwd":     str(Path.cwd()),
                "is_root": IS_ROOT,
                "online":  is_online(),
                "theme":   _CURRENT_THEME,
                "clients": len(_GUI_CLIENTS),
            })

        elif action == "cwd":
            _reply({"event": "cwd", "cwd": str(Path.cwd())})

        elif action == "ls":
            target = Path(msg.get("path", ".")).expanduser()
            try:
                entries = []
                for child in sorted(target.iterdir()):
                    try:
                        st = child.stat()
                        entries.append({
                            "name":  child.name,
                            "type":  "dir"  if child.is_dir()  else "file",
                            "size":  st.st_size,
                            "mtime": datetime.datetime.fromtimestamp(
                                st.st_mtime).isoformat(),
                        })
                    except Exception:  # ignorowane celowo
                        pass
                _reply({"event": "ls", "path": str(target.resolve()),
                        "entries": entries})
            except Exception as e:
                _reply({"event": "error", "msg": str(e)})

        elif action == "read":
            fpath = Path(msg.get("path", "")).expanduser()
            try:
                content = fpath.read_text(encoding="utf-8", errors="replace")
                _reply({"event": "read", "path": str(fpath.resolve()),
                        "content": content})
            except Exception as e:
                _reply({"event": "error", "msg": str(e)})

        elif action == "write":
            fpath   = Path(msg.get("path", "")).expanduser()
            content = msg.get("content", "")
            try:
                fpath.write_text(content, encoding="utf-8")
                _reply({"event": "write_ok", "path": str(fpath.resolve()),
                        "bytes": len(content.encode())})
            except Exception as e:
                _reply({"event": "error", "msg": str(e)})

        elif action == "env_get":
            key = msg.get("key")
            if key:
                _reply({"event": "env", "key": key,
                        "value": SHELL_VARS.get(key, os.environ.get(key))})
            else:
                _reply({"event": "env", "vars": dict(SHELL_VARS)})

        elif action == "env_set":
            key, value = msg.get("key",""), str(msg.get("value",""))
            if key:
                SHELL_VARS[key] = value
                _reply({"event": "ok", "key": key, "value": value})

        elif action == "history":
            limit = int(msg.get("limit", 50))
            _reply({"event": "history", "history": HISTORY[-limit:]})

        else:
            _reply({"event": "error",
                    "msg":  f"Unknown action: {action!r}",
                    "hint": "Valid: exec, status, ls, read, write, env_get, env_set, history, ping"})

class _GuiServer:
    """IPC backend przez Unix socket (Linux/macOS) lub TCP fallback (Windows)."""

    def __init__(self, socket_path: str = "", port: int = 7702):
        self.port        = port
        self._use_unix   = (os.name != "nt")
        # Ścieżka Unix socket lub TCP host:port
        if socket_path:
            self.socket_path = socket_path
        else:
            self.socket_path = str(_BASE / ".terminalx_gui.sock")
        self._sock: _sock.socket | None = None
        self._thread: _threading.Thread | None = None
        self._start_time = None

    def start(self) -> bool:
        try:
            if self._use_unix:
                # Usuń stary socket jeśli istnieje
                try:
                    os.unlink(self.socket_path)
                except FileNotFoundError:
                    pass
                self._sock = _sock.socket(_sock.AF_UNIX, _sock.SOCK_STREAM)
                self._sock.bind(self.socket_path)
                addr_desc = self.socket_path
            else:
                self._sock = _sock.socket(_sock.AF_INET, _sock.SOCK_STREAM)
                self._sock.setsockopt(_sock.SOL_SOCKET, _sock.SO_REUSEADDR, 1)
                self._sock.bind(("127.0.0.1", self.port))
                addr_desc = f"127.0.0.1:{self.port}"
            self._sock.listen(5)
            self._sock.settimeout(1.0)
            self._thread = _threading.Thread(
                target=self._accept_loop, daemon=True,
                name="TerminalX-gui")
            self._thread.start()
            self._start_time = datetime.datetime.now()
            _slog("gui", f"Uruchomiono IPC: {addr_desc}")
            return True
        except OSError as e:
            _slog("gui", f"Blad startu GUI: {e}", "ERROR")
            return False

    def _accept_loop(self):
        while self._sock:
            try:
                conn, addr = self._sock.accept()
            except _sock.timeout:
                continue
            except Exception:
                break
            client = _GuiClient(conn, addr)
            with _GUI_CLIENTS_LOCK:
                _GUI_CLIENTS.append(client)
            _slog("gui", f"GUI klient połączony: {addr}")
            t = _threading.Thread(target=client.handle, daemon=True,
                                  name=f"gui-client-{addr}")
            t.start()

    def stop(self):
        s = self._sock
        self._sock = None
        if s:
            try: s.close()
            except Exception:
                pass  # ignorowane celowo
        # Usuń plik socket
        if self._use_unix:
            try: os.unlink(self.socket_path)
            except Exception:
                pass  # ignorowane celowo
        with _GUI_CLIENTS_LOCK:
            for client in list(_GUI_CLIENTS):
                try: client.conn.close()
                except Exception:
                    pass  # ignorowane celowo
            _GUI_CLIENTS.clear()
        _slog("gui", "Zatrzymano")

    @property
    def running(self) -> bool:
        return (self._sock is not None and
                self._thread is not None and self._thread.is_alive())

    @property
    def uptime(self) -> str:
        if not self._start_time: return "—"
        delta = datetime.datetime.now() - self._start_time
        s = int(delta.total_seconds())
        return f"{s//3600:02d}:{(s%3600)//60:02d}:{s%60:02d}"

    def broadcast(self, data: dict):
        with _GUI_CLIENTS_LOCK:
            for client in list(_GUI_CLIENTS):
                try: client.send(data)
                except Exception:
                    pass  # ignorowane celowo

# ── Hook: after_cmd → rozgłoś zdarzenie do GUI klientów ─────────────────────

def _integration_after_cmd_hook(cmd_name: str, args: list, exit_code: int):
    """Powiadamia GUI i WS klientów po każdej komendzie."""
    event = {
        "event":     "after_cmd",
        "cmd":       cmd_name,
        "exit_code": exit_code,
        "cwd":       str(Path.cwd()),
        "ts":        datetime.datetime.now().isoformat(),
    }
    # GUI broadcast
    gui_srv = _SERVERS.get("gui")
    if gui_srv and gui_srv.running:
        gui_srv.broadcast({**event, "event": "cmd_done"})
    # WS broadcast
    _ws_broadcast_event("after_cmd", event)

# Zarejestruj hook globalnie przy imporcie modułu
PLUGIN_HOOKS["after_cmd"].append(_integration_after_cmd_hook)

# ██  KOMENDY SHELLA  █████████████████████████████████████████████████████████

def _srv_status_box(w: int):
    """Wyświetla tabelę statusu wszystkich serwerów."""
    print()
    print(box_top("Serwery integracji  TerminalX", width=w, color=C.EXEC))
    header = (f"  {C.BOLD}{'Serwer':<12}{'Status':<12}"
              f"{'Adres':<30}{'Uptime':<10}{'Klienci'}{C.RESET}")
    print(box_row(header, width=w, color=C.EXEC))
    print(box_sep(width=w, color=C.EXEC))

    rest_srv = _SERVERS["rest"]
    ws_srv   = _SERVERS["websocket"]
    gui_srv  = _SERVERS["gui"]

    def _row(name, srv, addr, clients_fn):
        if srv and srv.running:
            status  = f"{C.PATH}● DZIAŁA{C.RESET}"
            uptime  = srv.uptime
            clients = str(clients_fn())
        else:
            status  = f"{C.DIM}○ stop{C.RESET}"
            uptime  = "—"
            clients = "—"
        print(box_row(
            f"  {C.BOLD}{name:<12}{C.RESET}{status:<21}{C.DIM}{addr:<30}{C.RESET}"
            f"{C.DIM}{uptime:<10}{clients}{C.RESET}",
            width=w, color=C.EXEC))

    rest_addr = f"http://{rest_srv.host}:{rest_srv.port}" if rest_srv else "http://127.0.0.1:7700"
    ws_addr   = f"ws://{ws_srv.host}:{ws_srv.port}"       if ws_srv   else "ws://127.0.0.1:7701"
    gui_addr  = (gui_srv.socket_path if gui_srv and hasattr(gui_srv, 'socket_path')
                 else str(_BASE / ".terminalx_gui.sock"))

    _row("REST API",  rest_srv, rest_addr,  lambda: "—")
    _row("WebSocket", ws_srv,   ws_addr,    lambda: len(_WS_CLIENTS))
    _row("GUI IPC",   gui_srv,  gui_addr,   lambda: len(_GUI_CLIENTS))

    print(box_sep(width=w, color=C.EXEC))
    print(box_row(
        f"  {C.DIM}serve start|stop  ·  wss start|stop  ·  gui start|stop  ·  serve log{C.RESET}",
        width=w, color=C.EXEC))
    print(box_bottom(width=w, color=C.EXEC))
    print()

# ── serve (REST API) ──────────────────────────────────────────────────────────

@command("serve", "REST API serwer na localhost (HTTP/JSON)",
         aliases=["api", "restapi", "apiserver"],
         flags=["start", "stop", "status", "log"])
def cmd_serve(args):
    """
    serve                     — status wszystkich serwerów
    serve start [port]        — uruchom REST API (domyslnie :7700)
    serve start --token <key> — uruchom z autoryzacja Bearer
    serve stop                — zatrzymaj REST API
    serve log [-n N]          — ostatnie N requestow (domyslnie 20)
    serve test                — wyslij testowy request GET /api/v1/status

    Endpointy:
      GET  /api/v1/status   GET  /api/v1/commands  GET  /api/v1/env
      GET  /api/v1/history  GET  /api/v1/plugins    GET  /api/v1/version
      GET  /api/v1/files    GET  /api/v1/read        POST /api/v1/exec
      POST /api/v1/env      POST /api/v1/write       POST /api/v1/plugin/reload

    Przyklad (curl):
      curl http://localhost:7700/api/v1/status
      curl -X POST http://localhost:7700/api/v1/exec \\
           -H 'Content-Type: application/json' \\
           -d '{"cmd":"ls -la"}'
    """
    sub = args[0].lower() if args else ""
    w   = min(terminal_width() - 2, 72)

    if not sub or sub == "status":
        _srv_status_box(w); return

    if sub == "start":
        if _SERVERS["rest"] and _SERVERS["rest"].running:
            print_error("REST API już działa.",
                        f"http://{_SERVERS['rest'].host}:{_SERVERS['rest'].port}"); return
        port = 7700
        token = ""
        clean = [a for a in args[1:] if not a.startswith("-")]
        if clean:
            try: port = int(clean[0])
            except ValueError: pass
        if "--token" in args:
            idx = args.index("--token")
            if idx + 1 < len(args):
                token = args[idx + 1]
        srv = _RestServer("127.0.0.1", port, auth_token=token)
        if srv.start():
            _SERVERS["rest"] = srv
            print_info(f"REST API uruchomione: {C.PATH}http://127.0.0.1:{port}/api/v1{C.RESET}")
            if token:
                print_info(f"Auth: {C.DIM}Bearer {token[:8]}...{C.RESET}")
            print_info(f"{C.DIM}Dokumentacja: GET /api/v1{C.RESET}")
        else:
            print_error(f"Nie udalo sie uruchomic REST API na porcie {port}.",
                        "Sprawdz czy port nie jest zajety (serve log).")
        return

    if sub == "stop":
        srv = _SERVERS["rest"]
        if not srv or not srv.running:
            print_error("REST API nie jest uruchomione."); return
        srv.stop()
        _SERVERS["rest"] = None
        print_info("REST API zatrzymane."); return

    if sub == "log":
        n = 20
        if "-n" in args:
            idx = args.index("-n")
            if idx + 1 < len(args):
                try: n = int(args[idx + 1])
                except ValueError: pass
        entries = [e for e in _SERVER_LOG if e["server"] == "rest"][-n:]
        if not entries:
            print_info("Brak wpisow w logu REST API."); return
        print()
        print(box_top(f"Log REST API  (ostatnie {len(entries)})", width=w, color=C.DIM))
        for e in entries:
            lc = C.ERROR if e["level"] == "ERROR" else C.DIM
            print(box_row(
                f"  {C.DIM}{e['ts']}{C.RESET}  {lc}{e['msg']}{C.RESET}",
                width=w, color=C.DIM))
        print(box_bottom(width=w, color=C.DIM))
        print(); return

    if sub == "test":
        srv = _SERVERS["rest"]
        if not srv or not srv.running:
            print_error("REST API nie jest uruchomione. Uruchom: serve start"); return
        try:
            import urllib.request as _ur
            # Połączenie wyłącznie do localhost (127.0.0.1) — nie wysyła danych na zewnątrz
            url = f"http://127.0.0.1:{srv.port}/api/v1/status"
            with _ur.urlopen(url, timeout=3) as resp:
                data = json.loads(resp.read())
            print()
            print(box_top(f"Test REST API — {url}", width=w, color=C.PATH))
            for k, v in data.items():
                print(box_row(kv_row(str(k), str(v), key_color=C.DIM),
                              width=w, color=C.PATH))
            print(box_bottom(width=w, color=C.PATH))
            print()
        except Exception as e:
            print_error(f"Test nie powiodl sie: {e}"); return

    else:
        print_error(f"Nieznana podkomenda: {sub}",
                    "Uzycie: serve start|stop|status|log|test")

# ── wss (WebSocket) ───────────────────────────────────────────────────────────

@command("wss", "WebSocket serwer na localhost (RFC 6455)",
         aliases=["websocket", "wsserver"],
         flags=["start", "stop", "status", "broadcast"])
def cmd_wss(args):
    """
    wss                       — status serwera WebSocket
    wss start [port]          — uruchom (domyslnie :7701)
    wss stop                  — zatrzymaj
    wss broadcast <tekst>     — wyslij wiadomosc do wszystkich klientow
    wss clients               — lista podlaczonych klientow

    Protokol (JSON frames):
      Klient → { "type":"exec",      "cmd":"ls",  "id":1 }
      Shell  → { "type":"exec_result","stdout":"...","exit_code":0,"id":1 }
      Klient → { "type":"ping" }
      Shell  → { "type":"pong" }
      Klient → { "type":"subscribe",  "events":["cmd_done"] }
      Klient → { "type":"status" }
      Klient → { "type":"env_set",    "key":"X","value":"Y" }

    Przyklad JavaScript:
      const ws = new WebSocket('ws://localhost:7701');
      ws.onopen = () => ws.send(JSON.stringify({type:'exec',cmd:'ls'}));
      ws.onmessage = e => console.log(JSON.parse(e.data));
    """
    sub = args[0].lower() if args else ""
    w   = min(terminal_width() - 2, 72)

    if not sub or sub == "status":
        _srv_status_box(w); return

    if sub == "start":
        if _SERVERS["websocket"] and _SERVERS["websocket"].running:
            print_error("WebSocket serwer już działa."); return
        port = 7701
        clean = [a for a in args[1:] if not a.startswith("-")]
        if clean:
            try: port = int(clean[0])
            except ValueError: pass
        srv = _WsServer("127.0.0.1", port)
        if srv.start():
            _SERVERS["websocket"] = srv
            print_info(f"WebSocket serwer uruchomiony: {C.PATH}ws://127.0.0.1:{port}{C.RESET}")
            print_info(f"{C.DIM}Protokol: JSON frames  |  wss broadcast <msg>{C.RESET}")
        else:
            print_error(f"Nie udalo sie uruchomic WebSocket na porcie {port}.")
        return

    if sub == "stop":
        srv = _SERVERS["websocket"]
        if not srv or not srv.running:
            print_error("WebSocket serwer nie jest uruchomiony."); return
        srv.stop()
        _SERVERS["websocket"] = None
        print_info("WebSocket serwer zatrzymany."); return

    if sub == "broadcast":
        if len(args) < 2:
            print_error("Podaj wiadomosc: wss broadcast <tekst>"); return
        msg_txt = " ".join(args[1:])
        payload = json.dumps({"type": "broadcast", "msg": msg_txt,
                              "ts": datetime.datetime.now().isoformat()},
                             ensure_ascii=False).encode("utf-8")
        with _WS_CLIENTS_LOCK:
            sent = 0
            for client in list(_WS_CLIENTS):
                try:
                    _ws_send_frame(client.conn, payload)
                    sent += 1
                except Exception:  # ignorowane celowo
                    pass
        print_info(f"Wyslano do {sent} klientow: {msg_txt[:60]}"); return

    if sub == "clients":
        with _WS_CLIENTS_LOCK:
            clients = list(_WS_CLIENTS)
        if not clients:
            print_info("Brak podłączonych klientów."); return
        print()
        print(box_top(f"Klienci WebSocket ({len(clients)})", width=w, color=C.INFO))
        for i, c in enumerate(clients, 1):
            subs = ", ".join(c.subscriptions) or "*"
            print(box_row(
                f"  {C.BOLD}{i}{C.RESET}  {C.DIM}{c.addr}{C.RESET}"
                f"  uptime:{c.uptime}  sub:[{subs}]",
                width=w, color=C.INFO))
        print(box_bottom(width=w, color=C.INFO))
        print(); return

    print_error(f"Nieznana podkomenda: {sub}",
                "Uzycie: wss start|stop|status|broadcast|clients")

# ── gui (IPC backend) ─────────────────────────────────────────────────────────

@command("gui", "GUI backend przez IPC socket (NDJSON)",
         aliases=["guiserver", "ipc", "backend"],
         flags=["start", "stop", "status", "send"])
def cmd_gui(args):
    """
    gui                        — status backendu GUI
    gui start [sciezka|port]   — uruchom IPC (Unix socket lub TCP)
    gui stop                   — zatrzymaj
    gui send <json>            — wyslij wiadomosc do wszystkich GUI klientow
    gui clients                — lista polaczonych klientow

    Protokol (NDJSON — newline-delimited JSON):
      Klient → { "id":1, "cmd":"exec",   "args":"ls -la" }
      Shell  → { "id":1, "event":"exec_result", "stdout":"...",
                 "exit_code":0, "done":true }
      Shell  → { "event":"prompt_ready", "cwd":"/home/...", "is_root":false }

      Zdarzenia:  connected  cmd_done  prompt_ready  after_cmd

    Przyklad Python klienta:
      import socket, json
      s = socket.socket(socket.AF_UNIX, socket.SOCK_STREAM)
      s.connect('/path/to/.terminalx_gui.sock')
      s.sendall(json.dumps({"id":1,"cmd":"exec","args":"ls"}).encode()+'\\n')
      print(s.recv(4096).decode())

    Przyklad TCP (Windows):
      import socket, json
      s = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
      s.connect(('127.0.0.1', 7702))
    """
    sub = args[0].lower() if args else ""
    w   = min(terminal_width() - 2, 72)

    if not sub or sub == "status":
        _srv_status_box(w); return

    if sub == "start":
        if _SERVERS["gui"] and _SERVERS["gui"].running:
            print_error("GUI backend już działa."); return
        socket_path = ""
        port = 7702
        clean = [a for a in args[1:] if not a.startswith("-")]
        if clean:
            if "/" in clean[0] or "\\" in clean[0]:
                socket_path = clean[0]
            else:
                try: port = int(clean[0])
                except ValueError: socket_path = clean[0]
        srv = _GuiServer(socket_path=socket_path, port=port)
        if srv.start():
            _SERVERS["gui"] = srv
            if os.name != "nt":
                print_info(f"GUI IPC uruchomiony: {C.PATH}{srv.socket_path}{C.RESET}")
            else:
                print_info(f"GUI IPC uruchomiony: {C.PATH}127.0.0.1:{port}{C.RESET}")
            print_info(f"{C.DIM}Protokol: NDJSON  |  gui send '{{\"cmd\":\"ping\"}}'{C.RESET}")
        else:
            print_error("Nie udalo sie uruchomic GUI backendu.")
        return

    if sub == "stop":
        srv = _SERVERS["gui"]
        if not srv or not srv.running:
            print_error("GUI backend nie jest uruchomiony."); return
        srv.stop()
        _SERVERS["gui"] = None
        print_info("GUI backend zatrzymany."); return

    if sub == "send":
        if len(args) < 2:
            print_error("Podaj JSON: gui send '{\"event\":\"reload\"}'"); return
        raw = " ".join(args[1:])
        try:
            data = json.loads(raw)
        except json.JSONDecodeError as e:
            print_error(f"Nieprawidlowy JSON: {e}"); return
        srv = _SERVERS["gui"]
        if not srv or not srv.running:
            print_error("GUI backend nie jest uruchomiony. Uruchom: gui start"); return
        srv.broadcast(data)
        print_info(f"Wyslano do {len(_GUI_CLIENTS)} klientow GUI."); return

    if sub == "clients":
        with _GUI_CLIENTS_LOCK:
            clients = list(_GUI_CLIENTS)
        if not clients:
            print_info("Brak podłączonych klientów GUI."); return
        print()
        print(box_top(f"Klienci GUI ({len(clients)})", width=w, color=C.INFO))
        for i, c in enumerate(clients, 1):
            print(box_row(
                f"  {C.BOLD}{i}{C.RESET}  {C.DIM}{c.addr}{C.RESET}",
                width=w, color=C.INFO))
        print(box_bottom(width=w, color=C.INFO))
        print(); return

    print_error(f"Nieznana podkomenda: {sub}",
                "Uzycie: gui start|stop|status|send|clients")

# SERVER EXTENSIONS
#
#   Rozszerzenia trybu serwerowego (wszystkie standalone, bez instalacji):
#
#   1. SSE (Server-Sent Events)           GET /api/v1/events
#      Strumieniowanie zdarzeń shella do przeglądarki / curl w czasie rzeczywistym
#
#   2. Rate Limiting                      wbudowany w _RestHandler
#      Per-IP limitowanie requestów (okno czasowe, konfigurowalne)
#
#   3. Remote Shell (SSH-like TCP)        serve remote [port]
#      Pełna interaktywna powłoka przez gniazdo TCP (netcat-compatible)
#
#   4. Web Panel (wbudowane HTML/JS)      GET /
#      Przeglądarkowy terminal + dashboard bez zewnętrznych plików
#
#   5. OpenAPI 3.0 schema                 GET /api/v1/openapi.json
#      Automatycznie generowany opis API (kompatybilny ze Swagger UI)
#
#   6. Webhook outbound                   serve webhook add|list|remove|test
#      Wysyła POST na zewnętrzny URL przy zdarzeniach shella
#
#   7. Daemon mode (PID file)             serve daemon start|stop|status
#      Uruchomienie jako daemon w tle z zapisem PID do pliku
#
#   8. Multi-server start                 serve all [--token X]
#      Uruchamia REST + WebSocket + GUI jedną komendą
#

# ── 1. SSE — Server-Sent Events ──────────────────────────────────────────────
#
#   Klienci mogą subskrybować zdarzenia shella strumieniem HTTP:
#     curl http://localhost:7700/api/v1/events
#     curl http://localhost:7700/api/v1/events?filter=cmd_done,error
#
#   Format SSE (text/event-stream):
#     event: cmd_done
#     data: {"cmd":"ls","exit_code":0,"ts":"..."}
#
#     event: prompt_ready
#     data: {"cwd":"/home/user","is_root":false}
#
#     event: error
#     data: {"msg":"...","context":"..."}

_SSE_CLIENTS: list  = []    # list of queue.Queue
_SSE_LOCK           = _threading.Lock()
_SSE_MAX_CLIENTS    = 16    # max jednoczesnych SSE subskrybentów
_SSE_KEEPALIVE_SEC  = 15    # co ile sekund wysyłamy komentarz keepalive

def _sse_publish(event: str, data: dict):
    """Publikuje zdarzenie do wszystkich aktywnych SSE klientów."""
    payload = (
        f"event: {event}\n"
        f"data: {json.dumps(data, ensure_ascii=False, default=str)}\n\n"
    ).encode("utf-8")
    with _SSE_LOCK:
        dead = []
        for q in _SSE_CLIENTS:
            try:
                q.put_nowait(payload)
            except Exception:
                dead.append(q)
        for q in dead:
            _SSE_CLIENTS.remove(q)

def _sse_hook_after_cmd(cmd_name: str, args: list, exit_code: int):
    """Hook after_cmd → SSE event."""
    _sse_publish("cmd_done", {
        "cmd":       cmd_name,
        "args":      args,
        "exit_code": exit_code,
        "cwd":       str(Path.cwd()),
        "ts":        datetime.datetime.now().isoformat(timespec="seconds"),
    })

def _sse_stream_handler(handler: "_RestHandler", filter_events: set):
    """
    Obsługuje SSE endpoint — blokuje wątek HTTP do czasu rozłączenia klienta.
    Wywoływana z _RestHandler.do_GET dla /api/v1/events.
    """
    if len(_SSE_CLIENTS) >= _SSE_MAX_CLIENTS:
        handler._send_error_json("Too many SSE clients", 503)
        return

    q: "_queue.Queue[bytes | None]" = _queue.Queue(maxsize=64)

    handler.send_response(200)
    handler.send_header("Content-Type",  "text/event-stream; charset=utf-8")
    handler.send_header("Cache-Control", "no-cache")
    handler.send_header("Connection",    "keep-alive")
    handler.send_header("Access-Control-Allow-Origin", "*")
    handler.send_header("X-Accel-Buffering", "no")   # nginx: wyłącz buforowanie
    handler.end_headers()

    # Wyślij połączenie handshake + snapshot stanu
    hello = _sse_publish_snapshot()
    try:
        handler.wfile.write(hello)
        handler.wfile.flush()
    except Exception:
        return

    with _SSE_LOCK:
        _SSE_CLIENTS.append(q)

    _slog("rest", f"SSE klient podłączony ({len(_SSE_CLIENTS)} aktywnych)")

    try:
        while True:
            try:
                chunk = q.get(timeout=_SSE_KEEPALIVE_SEC)
                if chunk is None:
                    break   # sygnał zamknięcia
            except _queue.Empty:
                # keepalive comment
                chunk = b": keepalive\n\n"

            # Filtruj zdarzenia jeśli klient podał filter=
            if filter_events and chunk.startswith(b"event:"):
                evt_line = chunk.split(b"\n")[0].decode("utf-8", errors="replace")
                evt_name = evt_line.split(":", 1)[1].strip()
                if evt_name not in filter_events:
                    continue

            try:
                handler.wfile.write(chunk)
                handler.wfile.flush()
            except (BrokenPipeError, ConnectionResetError, OSError):
                break
    finally:
        with _SSE_LOCK:
            if q in _SSE_CLIENTS:
                _SSE_CLIENTS.remove(q)
        _slog("rest", f"SSE klient rozłączony ({len(_SSE_CLIENTS)} aktywnych)")

def _sse_publish_snapshot() -> bytes:
    """Zwraca początkowy snapshot stanu shella jako SSE event."""
    data = {
        "shell":   f"{SHELL_NAME} v{SHELL_VERSION}",
        "cwd":     str(Path.cwd()),
        "is_root": bool(os.environ.get("IS_ROOT", False)),
        "servers": {k: bool(v and v.running) for k, v in _SERVERS.items()},
        "ts":      datetime.datetime.now().isoformat(timespec="seconds"),
    }
    return (
        f"event: connected\n"
        f"data: {json.dumps(data, ensure_ascii=False)}\n\n"
    ).encode("utf-8")

# Zarejestruj SSE hook w PLUGIN_HOOKS
PLUGIN_HOOKS.setdefault("after_cmd", []).append(_sse_hook_after_cmd)

# ── 2. Rate Limiting ──────────────────────────────────────────────────────────
#
#   Per-IP sliding window rate limiter wbudowany w _RestHandler.
#   Domyślnie: 60 requestów / 60 sekund per IP.
#   Konfiguracja: _RATE_LIMIT_MAX, _RATE_LIMIT_WINDOW_SEC

_RATE_LIMIT_MAX        = 60    # requestów per okno
_RATE_LIMIT_WINDOW_SEC = 60    # szerokość okna (sekundy)
_RATE_LIMIT_TABLE: dict[str, list[float]] = {}   # ip → [timestamps]
_RATE_LIMIT_LOCK       = _threading.Lock()

def _rate_check(ip: str) -> tuple[bool, int]:
    """
    Sprawdza czy IP nie przekroczyło limitu.
    Zwraca (allowed: bool, remaining: int).
    """
    now = _time_mod.monotonic()
    cutoff = now - _RATE_LIMIT_WINDOW_SEC

    with _RATE_LIMIT_LOCK:
        hits = _RATE_LIMIT_TABLE.get(ip, [])
        hits = [t for t in hits if t > cutoff]   # usuń stare
        remaining = _RATE_LIMIT_MAX - len(hits)
        if remaining <= 0:
            _RATE_LIMIT_TABLE[ip] = hits
            return False, 0
        hits.append(now)
        _RATE_LIMIT_TABLE[ip] = hits
        return True, remaining - 1

def _rate_purge_old():
    """Czyści stare wpisy z tabeli (wywoływane co jakiś czas)."""
    now = _time_mod.monotonic()
    cutoff = now - _RATE_LIMIT_WINDOW_SEC
    with _RATE_LIMIT_LOCK:
        for ip in list(_RATE_LIMIT_TABLE):
            _RATE_LIMIT_TABLE[ip] = [t for t in _RATE_LIMIT_TABLE[ip] if t > cutoff]
            if not _RATE_LIMIT_TABLE[ip]:
                del _RATE_LIMIT_TABLE[ip]

# Wstrzyknij rate limiting do _RestHandler — monkey-patch do_GET i do_POST

_orig_RestHandler_do_GET  = _RestHandler.do_GET
_orig_RestHandler_do_POST = _RestHandler.do_POST

def _rl_do_GET(self):
    ip = self.client_address[0]
    allowed, remaining = _rate_check(ip)
    if not allowed:
        self.send_response(429)
        self.send_header("Content-Type", "application/json")
        self.send_header("Retry-After", str(_RATE_LIMIT_WINDOW_SEC))
        self.send_header("X-RateLimit-Limit",     str(_RATE_LIMIT_MAX))
        self.send_header("X-RateLimit-Remaining", "0")
        self.send_header("Access-Control-Allow-Origin", "*")
        self.end_headers()
        self.wfile.write(b'{"error":"Rate limit exceeded","code":429}')
        _slog("rest", f"Rate limit: {ip}", "WARN")
        return
    self.send_header  # nie wywołujemy przed oryginalną metodą
    # Dodaj nagłówki RL przez patch _send_json
    _orig_RestHandler_do_GET(self)

def _rl_do_POST(self):
    ip = self.client_address[0]
    allowed, remaining = _rate_check(ip)
    if not allowed:
        self.send_response(429)
        self.send_header("Content-Type", "application/json")
        self.send_header("Retry-After", str(_RATE_LIMIT_WINDOW_SEC))
        self.send_header("Access-Control-Allow-Origin", "*")
        self.end_headers()
        self.wfile.write(b'{"error":"Rate limit exceeded","code":429}')
        _slog("rest", f"Rate limit POST: {ip}", "WARN")
        return
    _orig_RestHandler_do_POST(self)

_RestHandler.do_GET  = _rl_do_GET
_RestHandler.do_POST = _rl_do_POST

# Wstrzyknij obsługę SSE i Web Panel do _route_get

_orig_route_get = _RestHandler._route_get

def _extended_route_get(self, path: str, q: dict):
    # ── SSE endpoint ─────────────────────────────────────────────────────
    if path == "/api/v1/events":
        filt_str = q.get("filter", "")
        filt_set = set(filt_str.split(",")) if filt_str else set()
        _sse_stream_handler(self, filt_set)
        return

    # ── OpenAPI 3.0 schema ────────────────────────────────────────────────
    if path in ("/api/v1/openapi.json", "/api/openapi.json", "/openapi.json"):
        # Wywołaj zawsze najnowszą wersję (może być nadpisana przez v2)
        builder = globals().get("_build_openapi_schema_v2") or _build_openapi_schema
        self._send_json(builder())
        return

    # ── Web Panel (wbudowany HTML terminal) ──────────────────────────────
    if path in ("/", "/panel", "/ui", "/terminal"):
        html = _build_web_panel()
        body = html.encode("utf-8")
        self.send_response(200)
        self.send_header("Content-Type",  "text/html; charset=utf-8")
        self.send_header("Content-Length", str(len(body)))
        self.send_header("X-Shell", f"{SHELL_NAME}/{SHELL_VERSION}")
        self.end_headers()
        self.wfile.write(body)
        return

    # ── Rate limit status (admin) ─────────────────────────────────────────
    if path == "/api/v1/ratelimit":
        with _RATE_LIMIT_LOCK:
            table_copy = {ip: len(ts) for ip, ts in _RATE_LIMIT_TABLE.items()}
        self._send_json({
            "limit":   _RATE_LIMIT_MAX,
            "window":  _RATE_LIMIT_WINDOW_SEC,
            "clients": table_copy,
        })
        return

    # Przekaż do oryginalnego routera
    _orig_route_get(self, path, q)

_RestHandler._route_get = _extended_route_get

# Wstrzyknij POST webhook do _route_post

_orig_route_post = _RestHandler._route_post

def _extended_route_post(self, path: str, body: dict):
    # ── Webhook management ────────────────────────────────────────────────
    if path == "/api/v1/webhook":
        sub = body.get("action", "")
        if sub == "add":
            url    = body.get("url", "")
            events = body.get("events", ["cmd_done"])
            if not url:
                self._send_error_json("Pole 'url' wymagane"); return
            wh = _webhook_add(url, events)
            self._send_json({"ok": True, "webhook": wh})
        elif sub == "list":
            self._send_json({"webhooks": _WEBHOOKS})
        elif sub == "remove":
            wid = body.get("id", "")
            ok  = _webhook_remove(wid)
            self._send_json({"ok": ok})
        elif sub == "test":
            wid = body.get("id", "")
            ok, msg = _webhook_test(wid)
            self._send_json({"ok": ok, "msg": msg})
        else:
            self._send_error_json("action: add|list|remove|test")
        return

    _orig_route_post(self, path, body)

_RestHandler._route_post = _extended_route_post

# ── 3. Remote Shell (SSH-like TCP) ────────────────────────────────────────────
#
#   Pełna interaktywna powłoka przez TCP — kompatybilna z netcat, telnet.
#   NIE szyfrowana (localhost only) — do remote przez SSH tunnel.
#
#   serve remote start [port]  — uruchom (domyślnie :7703)
#   serve remote stop          — zatrzymaj
#   serve remote connect       — połącz się (interaktywnie, jeśli lokalnie)
#
#   Protokół: surowe bajty UTF-8 (prompt → komenda → wynik → prompt)
#   Każda sesja to osobny wątek.

_REMOTE_SESSIONS: list  = []   # aktywne sesje _RemoteSession
_REMOTE_LOCK            = _threading.Lock()
_REMOTE_MAX_SESSIONS    = 8
_REMOTE_BANNER          = (
    f"\r\n"
    f"  ╔══════════════════════════════════════╗\r\n"
    f"  ║  {SHELL_NAME} v{SHELL_VERSION} — Remote Shell     ║\r\n"
    f"  ║  Wyjście: exit | Ctrl+D              ║\r\n"
    f"  ╚══════════════════════════════════════╝\r\n\r\n"
).encode("utf-8")

class _RemoteSession:
    """Jedna sesja remote shell przez TCP."""

    def __init__(self, conn: "_sock.socket", addr: tuple):
        self.conn      = conn
        self.addr      = addr
        self.alive     = True
        self.started   = datetime.datetime.now()
        self._thread: "_threading.Thread | None" = None

    def start(self):
        self._thread = _threading.Thread(
            target=self._run, daemon=True,
            name=f"TerminalX-remote-{self.addr[0]}:{self.addr[1]}")
        self._thread.start()

    def _send(self, data: "str | bytes"):
        if isinstance(data, str):
            data = data.encode("utf-8")
        try:
            self.conn.sendall(data)
        except Exception:
            self.alive = False

    def _run(self):
        self._send(_REMOTE_BANNER)
        _slog("remote", f"Nowa sesja: {self.addr[0]}:{self.addr[1]}")

        with _REMOTE_LOCK:
            _REMOTE_SESSIONS.append(self)

        try:
            while self.alive:
                # Wyślij prompt
                prompt_str = (
                    f"[remote@{SHELL_NAME}] "
                    f"{Path.cwd().name}$ "
                )
                self._send(prompt_str)

                # Odbierz linię
                buf = b""
                while self.alive:
                    try:
                        ch = self.conn.recv(1)
                    except Exception:
                        self.alive = False
                        break
                    if not ch:
                        self.alive = False
                        break
                    if ch in (b"\r", b"\n"):
                        self._send(b"\r\n")
                        break
                    if ch == b"\x7f" or ch == b"\x08":   # backspace
                        if buf:
                            buf = buf[:-1]
                            self._send(b"\x08 \x08")
                    elif ch == b"\x04":   # Ctrl+D
                        self.alive = False
                        break
                    elif ch[0] >= 0x20:   # printable
                        buf += ch
                        self._send(ch)   # echo

                if not self.alive:
                    break

                line = buf.decode("utf-8", errors="replace").strip()
                if not line:
                    continue
                if line.lower() in ("exit", "quit", "logout"):
                    self._send("  Do widzenia!\r\n")
                    break

                # Wykonaj komendę
                import io as _sio_r
                buf_out = _sio_r.StringIO()
                buf_err = _sio_r.StringIO()
                old_out, old_err = sys.stdout, sys.stderr
                try:
                    sys.stdout = buf_out
                    sys.stderr = buf_err
                    execute_line(line)
                except SystemExit:
                    pass
                except Exception as e:
                    buf_err.write(str(e))
                finally:
                    sys.stdout = old_out
                    sys.stderr = old_err

                out = buf_out.getvalue()
                err = buf_err.getvalue()

                # Wyślij wynik (zamień \n → \r\n dla terminali)
                if out:
                    self._send(out.replace("\n", "\r\n"))
                if err:
                    self._send(f"\r\n  ERROR: {err}\r\n".replace("\n", "\r\n"))

                _slog("remote", f"{self.addr[0]}: {line[:60]}")

        finally:
            self.alive = False
            try:
                self.conn.close()
            except Exception:  # ignorowane celowo
                pass
            with _REMOTE_LOCK:
                if self in _REMOTE_SESSIONS:
                    _REMOTE_SESSIONS.remove(self)
            _slog("remote", f"Sesja zakończona: {self.addr[0]}:{self.addr[1]}")

    @property
    def uptime(self) -> str:
        delta = datetime.datetime.now() - self.started
        s = int(delta.total_seconds())
        return f"{s//3600:02d}:{(s%3600)//60:02d}:{s%60:02d}"

class _RemoteServer:
    """TCP listener dla remote shell."""

    def __init__(self, host: str = "127.0.0.1", port: int = 7703):
        self.host     = host
        self.port     = port
        self.running  = False
        self._sock: "_sock.socket | None" = None
        self._thread: "_threading.Thread | None" = None
        self._started = None

    def start(self) -> bool:
        try:
            self._sock = _sock.socket(_sock.AF_INET, _sock.SOCK_STREAM)
            self._sock.setsockopt(_sock.SOL_SOCKET, _sock.SO_REUSEADDR, 1)
            self._sock.bind((self.host, self.port))
            self._sock.listen(4)
            self.running = True
            self._started = datetime.datetime.now()
            self._thread  = _threading.Thread(
                target=self._accept_loop, daemon=True,
                name="TerminalX-remote-listener")
            self._thread.start()
            _slog("remote", f"Nasłuchuję na {self.host}:{self.port}")
            return True
        except OSError as e:
            _slog("remote", f"Błąd startu: {e}", "ERROR")
            return False

    def stop(self):
        self.running = False
        if self._sock:
            try:
                self._sock.close()
            except Exception:  # ignorowane celowo
                pass
            self._sock = None
        # Zakończ aktywne sesje
        with _REMOTE_LOCK:
            for s in list(_REMOTE_SESSIONS):
                s.alive = False
        _slog("remote", "Serwer zatrzymany")

    def _accept_loop(self):
        while self.running:
            try:
                conn, addr = self._sock.accept()
            except Exception:
                break
            with _REMOTE_LOCK:
                if len(_REMOTE_SESSIONS) >= _REMOTE_MAX_SESSIONS:
                    conn.sendall(b"Too many sessions. Try later.\r\n")
                    conn.close()
                    continue
            session = _RemoteSession(conn, addr)
            session.start()

    @property
    def uptime(self) -> str:
        if not self._started:
            return "—"
        delta = datetime.datetime.now() - self._started
        s = int(delta.total_seconds())
        return f"{s//3600:02d}:{(s%3600)//60:02d}:{s%60:02d}"

# ── 4. Web Panel (wbudowany HTML/JS terminal) ─────────────────────────────────
#
#   Serwowany przez REST API pod GET /  (lub /panel, /ui)
#   Przeglądarkowy terminal z:
#   - kolorowaniem składni (ANSI → HTML)
#   - historią komend (strzałki góra/dół)
#   - auto-uzupełnianiem przez API /api/v1/commands
#   - live events przez SSE /api/v1/events
#   - widgetem statusu serwerów

def _ansi_to_html_color(code: str) -> str:
    """Zamienia kod ANSI na styl CSS (uproszczone mapowanie)."""
    _MAP = {
        "0": "", "1": "font-weight:bold",
        "31": "color:#e06c75", "32": "color:#98c379",
        "33": "color:#e5c07b", "34": "color:#61afef",
        "35": "color:#c678dd", "36": "color:#56b6c2",
        "37": "color:#abb2bf", "90": "color:#5c6370",
        "91": "color:#e06c75", "92": "color:#98c379",
        "93": "color:#e5c07b", "94": "color:#61afef",
    }
    return _MAP.get(code, "")

def _build_web_panel() -> str:
    """Generuje pełny HTML panelu webowego TerminalXa."""
    base_port = 7700
    srv = _SERVERS.get("rest")
    port = srv.port if srv and srv.running else base_port

    return f"""<!DOCTYPE html>
<html lang="pl">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1">
<title>{SHELL_NAME} v{SHELL_VERSION} — Web Panel</title>
<style>
  :root {{
    --bg: #1e2127; --bg2: #21252b; --bg3: #2c313c;
    --fg: #abb2bf; --fg2: #5c6370; --green: #98c379;
    --blue: #61afef; --yellow: #e5c07b; --red: #e06c75;
    --purple: #c678dd; --cyan: #56b6c2; --border: #3e4451;
    --font: 'Cascadia Code','Fira Code','Consolas',monospace;
  }}
  * {{ box-sizing: border-box; margin: 0; padding: 0; }}
  body {{ background: var(--bg); color: var(--fg); font-family: var(--font);
          font-size: 14px; height: 100vh; display: flex; flex-direction: column; }}
  #header {{ background: var(--bg2); border-bottom: 1px solid var(--border);
             padding: 8px 16px; display: flex; align-items: center; gap: 12px; }}
  #header h1 {{ font-size: 14px; color: var(--blue); }}
  #status-bar {{ display: flex; gap: 16px; margin-left: auto; font-size: 12px; }}
  .srv-badge {{ padding: 2px 8px; border-radius: 3px; background: var(--bg3); }}
  .srv-badge.on {{ color: var(--green); }}
  .srv-badge.off {{ color: var(--fg2); }}
  #main {{ display: flex; flex: 1; overflow: hidden; }}
  #terminal-col {{ flex: 1; display: flex; flex-direction: column; }}
  #output {{ flex: 1; padding: 12px 16px; overflow-y: auto; white-space: pre-wrap;
             word-break: break-all; font-size: 13px; line-height: 1.5; }}
  #output .line {{ margin-bottom: 2px; }}
  #output .prompt {{ color: var(--blue); }}
  #output .error  {{ color: var(--red); }}
  #output .info   {{ color: var(--cyan); }}
  #input-row {{ background: var(--bg2); border-top: 1px solid var(--border);
                padding: 8px 16px; display: flex; align-items: center; gap: 8px; }}
  #prompt-label {{ color: var(--blue); white-space: nowrap; }}
  #cmd-input {{ flex: 1; background: transparent; border: none; outline: none;
                color: var(--fg); font-family: var(--font); font-size: 13px; }}
  #sidebar {{ width: 200px; background: var(--bg2); border-left: 1px solid var(--border);
              overflow-y: auto; padding: 8px 0; display: flex; flex-direction: column; }}
  #sidebar h3 {{ color: var(--fg2); font-size: 11px; text-transform: uppercase;
                 padding: 8px 12px 4px; letter-spacing: 1px; }}
  #events-log {{ flex: 1; overflow-y: auto; padding: 4px 12px; }}
  .evt {{ font-size: 11px; color: var(--fg2); padding: 2px 0;
          border-bottom: 1px solid var(--bg3); }}
  .evt.cmd_done {{ color: var(--green); }}
  .evt.error {{ color: var(--red); }}
  #completions {{ position: absolute; background: var(--bg3); border: 1px solid var(--border);
                  max-height: 160px; overflow-y: auto; z-index: 100;
                  border-radius: 4px; display: none; }}
  .comp-item {{ padding: 3px 10px; cursor: pointer; font-size: 12px; }}
  .comp-item:hover {{ background: var(--border); color: var(--blue); }}
</style>
</head>
<body>
<div id="header">
  <h1>🖥️ {SHELL_NAME} v{SHELL_VERSION}</h1>
  <div id="status-bar">
    <span class="srv-badge on">REST :{port}</span>
    <span class="srv-badge" id="badge-ws">WS —</span>
    <span class="srv-badge" id="badge-sse">SSE ●</span>
    <span id="cwd-label" style="color:var(--yellow);font-size:12px"></span>
  </div>
</div>
<div id="main">
  <div id="terminal-col">
    <div id="output"></div>
    <div id="input-row">
      <span id="prompt-label">TerminalX $</span>
      <input id="cmd-input" type="text" autocomplete="off" spellcheck="false"
             placeholder="wpisz komendę...">
    </div>
  </div>
  <div id="sidebar">
    <h3>Zdarzenia</h3>
    <div id="events-log"></div>
  </div>
</div>
<div id="completions"></div>

<script>
const API = 'http://localhost:{port}/api/v1';
const out = document.getElementById('output');
const inp = document.getElementById('cmd-input');
const evl = document.getElementById('events-log');
const compl = document.getElementById('completions');
let history = [], histIdx = -1, allCmds = [];

function appendLine(text, cls='') {{
  const d = document.createElement('div');
  d.className = 'line ' + cls;
  d.textContent = text;
  out.appendChild(d);
  out.scrollTop = out.scrollHeight;
}}

function appendHTML(html, cls='') {{
  const d = document.createElement('div');
  d.className = 'line ' + cls;
  d.innerHTML = html;
  out.appendChild(d);
  out.scrollTop = out.scrollHeight;
}}

function ansiToHtml(s) {{
  return s
    .replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;')
    .replace(/\x1b[([0-9;]*)m/g, (_, c) => {{
      const codes = {{ '0':'</span>', '1':'<b>', '31':'<span style="color:#e06c75">',
        '32':'<span style="color:#98c379">', '33':'<span style="color:#e5c07b">',
        '34':'<span style="color:#61afef">', '35':'<span style="color:#c678dd">',
        '36':'<span style="color:#56b6c2">', '90':'<span style="color:#5c6370">' }};
      return codes[c] || '';
    }});
}}

async function runCmd(cmd) {{
  appendHTML('<span style="color:#61afef">$ ' + cmd + '</span>', 'prompt');
  try {{
    const r = await fetch(API + '/exec', {{
      method: 'POST',
      headers: {{'Content-Type':'application/json'}},
      body: JSON.stringify({{cmd}})
    }});
    const d = await r.json();
    if (d.stdout) appendHTML(ansiToHtml(d.stdout));
    if (d.stderr) appendLine(d.stderr, 'error');
    if (d.exit_code !== 0) appendLine('↳ exit: ' + d.exit_code, 'error');
  }} catch(e) {{ appendLine('Błąd: ' + e.message, 'error'); }}
}}

async function loadCommands() {{
  try {{
    const r = await fetch(API + '/commands');
    const d = await r.json();
    allCmds = d.commands || [];
  }} catch(e) {{}}
}}

async function updateStatus() {{
  try {{
    const r = await fetch(API + '/status');
    const d = await r.json();
    document.getElementById('cwd-label').textContent = d.cwd || '';
    document.getElementById('prompt-label').textContent =
      (d.is_root ? 'root#' : 'TerminalX$');
  }} catch(e) {{}}
}}

// SSE live events
function connectSSE() {{
  const es = new EventSource(API + '/events');
  document.getElementById('badge-sse').textContent = 'SSE ●';
  document.getElementById('badge-sse').style.color = '#98c379';

  es.addEventListener('cmd_done', e => {{
    const d = JSON.parse(e.data);
    const div = document.createElement('div');
    div.className = 'evt cmd_done';
    div.textContent = d.cmd + ' [' + d.exit_code + ']';
    evl.prepend(div);
    if (evl.children.length > 40) evl.removeChild(evl.lastChild);
    updateStatus();
  }});

  es.addEventListener('connected', e => {{
    const d = JSON.parse(e.data);
    document.getElementById('cwd-label').textContent = d.cwd || '';
    appendLine('Połączono z ' + d.shell, 'info');
  }});

  es.onerror = () => {{
    document.getElementById('badge-sse').textContent = 'SSE ✗';
    document.getElementById('badge-sse').style.color = '#e06c75';
    setTimeout(connectSSE, 3000);
  }};
}}

// Tab completion
inp.addEventListener('input', () => {{
  const val = inp.value.trim();
  if (!val) {{ compl.style.display='none'; return; }}
  const matches = allCmds.filter(c => c.startsWith(val) && c !== val);
  if (!matches.length) {{ compl.style.display='none'; return; }}
  compl.innerHTML = matches.slice(0,12).map(c =>
    `<div class="comp-item" onclick="inp.value='${{c}} ';inp.focus();compl.style.display='none'">${{c}}</div>`
  ).join('');
  const rect = inp.getBoundingClientRect();
  compl.style.left = rect.left + 'px';
  compl.style.bottom = (window.innerHeight - rect.top + 2) + 'px';
  compl.style.display = 'block';
}});

document.addEventListener('click', e => {{
  if (!compl.contains(e.target)) compl.style.display = 'none';
}});

inp.addEventListener('keydown', e => {{
  if (e.key === 'Enter') {{
    const cmd = inp.value.trim();
    compl.style.display = 'none';
    if (!cmd) return;
    history.unshift(cmd);
    histIdx = -1;
    inp.value = '';
    runCmd(cmd).then(() => updateStatus());
  }} else if (e.key === 'ArrowUp') {{
    e.preventDefault();
    if (histIdx < history.length - 1) inp.value = history[++histIdx] || '';
  }} else if (e.key === 'ArrowDown') {{
    e.preventDefault();
    inp.value = histIdx > 0 ? history[--histIdx] : '';
  }} else if (e.key === 'Tab') {{
    e.preventDefault();
    const items = compl.querySelectorAll('.comp-item');
    if (items.length === 1) {{ inp.value = items[0].textContent + ' '; compl.style.display='none'; }}
  }}
}});

appendLine('{SHELL_NAME} v{SHELL_VERSION} Web Panel — wpisz komendę lub naciśnij Enter', 'info');
appendLine('API: ' + API + '  |  SSE: /api/v1/events  |  OpenAPI: /api/v1/openapi.json', 'info');
loadCommands();
updateStatus();
connectSSE();
</script>
</body>
</html>"""

# ── 5. OpenAPI 3.0 schema ─────────────────────────────────────────────────────

def _build_openapi_schema() -> dict:
    """Generuje schemat OpenAPI 3.0 dla REST API TerminalXa."""
    srv = _SERVERS.get("rest")
    port = srv.port if srv and srv.running else 7700
    return {
        "openapi": "3.0.3",
        "info": {
            "title":       f"{SHELL_NAME} REST API",
            "version":     SHELL_VERSION,
            "description": SHELL_TAGLINE,
            "contact":     {"name": SHELL_AUTHOR, "url": SHELL_HOMEPAGE},
            "license":     {"name": SHELL_LICENSE, "url": SHELL_LICENSE_URL},
        },
        "servers": [{"url": f"http://localhost:{port}/api/v1",
                     "description": "Local TerminalX server"}],
        "security": [{"BearerAuth": []}],
        "components": {
            "securitySchemes": {
                "BearerAuth": {
                    "type": "http", "scheme": "bearer",
                    "description": "Opcjonalny token (serve start --token <key>)"
                }
            },
            "schemas": {
                "ExecRequest":  {"type": "object", "required": ["cmd"],
                                 "properties": {"cmd": {"type": "string",
                                  "example": "ls -la"}}},
                "ExecResult":   {"type": "object", "properties": {
                                  "stdout":    {"type": "string"},
                                  "stderr":    {"type": "string"},
                                  "exit_code": {"type": "integer"},
                                  "cmd":       {"type": "string"}}},
                "EnvSet":       {"type": "object", "required": ["key","value"],
                                 "properties": {
                                  "key":   {"type": "string"},
                                  "value": {"type": "string"}}},
                "FileWrite":    {"type": "object", "required": ["path","content"],
                                 "properties": {
                                  "path":    {"type": "string"},
                                  "content": {"type": "string"}}},
                "Error":        {"type": "object", "properties": {
                                  "error": {"type": "string"},
                                  "code":  {"type": "integer"}}},
            }
        },
        "paths": {
            "/status": {"get": {"summary": "Status shella", "tags": ["info"],
                "responses": {"200": {"description": "OK"}}}},
            "/version": {"get": {"summary": "Wersja shella", "tags": ["info"],
                "responses": {"200": {"description": "OK"}}}},
            "/commands": {"get": {"summary": "Lista komend wbudowanych", "tags": ["info"],
                "responses": {"200": {"description": "OK"}}}},
            "/env": {
                "get":  {"summary": "Zmienne środowiskowe", "tags": ["env"],
                         "responses": {"200": {"description": "OK"}}},
                "post": {"summary": "Ustaw zmienną", "tags": ["env"],
                         "requestBody": {"content": {"application/json": {
                             "schema": {"$ref": "#/components/schemas/EnvSet"}}}},
                         "responses": {"200": {"description": "OK"}}}
            },
            "/history": {"get": {"summary": "Historia komend", "tags": ["history"],
                "parameters": [{"name": "n", "in": "query", "schema": {"type": "integer"}}],
                "responses": {"200": {"description": "OK"}}}},
            "/files": {"get": {"summary": "Listuj katalog/plik", "tags": ["fs"],
                "parameters": [{"name": "path", "in": "query", "required": True,
                                "schema": {"type": "string"}}],
                "responses": {"200": {"description": "OK"}}}},
            "/read": {"get": {"summary": "Odczytaj plik", "tags": ["fs"],
                "parameters": [{"name": "path", "in": "query", "required": True,
                                "schema": {"type": "string"}}],
                "responses": {"200": {"description": "OK"}}}},
            "/write": {"post": {"summary": "Zapisz plik", "tags": ["fs"],
                "requestBody": {"content": {"application/json": {
                    "schema": {"$ref": "#/components/schemas/FileWrite"}}}},
                "responses": {"200": {"description": "OK"}}}},
            "/exec": {"post": {
                "summary": "Wykonaj komendę shella", "tags": ["exec"],
                "requestBody": {"required": True, "content": {"application/json": {
                    "schema": {"$ref": "#/components/schemas/ExecRequest"}}}},
                "responses": {
                    "200": {"description": "Wynik wykonania",
                            "content": {"application/json": {
                                "schema": {"$ref": "#/components/schemas/ExecResult"}}}},
                    "401": {"description": "Unauthorized"},
                    "429": {"description": "Rate limit exceeded"},
                }}},
            "/events": {"get": {
                "summary": "Server-Sent Events (stream zdarzeń)", "tags": ["stream"],
                "parameters": [{"name": "filter", "in": "query",
                                "description": "Filtr zdarzeń: cmd_done,error,connected",
                                "schema": {"type": "string"}}],
                "responses": {"200": {
                    "description": "SSE stream",
                    "content": {"text/event-stream": {"schema": {"type": "string"}}}}}}},
            "/plugins": {"get": {"summary": "Załadowane pluginy", "tags": ["plugins"],
                "responses": {"200": {"description": "OK"}}}},
            "/ratelimit": {"get": {"summary": "Stan rate limitera", "tags": ["admin"],
                "responses": {"200": {"description": "OK"}}}},
            "/openapi.json": {"get": {"summary": "Ten schemat OpenAPI", "tags": ["meta"],
                "responses": {"200": {"description": "OpenAPI 3.0 JSON"}}}},
            "/webhook": {"post": {
                "summary": "Zarządzaj webhookami (add/list/remove/test)", "tags": ["webhooks"],
                "requestBody": {"content": {"application/json": {"schema": {
                    "type": "object",
                    "properties": {
                        "action": {"type": "string", "enum": ["add","list","remove","test"]},
                        "url":    {"type": "string"},
                        "events": {"type": "array", "items": {"type": "string"}},
                        "id":     {"type": "string"},
                    }}}}},
                "responses": {"200": {"description": "OK"}}}},
        }
    }

# ── 6. Webhook outbound ───────────────────────────────────────────────────────
#
#   serve webhook add <url> [--events cmd_done,error]
#   serve webhook list
#   serve webhook remove <id>
#   serve webhook test <id>
#
#   TerminalX wysyła POST na url przy każdym zdarzeniu.
#   Payload: { "event": "cmd_done", "data": {...}, "shell": "...", "ts": "..." }

_WEBHOOKS: list[dict] = []   # {"id": str, "url": str, "events": list, "sent": int}
_WEBHOOK_LOCK = _threading.Lock()
_WEBHOOK_FILE = _BASE / ".terminalx_webhooks.json"

def _webhooks_load():
    if _WEBHOOK_FILE.exists():
        try:
            data = json.loads(_WEBHOOK_FILE.read_text(encoding="utf-8"))
            _WEBHOOKS.extend(data)
        except Exception:  # ignorowane celowo
            pass

def _webhooks_save():
    _WEBHOOK_FILE.write_text(
        json.dumps(_WEBHOOKS, indent=2, ensure_ascii=False), encoding="utf-8")

def _webhook_add(url: str, events: list) -> dict:
    wh = {
        "id":     hashlib.sha256(f"{url}{_time_mod.time()}".encode()).hexdigest()[:8],
        "url":    url,
        "events": events or ["cmd_done"],
        "sent":   0,
        "errors": 0,
        "added":  datetime.datetime.now().isoformat(timespec="seconds"),
    }
    with _WEBHOOK_LOCK:
        _WEBHOOKS.append(wh)
    _webhooks_save()
    return wh

def _webhook_remove(wid: str) -> bool:
    with _WEBHOOK_LOCK:
        before = len(_WEBHOOKS)
        _WEBHOOKS[:] = [w for w in _WEBHOOKS if w["id"] != wid]
    _webhooks_save()
    return len(_WEBHOOKS) < before

def _webhook_fire(event: str, data: dict):
    """Wysyła webhook do wszystkich subskrybentów asynchronicznie.
    WYMAGA trybu online — nie wysyła danych bez zgody użytkownika."""
    # Nigdy nie wysyłaj danych na zewnątrz w trybie offline
    if not is_online():
        log_info(f"_webhook_fire: zablokowano '{event}' — tryb offline")
        return

    payload = json.dumps({
        "event":  event,
        "data":   data,
        "shell":  f"{SHELL_NAME} v{SHELL_VERSION}",
        "ts":     datetime.datetime.now().isoformat(timespec="seconds"),
    }, ensure_ascii=False).encode("utf-8")

    with _WEBHOOK_LOCK:
        targets = [w for w in _WEBHOOKS if event in w.get("events", [])]

    def _send_one(wh: dict):
        try:
            import urllib.request as _ur
            import urllib.error as _ue
            log_security(f"webhook: wysylanie zdarzenia '{event}' do {wh['url'][:60]}")
            req = _ur.Request(
                wh["url"], data=payload,
                headers={
                    "Content-Type": "application/json",
                    "User-Agent":   f"TerminalX/{SHELL_VERSION}",
                    "X-Shell-Event": event,
                })
            with _ur.urlopen(req, timeout=5) as resp:
                _ = resp.read()
            with _WEBHOOK_LOCK:
                wh["sent"] = wh.get("sent", 0) + 1
        except Exception as e:
            with _WEBHOOK_LOCK:
                wh["errors"] = wh.get("errors", 0) + 1
            _slog("webhook", f"Błąd → {wh['url']}: {e}", "WARN")

    for wh in targets:
        t = _threading.Thread(target=_send_one, args=(wh,), daemon=True)
        t.start()

def _webhook_test(wid: str) -> tuple[bool, str]:
    """Wysyła testowy webhook i zwraca wynik.
    Wymaga trybu online — nie wysyła danych w trybie offline."""
    if not is_online():
        return False, "Tryb offline — nie mozna wyslac webhook testowy."
    with _WEBHOOK_LOCK:
        wh = next((w for w in _WEBHOOKS if w["id"] == wid), None)
    if not wh:
        return False, f"Webhook '{wid}' nie znaleziony."
    try:
        import urllib.request as _ur
        payload = json.dumps({
            "event": "test", "data": {"msg": "ping"},
            "shell": f"{SHELL_NAME} v{SHELL_VERSION}",
            "ts":    datetime.datetime.now().isoformat(),
        }).encode("utf-8")
        req = _ur.Request(
            wh["url"], data=payload,
            headers={"Content-Type": "application/json",
                     "User-Agent": f"TerminalX/{SHELL_VERSION}"})
        with _ur.urlopen(req, timeout=5) as resp:
            code = resp.getcode()
        return True, f"HTTP {code}"
    except Exception as e:
        return False, str(e)

# Podpnij webhook hook po after_cmd (obok SSE)
def _webhook_hook_after_cmd(cmd_name: str, args: list, exit_code: int):
    if not _WEBHOOKS:
        return
    _webhook_fire("cmd_done", {
        "cmd":       cmd_name,
        "exit_code": exit_code,
        "cwd":       str(Path.cwd()),
        "ts":        datetime.datetime.now().isoformat(timespec="seconds"),
    })

PLUGIN_HOOKS["after_cmd"].append(_webhook_hook_after_cmd)

# Załaduj webhooks przy starcie
_webhooks_load()

# ── 7. Daemon mode (PID file) ─────────────────────────────────────────────────
#
#   serve daemon start [port] [--token X] — fork do tła, zapisz PID
#   serve daemon stop                     — zabij daemon przez PID
#   serve daemon status                   — sprawdź czy daemon żyje

_DAEMON_PID_FILE = _BASE / ".terminalx_server.pid"

def _daemon_start(port: int = 7700, token: str = "") -> tuple[bool, str]:
    """Uruchamia REST server jako daemon w tle (fork/subprocess)."""
    if _DAEMON_PID_FILE.exists():
        try:
            pid = int(_DAEMON_PID_FILE.read_text().strip())
            try:
                os.kill(pid, 0)   # sprawdź czy proces istnieje
                return False, f"Daemon już działa (PID {pid})"
            except ProcessLookupError:
                pass   # stary PID — przepiszemy
        except Exception:  # ignorowane celowo
            pass

    script = _integ_script_path()
    py     = sys.executable

    # Uruchom w osobnym procesie (niezależnym od bieżącego terminala)
    args = [py, str(script), "--serve-daemon",
            f"--port={port}"]
    if token:
        args += [f"--token={token}"]

    try:
        if os.name == "nt":
            # Windows: DETACHED_PROCESS
            DETACHED_PROCESS = 0x00000008
            CREATE_NEW_PROCESS_GROUP = 0x00000200
            proc = subprocess.Popen(
                args,
                creationflags=DETACHED_PROCESS | CREATE_NEW_PROCESS_GROUP,
                close_fds=True,
                stdout=subprocess.DEVNULL,
                stderr=subprocess.DEVNULL,
            )
        else:
            # Unix: fork
            proc = subprocess.Popen(
                args,
                start_new_session=True,
                stdout=subprocess.DEVNULL,
                stderr=subprocess.DEVNULL,
                close_fds=True,
            )
        _time_mod.sleep(0.8)   # poczekaj na start
        if proc.poll() is None:
            _DAEMON_PID_FILE.write_text(str(proc.pid), encoding="utf-8")
            return True, f"Daemon uruchomiony PID {proc.pid} — port {port}"
        return False, "Daemon zakończył się natychmiast (błąd startu)"
    except Exception as e:
        return False, str(e)

def _daemon_stop() -> tuple[bool, str]:
    if not _DAEMON_PID_FILE.exists():
        return False, "Brak pliku PID — daemon nie jest uruchomiony."
    try:
        pid = int(_DAEMON_PID_FILE.read_text().strip())
        if os.name == "nt":
            subprocess.run(["taskkill", "/F", "/PID", str(pid)],
                           capture_output=True)
        else:
            os.kill(pid, 15)   # SIGTERM
        _time_mod.sleep(0.3)
        _DAEMON_PID_FILE.unlink(missing_ok=True)
        return True, f"Daemon (PID {pid}) zatrzymany."
    except ProcessLookupError:
        _DAEMON_PID_FILE.unlink(missing_ok=True)
        return True, "Daemon już nie działał (stary PID usunięty)."
    except Exception as e:
        return False, str(e)

def _daemon_status() -> tuple[bool, str]:
    if not _DAEMON_PID_FILE.exists():
        return False, "Daemon nie jest uruchomiony (brak PID file)."
    try:
        pid = int(_DAEMON_PID_FILE.read_text().strip())
        os.kill(pid, 0)
        return True, f"Daemon działa — PID {pid}"
    except ProcessLookupError:
        _DAEMON_PID_FILE.unlink(missing_ok=True)
        return False, "Daemon nie żyje (PID file usunięty)."
    except Exception as e:
        return False, str(e)

# ── 8. Multi-server start ─────────────────────────────────────────────────────

def _srv_start_all(token: str = "") -> list[str]:
    """Uruchamia REST + WebSocket + GUI + Remote jedną operacją."""
    results = []

    # REST
    if not (_SERVERS["rest"] and _SERVERS["rest"].running):
        srv = _RestServer("127.0.0.1", 7700, auth_token=token)
        if srv.start():
            _SERVERS["rest"] = srv
            results.append(f"✔ REST API    http://127.0.0.1:7700/api/v1")
            results.append(f"  Web Panel   http://127.0.0.1:7700/")
            results.append(f"  OpenAPI     http://127.0.0.1:7700/api/v1/openapi.json")
        else:
            results.append(f"✖ REST API    port 7700 zajęty")
    else:
        results.append(f"– REST API    już działa")

    # WebSocket
    if not (_SERVERS["websocket"] and _SERVERS["websocket"].running):
        srv = _WsServer("127.0.0.1", 7701)
        if srv.start():
            _SERVERS["websocket"] = srv
            results.append(f"✔ WebSocket   ws://127.0.0.1:7701")
        else:
            results.append(f"✖ WebSocket   port 7701 zajęty")
    else:
        results.append(f"– WebSocket   już działa")

    # GUI IPC
    if not (_SERVERS["gui"] and _SERVERS["gui"].running):
        srv = _GuiServer(port=7702)
        if srv.start():
            _SERVERS["gui"] = srv
            results.append(f"✔ GUI IPC     127.0.0.1:7702 (NDJSON)")
        else:
            results.append(f"✖ GUI IPC     port 7702 zajęty")
    else:
        results.append(f"– GUI IPC     już działa")

    # Remote Shell
    if not (_SERVERS.get("remote") and _SERVERS["remote"].running):
        srv = _RemoteServer("127.0.0.1", 7703)
        if srv.start():
            _SERVERS["remote"] = srv
            results.append(f"✔ Remote Shell  tcp://127.0.0.1:7703")
            results.append(f"  Połącz: nc 127.0.0.1 7703")
        else:
            results.append(f"✖ Remote Shell  port 7703 zajęty")
    else:
        results.append(f"– Remote Shell  już działa")

    if token:
        results.append(f"  Auth token: Bearer {token[:8]}…")
    return results

def _srv_stop_all() -> list[str]:
    results = []
    for name in ("rest", "websocket", "gui", "remote"):
        srv = _SERVERS.get(name)
        if srv and srv.running:
            srv.stop()
            _SERVERS[name] = None
            results.append(f"✔ {name} zatrzymany")
        else:
            results.append(f"– {name} nie działał")
    return results

# ██ SERVER QUALITY PATCHES ███████████████████████████████████████████████████
#
#   Łata 10 luk wykrytych przez audit:
#
#   1. WebSocket token auth (--token przy wss start)
#   2. GUI IPC token auth  (--token przy gui start)
#   3. Remote shell token auth (--token przy serve remote start)
#   4. REST /api/v1/config (GET + POST)
#   5. REST /api/v1/processes (GET)
#   6. REST /api/v1/aliases  (GET + POST)
#   7. serve help  — pełna pomoc ze wszystkimi podkomendami
#   8. serve test  — obejmuje REST + WebSocket + GUI + Remote
#   9. Dokumentacja nowych endpointów w OpenAPI
#  10. serve all z tokenem propaguje do WS i GUI

# ── 1 & 2 & 3. Token auth dla WS, GUI, Remote ─────────────────────────────────
#
#   Schemat:
#     klient przy połączeniu wysyła: { "type": "auth", "token": "<bearer>" }
#     serwer odpowiada:              { "type": "auth_ok" }  lub  { "type": "auth_fail" }
#                                    i rozłącza przy braku autoryzacji
#
#   WS: token w headerze HTTP Upgrade (Sec-WebSocket-Protocol) lub w pierwszej
#       ramce JSON po nawiązaniu połączenia
#   GUI: token jako pierwsza linia NDJSON po połączeniu
#   Remote: token wpisywany jako hasło w bannerze

# Globalny token — ustawiany przez serve all --token lub wss/gui/serve remote --token
_SERVER_TOKEN: str = _STATE.server_token

def _token_ok(candidate: str) -> bool:
    """Sprawdza token (stałoczasowo, odporne na timing attack)."""
    if not _SERVER_TOKEN:
        return True   # brak tokenu = otwarty dostęp (localhost only)
    import hmac as _h
    return _h.compare_digest(candidate.strip(), _SERVER_TOKEN)

# ── Patch _WsClient._dispatch — sprawdź token w ramce auth ──────────────────

_orig_ws_dispatch = None
try:
    _orig_ws_dispatch = _WsClient._dispatch
except NameError:
    pass

def _ws_dispatch_with_auth(self, msg: dict):
    mtype  = msg.get("type", "")
    req_id = msg.get("id")

    def _reply(data: dict):
        if req_id is not None:
            data["id"] = req_id
        _ws_send_frame(self.conn,
                       json.dumps(data, ensure_ascii=False,
                                  default=str).encode("utf-8"))

    # Obsługa auth frame
    if mtype == "auth":
        if _token_ok(msg.get("token", "")):
            self._authenticated = True
            _reply({"type": "auth_ok",
                    "shell": f"{SHELL_NAME} v{SHELL_VERSION}"})
        else:
            _reply({"type": "auth_fail", "msg": "Invalid token"})
            self._authenticated = False
        return

    # Blokuj jeśli token wymagany a nie uwierzytelniony
    if _SERVER_TOKEN and not getattr(self, "_authenticated", False):
        _reply({"type": "auth_required",
                "msg": "Send {\"type\":\"auth\",\"token\":\"<key>\"} first"})
        return

    # Przekaż do oryginalnego dispatcha
    if _orig_ws_dispatch:
        _orig_ws_dispatch(self, msg)

if _orig_ws_dispatch:
    _WsClient._dispatch = _ws_dispatch_with_auth

    # Inicjuj _authenticated na False przy nowym połączeniu
    _orig_ws_client_init = _WsClient.__init__

    def _ws_client_init_with_auth(self, conn, addr):
        _orig_ws_client_init(self, conn, addr)
        self._authenticated = not bool(_SERVER_TOKEN)  # True jeśli brak tokenu

    _WsClient.__init__ = _ws_client_init_with_auth

# ── Patch _GuiClient.handle — sprawdź token w pierwszej linii NDJSON ─────────

_orig_gui_client_handle = None
try:
    _orig_gui_client_handle = _GuiClient.handle
except NameError:
    pass

def _gui_handle_with_auth(self):
    """Handle z autoryzacją tokenem jako pierwsza linia NDJSON."""
    if not _SERVER_TOKEN:
        # Brak tokenu — od razu oryginalna obsługa
        if _orig_gui_client_handle:
            _orig_gui_client_handle(self)
        return

    # Wyślij challenge
    try:
        challenge = json.dumps(
            {"event": "auth_required",
             "msg": "Send {\"token\":\"<key>\"} as first line"}) + "\n"
        self.conn.sendall(challenge.encode("utf-8"))

        # Odbierz pierwszą linię
        buf = b""
        while b"\n" not in buf:
            chunk = self.conn.recv(256)
            if not chunk:
                return
            buf += chunk

        first_line = buf.split(b"\n")[0].decode("utf-8", errors="replace").strip()
        try:
            auth_msg = json.loads(first_line)
        except Exception:
            auth_msg = {}

        token_candidate = auth_msg.get("token", "")
        if not _token_ok(token_candidate):
            self.conn.sendall(
                (json.dumps({"event": "auth_fail",
                             "msg": "Invalid token"}) + "\n").encode("utf-8"))
            self.conn.close()
            return

        self.conn.sendall(
            (json.dumps({"event": "auth_ok",
                         "shell": f"{SHELL_NAME} v{SHELL_VERSION}"}) + "\n"
             ).encode("utf-8"))
    except Exception:
        return

    if _orig_gui_client_handle:
        _orig_gui_client_handle(self)

if _orig_gui_client_handle:
    _GuiClient.handle = _gui_handle_with_auth

# ── Remote shell token auth ───────────────────────────────────────────────────

_orig_remote_session_run = _RemoteSession._run

def _remote_run_with_auth(self):
    """Remote shell z opcjonalnym tokenem/hasłem."""
    if _SERVER_TOKEN:
        try:
            self._send(_REMOTE_BANNER)
            self._send(b"Password: ")
            buf = b""
            while b"\n" not in buf and b"\r" not in buf:
                ch = self.conn.recv(1)
                if not ch:
                    self.alive = False
                    return
                if ch in (b"\r", b"\n"):
                    break
                buf += ch
            self._send(b"\r\n")
            pwd = buf.decode("utf-8", errors="replace").strip()
            if not _token_ok(pwd):
                self._send(b"Access denied.\r\n")
                self.alive = False
                try:
                    self.conn.close()
                except Exception:  # ignorowane celowo
                    pass
                _slog("remote", f"Auth failed: {self.addr[0]}", "WARN")
                return
            self._send(b"Authenticated.\r\n\r\n")
        except Exception:
            return
    _orig_remote_session_run(self)

_RemoteSession._run = _remote_run_with_auth

# ── 4. REST /api/v1/config ────────────────────────────────────────────────────

def _rest_handle_config_get(self, q: dict):
    """GET /api/v1/config — zwraca aktywną konfigurację."""
    keys = q.get("keys", "").split(",") if q.get("keys") else None
    if keys and keys != [""]:
        data = {k: cfg(k) for k in keys if k}
    else:
        data = dict(_CONFIG)
    self._send_json({"config": data,
                     "defaults": dict(_CONFIG_DEFAULTS),
                     "file": str(CONFIG_FILE)})

def _rest_handle_config_post(self, body: dict):
    """POST /api/v1/config — ustawia klucz konfiguracji."""
    key   = body.get("key", "")
    value = body.get("value")
    if not key:
        self._send_error_json("Pole 'key' wymagane"); return
    if value is None:
        self._send_error_json("Pole 'value' wymagane"); return
    if key not in _CONFIG_DEFAULTS:
        self._send_error_json(f"Nieznany klucz: {key!r}"); return
    old = cfg(key)
    cfg_set(key, value, save=True)
    self._send_json({"ok": True, "key": key,
                     "old": old, "new": cfg(key)})

# ── 5. REST /api/v1/processes ─────────────────────────────────────────────────

def _rest_handle_processes(self, q: dict):
    """GET /api/v1/processes — lista procesów (przez ps lub psutil)."""
    procs = []
    try:
        import psutil as _ps
        for p in _ps.process_iter(["pid", "name", "cpu_percent",
                                    "memory_percent", "status"]):
            try:
                procs.append(p.info)
            except Exception:  # ignorowane celowo
                pass
        procs = sorted(procs, key=lambda x: x.get("cpu_percent", 0),
                       reverse=True)[:50]
    except ImportError:
        # Fallback: subprocess ps
        try:
            if os.name != "nt":
                r = subprocess.run(
                    ["ps", "aux", "--no-headers"],
                    capture_output=True, text=True, timeout=5)
                for line in r.stdout.strip().split("\n")[:30]:
                    parts = line.split(None, 10)
                    if len(parts) >= 11:
                        procs.append({
                            "user":   parts[0], "pid":    int(parts[1]),
                            "cpu":    parts[2], "mem":    parts[3],
                            "status": parts[7], "name":   parts[10][:40],
                        })
            else:
                r = subprocess.run(
                    ["tasklist", "/FO", "CSV", "/NH"],
                    capture_output=True, text=True, timeout=5)
                for line in r.stdout.strip().split("\n")[:30]:
                    parts = [p.strip('"') for p in line.split('","')]
                    if len(parts) >= 2:
                        procs.append({"name": parts[0],
                                      "pid": parts[1],
                                      "mem": parts[4] if len(parts) > 4 else "?"})
        except Exception as e:
            self._send_error_json(f"Błąd ps: {e}"); return

    self._send_json({"processes": procs,
                     "count": len(procs),
                     "ts": datetime.datetime.now().isoformat(timespec="seconds")})

# ── 6. REST /api/v1/aliases ───────────────────────────────────────────────────

def _rest_handle_aliases_get(self):
    """GET /api/v1/aliases — lista aliasów."""
    self._send_json({
        "aliases": dict(ALIASES),
        "count":   len(ALIASES),
    })

def _rest_handle_aliases_post(self, body: dict):
    """POST /api/v1/aliases — dodaj/usuń alias."""
    action = body.get("action", "add")
    name   = body.get("name", "")
    if not name:
        self._send_error_json("Pole 'name' wymagane"); return
    if action == "add":
        value = body.get("value", "")
        if not value:
            self._send_error_json("Pole 'value' wymagane"); return
        ALIASES[name] = value
        save_aliases()
        self._send_json({"ok": True, "name": name, "value": value})
    elif action == "remove":
        if name not in ALIASES:
            self._send_error_json(f"Alias '{name}' nie istnieje"); return
        del ALIASES[name]
        save_aliases()
        self._send_json({"ok": True, "removed": name})
    else:
        self._send_error_json("action: add | remove")

# Wstrzyknij nowe endpointy do routera GET i POST

_orig_route_get_v2  = _RestHandler._route_get
_orig_route_post_v2 = _RestHandler._route_post

def _route_get_v2(self, path: str, q: dict):
    if path == "/api/v1/config":
        _rest_handle_config_get(self, q); return
    if path == "/api/v1/processes":
        _rest_handle_processes(self, q); return
    if path == "/api/v1/aliases":
        _rest_handle_aliases_get(self); return
    _orig_route_get_v2(self, path, q)

def _route_post_v2(self, path: str, body: dict):
    if path == "/api/v1/config":
        _rest_handle_config_post(self, body); return
    if path == "/api/v1/aliases":
        _rest_handle_aliases_post(self, body); return
    _orig_route_post_v2(self, path, body)

_RestHandler._route_get  = _route_get_v2
_RestHandler._route_post = _route_post_v2

# Zaktualizuj też dokumentację root /api/v1
_orig_route_get_v3 = _RestHandler._route_get

def _route_get_v3(self, path: str, q: dict):
    if path in ("", "/", "/api", "/api/v1"):
        self._send_json({
            "shell":   f"{SHELL_NAME} v{SHELL_VERSION}",
            "author":  SHELL_AUTHOR,
            "endpoints": [
                "GET  /api/v1/status",
                "GET  /api/v1/version",
                "GET  /api/v1/commands",
                "GET  /api/v1/env",
                "GET  /api/v1/history",
                "GET  /api/v1/plugins",
                "GET  /api/v1/files?path=.",
                "GET  /api/v1/read?path=<file>",
                "GET  /api/v1/config",
                "GET  /api/v1/config?keys=key1,key2",
                "GET  /api/v1/processes",
                "GET  /api/v1/aliases",
                "GET  /api/v1/events  (SSE stream)",
                "GET  /api/v1/ratelimit",
                "GET  /api/v1/openapi.json",
                "POST /api/v1/exec",
                "POST /api/v1/env",
                "POST /api/v1/write",
                "POST /api/v1/config",
                "POST /api/v1/aliases",
                "POST /api/v1/plugin/reload",
                "POST /api/v1/webhook",
                "GET  /  (Web Panel)",
            ],
            "auth":     "Bearer token (serve start --token <key>)",
            "ratelimit": f"{_RATE_LIMIT_MAX} req/{_RATE_LIMIT_WINDOW_SEC}s per IP",
            "sse":      "/api/v1/events?filter=cmd_done,error",
            "openapi":  "/api/v1/openapi.json",
            "panel":    "/",
        })
        return
    _orig_route_get_v3(self, path, q)

_RestHandler._route_get = _route_get_v3

