# ── 8. serve test — obejmuje REST + WS + GUI + Remote ────────────────────────

def _srv_test_all(w: int):
    """Testuje wszystkie uruchomione serwery."""
    print()
    print(box_top("  🧪 serve test — diagnostyka serwerów  ", width=w, color=C.INFO))
    results = []

    # REST API
    srv = _SERVERS.get("rest")
    if srv and srv.running:
        try:
            import urllib.request as _ur
            # Połączenie wyłącznie do localhost (127.0.0.1) — nie wysyła danych na zewnątrz
            url = f"http://127.0.0.1:{srv.port}/api/v1/status"
            with _ur.urlopen(url, timeout=3) as resp:
                data = json.loads(resp.read())
            results.append((True, f"REST  {url} → HTTP 200  shell:{data.get('shell','')}"))
        except Exception as e:
            results.append((False, f"REST  błąd: {e}"))
    else:
        results.append((None, "REST  nieaktywny (serve start)"))

    # WebSocket ping
    srv_ws = _SERVERS.get("websocket")
    if srv_ws and srv_ws.running:
        try:
            import socket as _st
            s = _st.socket(_st.AF_INET, _st.SOCK_STREAM)
            s.settimeout(2)
            s.connect(("127.0.0.1", srv_ws.port))
            # Minimalny HTTP upgrade
            key_b64 = "dGhlIHNhbXBsZSBub25jZQ=="
            s.sendall((
                f"GET / HTTP/1.1\r\n"
                f"Host: 127.0.0.1:{srv_ws.port}\r\n"
                f"Upgrade: websocket\r\n"
                f"Connection: Upgrade\r\n"
                f"Sec-WebSocket-Key: {key_b64}\r\n"
                f"Sec-WebSocket-Version: 13\r\n\r\n"
            ).encode())
            resp = s.recv(256).decode("utf-8", errors="replace")
            ok   = "101" in resp or "Switching" in resp
            s.close()
            results.append((ok, f"WS    ws://127.0.0.1:{srv_ws.port} → "
                                 f"{'101 Switching' if ok else 'handshake failed'}"))
        except Exception as e:
            results.append((False, f"WS    błąd: {e}"))
    else:
        results.append((None, "WS    nieaktywny (wss start)"))

    # GUI IPC ping
    srv_gui = _SERVERS.get("gui")
    if srv_gui and srv_gui.running:
        try:
            import socket as _st2
            if os.name != "nt" and hasattr(srv_gui, "socket_path"):
                import socket as _st3
                s = _st3.socket(_st3.AF_UNIX, _st3.SOCK_STREAM)
                s.settimeout(2)
                s.connect(srv_gui.socket_path)
            else:
                s = _st2.socket(_st2.AF_INET, _st2.SOCK_STREAM)
                s.settimeout(2)
                s.connect(("127.0.0.1", srv_gui.port))
            s.close()
            results.append((True, f"GUI   IPC połączenie OK"))
        except Exception as e:
            results.append((False, f"GUI   błąd: {e}"))
    else:
        results.append((None, "GUI   nieaktywny (gui start)"))

    # Remote shell ping
    srv_rem = _SERVERS.get("remote")
    if srv_rem and srv_rem.running:
        try:
            import socket as _st4
            s = _st4.socket(_st4.AF_INET, _st4.SOCK_STREAM)
            s.settimeout(2)
            s.connect(("127.0.0.1", srv_rem.port))
            banner = s.recv(256)
            s.close()
            ok = b"TerminalX" in banner or b"Remote" in banner
            results.append((ok, f"Remote tcp://127.0.0.1:{srv_rem.port} → "
                                 f"{'banner OK' if ok else 'no banner'}"))
        except Exception as e:
            results.append((False, f"Remote błąd: {e}"))
    else:
        results.append((None, "Remote nieaktywny (serve remote start)"))

    for ok, msg in results:
        if ok is True:
            icon = f"{C.OK}✔{C.RESET}"
        elif ok is False:
            icon = f"{C.ERROR}✖{C.RESET}"
        else:
            icon = f"{C.DIM}–{C.RESET}"
        print(box_row(f"  {icon}  {msg}", width=w, color=C.INFO))

    total  = sum(1 for ok, _ in results if ok is True)
    failed = sum(1 for ok, _ in results if ok is False)
    print(box_sep(width=w, color=C.INFO))
    col = C.OK if failed == 0 else C.ERROR
    print(box_row(
        f"  {col}Wynik: {total} OK  {failed} błędów{C.RESET}",
        width=w, color=C.INFO))
    print(box_bottom(width=w, color=C.INFO))
    print()

# ── 9. Zaktualizuj OpenAPI o nowe endpointy ───────────────────────────────────

_orig_build_openapi = _build_openapi_schema

def _build_openapi_schema_v2() -> dict:
    schema = _orig_build_openapi()
    schema["paths"].update({
        "/config": {
            "get": {
                "summary": "Pobierz konfigurację (wszystkie klucze lub ?keys=k1,k2)",
                "tags": ["config"],
                "parameters": [{"name": "keys", "in": "query",
                                 "description": "Oddzielone przecinkami klucze",
                                 "schema": {"type": "string"}}],
                "responses": {"200": {"description": "Konfiguracja"}}
            },
            "post": {
                "summary": "Ustaw klucz konfiguracji",
                "tags": ["config"],
                "requestBody": {"content": {"application/json": {"schema": {
                    "type": "object", "required": ["key", "value"],
                    "properties": {
                        "key":   {"type": "string"},
                        "value": {}
                    }}}}},
                "responses": {
                    "200": {"description": "Zaktualizowano"},
                    "400": {"description": "Nieznany klucz"}
                }
            }
        },
        "/processes": {
            "get": {
                "summary": "Lista procesów systemu (top 50 wg CPU)",
                "tags": ["system"],
                "responses": {"200": {"description": "Lista procesów"}}
            }
        },
        "/aliases": {
            "get": {
                "summary": "Pobierz aliasy shella",
                "tags": ["shell"],
                "responses": {"200": {"description": "Aliasy"}}
            },
            "post": {
                "summary": "Dodaj lub usuń alias",
                "tags": ["shell"],
                "requestBody": {"content": {"application/json": {"schema": {
                    "type": "object",
                    "properties": {
                        "action": {"type": "string", "enum": ["add", "remove"]},
                        "name":   {"type": "string"},
                        "value":  {"type": "string"},
                    }}}}},
                "responses": {"200": {"description": "OK"}}
            }
        },
    })
    return schema

# Nadpisz funkcję
import builtins as _blt
_blt._build_openapi_schema = _build_openapi_schema_v2

# ── 10. serve all propaguje token do WS, GUI i Remote ────────────────────────

_orig_srv_start_all = _srv_start_all

def _srv_start_all_with_token(token: str = "") -> list[str]:
    if token:
        _STATE.server_token = token
    return _orig_srv_start_all(token)

# ── Rozszerzenie komendy serve o nowe podkomendy ──────────────────────────────

_orig_cmd_serve_func = None
if "serve" in BUILTINS:
    _orig_cmd_serve_func = BUILTINS["serve"].func

def _extended_serve(args: list):
    sub = args[0].lower() if args else ""
    w   = min(terminal_width() - 2, 72)

    # ── all ───────────────────────────────────────────────────────────────
    if sub == "all":
        token = ""
        if "--token" in args:
            idx = args.index("--token")
            if idx + 1 < len(args):
                token = args[idx + 1]
        print()
        print(box_top("  🖥️  Uruchamiam wszystkie serwery…  ", width=w, color=C.PATH))
        for line in _srv_start_all(token):
            color = C.OK if line.startswith("✔") else (C.ERROR if line.startswith("✖") else C.DIM)
            print(box_row(f"  {color}{line}{C.RESET}", width=w, color=C.PATH))
        print(box_row(
            f"  {C.DIM}Zatrzymaj wszystkie: serve stopall{C.RESET}",
            width=w, color=C.PATH))
        print(box_bottom(width=w, color=C.PATH))
        print()

    # ── stopall ───────────────────────────────────────────────────────────
    elif sub == "stopall":
        print()
        print(box_top("  Zatrzymuję wszystkie serwery…  ", width=w, color=C.WARN))
        for line in _srv_stop_all():
            col = C.OK if line.startswith("✔") else C.DIM
            print(box_row(f"  {col}{line}{C.RESET}", width=w, color=C.WARN))
        print(box_bottom(width=w, color=C.WARN))
        print()

    # ── remote ────────────────────────────────────────────────────────────
    elif sub == "remote":
        rsub = args[1].lower() if len(args) > 1 else "status"

        if rsub == "start":
            if _SERVERS.get("remote") and _SERVERS["remote"].running:
                print_error("Remote shell już działa."); return
            port = 7703
            clean = [a for a in args[2:] if not a.startswith("-")]
            if clean:
                try: port = int(clean[0])
                except ValueError: pass
            srv = _RemoteServer("127.0.0.1", port)
            if srv.start():
                _SERVERS["remote"] = srv
                print_info(
                    f"Remote shell uruchomiony: {C.PATH}tcp://127.0.0.1:{port}{C.RESET}")
                print_info(
                    f"{C.DIM}Połącz: nc 127.0.0.1 {port}  "
                    f"lub  telnet 127.0.0.1 {port}{C.RESET}")
            else:
                print_error(f"Nie udało się uruchomić remote shell na porcie {port}.")

        elif rsub == "stop":
            srv = _SERVERS.get("remote")
            if not srv or not srv.running:
                print_error("Remote shell nie jest uruchomiony."); return
            srv.stop()
            _SERVERS["remote"] = None
            print_info("Remote shell zatrzymany.")

        elif rsub == "status":
            srv = _SERVERS.get("remote")
            if srv and srv.running:
                with _REMOTE_LOCK:
                    nsess = len(_REMOTE_SESSIONS)
                print_info(
                    f"Remote shell: {C.OK}aktywny{C.RESET}  "
                    f"port:{srv.port}  sesje:{nsess}  uptime:{srv.uptime}")
            else:
                print_info(f"Remote shell: {C.DIM}nieaktywny{C.RESET}")

        elif rsub == "sessions":
            with _REMOTE_LOCK:
                sessions = list(_REMOTE_SESSIONS)
            if not sessions:
                print_info("Brak aktywnych sesji remote shell."); return
            print()
            print(box_top(f"Sesje remote shell ({len(sessions)})", width=w, color=C.INFO))
            for i, s in enumerate(sessions, 1):
                print(box_row(
                    f"  {C.BOLD}{i}{C.RESET}  {C.DIM}{s.addr[0]}:{s.addr[1]}{C.RESET}"
                    f"  uptime:{s.uptime}",
                    width=w, color=C.INFO))
            print(box_bottom(width=w, color=C.INFO))
            print()
        else:
            print_error(f"Nieznana podkomenda: remote {rsub}",
                        "Dostępne: start|stop|status|sessions")

    # ── daemon ────────────────────────────────────────────────────────────
    elif sub == "daemon":
        dsub = args[1].lower() if len(args) > 1 else "status"

        if dsub == "start":
            port = 7700
            token = ""
            clean = [a for a in args[2:] if not a.startswith("-")]
            if clean:
                try: port = int(clean[0])
                except ValueError: pass
            if "--token" in args:
                idx = args.index("--token")
                if idx + 1 < len(args):
                    token = args[idx + 1]
            ok, msg = _daemon_start(port, token)
            (print_info if ok else print_error)(msg)
            if ok:
                print(f"  {C.DIM}Zatrzymaj: serve daemon stop{C.RESET}")
                print(f"  {C.DIM}PID file:  {_DAEMON_PID_FILE}{C.RESET}")

        elif dsub == "stop":
            ok, msg = _daemon_stop()
            (print_info if ok else print_error)(msg)

        elif dsub == "status":
            ok, msg = _daemon_status()
            col = C.OK if ok else C.DIM
            print_info(f"{col}{msg}{C.RESET}")

        else:
            print_error(f"Nieznana podkomenda: daemon {dsub}",
                        "Dostępne: start [port] [--token X] | stop | status")

    # ── webhook ───────────────────────────────────────────────────────────
    elif sub == "webhook":
        wsub = args[1].lower() if len(args) > 1 else "list"

        if wsub == "add":
            url = args[2] if len(args) > 2 else ""
            if not url:
                print_error("Podaj URL: serve webhook add <url> [--events cmd_done,error]")
                return
            events = ["cmd_done"]
            if "--events" in args:
                idx = args.index("--events")
                if idx + 1 < len(args):
                    events = args[idx + 1].split(",")
            wh = _webhook_add(url, events)
            print_info(
                f"Webhook dodany: {wh['id']} → {url}  events:{','.join(events)}")
            print(f"  {C.DIM}Testuj: serve webhook test {wh['id']}{C.RESET}")

        elif wsub == "list":
            if not _WEBHOOKS:
                print_info("Brak webhooków. Dodaj: serve webhook add <url>"); return
            print()
            print(box_top(f"  📡 Webhooki ({len(_WEBHOOKS)})  ", width=w, color=C.INFO))
            for wh in _WEBHOOKS:
                print(box_row(
                    f"  {C.INFO}{wh['id']}{C.RESET}  "
                    f"{C.PATH}{wh['url'][:35]}{C.RESET}  "
                    f"{C.DIM}sent:{wh.get('sent',0)}  err:{wh.get('errors',0)}"
                    f"  [{','.join(wh.get('events',[]))}]{C.RESET}",
                    width=w, color=C.INFO))
            print(box_bottom(width=w, color=C.INFO))
            print()

        elif wsub == "remove":
            wid = args[2] if len(args) > 2 else ""
            if not wid:
                print_error("Podaj ID: serve webhook remove <id>"); return
            ok = _webhook_remove(wid)
            (print_info if ok else print_error)(
                f"Webhook {wid} usunięty." if ok else f"Nie znaleziono: {wid}")

        elif wsub == "test":
            wid = args[2] if len(args) > 2 else ""
            if not wid:
                print_error("Podaj ID: serve webhook test <id>"); return
            ok, msg = _webhook_test(wid)
            (print_info if ok else print_error)(f"Test {wid}: {msg}")

        else:
            print_error(f"Nieznana podkomenda: webhook {wsub}",
                        "Dostępne: add <url> | list | remove <id> | test <id>")

    # ── panel (alias do otwarcia w przeglądarce) ──────────────────────────
    elif sub == "panel":
        srv = _SERVERS.get("rest")
        if not srv or not srv.running:
            print_error("REST API nie jest uruchomione. Uruchom: serve start lub serve all")
            return
        url = f"http://127.0.0.1:{srv.port}/"
        print_info(f"Web Panel: {C.PATH}{url}{C.RESET}")
        # Spróbuj otworzyć w przeglądarce
        opener = shutil.which("xdg-open") or shutil.which("open") or shutil.which("start")
        if opener:
            subprocess.Popen([opener, url], stdout=subprocess.DEVNULL,
                             stderr=subprocess.DEVNULL)
            print_info(f"Otwarto w przeglądarce.")
        else:
            print(f"  {C.DIM}Otwórz ręcznie: {url}{C.RESET}")

    # ── sse (status SSE) ──────────────────────────────────────────────────
    elif sub == "sse":
        with _SSE_LOCK:
            n = len(_SSE_CLIENTS)
        print_info(
            f"SSE klienci: {C.BOLD}{n}{C.RESET}  "
            f"(max {_SSE_MAX_CLIENTS})  "
            f"endpoint: /api/v1/events")

    # ── ratelimit ─────────────────────────────────────────────────────────
    elif sub == "ratelimit":
        _rate_purge_old()
        with _RATE_LIMIT_LOCK:
            table = dict(_RATE_LIMIT_TABLE)
        print()
        print(box_top(
            f"  Rate Limit: {_RATE_LIMIT_MAX} req/{_RATE_LIMIT_WINDOW_SEC}s per IP  ",
            width=w, color=C.INFO))
        if not table:
            print(box_row(f"  {C.DIM}Brak aktywnych klientów.{C.RESET}",
                          width=w, color=C.INFO))
        for ip, hits in table.items():
            remaining = _RATE_LIMIT_MAX - len(hits)
            col = C.ERROR if remaining < 5 else C.OK
            print(box_row(
                f"  {C.DIM}{ip:<20}{C.RESET}  "
                f"hits:{len(hits):3d}  "
                f"pozostało:{col}{remaining:3d}{C.RESET}",
                width=w, color=C.INFO))
        print(box_bottom(width=w, color=C.INFO))
        print()

    else:
        # Przekaż do oryginalnej serve
        if _orig_cmd_serve_func:
            _orig_cmd_serve_func(args)
        else:
            print_error(f"Nieznana podkomenda: serve {sub}",
                        "Dostępne: start|stop|status|log|test|all|stopall|"
                        "remote|daemon|webhook|panel|sse|ratelimit")

# Zaktualizuj BUILTINS
if "serve" in BUILTINS:
    BUILTINS["serve"].func = _extended_serve
    for alias in ("api", "restapi", "apiserver"):
        if alias in BUILTINS:
            BUILTINS[alias].func = _extended_serve

