# ── Operacje na profilach ────────────────────────────────────────────────────

def _profiles_dir() -> Path:
    """Upewnij się, że katalog profili istnieje."""
    PROFILES_DIR.mkdir(parents=True, exist_ok=True)
    return PROFILES_DIR

def _profile_path(name: str) -> Path:
    return _profiles_dir() / (name + _PROFILE_EXT)

def _profile_list() -> list[dict]:
    """
    Zwraca listę wszystkich profili (wbudowane + użytkownika).
    Każdy jako dict: {name, builtin, description, tags, path}
    """
    result = []
    # Wbudowane
    for name, data in _BUILTIN_PROFILE_DATA.items():
        meta = data.get("_meta", {})
        result.append({
            "name":        name,
            "builtin":     True,
            "description": meta.get("description", ""),
            "tags":        meta.get("tags", []),
            "path":        str(_profile_path(name)),
            "active":      name == _CURRENT_PROFILE,
        })
    # Użytkownika (pliki w katalogu profili, nie wbudowane)
    if _profiles_dir().exists():
        for f in sorted(_profiles_dir().glob(f"*{_PROFILE_EXT}")):
            name = f.stem
            if name in _BUILTIN_PROFILES:
                continue
            try:
                data = json.loads(f.read_text(encoding="utf-8"))
                meta = data.get("_meta", {})
                result.append({
                    "name":        name,
                    "builtin":     False,
                    "description": meta.get("description", ""),
                    "tags":        meta.get("tags", []),
                    "path":        str(f),
                    "active":      name == _CURRENT_PROFILE,
                })
            except Exception:  # ignorowane celowo
                pass
    return result

def _profile_load_data(name: str) -> dict | None:
    """Wczytuje dane profilu (wbudowany lub plik)."""
    if name in _BUILTIN_PROFILE_DATA:
        return dict(_BUILTIN_PROFILE_DATA[name])
    fpath = _profile_path(name)
    if not fpath.exists():
        return None
    try:
        return json.loads(fpath.read_text(encoding="utf-8"))
    except Exception:
        return None

def _profile_save(name: str, data: dict) -> bool:
    """Zapisuje profil do pliku."""
    try:
        _profiles_dir()
        fpath = _profile_path(name)
        fpath.write_text(json.dumps(data, indent=2, ensure_ascii=False),
                         encoding="utf-8")
        return True
    except Exception as e:
        print_error(f"Błąd zapisu profilu: {e}")
        return False

def _profile_apply(data: dict, silent: bool = False) -> list[str]:
    """
    Aplikuje ustawienia profilu do aktywnej konfiguracji.
    Obsługuje efekty natychmiastowe: motyw, verbose/debug, font, okno.
    Zwraca listę zmienionych kluczy.
    """
    changed = []
    skip = {"_meta"}
    for key, value in data.items():
        if key in skip:
            continue
        old = cfg(key)
        if old != value:
            cfg_set(key, value, save=False)
            changed.append(key)

    # ── Efekty natychmiastowe ─────────────────────────────────────────────
    # Motyw
    new_theme = data.get("theme")
    if new_theme and new_theme in _THEMES:
        _apply_theme(new_theme)

    # Verbose / debug (jeśli dostępne z v27+)
    if "shell_verbose" in data:
        try:
            _STATE.shell_verbose = bool(data["shell_verbose"])
        except Exception:  # ignorowane celowo
            pass
    if "shell_debug" in data:
        try:
            _STATE.shell_debug = bool(data["shell_debug"])
            if _SHELL_DEBUG:
                SHELL_VARS["_DEBUG"] = "1"
            else:
                SHELL_VARS.pop("_DEBUG", None)
        except Exception:  # ignorowane celowo
            pass

    # config_apply() obsługuje resztę (box_style, prompt, status_bar…)
    config_apply()
    return changed

def _snapshot_current_config() -> dict:
    """
    Tworzy snapshot bieżącej konfiguracji jako słownik profilu.
    """
    snap = {}
    for key in _CONFIG_DEFAULTS:
        snap[key] = cfg(key, _CONFIG_DEFAULTS[key])
    return snap

# ── Automatyczne wykrywanie środowiska ───────────────────────────────────────

def _detect_project_type(cwd: Path) -> str:
    """Wykrywa typ projektu na podstawie plików w bieżącym katalogu."""
    markers = {
        "python": ["pyproject.toml", "setup.py", "setup.cfg",
                   "requirements.txt", "Pipfile", "poetry.lock"],
        "node":   ["package.json", "yarn.lock", "pnpm-lock.yaml"],
        "rust":   ["Cargo.toml", "Cargo.lock"],
        "go":     ["go.mod", "go.sum"],
        "java":   ["pom.xml", "build.gradle", "gradlew"],
        "cpp":    ["CMakeLists.txt", "configure.ac"],
        "docker": ["Dockerfile", "docker-compose.yml", "docker-compose.yaml"],
    }
    for ptype, files in markers.items():
        if any((cwd / f).exists() for f in files):
            return ptype
    return "generic"

def _detect_git_branch_env() -> str | None:
    """Próbuje odczytać gałąź git bez subprocess (przez .git/HEAD)."""
    try:
        head = Path(".git") / "HEAD"
        if head.exists():
            txt = head.read_text(encoding="utf-8").strip()
            if txt.startswith("ref: refs/heads/"):
                return txt[len("ref: refs/heads/"):]
    except Exception:  # ignorowane celowo
        pass
    return None

def _detect_low_memory() -> bool:
    """Zwraca True jeśli dostępne RAM < 512 MB."""
    try:
        meminfo = Path("/proc/meminfo")
        if meminfo.exists():
            for line in meminfo.read_text().splitlines():
                if line.startswith("MemAvailable:"):
                    return int(line.split()[1]) < 512 * 1024
    except Exception:  # ignorowane celowo
        pass
    return False

def detect_environment() -> dict:
    """
    Wykrywa aktualne środowisko uruchomienia shella.
    Zwraca słownik z wykrytymi flagami i metadanymi.
    """
    env = {}

    # Docker / kontener
    env["docker"] = Path("/.dockerenv").exists()
    if not env["docker"]:
        cgroup = Path("/proc/self/cgroup")
        if cgroup.exists():
            try:
                txt = cgroup.read_text(errors="ignore")
                env["docker"] = any(k in txt for k in ("docker", "kubepods", "lxc"))
            except Exception:  # ignorowane celowo
                pass

    # WSL (Windows Subsystem for Linux)
    env["wsl"] = False
    pv = Path("/proc/version")
    if pv.exists():
        try:
            txt = pv.read_text(errors="ignore").lower()
            env["wsl"] = "microsoft" in txt or "wsl" in txt
        except Exception:  # ignorowane celowo
            pass

    # CI / Continuous Integration
    ci_vars = ["CI", "CONTINUOUS_INTEGRATION", "GITHUB_ACTIONS",
                "GITLAB_CI", "JENKINS_URL", "TRAVIS", "CIRCLECI",
                "BITBUCKET_BUILD_NUMBER", "TEAMCITY_VERSION"]
    env["ci"] = any(os.environ.get(v) for v in ci_vars)
    env["ci_name"] = next(
        (v.replace("_", " ").title() for v in ci_vars if os.environ.get(v)),
        None)

    # SSH
    env["ssh"] = bool(os.environ.get("SSH_TTY") or os.environ.get("SSH_CONNECTION"))

    # Python virtual environment
    env["venv"] = bool(os.environ.get("VIRTUAL_ENV"))
    env["venv_name"] = Path(os.environ["VIRTUAL_ENV"]).name if env["venv"] else None

    # Conda
    env["conda"] = bool(os.environ.get("CONDA_DEFAULT_ENV"))
    env["conda_env"] = os.environ.get("CONDA_DEFAULT_ENV")

    # Jupyter
    env["jupyter"] = bool(
        os.environ.get("JPY_SESSION_NAME") or
        os.environ.get("JUPYTER_SERVER_URL") or
        os.environ.get("IPYTHON_STARTUP") or
        "ipykernel" in sys.modules)

    # Root
    env["root"] = IS_ROOT

    # tmux / screen
    env["tmux"]   = bool(os.environ.get("TMUX"))
    env["screen"] = bool(os.environ.get("STY"))

    # Neovim / terminal embedded
    env["nvim"]    = bool(os.environ.get("NVIM"))
    env["vscode"]  = os.environ.get("TERM_PROGRAM") == "vscode"

    # Android (Termux)
    env["android"] = Path("/system/build.prop").exists()

    # Windows native
    env["windows"] = (os.name == "nt")

    # macOS
    env["macos"] = sys.platform == "darwin"

    # Portable mode
    env["portable"] = _PORTABLE_MODE

    # Terminal type
    env["term"]  = os.environ.get("TERM", "unknown")
    env["term_program"] = os.environ.get("TERM_PROGRAM", "")
    env["colorterm"] = os.environ.get("COLORTERM", "")
    env["columns"] = terminal_width()

    # 256-color / true-color support
    env["truecolor"] = env["colorterm"].lower() in ("truecolor", "24bit")
    env["colors256"] = "256color" in env["term"] or env["truecolor"]

    # Python details
    env["python_version"] = sys.version.split()[0]
    env["python_impl"]    = sys.implementation.name

    # ── Nowe: projekt, git, zasoby ───────────────────────────────────────
    env["project_type"]  = _detect_project_type(Path("."))
    env["git_branch"]    = _detect_git_branch_env()
    env["git_repo"]      = env["git_branch"] is not None or Path(".git").exists()
    env["low_memory"]    = _detect_low_memory()
    env["slow_terminal"] = env["columns"] < 80

    return env

def suggest_profile(env: dict) -> tuple[str, str]:
    """
    Sugeruje optymalny profil na podstawie wykrytego środowiska.
    Drzewo decyzyjne (priorytety malejąco):
      root      → admin
      CI        → ci
      Docker    → minimal
      Jupyter   → minimal
      SSH       → ssh
      vscode    → dev (lub light jeśli motyw jasny)
      venv/conda + projekt python/node/rust/go → dev
      git repo  → dev
      WSL + projekt → dev
      mało RAM  → minimal
      wąski terminal / brak kolorów → minimal
      Android   → minimal
      motyw light → light
      domyślnie → default
    """
    if env.get("root"):
        return "admin", "wykryto tryb root/sudo"

    if env.get("ci"):
        return "ci", f"środowisko CI/CD ({env.get('ci_name', 'CI')})"

    if env.get("docker") and not env.get("venv") and not env.get("conda"):
        return "minimal", "kontener Docker bez venv"

    if env.get("jupyter"):
        return "minimal", "Jupyter Notebook"

    if env.get("ssh"):
        return "ssh", "sesja SSH (połączenie zdalne)"

    # VSCode z jasnym tłem → light
    if env.get("vscode") and cfg("theme", "dark") == "light":
        return "light", "terminal VS Code z motywem jasnym"

    # Projekty deweloperskie
    proj = env.get("project_type", "generic")
    dev_projects = {"python", "node", "rust", "go", "java", "cpp"}
    has_dev_env  = env.get("venv") or env.get("conda") or env.get("wsl")

    if proj in dev_projects:
        label = env.get("venv_name") or env.get("conda_env") or proj
        return "dev", f"projekt {proj} ({label})"

    if env.get("vscode"):
        return "dev", "terminal zintegrowany z VS Code"

    if has_dev_env:
        label = env.get("venv_name") or env.get("conda_env") or "env"
        return "dev", f"środowisko deweloperskie Python ({label})"

    if env.get("git_repo"):
        branch = env.get("git_branch") or "?"
        return "dev", f"repozytorium git (gałąź: {branch})"

    if env.get("low_memory"):
        return "minimal", "mało dostępnej pamięci RAM (< 512 MB)"

    if env.get("slow_terminal") or not env.get("colors256"):
        return "minimal", "wąski terminal lub brak kolorów 256"

    if env.get("android"):
        return "minimal", "Termux/Android"

    if cfg("theme", "dark") == "light":
        return "light", "aktywny motyw light w konfiguracji"

    return "default", "standardowe środowisko"

# ── Komenda profile ───────────────────────────────────────────────────────────

@command("profile", "Zarządzaj profilami konfiguracji TerminalXa",
         aliases=["prof", "profiles"],
         flags=["list", "switch", "create", "save", "delete", "show", "diff",
                "import", "export", "reset"])
def cmd_profile(args):
    """
    profile                      — aktywny profil + status
    profile list                 — lista wszystkich profili
    profile switch <nazwa>       — przełącz profil
    profile create <nazwa>       — utwórz nowy profil z bieżącej konfiguracji
    profile save [nazwa]         — zapisz bieżące ustawienia do profilu
    profile delete <nazwa>       — usuń profil (nie można usunąć wbudowanych)
    profile show <nazwa>         — podgląd ustawień profilu
    profile diff <a> <b>         — różnice między dwoma profilami
    profile import <plik.json>   — importuj profil z pliku
    profile export <nazwa>       — eksportuj profil do pliku
    profile reset                — wróć do profilu default

    Wbudowane profile: default  admin  dev  diagnostic  minimal
    Katalog profili: ~/.terminalx_profiles/
    """
    sub = args[0].lower() if args else ""
    w   = min(terminal_width() - 2, 74)

    # ── Brak argumentu — status aktywnego profilu ─────────────────────────
    if not sub:
        data = _profile_load_data(_CURRENT_PROFILE)
        meta = data.get("_meta", {}) if data else {}
        print()
        print(box_top(f"Aktywny profil: {_CURRENT_PROFILE}", width=w, color=C.PROMPT))
        print(box_row(kv_row("Nazwa",    _CURRENT_PROFILE,
                             key_color=C.DIM, key_w=18), width=w, color=C.PROMPT))
        print(box_row(kv_row("Opis",     meta.get("description", "profil użytkownika"),
                             key_color=C.DIM, key_w=18), width=w, color=C.PROMPT))
        print(box_row(kv_row("Wbudowany",
                             "tak" if _CURRENT_PROFILE in _BUILTIN_PROFILES else "nie",
                             key_color=C.DIM, key_w=18), width=w, color=C.PROMPT))
        tags = ", ".join(meta.get("tags", [])) or "—"
        print(box_row(kv_row("Tagi",     tags,
                             key_color=C.DIM, key_w=18), width=w, color=C.PROMPT))
        print(box_sep(width=w, color=C.PROMPT))
        # Kluczowe ustawienia layoutu + font + verbose
        layout_keys = ["theme", "box_style", "prompt_style", "status_bar",
                       "show_git_branch", "use_emoji_icons",
                       "font_family", "font_size", "font_ligatures",
                       "window_width", "window_height",
                       "shell_verbose", "shell_debug"]
        for k in layout_keys:
            v = cfg(k, _CONFIG_DEFAULTS.get(k, ""))
            print(box_row(kv_row(k, str(v), key_color=C.DIM, key_w=18),
                          width=w, color=C.PROMPT))
        print(box_sep(width=w, color=C.PROMPT))
        all_profiles = [p["name"] for p in _profile_list()]
        print(box_row(
            f"  {C.DIM}Dostępne: {', '.join(all_profiles)}{C.RESET}",
            width=w, color=C.PROMPT))
        print(box_row(
            f"  {C.DIM}profile switch <nazwa>  ·  profile list  ·  envdetect{C.RESET}",
            width=w, color=C.PROMPT))
        print(box_bottom(width=w, color=C.PROMPT))
        print()
        return

    # ── list ─────────────────────────────────────────────────────────────
    if sub == "list":
        profiles = _profile_list()
        print()
        print(box_top(f"Profile TerminalXa ({len(profiles)})", width=w, color=C.PROMPT))
        print(box_row(
            f"  {C.BOLD}{'Nazwa':<16}{'Typ':<12}{'Tagi':<24}Opis{C.RESET}",
            width=w, color=C.PROMPT))
        print(box_sep(width=w, color=C.PROMPT))
        for p in profiles:
            btype  = f"{C.DIM}wbudowany{C.RESET}" if p["builtin"] else f"{C.PATH}użytkownik{C.RESET}"
            tags   = ",".join(p["tags"])[:20] if p["tags"] else "—"
            desc   = p["description"][:28] if p["description"] else ""
            active = f" {C.PATH}◄{C.RESET}" if p["active"] else ""
            name_col = f"{C.BOLD}{p['name']}{C.RESET}{active}"
            print(box_row(
                f"  {name_col:<26}{btype:<21}{C.DIM}{tags:<24}{desc}{C.RESET}",
                width=w, color=C.PROMPT))
        print(box_sep(width=w, color=C.PROMPT))
        print(box_row(
            f"  {C.DIM}profile switch <nazwa>  ·  profile create <nazwa>  "
            f"·  profile show <nazwa>{C.RESET}",
            width=w, color=C.PROMPT))
        print(box_bottom(width=w, color=C.PROMPT))
        print()
        return

    # ── switch ────────────────────────────────────────────────────────────
    if sub == "switch":
        if len(args) < 2:
            print_error("Podaj nazwę profilu: profile switch <nazwa>"); return
        name = args[1]
        data = _profile_load_data(name)
        if data is None:
            # Sprawdź czy istnieje plik
            fpath = _profile_path(name)
            if not fpath.exists():
                available = [p["name"] for p in _profile_list()]
                print_error(f"Profil nie istnieje: '{name}'",
                            f"Dostępne: {', '.join(available)}")
                return
            try:
                data = json.loads(fpath.read_text(encoding="utf-8"))
            except Exception as e:
                print_error(f"Błąd wczytywania profilu: {e}"); return

        prev = _CURRENT_PROFILE
        changed = _profile_apply(data)
        _STATE.current_profile = name
        # Zapisz aktywny profil do config
        cfg_set("_active_profile", name, save=True)
        save_config()

        meta = data.get("_meta", {})
        desc = meta.get("description", "")
        w2   = min(w, 60)
        print()
        print(box_top(f"Przełączono: {prev} → {name}", width=w2, color=C.PATH))
        if desc:
            print(box_row(f"  {C.DIM}{desc}{C.RESET}", width=w2, color=C.PATH))
            print(box_sep(width=w2, color=C.PATH))
        if changed:
            print(box_row(f"  {C.DIM}Zmieniono {len(changed)} ustawień:{C.RESET}",
                          width=w2, color=C.PATH))
            for k in changed[:8]:
                print(box_row(f"    {C.DIM}{k} = {cfg(k)}{C.RESET}",
                              width=w2, color=C.PATH))
            if len(changed) > 8:
                print(box_row(
                    f"    {C.DIM}... i {len(changed)-8} więcej{C.RESET}",
                    width=w2, color=C.PATH))
        else:
            print(box_row(f"  {C.DIM}Brak zmian — konfiguracja identyczna.{C.RESET}",
                          width=w2, color=C.PATH))
        print(box_bottom(width=w2, color=C.PATH))
        print()
        return

    # ── create ────────────────────────────────────────────────────────────
    if sub == "create":
        if len(args) < 2:
            print_error("Podaj nazwę: profile create <nazwa>"); return
        name = args[1].lower().replace(" ", "_")
        if name in _BUILTIN_PROFILES:
            print_error(f"Nie można nadpisać wbudowanego profilu: {name}",
                        "Użyj innej nazwy."); return
        snap = _snapshot_current_config()
        desc = " ".join(args[2:]) if len(args) > 2 else f"Profil użytkownika (utworzony z {_CURRENT_PROFILE})"
        snap["_meta"] = {
            "name":        name,
            "description": desc,
            "author":      os.environ.get("USER", os.environ.get("USERNAME", "user")),
            "tags":        [],
            "builtin":     False,
            "created":     datetime.datetime.now().isoformat(timespec="seconds"),
            "based_on":    _CURRENT_PROFILE,
        }
        if _profile_save(name, snap):
            print_info(f"Profil '{name}' utworzony z bieżącej konfiguracji.")
            print_info(f"Przełącz: {C.DIM}profile switch {name}{C.RESET}")
        return

    # ── save ──────────────────────────────────────────────────────────────
    if sub == "save":
        name = args[1] if len(args) >= 2 else _CURRENT_PROFILE
        if name in _BUILTIN_PROFILES:
            print_error(f"Nie można nadpisać wbudowanego profilu: {name}",
                        "Utwórz własną kopię: profile create <moja_nazwa>"); return
        snap = _snapshot_current_config()
        existing = _profile_load_data(name)
        if existing:
            snap["_meta"] = existing.get("_meta", {})
            snap["_meta"]["updated"] = datetime.datetime.now().isoformat(timespec="seconds")
        else:
            snap["_meta"] = {
                "name":    name,
                "description": f"Profil '{name}'",
                "author":  os.environ.get("USER", "user"),
                "tags":    [],
                "builtin": False,
                "created": datetime.datetime.now().isoformat(timespec="seconds"),
            }
        if _profile_save(name, snap):
            print_info(f"Profil '{name}' zapisany.")
        return

    # ── delete ────────────────────────────────────────────────────────────
    if sub == "delete":
        if len(args) < 2:
            print_error("Podaj nazwę: profile delete <nazwa>"); return
        name = args[1]
        if name in _BUILTIN_PROFILES:
            print_error(f"Nie można usunąć wbudowanego profilu: {name}"); return
        fpath = _profile_path(name)
        if not fpath.exists():
            print_error(f"Profil nie istnieje: {name}"); return
        if name == _CURRENT_PROFILE:
            print_error(f"Nie można usunąć aktywnego profilu.",
                        "Przełącz się na inny profil: profile switch default"); return
        try:
            fpath.unlink()
            print_info(f"Profil '{name}' usunięty.")
        except Exception as e:
            print_error(f"Błąd usuwania: {e}")
        return

    # ── show ──────────────────────────────────────────────────────────────
    if sub == "show":
        if len(args) < 2:
            print_error("Podaj nazwę: profile show <nazwa>"); return
        name = args[1]
        data = _profile_load_data(name)
        if data is None:
            print_error(f"Profil nie istnieje: {name}"); return
        meta = data.get("_meta", {})
        print()
        print(box_top(f"Profil: {name}", width=w, color=C.INFO))
        # Meta
        for k, v in meta.items():
            if k == "builtin": continue
            print(box_row(kv_row(f"_{k}", str(v), key_color=C.DIM, key_w=16),
                          width=w, color=C.INFO))
        print(box_sep(width=w, color=C.INFO))
        # Layout najpierw
        layout_keys = ["theme", "box_style", "prompt_style", "status_bar",
                       "show_git_branch", "use_emoji_icons", "ls_columns",
                       "custom_prompt_prefix", "custom_greeting"]
        for k in layout_keys:
            if k in data:
                print(box_row(kv_row(k, str(data[k]), key_color=C.DIM, key_w=24),
                              width=w, color=C.INFO))
        print(box_sep(width=w, color=C.INFO))
        # Reszta
        skip = set(layout_keys) | {"_meta"}
        for k, v in sorted(data.items()):
            if k in skip: continue
            print(box_row(kv_row(k, str(v), key_color=C.DIM, key_w=24),
                          width=w, color=C.INFO))
        print(box_bottom(width=w, color=C.INFO))
        print()
        return

    # ── diff ──────────────────────────────────────────────────────────────
    if sub == "diff":
        if len(args) < 3:
            print_error("Podaj dwa profile: profile diff <a> <b>"); return
        name_a, name_b = args[1], args[2]
        data_a = _profile_load_data(name_a)
        data_b = _profile_load_data(name_b)
        if data_a is None:
            print_error(f"Profil nie istnieje: {name_a}"); return
        if data_b is None:
            print_error(f"Profil nie istnieje: {name_b}"); return
        print()
        print(box_top(f"Diff: {name_a}  vs  {name_b}", width=w, color=C.DIM))
        print(box_row(
            f"  {C.ERROR}─ {name_a}{C.RESET}   {C.PATH}+ {name_b}{C.RESET}",
            width=w, color=C.DIM))
        print(box_sep(width=w, color=C.DIM))
        diffs = 0
        all_keys = sorted(set(data_a.keys()) | set(data_b.keys()))
        for k in all_keys:
            if k == "_meta": continue
            va = data_a.get(k, "<brak>")
            vb = data_b.get(k, "<brak>")
            if va != vb:
                diffs += 1
                print(box_row(
                    f"  {C.DIM}{k:<28}{C.RESET}"
                    f"  {C.ERROR}{str(va):<20}{C.RESET}"
                    f"  {C.PATH}{str(vb)}{C.RESET}",
                    width=w, color=C.DIM))
        if diffs == 0:
            print(box_row(f"  {C.DIM}Profile są identyczne.{C.RESET}",
                          width=w, color=C.DIM))
        print(box_sep(width=w, color=C.DIM))
        print(box_row(f"  {C.DIM}{diffs} różnic{C.RESET}", width=w, color=C.DIM))
        print(box_bottom(width=w, color=C.DIM))
        print()
        return

    # ── import ────────────────────────────────────────────────────────────
    if sub == "import":
        if len(args) < 2:
            print_error("Podaj ścieżkę pliku: profile import <plik.json>"); return
        src = Path(args[1]).expanduser()
        if not src.exists():
            print_error(f"Plik nie istnieje: {src}"); return
        try:
            data = json.loads(src.read_text(encoding="utf-8"))
        except Exception as e:
            print_error(f"Błąd odczytu: {e}"); return
        meta = data.get("_meta", {})
        name = meta.get("name") or src.stem
        if name in _BUILTIN_PROFILES:
            name = name + "_imported"
        data["_meta"]["name"] = name
        if _profile_save(name, data):
            print_info(f"Profil '{name}' zaimportowany z {src}")
        return

    # ── export ────────────────────────────────────────────────────────────
    if sub == "export":
        name = args[1] if len(args) >= 2 else _CURRENT_PROFILE
        data = _profile_load_data(name)
        if data is None:
            print_error(f"Profil nie istnieje: {name}"); return
        out = Path(f"{name}_profile.json")
        try:
            out.write_text(json.dumps(data, indent=2, ensure_ascii=False),
                           encoding="utf-8")
            print_info(f"Profil '{name}' wyeksportowany: {out}")
        except Exception as e:
            print_error(f"Błąd eksportu: {e}")
        return

    # ── reset ─────────────────────────────────────────────────────────────
    if sub == "reset":
        data    = _profile_load_data("default")
        changed = _profile_apply(data)
        _STATE.current_profile = "default"
        cfg_set("_active_profile", "default", save=True)
        save_config()
        print_info(f"Przywrócono profil default ({len(changed)} zmian).")
        return

    # ── theme ──────────────────────────────────────────────────────────────
    if sub == "theme":
        # profile theme             — motyw aktywnego profilu
        # profile theme <profil>    — motyw danego profilu
        # profile theme set <motyw> — zmień motyw aktywnego profilu
        if len(args) >= 3 and args[1].lower() == "set":
            new_theme = args[2].lower()
            if new_theme not in _THEMES:
                print_error(f"Nieznany motyw: '{new_theme}'",
                            f"Dostępne: {', '.join(_THEMES)}")
                return
            _apply_theme(new_theme)
            cfg_set("theme", new_theme, save=True)
            print_info(f"Motyw profilu '{_CURRENT_PROFILE}' → {C.BOLD}{new_theme}{C.RESET}")
        else:
            target = args[1] if len(args) > 1 else _CURRENT_PROFILE
            data   = _profile_load_data(target)
            if data is None:
                print_error(f"Profil nie istnieje: '{target}'"); return
            t_name = data.get("theme", "dark")
            print_info(f"Profil '{target}' używa motywu: {C.BOLD}{t_name}{C.RESET}")
            _theme_preview(t_name)
        return

    # ── layout ─────────────────────────────────────────────────────────────
    if sub == "layout":
        # profile layout              — layout aktywnego profilu
        # profile layout <profil>     — layout danego profilu
        # profile layout apply <profil> — zastosuj tylko warstwę layoutu
        if len(args) >= 2 and args[1].lower() == "apply":
            target = args[2] if len(args) > 2 else _CURRENT_PROFILE
            data   = _profile_load_data(target)
            if data is None:
                print_error(f"Profil nie istnieje: '{target}'"); return
            changed = []
            for key in _PROFILE_LAYOUT_KEYS:
                if key in data:
                    old = cfg(key)
                    if old != data[key]:
                        cfg_set(key, data[key], save=False)
                        changed.append(key)
            save_config()
            config_apply()
            theme_val = data.get("theme", "dark")
            if theme_val in _THEMES:
                _apply_theme(theme_val)
            print_info(f"Zastosowano layout profilu '{target}' ({len(changed)} zmian)")
            return

        target = args[1] if len(args) > 1 else _CURRENT_PROFILE
        data   = _profile_load_data(target)
        if data is None:
            print_error(f"Profil nie istnieje: '{target}'"); return
        wl = min(terminal_width() - 2, 62)
        print()
        print(box_top(f"Layout profilu: {target}", width=wl, color=C.PROMPT))
        for key in _PROFILE_LAYOUT_KEYS:
            val = data.get(key, _CONFIG_DEFAULTS.get(key, "—"))
            cur = cfg(key, "")
            diff = f"  {C.WARN}(aktualnie: {cur}){C.RESET}" if str(cur) != str(val) else ""
            print(box_row(kv_row(key, str(val), key_color=C.DIM, key_w=24) + diff,
                          width=wl, color=C.PROMPT))
        print(box_sep(width=wl, color=C.PROMPT))
        print(box_row(
            f"  {C.DIM}profile layout apply {target}  — zastosuj sam layout{C.RESET}",
            width=wl, color=C.PROMPT))
        print(box_bottom(width=wl, color=C.PROMPT))
        print()
        return

    print_error(f"Nieznana podkomenda: profile {sub}",
                "Dostępne: list switch create save delete show diff "
                "import export reset theme layout")

# MODULE: PORTABLE — zarządzanie trybem przenośnym

#
#  portable init              — utwórz .terminalx_data/ → aktywuj portable
#  portable status            — tryb, ścieżki, rozmiar danych, env vars
#  portable copy <cel>        — skopiuj instalację do katalogu docelowego
#  portable pack [plik.pyz]   — spakuj do self-contained zipapp
#  portable check             — weryfikacja: stdlib-only, Python, platform
#  portable env               — pokaż aktywne zmienne środowiskowe TERMINALX_*
#

def _portable_data_size(path: Path) -> str:
    """Zlicza rozmiar katalogu danych (rekursywnie)."""
    try:
        total = sum(f.stat().st_size for f in path.rglob("*") if f.is_file())
        if total < 1024:        return f"{total} B"
        if total < 1024**2:     return f"{total/1024:.1f} KB"
        return f"{total/1024**2:.1f} MB"
    except Exception:
        return "?"

def _portable_script_path() -> Path:
    """Zwraca ścieżkę do tego pliku (frozen exe lub .py)."""
    if _IS_FROZEN:
        return Path(sys.executable).resolve()
    try:
        return Path(__file__).resolve()
    except NameError:
        return Path(sys.argv[0]).resolve()

@command("portable", "Zarządzaj trybem przenośnym TerminalXa",
         aliases=["portabl"],
         flags=["init", "status", "copy", "pack", "check", "env"])
def cmd_portable(args):
    """
    portable init              — utwórz .terminalx_data/ obok skryptu (→ tryb portable)
    portable status            — tryb, ścieżki, rozmiar danych, aktywne env
    portable copy <katalog>    — skopiuj skrypt + dane do katalogu (np. pendrive)
    portable pack [plik.pyz]   — spakuj do self-contained Python zipapp
    portable check             — weryfikuj przenośność (stdlib only, Python, platform)
    portable env               — pokaż zmienne środowiskowe TERMINALX_* + NO_COLOR

    Tryb portable:
      Gdy obok skryptu istnieje .terminalx_data/ — historia, config, pluginy
      są trzymane TAM zamiast w katalogu domowym (~/).
      Działa z pendrive'a, katalogu sieciowego, kontenera lub offline.

    Zmienne środowiskowe:
      TERMINALX_DATA=<ścieżka>   niestandardowy katalog danych
      TERMINALX_RC=<plik>        niestandardowy .terminalxrc
      TERMINALX_CONFIG=<plik>    niestandardowy plik config JSON
      TERMINALX_PROFILE=<nazwa>  automatyczny profil przy starcie
      TERMINALX_THEME=<nazwa>    motyw (dark/light/własny)
      TERMINALX_OFFLINE=1        wymuś tryb offline
      TERMINALX_NO_COLOR=1       wyłącz kolory ANSI
      TERMINALX_VERBOSE=1        tryb verbose
      TERMINALX_DEBUG=1          tryb debug
      TERMINALX_LOG=0            wyłącz logowanie
      NO_COLOR=1                  standard https://no-color.org
    """
    sub = args[0].lower() if args else "status"
    w   = min(terminal_width() - 2, 72)

    # ── init ──────────────────────────────────────────────────────────────────
    if sub == "init":
        script_path = _portable_script_path()
        target_dir  = script_path.parent / ".terminalx_data"
        if target_dir.exists():
            print_info(f"Tryb portable już aktywny: {target_dir}")
            print(f"  {C.DIM}Uruchom ponownie skrypt aby załadować dane z tego katalogu.{C.RESET}")
            return
        try:
            target_dir.mkdir(parents=True)
            # Skopiuj istniejące dane z ~/ do nowego katalogu portable
            import shutil as _sh
            moved = []
            for fname in [".terminalx_history", ".terminalx_aliases",
                          ".terminalxrc", ".terminalx.json",
                          ".terminalx_themes.json"]:
                src = Path.home() / fname
                if src.exists():
                    _sh.copy2(src, target_dir / fname)
                    moved.append(fname)
            print()
            print(box_top("Tryb portable aktywowany", width=w, color=C.PATH))
            print(box_row(f"  {C.PATH}✔{C.RESET}  Katalog: {target_dir}", width=w, color=C.PATH))
            if moved:
                print(box_row(f"  {C.DIM}Skopiowano: {', '.join(moved)}{C.RESET}",
                              width=w, color=C.PATH))
            print(box_sep(width=w, color=C.PATH))
            print(box_row(
                f"  {C.DIM}Uruchom ponownie skrypt — dane będą czytane z katalogu portable.{C.RESET}",
                width=w, color=C.PATH))
            print(box_bottom(width=w, color=C.PATH))
            print()
        except Exception as e:
            print_error(f"Błąd tworzenia katalogu portable: {e}")
        return

    # ── status ────────────────────────────────────────────────────────────────
    if sub == "status" or not sub:
        mode_label = (f"{C.PATH}PORTABLE{C.RESET}" if _PORTABLE_MODE
                      else f"{C.DIM}standardowy (HOME){C.RESET}")
        frozen_label = (f"{C.INFO}frozen exe (.pyz/.exe){C.RESET}" if _IS_FROZEN
                        else f"{C.DIM}skrypt .py{C.RESET}")
        ansi_label = (f"{C.WARN}wyłączone (NO_COLOR){C.RESET}" if _ANSI_DISABLED
                      else f"{C.PATH}włączone{C.RESET}")
        online_label = (f"{C.PATH}ONLINE{C.RESET}" if is_online()
                        else f"{C.DIM}OFFLINE{C.RESET}")

        print()
        print(box_top(f"TerminalX — status przenośności  v{SHELL_VERSION}",
                      width=w, color=C.PROMPT))
        print(box_row(kv_row("Tryb",          mode_label,        key_w=22, key_color=C.DIM),
                      width=w, color=C.PROMPT))
        print(box_row(kv_row("Format",         frozen_label,      key_w=22, key_color=C.DIM),
                      width=w, color=C.PROMPT))
        print(box_row(kv_row("Python",         sys.version.split()[0], key_w=22, key_color=C.DIM),
                      width=w, color=C.PROMPT))
        print(box_row(kv_row("Platforma",      sys.platform,      key_w=22, key_color=C.DIM),
                      width=w, color=C.PROMPT))
        print(box_row(kv_row("Kolory ANSI",    ansi_label,        key_w=22, key_color=C.DIM),
                      width=w, color=C.PROMPT))
        print(box_row(kv_row("Sieć",           online_label,      key_w=22, key_color=C.DIM),
                      width=w, color=C.PROMPT))
        print(box_sep(width=w, color=C.PROMPT))
        print(box_row(f"  {C.BOLD}Ścieżki{C.RESET}", width=w, color=C.PROMPT))
        print(box_row(kv_row("Skrypt",         str(_portable_script_path()), key_w=22, key_color=C.DIM),
                      width=w, color=C.PROMPT))
        print(box_row(kv_row("Dane (_BASE)",   str(_BASE),        key_w=22, key_color=C.DIM),
                      width=w, color=C.PROMPT))
        print(box_row(kv_row("Rozmiar danych", _portable_data_size(_BASE), key_w=22, key_color=C.DIM),
                      width=w, color=C.PROMPT))
        print(box_row(kv_row("Config",         str(CONFIG_FILE),  key_w=22, key_color=C.DIM),
                      width=w, color=C.PROMPT))
        print(box_row(kv_row("RC",             str(RC_FILE),      key_w=22, key_color=C.DIM),
                      width=w, color=C.PROMPT))
        print(box_row(kv_row("Pluginy",        str(PLUGINS_DIR),  key_w=22, key_color=C.DIM),
                      width=w, color=C.PROMPT))

        # Aktywne env vars TERMINALX_*
        active_env = {k: v for k, v in os.environ.items()
                      if k.startswith("TERMINALX_") or k == "NO_COLOR"}
        if active_env:
            print(box_sep(width=w, color=C.PROMPT))
            print(box_row(f"  {C.BOLD}Aktywne zmienne środowiskowe{C.RESET}",
                          width=w, color=C.PROMPT))
            for k, v in active_env.items():
                print(box_row(kv_row(f"  {k}", v, key_w=26, key_color=C.INFO),
                              width=w, color=C.PROMPT))

        print(box_sep(width=w, color=C.PROMPT))
        print(box_row(
            f"  {C.DIM}portable init  |  portable copy <cel>  |  portable pack{C.RESET}",
            width=w, color=C.PROMPT))
        print(box_bottom(width=w, color=C.PROMPT))
        print()
        return

    # ── copy ──────────────────────────────────────────────────────────────────
    if sub == "copy":
        if len(args) < 2:
            print_error("Uzycie: portable copy <katalog_docelowy>"); return
        import shutil as _sh
        dest = Path(args[1]).expanduser().resolve()
        try:
            dest.mkdir(parents=True, exist_ok=True)
        except Exception as e:
            print_error(f"Nie można utworzyć katalogu docelowego: {e}"); return

        script_src = _portable_script_path()
        files_copied = []

        # Kopiuj skrypt
        try:
            _sh.copy2(script_src, dest / script_src.name)
            files_copied.append(script_src.name)
        except Exception as e:
            print_error(f"Błąd kopiowania skryptu: {e}"); return

        # Stwórz katalog .terminalx_data/ w docelowym
        data_dest = dest / ".terminalx_data"
        data_dest.mkdir(exist_ok=True)

        # Kopiuj pliki danych
        for fname in [".terminalx_history", ".terminalx_aliases",
                      ".terminalxrc", ".terminalx.json",
                      ".terminalx_themes.json", ".terminalx_plugin_trust.json"]:
            src = _BASE / fname
            if src.exists():
                try:
                    _sh.copy2(src, data_dest / fname)
                    files_copied.append(fname)
                except Exception:  # ignorowane celowo
                    pass

        # Kopiuj katalogi (pluginy, pakiety)
        for dname in [".terminalx_plugins", ".terminalx_packages",
                      ".terminalx_profiles"]:
            src_d = _BASE / dname
            if src_d.exists():
                try:
                    _sh.copytree(src_d, data_dest / dname, dirs_exist_ok=True)
                    files_copied.append(dname + "/")
                except Exception:  # ignorowane celowo
                    pass

        print()
        print(box_top(f"Skopiowano do: {dest}", width=w, color=C.PATH))
        for f in files_copied:
            print(box_row(f"  {C.PATH}✔{C.RESET}  {f}", width=w, color=C.PATH))
        print(box_sep(width=w, color=C.PROMPT))
        print(box_row(
            f"  {C.DIM}Uruchom: python {script_src.name}{C.RESET}",
            width=w, color=C.PROMPT))
        print(box_bottom(width=w, color=C.PROMPT))
        print()
        return

    # ── pack ──────────────────────────────────────────────────────────────────
    if sub == "pack":
        # Tworzy self-contained Python zipapp (.pyz)
        # python -m zipapp TerminalX.py -o TerminalX.pyz
        # Efekt: python TerminalX.pyz  lub  ./TerminalX.pyz (Linux z +x)
        import zipfile, tempfile as _tmp

        script_src = _portable_script_path()
        default_out = script_src.with_suffix(".pyz")
        out_path    = Path(args[1]).expanduser() if len(args) > 1 else default_out

        try:
            # Twórz .pyz — zipapp to ZIP z __main__.py jako entrypoint
            with _tmp.TemporaryDirectory() as td:
                td_path = Path(td)
                # Skopiuj skrypt jako __main__.py
                import shutil as _sh
                _sh.copy2(script_src, td_path / "__main__.py")
                # Spakuj do ZIP z nagłówkiem shebang
                with open(out_path, "wb") as pyz_f:
                    pyz_f.write(b"#!/usr/bin/env python3\n")
                    with zipfile.ZipFile(pyz_f, "w", zipfile.ZIP_DEFLATED) as zf:
                        zf.write(td_path / "__main__.py", "__main__.py")

            # Na Linux/Mac nadaj +x
            try:
                import stat as _st
                out_path.chmod(out_path.stat().st_mode | _st.S_IXUSR | _st.S_IXGRP)
            except Exception:  # ignorowane celowo
                pass

            size_kb = out_path.stat().st_size / 1024
            print()
            print(box_top("Spakowano — portable zipapp", width=w, color=C.PATH))
            print(box_row(f"  {C.PATH}✔{C.RESET}  Plik:    {out_path}",
                          width=w, color=C.PATH))
            print(box_row(f"  {C.DIM}Rozmiar: {size_kb:.0f} KB{C.RESET}",
                          width=w, color=C.PATH))
            print(box_sep(width=w, color=C.PATH))
            print(box_row(f"  {C.DIM}Uruchom: python {out_path.name}{C.RESET}",
                          width=w, color=C.PATH))
            print(box_row(f"  {C.DIM}Linux:   ./{out_path.name}  (wymaga chmod +x){C.RESET}",
                          width=w, color=C.PATH))
            print(box_row(
                f"  {C.DIM}Dane: utwórz .terminalx_data/ obok .pyz → tryb portable{C.RESET}",
                width=w, color=C.PATH))
            print(box_bottom(width=w, color=C.PATH))
            print()
        except Exception as e:
            print_error(f"Błąd pakowania: {e}")
        return

    # ── check ─────────────────────────────────────────────────────────────────
    if sub == "check":
        print()
        print(box_top("Weryfikacja przenośności", width=w, color=C.INFO))

        checks = []

        # 1. Wersja Pythona
        vi = sys.version_info
        py_ok = vi >= (3, 10)
        checks.append((py_ok, f"Python {vi.major}.{vi.minor}.{vi.micro}",
                       "≥ 3.10 wymagane" if not py_ok else ""))

        # 2. Brak zewnętrznych zależności
        EXTERNAL_LIBS = [
            "requests", "numpy", "pandas", "flask", "django", "PIL",
            "click", "rich", "prompt_toolkit", "colorama", "pydantic",
        ]
        bad_imports = []
        for lib in EXTERNAL_LIBS:
            try:
                __import__(lib)
                bad_imports.append(lib)
            except ImportError:
                pass
        checks.append((not bad_imports,
                       "Brak zewnętrznych bibliotek",
                       f"Znaleziono: {', '.join(bad_imports)}" if bad_imports else ""))

        # 3. stdlib imports — kluczowe moduły
        REQUIRED_STDLIB = [
            "os", "sys", "pathlib", "json", "hashlib", "re",
            "subprocess", "shutil", "datetime", "importlib.util",
            "http.server", "socket", "threading", "zipfile", "tarfile",
        ]
        missing_stdlib = []
        for mod in REQUIRED_STDLIB:
            try:
                __import__(mod)
            except ImportError:
                missing_stdlib.append(mod)
        checks.append((not missing_stdlib,
                       "Wszystkie stdlib OK",
                       f"Brakuje: {', '.join(missing_stdlib)}" if missing_stdlib else ""))

        # 4. Moduły opcjonalne
        optional = {
            "curses":    "nano-lite (edytor tekstowy)",
            "readline":  "autouzupełnianie TAB (ulepszone)",
            "tty":       "surowy tryb klawiatury (Unix)",
            "termios":   "sterowanie terminalem (Unix)",
        }
        opt_status = []
        for mod, desc in optional.items():
            try:
                __import__(mod)
                opt_status.append((True, f"{mod}", desc))
            except ImportError:
                opt_status.append((False, f"{mod} (opcjonalne)", desc))

        # 5. Plik skryptu czytelny
        script = _portable_script_path()
        script_ok = script.exists() and script.stat().st_size > 0
        checks.append((script_ok, f"Skrypt: {script.name}",
                       "Nie znaleziono pliku" if not script_ok else ""))

        # 6. Katalog danych dostępny do zapisu
        try:
            test_f = _BASE / ".portable_write_test"
            test_f.write_text("ok")
            test_f.unlink()
            data_writable = True
        except Exception:
            data_writable = False
        checks.append((data_writable, f"Zapis danych: {_BASE}",
                       "Brak uprawnień zapisu!" if not data_writable else ""))

        # 7. Stdout / stderr dostępne
        io_ok = (sys.stdout is not None and sys.stderr is not None)
        checks.append((io_ok, "stdout/stderr dostępne", ""))

        # Drukuj wyniki
        all_ok = True
        for ok, label, hint in checks:
            icon  = f"{C.PATH}✔{C.RESET}" if ok else f"{C.ERROR}✖{C.RESET}"
            extra = f"  {C.DIM}({hint}){C.RESET}" if hint else ""
            print(box_row(f"  {icon}  {label}{extra}", width=w, color=C.INFO))
            if not ok:
                all_ok = False

        # Opcjonalne moduły (osobna sekcja)
        print(box_sep(width=w, color=C.INFO))
        print(box_row(f"  {C.BOLD}Moduły opcjonalne{C.RESET}", width=w, color=C.INFO))
        for ok, label, desc in opt_status:
            icon = f"{C.PATH}✔{C.RESET}" if ok else f"{C.DIM}○{C.RESET}"
            print(box_row(f"  {icon}  {label:<16} {C.DIM}{desc}{C.RESET}",
                          width=w, color=C.INFO))

        print(box_sep(width=w, color=C.INFO))
        if all_ok:
            print(box_row(
                f"  {C.PATH}{C.BOLD}✔ Pełna przenośność potwierdzona{C.RESET}  "
                f"{C.DIM}(stdlib only, Python {sys.version.split()[0]}){C.RESET}",
                width=w, color=C.INFO))
        else:
            print(box_row(
                f"  {C.WARN}⚠ Niektóre testy nie przeszły — sprawdź wyniki powyżej{C.RESET}",
                width=w, color=C.INFO))
        print(box_bottom(width=w, color=C.INFO))
        print()
        return

    # ── env ───────────────────────────────────────────────────────────────────
    if sub == "env":
        all_vars = {
            "TERMINALX_DATA":    (_BOOT_DATA_OVERRIDE or os.environ.get("TERMINALX_DATA",""), "katalog danych"),
            "TERMINALX_RC":      (_BOOT_RC_FILE,         "plik .terminalxrc"),
            "TERMINALX_CONFIG":  (_BOOT_CONFIG_FILE,     "plik config JSON"),
            "TERMINALX_PROFILE": (_BOOT_PROFILE,         "profil przy starcie"),
            "TERMINALX_THEME":   (_BOOT_THEME,           "motyw"),
            "TERMINALX_OFFLINE": ("1" if _BOOT_FORCE_OFFLINE else "", "tryb offline"),
            "TERMINALX_NO_COLOR":("1" if _ANSI_DISABLED  else "", "wyłącz kolory"),
            "TERMINALX_VERBOSE": ("1" if _BOOT_VERBOSE   else "", "verbose mode"),
            "TERMINALX_DEBUG":   ("1" if _BOOT_DEBUG     else "", "debug mode"),
            "TERMINALX_LOG":     ("0" if _BOOT_LOG_OFF   else "", "wyłącz log"),
            "NO_COLOR":           (os.environ.get("NO_COLOR",""), "standard no-color.org"),
        }
        print()
        print(box_top("Zmienne środowiskowe portable", width=w, color=C.PROMPT))
        for var, (val, desc) in all_vars.items():
            if val:
                icon  = f"{C.PATH}✔{C.RESET}"
                v_str = f"{C.INFO}{val}{C.RESET}"
            else:
                icon  = f"{C.DIM}○{C.RESET}"
                v_str = f"{C.DIM}(nieustawiona){C.RESET}"
            print(box_row(
                f"  {icon}  {var:<26} {v_str}  {C.DIM}{desc}{C.RESET}",
                width=w, color=C.PROMPT))
        print(box_sep(width=w, color=C.PROMPT))
        print(box_row(
            f"  {C.DIM}Ustaw np.: export TERMINALX_OFFLINE=1  lub  "
            f"TERMINALX_DATA=/mnt/pendrive/data{C.RESET}",
            width=w, color=C.PROMPT))
        print(box_bottom(width=w, color=C.PROMPT))
        print()
        return

    print_error(f"Nieznana podkomenda: portable {sub}",
                "Dostępne: init status copy pack check env")

# ── Komenda build ─────────────────────────────────────────────────────────────
# Buduje standalone EXE z TerminalX.py przy użyciu PyInstaller.
# Jeśli PyInstaller nie jest zainstalowany — oferuje auto-instalację.
#
#   build exe [nazwa]     — buduj EXE (domyślna nazwa: polsoft-terminal)
#   build exe --onedir    — katalog z EXE zamiast pojedynczego pliku
#   build check           — sprawdź czy PyInstaller jest dostępny
#   build clean           — usuń katalogi dist/ i build/
#   build info            — pokaż parametry ostatniego buildu

_BUILD_LAST_LOG: dict = {}   # zapamiętuje parametry ostatniego buildu

@command("build", "Buduj standalone EXE z PyInstaller",
         aliases=["buildexe", "makeexe"],
         flags=["exe", "check", "clean", "info"])
def cmd_build_exe(args):
    """
    Użycie: build <podkomenda> [opcje]

    Podkomendy:
      exe [nazwa]     — zbuduj standalone .exe (--onefile, domyślna nazwa: polsoft-terminal)
      exe --onedir    — zbuduj katalog z EXE zamiast pojedynczego pliku
      check           — sprawdź dostępność PyInstaller
      clean           — usuń katalogi dist/ i build/ po buildzie
      info            — parametry ostatniego buildu

    Przykłady:
      build exe
      build exe moj-terminal
      build exe moj-terminal --onedir
      build check
      build clean
    """
    import shutil as _sh

    sub = args[0].lower() if args else "exe"
    w = min(terminal_width() - 2, 72)

    # ── check ────────────────────────────────────────────────────────────────
    def _pyinstaller_available() -> tuple[bool, str]:
        """Zwraca (dostępny, ścieżka_lub_komunikat)."""
        path = _sh.which("pyinstaller")
        if path:
            return True, path
        try:
            import PyInstaller  # noqa: F401
            return True, "pyinstaller (jako moduł Python)"
        except ImportError:
            pass
        return False, "nie znaleziono"

    if sub == "check":
        ok, info = _pyinstaller_available()
        print()
        print(box_top("Build — sprawdzanie środowiska", width=w, color=C.INFO))
        py_ver = f"{sys.version_info.major}.{sys.version_info.minor}.{sys.version_info.micro}"
        print(box_row(kv_row("Python", py_ver, key_w=24, key_color=C.DIM), width=w, color=C.INFO))
        status = f"{C.OK}✔  {info}{C.RESET}" if ok else f"{C.ERROR}✘  {info}{C.RESET}"
        print(box_row(kv_row("PyInstaller", status, key_w=24, key_color=C.DIM), width=w, color=C.INFO))
        if not ok:
            print(box_sep(width=w, color=C.INFO))
            print(box_row(f"  {C.DIM}Zainstaluj: pip install pyinstaller{C.RESET}", width=w, color=C.INFO))
            print(box_row(f"  {C.DIM}lub: build exe  (auto-instalacja){C.RESET}", width=w, color=C.INFO))
        print(box_bottom(width=w, color=C.INFO))
        print()
        return

    # ── clean ────────────────────────────────────────────────────────────────
    if sub == "clean":
        script_dir = _portable_script_path().parent
        removed = []
        for d in ["dist", "build"]:
            p = script_dir / d
            if p.exists():
                try:
                    _sh.rmtree(p)
                    removed.append(str(p))
                except Exception as e:
                    print_error(f"Błąd usuwania {p}: {e}")
        # spec files
        for spec in script_dir.glob("*.spec"):
            try:
                spec.unlink()
                removed.append(str(spec))
            except Exception:  # ignorowane celowo
                pass
        print()
        if removed:
            print(box_top("Build — wyczyszczono", width=w, color=C.PATH))
            for r in removed:
                print(box_row(f"  {C.PATH}✔{C.RESET}  {r}", width=w, color=C.PATH))
            print(box_bottom(width=w, color=C.PATH))
        else:
            print_info("Brak katalogów dist/ build/ do usunięcia.")
        print()
        return

    # ── info ─────────────────────────────────────────────────────────────────
    if sub == "info":
        print()
        print(box_top("Build — ostatni build", width=w, color=C.INFO))
        if not _BUILD_LAST_LOG:
            print(box_row(f"  {C.DIM}Brak danych — uruchom: build exe{C.RESET}", width=w, color=C.INFO))
        else:
            for k, v in _BUILD_LAST_LOG.items():
                print(box_row(kv_row(k, str(v), key_w=20, key_color=C.DIM), width=w, color=C.INFO))
        print(box_bottom(width=w, color=C.INFO))
        print()
        return

    # ── exe ──────────────────────────────────────────────────────────────────
    if sub in ("exe", "build", ""):
        # Parsuj argumenty: build exe [nazwa] [--onedir]
        remaining = args[1:] if len(args) > 1 else []
        onedir    = "--onedir" in remaining
        remaining = [a for a in remaining if a != "--onedir"]
        exe_name  = remaining[0] if remaining else "polsoft-terminal"

        # Walidacja nazwy
        if not re.match(r"^[a-zA-Z0-9._-]+$", exe_name):
            print_error("Nazwa EXE może zawierać tylko litery, cyfry, kropki, myślniki, podkreślenia.")
            return

        ok, pi_path = _pyinstaller_available()
        if not ok:
            print_warn("PyInstaller nie jest zainstalowany.")
            try:
                ans = input(f"  {C.INFO}Zainstalować teraz (pip install pyinstaller)? [t/n]: {C.RESET}").strip().lower()
            except (EOFError, KeyboardInterrupt):
                print(); return
            if ans in ("t", "y", "tak", "yes"):
                print_info("Instaluję PyInstaller...")
                ret = subprocess.run(
                    [sys.executable, "-m", "pip", "install", "pyinstaller"],
                    capture_output=False
                )
                if ret.returncode != 0:
                    print_error("Instalacja PyInstaller nie powiodła się.")
                    print(f"  {C.DIM}Spróbuj ręcznie: pip install pyinstaller{C.RESET}")
                    return
                ok, pi_path = _pyinstaller_available()
                if not ok:
                    print_error("PyInstaller nadal niedostępny po instalacji.")
                    return
            else:
                print_info("Anulowano. Zainstaluj: pip install pyinstaller")
                return

        script_src = _portable_script_path()
        mode_flag  = "--onedir" if onedir else "--onefile"
        mode_label = "onedir (katalog)" if onedir else "onefile (pojedynczy plik)"

        cmd = [
            sys.executable, "-m", "PyInstaller",
            mode_flag,
            "--noconsole" if sys.platform == "win32" else "--console",
            "--name", exe_name,
            str(script_src),
        ]

        print()
        print(box_top(f"Build EXE — {exe_name}", width=w, color=C.PROMPT))
        print(box_row(kv_row("Skrypt",  str(script_src), key_w=16, key_color=C.DIM), width=w, color=C.PROMPT))
        print(box_row(kv_row("Tryb",    mode_label,      key_w=16, key_color=C.DIM), width=w, color=C.PROMPT))
        print(box_row(kv_row("Nazwa",   exe_name,        key_w=16, key_color=C.DIM), width=w, color=C.PROMPT))
        print(box_row(kv_row("Platforma", sys.platform,  key_w=16, key_color=C.DIM), width=w, color=C.PROMPT))
        print(box_sep(width=w, color=C.PROMPT))
        print(box_row(f"  {C.DIM}Budowanie — może potrwać 30–120 sekund...{C.RESET}", width=w, color=C.PROMPT))
        print(box_bottom(width=w, color=C.PROMPT))
        print()

        try:
            ret = subprocess.run(cmd, capture_output=False)
        except FileNotFoundError:
            print_error("Nie można uruchomić PyInstaller.", "Sprawdź: build check")
            return

        # Znajdź wyjściowy plik/katalog
        out_dir = script_src.parent / "dist"
        if onedir:
            out_path = out_dir / exe_name
        else:
            suffixes = {
                "win32":  ".exe",
                "darwin": "",
                "linux":  "",
            }
            suf = suffixes.get(sys.platform, "")
            out_path = out_dir / f"{exe_name}{suf}"

        _BUILD_LAST_LOG.update({
            "Nazwa":    exe_name,
            "Tryb":     mode_label,
            "Skrypt":   str(script_src),
            "Wyjście":  str(out_path),
            "Status":   "OK" if ret.returncode == 0 else f"BŁĄD ({ret.returncode})",
        })

        print()
        if ret.returncode == 0:
            print(box_top("Build zakończony", width=w, color=C.OK))
            print(box_row(f"  {C.OK}✔{C.RESET}  {out_path}", width=w, color=C.OK))
            print(box_sep(width=w, color=C.OK))
            if sys.platform != "win32":
                print(box_row(f"  {C.DIM}Uruchom: ./{out_path.name}{C.RESET}", width=w, color=C.OK))
            else:
                print(box_row(f"  {C.DIM}Uruchom: {out_path.name}{C.RESET}", width=w, color=C.OK))
            print(box_row(f"  {C.DIM}Wyczyść: build clean{C.RESET}", width=w, color=C.OK))
            print(box_bottom(width=w, color=C.OK))
        else:
            print_error(f"Build zakończony z błędem (kod {ret.returncode}).",
                        "Sprawdź logi powyżej lub użyj: crashlog")
        print()
        return

    print_error(f"Nieznana podkomenda: build {sub}",
                "Dostępne: exe | check | clean | info")

# ── Komenda envdetect ─────────────────────────────────────────────────────────

@command("envdetect", "Automatyczne wykrywanie środowiska i sugestia profilu",
         aliases=["env-detect", "environment", "sysenv"],
         flags=["--auto", "--json", "--short"])
def cmd_envdetect(args):
    """
    envdetect              — pełny raport środowiska
    envdetect --short      — skrócony raport (jedna linia na flagę)
    envdetect --json       — wynik jako JSON
    envdetect --auto       — wykryj i automatycznie przełącz optymalny profil
    envdetect --apply      — alias dla --auto

    Wykrywane:
      docker  wsl  ci  ssh  venv  conda  jupyter  root
      tmux  screen  nvim  vscode  android  windows  macos
      truecolor  colors256  portable
    """
    import json as _json

    auto_switch = "--auto" in args or "--apply" in args
    as_json     = "--json" in args
    short       = "--short" in args

    env = detect_environment()
    suggested, reason = suggest_profile(env)

    if as_json:
        out = dict(env)
        out["suggested_profile"] = suggested
        out["suggestion_reason"] = reason
        print(_json.dumps(out, ensure_ascii=False, default=str, indent=2))
        return

    w = min(terminal_width() - 2, 72)

    if short:
        active_flags = [k for k, v in env.items()
                        if isinstance(v, bool) and v]
        print(f"  {C.BOLD}Środowisko:{C.RESET}  "
              f"{C.DIM}{', '.join(active_flags) or 'standardowe'}{C.RESET}")
        print(f"  {C.BOLD}Sugerowany profil:{C.RESET}  "
              f"{C.PATH}{suggested}{C.RESET}  {C.DIM}({reason}){C.RESET}")
        return

    print()
    print(box_top("Wykrywanie środowiska  TerminalX", width=w, color=C.EXEC))

    # Sekcja: projekt i git (nowe)
    proj   = env.get("project_type", "generic")
    git_r  = env.get("git_repo",   False)
    branch = env.get("git_branch", None)
    proj_icons = {
        "python": "🐍", "node": "📦", "rust": "🦀",
        "go": "🐹", "java": "☕", "cpp": "🔧",
        "docker": "🐳", "generic": "📁",
    }
    print(box_sep(width=w, color=C.EXEC))
    print(box_row(f"  {C.BOLD}Projekt (cwd){C.RESET}", width=w, color=C.EXEC))
    print(box_row(
        f"    {proj_icons.get(proj,'📁')}  typ: {C.INFO}{proj}{C.RESET}",
        width=w, color=C.EXEC))
    if git_r:
        b_str = f"gałąź: {C.PATH}{branch}{C.RESET}" if branch else "brak gałęzi"
        print(box_row(f"    {C.PATH}✔{C.RESET}  git repo  {C.DIM}({b_str}){C.RESET}",
                      width=w, color=C.EXEC))
    else:
        print(box_row(f"    {C.DIM}○  brak repozytorium git{C.RESET}",
                      width=w, color=C.EXEC))
    if env.get("low_memory"):
        print(box_row(
            f"    {C.WARN}⚠ Mało RAM{C.RESET}  {C.DIM}(< 512 MB dostępne){C.RESET}",
            width=w, color=C.EXEC))

    # Sekcja: flagi środowiskowe
    flag_groups = {
        "Kontener / VM":      ["docker", "wsl", "android"],
        "CI / Automatyzacja": ["ci"],
        "Połączenie":         ["ssh", "tmux", "screen"],
        "Python env":         ["venv", "conda", "jupyter"],
        "Terminal / IDE":     ["nvim", "vscode", "truecolor", "colors256",
                               "slow_terminal"],
        "System":             ["root", "windows", "macos", "portable",
                               "low_memory"],
    }

    for group, keys in flag_groups.items():
        print(box_sep(width=w, color=C.EXEC))
        print(box_row(f"  {C.BOLD}{group}{C.RESET}", width=w, color=C.EXEC))
        for k in keys:
            v = env.get(k, False)
            if isinstance(v, bool):
                if v:
                    icon  = f"{C.PATH}✔{C.RESET}"
                    label = f"{C.PATH}tak{C.RESET}"
                else:
                    icon  = f"{C.DIM}○{C.RESET}"
                    label = f"{C.DIM}nie{C.RESET}"
                # Extra detail
                detail = ""
                if k == "ci"    and env.get("ci_name"):
                    detail = f"  {C.DIM}({env['ci_name']}){C.RESET}"
                if k == "venv"  and env.get("venv_name"):
                    detail = f"  {C.DIM}({env['venv_name']}){C.RESET}"
                if k == "conda" and env.get("conda_env"):
                    detail = f"  {C.DIM}({env['conda_env']}){C.RESET}"
                print(box_row(
                    f"    {icon}  {k:<20} {label}{detail}",
                    width=w, color=C.EXEC))

    # Sekcja: terminal info
    print(box_sep(width=w, color=C.EXEC))
    print(box_row(f"  {C.BOLD}Terminal{C.RESET}", width=w, color=C.EXEC))
    for k, label in [("term", "TERM"), ("term_program", "TERM_PROGRAM"),
                     ("colorterm", "COLORTERM"), ("columns", "Szerokość"),
                     ("python_version", "Python"), ("python_impl", "Implementacja")]:
        v = env.get(k, "")
        if v:
            print(box_row(kv_row(f"    {label}", str(v), key_color=C.DIM, key_w=20),
                          width=w, color=C.EXEC))

    # Sekcja: sugestia profilu
    print(box_sep(width=w, color=C.EXEC))
    print(box_row(f"  {C.BOLD}Sugestia profilu{C.RESET}", width=w, color=C.EXEC))
    print(box_row(
        f"    {C.PATH}{C.BOLD}{suggested}{C.RESET}  "
        f"{C.DIM}— {reason}{C.RESET}",
        width=w, color=C.EXEC))

    if suggested != _CURRENT_PROFILE:
        print(box_row(
            f"    {C.DIM}Aktywny: {_CURRENT_PROFILE}  "
            f"|  Przełącz: profile switch {suggested}{C.RESET}",
            width=w, color=C.EXEC))
    else:
        print(box_row(
            f"    {C.DIM}✔ Aktywny profil '{_CURRENT_PROFILE}' jest optymalny.{C.RESET}",
            width=w, color=C.EXEC))

    print(box_sep(width=w, color=C.EXEC))
    print(box_row(
        f"  {C.DIM}envdetect --auto  — automatyczne przełączenie  "
        f"|  --json  |  --short{C.RESET}",
        width=w, color=C.EXEC))
    print(box_bottom(width=w, color=C.EXEC))
    print()

    # Auto-switch
    if auto_switch:
        if suggested != _CURRENT_PROFILE:
            print_info(f"Automatyczne przełączanie: {_CURRENT_PROFILE} → {suggested}")
            print_info(f"Powód: {reason}")
            cmd_profile(["switch", suggested])
        else:
            print_info(f"Profil '{_CURRENT_PROFILE}' jest już optymalny — brak zmian.")

# ── Auto-apply profilu przy starcie ──────────────────────────────────────────

def _auto_apply_saved_profile():
    """
    Przy starcie shella:
    1. Wczyta profil zapisany w konfiguracji (_active_profile).
    2. Jeśli ustawiono auto_profile_detect=True — zastosuje sugerowany przez envdetect.
    """
    saved = cfg("_active_profile", "default")
    data  = _profile_load_data(saved)
    if data and saved != "default":
        _STATE.current_profile = saved
        _profile_apply(data, silent=True)
    # Auto-detect (jeśli włączone)
    if cfg("auto_profile_detect", False):
        env = detect_environment()
        suggested, _ = suggest_profile(env)
        if suggested != _CURRENT_PROFILE:
            auto_data = _profile_load_data(suggested)
            if auto_data:
                _profile_apply(auto_data, silent=True)
                _STATE.current_profile = suggested

# MODULE: SESSION MANAGER — Obsługa wielu sesji, split-screen, tmux-style
# Wersja v21.0

#
# Funkcje:
#   session new [nazwa]         — utwórz nową sesję
#   session list                — lista wszystkich sesji
#   session switch <id|nazwa>   — przełącz aktywną sesję
#   session rename <id> <nazwa> — zmień nazwę sesji
#   session kill <id|nazwa>     — zakończ sesję
#   session pin <id> <zadanie>  — przypisz zadanie do sesji
#   session unpin <id>          — odpnij zadanie
#   session info [id]           — szczegóły sesji
#
#   split h [cmd]               — podziel poziomo (górna/dolna strefa)
#   split v [cmd]               — podziel pionowo (lewa/prawa strefa)
#   split close                 — zamknij split-view, wróć do jednej strefy
#   split run <cmd>             — uruchom komendę w nieaktywnym panelu
#
# Skróty (tmux-style, prefix Ctrl+B symulowany przez komendę 'tmux'):
#   tmux c      — new session (create)
#   tmux n      — next session
#   tmux p      — previous session
#   tmux l      — list sessions
#   tmux d      — detach (dezaktywuj / odepnij) sesję
#   tmux ,      — rename session
#   tmux &      — kill session
#   tmux %      — split pionowy
#   tmux "      — split poziomy
#   tmux o      — przejdź do drugiego panelu
#   tmux s      — wybierz sesję interaktywnie
#
# ── Dane sesji ────────────────────────────────────────────────────────────────

import threading as _threading

_SESSIONS: dict = {}          # id → SessionEntry
_ACTIVE_SESSION: str  = _STATE.active_session
_SESSION_COUNTER: int = _STATE.session_counter
_SESSION_LOCK = _threading.Lock()

# ── Split state ───────────────────────────────────────────────────────────────

_SPLIT_MODE: str        = _STATE.split_mode
_SPLIT_OUTPUT: list     = _STATE.split_output
_SPLIT_ACTIVE_PANE: int = _STATE.split_active_pane

SESSION_FILE = _BASE / ".terminalx_sessions.json"

class _SessionEntry:
    """Pojedyncza sesja shella."""

    def __init__(self, sid: str, name: str):
        self.id      = sid
        self.name    = name
        self.cwd     = str(Path.cwd())
        self.history: list[str] = []   # lokalna historia komend tej sesji
        self.created = datetime.datetime.now().isoformat(timespec="seconds")
        self.last_cmd = ""
        self.pin: str = ""             # przypisane zadanie (opis)
        self.detached: bool = False    # czy sesja jest dezaktywowana

    def to_dict(self) -> dict:
        return {
            "id":       self.id,
            "name":     self.name,
            "cwd":      self.cwd,
            "created":  self.created,
            "last_cmd": self.last_cmd,
            "pin":      self.pin,
            "detached": self.detached,
            "history":  self.history[-50:],  # zapisuj max 50 ostatnich
        }

    @classmethod
    def from_dict(cls, d: dict) -> "_SessionEntry":
        s = cls(d["id"], d["name"])
        s.cwd      = d.get("cwd", str(Path.cwd()))
        s.created  = d.get("created", s.created)
        s.last_cmd = d.get("last_cmd", "")
        s.pin      = d.get("pin", "")
        s.detached = d.get("detached", False)
        s.history  = d.get("history", [])
        return s

# ── Helpers ───────────────────────────────────────────────────────────────────

def _session_new_id() -> str:
    _STATE.session_counter += 1
    return str(_SESSION_COUNTER)

def _session_save():
    """Zapisz stan sesji do pliku JSON."""
    try:
        data = {
            "active": _ACTIVE_SESSION,
            "counter": _SESSION_COUNTER,
            "sessions": {sid: s.to_dict() for sid, s in _SESSIONS.items()},
        }
        SESSION_FILE.write_text(
            json.dumps(data, indent=2, ensure_ascii=False), encoding="utf-8"
        )
    except Exception:  # ignorowane celowo
        pass

def _session_load():
    """Wczytaj stan sesji z pliku JSON (przy starcie)."""
    if not SESSION_FILE.exists():
        return
    try:
        data = json.loads(SESSION_FILE.read_text(encoding="utf-8"))
        _STATE.session_counter = data.get("counter", 0)
        for sid, sd in data.get("sessions", {}).items():
            _SESSIONS[sid] = _SessionEntry.from_dict(sd)
        _STATE.active_session = data.get("active", "")
        # Jeśli wskazana sesja nie istnieje — resetuj
        if _ACTIVE_SESSION not in _SESSIONS:
            _STATE.active_session = next(iter(_SESSIONS), "")
    except Exception:  # ignorowane celowo
        pass

def _ensure_default_session():
    """Upewnij się że istnieje co najmniej jedna sesja."""
    if not _SESSIONS:
        sid  = _session_new_id()
        name = "main"
        _SESSIONS[sid] = _SessionEntry(sid, name)
        _STATE.active_session = sid
        _session_save()

def _active_session() -> "_SessionEntry | None":
    return _SESSIONS.get(_ACTIVE_SESSION)

def _find_session(query: str) -> "_SessionEntry | None":
    """Znajdź sesję po ID lub nazwie."""
    if query in _SESSIONS:
        return _SESSIONS[query]
    for s in _SESSIONS.values():
        if s.name == query:
            return s
    return None

def _session_status_line() -> str:
    """Zwraca jednolinijkowy pasek sesji (jak tmux status bar)."""
    parts = []
    for sid, s in _SESSIONS.items():
        active   = (sid == _ACTIVE_SESSION)
        pin_mark = f"📌" if s.pin else ""
        detach   = f"[d]" if s.detached else ""
        if active:
            parts.append(f"{C.PATH}[{C.BOLD}{sid}:{s.name}{pin_mark}{detach}{C.RESET}{C.PATH}]*{C.RESET}")
        else:
            parts.append(f"{C.DIM}[{sid}:{s.name}{pin_mark}{detach}]{C.RESET}")
    bar = "  ".join(parts)
    split_info = ""
    if _SPLIT_MODE:
        pane = "górna/lewa" if _SPLIT_ACTIVE_PANE == 0 else "dolna/prawa"
        split_info = f"  {C.INFO}│ split-{_SPLIT_MODE.upper()} [{pane}]{C.RESET}"
    return f"  {C.DIM}SESJE:{C.RESET} {bar}{split_info}"

def _session_record_cmd(cmd: str):
    """Zapisz komendę do historii aktywnej sesji."""
    s = _active_session()
    if s and cmd.strip():
        s.history.append(cmd.strip())
        if len(s.history) > 200:
            s.history = s.history[-200:]
        s.last_cmd = cmd.strip()

# ── Split helpers ─────────────────────────────────────────────────────────────

def _split_render(cmd_output: str, mode: str):
    """
    Wyrenderuj pseudo split-screen w terminalu tekstowym.
    Używa ANSI do narysowania dwóch paneli side-by-side (v) lub top-bottom (h).
    """
    w = terminal_width()

    if mode == "v":
        # Pionowy split — lewa/prawa strefa
        half = max(20, (w - 3) // 2)
        sep  = f"{C.DIM}│{C.RESET}"

        # Nagłówek
        lbl_active = "AKTYWNY" if _SPLIT_ACTIVE_PANE == 0 else "       "
        lbl_other  = "AKTYWNY" if _SPLIT_ACTIVE_PANE == 1 else "       "
        header_l   = f"{C.BOLD}{'Panel 1':^{half}}{C.RESET} {C.INFO}{lbl_active}{C.RESET}"
        header_r   = f"{C.BOLD}{'Panel 2':^{half}}{C.RESET} {C.INFO}{lbl_other}{C.RESET}"
        print(f"{header_l} {sep} {header_r}")
        print(f"{C.DIM}{'─'*half} ┼ {'─'*half}{C.RESET}")

        # Wyjście
        active_lines = cmd_output.splitlines() if cmd_output else []
        other_lines  = _SPLIT_OUTPUT[-20:] if _SPLIT_OUTPUT else ["(brak danych)"]
        max_lines    = max(len(active_lines), len(other_lines), 5)

        for i in range(max_lines):
            al = active_lines[i] if i < len(active_lines) else ""
            ol = other_lines[i]  if i < len(other_lines)  else ""
            # Przytnij do szerokości panelu
            al_disp = al[:half].ljust(half)
            ol_disp = ol[:half].ljust(half)
            if _SPLIT_ACTIVE_PANE == 0:
                print(f"{al_disp} {sep} {C.DIM}{ol_disp}{C.RESET}")
            else:
                print(f"{C.DIM}{al_disp}{C.RESET} {sep} {ol_disp}")

    elif mode == "h":
        # Poziomy split — górna/dolna strefa
        other_lines  = _SPLIT_OUTPUT[-10:] if _SPLIT_OUTPUT else ["(brak danych)"]
        active_lines = cmd_output.splitlines() if cmd_output else []

        if _SPLIT_ACTIVE_PANE == 0:
            # Aktywny na górze
            print(f"{C.BOLD}┌─ Panel 1 (aktywny) {'─'*max(0,w-22)}┐{C.RESET}")
            for ln in active_lines[-10:]:
                print(f"│ {ln[:max(0,w-4)]}")
            print(f"{C.DIM}├─ Panel 2 {'─'*max(0,w-12)}┤{C.RESET}")
            for ln in other_lines:
                print(f"{C.DIM}│ {ln[:max(0,w-4)]}{C.RESET}")
            print(f"{C.DIM}└{'─'*max(0,w-2)}┘{C.RESET}")
        else:
            # Aktywny na dole
            print(f"{C.DIM}┌─ Panel 1 {'─'*max(0,w-12)}┐{C.RESET}")
            for ln in other_lines:
                print(f"{C.DIM}│ {ln[:max(0,w-4)]}{C.RESET}")
            print(f"{C.BOLD}├─ Panel 2 (aktywny) {'─'*max(0,w-22)}┤{C.RESET}")
            for ln in active_lines[-10:]:
                print(f"│ {ln[:max(0,w-4)]}")
            print(f"{C.DIM}└{'─'*max(0,w-2)}┘{C.RESET}")

# ── Komenda: session ──────────────────────────────────────────────────────────

@command("session", "Zarządzaj sesjami TerminalXa (tmux-style)",
         aliases=["ses", "sessions"],
         flags=["new", "list", "switch", "rename", "kill", "pin",
                "unpin", "info", "detach", "attach"])
def cmd_session(args):
    """
    session new [nazwa]         — utwórz nową sesję
    session list                — lista sesji (domyślne)
    session switch <id|nazwa>   — przełącz sesję
    session rename <id> <nazwa> — zmień nazwę
    session kill <id|nazwa>     — zakończ sesję
    session pin <id> <zadanie>  — przypisz zadanie
    session unpin <id>          — odpnij zadanie
    session info [id]           — szczegóły sesji
    session detach [id]         — dezaktywuj sesję (zachowaj w tle)
    session attach <id|nazwa>   — reaktywuj dezaktywowaną sesję
    """

    _ensure_default_session()
    sub = args[0] if args else "list"

    # ── list ──────────────────────────────────────────────────────────────
    if sub in ("list", "ls", "l"):
        w = min(terminal_width() - 2, 72)
        print()
        print(box_top("Sesje TerminalXa", width=w, color=C.INFO))
        if not _SESSIONS:
            print(box_row(f"  {C.DIM}Brak sesji.{C.RESET}", width=w, color=C.INFO))
        for sid, s in _SESSIONS.items():
            active  = "▶" if sid == _ACTIVE_SESSION else " "
            pin_str = f"  📌 {C.DIM}{s.pin}{C.RESET}" if s.pin else ""
            det_str = f"  {C.DIM}[detached]{C.RESET}" if s.detached else ""
            age     = ""
            try:
                dt  = datetime.datetime.fromisoformat(s.created)
                age = f"  {C.DIM}utworzona {dt.strftime('%H:%M:%S')}{C.RESET}"
            except Exception:  # ignorowane celowo
                pass
            cwd_short = s.cwd[:30] + "…" if len(s.cwd) > 30 else s.cwd
            row1 = (f"  {C.PATH}{active}{C.RESET} "
                    f"{C.BOLD}[{sid}]{C.RESET} {C.PATH}{s.name}{C.RESET}"
                    f"{pin_str}{det_str}{age}")
            row2 = f"      {C.DIM}📁 {cwd_short}  │  ostatnia: {s.last_cmd or '—'}{C.RESET}"
            print(box_row(row1, width=w, color=C.INFO))
            print(box_row(row2, width=w, color=C.INFO))
            print(box_sep(width=w, color=C.INFO))
        print(box_row(
            f"  {C.DIM}session new | switch <id> | kill <id> | pin <id> <zadanie>{C.RESET}",
            width=w, color=C.INFO))
        print(box_bottom(width=w, color=C.INFO))
        print()
        return

    # ── new ───────────────────────────────────────────────────────────────
    if sub == "new":
        name = args[1] if len(args) >= 2 else f"ses-{_session_new_id()}"
        # sprawdź duplikat nazwy
        for s in _SESSIONS.values():
            if s.name == name:
                print_error(f"Sesja o nazwie '{name}' już istnieje.",
                            "Użyj innej nazwy lub: session switch " + s.id)
                return
        sid = _session_new_id()
        entry = _SessionEntry(sid, name)
        entry.cwd = str(Path.cwd())
        with _SESSION_LOCK:
            _SESSIONS[sid] = entry
        _STATE.active_session = sid
        _session_save()
        print_info(f"Nowa sesja [{sid}] '{name}' — aktywna.")
        print(f"  {C.DIM}Tip: session list  |  session switch <id>  |  tmux n{C.RESET}")
        return

    # ── switch ────────────────────────────────────────────────────────────
    if sub in ("switch", "sw", "select"):
        if len(args) < 2:
            print_error("Podaj ID lub nazwę sesji.", "Użyj: session switch <id|nazwa>")
            return
        target = _find_session(args[1])
        if not target:
            print_error(f"Sesja '{args[1]}' nie istnieje.",
                        "Sprawdź: session list")
            return
        # Zapisz CWD bieżącej sesji
        cur = _active_session()
        if cur:
            cur.cwd = str(Path.cwd())
        _STATE.active_session = target.id
        # Przywróć CWD nowej sesji
        try:
            os.chdir(target.cwd)
        except Exception:  # ignorowane celowo
            pass
        target.detached = False
        _session_save()
        print_info(f"Przełączono na sesję [{target.id}] '{target.name}'.")
        if target.pin:
            print(f"  {C.PATH}📌 Zadanie:{C.RESET} {target.pin}")
        return

    # ── rename ────────────────────────────────────────────────────────────
    if sub == "rename":
        if len(args) < 3:
            print_error("Użycie: session rename <id|nazwa> <nowa_nazwa>")
            return
        target = _find_session(args[1])
        if not target:
            print_error(f"Sesja '{args[1]}' nie istnieje.")
            return
        old_name = target.name
        target.name = args[2]
        _session_save()
        print_info(f"Sesja [{target.id}] '{old_name}' → '{target.name}'.")
        return

    # ── kill ──────────────────────────────────────────────────────────────
    if sub in ("kill", "close", "rm"):
        if len(args) < 2:
            print_error("Podaj ID lub nazwę sesji.", "Użyj: session kill <id|nazwa>")
            return
        target = _find_session(args[1])
        if not target:
            print_error(f"Sesja '{args[1]}' nie istnieje.")
            return
        if len(_SESSIONS) == 1:
            print_error("Nie można usunąć ostatniej sesji.",
                        "Utwórz nową (session new) przed zamknięciem tej.")
            return
        with _SESSION_LOCK:
            del _SESSIONS[target.id]
        # Jeśli usuwamy aktywną — przełącz na pierwszą dostępną
        if _ACTIVE_SESSION == target.id:
            first = next(iter(_SESSIONS))
            _STATE.active_session = first
            try:
                os.chdir(_SESSIONS[first].cwd)
            except Exception:  # ignorowane celowo
                pass
        _session_save()
        print_info(f"Sesja [{target.id}] '{target.name}' zamknięta.")
        return

    # ── pin ───────────────────────────────────────────────────────────────
    if sub == "pin":
        if len(args) < 3:
            print_error("Użycie: session pin <id|nazwa> <opis zadania>")
            return
        target = _find_session(args[1])
        if not target:
            print_error(f"Sesja '{args[1]}' nie istnieje.")
            return
        task = " ".join(args[2:])
        target.pin = task
        _session_save()
        print_info(f"📌 Sesja [{target.id}] '{target.name}' przypisana do: {task}")
        return

    # ── unpin ─────────────────────────────────────────────────────────────
    if sub == "unpin":
        query = args[1] if len(args) >= 2 else _ACTIVE_SESSION
        target = _find_session(query)
        if not target:
            print_error(f"Sesja '{query}' nie istnieje.")
            return
        target.pin = ""
        _session_save()
        print_info(f"Sesja [{target.id}] '{target.name}' — zadanie odpięte.")
        return

    # ── detach ────────────────────────────────────────────────────────────
    if sub == "detach":
        query  = args[1] if len(args) >= 2 else _ACTIVE_SESSION
        target = _find_session(query)
        if not target:
            print_error(f"Sesja '{query}' nie istnieje.")
            return
        target.detached = True
        target.cwd      = str(Path.cwd())
        # Przełącz na inną sesję jeśli dezaktywujemy aktywną
        if target.id == _ACTIVE_SESSION:
            others = [sid for sid in _SESSIONS if sid != target.id]
            if others:
                _STATE.active_session = others[0]
                try:
                    os.chdir(_SESSIONS[_ACTIVE_SESSION].cwd)
                except Exception:  # ignorowane celowo
                    pass
                print_info(f"Sesja [{target.id}] '{target.name}' detached. "
                           f"Aktywna: [{_ACTIVE_SESSION}] "
                           f"'{_SESSIONS[_ACTIVE_SESSION].name}'.")
            else:
                print_info(f"Sesja [{target.id}] oznaczona jako detached "
                           f"(jedyna sesja — pozostaje aktywna).")
                target.detached = False
        else:
            print_info(f"Sesja [{target.id}] '{target.name}' — detached.")
        _session_save()
        return

    # ── attach ────────────────────────────────────────────────────────────
    if sub == "attach":
        if len(args) < 2:
            # Pokaż detached sesje
            detached = [(sid, s) for sid, s in _SESSIONS.items() if s.detached]
            if not detached:
                print_info("Brak sesji w trybie detached.")
                return
            print(f"\n  {C.BOLD}Sesje detached:{C.RESET}")
            for sid, s in detached:
                print(f"    [{sid}] {C.PATH}{s.name}{C.RESET}  {C.DIM}{s.cwd}{C.RESET}")
            print(f"\n  {C.DIM}Użyj: session attach <id|nazwa>{C.RESET}\n")
            return
        target = _find_session(args[1])
        if not target:
            print_error(f"Sesja '{args[1]}' nie istnieje.")
            return
        cur = _active_session()
        if cur:
            cur.cwd = str(Path.cwd())
        target.detached = False
        _STATE.active_session = target.id
        try:
            os.chdir(target.cwd)
        except Exception:  # ignorowane celowo
            pass
        _session_save()
        print_info(f"Attach: sesja [{target.id}] '{target.name}' — aktywna.")
        if target.pin:
            print(f"  {C.PATH}📌 Zadanie:{C.RESET} {target.pin}")
        return

    # ── info ──────────────────────────────────────────────────────────────
    if sub == "info":
        query  = args[1] if len(args) >= 2 else _ACTIVE_SESSION
        target = _find_session(query)
        if not target:
            print_error(f"Sesja '{query}' nie istnieje.")
            return
        w = min(terminal_width() - 2, 60)
        print()
        print(box_top(f"Sesja [{target.id}] {target.name}", width=w, color=C.PATH))
        rows = [
            ("ID",        target.id),
            ("Nazwa",     target.name),
            ("CWD",       target.cwd),
            ("Utworzona", target.created),
            ("Ostatnia",  target.last_cmd or "—"),
            ("Zadanie",   target.pin or "—"),
            ("Status",    "detached" if target.detached else "aktywna"),
            ("Hist.",     f"{len(target.history)} komend"),
        ]
        for k, v in rows:
            print(box_row(kv_row(f"  {k}", v, key_w=12), width=w, color=C.PATH))
        if target.history:
            print(box_sep(width=w, color=C.PATH))
            print(box_row(f"  {C.BOLD}Ostatnie komendy:{C.RESET}", width=w, color=C.PATH))
            for h in target.history[-5:]:
                print(box_row(f"    {C.DIM}{h[:w-8]}{C.RESET}", width=w, color=C.PATH))
        print(box_bottom(width=w, color=C.PATH))
        print()
        return

    print_error(f"Nieznana podkomenda: session {sub}",
                "Dostępne: new list switch rename kill pin unpin info detach attach")

# ── Komenda: split ────────────────────────────────────────────────────────────

@command("split", "Pseudo split-screen — podział terminala na panele",
         aliases=["sp"],
         flags=["h", "v", "close", "swap", "run", "status"])
def cmd_split(args):
    """
    split h [komenda]   — podziel poziomo (górna/dolna strefa)
    split v [komenda]   — podziel pionowo (lewa/prawa strefa)
    split swap          — przełącz aktywny panel
    split run <komenda> — uruchom komendę w nieaktywnym panelu
    split status        — pokaż stan podziału
    split close         — zamknij podział, wróć do trybu pojedynczego okna
    """

    sub = args[0] if args else "status"

    # ── h / v — otwórz split ──────────────────────────────────────────────
    if sub in ("h", "v"):
        _STATE.split_mode = sub
        _STATE.split_active_pane = 0
        _STATE.split_output = []
        direction = "poziomy (górna/dolna)" if sub == "h" else "pionowy (lewa/prawa)"
        print_info(f"Split {direction} aktywny. Panel 1 — aktywny.")
        print(f"  {C.DIM}split swap  |  split run <cmd>  |  split close{C.RESET}")
        # Jeśli podano komendę — uruchom w panelu 2
        if len(args) >= 2:
            panel_cmd = " ".join(args[1:])
            print_info(f"Panel 2 ← {panel_cmd}")
            try:
                buf = _io.StringIO()
                import contextlib
                with contextlib.redirect_stdout(buf):
                    execute_line(panel_cmd)
                _STATE.split_output = buf.getvalue().splitlines()
            except Exception as e:
                _STATE.split_output = [f"[błąd: {e}]"]
        return

    # ── swap — przełącz aktywny panel ────────────────────────────────────
    if sub == "swap":
        if not _SPLIT_MODE:
            print_error("Brak aktywnego podziału.", "Użyj: split h lub split v")
            return
        _STATE.split_active_pane = 1 - _SPLIT_ACTIVE_PANE
        panel = "Panel 1 (górna/lewa)" if _SPLIT_ACTIVE_PANE == 0 else "Panel 2 (dolna/prawa)"
        print_info(f"Aktywny: {panel}")
        return

    # ── run — uruchom w nieaktywnym panelu ───────────────────────────────
    if sub == "run":
        if not _SPLIT_MODE:
            print_error("Brak aktywnego podziału.", "Użyj: split h lub split v")
            return
        if len(args) < 2:
            print_error("Podaj komendę: split run <komenda>")
            return
        panel_cmd = " ".join(args[1:])
        print_info(f"Panel {2 - _SPLIT_ACTIVE_PANE} ← {panel_cmd}")
        try:
            buf = _io.StringIO()
            import contextlib
            with contextlib.redirect_stdout(buf):
                execute_line(panel_cmd)
            _STATE.split_output = buf.getvalue().splitlines()
        except Exception as e:
            _STATE.split_output = [f"[błąd: {e}]"]
        # Wyrenderuj aktualny split
        _split_render("", _SPLIT_MODE)
        return

    # ── status ────────────────────────────────────────────────────────────
    if sub == "status":
        if not _SPLIT_MODE:
            print(f"  {C.DIM}Split nieaktywny. Użyj: split h | split v{C.RESET}")
        else:
            pane = "Panel 1" if _SPLIT_ACTIVE_PANE == 0 else "Panel 2"
            direction = "poziomy" if _SPLIT_MODE == "h" else "pionowy"
            print(f"  {C.INFO}Split {direction}{C.RESET} — aktywny: {C.PATH}{pane}{C.RESET}")
            print(f"  {C.DIM}Bufor panelu 2: {len(_SPLIT_OUTPUT)} linii{C.RESET}")
        return

    # ── close ─────────────────────────────────────────────────────────────
    if sub == "close":
        _STATE.split_mode = ""
        _STATE.split_output = []
        _STATE.split_active_pane = 0
        print_info("Podział zamknięty — tryb pojedynczego okna.")
        return

    print_error(f"Nieznana podkomenda: split {sub}",
                "Dostępne: h v swap run status close")

# ── Komenda: tmux (skróty klawiszowe tmux-style) ─────────────────────────────

@command("tmux", "Skróty tmux-style do zarządzania sesjami i splitami",
         aliases=["tx"],
         flags=["c","n","p","l","d","s",",","&","%",'"',"o","q"])
def cmd_tmux(args):
    """
    Emulacja skrótów tmux (prefix-key zastąpiony komendą 'tmux <klucz>'):

      tmux c     — nowa sesja (create)
      tmux n     — następna sesja (next)
      tmux p     — poprzednia sesja (prev)
      tmux l     — lista sesji
      tmux d     — detach aktywnej sesji
      tmux s     — interaktywny wybór sesji
      tmux ,     — zmień nazwę aktywnej sesji
      tmux &     — zabij aktywną sesję
      tmux %     — split pionowy
      tmux "     — split poziomy
      tmux o     — zamień aktywny panel (swap)
      tmux q     — zamknij split
    """

    _ensure_default_session()
    key = args[0] if args else ""

    if key == "c":
        cmd_session(["new"] + args[1:])

    elif key == "n":
        # Następna sesja
        ids  = list(_SESSIONS.keys())
        idx  = ids.index(_ACTIVE_SESSION) if _ACTIVE_SESSION in ids else -1
        nidx = (idx + 1) % len(ids)
        cmd_session(["switch", ids[nidx]])

    elif key == "p":
        # Poprzednia sesja
        ids  = list(_SESSIONS.keys())
        idx  = ids.index(_ACTIVE_SESSION) if _ACTIVE_SESSION in ids else 1
        pidx = (idx - 1) % len(ids)
        cmd_session(["switch", ids[pidx]])

    elif key == "l":
        cmd_session(["list"])

    elif key == "d":
        cmd_session(["detach"])

    elif key == "s":
        # Interaktywny wybór sesji
        ids = list(_SESSIONS.keys())
        if not ids:
            print_info("Brak sesji."); return
        print(f"\n  {C.BOLD}Wybierz sesję:{C.RESET}")
        for i, sid in enumerate(ids):
            s      = _SESSIONS[sid]
            marker = f"{C.PATH}▶{C.RESET}" if sid == _ACTIVE_SESSION else " "
            print(f"  {marker} {i+1}) [{sid}] {C.PATH}{s.name}{C.RESET}"
                  f"  {C.DIM}{s.cwd}{C.RESET}")
        print()
        try:
            choice = input(f"  {C.PROMPT}Nr (Enter=anuluj):{C.RESET} ").strip()
            if not choice:
                return
            idx = int(choice) - 1
            if 0 <= idx < len(ids):
                cmd_session(["switch", ids[idx]])
            else:
                print_error("Nieprawidłowy numer.")
        except (ValueError, EOFError, KeyboardInterrupt):
            pass

    elif key == ",":
        cur = _active_session()
        if not cur:
            print_error("Brak aktywnej sesji."); return
        try:
            new_name = input(f"  {C.PROMPT}Nowa nazwa dla [{cur.id}] '{cur.name}': {C.RESET}").strip()
            if new_name:
                cmd_session(["rename", cur.id, new_name])
        except (EOFError, KeyboardInterrupt):
            pass

    elif key == "&":
        cur = _active_session()
        if not cur:
            print_error("Brak aktywnej sesji."); return
        try:
            ans = input(f"  {C.ERROR}Zabić sesję [{cur.id}] '{cur.name}'? [t/n]: {C.RESET}").strip().lower()
            if ans in ("t", "y", "tak", "yes"):
                cmd_session(["kill", cur.id])
        except (EOFError, KeyboardInterrupt):
            pass

    elif key == "%":
        cmd_split(["v"])

    elif key in ('"', "'"):
        cmd_split(["h"])

    elif key == "o":
        cmd_split(["swap"])

    elif key == "q":
        cmd_split(["close"])

    else:
        print(f"\n  {C.BOLD}tmux — skróty zarządzania sesjami{C.RESET}\n")
        shortcuts = [
            ("c",   "nowa sesja"),
            ("n",   "następna sesja"),
            ("p",   "poprzednia sesja"),
            ("l",   "lista sesji"),
            ("d",   "detach aktywnej sesji"),
            ("s",   "interaktywny wybór sesji"),
            (",",   "zmień nazwę aktywnej sesji"),
            ("&",   "zabij aktywną sesję"),
            ("%",   "split pionowy"),
            ('\"',  "split poziomy"),
            ("o",   "zamień aktywny panel"),
            ("q",   "zamknij split"),
        ]
        for k, desc in shortcuts:
            print(f"    {C.PATH}tmux {k:<4}{C.RESET}  {C.DIM}{desc}{C.RESET}")
        print()

# ── Integracja z główną pętlą — inicjalizacja sesji przy starcie ─────────────

def _sessions_init():
    """Wywoływane raz przy starcie TerminalXa."""
    _session_load()
    _ensure_default_session()

# Rejestracja inicjalizacji — zostanie wywołana po załadowaniu modułu
try:
    _sessions_init()
except Exception:  # ignorowane celowo
    pass

# MODULE: SCHEDULER — Wbudowany harmonogram zadań (lokalny, cross-platform)
# Wersja v22.0

#
# Funkcje:
#   sched add <spec> <komenda>  — dodaj zadanie
#     Spec (jeden z formatów):
#       @once HH:MM             — jednorazowo o podanej godzinie (dziś lub jutro)
#       @daily HH:MM            — codziennie o godzinie
#       @hourly [MM]            — co godzinę (opcjonalnie: o podanej minucie)
#       @interval Ns|Nm|Nh      — co N sekund / minut / godzin
#       @boot                   — raz przy starcie shella
#       @cron M H D Mo W        — klasyczny cron (5 pól, * = każdy)
#
#   sched list                  — lista zadań
#   sched info <id>             — szczegóły zadania
#   sched run <id>              — uruchom natychmiast
#   sched enable <id>           — włącz zadanie
#   sched disable <id>          — wyłącz zadanie
#   sched remove <id>           — usuń zadanie
#   sched clear                 — usuń wszystkie zadania
#   sched log [id]              — log wykonań (opcjonalnie: tylko danego zadania)
#   sched start                 — uruchom wątek schedulera (auto przy starcie)
#   sched stop                  — zatrzymaj wątek schedulera
#   sched status                — czy wątek działa + ile zadań czeka
#
# ── Typy i stałe ─────────────────────────────────────────────────────────────

import time   as _time
import calendar as _calendar

SCHED_FILE    = _BASE / ".terminalx_scheduler.json"
SCHED_LOG     = _BASE / ".terminalx_sched_log.txt"
_SCHED_MAX_LOG = 500        # max wierszy w logu
_SCHED_TICK    = 10         # sekund — dokładność sprawdzania

# Globalne struktury
_SCHED_JOBS:   dict = {}    # id → _SchedJob
_SCHED_LOCK  = _threading.Lock()
_SCHED_THREAD: "_threading.Thread | None" = _STATE.sched_thread
_SCHED_RUNNING = _STATE.sched_running
_SCHED_COUNTER: int = _STATE.sched_counter

# ── Klasa zadania ─────────────────────────────────────────────────────────────

class _SchedJob:
    """Pojedyncze zaplanowane zadanie."""

    VALID_TYPES = ("once", "daily", "hourly", "interval", "boot", "cron")

    def __init__(self, jid: str, jtype: str, spec: str, command: str, label: str = ""):
        self.id       = jid
        self.type     = jtype      # once | daily | hourly | interval | boot | cron
        self.spec     = spec       # surowy opis (np. "14:30", "30m", "* * * * *")
        self.command  = command
        self.label    = label or command[:40]
        self.enabled  = True
        self.created  = datetime.datetime.now().isoformat(timespec="seconds")
        self.last_run: str = ""    # ISO timestamp ostatniego uruchomienia
        self.next_run: float = 0.0 # unix timestamp planowanego uruchomienia
        self.run_count: int = 0
        self.last_exit: int | None = None
        # Dla @interval — okres w sekundach
        self._interval_sec: float = 0.0
        # Dla @boot — czy już uruchomione w tej sesji
        self._boot_done: bool = False
        # Dla @cron — 5 pól (min, hour, mday, mon, wday), None = *
        self._cron_fields: list = []

    # ── Serializacja ──────────────────────────────────────────────────────

    def to_dict(self) -> dict:
        return {
            "id":           self.id,
            "type":         self.type,
            "spec":         self.spec,
            "command":      self.command,
            "label":        self.label,
            "enabled":      self.enabled,
            "created":      self.created,
            "last_run":     self.last_run,
            "next_run":     self.next_run,
            "run_count":    self.run_count,
            "last_exit":    self.last_exit,
            "_interval_sec":self._interval_sec,
            "_boot_done":   self._boot_done,
            "_cron_fields": self._cron_fields,
        }

    @classmethod
    def from_dict(cls, d: dict) -> "_SchedJob":
        j = cls(d["id"], d["type"], d["spec"], d["command"], d.get("label",""))
        j.enabled       = d.get("enabled", True)
        j.created       = d.get("created", "")
        j.last_run      = d.get("last_run", "")
        j.next_run      = d.get("next_run", 0.0)
        j.run_count     = d.get("run_count", 0)
        j.last_exit     = d.get("last_exit", None)
        j._interval_sec = d.get("_interval_sec", 0.0)
        j._boot_done    = d.get("_boot_done", False)
        j._cron_fields  = d.get("_cron_fields", [])
        return j

    # ── Oblicz następny czas uruchomienia ────────────────────────────────

    def compute_next(self, after: float | None = None) -> float:
        """Zwraca unix timestamp następnego uruchomienia (0 = nigdy / jednorazowe wyczerpane)."""
        now = after if after is not None else _time.time()
        dt  = datetime.datetime.fromtimestamp(now)

        if self.type == "once":
            # Spec: HH:MM
            t = _sched_parse_time(self.spec)
            if t is None:
                return 0.0
            h, m   = t
            target = dt.replace(hour=h, minute=m, second=0, microsecond=0)
            if target.timestamp() <= now:
                target += datetime.timedelta(days=1)
            return target.timestamp()

        if self.type == "daily":
            t = _sched_parse_time(self.spec)
            if t is None:
                return 0.0
            h, m   = t
            target = dt.replace(hour=h, minute=m, second=0, microsecond=0)
            if target.timestamp() <= now:
                target += datetime.timedelta(days=1)
            return target.timestamp()

        if self.type == "hourly":
            minute = 0
            try:
                minute = int(self.spec) if self.spec.strip() else 0
            except ValueError:
                pass
            target = dt.replace(minute=minute, second=0, microsecond=0)
            if target.timestamp() <= now:
                target += datetime.timedelta(hours=1)
            return target.timestamp()

        if self.type == "interval":
            if self._interval_sec <= 0:
                return 0.0
            return now + self._interval_sec

        if self.type == "boot":
            # Uruchamiane raz — nie planuj następnego
            return 0.0

        if self.type == "cron":
            return _sched_cron_next(self._cron_fields, now)

        return 0.0

    def is_due(self, now: float) -> bool:
        """Czy zadanie powinno zostać uruchomione teraz."""
        if not self.enabled:
            return False
        if self.type == "boot":
            return not self._boot_done
        if self.next_run <= 0:
            return False
        return now >= self.next_run

# ── Parsery ───────────────────────────────────────────────────────────────────

def _sched_parse_time(spec: str) -> "tuple[int,int] | None":
    """Parsuje 'HH:MM' → (h, m). Zwraca None przy błędzie."""
    spec = spec.strip()
    parts = spec.split(":")
    if len(parts) != 2:
        return None
    try:
        h, m = int(parts[0]), int(parts[1])
        if 0 <= h <= 23 and 0 <= m <= 59:
            return (h, m)
    except ValueError:
        pass
    return None

def _sched_parse_interval(spec: str) -> float:
    """Parsuje '30s' / '5m' / '2h' / '1d' → sekundy. 0.0 przy błędzie."""
    spec = spec.strip().lower()
    units = {"s": 1, "m": 60, "h": 3600, "d": 86400}
    if spec and spec[-1] in units:
        try:
            return float(spec[:-1]) * units[spec[-1]]
        except ValueError:
            pass
    # Spróbuj jako czysta liczba sekund
    try:
        return float(spec)
    except ValueError:
        return 0.0

def _sched_parse_cron(spec: str) -> "list | None":
    """
    Parsuje 5-polowy cron: 'M H D Mo W'
    Każde pole: liczba lub '*'. Zwraca listę 5 elementów (int lub None).
    """
    parts = spec.strip().split()
    if len(parts) != 5:
        return None
    result = []
    for p in parts:
        if p == "*":
            result.append(None)
        else:
            try:
                result.append(int(p))
            except ValueError:
                return None
    return result

def _sched_cron_next(fields: list, after: float) -> float:
    """
    Oblicza następny czas wyzwolenia dla crona.
    fields = [min, hour, mday, mon, wday]  (None = *)
    """
    if not fields or len(fields) != 5:
        return 0.0
    f_min, f_hour, f_mday, f_mon, f_wday = fields
    dt = datetime.datetime.fromtimestamp(after) + datetime.timedelta(minutes=1)
    dt = dt.replace(second=0, microsecond=0)

    # Przeszukujemy minuty do przodu (max 1 rok)
    limit = dt + datetime.timedelta(days=366)
    while dt < limit:
        if f_mon  is not None and dt.month      != f_mon:
            dt += datetime.timedelta(hours=1); dt = dt.replace(minute=0); continue
        if f_mday is not None and dt.day        != f_mday:
            dt += datetime.timedelta(hours=1); dt = dt.replace(minute=0); continue
        if f_wday is not None and dt.weekday()  != f_wday % 7:
            dt += datetime.timedelta(hours=1); dt = dt.replace(minute=0); continue
        if f_hour is not None and dt.hour       != f_hour:
            dt += datetime.timedelta(hours=1); dt = dt.replace(minute=0); continue
        if f_min  is not None and dt.minute     != f_min:
            dt += datetime.timedelta(minutes=1); continue
        return dt.timestamp()
    return 0.0

def _sched_parse_spec(at_type: str, spec_parts: list) -> "tuple[str,str,float,list] | str":
    """
    Parsuje spec i zwraca (jtype, spec_str, interval_sec, cron_fields)
    lub string z komunikatem błędu.
    """
    spec_str   = " ".join(spec_parts)
    interval   = 0.0
    cron_fields: list = []

    if at_type == "once":
        if not spec_parts:
            return "Brakuje godziny: @once HH:MM"
        if _sched_parse_time(spec_parts[0]) is None:
            return f"Nieprawidłowy format czasu '{spec_parts[0]}'. Użyj HH:MM."
        spec_str = spec_parts[0]

    elif at_type == "daily":
        if not spec_parts:
            return "Brakuje godziny: @daily HH:MM"
        if _sched_parse_time(spec_parts[0]) is None:
            return f"Nieprawidłowy format czasu '{spec_parts[0]}'. Użyj HH:MM."
        spec_str = spec_parts[0]

    elif at_type == "hourly":
        spec_str = spec_parts[0] if spec_parts else "0"
        try:
            m = int(spec_str)
            if not (0 <= m <= 59):
                return "Minuta musi być w zakresie 0–59."
        except ValueError:
            return f"Nieprawidłowa minuta '{spec_str}'."

    elif at_type == "interval":
        if not spec_parts:
            return "Brakuje okresu: @interval 30s | 5m | 2h | 1d"
        interval = _sched_parse_interval(spec_parts[0])
        if interval <= 0:
            return f"Nieprawidłowy okres '{spec_parts[0]}'. Przykłady: 30s, 5m, 2h, 1d"
        spec_str = spec_parts[0]

    elif at_type == "boot":
        spec_str = ""

    elif at_type == "cron":
        if len(spec_parts) < 5:
            return ("Za mało pól cron (potrzeba 5): @cron MIN HOUR DAY MON WDAY\n"
                    "  Przykład: @cron 0 9 * * 1  (pon. o 9:00)")
        cron_fields = _sched_parse_cron(" ".join(spec_parts[:5]))
        if cron_fields is None:
            return "Nieprawidłowy format cron. Przykład: @cron 0 9 * * 1"
        spec_str = " ".join(spec_parts[:5])

    else:
        return (f"Nieznany typ: @{at_type}. "
                "Dostępne: once daily hourly interval boot cron")

    return (at_type, spec_str, interval, cron_fields)

# ── Persystencja ─────────────────────────────────────────────────────────────

def _sched_save():
    try:
        data = {
            "counter": _SCHED_COUNTER,
            "jobs":    {jid: j.to_dict() for jid, j in _SCHED_JOBS.items()},
        }
        SCHED_FILE.write_text(
            json.dumps(data, indent=2, ensure_ascii=False), encoding="utf-8"
        )
    except Exception:  # ignorowane celowo
        pass

def _sched_load():
    if not SCHED_FILE.exists():
        return
    try:
        data = json.loads(SCHED_FILE.read_text(encoding="utf-8"))
        _STATE.sched_counter = data.get("counter", 0)
        for jid, jd in data.get("jobs", {}).items():
            j = _SchedJob.from_dict(jd)
            # Odśwież next_run dla zadań cyklicznych po restarcie
            if j.type not in ("once", "boot") and j.next_run > 0:
                now = _time.time()
                if j.next_run < now:
                    j.next_run = j.compute_next(now)
            _SCHED_JOBS[jid] = j
    except Exception:  # ignorowane celowo
        pass

# ── Log wykonań ───────────────────────────────────────────────────────────────

def _sched_log_write(jid: str, command: str, exit_code: int, note: str = ""):
    try:
        ts    = datetime.datetime.now().strftime("%Y-%m-%d %H:%M:%S")
        ok    = "OK" if exit_code == 0 else f"ERR({exit_code})"
        extra = f"  [{note}]" if note else ""
        line  = f"{ts}  [{jid}]  {ok}  {command[:60]}{extra}\n"
        with open(SCHED_LOG, "a", encoding="utf-8") as fh:
            fh.write(line)
        # Rotacja logu
        try:
            lines = SCHED_LOG.read_text(encoding="utf-8").splitlines(keepends=True)
            if len(lines) > _SCHED_MAX_LOG:
                SCHED_LOG.write_text("".join(lines[-_SCHED_MAX_LOG:]), encoding="utf-8")
        except Exception:  # ignorowane celowo
            pass
    except Exception:  # ignorowane celowo
        pass

# ── Wykonanie zadania ─────────────────────────────────────────────────────────

def _sched_run_job(j: "_SchedJob", reason: str = "scheduled"):
    """Wykonuje komendę zadania i aktualizuje statystyki."""
    ts  = datetime.datetime.now().isoformat(timespec="seconds")
    ret = 0
    try:
        ret = execute_line(j.command)
        if ret is None:
            ret = 0
    except Exception as e:
        ret = 1
        _sched_log_write(j.id, j.command, 1, note=str(e)[:60])
        return

    j.last_run  = ts
    j.run_count += 1
    j.last_exit = ret

    now = _time.time()
    if j.type == "once":
        j.enabled  = False  # jednorazowe — wyłącz po wykonaniu
        j.next_run = 0.0
    elif j.type == "boot":
        j._boot_done = True
        j.next_run   = 0.0
    else:
        j.next_run = j.compute_next(now)

    _sched_log_write(j.id, j.command, ret, note=reason)
    _sched_save()

# ── Wątek schedulera ─────────────────────────────────────────────────────────

def _sched_worker():
    """Główna pętla schedulera — sprawdza zadania co _SCHED_TICK sekund."""
    _log("INFO", "Scheduler: wątek uruchomiony.")
    while _SCHED_RUNNING:
        now = _time.time()
        with _SCHED_LOCK:
            due = [(jid, j) for jid, j in _SCHED_JOBS.items() if j.is_due(now)]
        for jid, j in due:
            try:
                _sched_run_job(j, reason="auto")
            except Exception as e:
                _sched_log_write(jid, j.command, -1, note=f"wyjątek: {e}")
        _time.sleep(_SCHED_TICK)
    _log("INFO", "Scheduler: wątek zatrzymany.")

def _sched_start():
    if _SCHED_RUNNING and _SCHED_THREAD and _SCHED_THREAD.is_alive():
        return  # już działa
    _STATE.sched_running = True
    _STATE.sched_thread = _threading.Thread(
        target=_sched_worker,
        name="TerminalX-sched",
        daemon=True
    )
    _SCHED_THREAD.start()

def _sched_stop():
    _STATE.sched_running = False

# ── Formatowanie ──────────────────────────────────────────────────────────────

_SCHED_TYPE_ICON = {
    "once":     "🕐",
    "daily":    "📅",
    "hourly":   "⏰",
    "interval": "🔁",
    "boot":     "🚀",
    "cron":     "⚙️ ",
}

def _sched_next_str(j: "_SchedJob") -> str:
    if not j.enabled:
        return f"{C.DIM}wyłączone{C.RESET}"
    if j.type == "boot":
        return f"{C.DIM}{'✔ wykonane' if j._boot_done else 'przy starcie'}{C.RESET}"
    if j.next_run <= 0:
        return f"{C.DIM}—{C.RESET}"
    dt   = datetime.datetime.fromtimestamp(j.next_run)
    diff = j.next_run - _time.time()
    if diff < 0:
        return f"{C.DIM}wkrótce{C.RESET}"
    if diff < 3600:
        mins = int(diff // 60)
        return f"{C.PATH}za {mins} min  ({dt.strftime('%H:%M:%S')}){C.RESET}"
    if diff < 86400:
        hrs  = int(diff // 3600)
        return f"{C.PATH}za {hrs} h  ({dt.strftime('%H:%M')}){C.RESET}"
    return f"{C.PATH}{dt.strftime('%Y-%m-%d %H:%M')}{C.RESET}"

def _sched_new_id() -> str:
    _STATE.sched_counter += 1
    return str(_SCHED_COUNTER)

# ── Komenda: sched ────────────────────────────────────────────────────────────

@command("sched", "Harmonogram zadań — wbudowany scheduler (cross-platform)",
         aliases=["scheduler", "cron", "at"],
         flags=["add","list","info","run","enable","disable","remove",
                "clear","log","start","stop","status"])
def cmd_sched(args):
    """
    sched add @<typ> [spec] <komenda>  — dodaj zadanie
      Typy:
        @once HH:MM <cmd>          — jednorazowo o godzinie
        @daily HH:MM <cmd>         — codziennie o godzinie
        @hourly [MM] <cmd>         — co godzinę (MM = minuta)
        @interval <okres> <cmd>    — cyklicznie (30s | 5m | 2h | 1d)
        @boot <cmd>                — raz przy starcie shella
        @cron M H D Mo W <cmd>     — format cron (5 pól)

    sched list                     — lista zadań
    sched info <id>                — szczegóły zadania
    sched run <id>                 — uruchom natychmiast
    sched enable <id>              — włącz zadanie
    sched disable <id>             — wyłącz zadanie
    sched remove <id>              — usuń zadanie
    sched clear                    — usuń wszystkie zadania
    sched log [id]                 — log wykonań
    sched start                    — uruchom wątek schedulera
    sched stop                     — zatrzymaj wątek
    sched status                   — stan schedulera

    Przykłady:
      sched add @daily 08:00 echo "Dzień dobry!"
      sched add @interval 10m diag --short
      sched add @cron 0 9 * * 1 echo "Poniedzialek!"
      sched add @boot plugin reload
    """
    sub = args[0] if args else "list"

    # ── add ───────────────────────────────────────────────────────────────
    if sub == "add":
        # Poszukaj tokenu @<typ>
        if len(args) < 2:
            print_error("Użycie: sched add @<typ> [spec] <komenda>",
                        "Przykład: sched add @daily 08:00 echo hello")
            return
        type_token = args[1]
        if not type_token.startswith("@"):
            print_error(f"Typ zadania musi zaczynać się od '@', np. @daily.",
                        "Typy: @once @daily @hourly @interval @boot @cron")
            return
        at_type = type_token[1:].lower()

        # Reszta argumentów: [spec...] <komenda...>
        rest = args[2:]
        if not rest:
            print_error("Brakuje komendy po typie zadania.")
            return

        # Długość spec wg typu
        spec_len_map = {
            "once": 1, "daily": 1, "hourly": 1,
            "interval": 1, "boot": 0, "cron": 5,
        }
        spec_len = spec_len_map.get(at_type, 0)
        if len(rest) < spec_len + (1 if at_type != "boot" else 1):
            # Musimy mieć conajmniej spec + 1 token komendy (boot: 1 token)
            pass

        spec_parts = rest[:spec_len]
        cmd_parts  = rest[spec_len:]
        if not cmd_parts:
            # Boot nie ma spec — cała reszta to komenda
            if at_type == "boot":
                spec_parts = []
                cmd_parts  = rest
            else:
                print_error("Brakuje komendy (po spec).",
                            f"Przykład: sched add @{at_type} {'HH:MM ' if at_type in ('once','daily') else ''}<komenda>")
                return

        command_str = " ".join(cmd_parts)

        parsed = _sched_parse_spec(at_type, spec_parts)
        if isinstance(parsed, str):
            print_error(parsed); return

        jtype, spec_str, interval_sec, cron_fields = parsed

        jid = _sched_new_id()
        j   = _SchedJob(jid, jtype, spec_str, command_str)
        j._interval_sec = interval_sec
        j._cron_fields  = cron_fields

        # Oblicz pierwszy czas uruchomienia
        now = _time.time()
        if jtype == "boot":
            j.next_run = 0.0
        elif jtype == "interval":
            j.next_run = now + interval_sec
        else:
            j.next_run = j.compute_next(now)

        with _SCHED_LOCK:
            _SCHED_JOBS[jid] = j
        _sched_save()

        icon = _SCHED_TYPE_ICON.get(jtype, "•")
        print_info(f"{icon} Zadanie [{jid}] dodane: {C.BOLD}{command_str}{C.RESET}")
        print(f"  {C.DIM}Typ: @{jtype}  "
              f"Spec: {spec_str or '—'}  "
              f"Następne: {_sched_next_str(j)}{C.RESET}")
        return

    # ── list ──────────────────────────────────────────────────────────────
    if sub in ("list", "ls", "l", ""):
        w = min(terminal_width() - 2, 78)
        print()
        running_str = (f"{C.PATH}działa ✔{C.RESET}" if _SCHED_RUNNING
                       else f"{C.DIM}zatrzymany{C.RESET}")
        print(box_top(f"Harmonogram zadań  — scheduler {running_str}",
                      width=w, color=C.EXEC))
        if not _SCHED_JOBS:
            print(box_row(
                f"  {C.DIM}Brak zadań. Dodaj: sched add @daily 08:00 <komenda>{C.RESET}",
                width=w, color=C.EXEC))
        else:
            for jid, j in _SCHED_JOBS.items():
                icon   = _SCHED_TYPE_ICON.get(j.type, "•")
                status = f"{C.PATH}✔{C.RESET}" if j.enabled else f"{C.ERROR}✖{C.RESET}"
                nxt    = _sched_next_str(j)
                spec_d = f"@{j.type} {j.spec}".strip()
                row1   = (f"  {status} {icon} {C.BOLD}[{jid}]{C.RESET} "
                          f"{C.PATH}{j.label[:38]}{C.RESET}")
                row2   = (f"      {C.DIM}Spec: {spec_d:<22}  "
                          f"Uruchomień: {j.run_count:<5}  "
                          f"Ostatnie: {j.last_run or '—'}{C.RESET}")
                row3   = f"      Następne: {nxt}"
                print(box_row(row1, width=w, color=C.EXEC))
                print(box_row(row2, width=w, color=C.EXEC))
                print(box_row(row3, width=w, color=C.EXEC))
                print(box_sep(width=w, color=C.EXEC))
        print(box_row(
            f"  {C.DIM}sched add @daily 08:00 <cmd> | sched run <id> | "
            f"sched disable <id>{C.RESET}",
            width=w, color=C.EXEC))
        print(box_bottom(width=w, color=C.EXEC))
        print()
        return

    # ── info ──────────────────────────────────────────────────────────────
    if sub == "info":
        if len(args) < 2:
            print_error("Podaj ID zadania: sched info <id>"); return
        j = _SCHED_JOBS.get(args[1])
        if not j:
            print_error(f"Zadanie '{args[1]}' nie istnieje."); return
        w = min(terminal_width() - 2, 64)
        icon = _SCHED_TYPE_ICON.get(j.type, "•")
        print()
        print(box_top(f"{icon} Zadanie [{j.id}]", width=w, color=C.PATH))
        rows = [
            ("ID",         j.id),
            ("Typ",        f"@{j.type}"),
            ("Spec",       j.spec or "—"),
            ("Komenda",    j.command),
            ("Etykieta",   j.label),
            ("Status",     "włączone" if j.enabled else "wyłączone"),
            ("Utworzone",  j.created),
            ("Ostatnie",   j.last_run or "—"),
            ("Uruchomień", str(j.run_count)),
            ("Exit",       str(j.last_exit) if j.last_exit is not None else "—"),
            ("Następne",   _sched_next_str(j)),
        ]
        if j.type == "interval":
            rows.append(("Okres",    f"{j._interval_sec:.0f}s "
                                      f"({j._interval_sec/60:.1f} min)"))
        if j.type == "cron":
            rows.append(("Cron",     j.spec))
        for k, v in rows:
            print(box_row(kv_row(f"  {k}", v, key_w=12), width=w, color=C.PATH))
        print(box_bottom(width=w, color=C.PATH))
        print()
        return

    # ── run — natychmiastowe uruchomienie ─────────────────────────────────
    if sub == "run":
        if len(args) < 2:
            print_error("Podaj ID zadania: sched run <id>"); return
        j = _SCHED_JOBS.get(args[1])
        if not j:
            print_error(f"Zadanie '{args[1]}' nie istnieje."); return
        print_info(f"Uruchamiam zadanie [{j.id}]: {j.command}")
        _sched_run_job(j, reason="manual")
        return

    # ── enable ────────────────────────────────────────────────────────────
    if sub == "enable":
        if len(args) < 2:
            print_error("Podaj ID zadania: sched enable <id>"); return
        j = _SCHED_JOBS.get(args[1])
        if not j:
            print_error(f"Zadanie '{args[1]}' nie istnieje."); return
        j.enabled  = True
        j.next_run = j.compute_next(_time.time())
        _sched_save()
        print_info(f"Zadanie [{j.id}] włączone. Następne: {_sched_next_str(j)}")
        return

    # ── disable ───────────────────────────────────────────────────────────
    if sub == "disable":
        if len(args) < 2:
            print_error("Podaj ID zadania: sched disable <id>"); return
        j = _SCHED_JOBS.get(args[1])
        if not j:
            print_error(f"Zadanie '{args[1]}' nie istnieje."); return
        j.enabled = False
        _sched_save()
        print_info(f"Zadanie [{j.id}] wyłączone.")
        return

    # ── remove ────────────────────────────────────────────────────────────
    if sub in ("remove", "rm", "delete", "del"):
        if len(args) < 2:
            print_error("Podaj ID zadania: sched remove <id>"); return
        j = _SCHED_JOBS.get(args[1])
        if not j:
            print_error(f"Zadanie '{args[1]}' nie istnieje."); return
        try:
            ans = input(f"  {C.ERROR}Usunąć zadanie [{j.id}] '{j.label}'? [t/n]: {C.RESET}").strip().lower()
        except (EOFError, KeyboardInterrupt):
            return
        if ans in ("t", "y", "tak", "yes"):
            with _SCHED_LOCK:
                del _SCHED_JOBS[args[1]]
            _sched_save()
            print_info(f"Zadanie [{j.id}] usunięte.")
        return

    # ── clear ─────────────────────────────────────────────────────────────
    if sub == "clear":
        if not _SCHED_JOBS:
            print_info("Brak zadań."); return
        try:
            ans = input(f"  {C.ERROR}Usunąć WSZYSTKIE {len(_SCHED_JOBS)} zadania? [t/n]: {C.RESET}").strip().lower()
        except (EOFError, KeyboardInterrupt):
            return
        if ans in ("t", "y", "tak", "yes"):
            with _SCHED_LOCK:
                _SCHED_JOBS.clear()
            _sched_save()
            print_info("Wszystkie zadania usunięte.")
        return

    # ── log ───────────────────────────────────────────────────────────────
    if sub == "log":
        if not SCHED_LOG.exists():
            print_info("Brak logu wykonań."); return
        filter_id = args[1] if len(args) >= 2 else ""
        lines = SCHED_LOG.read_text(encoding="utf-8", errors="replace").splitlines()
        if filter_id:
            lines = [l for l in lines if f"[{filter_id}]" in l]
        if not lines:
            print_info(f"Brak wpisów{' dla zadania ' + filter_id if filter_id else ''}."); return
        w = min(terminal_width() - 2, 80)
        title = f"Log schedulera{' [' + filter_id + ']' if filter_id else ''}"
        print()
        print(box_top(title, width=w, color=C.DIM))
        for ln in lines[-40:]:
            # Kolorowanie: OK = zielony, ERR = czerwony
            if "  OK  " in ln:
                colored = ln.replace("  OK  ", f"  {C.PATH}OK{C.RESET}  ")
            elif "  ERR" in ln:
                colored = ln.replace("  ERR", f"  {C.ERROR}ERR")
                colored += C.RESET
            else:
                colored = f"{C.DIM}{ln}{C.RESET}"
            print(box_row(f"  {colored}", width=w, color=C.DIM))
        print(box_bottom(width=w, color=C.DIM))
        print()
        return

    # ── start ─────────────────────────────────────────────────────────────
    if sub == "start":
        if _SCHED_RUNNING and _SCHED_THREAD and _SCHED_THREAD.is_alive():
            print_info("Scheduler już działa."); return
        _sched_start()
        print_info(f"Scheduler uruchomiony (tick co {_SCHED_TICK}s).")
        return

    # ── stop ──────────────────────────────────────────────────────────────
    if sub == "stop":
        _sched_stop()
        print_info("Scheduler zatrzymany (aktywne zadania nie zostaną usunięte).")
        return

    # ── status ────────────────────────────────────────────────────────────
    if sub == "status":
        alive   = _SCHED_THREAD is not None and _SCHED_THREAD.is_alive()
        running = _SCHED_RUNNING and alive
        total   = len(_SCHED_JOBS)
        enabled = sum(1 for j in _SCHED_JOBS.values() if j.enabled)
        due_now = sum(1 for j in _SCHED_JOBS.values() if j.is_due(_time.time()))

        w = min(terminal_width() - 2, 56)
        print()
        print(box_top("Stan schedulera", width=w, color=C.EXEC))
        st_str = f"{C.PATH}✔ działa{C.RESET}" if running else f"{C.ERROR}✖ zatrzymany{C.RESET}"
        rows = [
            ("Wątek",       st_str),
            ("Tick",        f"co {_SCHED_TICK}s"),
            ("Zadania",     f"{total} (włączone: {enabled})"),
            ("Gotowe teraz",str(due_now)),
            ("Plik",        str(SCHED_FILE)),
        ]
        for k, v in rows:
            print(box_row(kv_row(f"  {k}", v, key_w=14), width=w, color=C.EXEC))
        print(box_bottom(width=w, color=C.EXEC))
        print()
        return

    print_error(f"Nieznana podkomenda: sched {sub}",
                "Dostępne: add list info run enable disable remove clear log start stop status")

# ── Inicjalizacja schedulera przy starcie shella ──────────────────────────────

def _sched_init():
    """Wczytaj zadania i uruchom wątek schedulera."""
    _sched_load()
    if _SCHED_JOBS:
        _sched_start()

try:
    _sched_init()
except Exception:  # ignorowane celowo
    pass

# MODULE: MACRO — Makra i sekwencje poleceń
# Wersja v23.0

#
# Funkcje:
#   macro define <nazwa> <cmd1> [; cmd2 ; ...]  — zdefiniuj makro (inline)
#   macro record <nazwa>                         — zacznij nagrywanie (zakończ: macro stop)
#   macro stop                                   — zakończ nagrywanie
#   macro run <nazwa> [arg1 arg2 ...]            — uruchom makro ($1..$9, $@ = wszystkie)
#   macro list                                   — lista makr
#   macro show <nazwa>                           — pokaż kroki makra
#   macro edit <nazwa>                           — edytuj (nano-lite lub inline)
#   macro delete <nazwa>                         — usuń makro
#   macro export <nazwa> [plik]                  — eksportuj do pliku .sh
#   macro import <plik>                          — importuj z pliku .sh / .txt
#   macro alias <nazwa> <alias>                  — utwórz alias do makra
#
# Skróty:
#   @<nazwa> [args]  — uruchom makro bezpośrednio z promptu

MACRO_FILE = _BASE / ".terminalx_macros.json"

_MACROS: dict     = {}      # nazwa → _Macro
_MACRO_RECORDING: "str | None" = _STATE.macro_recording
_MACRO_BUFFER:    list    = _STATE.macro_buffer

class _Macro:
    """Pojedyncze makro — lista kroków (komend shella)."""

    def __init__(self, name: str, steps: "list[str]", description: str = ""):
        self.name        = name
        self.steps:  list[str] = steps          # lista komend (mogą zawierać $1..$9)
        self.description        = description   # opcjonalny opis
        self.created            = datetime.datetime.now().isoformat(timespec="seconds")
        self.modified           = self.created
        self.run_count: int     = 0
        self.last_run:  str     = ""

    def to_dict(self) -> dict:
        return {
            "name":        self.name,
            "steps":       self.steps,
            "description": self.description,
            "created":     self.created,
            "modified":    self.modified,
            "run_count":   self.run_count,
            "last_run":    self.last_run,
        }

    @classmethod
    def from_dict(cls, d: dict) -> "_Macro":
        m = cls(d["name"], d.get("steps", []), d.get("description", ""))
        m.created   = d.get("created",   m.created)
        m.modified  = d.get("modified",  m.modified)
        m.run_count = d.get("run_count", 0)
        m.last_run  = d.get("last_run",  "")
        return m

# ── Persystencja ──────────────────────────────────────────────────────────────

def _macro_save():
    try:
        MACRO_FILE.write_text(
            json.dumps(
                {name: m.to_dict() for name, m in _MACROS.items()},
                indent=2, ensure_ascii=False
            ), encoding="utf-8"
        )
    except Exception:  # ignorowane celowo
        pass

def _macro_load():
    if not MACRO_FILE.exists():
        return
    try:
        data = json.loads(MACRO_FILE.read_text(encoding="utf-8"))
        for name, d in data.items():
            _MACROS[name] = _Macro.from_dict(d)
    except Exception:  # ignorowane celowo
        pass

# ── Interpolacja argumentów ───────────────────────────────────────────────────

def _macro_interpolate(step: str, args: "list[str]") -> str:
    """
    Podstawia $1..$9 i $@ w kroku makra.
    $0 = nazwa makra (pierwszy token) — nie dotyczy, zostawiamy jako literal.
    """
    result = step
    # $@ = wszystkie argumenty
    result = result.replace("$@", " ".join(args))
    # $1..$9
    for i in range(9, 0, -1):
        val = args[i - 1] if i <= len(args) else ""
        result = result.replace(f"${i}", val)
    return result

# ── Wykonanie makra ───────────────────────────────────────────────────────────

def _macro_run(m: "_Macro", args: "list[str]", verbose: bool = True) -> int:
    """
    Uruchamia makro. Zwraca kod wyjścia ostatniego kroku.
    """
    if not m.steps:
        print_error(f"Makro '{m.name}' jest puste.")
        return 1

    if verbose:
        print(f"\n  {C.BOLD}{C.EXEC}▶ Makro: {m.name}{C.RESET}"
              f"  {C.DIM}({len(m.steps)} {'krok' if len(m.steps)==1 else 'kroków'}){C.RESET}\n")

    last_exit = 0
    for i, step in enumerate(m.steps, 1):
        cmd = _macro_interpolate(step, args)
        if verbose:
            print(f"  {C.DIM}[{i}/{len(m.steps)}]{C.RESET} {C.PATH}{cmd}{C.RESET}")
        try:
            rc = execute_line(cmd)
            last_exit = rc if isinstance(rc, int) else 0
        except Exception as e:
            print_error(f"Krok {i} nie powiódł się: {e}")
            last_exit = 1

    m.run_count += 1
    m.last_run   = datetime.datetime.now().isoformat(timespec="seconds")
    _macro_save()

    if verbose:
        status = f"{C.PATH}OK{C.RESET}" if last_exit == 0 else f"{C.ERROR}ERR({last_exit}){C.RESET}"
        print(f"\n  {C.DIM}▶ Makro '{m.name}' zakończone — {status}{C.RESET}\n")

    return last_exit

# ── Komenda: macro ────────────────────────────────────────────────────────────

@command("macro", "Makra i sekwencje poleceń",
         aliases=["mac", "m"],
         flags=["define","record","stop","run","list","show","edit",
                "delete","export","import","alias"])
def cmd_macro(args):
    """
    macro define <nazwa> <cmd> [; cmd2 ; ...]  — zdefiniuj makro inline
    macro record <nazwa>                        — zacznij nagrywanie kroków
    macro stop                                  — zakończ nagrywanie
    macro run <nazwa> [arg1 ...]               — uruchom makro ($1..$9, $@)
    macro list                                  — lista makr
    macro show <nazwa>                          — wyświetl kroki
    macro edit <nazwa>                          — edytuj kroki interaktywnie
    macro delete <nazwa>                        — usuń makro
    macro export <nazwa> [plik]                 — eksportuj jako skrypt .sh
    macro import <plik>                         — importuj makro z pliku
    macro alias <nazwa> <alias>                 — utwórz alias do makra

    W makrach dostępne: $1..$9 (argumenty), $@ (wszystkie), ; (separator kroków)

    Szybkie uruchomienie z promptu:  @nazwa [arg1 arg2 ...]
    """

    sub = args[0] if args else "list"

    # ── define ────────────────────────────────────────────────────────────
    if sub == "define":
        if len(args) < 3:
            print_error("Użycie: macro define <nazwa> <komenda> [; komenda2 ...]",
                        "Przykład: macro define backup cd /tmp ; ls -la ; echo done")
            return
        name     = args[1]
        raw_body = " ".join(args[2:])
        # Podziel po ; na kroki
        steps    = [s.strip() for s in raw_body.split(";") if s.strip()]
        if not steps:
            print_error("Makro musi zawierać co najmniej jedną komendę.")
            return
        _MACROS[name] = _Macro(name, steps)
        _macro_save()
        print_info(f"Makro '{name}' zdefiniowane — {len(steps)} kroków.")
        for i, s in enumerate(steps, 1):
            print(f"  {C.DIM}[{i}] {s}{C.RESET}")
        return

    # ── record ────────────────────────────────────────────────────────────
    if sub == "record":
        if len(args) < 2:
            print_error("Podaj nazwę makra: macro record <nazwa>"); return
        name = args[1]
        if _MACRO_RECORDING:
            print_error(f"Nagrywanie już aktywne: '{_MACRO_RECORDING}'.",
                        "Zakończ: macro stop")
            return
        _STATE.macro_recording = name
        _STATE.macro_buffer = []
        print_info(f"⏺  Nagrywanie makra '{name}' — wpisuj komendy.")
        print(f"  {C.DIM}Zakończ: macro stop  |  Przerwij: Ctrl+C{C.RESET}")
        return

    # ── stop ──────────────────────────────────────────────────────────────
    if sub == "stop":
        if not _MACRO_RECORDING:
            print_error("Brak aktywnego nagrywania."); return
        name = _MACRO_RECORDING
        _STATE.macro_recording = None
        if not _MACRO_BUFFER:
            print_error(f"Makro '{name}' jest puste — nie zapisano.")
            return
        _MACROS[name] = _Macro(name, list(_MACRO_BUFFER))
        _STATE.macro_buffer = []
        _macro_save()
        print_info(f"⏹  Makro '{name}' nagrane — {len(_MACROS[name].steps)} kroków.")
        for i, s in enumerate(_MACROS[name].steps, 1):
            print(f"  {C.DIM}[{i}] {s}{C.RESET}")
        return

    # ── run ───────────────────────────────────────────────────────────────
    if sub == "run":
        if len(args) < 2:
            print_error("Podaj nazwę makra: macro run <nazwa> [arg1 arg2 ...]"); return
        name = args[1]
        m    = _MACROS.get(name)
        if not m:
            print_error(f"Makro '{name}' nie istnieje.", "Sprawdź: macro list"); return
        _macro_run(m, args[2:])
        return

    # ── list ──────────────────────────────────────────────────────────────
    if sub in ("list", "ls", "l", ""):
        w = min(terminal_width() - 2, 70)
        print()
        rec_badge = (f"  {C.ERROR}⏺ NAGRYWANIE: {_MACRO_RECORDING}{C.RESET}"
                     if _MACRO_RECORDING else "")
        print(box_top(f"Makra{rec_badge}", width=w, color=C.EXEC))
        if not _MACROS:
            print(box_row(
                f"  {C.DIM}Brak makr. Utwórz: macro define <nazwa> <cmd1> [; cmd2]{C.RESET}",
                width=w, color=C.EXEC))
        else:
            for name, m in sorted(_MACROS.items()):
                desc = f"  {C.DIM}{m.description}{C.RESET}" if m.description else ""
                row1 = (f"  {C.BOLD}{C.PATH}{name}{C.RESET}{desc}")
                row2 = (f"    {C.DIM}{len(m.steps)} kroków  |  "
                        f"uruchomień: {m.run_count}  |  "
                        f"ostatnie: {m.last_run or '—'}{C.RESET}")
                preview = " ; ".join(m.steps[:3])
                if len(m.steps) > 3:
                    preview += f" ; … (+{len(m.steps)-3})"
                row3 = f"    {C.DIM}{preview[:w-10]}{C.RESET}"
                print(box_row(row1, width=w, color=C.EXEC))
                print(box_row(row2, width=w, color=C.EXEC))
                print(box_row(row3, width=w, color=C.EXEC))
                print(box_sep(width=w, color=C.EXEC))
        print(box_row(
            f"  {C.DIM}macro run <nazwa> | macro show <nazwa> | @<nazwa> [args]{C.RESET}",
            width=w, color=C.EXEC))
        print(box_bottom(width=w, color=C.EXEC))
        print()
        return

    # ── show ──────────────────────────────────────────────────────────────
    if sub == "show":
        if len(args) < 2:
            print_error("Podaj nazwę: macro show <nazwa>"); return
        m = _MACROS.get(args[1])
        if not m:
            print_error(f"Makro '{args[1]}' nie istnieje."); return
        w = min(terminal_width() - 2, 64)
        print()
        print(box_top(f"Makro: {m.name}", width=w, color=C.PATH))
        meta = [
            ("Nazwa",      m.name),
            ("Opis",       m.description or "—"),
            ("Kroki",      str(len(m.steps))),
            ("Uruchomień", str(m.run_count)),
            ("Ostatnie",   m.last_run or "—"),
            ("Utworzone",  m.created),
        ]
        for k, v in meta:
            print(box_row(kv_row(f"  {k}", v, key_w=12), width=w, color=C.PATH))
        print(box_sep(width=w, color=C.PATH))
        print(box_row(f"  {C.BOLD}Kroki:{C.RESET}", width=w, color=C.PATH))
        for i, s in enumerate(m.steps, 1):
            print(box_row(f"  {C.DIM}[{i:>2}]{C.RESET} {s[:w-8]}", width=w, color=C.PATH))
        print(box_bottom(width=w, color=C.PATH))
        print()
        return

    # ── edit ──────────────────────────────────────────────────────────────
    if sub == "edit":
        if len(args) < 2:
            print_error("Podaj nazwę: macro edit <nazwa>"); return
        m = _MACROS.get(args[1])
        if not m:
            print_error(f"Makro '{args[1]}' nie istnieje."); return
        print(f"\n  {C.BOLD}Edycja makra '{m.name}'{C.RESET}  "
              f"{C.DIM}(Enter = zachowaj, nowa treść = zastąp, 'd' = usuń krok){C.RESET}\n")
        new_steps: list[str] = []
        for i, step in enumerate(m.steps, 1):
            try:
                val = input(f"  {C.DIM}[{i}]{C.RESET} [{step}]: ").strip()
            except (EOFError, KeyboardInterrupt):
                print(); break
            if val == "d":
                print(f"  {C.DIM}Krok {i} usunięty.{C.RESET}")
                continue
            new_steps.append(val if val else step)
        # Dodaj nowe kroki
        print(f"  {C.DIM}Dodaj nowe kroki (Enter = koniec):{C.RESET}")
        while True:
            try:
                val = input(f"  {C.DIM}[{len(new_steps)+1}]{C.RESET} ").strip()
            except (EOFError, KeyboardInterrupt):
                print(); break
            if not val:
                break
            new_steps.append(val)
        if not new_steps:
            print_error("Makro po edycji jest puste — zmiany odrzucone.")
            return
        m.steps    = new_steps
        m.modified = datetime.datetime.now().isoformat(timespec="seconds")
        _macro_save()
        print_info(f"Makro '{m.name}' zaktualizowane — {len(m.steps)} kroków.")
        return

    # ── delete ────────────────────────────────────────────────────────────
    if sub in ("delete", "del", "rm", "remove"):
        if len(args) < 2:
            print_error("Podaj nazwę: macro delete <nazwa>"); return
        name = args[1]
        if name not in _MACROS:
            print_error(f"Makro '{name}' nie istnieje."); return
        try:
            ans = input(f"  {C.ERROR}Usunąć makro '{name}'? [t/n]: {C.RESET}").strip().lower()
        except (EOFError, KeyboardInterrupt):
            return
        if ans in ("t", "y", "tak", "yes"):
            del _MACROS[name]
            _macro_save()
            print_info(f"Makro '{name}' usunięte.")
        return

    # ── export ────────────────────────────────────────────────────────────
    if sub == "export":
        if len(args) < 2:
            print_error("Podaj nazwę: macro export <nazwa> [plik]"); return
        m = _MACROS.get(args[1])
        if not m:
            print_error(f"Makro '{args[1]}' nie istnieje."); return
        out_path = Path(args[2]) if len(args) >= 3 else Path(f"{m.name}.sh")
        lines = [
            "#!/usr/bin/env bash",
            f"# Makro: {m.name}",
            f"# Opis:  {m.description or '—'}",
            f"# Eksport: {datetime.datetime.now().strftime('%Y-%m-%d %H:%M')}",
            f"# Uruchomień: {m.run_count}",
            "",
        ]
        for step in m.steps:
            lines.append(step)
        try:
            out_path.write_text("\n".join(lines) + "\n", encoding="utf-8")
            print_info(f"Makro '{m.name}' wyeksportowane → {out_path}")
        except Exception as e:
            print_error(f"Błąd eksportu: {e}")
        return

    # ── import ────────────────────────────────────────────────────────────
    if sub == "import":
        if len(args) < 2:
            print_error("Podaj ścieżkę: macro import <plik>"); return
        src = Path(args[1]).expanduser()
        if not src.exists():
            print_error(f"Plik nie istnieje: {src}"); return
        try:
            raw = src.read_text(encoding="utf-8")
        except Exception as e:
            print_error(f"Błąd odczytu: {e}"); return
        # Wyciągnij nazwę z komentarza lub z nazwy pliku
        name     = src.stem
        desc     = ""
        steps_in = []
        for line in raw.splitlines():
            line = line.strip()
            if not line or line.startswith("#!"):
                continue
            if line.startswith("# Makro:"):
                name = line.split(":", 1)[1].strip() or name
            elif line.startswith("# Opis:"):
                desc = line.split(":", 1)[1].strip()
            elif line.startswith("#"):
                continue
            else:
                steps_in.append(line)
        if not steps_in:
            print_error(f"Plik '{src}' nie zawiera żadnych kroków."); return
        _MACROS[name] = _Macro(name, steps_in, desc)
        _macro_save()
        print_info(f"Zaimportowano makro '{name}' — {len(steps_in)} kroków.")
        return

    # ── alias ─────────────────────────────────────────────────────────────
    if sub == "alias":
        if len(args) < 3:
            print_error("Użycie: macro alias <nazwa_makra> <alias>"); return
        name  = args[1]
        alias = args[2]
        if name not in _MACROS:
            print_error(f"Makro '{name}' nie istnieje."); return
        # Dodaj do systemu aliasów shella jako "macro run <name>"
        ALIASES[alias] = f"macro run {name}"
        try:
            save_aliases()
        except Exception:  # ignorowane celowo
            pass
        print_info(f"Alias '{alias}' → 'macro run {name}' utworzony.")
        return

    print_error(f"Nieznana podkomenda: macro {sub}",
                "Dostępne: define record stop run list show edit delete export import alias")

# ── Integracja z główną pętlą: nagrywanie + @shortcut ────────────────────────

def _macro_intercept(line: str) -> "tuple[bool, str]":
    """
    Przechwytuje komendy podczas nagrywania i obsługuje @nazwa.
    Zwraca (True, "") jeśli linia została obsłużona i nie ma być dalej wykonywana,
    albo (False, line) jeśli linia powinna być wykonana normalnie.
    """

    stripped = line.strip()

    # Tryb nagrywania — przechwytuj komendy (oprócz macro stop)
    if _MACRO_RECORDING:
        if stripped in ("macro stop", "mac stop", "m stop"):
            return False, line   # przepuść do normalnego wykonania
        _MACRO_BUFFER.append(stripped)
        print(f"  {C.DIM}⏺ [{len(_MACRO_BUFFER)}] {stripped}{C.RESET}")
        return True, ""          # pochłonięto

    # Skrót @nazwa [args]
    if stripped.startswith("@") and len(stripped) > 1:
        parts    = stripped[1:].split()
        mac_name = parts[0]
        mac_args = parts[1:]
        m = _MACROS.get(mac_name)
        if m:
            _macro_run(m, mac_args)
            return True, ""
        # Jeśli nie znaleziono — nie przechwytuj (może to @dekorator w kodzie?)

    return False, line

# Inicjalizacja
try:
    _macro_load()
except Exception:  # ignorowane celowo
    pass

# MODULE: WATCHER — Automatyczne wykonywanie zadań po wykryciu zdarzeń
# Wersja v23.0

#
# Obsługiwane zdarzenia:
#   file:changed  <ścieżka|glob>     — zmiana pliku (mtime / rozmiar)
#   file:created  <ścieżka|glob>     — pojawienie się nowego pliku
#   file:deleted  <ścieżka|glob>     — zniknięcie pliku
#   dir:changed   <katalog>          — jakakolwiek zmiana w katalogu
#   disk:mounted  [etykieta|glob]    — podłączenie dysku/wolumenu (Linux/Mac/Win)
#   disk:removed  [etykieta|glob]    — odłączenie dysku/wolumenu
#   process:start <nazwa_procesu>    — pojawienie się procesu w ps
#   process:stop  <nazwa_procesu>    — zniknięcie procesu z ps
#   net:up        [iface]            — pojawienie się interfejsu sieciowego
#   net:down      [iface]            — zniknięcie interfejsu sieciowego
#
# Komendy:
#   watch add <zdarzenie> <target> <komenda>  — dodaj regułę
#   watch list                                — lista reguł
#   watch info <id>                           — szczegóły reguły
#   watch enable <id>                         — włącz regułę
#   watch disable <id>                        — wyłącz regułę
#   watch remove <id>                         — usuń regułę
#   watch test <id>                           — wymuś sprawdzenie i uruchomienie
#   watch log [id]                            — log zdarzeń
#   watch start                               — uruchom wątek watchera
#   watch stop                                — zatrzymaj wątek
#   watch status                              — stan watchera

WATCH_FILE    = _BASE / ".terminalx_watch.json"
WATCH_LOG     = _BASE / ".terminalx_watch_log.txt"
_WATCH_MAX_LOG = 500
_WATCH_TICK    = 2.0      # sekund — dokładność pollingu

_WATCH_RULES:  dict = {}      # id → _WatchRule
_WATCH_LOCK  = _threading.Lock()
_WATCH_THREAD: "_threading.Thread | None" = _STATE.watch_thread
_WATCH_RUNNING = _STATE.watch_running
_WATCH_COUNTER: int = _STATE.watch_counter

# Typy zdarzeń
_WATCH_EVENT_TYPES = (
    "file:changed", "file:created", "file:deleted",
    "dir:changed",
    "disk:mounted", "disk:removed",
    "process:start", "process:stop",
    "net:up", "net:down",
)

class _WatchRule:
    """Pojedyncza reguła watchera."""

    def __init__(self, rid: str, event: str, target: str, command: str):
        self.id       = rid
        self.event    = event     # np. "file:changed"
        self.target   = target    # np. "/tmp/test.log" lub "*.py"
        self.command  = command
        self.enabled  = True
        self.created  = datetime.datetime.now().isoformat(timespec="seconds")
        self.last_fire: str = ""
        self.fire_count: int = 0
        self.last_exit: "int | None" = None
        # Stan wewnętrzny (niepersystowany między restartami)
        self._state: dict = {}    # np. {"mtime": ..., "size": ..., "exists": ...}

    def to_dict(self) -> dict:
        return {
            "id":         self.id,
            "event":      self.event,
            "target":     self.target,
            "command":    self.command,
            "enabled":    self.enabled,
            "created":    self.created,
            "last_fire":  self.last_fire,
            "fire_count": self.fire_count,
            "last_exit":  self.last_exit,
        }

    @classmethod
    def from_dict(cls, d: dict) -> "_WatchRule":
        r = cls(d["id"], d["event"], d["target"], d["command"])
        r.enabled    = d.get("enabled", True)
        r.created    = d.get("created", "")
        r.last_fire  = d.get("last_fire", "")
        r.fire_count = d.get("fire_count", 0)
        r.last_exit  = d.get("last_exit", None)
        return r

# ── Persystencja ──────────────────────────────────────────────────────────────

def _watch_save():
    try:
        data = {
            "counter": _WATCH_COUNTER,
            "rules":   {rid: r.to_dict() for rid, r in _WATCH_RULES.items()},
        }
        WATCH_FILE.write_text(
            json.dumps(data, indent=2, ensure_ascii=False), encoding="utf-8"
        )
    except Exception:  # ignorowane celowo
        pass

def _watch_load():
    if not WATCH_FILE.exists():
        return
    try:
        data = json.loads(WATCH_FILE.read_text(encoding="utf-8"))
        _STATE.watch_counter = data.get("counter", 0)
        for rid, rd in data.get("rules", {}).items():
            _WATCH_RULES[rid] = _WatchRule.from_dict(rd)
    except Exception:  # ignorowane celowo
        pass

# ── Log ───────────────────────────────────────────────────────────────────────

def _watch_log_write(rid: str, event: str, target: str, cmd: str,
                     exit_code: int, note: str = ""):
    try:
        ts    = datetime.datetime.now().strftime("%Y-%m-%d %H:%M:%S")
        ok    = "OK" if exit_code == 0 else f"ERR({exit_code})"
        extra = f"  [{note}]" if note else ""
        line  = f"{ts}  [{rid}]  {event:<16}  {ok}  {cmd[:50]}{extra}\n"
        with open(WATCH_LOG, "a", encoding="utf-8") as fh:
            fh.write(line)
        # Rotacja
        lines = WATCH_LOG.read_text(encoding="utf-8").splitlines(keepends=True)
        if len(lines) > _WATCH_MAX_LOG:
            WATCH_LOG.write_text("".join(lines[-_WATCH_MAX_LOG:]), encoding="utf-8")
    except Exception:  # ignorowane celowo
        pass

# ── Detekcja stanu systemu ────────────────────────────────────────────────────

def _watch_get_file_state(path_glob: str) -> dict:
    """Pobiera stan pliku/glob: {exists, mtime, size}."""
    from glob import glob as _glob
    matches = _glob(path_glob, recursive=True)
    if not matches:
        return {"exists": False, "mtime": 0.0, "size": 0}
    # Suma mtime i size wszystkich pasujących plików
    total_mtime = 0.0
    total_size  = 0
    for p in matches:
        try:
            st = os.stat(p)
            total_mtime = max(total_mtime, st.st_mtime)
            total_size += st.st_size
        except OSError:
            pass
    return {"exists": True, "mtime": total_mtime, "size": total_size}

def _watch_get_dir_state(dirpath: str) -> dict:
    """Stan katalogu: lista plików + sumaryczny mtime."""
    try:
        entries = sorted(os.listdir(dirpath))
        total_m = 0.0
        for e in entries:
            try:
                total_m = max(total_m, os.stat(os.path.join(dirpath, e)).st_mtime)
            except OSError:
                pass
        return {"entries": entries, "mtime": total_m}
    except OSError:
        return {"entries": [], "mtime": 0.0}

def _watch_get_disks() -> set:
    """Zwraca zbiór identyfikatorów podłączonych dysków/wolumenów."""
    disks: set = set()
    if sys.platform == "win32":
        import string
        for letter in string.ascii_uppercase:
            if os.path.exists(f"{letter}:\\"):
                disks.add(f"{letter}:")
    elif sys.platform == "darwin":
        try:
            vol = Path("/Volumes")
            disks = {p.name for p in vol.iterdir() if p.is_dir()}
        except Exception:  # ignorowane celowo
            pass
    else:
        # Linux: /proc/mounts
        try:
            mounts = Path("/proc/mounts").read_text().splitlines()
            for line in mounts:
                parts = line.split()
                if len(parts) >= 2:
                    disks.add(parts[1])   # mount point
        except Exception:  # ignorowane celowo
            pass
    return disks

def _watch_get_processes() -> set:
    """Zwraca zbiór nazw aktywnych procesów."""
    procs: set = set()
    try:
        if sys.platform == "win32":
            r = subprocess.run(
                ["tasklist", "/fo", "csv", "/nh"],
                capture_output=True, text=True, timeout=3
            )
            for line in r.stdout.splitlines():
                name = line.strip('"').split('"')[0]
                if name:
                    procs.add(name.lower())
        else:
            r = subprocess.run(
                ["ps", "-e", "-o", "comm="],
                capture_output=True, text=True, timeout=3
            )
            for line in r.stdout.splitlines():
                n = line.strip()
                if n:
                    procs.add(n.lower())
    except Exception:  # ignorowane celowo
        pass
    return procs

def _watch_get_net_ifaces() -> set:
    """Zwraca zbiór aktywnych interfejsów sieciowych."""
    ifaces: set = set()
    try:
        if sys.platform == "win32":
            r = subprocess.run(
                ["netsh", "interface", "show", "interface"],
                capture_output=True, text=True, timeout=3
            )
            for line in r.stdout.splitlines():
                parts = line.split()
                if len(parts) >= 4 and parts[0].lower() in ("enabled", "connected"):
                    ifaces.add(parts[-1].lower())
        else:
            net_dir = Path("/sys/class/net")
            if net_dir.exists():
                for iface in net_dir.iterdir():
                    try:
                        state = (iface / "operstate").read_text().strip()
                        if state == "up":
                            ifaces.add(iface.name)
                    except OSError:
                        pass
    except Exception:  # ignorowane celowo
        pass
    return ifaces

# ── Sprawdzanie reguły ────────────────────────────────────────────────────────

def _watch_check_rule(r: "_WatchRule") -> "str | None":
    """
    Sprawdza czy reguła powinna zostać wyzwolona.
    Zwraca opis zdarzenia lub None.
    Aktualizuje r._state.
    """
    ev = r.event
    tg = r.target

    # ── file:changed ──────────────────────────────────────────────────────
    if ev == "file:changed":
        new  = _watch_get_file_state(tg)
        old  = r._state
        r._state = new
        if not old:    # pierwsza iteracja — zainicjuj
            return None
        if new["exists"] and old.get("exists"):
            if new["mtime"] != old.get("mtime") or new["size"] != old.get("size"):
                return f"plik zmieniony: {tg}"
        return None

    # ── file:created ──────────────────────────────────────────────────────
    if ev == "file:created":
        new  = _watch_get_file_state(tg)
        old  = r._state
        r._state = new
        if not old:
            return None
        if new["exists"] and not old.get("exists"):
            return f"plik pojawił się: {tg}"
        return None

    # ── file:deleted ──────────────────────────────────────────────────────
    if ev == "file:deleted":
        new  = _watch_get_file_state(tg)
        old  = r._state
        r._state = new
        if not old:
            return None
        if not new["exists"] and old.get("exists"):
            return f"plik zniknął: {tg}"
        return None

    # ── dir:changed ───────────────────────────────────────────────────────
    if ev == "dir:changed":
        new  = _watch_get_dir_state(tg)
        old  = r._state
        r._state = new
        if not old:
            return None
        if new["mtime"] != old.get("mtime") or new["entries"] != old.get("entries"):
            return f"katalog zmieniony: {tg}"
        return None

    # ── disk:mounted ──────────────────────────────────────────────────────
    if ev == "disk:mounted":
        new  = _watch_get_disks()
        old  = set(r._state.get("disks", []))
        r._state = {"disks": list(new)}
        if not r._state and not old:
            return None
        added = new - old
        if added:
            # Filtruj wg targetu (glob lub pusta = wszystkie)
            if tg and tg != "*":
                added = {d for d in added if fnmatch.fnmatch(d, tg)}
            if added:
                return f"dysk podłączony: {', '.join(sorted(added))}"
        return None

    # ── disk:removed ──────────────────────────────────────────────────────
    if ev == "disk:removed":
        new  = _watch_get_disks()
        old  = set(r._state.get("disks", []))
        r._state = {"disks": list(new)}
        removed = old - new
        if removed:
            if tg and tg != "*":
                removed = {d for d in removed if fnmatch.fnmatch(d, tg)}
            if removed:
                return f"dysk odłączony: {', '.join(sorted(removed))}"
        return None

    # ── process:start ─────────────────────────────────────────────────────
    if ev == "process:start":
        new  = _watch_get_processes()
        old  = set(r._state.get("procs", []))
        r._state = {"procs": list(new)}
        if not old:
            return None
        started = new - old
        match   = {p for p in started if fnmatch.fnmatch(p, tg.lower())}
        if match:
            return f"proces uruchomiony: {', '.join(sorted(match))}"
        return None

    # ── process:stop ──────────────────────────────────────────────────────
    if ev == "process:stop":
        new  = _watch_get_processes()
        old  = set(r._state.get("procs", []))
        r._state = {"procs": list(new)}
        if not old:
            return None
        stopped = old - new
        match   = {p for p in stopped if fnmatch.fnmatch(p, tg.lower())}
        if match:
            return f"proces zakończony: {', '.join(sorted(match))}"
        return None

    # ── net:up ────────────────────────────────────────────────────────────
    if ev == "net:up":
        new  = _watch_get_net_ifaces()
        old  = set(r._state.get("ifaces", []))
        r._state = {"ifaces": list(new)}
        if not old:
            return None
        added = new - old
        if tg and tg != "*":
            added = {i for i in added if fnmatch.fnmatch(i, tg.lower())}
        if added:
            return f"interfejs pojawił się: {', '.join(sorted(added))}"
        return None

    # ── net:down ──────────────────────────────────────────────────────────
    if ev == "net:down":
        new  = _watch_get_net_ifaces()
        old  = set(r._state.get("ifaces", []))
        r._state = {"ifaces": list(new)}
        if not old:
            return None
        removed = old - new
        if tg and tg != "*":
            removed = {i for i in removed if fnmatch.fnmatch(i, tg.lower())}
        if removed:
            return f"interfejs zniknął: {', '.join(sorted(removed))}"
        return None

    return None

# ── Wyzwolenie reguły ─────────────────────────────────────────────────────────

def _watch_fire(r: "_WatchRule", trigger_desc: str):
    """Wykonuje komendę powiązaną z regułą."""
    # Podstaw $EVENT i $TARGET w komendzie
    cmd = r.command.replace("$EVENT",  r.event).replace("$TARGET", r.target)
    ret = 0
    try:
        ret = execute_line(cmd)
        if ret is None:
            ret = 0
    except Exception as e:
        ret = 1
        _watch_log_write(r.id, r.event, r.target, cmd, 1, note=str(e)[:60])
        return

    r.last_fire  = datetime.datetime.now().isoformat(timespec="seconds")
    r.fire_count += 1
    r.last_exit  = ret
    _watch_log_write(r.id, r.event, r.target, cmd, ret, note=trigger_desc[:40])
    _watch_save()

# ── Wątek watchera ────────────────────────────────────────────────────────────

def _watch_worker():
    _log("INFO", "Watcher: wątek uruchomiony.")
    # Inicjalizacja stanu reguł
    with _WATCH_LOCK:
        for r in _WATCH_RULES.values():
            if r.enabled:
                _watch_check_rule(r)   # pierwsze wywołanie = zainicjuj _state

    while _WATCH_RUNNING:
        _time.sleep(_WATCH_TICK)
        with _WATCH_LOCK:
            active = [(rid, r) for rid, r in _WATCH_RULES.items() if r.enabled]
        for rid, r in active:
            try:
                trigger = _watch_check_rule(r)
                if trigger:
                    _watch_fire(r, trigger)
            except Exception as e:
                _watch_log_write(rid, r.event, r.target, r.command, -1,
                                 note=f"wyjątek: {e}")
    _log("INFO", "Watcher: wątek zatrzymany.")

def _watch_start():
    if _WATCH_RUNNING and _WATCH_THREAD and _WATCH_THREAD.is_alive():
        return
    _STATE.watch_running = True
    _STATE.watch_thread = _threading.Thread(
        target=_watch_worker,
        name="TerminalX-watch",
        daemon=True
    )
    _WATCH_THREAD.start()

def _watch_stop():
    _STATE.watch_running = False

# ── Komenda: watch ────────────────────────────────────────────────────────────

@command("watch", "Automatyczne zadania wyzwalane zdarzeniami systemowymi",
         aliases=["watcher", "on"],
         flags=["add","list","info","enable","disable","remove","test",
                "log","start","stop","status","events"])
def cmd_watch(args):
    """
    watch add <zdarzenie> <target> <komenda>  — dodaj regułę
    watch list                                — lista reguł
    watch info <id>                           — szczegóły reguły
    watch enable <id>                         — włącz
    watch disable <id>                        — wyłącz
    watch remove <id>                         — usuń regułę
    watch test <id>                           — wymuś sprawdzenie
    watch log [id]                            — log wyzwoleń
    watch start | stop | status               — sterowanie wątkiem
    watch events                              — lista dostępnych zdarzeń

    Zdarzenia:
      file:changed  <ścieżka|glob>   — zmiana pliku (mtime/rozmiar)
      file:created  <ścieżka|glob>   — pojawienie się pliku
      file:deleted  <ścieżka|glob>   — zniknięcie pliku
      dir:changed   <katalog>        — zmiana w katalogu
      disk:mounted  [glob|*]         — podłączenie dysku/wolumenu
      disk:removed  [glob|*]         — odłączenie dysku
      process:start <nazwa|glob>     — uruchomienie procesu
      process:stop  <nazwa|glob>     — zakończenie procesu
      net:up        [iface|*]        — pojawienie się interfejsu
      net:down      [iface|*]        — zniknięcie interfejsu

    W komendzie dostępne: $EVENT (typ zdarzenia), $TARGET (obserwowany cel)

    Przykłady:
      watch add file:changed /etc/hosts echo "hosts zmieniony!"
      watch add disk:mounted * echo "Dysk podłączony: $TARGET"
      watch add file:created /tmp/*.log macro run process_log
      watch add process:start chrome echo "Chrome uruchomiony"
    """

    sub = args[0] if args else "list"

    # ── events ────────────────────────────────────────────────────────────
    if sub == "events":
        w = min(terminal_width() - 2, 72)
        print()
        print(box_top("Dostępne typy zdarzeń — watcher", width=w, color=C.INFO))
        ev_info = [
            ("file:changed",  "<ścieżka|glob>", "Zmiana pliku (mtime lub rozmiar)"),
            ("file:created",  "<ścieżka|glob>", "Pojawienie się nowego pliku"),
            ("file:deleted",  "<ścieżka|glob>", "Zniknięcie pliku"),
            ("dir:changed",   "<katalog>",       "Dowolna zmiana w katalogu"),
            ("disk:mounted",  "[glob|*]",         "Podłączenie dysku/wolumenu"),
            ("disk:removed",  "[glob|*]",         "Odłączenie dysku/wolumenu"),
            ("process:start", "<nazwa|glob>",    "Uruchomienie procesu"),
            ("process:stop",  "<nazwa|glob>",    "Zakończenie procesu"),
            ("net:up",        "[iface|*]",        "Pojawienie się interfejsu siec."),
            ("net:down",      "[iface|*]",        "Zniknięcie interfejsu siec."),
        ]
        for ev, tg, desc in ev_info:
            print(box_row(
                f"  {C.PATH}{ev:<18}{C.RESET} {C.DIM}{tg:<16}{C.RESET} {desc}",
                width=w, color=C.INFO))
        print(box_sep(width=w, color=C.INFO))
        print(box_row(
            f"  {C.DIM}W komendzie: $EVENT (zdarzenie)  $TARGET (cel){C.RESET}",
            width=w, color=C.INFO))
        print(box_bottom(width=w, color=C.INFO))
        print()
        return

    # ── add ───────────────────────────────────────────────────────────────
    if sub == "add":
        if len(args) < 4:
            print_error("Użycie: watch add <zdarzenie> <target> <komenda>",
                        "Przykład: watch add file:changed /tmp/test.log echo zmieniono")
            return
        event   = args[1].lower()
        target  = args[2]
        command = " ".join(args[3:])
        if event not in _WATCH_EVENT_TYPES:
            print_error(f"Nieznane zdarzenie: '{event}'.",
                        f"Dostępne: {', '.join(_WATCH_EVENT_TYPES)}")
            return
        _STATE.watch_counter += 1
        rid = str(_WATCH_COUNTER)
        r   = _WatchRule(rid, event, target, command)
        with _WATCH_LOCK:
            _WATCH_RULES[rid] = r
        # Zainicjuj stan
        _watch_check_rule(r)
        _watch_save()
        print_info(f"Reguła [{rid}] dodana: {C.BOLD}{event}{C.RESET} "
                   f"→ {target}  ⇒  {command}")
        if not _WATCH_RUNNING:
            _watch_start()
            print(f"  {C.DIM}Watcher automatycznie uruchomiony (tick co {_WATCH_TICK}s).{C.RESET}")
        return

    # ── list ──────────────────────────────────────────────────────────────
    if sub in ("list", "ls", "l", ""):
        w = min(terminal_width() - 2, 78)
        alive = _WATCH_THREAD is not None and _WATCH_THREAD.is_alive()
        run_s = f"{C.PATH}działa ✔{C.RESET}" if alive else f"{C.DIM}zatrzymany{C.RESET}"
        print()
        print(box_top(f"Watcher zdarzeń — {run_s}", width=w, color=C.INFO))
        if not _WATCH_RULES:
            print(box_row(
                f"  {C.DIM}Brak reguł. Dodaj: watch add <zdarzenie> <target> <cmd>{C.RESET}",
                width=w, color=C.INFO))
        else:
            for rid, r in _WATCH_RULES.items():
                st   = f"{C.PATH}✔{C.RESET}" if r.enabled else f"{C.ERROR}✖{C.RESET}"
                row1 = (f"  {st} {C.BOLD}[{rid}]{C.RESET}  "
                        f"{C.PATH}{r.event}{C.RESET}  →  {C.DIM}{r.target}{C.RESET}")
                row2 = f"      ⇒  {r.command[:60]}"
                row3 = (f"      {C.DIM}Wyzwoleń: {r.fire_count}  |  "
                        f"Ostatnie: {r.last_fire or '—'}{C.RESET}")
                print(box_row(row1, width=w, color=C.INFO))
                print(box_row(row2, width=w, color=C.INFO))
                print(box_row(row3, width=w, color=C.INFO))
                print(box_sep(width=w, color=C.INFO))
        print(box_row(
            f"  {C.DIM}watch add | watch events | watch log | watch status{C.RESET}",
            width=w, color=C.INFO))
        print(box_bottom(width=w, color=C.INFO))
        print()
        return

    # ── info ──────────────────────────────────────────────────────────────
    if sub == "info":
        if len(args) < 2:
            print_error("Podaj ID: watch info <id>"); return
        r = _WATCH_RULES.get(args[1])
        if not r:
            print_error(f"Reguła '{args[1]}' nie istnieje."); return
        w = min(terminal_width() - 2, 64)
        print()
        print(box_top(f"Reguła [{r.id}] {r.event}", width=w, color=C.PATH))
        rows = [
            ("ID",         r.id),
            ("Zdarzenie",  r.event),
            ("Target",     r.target),
            ("Komenda",    r.command),
            ("Status",     "włączona" if r.enabled else "wyłączona"),
            ("Wyzwoleń",   str(r.fire_count)),
            ("Ostatnie",   r.last_fire or "—"),
            ("Exit",       str(r.last_exit) if r.last_exit is not None else "—"),
            ("Tick",       f"{_WATCH_TICK}s"),
            ("Utworzona",  r.created),
        ]
        for k, v in rows:
            print(box_row(kv_row(f"  {k}", v, key_w=12), width=w, color=C.PATH))
        print(box_bottom(width=w, color=C.PATH))
        print()
        return

    # ── enable ────────────────────────────────────────────────────────────
    if sub == "enable":
        if len(args) < 2:
            print_error("Podaj ID: watch enable <id>"); return
        r = _WATCH_RULES.get(args[1])
        if not r:
            print_error(f"Reguła '{args[1]}' nie istnieje."); return
        r.enabled = True
        _watch_check_rule(r)   # re-inicjalizuj stan
        _watch_save()
        print_info(f"Reguła [{r.id}] włączona.")
        return

    # ── disable ───────────────────────────────────────────────────────────
    if sub == "disable":
        if len(args) < 2:
            print_error("Podaj ID: watch disable <id>"); return
        r = _WATCH_RULES.get(args[1])
        if not r:
            print_error(f"Reguła '{args[1]}' nie istnieje."); return
        r.enabled = False
        _watch_save()
        print_info(f"Reguła [{r.id}] wyłączona.")
        return

    # ── remove ────────────────────────────────────────────────────────────
    if sub in ("remove", "rm", "del", "delete"):
        if len(args) < 2:
            print_error("Podaj ID: watch remove <id>"); return
        r = _WATCH_RULES.get(args[1])
        if not r:
            print_error(f"Reguła '{args[1]}' nie istnieje."); return
        try:
            ans = input(f"  {C.ERROR}Usunąć regułę [{r.id}] '{r.event} → {r.target}'? [t/n]: {C.RESET}").strip().lower()
        except (EOFError, KeyboardInterrupt):
            return
        if ans in ("t", "y", "tak", "yes"):
            with _WATCH_LOCK:
                del _WATCH_RULES[args[1]]
            _watch_save()
            print_info(f"Reguła [{r.id}] usunięta.")
        return

    # ── test ──────────────────────────────────────────────────────────────
    if sub == "test":
        if len(args) < 2:
            print_error("Podaj ID: watch test <id>"); return
        r = _WATCH_RULES.get(args[1])
        if not r:
            print_error(f"Reguła '{args[1]}' nie istnieje."); return
        print_info(f"Wymuszam wyzwolenie reguły [{r.id}]: {r.event} → {r.target}")
        _watch_fire(r, trigger_desc="manual test")
        return

    # ── log ───────────────────────────────────────────────────────────────
    if sub == "log":
        if not WATCH_LOG.exists():
            print_info("Brak logu wyzwoleń."); return
        filter_id = args[1] if len(args) >= 2 else ""
        lines = WATCH_LOG.read_text(encoding="utf-8", errors="replace").splitlines()
        if filter_id:
            lines = [l for l in lines if f"[{filter_id}]" in l]
        if not lines:
            print_info(f"Brak wpisów{' dla reguły ' + filter_id if filter_id else ''}."); return
        w = min(terminal_width() - 2, 80)
        print()
        print(box_top(f"Log watchera{' [' + filter_id + ']' if filter_id else ''}",
                      width=w, color=C.DIM))
        for ln in lines[-40:]:
            if "  OK  " in ln:
                colored = ln.replace("  OK  ", f"  {C.PATH}OK{C.RESET}  ")
            elif "  ERR" in ln:
                colored = ln.replace("  ERR", f"  {C.ERROR}ERR")
                colored += C.RESET
            else:
                colored = f"{C.DIM}{ln}{C.RESET}"
            print(box_row(f"  {colored}", width=w, color=C.DIM))
        print(box_bottom(width=w, color=C.DIM))
        print()
        return

    # ── start ─────────────────────────────────────────────────────────────
    if sub == "start":
        if _WATCH_RUNNING and _WATCH_THREAD and _WATCH_THREAD.is_alive():
            print_info("Watcher już działa."); return
        _watch_start()
        print_info(f"Watcher uruchomiony (tick co {_WATCH_TICK}s).")
        return

    # ── stop ──────────────────────────────────────────────────────────────
    if sub == "stop":
        _watch_stop()
        print_info("Watcher zatrzymany.")
        return

    # ── status ────────────────────────────────────────────────────────────
    if sub == "status":
        alive   = _WATCH_THREAD is not None and _WATCH_THREAD.is_alive()
        total   = len(_WATCH_RULES)
        enabled = sum(1 for r in _WATCH_RULES.values() if r.enabled)
        w = min(terminal_width() - 2, 56)
        print()
        print(box_top("Stan watchera", width=w, color=C.INFO))
        st_str = f"{C.PATH}✔ działa{C.RESET}" if alive else f"{C.ERROR}✖ zatrzymany{C.RESET}"
        rows = [
            ("Wątek",    st_str),
            ("Tick",     f"co {_WATCH_TICK}s"),
            ("Reguły",   f"{total} (włączone: {enabled})"),
            ("Zdarzenia",str(len(_WATCH_EVENT_TYPES))),
            ("Plik",     str(WATCH_FILE)),
        ]
        for k, v in rows:
            print(box_row(kv_row(f"  {k}", v, key_w=12), width=w, color=C.INFO))
        print(box_bottom(width=w, color=C.INFO))
        print()
        return

    print_error(f"Nieznana podkomenda: watch {sub}",
                "Dostępne: add list info enable disable remove test log start stop status events")

# ── Inicjalizacja watchera ────────────────────────────────────────────────────

def _watch_init():
    _watch_load()
    if _WATCH_RULES:
        _watch_start()

try:
    _watch_init()
except Exception:  # ignorowane celowo
    pass

# MODULE: RECOVERY — Tryb awaryjny / minimalny tryb działania
# Wersja v24.0

#
# Tryb awaryjny uruchamia się automatycznie gdy:
#   - Wykryto >= _RECOVERY_CRASH_THRESHOLD błędów w krótkim czasie
#   - Użytkownik wywołał: recovery  lub  safe  lub  uruchomił z flagą --safe
#   - Krytyczny moduł nie załadował się (config, pluginy, historia)
#   - Użytkownik wywołał: recovery enter
#
# W trybie awaryjnym:
#   - Wyłączone: pluginy, aliasy, RC, historia, scheduler, watcher, sesje
#   - Wyłączone: kolorowanie, banner, statusbar, autouzupełnianie
#   - Dostępny uproszczony zestaw komend bezpieczeństwa
#   - Prompt "[SAFE]" wyraźnie sygnalizuje tryb
#   - Możliwość: diagnostyki, naprawy konfiguracji, przywrócenia kopii
#
# Komendy dostępne zawsze (nawet w trybie awaryjnym):
#   recovery status          — czy tryb awaryjny jest aktywny i dlaczego
#   recovery enter           — ręczne wejście w tryb awaryjny
#   recovery exit            — wyjście z trybu awaryjnego (restart normalny)
#   recovery diagnose        — diagnostyka plików, środowiska i terminala
#   recovery fix config      — inteligentna naprawa konfiguracji (JSON repair + domyślne)
#   recovery fix aliases     — wyczyść plik aliasów
#   recovery fix history     — wyczyść historię komend
#   recovery fix plugins     — wyłącz wszystkie pluginy
#   recovery fix all         — reset wszystkiego do stanu fabrycznego
#   recovery backup create   — utwórz kopię zapasową danych użytkownika
#   recovery backup list     — lista kopii zapasowych
#   recovery backup restore <id>  — przywróć kopię zapasową
#   recovery log             — ostatnie błędy krytyczne z crashloga
#   recovery health          — szybki test zdrowia shella

_RECOVERY_ACTIVE      = _STATE.recovery_active
_RECOVERY_REASON: str = _STATE.recovery_reason
_RECOVERY_TRIGGERS: list[str] = []    # lista zdarzeń które spowodowały tryb awaryjny

# Próg błędów w oknie czasowym → automatyczny tryb awaryjny
_RECOVERY_CRASH_THRESHOLD = 3         # tyle błędów...
_RECOVERY_CRASH_WINDOW    = 60.0      # ...w ciągu tylu sekund
_RECOVERY_CRASH_TIMES:   list[float] = []  # timestamp-y ostatnich błędów

# Katalog kopii zapasowych
RECOVERY_BACKUP_DIR = _BASE / ".terminalx_backups"

# Minimalne komendy dostępne w trybie awaryjnym (poza modułem recovery)
_RECOVERY_SAFE_COMMANDS = {
    "help", "exit", "quit",
    "pwd", "ls", "cd", "cat", "echo",
    "cp", "mv", "rm", "mkdir",
    "recovery", "safe",
    "crashlog", "diag",
    "config", "version", "about",
}

# ── Wejście / wyjście z trybu awaryjnego ──────────────────────────────────────

def recovery_enter(reason: str = "ręczne", trigger: str = ""):
    """Przełącza shell w tryb awaryjny."""
    _STATE.recovery_active = True
    _STATE.recovery_reason = reason
    if trigger:
        _RECOVERY_TRIGGERS.append(
            f"{datetime.datetime.now().strftime('%H:%M:%S')}  {trigger}"
        )
    _log("INFO", f"Tryb awaryjny: {reason}")

def recovery_exit():
    """Wyłącza tryb awaryjny."""
    _STATE.recovery_active = False
    _STATE.recovery_reason = ""
    _log("INFO", "Wyjście z trybu awaryjnego.")

def recovery_record_crash(exc: "BaseException | None" = None, context: str = ""):
    """
    Rejestruje błąd. Jeśli w oknie _RECOVERY_CRASH_WINDOW pojawi się
    >= _RECOVERY_CRASH_THRESHOLD błędów — automatycznie włącza tryb awaryjny.
    """
    now = _time.time()
    _RECOVERY_CRASH_TIMES.append(now)
    # Wyrzuć stare wpisy poza oknem
    while _RECOVERY_CRASH_TIMES and (now - _RECOVERY_CRASH_TIMES[0]) > _RECOVERY_CRASH_WINDOW:
        _RECOVERY_CRASH_TIMES.pop(0)

    desc = f"{type(exc).__name__}: {str(exc)[:80]}" if exc else context
    if len(_RECOVERY_CRASH_TIMES) >= _RECOVERY_CRASH_THRESHOLD and not _RECOVERY_ACTIVE:
        recovery_enter(
            reason=f"auto: {len(_RECOVERY_CRASH_TIMES)} błędów / {_RECOVERY_CRASH_WINDOW:.0f}s",
            trigger=desc
        )
        # Wyraźne ostrzeżenie w terminalu
        print(f"\n  {C.ERROR}{'━'*60}{C.RESET}")
        print(f"  {C.ERROR}⚠  TRYB AWARYJNY AKTYWNY{C.RESET}")
        print(f"  {C.DIM}Wykryto {len(_RECOVERY_CRASH_TIMES)} błędów w ciągu "
              f"{_RECOVERY_CRASH_WINDOW:.0f}s.{C.RESET}")
        print(f"  {C.DIM}Ostatni błąd: {desc[:60]}{C.RESET}")
        print(f"  {C.DIM}Dostępne komendy: recovery diagnose | recovery fix all{C.RESET}")
        print(f"  {C.ERROR}{'━'*60}{C.RESET}\n")
    elif exc:
        _RECOVERY_TRIGGERS.append(
            f"{datetime.datetime.now().strftime('%H:%M:%S')}  {desc}"
        )

def recovery_is_active() -> bool:
    return _RECOVERY_ACTIVE

def recovery_prompt() -> str:
    """Zwraca prompt dla trybu awaryjnego."""
    cwd = Path.cwd().name or "/"
    return f"\001{C.ERROR}\002[SAFE:{cwd}]\001{C.RESET}\002 # "

def recovery_check_command(name: str) -> bool:
    """
    Sprawdza czy komenda jest dozwolona w trybie awaryjnym.
    Zwraca True = wykonaj, False = zablokuj.
    """
    if not _RECOVERY_ACTIVE:
        return True
    return name in _RECOVERY_SAFE_COMMANDS

# ── Diagnostyka ───────────────────────────────────────────────────────────────

def _recovery_check_file(path: "Path", label: str, parse_fn=None) -> dict:
    """Sprawdza stan pliku konfiguracyjnego. Zwraca dict ze statusem."""
    if not path.exists():
        return {"ok": True, "label": label, "note": "nie istnieje (OK — zostanie stworzony)"}
    try:
        size = path.stat().st_size
        if size == 0:
            return {"ok": True, "label": label, "note": "pusty plik"}
        if parse_fn:
            text = path.read_text(encoding="utf-8", errors="replace")
            parse_fn(text)
        return {"ok": True, "label": label, "note": f"{size} B"}
    except Exception as e:
        return {"ok": False, "label": label, "note": str(e)[:80], "path": path}

def _recovery_diagnose_terminal() -> list[dict]:
    """
    Diagnostyka samego terminala — niezależna od plików konfiguracyjnych.
    Sprawdza: TTY, kodowanie, kolory ANSI, zmienne TERM/COLORTERM,
    szerokość/wysokość okna, stdin/stdout/stderr, curses, obsługę Unicode.
    Zwraca listę dicts {ok, label, note} — ten sam format co _recovery_diagnose().
    """
    results = []

    # ── 1. stdin / stdout / stderr — czy to prawdziwy TTY ─────────────────
    for fd, name in [(0, "stdin"), (1, "stdout"), (2, "stderr")]:
        try:
            is_tty = os.isatty(fd)
            results.append({
                "ok":    is_tty,
                "label": f"TTY ({name})",
                "note":  "✔ TTY" if is_tty else "⚠ nie-TTY (potok/plik) — kolory mogą nie działać",
            })
        except Exception as e:
            results.append({"ok": False, "label": f"TTY ({name})", "note": str(e)[:60]})

    # ── 2. Kodowanie stdout ────────────────────────────────────────────────
    try:
        enc = getattr(sys.stdout, "encoding", None) or "?"
        is_utf8 = enc.lower().replace("-", "") in ("utf8", "utf8bom")
        results.append({
            "ok":    is_utf8,
            "label": "Kodowanie stdout",
            "note":  f"{enc}" + ("" if is_utf8 else "  ⚠ zalecane UTF-8 (fix: PYTHONIOENCODING=utf-8)"),
        })
    except Exception as e:
        results.append({"ok": False, "label": "Kodowanie stdout", "note": str(e)[:60]})

    # ── 3. Kodowanie lokalnego systemu (locale) ────────────────────────────
    try:
        import locale
        loc_enc = locale.getpreferredencoding(False) or "?"
        ok_loc  = loc_enc.lower().replace("-", "") in ("utf8", "utf8bom", "utf8sig")
        results.append({
            "ok":    ok_loc,
            "label": "Locale (kodowanie)",
            "note":  f"{loc_enc}" + ("" if ok_loc else "  ⚠ zalecane UTF-8"),
        })
    except Exception as e:
        results.append({"ok": False, "label": "Locale (kodowanie)", "note": str(e)[:60]})

    # ── 4. Zmienna TERM ────────────────────────────────────────────────────
    term_var = os.environ.get("TERM", "")
    term_ok  = bool(term_var) and term_var not in ("dumb", "unknown")
    results.append({
        "ok":    term_ok,
        "label": "Zmienna TERM",
        "note":  (term_var if term_var else "(nieustawiona)")
                 + ("" if term_ok else "  ⚠ terminal może nie obsługiwać kolorów"),
    })

    # ── 5. COLORTERM — truecolor / 256 ────────────────────────────────────
    colorterm = os.environ.get("COLORTERM", "")
    results.append({
        "ok":    True,   # informacyjne
        "label": "COLORTERM (true color)",
        "note":  colorterm if colorterm else "(brak — prawdopodobnie 256-kolorów lub mniej)",
    })

    # ── 6. Obsługa kolorów ANSI (próba zapisu escape code) ────────────────
    try:
        ansi_ok = False
        if os.isatty(1):
            sys.stdout.write("\x1b[0m")
            sys.stdout.flush()
            ansi_ok = True
        results.append({
            "ok":    ansi_ok,
            "label": "Kolory ANSI",
            "note":  "✔ obsługiwane" if ansi_ok else "⚠ brak TTY — kolory niedostępne",
        })
    except Exception as e:
        results.append({"ok": False, "label": "Kolory ANSI", "note": str(e)[:60]})

    # ── 7. Rozmiar terminala ───────────────────────────────────────────────
    try:
        ts = shutil.get_terminal_size(fallback=(0, 0))
        w, h = ts.columns, ts.lines
        size_ok = w >= 40 and h >= 10
        results.append({
            "ok":    size_ok,
            "label": "Rozmiar terminala",
            "note":  f"{w}×{h}" + ("" if size_ok else "  ⚠ bardzo małe okno"),
        })
    except Exception as e:
        results.append({"ok": False, "label": "Rozmiar terminala", "note": str(e)[:60]})

    # ── 8. Curses — dostępność i inicjalizacja ────────────────────────────
    if CURSES_OK:
        try:
            import curses as _curses_test
            stdscr = _curses_test.initscr()
            _curses_test.endwin()
            scr_ok = stdscr is not None
            results.append({"ok": scr_ok, "label": "Curses init",
                            "note": "✔ inicjalizacja OK" if scr_ok else "✖ initscr zwróciło None"})
        except Exception as e:
            results.append({"ok": False, "label": "Curses init",
                            "note": f"⚠ błąd: {str(e)[:50]}"})
    else:
        results.append({"ok": False, "label": "Curses init",
                        "note": "niedostępny — nano-lite wyłączony"})

    # ── 9. Obsługa Unicode w terminalu ────────────────────────────────────
    try:
        probe   = "✔"
        encoded = probe.encode(sys.stdout.encoding or "utf-8", errors="replace")
        uni_ok  = b"?" not in encoded
        results.append({
            "ok":    uni_ok,
            "label": "Unicode (znaki UTF-8)",
            "note":  "✔ renderowane poprawnie" if uni_ok
                     else "⚠ kodowanie zastępcze — emoji/ramki mogą być ??",
        })
    except Exception as e:
        results.append({"ok": False, "label": "Unicode (znaki UTF-8)", "note": str(e)[:60]})

    # ── 10. PATH — podstawowe narzędzia systemowe ─────────────────────────
    missing_tools = [t for t in ("ls", "cat", "grep", "find") if not shutil.which(t)]
    results.append({
        "ok":    not missing_tools,
        "label": "PATH (narzędzia systemowe)",
        "note":  "✔ wszystkie dostępne" if not missing_tools
                 else f"⚠ brak: {', '.join(missing_tools)}",
    })

    return results

def _recovery_fix_config_smart() -> tuple[bool, str]:
    """
    Inteligentna naprawa pliku konfiguracyjnego JSON.
    Próby w kolejności:
      1. Parsowanie poprawne → uzupełnij brakujące klucze domyślnymi.
      2. Naprawa JSON (trailing commas, BOM).
      3. Ratunkowe wydobycie kluczy przez regex.
      4. Ostateczność: rename + odtworzenie domyślnego pliku.
    Zwraca (sukces, opis_akcji).
    """
    active = _active_config_file()

    # Przypadek 1 — plik nie istnieje → utwórz domyślny
    if not active.exists():
        try:
            active.write_text(
                json.dumps(_CONFIG_DEFAULTS, indent=2, ensure_ascii=False),
                encoding="utf-8"
            )
            return True, f"Brak pliku — utworzono domyślny: {active.name}"
        except Exception as e:
            return False, f"Nie można utworzyć pliku: {e}"

    # Przypadek 2 — plik istnieje i jest poprawny → uzupełnij brakujące klucze
    try:
        raw    = active.read_text(encoding="utf-8", errors="replace")
        parsed = json.loads(raw)
        missing = [k for k in _CONFIG_DEFAULTS if k not in parsed]
        if missing:
            merged = {**_CONFIG_DEFAULTS, **parsed}
            active.write_text(
                json.dumps(merged, indent=2, ensure_ascii=False),
                encoding="utf-8"
            )
            return True, f"Plik OK — uzupełniono {len(missing)} brakujących kluczy: {', '.join(missing[:5])}{'…' if len(missing) > 5 else ''}"
        return True, "Plik konfiguracyjny jest poprawny — nic do naprawy."
    except json.JSONDecodeError:
        pass  # przejdź do naprawy

    # Przypadek 3 — próba naprawy JSON ────────────────────────────────────
    try:
        raw = active.read_text(encoding="utf-8-sig", errors="replace")  # obsługa BOM

        # Próba 3a: usunięcie trailing commas przed } i ]
        fixed = re.sub(r",\s*([}\]])", r"\1", raw)
        try:
            parsed_fixed = json.loads(fixed)
            bak = active.with_suffix(active.suffix + ".repaired_bak")
            shutil.copy2(active, bak)
            merged = {**_CONFIG_DEFAULTS, **parsed_fixed}
            active.write_text(
                json.dumps(merged, indent=2, ensure_ascii=False),
                encoding="utf-8"
            )
            return True, f"Naprawiono trailing commas w JSON. Kopia oryginału: {bak.name}"
        except json.JSONDecodeError:
            pass

        # Próba 3b: ratunkowe wydobycie kluczy regex
        rescued: dict = {}
        for key, default_val in _CONFIG_DEFAULTS.items():
            if isinstance(default_val, bool):
                m = re.search(rf'"{re.escape(key)}"\s*:\s*(true|false)', raw)
                if m:
                    rescued[key] = m.group(1) == "true"
            elif isinstance(default_val, int):
                m = re.search(rf'"{re.escape(key)}"\s*:\s*(\d+)', raw)
                if m:
                    rescued[key] = int(m.group(1))
            elif isinstance(default_val, str):
                m = re.search(rf'"{re.escape(key)}"\s*:\s*"([^"]*)"', raw)
                if m:
                    rescued[key] = m.group(1)

        if rescued:
            bak = active.with_suffix(active.suffix + ".broken")
            shutil.copy2(active, bak)
            merged = {**_CONFIG_DEFAULTS, **rescued}
            active.write_text(
                json.dumps(merged, indent=2, ensure_ascii=False),
                encoding="utf-8"
            )
            return True, (f"Odratowano {len(rescued)}/{len(_CONFIG_DEFAULTS)} kluczy. "
                          f"Kopia oryginału: {bak.name}")
    except Exception as e:
        _log("ERROR", f"_recovery_fix_config_smart repair: {e}")

    # Przypadek 4 — ostateczność: rename + domyślna konfiguracja ──────────
    try:
        bak = active.with_suffix(active.suffix + ".broken")
        shutil.move(str(active), str(bak))
        active.write_text(
            json.dumps(_CONFIG_DEFAULTS, indent=2, ensure_ascii=False),
            encoding="utf-8"
        )
        return True, (f"Plik nienaprawialny → przeniesiony: {bak.name}. "
                      f"Utworzono domyślny: {active.name}")
    except Exception as e:
        return False, f"Nie można naprawić konfiguracji: {e}"

def _recovery_diagnose() -> list[dict]:
    """Zwraca listę wyników diagnostycznych (pliki + środowisko + terminal)."""
    results = []

    # Pliki konfiguracyjne
    results.append(_recovery_check_file(CONFIG_FILE,  "Konfiguracja",
        lambda t: json.loads(t) if t.strip() else None))
    results.append(_recovery_check_file(ALIASES_FILE, "Aliasy"))
    results.append(_recovery_check_file(HISTORY_FILE, "Historia"))
    results.append(_recovery_check_file(RC_FILE,      "Plik RC"))
    results.append(_recovery_check_file(SCHED_FILE,   "Scheduler",
        lambda t: json.loads(t)))
    results.append(_recovery_check_file(SESSION_FILE, "Sesje",
        lambda t: json.loads(t)))
    results.append(_recovery_check_file(MACRO_FILE,   "Makra",
        lambda t: json.loads(t)))
    results.append(_recovery_check_file(WATCH_FILE,   "Watcher",
        lambda t: json.loads(t)))
    results.append(_recovery_check_file(CRASHLOG_FILE,"Crashlog"))

    # Katalogi
    for dirpath, label in [
        (PLUGINS_DIR,  "Katalog pluginów"),
        (PKG_DIR,      "Katalog pakietów"),
        (RECOVERY_BACKUP_DIR, "Katalog kopii"),
    ]:
        try:
            exists = dirpath.exists()
            results.append({
                "ok":    True,
                "label": label,
                "note":  str(dirpath) + ("  ✔" if exists else "  (brak — zostanie stworzony)"),
            })
        except Exception as e:
            results.append({"ok": False, "label": label, "note": str(e)[:60]})

    # Python / curses / readline
    results.append({
        "ok":    True,
        "label": "Python",
        "note":  f"{sys.version.split()[0]}  {sys.platform}",
    })
    results.append({
        "ok":    CURSES_OK,
        "label": "Curses (nano-lite)",
        "note":  "dostępny" if CURSES_OK else "niedostępny (bez edytora)",
    })
    results.append({
        "ok":    readline is not None,
        "label": "Readline (TAB)",
        "note":  "dostępny" if readline else "niedostępny (bez autouzupełniania)",
    })

    # Błędy w crashlogu
    crash_count = 0
    try:
        if CRASHLOG_FILE.exists():
            text = CRASHLOG_FILE.read_text(encoding="utf-8", errors="replace")
            crash_count = text.count("TERMINALX CRASHLOG")
    except Exception:  # ignorowane celowo
        pass
    results.append({
        "ok":    crash_count < 5,
        "label": "Crashlog (wpisy)",
        "note":  f"{crash_count} błędów" + ("  ⚠ dużo błędów" if crash_count >= 5 else ""),
    })

    # ── Diagnostyka terminala (nowa sekcja) ────────────────────────────────
    results.append({"ok": True, "label": "─── Terminal ───", "note": ""})
    results.extend(_recovery_diagnose_terminal())

    return results

# ── Backup / Restore ──────────────────────────────────────────────────────────

_RECOVERY_BACKUP_FILES = [
    CONFIG_FILE, ALIASES_FILE, RC_FILE, SCHED_FILE,
    SESSION_FILE, MACRO_FILE, WATCH_FILE,
]

def _recovery_backup_create(label: str = "") -> "Path | None":
    """Tworzy kopię zapasową plików danych użytkownika."""
    try:
        RECOVERY_BACKUP_DIR.mkdir(parents=True, exist_ok=True)
        ts      = datetime.datetime.now().strftime("%Y%m%d_%H%M%S")
        slug    = re.sub(r"[^a-z0-9_]", "_", label.lower())[:20] if label else "manual"
        bak_dir = RECOVERY_BACKUP_DIR / f"{ts}_{slug}"
        bak_dir.mkdir(exist_ok=True)

        copied = []
        for src in _RECOVERY_BACKUP_FILES:
            if src.exists():
                dst = bak_dir / src.name
                shutil.copy2(src, dst)
                copied.append(src.name)

        # Metadata
        meta = {
            "created": datetime.datetime.now().isoformat(timespec="seconds"),
            "label":   label or "manual",
            "files":   copied,
            "version": SHELL_VERSION,
        }
        (bak_dir / "meta.json").write_text(
            json.dumps(meta, indent=2, ensure_ascii=False), encoding="utf-8"
        )
        return bak_dir
    except Exception as e:
        _log("ERROR", f"Backup nieudany: {e}")
        return None

def _recovery_backup_list() -> list[dict]:
    """Lista dostępnych kopii zapasowych."""
    backups = []
    if not RECOVERY_BACKUP_DIR.exists():
        return backups
    for entry in sorted(RECOVERY_BACKUP_DIR.iterdir(), reverse=True):
        if not entry.is_dir():
            continue
        meta_path = entry / "meta.json"
        try:
            meta = json.loads(meta_path.read_text(encoding="utf-8"))
        except Exception:
            meta = {"created": "?", "label": entry.name, "files": [], "version": "?"}
        meta["path"] = entry
        meta["id"]   = entry.name
        backups.append(meta)
    return backups

def _recovery_backup_restore(backup_id: str) -> "tuple[bool, str]":
    """Przywraca kopię zapasową. Zwraca (sukces, komunikat)."""
    bak_dir = RECOVERY_BACKUP_DIR / backup_id
    if not bak_dir.exists():
        return False, f"Kopia '{backup_id}' nie istnieje."
    try:
        # Przed przywróceniem — auto-backup obecnego stanu
        _recovery_backup_create(label="przed_restore")
        restored = []
        for src_file in bak_dir.iterdir():
            if src_file.name == "meta.json":
                continue
            dst = _BASE / src_file.name
            shutil.copy2(src_file, dst)
            restored.append(src_file.name)
        return True, f"Przywrócono {len(restored)} plików: {', '.join(restored)}"
    except Exception as e:
        return False, str(e)

# ── Naprawa komponentów ───────────────────────────────────────────────────────

def _recovery_fix_config():
    """
    Inteligentna naprawa konfiguracji — najpierw próbuje odratować dane,
    dopiero w ostateczności przenosi uszkodzony plik i tworzy domyślny.
    """
    ok, msg = _recovery_fix_config_smart()
    return msg

def _recovery_fix_aliases():
    if ALIASES_FILE.exists():
        bak = ALIASES_FILE.with_suffix(".broken")
        shutil.move(str(ALIASES_FILE), bak)
        return f"Plik aliasów przeniesiony → {bak.name}"
    return "Plik aliasów nie istnieje — pomijam."

def _recovery_fix_history():
    if HISTORY_FILE.exists():
        HISTORY_FILE.unlink()
        return "Historia komend usunięta."
    return "Brak pliku historii — pomijam."

def _recovery_fix_plugins():
    """Przenosi katalog pluginów — shell wystartuje bez nich."""
    if PLUGINS_DIR.exists():
        bak = PLUGINS_DIR.parent / (PLUGINS_DIR.name + "_disabled")
        if bak.exists():
            shutil.rmtree(bak)
        shutil.move(str(PLUGINS_DIR), bak)
        return f"Katalog pluginów przeniesiony → {bak.name}"
    return "Katalog pluginów nie istnieje — pomijam."

def _recovery_fix_all() -> list[str]:
    """Reset wszystkich komponentów do stanu fabrycznego."""
    # Najpierw kopia zapasowa
    bak = _recovery_backup_create(label="przed_fix_all")
    results = []
    if bak:
        results.append(f"✔ Kopia zapasowa: {bak.name}")
    results.append(_recovery_fix_config())
    results.append(_recovery_fix_aliases())
    results.append(_recovery_fix_history())
    results.append(_recovery_fix_plugins())
    for extra_file in [SCHED_FILE, SESSION_FILE, MACRO_FILE, WATCH_FILE, RC_FILE]:
        if extra_file.exists():
            bak_f = extra_file.with_suffix(extra_file.suffix + ".broken")
            shutil.move(str(extra_file), bak_f)
            results.append(f"Przeniesiono {extra_file.name} → {bak_f.name}")
    return results

# SELFCHECK — TESTY WEWNĘTRZNE I SELF-CHECK
#
#   selfcheck               — uruchom wszystkie testy wewnętrzne
#   selfcheck <kategoria>   — uruchom tylko wybraną kategorię
#   selfcheck list          — lista dostępnych kategorii
#   selfcheck --fast        — tylko testy <100ms (bez I/O)
#   selfcheck --fail-only   — pokaż tylko niezdane
#   selfcheck --json        — wynik w JSON (do automatyzacji)
#
#   Kategorie testów:
#     core      — parser, tokenizer, zmienne, pipe, aliasy
#     config    — wczytanie/zapis konfiguracji, domyślne wartości
#     fs        — operacje na plikach: touch/rm/mkdir/cp/mv
#     builtins  — komendy wbudowane: ls/cd/pwd/echo/cat/grep/find
#     plugins   — ładowanie pluginów, sandbox, rejestracja komend
#     encoding  — UTF-8, emoji, kolory ANSI, escape-kody
#     history   — zapis/wczytanie historii, deduplicacja
#     aliases   — tworzenie/usuwanie aliasów, rozwijanie
#     network   — detekcja online/offline, timeout
#     terminal  — TTY, rozmiar, curses, readline
#     crash     — zapis crashlogu, rotacja
#     perf      — pomiar czasu: tokenizer, ls, grep (benchmark)

import time as _time_mod

# ── Rejestry i typ wyniku ─────────────────────────────────────────────────────

class SelfCheckResult:
    """Wynik pojedynczego testu."""
    __slots__ = ("category", "name", "ok", "msg", "elapsed_ms", "skip")

    def __init__(self, category: str, name: str, ok: bool,
                 msg: str = "", elapsed_ms: float = 0.0, skip: bool = False):
        self.category   = category
        self.name       = name
        self.ok         = ok
        self.msg        = msg
        self.elapsed_ms = elapsed_ms
        self.skip       = skip

    def to_dict(self) -> dict:
        return {
            "category":   self.category,
            "name":       self.name,
            "ok":         self.ok,
            "msg":        self.msg,
            "elapsed_ms": round(self.elapsed_ms, 2),
            "skip":       self.skip,
        }

_SELFCHECK_REGISTRY: dict[str, list] = {}   # category → [test_fn, ...]

def _sc_register(category: str):
    """Dekorator rejestrujący funkcję testową w danej kategorii."""
    def _deco(fn):
        _SELFCHECK_REGISTRY.setdefault(category, []).append(fn)
        return fn
    return _deco

def selfcheck(category: str):
    return _sc_register(category)

def _sc_run_one(category: str, fn) -> SelfCheckResult:
    """Uruchamia pojedynczą funkcję testową i zwraca SelfCheckResult."""
    name = fn.__name__.removeprefix("_sc_")
    t0 = _time_mod.monotonic()
    try:
        result = fn()          # fn() zwraca None (sukces) lub str (komunikat błędu)
        elapsed = (_time_mod.monotonic() - t0) * 1000
        if result is None:
            return SelfCheckResult(category, name, True, "", elapsed)
        elif result is True:
            return SelfCheckResult(category, name, True, "", elapsed)
        elif result is False:
            return SelfCheckResult(category, name, False, "zwrócono False", elapsed)
        elif isinstance(result, str):
            ok = not result.startswith("FAIL:")
            msg = result.removeprefix("FAIL:").removeprefix("OK:").strip()
            return SelfCheckResult(category, name, ok, msg, elapsed)
        elif isinstance(result, tuple):
            ok, msg = result
            return SelfCheckResult(category, name, ok, str(msg), elapsed)
        else:
            return SelfCheckResult(category, name, True, str(result), elapsed)
    except NotImplementedError:
        elapsed = (_time_mod.monotonic() - t0) * 1000
        return SelfCheckResult(category, name, True, "NotImplementedError (skip)", elapsed, skip=True)
    except Exception as e:
        elapsed = (_time_mod.monotonic() - t0) * 1000
        return SelfCheckResult(category, name, False,
                               f"{type(e).__name__}: {e}", elapsed)

