@_sc_register("core")
def _sc_tokenize_pipe():
    """Tokenizer wykrywa pipe |."""
    try:
        from __main__ import _tokenize_operators  # type: ignore
    except ImportError:
        raise NotImplementedError
    toks = _tokenize_operators("echo a | cat")
    types = [t for t, v in toks]
    if "pipe" not in types:
        return "FAIL: nie wykryto tokenu 'pipe'"

@_sc_register("core")
def _sc_tokenize_redirect():
    """Tokenizer wykrywa przekierowanie >."""
    try:
        from __main__ import _tokenize_operators  # type: ignore
    except ImportError:
        raise NotImplementedError
    toks = _tokenize_operators("echo x > /tmp/selfcheck_out.txt")
    types = [t for t, v in toks]
    if "redir_out" not in types and ">" not in str(toks):
        return "FAIL: nie wykryto przekierowania '>'"

@_sc_register("core")
def _sc_tokenize_and_or():
    """Tokenizer wykrywa && i ||."""
    try:
        from __main__ import _tokenize_operators  # type: ignore
    except ImportError:
        raise NotImplementedError
    toks_and = _tokenize_operators("true && echo ok")
    toks_or  = _tokenize_operators("false || echo ok")
    types_and = [t for t, v in toks_and]
    types_or  = [t for t, v in toks_or]
    if "and" not in types_and:
        return "FAIL: nie wykryto tokenu 'and' (&&)"
    if "or" not in types_or:
        return "FAIL: nie wykryto tokenu 'or' (||)"

