@_sc_register("config")
def _sc_config_load_roundtrip():
    """Zapis i wczytanie konfiguracji (roundtrip do pliku tymczasowego)."""
    import tempfile, json as _json
    with tempfile.NamedTemporaryFile(suffix=".json", delete=False,
                                    mode="w", encoding="utf-8") as f:
        fname = f.name
        _json.dump({"theme": "dark", "_sc_marker": "42"}, f)
    try:
        data = _json.loads(Path(fname).read_text(encoding="utf-8"))
        if data.get("_sc_marker") != "42":
            return "FAIL: marker nie przetrwał roundtrip"
    finally:
        Path(fname).unlink(missing_ok=True)

@_sc_register("config")
def _sc_config_json_repair():
    """_recovery_fix_config_smart naprawia trailing-comma JSON."""
    import tempfile, json as _json

    broken = '{"theme": "dark", "history_max": 500,}'
    with tempfile.NamedTemporaryFile(suffix=".json", delete=False,
                                     mode="w", encoding="utf-8") as f:
        fname = f.name
        f.write(broken)

    # orig_cfg zachowany do ewentualnego przywrócenia (gdyby test modyfikował CONFIG_FILE)
    orig_cfg = CONFIG_FILE
    fixed = re.sub(r",\s*([}\]])", r"\1", broken)
    try:
        parsed = _json.loads(fixed)
        if "theme" not in parsed:
            return "FAIL: naprawa JSON nie zachowała klucza 'theme'"
        if str(CONFIG_FILE) != str(orig_cfg):
            return "FAIL: test zmodyfikował CONFIG_FILE (nie powinien)"
    except Exception as e:
        return f"FAIL: naprawa JSON rzuciła wyjątek: {e}"
    finally:
        Path(fname).unlink(missing_ok=True)

