def _sc_capture(cmd: str) -> tuple[int, str]:
    """Uruchamia execute_line i przechwytuje stdout."""
    import io, contextlib
    buf = io.StringIO()
    with contextlib.redirect_stdout(buf):
        try:
            rc = execute_line(cmd)
        except Exception as e:
            rc = 1
            log_error(f"_sc_capture '{cmd}': {type(e).__name__}: {e}")
    return rc, buf.getvalue()

