@_sc_register("security")
def _sc_no_external_http_without_guard():
    """Wszystkie zewnętrzne wywołania HTTP mają is_online() guard."""
    import ast as _ast, re as _re
    with open(__file__, "r", encoding="utf-8") as _f:
        _src = _f.read()
    _lines = _src.splitlines()
    _tree = _ast.parse(_src)
    unguarded = []
    for _node in _ast.walk(_tree):
        if isinstance(_node, _ast.With):
            for _item in _node.items:
                _call = _item.context_expr
                if not isinstance(_call, _ast.Call): continue
                _fname = ""
                if isinstance(_call.func, _ast.Attribute): _fname = _call.func.attr
                elif isinstance(_call.func, _ast.Name): _fname = _call.func.id
                if _fname != "urlopen": continue
                # Sprawdź okno 40 linii przed — czy jest is_online()
                _ln = _node.lineno
                _window = "\n".join(_lines[max(0,_ln-40):_ln])
                _localhost = _re.search(r'127\.0\.0\.1|localhost', _window)
                _has_guard = _re.search(r'is_online\(\)|_ONLINE_MODE', _window)
                if not _has_guard and not _localhost:
                    _ctx = _lines[_ln-1].strip()[:60]
                    unguarded.append(f"linia {_ln}: {_ctx}")
    if unguarded:
        return f"FAIL: {len(unguarded)} zewnętrznych HTTP bez is_online() guard: {unguarded}"

