#   TESTY: integrity — integralność plików danych

#
#   Sprawdza czy pliki konfiguracyjne shella nie są uszkodzone:
#   - parsują się poprawnie (JSON/text)
#   - nie są zerowymi plikami
#   - mają sensowne rozmiary (nie przekroczyły limitu)
#   - suma kontrolna pliku skryptu (jeśli można) jest stabilna
#   - pliki danych nie zawierają wierszy NUL (binary corruption)
#   - katalogi danych nie są plikami (błąd struktury)

def _sc_file_json_ok(path: Path) -> "str | None":
    """Zwraca None jeśli plik JSON jest OK, opis błędu jeśli nie."""
    if not path.exists():
        return None    # nieistniejący = OK (zostanie stworzony)
    try:
        size = path.stat().st_size
    except Exception as e:
        return f"stat() failed: {e}"
    if size == 0:
        return "pusty plik (0 bajtów)"
    try:
        raw = path.read_bytes()
        if b"\x00" in raw:
            return "zawiera bajty NUL — możliwe uszkodzenie binarne"
        text = raw.decode("utf-8", errors="strict")
        json.loads(text)
        return None
    except UnicodeDecodeError as e:
        return f"błąd kodowania UTF-8: {e}"
    except json.JSONDecodeError as e:
        return f"nieprawidłowy JSON: {e}"
    except Exception as e:
        return f"{type(e).__name__}: {e}"

@_sc_register("integrity")
def _sc_int_config_file():
    """Plik konfiguracyjny (.terminalx.json) jest poprawnym JSON."""
    active = _active_config_file()
