@_sc_register("integrity")
def _sc_int_log_size():
    """Log shella nie przekroczył limitu rozmiaru (log_max_mb)."""
    if not LOG_FILE.exists():
        return None
    try:
        size_mb = LOG_FILE.stat().st_size / (1024 * 1024)
        limit   = cfg("log_max_mb", 5)
        if size_mb > limit * 1.5:   # 50% margines tolerancji
            return (f"FAIL: log {LOG_FILE.name} zajmuje {size_mb:.1f}MB "
                    f"(limit {limit}MB) — brak rotacji?")
        return f"OK: {size_mb:.2f}MB / {limit}MB"
    except Exception as e:
        return f"FAIL: {e}"

@_sc_register("integrity")
def _sc_int_script_self_readable():
    """Plik skryptu shella jest czytelny i niepusty."""
    try:
        script = Path(__file__).resolve()
        size   = script.stat().st_size
        if size < 1000:
            return f"FAIL: plik skryptu bardzo mały ({size}B) — możliwe uszkodzenie"
        # Sprawdź czy zaczyna się od poprawnego nagłówka Python
        header = script.read_bytes()[:50]
        if not (header.startswith(b"#!") or header.startswith(b"#") or
                b"coding" in header or b"import" in script.read_bytes()[:500]):
            return "FAIL: plik skryptu nie wygląda jak kod Python"
        return f"OK: {size // 1024}KB"
    except NameError:
        raise NotImplementedError   # uruchomiony interaktywnie — brak __file__
    except Exception as e:
        return f"FAIL: {e}"

@_sc_register("integrity")
def _sc_int_crashlog_not_exploded():
    """Crashlog nie ma więcej niż 100 wpisów (sygnał pętli błędów)."""
    if not CRASHLOG_FILE.exists():
        return None
    try:
        text  = CRASHLOG_FILE.read_text(encoding="utf-8", errors="replace")
        count = text.count("TERMINALX CRASHLOG")
        if count > 100:
            return (f"FAIL: {count} wpisów crashlog — możliwa pętla błędów. "
                    f"Napraw: crashlog clear")
        return f"OK: {count} wpisów"
    except Exception as e:
        return f"FAIL: {e}"

#   TESTY: versions — zgodność wersji modułów i środowiska

#
#   Sprawdza:
#   - wersja Pythona >= minimalna wymagana (3.10+)
#   - stdlib modules importują się poprawnie
#   - wersja API pluginów jest spójna
#   - opcjonalne moduły (psutil, readline, curses) mają właściwy status
#   - sys.version_info nie wskazuje na beta/alpha (stabilna gałąź)
#   - datetime/json/hashlib działają w oczekiwany sposób

_SC_MIN_PYTHON = (3, 10)   # minimalna wersja Python dla TerminalXa

_SC_REQUIRED_STDLIB = [
    "os", "sys", "re", "json", "hashlib", "shutil", "pathlib",
    "subprocess", "fnmatch", "datetime", "textwrap", "zipfile",
    "urllib.request", "urllib.error", "tempfile", "importlib.util",
    "shlex", "traceback", "hmac", "socket", "threading",
    "http.server", "base64", "struct", "io", "queue",
    "time", "calendar", "configparser",
]

_SC_OPTIONAL_MODULES = {
    "readline":  "autouzupełnianie TAB",
    "curses":    "edytor nano-lite",
    "psutil":    "procmon (rozszerzony)",
    "tty":       "TUI raw mode (Unix)",
    "termios":   "TUI raw mode (Unix)",
    "select":    "I/O multiplexing",
    "signal":    "obsługa sygnałów",
    "locale":    "kodowanie lokalne",
}

@_sc_register("versions")
def _sc_ver_python_minimum():
    """Python >= 3.10 (wymagany dla match/case i type hints)."""
    vi = sys.version_info[:2]
    if vi < _SC_MIN_PYTHON:
        return (f"FAIL: Python {vi[0]}.{vi[1]} < wymagane "
                f"{_SC_MIN_PYTHON[0]}.{_SC_MIN_PYTHON[1]}")
    return f"OK: Python {vi[0]}.{vi[1]}"

@_sc_register("versions")
def _sc_ver_python_not_prerelease():
    """Python nie jest w wersji alpha/beta/rc."""
    level = sys.version_info.releaselevel
    if level != "final":
        return (f"FAIL: Python {sys.version.split()[0]} "
                f"— wersja przedprodukcyjna ({level}). "
                f"Zalecana wersja finalna.")
    return f"OK: {sys.version.split()[0]} final"

@_sc_register("versions")
def _sc_ver_stdlib_all_present():
    """Wszystkie wymagane moduły stdlib importują się poprawnie."""
    import importlib
    failed = []
    for mod in _SC_REQUIRED_STDLIB:
        try:
            importlib.import_module(mod)
        except ImportError:
            failed.append(mod)
    if failed:
        return f"FAIL: brak modułów stdlib: {', '.join(failed)}"
    return f"OK: {len(_SC_REQUIRED_STDLIB)} modułów"

@_sc_register("versions")
def _sc_ver_optional_modules_status():
    """Opcjonalne moduły — raport dostępności (nie błąd jeśli brak)."""
    import importlib
    missing = []
    for mod, desc in _SC_OPTIONAL_MODULES.items():
        try:
            importlib.import_module(mod)
        except ImportError:
            missing.append(f"{mod} ({desc})")
    if missing:
        # Informacyjne — nie FAIL (moduły opcjonalne)
        return f"OK: brak opcjonalnych: {', '.join(missing)}"
    return f"OK: wszystkie opcjonalne dostępne"

@_sc_register("versions")
def _sc_ver_plugin_api_version():
    """PLUGIN_API_VERSION ma poprawny format (tuple dwóch intów)."""
    pav = PLUGIN_API_VERSION
    if not (isinstance(pav, tuple) and len(pav) == 2 and
            all(isinstance(x, int) for x in pav)):
        return f"FAIL: PLUGIN_API_VERSION={pav!r} — oczekiwano (int, int)"
    return f"OK: API v{pav[0]}.{pav[1]}"

@_sc_register("versions")
def _sc_ver_shell_version_format():
    """SHELL_VERSION ma format X.Y (liczby)."""
    parts = SHELL_VERSION.split(".")
    if not (1 <= len(parts) <= 3 and all(p.isdigit() for p in parts)):
        return f"FAIL: SHELL_VERSION={SHELL_VERSION!r} — oczekiwano formatu X.Y"
    return f"OK: v{SHELL_VERSION}"

@_sc_register("versions")
def _sc_ver_hashlib_algorithms():
    """hashlib dostarcza wymagane algorytmy (md5/sha1/sha256/sha512)."""
    required = {"md5", "sha1", "sha256", "sha512"}
    available = hashlib.algorithms_guaranteed
    missing   = required - available
    if missing:
        return f"FAIL: brak algorytmów hashlib: {missing}"
    return f"OK: {len(available)} algorytmów dostępnych"

@_sc_register("versions")
def _sc_ver_json_version():
    """json.encoder i json.decoder działają (stdlib sanity)."""
    try:
        data   = {"v": SHELL_VERSION, "ok": True, "n": 42}
        s      = json.dumps(data)
        parsed = json.loads(s)
        if parsed != data:
            return "FAIL: json roundtrip niezgodny"
    except Exception as e:
        return f"FAIL: json sanity: {e}"

@_sc_register("versions")
def _sc_ver_datetime_sanity():
    """datetime.datetime.now() zwraca aktualną datę (>= 2024)."""
    now = datetime.datetime.now()
    if now.year < 2024:
        return f"FAIL: zegar systemowy wskazuje {now.year} < 2024 — błędna data"
    return f"OK: {now.strftime('%Y-%m-%d %H:%M')}"

@_sc_register("versions")
def _sc_ver_re_flags():
    """re.compile z flagami działa poprawnie."""
    try:
        pat = re.compile(r"\btest\b", re.IGNORECASE | re.MULTILINE)
        m   = pat.search("line1\nThis TEST here\nline3")
        if not m:
            return "FAIL: re.compile/search nie znalazł dopasowania"
    except Exception as e:
        return f"FAIL: re.compile: {e}"

@_sc_register("versions")
def _sc_ver_pathlib_features():
    """pathlib.Path obsługuje wymagane metody (Python 3.10+)."""
    p = Path(tempfile.gettempdir()) / "sc_ver_test"
    try:
        # stem, suffix, with_suffix, expanduser — podstawowe API
        assert p.stem == "sc_ver_test"
        assert p.suffix == ""
        assert p.with_suffix(".tmp").suffix == ".tmp"
        assert Path("~").expanduser() != Path("~")
        # missing_ok w unlink — Python 3.8+
        p2 = Path(tempfile.gettempdir()) / "_sc_pathlib_test.tmp"
        p2.write_text("x")
        p2.unlink(missing_ok=True)
        p2.unlink(missing_ok=True)   # drugi raz — nie powinien rzucić
    except Exception as e:
        return f"FAIL: pathlib: {e}"

#   TESTY: config_valid — poprawność i spójność konfiguracji

#
#   Sprawdza każdy klucz w _CONFIG pod kątem:
#   - czy klucz jest znany (nie ma nieznanych kluczy)
#   - czy wartość ma właściwy typ (bool/str/int/list)
#   - czy wartości liczbowe mieszczą się w dopuszczalnym zakresie
#   - czy wartości wyliczeniowe (enum) mają dopuszczalne warianty
#   - czy config nie ma nadmiarowych kluczy z crashujących pluginów
#   - spójność wzajemna ustawień (np. log_enabled vs log_max_mb)

# Schemat walidacji: klucz → (typ | tuple typów, walidator_lub_None, opis)
_SC_CONFIG_SCHEMA: dict[str, tuple] = {
    "theme":                  (str,  lambda v: v in ("dark", "light"),
                               "dark | light"),
    "status_bar":             (bool, None, "bool"),
    "prompt_style":           (str,  lambda v: v in ("full", "short", "minimal"),
                               "full | short | minimal"),
    "box_style":              (str,  lambda v: v in ("single","round","double","heavy","ascii"),
                               "single | round | double | heavy | ascii"),
    "show_git_branch":        (bool, None, "bool"),
    "use_emoji_icons":        (bool, None, "bool"),
    "ls_columns":             (bool, None, "bool"),
    "history_max":            (int,  lambda v: 10 <= v <= 100_000,
                               "10 – 100 000"),
    "history_dedup":          (bool, None, "bool"),
    "history_timestamps":     (bool, None, "bool"),
    "auto_cd":                (bool, None, "bool"),
    "confirm_rm":             (bool, None, "bool"),
    "confirm_rm_root":        (bool, None, "bool"),
    "expand_aliases":         (bool, None, "bool"),
    "syntax_highlight_cat":   (bool, None, "bool"),
    "autoload_plugins":       (bool, None, "bool"),
    "plugin_silent":          (bool, None, "bool"),
    "plugin_sandbox":         (str,  lambda v: v in ("off", "warn", "strict"),
                               "off | warn | strict"),
    "log_enabled":            (bool, None, "bool"),
    "log_commands":           (bool, None, "bool"),
    "log_max_mb":             (int,  lambda v: 1 <= v <= 500,
                               "1 – 500 MB"),
    "telemetry":              (bool, lambda v: v is False,
                               "musi być False (prywatność)"),
    "custom_prompt_prefix":   (str,  None, "str"),
    "custom_greeting":        (str,  None, "str"),
    "startup_commands":       (list, None, "list"),
    "_active_profile":        (str,  None, "str"),
    "auto_profile_detect":    (bool, None, "bool"),
}

@_sc_register("config_valid")
def _sc_cfgv_all_defaults_present():
    """_CONFIG_DEFAULTS zawiera wszystkie klucze ze schematu."""
    missing = [k for k in _SC_CONFIG_SCHEMA if k not in _CONFIG_DEFAULTS]
    if missing:
        return f"FAIL: brak kluczy w _CONFIG_DEFAULTS: {', '.join(missing)}"
    return f"OK: {len(_SC_CONFIG_SCHEMA)} kluczy"

@_sc_register("config_valid")
def _sc_cfgv_no_unknown_keys():
    """Aktywna konfiguracja nie zawiera nieznanych kluczy."""
    known   = set(_CONFIG_DEFAULTS.keys())
    unknown = [k for k in _CONFIG if k not in known and not k.startswith("_")]
    if unknown:
        return (f"FAIL: nieznane klucze w konfiguracji: "
                f"{', '.join(unknown[:5])}{'…' if len(unknown) > 5 else ''}")

@_sc_register("config_valid")
def _sc_cfgv_types_correct():
    """Każda wartość w _CONFIG ma poprawny typ wg schematu."""
    errors = []
    for key, (expected_type, validator, desc) in _SC_CONFIG_SCHEMA.items():
        val = cfg(key)
        if val is None:
            continue   # klucz nieobecny — cfg() zwróciło None
        if not isinstance(val, expected_type):
            errors.append(
                f"{key}: {type(val).__name__} != {expected_type.__name__}")
    if errors:
        return (f"FAIL: błędne typy ({len(errors)}): "
                f"{'; '.join(errors[:3])}{'…' if len(errors) > 3 else ''}")
    return f"OK: {len(_SC_CONFIG_SCHEMA)} kluczy sprawdzonych"

@_sc_register("config_valid")
def _sc_cfgv_enum_values():
    """Wartości wyliczeniowe (theme, prompt_style itp.) są dozwolone."""
    errors = []
    for key, (expected_type, validator, desc) in _SC_CONFIG_SCHEMA.items():
        if validator is None:
            continue
        val = cfg(key)
        if val is None:
            continue
        if isinstance(val, expected_type):
            try:
                if not validator(val):
                    errors.append(f"{key}={val!r}  (dozwolone: {desc})")
            except Exception:  # ignorowane celowo
                pass
    if errors:
        return (f"FAIL: niedozwolone wartości: "
                f"{'; '.join(errors[:3])}{'…' if len(errors) > 3 else ''}")
    return f"OK: wszystkie enum-values poprawne"

@_sc_register("config_valid")
def _sc_cfgv_telemetry_always_false():
    """telemetry jest zawsze False (ochrona prywatności)."""
    val = cfg("telemetry", False)
    if val is not False:
        return f"FAIL: telemetry={val!r} — musi być False!"

@_sc_register("config_valid")
def _sc_cfgv_history_max_sane():
    """history_max jest sensowną liczbą (10–100 000)."""
    val = cfg("history_max", 500)
    if not isinstance(val, int) or not (10 <= val <= 100_000):
        return f"FAIL: history_max={val!r} poza zakresem 10–100 000"
    return f"OK: {val}"

@_sc_register("config_valid")
def _sc_cfgv_log_max_mb_sane():
    """log_max_mb jest w rozsądnym zakresie (1–500 MB)."""
    val = cfg("log_max_mb", 5)
    if not isinstance(val, int) or not (1 <= val <= 500):
        return f"FAIL: log_max_mb={val!r} poza zakresem 1–500"
    return f"OK: {val}MB"

@_sc_register("config_valid")
def _sc_cfgv_startup_commands_are_strings():
    """startup_commands zawiera tylko stringi."""
    cmds = cfg("startup_commands", [])
    if not isinstance(cmds, list):
        return f"FAIL: startup_commands to {type(cmds).__name__}, oczekiwano list"
    bad = [i for i, c in enumerate(cmds) if not isinstance(c, str)]
    if bad:
        return f"FAIL: startup_commands[{bad[0]}] nie jest stringiem"
    return f"OK: {len(cmds)} komend startowych"

@_sc_register("config_valid")
def _sc_cfgv_defaults_types_match_schema():
    """Domyślne wartości mają typy zgodne ze schematem."""
    errors = []
    for key, (expected_type, _, desc) in _SC_CONFIG_SCHEMA.items():
        default = _CONFIG_DEFAULTS.get(key)
        if default is not None and not isinstance(default, expected_type):
            errors.append(f"{key}: default {type(default).__name__} != {expected_type.__name__}")
    if errors:
        return f"FAIL: typy domyślnych niezgodne: {'; '.join(errors[:3])}"
    return f"OK: {len(_SC_CONFIG_SCHEMA)} domyślnych zgodnych"

@_sc_register("config_valid")
def _sc_cfgv_log_consistency():
    """Jeśli log_enabled=False to log_commands=False jest bez znaczenia (spójność)."""
    log_en  = cfg("log_enabled",  True)
    log_cmd = cfg("log_commands", True)
    # Nie FAIL — tylko ostrzeżenie informacyjne
    if not isinstance(log_en, bool) or not isinstance(log_cmd, bool):
        return (f"FAIL: log_enabled={log_en!r} lub log_commands={log_cmd!r} "
                f"— oba muszą być bool")
    return f"OK: log_enabled={log_en}, log_commands={log_cmd}"

@_sc_register("config_valid")
def _sc_cfgv_active_profile_exists():
    """Aktywny profil jest zdefiniowany lub jest 'default'."""
    try:
        from __main__ import _BUILTIN_PROFILES, _USER_PROFILES  # type: ignore
    except ImportError:
        raise NotImplementedError
    active = cfg("_active_profile", "default")
    all_profiles = set(_BUILTIN_PROFILES) | set(_USER_PROFILES.keys())
    if active not in all_profiles:
        return (f"FAIL: aktywny profil '{active}' nie istnieje. "
                f"Dostępne: {', '.join(sorted(all_profiles))}")
    return f"OK: profil '{active}'"

#   TESTY: resources — dostępność zasobów systemowych

#
#   Sprawdza:
#   - wolne miejsce na dysku (katalog _BASE)
#   - uprawnienia zapisu do katalogów danych
#   - dostępność wymaganych narzędzi systemowych (PATH)
#   - dostępność pamięci RAM (jeśli psutil dostępny)
#   - limity deskryptorów plików (ulimit)
#   - czy Python ma dostęp do tmpdir
#   - dostępność portów lokalnych (serve/wss)
#   - otwieranie pliku — nie przekroczono ulimit

_SC_MIN_DISK_MB  = 10     # minimum wolnego miejsca w MB
_SC_MIN_RAM_MB   = 32     # minimum wolnej RAM w MB (jeśli psutil)
_SC_MIN_FD_LIMIT = 64     # minimum deskryptorów plików

@_sc_register("resources")
def _sc_res_disk_space():
    """Wolne miejsce na dysku (_BASE) >= 10 MB."""
    try:
        usage = shutil.disk_usage(_BASE)
        free_mb = usage.free / (1024 * 1024)
        if free_mb < _SC_MIN_DISK_MB:
            return (f"FAIL: tylko {free_mb:.1f}MB wolnego miejsca "
                    f"(minimum {_SC_MIN_DISK_MB}MB)")
        return f"OK: {free_mb:.0f}MB wolnego"
    except Exception as e:
        return f"FAIL: disk_usage: {e}"

@_sc_register("resources")
def _sc_res_base_writable():
    """Katalog _BASE jest zapisywalny."""
    probe = _BASE / "_sc_write_probe.tmp"
    try:
        probe.write_text("probe", encoding="utf-8")
        probe.unlink()
    except PermissionError:
        return f"FAIL: _BASE ({_BASE}) nie jest zapisywalny"
    except Exception as e:
        return f"FAIL: zapis do _BASE: {e}"

@_sc_register("resources")
def _sc_res_tmpdir_writable():
    """Katalog tymczasowy (tempfile.gettempdir) jest zapisywalny."""
    tmpdir = Path(tempfile.gettempdir())
    probe  = tmpdir / "_sc_tmp_probe.tmp"
    try:
        probe.write_text("probe", encoding="utf-8")
        probe.unlink()
    except PermissionError:
        return f"FAIL: tmpdir ({tmpdir}) nie jest zapisywalny"
    except Exception as e:
        return f"FAIL: {e}"

@_sc_register("resources")
def _sc_res_plugins_dir_writable():
    """Katalog pluginów jest zapisywalny (lub można go stworzyć)."""
    try:
        PLUGINS_DIR.mkdir(parents=True, exist_ok=True)
        probe = PLUGINS_DIR / "_sc_plugin_probe.tmp"
        probe.write_text("probe", encoding="utf-8")
        probe.unlink()
    except PermissionError:
        return f"FAIL: PLUGINS_DIR ({PLUGINS_DIR}) nie jest zapisywalny"
    except Exception as e:
        return f"FAIL: {e}"

@_sc_register("resources")
def _sc_res_system_tools():
    """Dostępność narzędzi systemowych w PATH."""
    critical  = ["python3"]          # absolutnie wymagane
    useful    = ["ls", "cat", "grep", "find", "ps", "ping"]
    optional  = ["git", "curl", "wget", "nano", "vim"]
    missing_c = [t for t in critical if not shutil.which(t)]
    missing_u = [t for t in useful   if not shutil.which(t)]
    missing_o = [t for t in optional if not shutil.which(t)]
    if missing_c:
        return f"FAIL: brak krytycznych narzędzi: {', '.join(missing_c)}"
    parts = []
    if missing_u:
        parts.append(f"brak użytecznych: {', '.join(missing_u)}")
    if missing_o:
        parts.append(f"brak opcjonalnych: {', '.join(missing_o)}")
    return ("OK" + (": " + "; ".join(parts) if parts else ""))

@_sc_register("resources")
def _sc_res_fd_limit():
    """Limit deskryptorów plików >= 64 (ulimit -n)."""
    try:
        import resource as _resource
        soft, hard = _resource.getrlimit(_resource.RLIMIT_NOFILE)
        if soft < _SC_MIN_FD_LIMIT:
            return (f"FAIL: ulimit -n = {soft} < wymagane {_SC_MIN_FD_LIMIT}. "
                    f"Ustaw: ulimit -n 256")
        return f"OK: {soft} deskryptorów (hard: {hard})"
    except ImportError:
        raise NotImplementedError   # Windows — brak modułu resource
    except Exception as e:
        return f"FAIL: {e}"

@_sc_register("resources")
def _sc_res_open_file_roundtrip():
    """Można otworzyć, zapisać i zamknąć plik bez błędu."""
    p = Path(tempfile.gettempdir()) / "_sc_fd_test.tmp"
    try:
        with open(p, "w", encoding="utf-8") as f:
            f.write("fd_test")
        with open(p, "r", encoding="utf-8") as f:
            content = f.read()
        p.unlink(missing_ok=True)
        if content != "fd_test":
            return f"FAIL: odczytano {content!r}"
    except OSError as e:
        return f"FAIL: OSError (zbyt wiele otwartych plików?): {e}"
    except Exception as e:
        return f"FAIL: {e}"

@_sc_register("resources")
def _sc_res_ram_available():
    """Wolna pamięć RAM >= 32 MB (jeśli psutil dostępny)."""
    try:
        import psutil
        mem      = psutil.virtual_memory()
        free_mb  = mem.available / (1024 * 1024)
        total_mb = mem.total / (1024 * 1024)
        if free_mb < _SC_MIN_RAM_MB:
            return (f"FAIL: tylko {free_mb:.0f}MB wolnej RAM "
                    f"(minimum {_SC_MIN_RAM_MB}MB)")
        return f"OK: {free_mb:.0f}MB wolnej / {total_mb:.0f}MB"
    except ImportError:
        raise NotImplementedError   # psutil niedostępny — skip
    except Exception as e:
        return f"FAIL: {e}"

@_sc_register("resources")
def _sc_res_subprocess_works():
    """subprocess.run() działa (podstawowy mechanizm zewnętrznych komend)."""
    try:
        result = subprocess.run(
            [sys.executable, "-c", "print('sc_sub_ok')"],
            capture_output=True, text=True, timeout=5
        )
        if "sc_sub_ok" not in result.stdout:
            return f"FAIL: subprocess zwrócił {result.stdout!r}"
        return "OK"
    except subprocess.TimeoutExpired:
        return "FAIL: subprocess timeout (5s)"
    except Exception as e:
        return f"FAIL: {e}"

@_sc_register("resources")
def _sc_res_localhost_port_free():
    """Port localhost 18765 (serve default) jest wolny lub zajęty (informacyjne)."""
    import socket as _sock
    port = 18765
    try:
        with _sock.socket(_sock.AF_INET, _sock.SOCK_STREAM) as s:
            s.settimeout(0.5)
            result = s.connect_ex(("127.0.0.1", port))
            if result == 0:
                return f"OK: port {port} zajęty (serve uruchomiony?)"
            return f"OK: port {port} wolny"
    except Exception as e:
        return f"FAIL: sprawdzenie portu: {e}"

@_sc_register("resources")
def _sc_res_hashlib_works():
    """hashlib.sha256 oblicza hash w <5ms."""
    t0 = _time_mod.monotonic()
    data = b"TerminalX selfcheck integrity probe " * 100
    digest = hashlib.sha256(data).hexdigest()
    elapsed = (_time_mod.monotonic() - t0) * 1000
    if len(digest) != 64:
        return f"FAIL: sha256 zwrócił hash długości {len(digest)} != 64"
    if elapsed > 50:
        return f"FAIL: sha256 zbyt wolny: {elapsed:.1f}ms"
    return f"OK: {elapsed:.2f}ms"

#   TESTY v25: składnia własna, komendy, wydajność, pliki, moduły

# ── 1. SYNTAX — własna składnia i integralność kodu ─────────────────────────
#   Terminal sprawdza sam siebie: parsuje własny plik przez ast,
#   weryfikuje że wszystkie wymagane stałe istnieją,
#   i że żadna funkcja krytyczna nie zniknęła.

@_sc_register("syntax")
def _sc_syntax_self_ast():
    """Własny kod przechodzi ast.parse bez SyntaxError."""
    import ast as _ast
    try:
        script = Path(__file__).resolve()
    except NameError:
        raise NotImplementedError  # tryb interaktywny — pomiń
    try:
        src = script.read_text(encoding="utf-8", errors="replace")
        _ast.parse(src)
        return None   # OK
    except SyntaxError as e:
        return f"FAIL: SyntaxError linia {e.lineno}: {e.msg}"

@_sc_register("syntax")
def _sc_syntax_shell_version_defined():
    """SHELL_VERSION jest zdefiniowane i niepuste."""
    v = SHELL_VERSION
    if not v or not isinstance(v, str):
        return "FAIL: SHELL_VERSION niezdefiniowane lub puste"
    # Sprawdź format X.Y
    parts = v.split(".")
    if len(parts) < 2:
        return f"FAIL: SHELL_VERSION nieoczekiwany format: {v!r}"

@_sc_register("syntax")
def _sc_syntax_critical_functions_exist():
    """Krytyczne funkcje shella istnieją i są callable."""
    required = [
        ("dispatch",        dispatch),
        ("execute_line",    execute_line),
        ("cfg",             cfg),
        ("cfg_set",         cfg_set),
        ("log_info",        log_info),
        ("log_error",       log_error),
        ("log_security",    log_security),
        ("print_error",     print_error),
        ("print_warn",      print_warn),
        ("print_info",      print_info),
        ("print_ok",        print_ok),
        ("print_hint",      print_hint),
        ("section_header",  section_header),
        ("terminal_width",  terminal_width),
        ("box_top",         box_top),
        ("write_crashlog",  write_crashlog),
    ]
    missing = [name for name, fn in required if not callable(fn)]
    if missing:
        return f"FAIL: brakujące funkcje: {', '.join(missing)}"

@_sc_register("syntax")
def _sc_syntax_builtins_registry_consistent():
    """Każdy wpis w BUILTINS ma .func callable i .name string."""
    bad = []
    for name, cdef in BUILTINS.items():
        if not callable(getattr(cdef, "func", None)):
            bad.append(f"{name}:.func nie callable")
        if not isinstance(getattr(cdef, "name", None), str):
            bad.append(f"{name}:.name nie str")
    if bad:
        return f"FAIL: {len(bad)} błędów w BUILTINS: {', '.join(bad[:3])}"

@_sc_register("syntax")
def _sc_syntax_theme_attributes_complete():
    """Wszystkie wymagane atrybuty kolorów istnieją w obu motywach."""
    required = {"RESET", "PROMPT", "PATH", "ERROR", "INFO", "BOLD",
                "DIM", "OK", "WARN", "MATCH", "CODE"}
    for theme_name, theme_dict in _THEMES.items():
        missing = required - set(theme_dict.keys())
        if missing:
            return f"FAIL: motyw '{theme_name}' brakuje: {', '.join(sorted(missing))}"

@_sc_register("syntax")
def _sc_syntax_changelog_format():
    """CHANGELOG ma poprawny format — lista dict z version/date/changes."""
    if not isinstance(CHANGELOG, list):
        return "FAIL: CHANGELOG nie jest listą"
    for i, entry in enumerate(CHANGELOG[:5]):
        if not isinstance(entry, dict):
            return f"FAIL: CHANGELOG[{i}] nie jest dict"
        for key in ("version", "date", "changes"):
            if key not in entry:
                return f"FAIL: CHANGELOG[{i}] brakuje klucza '{key}'"
        if not isinstance(entry["changes"], list):
            return f"FAIL: CHANGELOG[{i}]['changes'] nie jest listą"

# ── 2. COMMANDS — dostępność wszystkich komend i pluginów ───────────────────
#   Sprawdza: czy komendy są w BUILTINS, czy da się je wywołać bez crashu,
#   czy pluginy mają poprawny interfejs API, czy nowe komendy z v25 działają.

@_sc_register("commands")
def _sc_cmd_all_registered_callable():
    """Wszystkie komendy w BUILTINS można wywołać (nie rzucają przy imporcie)."""
    not_callable = [n for n, c in BUILTINS.items() if not callable(c)]
    if not_callable:
        return f"FAIL: nie-callable: {', '.join(not_callable[:5])}"

@_sc_register("commands")
def _sc_cmd_required_builtins_present():
    """Zestaw obowiązkowych komend jest dostępny."""
    required = [
        "ls", "cd", "pwd", "cat", "echo", "grep", "find",
        "mkdir", "rm", "cp", "mv", "touch", "help",
        "config", "plugin", "selfcheck", "history", "alias",
        "nano", "pkg", "builder", "logs", "wizard",
    ]
    missing = [cmd for cmd in required if cmd not in BUILTINS]
    if missing:
        return f"FAIL: brakujące komendy: {', '.join(missing)}"

@_sc_register("commands")
def _sc_cmd_aliases_resolve_correctly():
    """Aliasy komend wskazują na te same CommandDef co główna nazwa."""
    bad = []
    seen: dict = {}
    for name, cdef in BUILTINS.items():
        main = cdef.name
        if main not in seen:
            seen[main] = cdef
        elif seen[main] is not cdef:
            bad.append(f"{name}→{main}")
    # To normalne że alias i główna nazwa to ten sam obiekt — liczymy niespójne
    # (aliasy wskazują na inny CommandDef niż główna nazwa)
    incoherent = []
    for name, cdef in BUILTINS.items():
        if name != cdef.name and BUILTINS.get(cdef.name) is not cdef:
            incoherent.append(name)
    if incoherent:
        return f"FAIL: aliasy z niespójnym CommandDef: {', '.join(incoherent[:5])}"

@_sc_register("commands")
def _sc_cmd_dispatch_returns_false_on_unknown():
    """dispatch() zwraca False dla nieznanej komendy."""
    result = dispatch("__nieistniejaca_komenda_xyzzy__", [])
    if result is not False:
        return f"FAIL: dispatch() zwrócił {result!r} zamiast False"

@_sc_register("commands")
def _sc_cmd_dispatch_returns_true_on_known():
    """dispatch() zwraca True dla istniejących komend."""
    import io, contextlib
    for cmd in ("pwd", "echo", "help"):
        buf = io.StringIO()
        try:
            with contextlib.redirect_stdout(buf):
                r = dispatch(cmd, ["--help"] if cmd == "help" else [])
        except Exception as e:
            return f"FAIL: dispatch('{cmd}') rzucił {type(e).__name__}: {e}"
        if r is not True:
            return f"FAIL: dispatch('{cmd}') zwrócił {r!r} zamiast True"

@_sc_register("commands")
def _sc_cmd_plugin_hooks_structure():
    """PLUGIN_HOOKS ma poprawną strukturę — dict ze stringowymi kluczami i listami."""
    if not isinstance(PLUGIN_HOOKS, dict):
        return f"FAIL: PLUGIN_HOOKS jest {type(PLUGIN_HOOKS).__name__}, oczekiwano dict"
    for k, v in PLUGIN_HOOKS.items():
        if not isinstance(k, str):
            return f"FAIL: PLUGIN_HOOKS klucz {k!r} nie jest stringiem"
        if not isinstance(v, list):
            return f"FAIL: PLUGIN_HOOKS['{k}'] nie jest listą"

@_sc_register("commands")
def _sc_cmd_builder_command_works():
    """Komenda 'builder' odpowiada na 'list' bez wyjątku."""
    import io, contextlib
    buf = io.StringIO()
    try:
        with contextlib.redirect_stdout(buf):
            dispatch("builder", ["list"])
    except Exception as e:
        return f"FAIL: builder list rzucił {type(e).__name__}: {e}"
    out = buf.getvalue()
    if not out.strip():
        return "FAIL: builder list nie wypisało niczego"

@_sc_register("commands")
def _sc_cmd_logs_command_works():
    """Komenda 'logs' odpowiada na 'tail 1' bez wyjątku."""
    import io, contextlib
    buf = io.StringIO()
    try:
        with contextlib.redirect_stdout(buf):
            dispatch("logs", ["tail", "1"])
    except Exception as e:
        return f"FAIL: logs tail 1 rzucił {type(e).__name__}: {e}"

@_sc_register("commands")
def _sc_cmd_selfcheck_meta():
    """selfcheck sam jest zarejestrowany i ma aliasy."""
    if "selfcheck" not in BUILTINS:
        return "FAIL: 'selfcheck' nie jest w BUILTINS"
    cdef = BUILTINS["selfcheck"]
    if not cdef.aliases:
        return "FAIL: selfcheck nie ma aliasów"
    for alias in cdef.aliases:
        if alias not in BUILTINS:
            return f"FAIL: alias '{alias}' nie jest w BUILTINS"

# ── 3. SETTINGS — konfiguracja i poprawność ustawień ────────────────────────
#   Głęboka walidacja konfiguracji: typy, zakresy, spójność między kluczami,
#   oraz sprawdzenie że nowe opcje z v25 (log_level, wizard) są obsługiwane.

@_sc_register("settings")
def _sc_set_all_defaults_have_correct_types():
    """Wszystkie domyślne wartości config mają oczekiwane typy."""
    _TYPE_MAP = {
        "theme":                str,
        "status_bar":           bool,
        "prompt_style":         str,
        "history_max":          int,
        "history_dedup":        bool,
        "auto_cd":              bool,
        "confirm_rm":           bool,
        "autoload_plugins":     bool,
        "plugin_sandbox":       str,
        "log_enabled":          bool,
        "log_commands":         bool,
        "log_max_mb":           int,
        "telemetry":            bool,
        "startup_commands":     list,
        "use_emoji_icons":      bool,
        "ls_columns":           bool,
    }
    bad = []
    for key, expected_type in _TYPE_MAP.items():
        val = _CONFIG_DEFAULTS.get(key)
        if val is None and expected_type is not type(None):
            # None jest OK dla opcjonalnych, sprawdź tylko jeśli klucz istnieje
            if key not in _CONFIG_DEFAULTS:
                bad.append(f"{key}: brak w defaults")
                continue
        if not isinstance(val, expected_type):
            bad.append(f"{key}: {type(val).__name__} ≠ {expected_type.__name__}")
    if bad:
        return f"FAIL: złe typy ({len(bad)}): {', '.join(bad[:4])}"

@_sc_register("settings")
def _sc_set_enum_values_valid():
    """Wartości enum w config są z dozwolonych zbiorów."""
    _ENUMS = {
        "theme":          {"dark", "light"},
        "prompt_style":   {"full", "short", "minimal"},
        "plugin_sandbox": {"off", "warn", "strict"},
        "box_style":      {"single", "round", "double", "heavy", "ascii"},
    }
    bad = []
    for key, allowed in _ENUMS.items():
        val = cfg(key)
        if val not in allowed:
            bad.append(f"{key}={val!r} (dozwolone: {sorted(allowed)})")
    if bad:
        return f"FAIL: niedozwolone wartości enum: {'; '.join(bad)}"

@_sc_register("settings")
def _sc_set_telemetry_hardcoded_false():
    """telemetry jest zawsze False — hardcoded."""
    val = cfg("telemetry", True)   # default True żeby wykryć błąd
    if val is not False:
        return f"FAIL: telemetry={val!r}, oczekiwano False"
    if not _NO_TELEMETRY:
        return "FAIL: _NO_TELEMETRY nie jest True"

@_sc_register("settings")
def _sc_set_log_max_mb_sane():
    """log_max_mb jest w sensownym zakresie 1–1000 MB."""
    val = cfg("log_max_mb", 5)
    try:
        n = int(val)
    except (TypeError, ValueError):
        return f"FAIL: log_max_mb={val!r} nie jest liczbą"
    if not (1 <= n <= 1000):
        return f"FAIL: log_max_mb={n} poza zakresem 1–1000"

@_sc_register("settings")
def _sc_set_history_max_sane():
    """history_max jest w sensownym zakresie 10–100000."""
    val = cfg("history_max", 500)
    try:
        n = int(val)
    except (TypeError, ValueError):
        return f"FAIL: history_max={val!r} nie jest liczbą"
    if not (10 <= n <= 100_000):
        return f"FAIL: history_max={n} poza zakresem 10–100000"

@_sc_register("settings")
def _sc_set_cfg_set_and_get_roundtrip():
    """cfg_set → cfg roundtrip działa dla różnych typów."""
    import uuid
    key = f"_sc_test_{uuid.uuid4().hex[:8]}"
    for val in (42, True, "testowy_string", [1, 2, 3]):
        cfg_set(key, val)
        got = cfg(key)
        if got != val:
            cfg_set(key, None)  # cleanup
            return f"FAIL: cfg_set({val!r}) → cfg={got!r}"
    cfg_set(key, None)  # usuń klucz testowy

@_sc_register("settings")
def _sc_set_startup_commands_are_list_of_strings():
    """startup_commands jest listą stringów."""
    val = cfg("startup_commands", [])
    if not isinstance(val, list):
        return f"FAIL: startup_commands jest {type(val).__name__}"
    for i, item in enumerate(val):
        if not isinstance(item, str):
            return f"FAIL: startup_commands[{i}] jest {type(item).__name__}, oczekiwano str"

_LOG_LEVELS = ("DEBUG", "INFO", "WARN", "CMD", "ERROR")

@_sc_register("settings")
def _sc_set_active_log_level_valid():
    """Aktywny poziom filtrowania logów jest jednym z dozwolonych."""

    valid = set(_LOG_LEVELS) | {"ALL"}
    if _ACTIVE_LOG_LEVEL not in valid:
        return f"FAIL: _ACTIVE_LOG_LEVEL={_ACTIVE_LOG_LEVEL!r} poza {sorted(valid)}"

@_sc_register("settings")
def _sc_set_config_file_parseable():
    """Plik konfiguracyjny (jeśli istnieje) da się sparsować."""
    cf = _active_config_file()
    if not cf.exists():
        return None  # OK — brak pliku to nie błąd
    try:
        ext = cf.suffix.lower()
        raw = cf.read_text(encoding="utf-8", errors="replace")
        if ext == ".json":
            json.loads(raw)
        elif ext in (".yaml", ".yml"):
            _parse_yaml(raw)
        elif ext == ".ini":
            _parse_ini(raw)
        else:
            return f"FAIL: nieznane rozszerzenie config: {ext}"
    except Exception as e:
        return f"FAIL: nie można sparsować {cf.name}: {type(e).__name__}: {e}"

# ── 4. PERF_EXT — wydajność nowych modułów v25 ──────────────────────────────
#   Uzupełnia istniejącą kategorię 'perf' o testy szybkości dla:
#   - parsowania logu (adv_parse_log_file)
#   - rejestracji builderów
#   - filtrowania logów
#   - dispatch overhead

@_sc_register("perf_ext")
def _sc_perfx_log_parse_speed():
    """Parsowanie LOG_FILE 100× w < 2000ms."""
    t0 = _time_mod.monotonic()
    for _ in range(100):
        _adv_parse_log_file()
    elapsed = (_time_mod.monotonic() - t0) * 1000
    if elapsed > 2000:
        return f"FAIL: 100× parse logu = {elapsed:.0f}ms (limit 2000ms)"
    return f"OK: {elapsed:.0f}ms"

@_sc_register("perf_ext")
def _sc_perfx_log_filter_speed():
    """Filtrowanie 1000 wpisów logu 500× w < 500ms."""
    entries = [{"ts": "2025-01-01 00:00:00", "level": lvl, "msg": "test"}
               for lvl in ("DEBUG", "INFO", "WARN", "CMD", "ERROR") * 200]
    t0 = _time_mod.monotonic()
    for _ in range(500):
        _adv_filter_entries(entries, "WARN")
    elapsed = (_time_mod.monotonic() - t0) * 1000
    if elapsed > 500:
        return f"FAIL: 500× filter(1000 wpisów) = {elapsed:.0f}ms (limit 500ms)"
    return f"OK: {elapsed:.0f}ms"

@_sc_register("perf_ext")
def _sc_perfx_dispatch_overhead():
    """dispatch() 1000× dla znanych komend w < 200ms."""
    import io, contextlib
    t0 = _time_mod.monotonic()
    for _ in range(1000):
        buf = io.StringIO()
        with contextlib.redirect_stdout(buf):
            dispatch("pwd", [])
    elapsed = (_time_mod.monotonic() - t0) * 1000
    if elapsed > 200:
        return f"FAIL: 1000× dispatch('pwd') = {elapsed:.0f}ms (limit 200ms)"
    return f"OK: {elapsed:.0f}ms"

@_sc_register("perf_ext")
def _sc_perfx_cfg_read_speed():
    """cfg() 5000× w < 300ms (cache lub dict lookup)."""
    t0 = _time_mod.monotonic()
    for _ in range(5000):
        cfg("theme")
        cfg("log_max_mb")
        cfg("history_max")
    elapsed = (_time_mod.monotonic() - t0) * 1000
    if elapsed > 300:
        return f"FAIL: 5000× cfg() = {elapsed:.0f}ms (limit 300ms)"
    return f"OK: {elapsed:.0f}ms"

@_sc_register("perf_ext")
def _sc_perfx_builder_list_speed():
    """_builder_list() 50× w < 500ms."""
    t0 = _time_mod.monotonic()
    for _ in range(50):
        _builder_list()
    elapsed = (_time_mod.monotonic() - t0) * 1000
    if elapsed > 500:
        return f"FAIL: 50× _builder_list() = {elapsed:.0f}ms (limit 500ms)"
    return f"OK: {elapsed:.0f}ms"

@_sc_register("perf_ext")
def _sc_perfx_box_render_speed():
    """box_top + box_row × 500 + box_bottom w < 100ms."""
    t0 = _time_mod.monotonic()
    for _ in range(500):
        box_top("test", width=72, color=C.PATH)
        box_row("  content row", width=72, color=C.PATH)
        box_bottom(width=72, color=C.PATH)
