@_sc_register("datafiles")
def _sc_df_crashlog_size():
    """Plik crashlogu nie przekracza 512 KB (rotacja działa)."""
    if not CRASHLOG_FILE.exists():
        return None
    size = CRASHLOG_FILE.stat().st_size
    limit = 512 * 1024
    if size > limit:
        return (f"FAIL: crashlog ma {size // 1024} KB "
                f"(limit {limit // 1024} KB) — rotacja nie zadziałała?")

