@_sc_register("datafiles")
def _sc_df_log_adv_parse_returns_list():
    """_adv_parse_log_file() zawsze zwraca listę (nawet gdy plik brak)."""
    result = _adv_parse_log_file()
    if not isinstance(result, list):
        return f"FAIL: _adv_parse_log_file() zwróciło {type(result).__name__}"
    for i, e in enumerate(result[:5]):
        if not isinstance(e, dict):
            return f"FAIL: wpis logu [{i}] to {type(e).__name__}, oczekiwano dict"
        for key in ("ts", "level", "msg"):
            if key not in e:
                return f"FAIL: wpis logu [{i}] brakuje klucza '{key}'"

