# SELFCHECK — kategoria: portable (v29)

@selfcheck("portable")
def _sc_portable_python_guard():
    """Python ≥ 3.10 guard aktywny."""
    vi = sys.version_info
    if vi < (3, 10):
        return f"FAIL: Python {vi.major}.{vi.minor} < 3.10"
    return f"OK: Python {vi.major}.{vi.minor}.{vi.micro}"

@selfcheck("portable")
def _sc_portable_no_external_deps():
    """Brak zewnętrznych bibliotek (stdlib only)."""
    external = [
        "requests", "numpy", "pandas", "flask", "django",
        "PIL", "click", "rich", "prompt_toolkit", "colorama",
        "pydantic", "aiohttp",
    ]
    found = []
    for lib in external:
        try:
            __import__(lib)
            found.append(lib)
        except ImportError:
            pass
    if found:
        return f"FAIL: znaleziono zewnętrzne biblioteki: {', '.join(found)}"
    return "OK: brak zewnętrznych zależności"

@selfcheck("portable")
def _sc_portable_stdlib_required():
    """Kluczowe moduły stdlib dostępne."""
    required = [
        "os", "sys", "pathlib", "json", "hashlib", "re",
        "subprocess", "shutil", "datetime", "importlib.util",
        "http.server", "socket", "threading", "zipfile",
        "tarfile", "tempfile", "signal", "traceback",
    ]
    missing = []
    for mod in required:
        try:
            __import__(mod)
        except ImportError:
            missing.append(mod)
    if missing:
        return f"FAIL: brakujące stdlib: {', '.join(missing)}"
    return f"OK: {len(required)} modułów stdlib dostępnych"

@selfcheck("portable")
def _sc_portable_base_dir():
    """_BASE wskazuje istniejący, zapisywalny katalog."""
    if not _BASE.exists():
        return f"FAIL: katalog _BASE nie istnieje: {_BASE}"
    try:
        test = _BASE / ".sc_write_test"
        test.write_text("ok")
        test.unlink()
    except Exception as e:
        return f"FAIL: _BASE nie jest zapisywalny: {e}"
    return f"OK: {_BASE}  portable={_PORTABLE_MODE}"

@selfcheck("portable")
def _sc_portable_env_vars():
    """Zmienne TERMINALX_* są poprawnie rozpoznawane."""
    # Sprawdź że _BOOT_* mają właściwe typy
    assert isinstance(_ANSI_DISABLED,      bool), "_ANSI_DISABLED musi być bool"
    assert isinstance(_BOOT_FORCE_OFFLINE, bool), "_BOOT_FORCE_OFFLINE musi być bool"
    assert isinstance(_IS_FROZEN,          bool), "_IS_FROZEN musi być bool"
    assert isinstance(_PORTABLE_MODE,      bool), "_PORTABLE_MODE musi być bool"
    assert isinstance(_BOOT_VERBOSE,       bool), "_BOOT_VERBOSE musi być bool"
    assert isinstance(_BOOT_DEBUG,         bool), "_BOOT_DEBUG musi być bool"
    assert isinstance(_BOOT_LOG_OFF,       bool), "_BOOT_LOG_OFF musi być bool"
    return (f"OK: ANSI={'off' if _ANSI_DISABLED else 'on'}  "
            f"offline={'forced' if _BOOT_FORCE_OFFLINE else 'auto'}  "
            f"frozen={_IS_FROZEN}  portable={_PORTABLE_MODE}")

@selfcheck("portable")
def _sc_portable_rc_config_paths():
    """RC_FILE i CONFIG_FILE są instancjami Path."""
    assert isinstance(RC_FILE,     Path), f"RC_FILE nie jest Path: {type(RC_FILE)}"
    assert isinstance(CONFIG_FILE, Path), f"CONFIG_FILE nie jest Path: {type(CONFIG_FILE)}"
    # Rodzic musi istnieć lub dać się stworzyć
    for p in (RC_FILE, CONFIG_FILE):
        if not p.parent.exists():
            return f"FAIL: katalog nadrzędny nie istnieje: {p.parent}"
    return f"OK: RC={RC_FILE.name}  CONFIG={CONFIG_FILE.name}"

@selfcheck("portable")
def _sc_portable_no_color_respected():
    """_ANSI_DISABLED wyłącza kolory (C.RESET == '' gdy NO_COLOR)."""
    if _ANSI_DISABLED:
        val = C.RESET
        if val != "":
            return f"FAIL: C.RESET='{val!r}' powinno być '' przy _ANSI_DISABLED=True"
        return "OK: NO_COLOR aktywny — C.RESET == ''"
    return "OK: kolory aktywne — _ANSI_DISABLED=False"

@selfcheck("portable")
def _sc_portable_detect_base_dir_callable():
    """_detect_base_dir() zwraca instancję Path."""
    result = _detect_base_dir()
    if not isinstance(result, Path):
        return f"FAIL: _detect_base_dir() zwróciło {type(result)}"
    return f"OK: {result}"

@selfcheck("portable")
def _sc_portable_cmd_registered():
    """Komenda 'portable' jest zarejestrowana w BUILTINS."""
    if "portable" not in BUILTINS:
        return "FAIL: 'portable' nie jest zarejestrowane w BUILTINS"
    cdef = BUILTINS["portable"]
    subs = cdef.get("flags", [])
    required_subs = {"init", "status", "copy", "pack", "check", "env"}
    missing = required_subs - set(subs)
    if missing:
        return f"FAIL: brakujące podkomendy: {', '.join(missing)}"
    return f"OK: portable  podkomendy: {', '.join(sorted(subs))}"

@selfcheck("portable")
def _sc_portable_script_path_callable():
    """_portable_script_path() zwraca Path do istniejącego pliku."""
    try:
        p = _portable_script_path()
        if not isinstance(p, Path):
            return f"FAIL: nie jest Path: {type(p)}"
        if not p.exists():
            return f"FAIL: plik nie istnieje: {p}"
        return f"OK: {p.name}  ({p.stat().st_size // 1024} KB)"
    except Exception as e:
        return f"FAIL: {e}"

def _sc_run_category(category: str) -> list[SelfCheckResult]:
    """Uruchamia wszystkie testy danej kategorii."""
    tests = _SELFCHECK_REGISTRY.get(category, [])
    return [_sc_run_one(category, fn) for fn in tests]

def _sc_run_all(categories: list[str], fast: bool = False) -> list[SelfCheckResult]:
    """Uruchamia wszystkie testy z podanych kategorii."""
    results = []
    for cat in categories:
        if fast and cat in _SC_FAST_SKIP:
            continue
        results.extend(_sc_run_category(cat))
    return results

def _sc_print_report(results: list[SelfCheckResult],
                     fail_only: bool = False,
                     show_perf: bool = True):
    """Drukuje sformatowany raport testów."""
    w = min(terminal_width() - 2, 80)

    total   = len(results)
    passed  = sum(1 for r in results if r.ok and not r.skip)
    failed  = sum(1 for r in results if not r.ok and not r.skip)
    skipped = sum(1 for r in results if r.skip)

    ok_all  = failed == 0
    # 'total' używane w podsumowaniu końcowym (box_row summary)

    header_color = C.OK if ok_all else C.ERROR
    print()
    print(box_top(f"  🧪 selfcheck — testy wewnętrzne TerminalXa  ", width=w, color=header_color))

    # Grupuj wg kategorii
    by_cat: dict[str, list[SelfCheckResult]] = {}
    for r in results:
        by_cat.setdefault(r.category, []).append(r)

    for cat, cat_results in by_cat.items():
        icon  = _SC_ICONS.get(cat, "•")
        n_ok  = sum(1 for r in cat_results if r.ok and not r.skip)
        n_err = sum(1 for r in cat_results if not r.ok and not r.skip)
        n_sk  = sum(1 for r in cat_results if r.skip)
        cat_color = C.ERROR if n_err else (C.DIM if n_ok == 0 else C.OK)

        # Nagłówek kategorii
        status_str = (f"{C.OK}✔ {n_ok}{C.RESET}" +
                      (f"  {C.ERROR}✖ {n_err}{C.RESET}" if n_err else "") +
                      (f"  {C.DIM}⊘ {n_sk}{C.RESET}" if n_sk else ""))
        print(box_sep(width=w, color=cat_color))
        print(box_row(
            f"  {icon} {C.BOLD}{cat.upper():<12}{C.RESET}  {status_str}",
            width=w, color=cat_color))

        # Szczegóły testów
        for r in cat_results:
            if fail_only and (r.ok or r.skip):
                continue
            if r.skip:
                icon_r = f"{C.DIM}⊘{C.RESET}"
                color_r = C.DIM
            elif r.ok:
                icon_r = f"{C.OK}✔{C.RESET}"
                color_r = C.DIM
            else:
                icon_r = f"{C.ERROR}✖{C.RESET}"
                color_r = C.ERROR

            time_str = (f"{C.DIM}{r.elapsed_ms:6.1f}ms{C.RESET}"
                        if show_perf else "")
            msg_str  = (f"  {color_r}{r.msg[:w - 30]}{C.RESET}"
                        if r.msg else "")
            name_str = r.name.replace("_", " ")
            row = (f"    {icon_r}  {color_r}{name_str:<30}{C.RESET}"
                   f"  {time_str}{msg_str}")
            print(box_row(row, width=w, color=cat_color))

    # Podsumowanie
    print(box_sep(width=w, color=header_color))
    total_ms = sum(r.elapsed_ms for r in results)
    summary  = (f"  Wynik: {C.BOLD}"
                f"{C.OK if ok_all else C.ERROR}"
                f"{'PASS' if ok_all else 'FAIL'}{C.RESET}"
                f"  ·  {total} testów  ✔ {passed}  ✖ {failed}  ⊘ {skipped}"
                f"  ·  {C.DIM}{total_ms:.0f}ms łącznie{C.RESET}")
    print(box_row(summary, width=w, color=header_color))
    print(box_bottom(width=w, color=header_color))

    if not ok_all:
        print(f"\n  {C.DIM}Napraw błędy: recovery fix all  |"
              f"  Szczegóły: selfcheck --fail-only{C.RESET}")
    print()

    return ok_all

@command("selfcheck",
         "Testy wewnętrzne i self-check TerminalXa",
         aliases=["test", "check", "verify"],
         flags=["list", "--fast", "--fail-only", "--json"])
def cmd_selfcheck(args):
    """
    selfcheck                  — uruchom wszystkie testy wewnętrzne
    selfcheck <kategoria>      — uruchom wybraną kategorię
    selfcheck list             — lista dostępnych kategorii testów
    selfcheck --fast           — tylko testy bez I/O (<100ms)
    selfcheck --fail-only      — pokaż tylko niezdane testy
    selfcheck --json           — wynik w JSON (do automatyzacji/CI)

    Kategorie (oryginalne):
      core         parser, tokenizer, zmienne, pipe, aliasy, dispatch
      config       wczytanie/zapis, domyślne, JSON repair
      fs           touch/rm/mkdir/cp/mv, UTF-8 I/O, ścieżki
      builtins     echo/pwd/ls/cd/cat/grep/find/calc/hash
      encoding     UTF-8, ANSI, json.dumps/loads, shlex
      history      append, plik, deduplicacja
      aliases      add/lookup/expand, plik roundtrip
      plugins      katalog, rejestr, sandbox, hooki
      terminal     terminal_width, box_*, curses, readline
      crash        write_crashlog, czytelność, _log()
      network      is_online(), socket, komenda 'mode'
      perf         tokenizer ×500, cfg ×1000, box ×200, regex ×200
      integrity    JSON plików danych, NUL-bytes, rozmiary, katalogi
      versions     Python ≥3.10, stdlib, API pluginów, hashlib, datetime
      config_valid typy, enum-values, telemetry=False, spójność
      resources    dysk, RAM, uprawnienia, PATH, fd-limit, subprocess

    Kategorie v25 (nowe):
      syntax       własna składnia ast.parse, krytyczne funkcje, motywy,
                   BUILTINS spójność, CHANGELOG format
      commands     wszystkie komendy callable, dispatch True/False,
                   aliasy, PLUGIN_HOOKS, builder/logs/wizard/selfcheck
      settings     typy defaults, enum-values, telemetry=False,
                   log_max_mb/history_max zakresy, cfg roundtrip,
                   aktywny poziom logów, plik config parseable
      perf_ext     log-parse ×100, filter ×500, dispatch ×1000,
                   cfg ×5000, builder_list ×50, box ×500
      datafiles    historia (NUL, UTF-8, rotacja), aliasy (format),
                   log (format wpisów), config JSON, ext-registry,
                   plugin-trust DB, crashlog rozmiar, PKG DB
    """
    # ── list ──────────────────────────────────────────────────────────────
    if args and args[0] == "list":
        w = min(terminal_width() - 2, 72)
        print()
        print(box_top("  🧪 selfcheck — dostępne kategorie  ", width=w, color=C.INFO))
        for cat in _SC_ALL_CATEGORIES:
            tests    = _SELFCHECK_REGISTRY.get(cat, [])
            icon     = _SC_ICONS.get(cat, "•")
            fast_tag = f"  {C.DIM}[--fast pomija]{C.RESET}" if cat in _SC_FAST_SKIP else ""
            print(box_row(
                f"  {icon}  {C.BOLD}{cat:<12}{C.RESET}  "
                f"{C.DIM}{len(tests)} testów{C.RESET}{fast_tag}",
                width=w, color=C.INFO))
        print(box_row(
            f"  {C.DIM}Łącznie: "
            f"{sum(len(v) for v in _SELFCHECK_REGISTRY.values())} testów{C.RESET}",
            width=w, color=C.INFO))
        print(box_bottom(width=w, color=C.INFO))
        print()
        return

    # ── flagi ─────────────────────────────────────────────────────────────
    fast       = "--fast"      in args
    fail_only  = "--fail-only" in args
    as_json    = "--json"      in args
    clean_args = [a for a in args
                  if a not in ("--fast", "--fail-only", "--json")]

    # ── wybór kategorii ───────────────────────────────────────────────────
    if clean_args:
        cat = clean_args[0].lower()
        if cat not in _SC_ALL_CATEGORIES:
            print_error(
                f"Nieznana kategoria: '{cat}'",
                f"Dostępne: {', '.join(_SC_ALL_CATEGORIES)}")
            return
        categories = [cat]
    else:
        categories = _SC_ALL_CATEGORIES

    # ── uruchomienie ──────────────────────────────────────────────────────
    if not as_json:
        skip_msg = "  (tryb --fast: pomijam network/crash/perf)" if fast else ""
        cats_str = ", ".join(categories)
        print_info(f"Uruchamiam testy: {cats_str}{skip_msg}")

    results = _sc_run_all(categories, fast=fast)

    # ── wynik JSON ────────────────────────────────────────────────────────
    if as_json:
        output = {
            "version":  SHELL_VERSION,
            "timestamp": datetime.datetime.now().isoformat(timespec="seconds"),
            "total":    len(results),
            "passed":   sum(1 for r in results if r.ok and not r.skip),
            "failed":   sum(1 for r in results if not r.ok and not r.skip),
            "skipped":  sum(1 for r in results if r.skip),
            "ok":       all(r.ok or r.skip for r in results),
            "tests":    [r.to_dict() for r in results],
        }
        print(json.dumps(output, indent=2, ensure_ascii=False))
        return

    # ── raport tekstowy ───────────────────────────────────────────────────
    ok_all = _sc_print_report(results, fail_only=fail_only, show_perf=True)

    # Zapisz wynik do logu i ustaw kod wyjścia
    total   = len(results)
    passed  = sum(1 for r in results if r.ok and not r.skip)
    failed  = sum(1 for r in results if not r.ok and not r.skip)
    _log("INFO", f"selfcheck: {passed}/{total} PASS, {failed} FAIL")
    SHELL_VARS["?"] = "0" if ok_all else "1"   # kod wyjścia dla skryptów

# INTEGRATE — INTEGRACJA Z SYSTEMEM BEZ INSTALACJI
#
#   Nadal standalone (.py), ale shell może:
#
#   integrate status          — pokaż aktualny stan integracji
#   integrate path            — dodaj katalog skryptu do PATH (~/.bashrc / ~/.zshrc)
#   integrate shell           — zarejestruj jako powłokę w /etc/shells (wymaga sudo)
#   integrate alias           — dodaj alias 'ms' w ~/.bashrc / ~/.zshrc
#   integrate desktop         — stwórz plik .desktop (Linux XDG launcher)
#   integrate autostart       — dodaj do autostartu (~/.config/autostart/)
#   integrate symlink [dir]   — stwórz dowiązanie symboliczne w ~/bin lub /usr/local/bin
#   integrate rc              — skonfiguruj ~/.terminalxrc (plik startowy shella)
#   integrate bat             — wygeneruj wrapper .bat / .cmd (Windows)
#   integrate remove <co>     — cofnij wybraną integrację
#   integrate remove all      — cofnij wszystkie integracje
#
#   Zasady:
#   - Żadna operacja nie wymaga pip ani uprawnień root (poza 'shell')
#   - Każda zmiana jest odwracalna przez 'integrate remove'
#   - Pliki modyfikowane mają backup z timestampem przed zmianą
#   - Wszystkie ścieżki są absolutne i rozwijane

# ── Stałe i helpers ───────────────────────────────────────────────────────────

def _integ_script_path() -> Path:
    """Absolutna ścieżka do pliku skryptu TerminalXa."""
    try:
        return Path(__file__).resolve()
    except NameError:
        return Path(sys.argv[0]).resolve()

def _integ_script_dir() -> Path:
    return _integ_script_path().parent

def _integ_home() -> Path:
    return Path.home()

def _integ_shell_rc_files() -> list[Path]:
    """Pliki RC powłoki systemowej (bash/zsh/fish) — tylko istniejące lub domyślny."""
    candidates = [
        _integ_home() / ".bashrc",
        _integ_home() / ".zshrc",
        _integ_home() / ".bash_profile",
        _integ_home() / ".profile",
    ]
    # Fish config
    fish_cfg = _integ_home() / ".config" / "fish" / "config.fish"
    if fish_cfg.parent.exists():
        candidates.append(fish_cfg)
    return [p for p in candidates if p.exists()]

def _integ_timestamp() -> str:
    return datetime.datetime.now().strftime("%Y%m%d_%H%M%S")

def _integ_backup(path: Path) -> Path:
    """Tworzy backup pliku przed modyfikacją."""
    bak = path.with_suffix(path.suffix + f".bak_{_integ_timestamp()}")
    shutil.copy2(path, bak)
    return bak

def _integ_marker(tag: str) -> tuple[str, str]:
    """Zwraca znaczniki BEGIN/END dla bloku dodanego przez TerminalX."""
    return (
        f"# >>> TerminalX {tag} BEGIN <<<",
        f"# >>> TerminalX {tag} END <<<",
    )

def _integ_block_present(path: Path, tag: str) -> bool:
    """Sprawdza czy blok z danym znacznikiem już istnieje w pliku."""
    if not path.exists():
        return False
    begin, _ = _integ_marker(tag)
    try:
        return begin in path.read_text(encoding="utf-8", errors="replace")
    except Exception:
        return False

def _integ_append_block(path: Path, tag: str, lines: list[str]) -> bool:
    """Dodaje blok do pliku RC. Zwraca True jeśli dodano, False jeśli już istniał."""
    if _integ_block_present(path, tag):
        return False  # już istnieje
    begin, end = _integ_marker(tag)
    block = "\n" + begin + "\n" + "\n".join(lines) + "\n" + end + "\n"
    if path.exists():
        _integ_backup(path)
    with open(path, "a", encoding="utf-8") as f:
        f.write(block)
    return True

def _integ_remove_block(path: Path, tag: str) -> bool:
    """Usuwa blok z pliku RC. Zwraca True jeśli usunięto."""
    if not path.exists():
        return False
    begin, end = _integ_marker(tag)
    text = path.read_text(encoding="utf-8", errors="replace")
    if begin not in text:
        return False
    # Usuń blok od BEGIN do END (włącznie)
    pattern = re.compile(
        r"\n?" + re.escape(begin) + r".*?" + re.escape(end) + r"\n?",
        re.DOTALL
    )
    new_text = pattern.sub("", text)
    _integ_backup(path)
    path.write_text(new_text, encoding="utf-8")
    return True

# ── Stan integracji ───────────────────────────────────────────────────────────

def _integ_status() -> dict:
    """Zbiera aktualny stan wszystkich integracji."""
    script   = _integ_script_path()
    script_d = _integ_script_dir()
    home     = _integ_home()
    status   = {}

    # PATH
    rc_files  = _integ_shell_rc_files()
    path_in   = [p for p in rc_files if _integ_block_present(p, "PATH")]
    status["path"] = {
        "ok":     bool(path_in),
        "detail": f"w {path_in[0].name}" if path_in else "nie dodany",
        "files":  [str(p) for p in path_in],
        "script_dir": str(script_d),
    }

    # alias 'ms'
    alias_in  = [p for p in rc_files if _integ_block_present(p, "alias")]
    status["alias"] = {
        "ok":     bool(alias_in),
        "detail": f"ms → {script.name}" if alias_in else "nie dodany",
        "files":  [str(p) for p in alias_in],
    }

    # symlink
    symlink_locations = [
        home / "bin" / "ms",
        home / ".local" / "bin" / "ms",
        Path("/usr/local/bin/ms"),
    ]
    found_links = [p for p in symlink_locations if p.is_symlink() and p.resolve() == script]
    status["symlink"] = {
        "ok":     bool(found_links),
        "detail": str(found_links[0]) if found_links else "brak",
        "files":  [str(p) for p in found_links],
    }

    # .desktop
    desktop_dirs = [
        home / ".local" / "share" / "applications",
        home / "Desktop",
    ]
    desktop_files = [d / "TerminalX.desktop" for d in desktop_dirs
                     if (d / "TerminalX.desktop").exists()]
    status["desktop"] = {
        "ok":     bool(desktop_files),
        "detail": str(desktop_files[0]) if desktop_files else "brak",
        "files":  [str(p) for p in desktop_files],
    }

    # autostart
    autostart_file = home / ".config" / "autostart" / "TerminalX.desktop"
    status["autostart"] = {
        "ok":     autostart_file.exists(),
        "detail": str(autostart_file) if autostart_file.exists() else "brak",
        "files":  [str(autostart_file)] if autostart_file.exists() else [],
    }

    # /etc/shells
    etc_shells_ok = False
    try:
        shells_text = Path("/etc/shells").read_text(encoding="utf-8", errors="replace")
        etc_shells_ok = str(script) in shells_text
    except Exception:  # ignorowane celowo
        pass
    status["shell"] = {
        "ok":     etc_shells_ok,
        "detail": "zarejestrowany w /etc/shells" if etc_shells_ok else "nie zarejestrowany",
        "files":  ["/etc/shells"] if etc_shells_ok else [],
    }

    # .terminalxrc
    status["rc"] = {
        "ok":     RC_FILE.exists(),
        "detail": str(RC_FILE) if RC_FILE.exists() else "brak",
        "files":  [str(RC_FILE)] if RC_FILE.exists() else [],
    }

    # wrapper .bat (Windows)
    bat_file = script.with_suffix(".bat")
    status["bat"] = {
        "ok":     bat_file.exists(),
        "detail": str(bat_file) if bat_file.exists() else "brak",
        "files":  [str(bat_file)] if bat_file.exists() else [],
    }

    return status

# ── Akcje integracji ──────────────────────────────────────────────────────────

def _integ_do_path() -> tuple[bool, str]:
    """Dodaj katalog skryptu do PATH w plikach RC powłoki."""
    script_d = _integ_script_dir()
    rc_files  = _integ_shell_rc_files()

    # Określ domyślne rc do modyfikacji
    preferred = [_integ_home() / ".bashrc", _integ_home() / ".zshrc"]
    targets   = [p for p in preferred if p.exists()]
    if not targets:
        # Stwórz .bashrc jeśli żaden nie istnieje
        targets = [_integ_home() / ".bashrc"]

    lines = [f'export PATH="{script_d}:$PATH"']
    added_to = []
    for rc in targets:
        if _integ_append_block(rc, "PATH", lines):
            added_to.append(rc.name)

    if not added_to:
        already = [p.name for p in rc_files if _integ_block_present(p, "PATH")]
        return True, f"PATH już dodany (w: {', '.join(already)})"

    return True, (f"Dodano PATH do: {', '.join(added_to)}\n"
                  f"  Zastosuj: source ~/.bashrc  lub otwórz nowy terminal")

def _integ_do_alias() -> tuple[bool, str]:
    """Dodaj alias 'ms' do plików RC powłoki."""
    script   = _integ_script_path()
    rc_files  = _integ_shell_rc_files()

    # Użyj rc_files jako baza, z priorytetem dla .bashrc i .zshrc
    preferred_names = {".bashrc", ".zshrc"}
    targets = [p for p in rc_files if p.name in preferred_names and p.exists()]
    if not targets:
        targets = [p for p in rc_files if p.exists()]
    if not targets:
        targets = [_integ_home() / ".bashrc"]

    lines = [
        f'alias ms="python3 {script}"',
        f'alias TerminalX="python3 {script}"',
    ]
    added_to = []
    for rc in targets:
        if _integ_append_block(rc, "alias", lines):
            added_to.append(rc.name)

    if not added_to:
        return True, "Alias 'ms' już istnieje w plikach RC."

    return True, (f"Alias ms= dodany do: {', '.join(added_to)}\n"
                  f"  Zastosuj: source ~/.bashrc  lub otwórz nowy terminal")

def _integ_do_symlink(target_dir: "Path | None" = None) -> tuple[bool, str]:
    """Stwórz dowiązanie symboliczne ms → skrypt."""
    script = _integ_script_path()
    home   = _integ_home()

    if target_dir is None:
        # Preferuj ~/bin lub ~/.local/bin (nie wymaga sudo)
        for candidate in [home / "bin", home / ".local" / "bin"]:
            candidate.mkdir(parents=True, exist_ok=True)
            target_dir = candidate
            break

    link = target_dir / "ms"

    if link.exists() or link.is_symlink():
        if link.is_symlink() and link.resolve() == script:
            return True, f"Symlink już istnieje: {link}"
        return False, (f"Istnieje inny plik/link: {link}\n"
                       f"  Usuń ręcznie i ponów: integrate symlink")
    try:
        link.symlink_to(script)
        # Uprawnienia wykonywalne dla skryptu
        script.chmod(script.stat().st_mode | 0o111)
        return True, f"Symlink stworzony: {link} → {script}"
    except PermissionError:
        return False, f"Brak uprawnień do {target_dir} — spróbuj: integrate symlink ~/bin"
    except Exception as e:
        return False, str(e)

def _integ_do_desktop() -> tuple[bool, str]:
    """Stwórz plik .desktop (Linux XDG — launcher aplikacji)."""
    if sys.platform not in ("linux", "linux2"):
        return False, "Pliki .desktop są tylko dla systemu Linux."

    script  = _integ_script_path()
    home    = _integ_home()
    app_dir = home / ".local" / "share" / "applications"
    app_dir.mkdir(parents=True, exist_ok=True)
    desktop = app_dir / "TerminalX.desktop"

    # Szukaj terminala systemowego
    terminal_exec = None
    for term in ("gnome-terminal", "konsole", "xterm", "xfce4-terminal",
                 "lxterminal", "tilix", "alacritty", "kitty"):
        if shutil.which(term):
            terminal_exec = term
            break

    if terminal_exec is None:
        terminal_exec = "xterm"

    # Różne terminale mają różną składnię -e
    if terminal_exec in ("gnome-terminal",):
        exec_line = f"{terminal_exec} -- python3 {script}"
    elif terminal_exec in ("alacritty", "kitty"):
        exec_line = f"{terminal_exec} -e python3 {script}"
    else:
        exec_line = f"{terminal_exec} -e python3 {script}"

    content = (
        "[Desktop Entry]\n"
        "Version=1.0\n"
        "Type=Application\n"
        f"Name=TerminalX\n"
        f"Comment={SHELL_TAGLINE}\n"
        f"Exec={exec_line}\n"
        "Icon=utilities-terminal\n"
        "Terminal=false\n"
        "Categories=System;TerminalEmulator;\n"
        f"Path={_integ_script_dir()}\n"
        "StartupNotify=false\n"
    )

    if desktop.exists():
        _integ_backup(desktop)

    desktop.write_text(content, encoding="utf-8")
    desktop.chmod(0o755)

    # Odśwież bazę .desktop (jeśli dostępne)
    if shutil.which("update-desktop-database"):
        subprocess.run(
            ["update-desktop-database", str(app_dir)],
            capture_output=True
        )

    return True, f"Plik .desktop stworzony: {desktop}"

def _integ_do_autostart() -> tuple[bool, str]:
    """Dodaj do autostartu (~/.config/autostart/)."""
    if sys.platform not in ("linux", "linux2"):
        return False, "Autostart XDG jest tylko dla systemu Linux."

    script      = _integ_script_path()
    autostart_d = _integ_home() / ".config" / "autostart"
    autostart_d.mkdir(parents=True, exist_ok=True)
    afile       = autostart_d / "TerminalX.desktop"

    terminal_exec = None
    for term in ("gnome-terminal", "konsole", "xterm", "xfce4-terminal",
                 "alacritty", "kitty"):
        if shutil.which(term):
            terminal_exec = term
            break
    terminal_exec = terminal_exec or "xterm"

    content = (
        "[Desktop Entry]\n"
        "Version=1.0\n"
        "Type=Application\n"
        f"Name=TerminalX (autostart)\n"
        f"Exec={terminal_exec} -e python3 {script}\n"
        "Terminal=false\n"
        "X-GNOME-Autostart-enabled=true\n"
        f"Comment=Autostart TerminalX v{SHELL_VERSION}\n"
    )

    if afile.exists():
        _integ_backup(afile)
    afile.write_text(content, encoding="utf-8")
    return True, f"Autostart dodany: {afile}"

def _integ_do_shell_register() -> tuple[bool, str]:
    """Zarejestruj TerminalX w /etc/shells (wymaga sudo)."""
    script     = _integ_script_path()
    shells_f   = Path("/etc/shells")

    if not shells_f.exists():
        return False, "/etc/shells nie istnieje (nie-Unix?)"

    try:
        content = shells_f.read_text(encoding="utf-8", errors="replace")
    except PermissionError:
        return False, "Brak uprawnień do odczytu /etc/shells"

    if str(script) in content:
        return True, f"Już zarejestrowany w /etc/shells: {script}"

    # Spróbuj przez sudo tee
    if shutil.which("sudo"):
        try:
            result = subprocess.run(
                ["sudo", "sh", "-c",
                 f'echo "{script}" >> /etc/shells'],
                capture_output=True, text=True, timeout=15
            )
            if result.returncode == 0:
                return True, f"Zarejestrowano w /etc/shells: {script}"
            else:
                return False, (f"sudo nieudane (rc={result.returncode}): "
                               f"{result.stderr[:80]}")
        except subprocess.TimeoutExpired:
            return False, "sudo timeout (15s) — sprawdź uprawnienia"
        except Exception as e:
            return False, str(e)
    else:
        return False, (f"Brak sudo — dodaj ręcznie:\n"
                       f'  echo "{script}" | sudo tee -a /etc/shells')

def _integ_do_rc() -> tuple[bool, str]:
    """Stwórz lub zaktualizuj ~/.terminalxrc z przykładową konfiguracją."""
    if RC_FILE.exists():
        size = RC_FILE.stat().st_size
        return True, f"Plik RC już istnieje: {RC_FILE} ({size}B)"

    content = (
        f"# ~/.terminalxrc — plik startowy TerminalXa\n"
        f"# Wygenerowano: {datetime.datetime.now().strftime('%Y-%m-%d %H:%M')}\n"
        f"# Wersja: TerminalX v{SHELL_VERSION}\n"
        f"#\n"
        f"# Komendy tutaj są wykonywane przy każdym starcie shella.\n"
        f"# Możesz tu ustawiać aliasy, zmienne i konfigurację.\n\n"
        f"# Przykładowe aliasy\n"
        f"alias ll=\"ls -l\"\n"
        f"alias la=\"ls -a\"\n"
        f"alias lal=\"ls -al\"\n"
        f"alias cls=\"clear\"\n\n"
        f"# Przykładowe zmienne środowiskowe\n"
        f"# export EDITOR=nano\n\n"
        f"# Motyw (dark / light)\n"
        f"# theme dark\n\n"
        f"# Komendy startowe\n"
        f"# echo \"Witaj w TerminalX!\"\n"
    )

    RC_FILE.write_text(content, encoding="utf-8")
    return True, f"Stworzono ~/.terminalxrc: {RC_FILE}"

def _integ_do_bat() -> tuple[bool, str]:
    """Wygeneruj wrapper .bat / .cmd dla Windows."""
    script  = _integ_script_path()
    bat     = script.with_suffix(".bat")
    ps1     = script.with_suffix(".ps1")

    # .bat dla cmd.exe
    bat_content = (
        f"@echo off\n"
        f"REM TerminalX v{SHELL_VERSION} — wrapper .bat\n"
        f"REM Wygenerowano przez: integrate bat\n"
        f"python \"{script}\" %*\n"
    )

    # .ps1 dla PowerShell
    ps1_content = (
        f"# TerminalX v{SHELL_VERSION} — wrapper PowerShell\n"
        f"# Wygenerowano przez: integrate bat\n"
        f"python \"{script}\" @args\n"
    )

    created = []
    for path, content in [(bat, bat_content), (ps1, ps1_content)]:
        if path.exists():
            _integ_backup(path)
        path.write_text(content, encoding="utf-8")
        created.append(path.name)

    return True, (f"Wygenerowano: {', '.join(created)}\n"
                  f"  Użycie (cmd):        {bat.name}\n"
                  f"  Użycie (PowerShell): .\\{ps1.name}")

def _integ_remove(what: str) -> tuple[bool, str]:
    """Cofnij konkretną integrację."""
    home    = _integ_home()
    script  = _integ_script_path()
    results = []

    if what in ("path", "all"):
        for rc in _integ_shell_rc_files():
            if _integ_remove_block(rc, "PATH"):
                results.append(f"PATH usunięty z {rc.name}")

    if what in ("alias", "all"):
        for rc in _integ_shell_rc_files():
            if _integ_remove_block(rc, "alias"):
                results.append(f"Alias usunięty z {rc.name}")

    if what in ("symlink", "all"):
        for link_dir in [home / "bin", home / ".local" / "bin",
                         Path("/usr/local/bin")]:
            link = link_dir / "ms"
            if link.is_symlink() and link.resolve() == script:
                try:
                    link.unlink()
                    results.append(f"Symlink usunięty: {link}")
                except Exception as e:
                    results.append(f"Błąd usuwania symlink {link}: {e}")

    if what in ("desktop", "all"):
        for d in [home / ".local" / "share" / "applications", home / "Desktop"]:
            df = d / "TerminalX.desktop"
            if df.exists():
                df.unlink()
                results.append(f"Desktop usunięty: {df}")

    if what in ("autostart", "all"):
        af = home / ".config" / "autostart" / "TerminalX.desktop"
        if af.exists():
            af.unlink()
            results.append(f"Autostart usunięty: {af}")

    if what in ("bat", "all"):
        for ext in (".bat", ".ps1"):
            f = script.with_suffix(ext)
            if f.exists():
                f.unlink()
                results.append(f"Usunięto: {f.name}")

    if what == "rc":
        # RC nie usuwamy automatycznie — może zawierać dane użytkownika
        return False, (f"Plik RC ({RC_FILE}) nie jest usuwany automatycznie.\n"
                       f"  Usuń ręcznie: rm {RC_FILE}")

    if what == "shell":
        return False, ("Wpis w /etc/shells nie jest usuwany automatycznie.\n"
                       f"  Usuń ręcznie: sudo sed -i '/{script.name}/d' /etc/shells")

    if not results:
        return False, f"Nie znaleziono integracji do usunięcia: '{what}'"

    return True, "\n  ".join(results)

# ── Komenda: integrate ────────────────────────────────────────────────────────

@command("integrate",
         "Integracja z systemem bez instalacji (PATH, alias, symlink, desktop…)",
         aliases=["install", "sysintegrate"],
         flags=["status", "path", "alias", "symlink", "desktop",
                "autostart", "shell", "rc", "bat", "remove"])
def cmd_integrate(args):
    """
    integrate status          — aktualny stan wszystkich integracji
    integrate path            — dodaj skrypt do PATH (~/.bashrc / ~/.zshrc)
    integrate alias           — dodaj alias 'ms' i 'TerminalX'
    integrate symlink [dir]   — stwórz dowiązanie ~/bin/ms → skrypt
    integrate desktop         — plik .desktop (Linux XDG launcher)
    integrate autostart       — dodaj do autostartu przy logowaniu (Linux)
    integrate shell           — zarejestruj w /etc/shells (wymaga sudo)
    integrate rc              — stwórz ~/.terminalxrc z przykładową konfiguracją
    integrate bat             — wygeneruj wrapper .bat i .ps1 (Windows)
    integrate remove <co>     — cofnij: path | alias | symlink | desktop |
                                        autostart | bat | all
    """
    sub = args[0] if args else "status"
    w   = min(terminal_width() - 2, 72)

    # ── status ────────────────────────────────────────────────────────────
    if sub == "status":
        st      = _integ_status()
        script  = _integ_script_path()
        all_ok  = all(v["ok"] for v in st.values())
        col     = C.OK if all_ok else C.INFO

        print()
        print(box_top(f"  🔗 integrate — integracja TerminalXa  ", width=w, color=col))
        print(box_row(
            f"  {C.DIM}Skrypt:{C.RESET}  {C.PATH}{script}{C.RESET}",
            width=w, color=col))
        print(box_sep(width=w, color=col))

        icons   = {
            "path":      "🛤️ ", "alias":    "🔤", "symlink":  "🔗",
            "desktop":   "🖥️ ", "autostart":"🚀", "shell":    "🐚",
            "rc":        "⚙️ ", "bat":      "🪟",
        }
        labels  = {
            "path":      "PATH (shell RC)",
            "alias":     "Alias 'ms'",
            "symlink":   "Symlink ~/bin/ms",
            "desktop":   "Plik .desktop (XDG)",
            "autostart": "Autostart (XDG)",
            "shell":     "/etc/shells",
            "rc":        "~/.terminalxrc",
            "bat":       "Wrapper .bat/.ps1",
        }
        for key, info in st.items():
            ok_icon = f"{C.OK}✔{C.RESET}" if info["ok"] else f"{C.DIM}–{C.RESET}"
            row = (f"  {ok_icon}  {icons.get(key,'•')}  "
                   f"{C.BOLD}{labels.get(key, key):<22}{C.RESET}  "
                   f"{C.DIM}{info['detail']}{C.RESET}")
            print(box_row(row, width=w, color=col))

        print(box_sep(width=w, color=col))
        active = [k for k, v in st.items() if v["ok"]]
        inactive = [k for k, v in st.items() if not v["ok"]]
        print(box_row(
            f"  {C.DIM}Aktywne: {C.OK}{', '.join(active) or 'brak'}{C.RESET}"
            f"  {C.DIM}Nieaktywne: {', '.join(inactive) or 'brak'}{C.RESET}",
            width=w, color=col))
        print(box_row(
            f"  {C.DIM}integrate path | alias | symlink | desktop | rc | bat{C.RESET}",
            width=w, color=col))
        print(box_bottom(width=w, color=col))
        print()
        return

    # ── path ──────────────────────────────────────────────────────────────
    if sub == "path":
        ok, msg = _integ_do_path()
        (print_info if ok else print_error)(msg)
        return

    # ── alias ─────────────────────────────────────────────────────────────
    if sub == "alias":
        ok, msg = _integ_do_alias()
        (print_info if ok else print_error)(msg)
        return

    # ── symlink ───────────────────────────────────────────────────────────
    if sub == "symlink":
        target = Path(args[1]).expanduser() if len(args) >= 2 else None
        ok, msg = _integ_do_symlink(target)
        (print_info if ok else print_error)(msg)
        return

    # ── desktop ───────────────────────────────────────────────────────────
    if sub == "desktop":
        ok, msg = _integ_do_desktop()
        (print_info if ok else print_error)(msg)
        return

    # ── autostart ─────────────────────────────────────────────────────────
    if sub == "autostart":
        ok, msg = _integ_do_autostart()
        (print_info if ok else print_error)(msg)
        return

    # ── shell ─────────────────────────────────────────────────────────────
    if sub == "shell":
        print(f"  {C.WARN}⚠  Ta operacja modyfikuje /etc/shells i wymaga sudo.{C.RESET}")
        try:
            ans = input(f"  Kontynuować? [t/n]: ").strip().lower()
        except (EOFError, KeyboardInterrupt):
            print(); return
        if ans not in ("t", "y", "tak", "yes"):
            print_info("Anulowano.")
            return
        ok, msg = _integ_do_shell_register()
        (print_info if ok else print_error)(msg)
        return

    # ── rc ────────────────────────────────────────────────────────────────
    if sub == "rc":
        ok, msg = _integ_do_rc()
        (print_info if ok else print_error)(msg)
        if ok and RC_FILE.exists():
            print(f"  {C.DIM}Edytuj: nano {RC_FILE}{C.RESET}")
        return

    # ── bat ───────────────────────────────────────────────────────────────
    if sub == "bat":
        ok, msg = _integ_do_bat()
        (print_info if ok else print_error)(msg)
        return

    # ── remove ────────────────────────────────────────────────────────────
    if sub == "remove":
        what = args[1] if len(args) >= 2 else ""
        if not what:
            print_error(
                "Podaj co usunąć: path | alias | symlink | desktop | "
                "autostart | bat | rc | shell | all")
            return
        valid = {"path", "alias", "symlink", "desktop",
                 "autostart", "bat", "rc", "shell", "all"}
        if what not in valid:
            print_error(f"Nieznany cel: '{what}'",
                        f"Dostępne: {', '.join(sorted(valid))}")
            return
        if what == "all":
            print(f"  {C.WARN}⚠  Cofnięcie wszystkich integracji.{C.RESET}")
            try:
                ans = input(f"  Kontynuować? [t/n]: ").strip().lower()
            except (EOFError, KeyboardInterrupt):
                print(); return
            if ans not in ("t", "y", "tak", "yes"):
                print_info("Anulowano."); return
        ok, msg = _integ_remove(what)
        (print_info if ok else print_error)(msg)
        return

    print_error(
        f"Nieznana podkomenda: integrate {sub}",
        "Dostępne: status path alias symlink desktop autostart shell rc bat remove "
        "ext context drop"
    )

# ██ INTEGRATE EXTENSION: ext / context / drop ████████████████████████████████
#
#   integrate ext list                    — pokaż zarejestrowane rozszerzenia
#   integrate ext add <.ext> [program]    — zarejestruj rozszerzenie (tymczasowo)
#   integrate ext remove <.ext>           — wyrejestruj
#   integrate ext open <plik>             — otwórz plik zarejestrowanym handlerem
#   integrate ext status                  — pokaż co jest zarejestrowane w systemie
#
#   integrate context install             — dodaj "Otwórz w TerminalX" do menu
#   integrate context remove              — usuń z menu kontekstowego
#   integrate context status              — sprawdź stan wpisu
#
#   integrate drop                        — uruchom TerminalX w trybie drop:
#                                           akceptuje pliki jako argumenty
#                                           (przeciągnięte z menadżera plików)
#   integrate drop daemon                 — nasłuchuj na stdin na ścieżki plików
#   integrate drop test <plik…>           — symuluj drag & drop z podanymi plikami
#
#   Zasady:
#   - Wszystko tymczasowe / per-user — bez sudo, bez instalacji systemowej
#   - Linux: xdg-mime + ~/.local/share/mime + mimeapps.list
#   - macOS: duti + LaunchServices (jeśli duti dostępne) lub info.plist
#   - Windows: rejestr HKCU (bez praw admina) przez reg.exe
#   - Każda zmiana zapisywana w _EXT_REGISTRY_FILE (JSON) do śledzenia

# ── Plik rejestru rozszerzeń (per-user, tymczasowy) ──────────────────────────


# Struktura: { ".ext": { "program": str|None, "system": "linux"|"macos"|"windows",
#                        "method":  str, "registered": ISO-timestamp,
#                        "rollback": {...} } }

def _ext_load_registry() -> dict:
    if _EXT_REGISTRY_FILE.exists():
        try:
            return json.loads(
                _EXT_REGISTRY_FILE.read_text(encoding="utf-8", errors="replace"))
        except Exception:  # ignorowane celowo
            pass
    return {}

def _ext_save_registry(data: dict):
    _EXT_REGISTRY_FILE.write_text(
        json.dumps(data, indent=2, ensure_ascii=False), encoding="utf-8")

def _ext_detect_system() -> str:
    if sys.platform.startswith("linux"):
        return "linux"
    if sys.platform == "darwin":
        return "macos"
    if os.name == "nt":
        return "windows"
    return "unknown"

def _ext_mime_for(ext: str) -> str:
    """Zwraca MIME type dla rozszerzenia (heurystyczny)."""
    ext = ext.lower().lstrip(".")
    _MAP = {
        "minipkg": "application/x-minipkg",
        "py":      "text/x-python",
        "sh":      "application/x-shellscript",
        "json":    "application/json",
        "yaml":    "application/x-yaml",
        "yml":     "application/x-yaml",
        "toml":    "application/toml",
        "md":      "text/markdown",
        "txt":     "text/plain",
        "log":     "text/plain",
        "csv":     "text/csv",
        "ini":     "text/plain",
        "cfg":     "text/plain",
    }
    return _MAP.get(ext, f"application/x-TerminalX-{ext}")

def _ext_script_exec_line() -> str:
    """Zwraca linię exec dla TerminalXa z plikiem jako argumentem."""
    script = _integ_script_path()
    py     = shutil.which("python3") or sys.executable
    return f"{py} {script}"

# ── Linux: xdg-mime + mimeapps.list ──────────────────────────────────────────

def _ext_linux_install(ext: str, mime: str) -> tuple[bool, str, dict]:
    """
    Rejestruje rozszerzenie na Linux przez:
    1. Plik XML MIME w ~/.local/share/mime/packages/
    2. Plik .desktop w ~/.local/share/applications/
    3. update-mime-database + xdg-mime default
    Zwraca (ok, komunikat, dane_rollback).
    """
    home       = _integ_home()
    mime_pkg_d = home / ".local" / "share" / "mime" / "packages"
    apps_d     = home / ".local" / "share" / "applications"
    mime_pkg_d.mkdir(parents=True, exist_ok=True)
    apps_d.mkdir(parents=True, exist_ok=True)

    app_id   = f"TerminalX-{ext.lstrip('.')}"
    desktop  = apps_d / f"{app_id}.desktop"
    xml_file = mime_pkg_d / f"{app_id}.xml"
    exec_l   = _ext_script_exec_line()

    # ── 1. XML MIME type ────────────────────────────────────────────────
    xml_content = (
        '<?xml version="1.0" encoding="UTF-8"?>\n'
        '<mime-info xmlns="http://www.freedesktop.org/standards/shared-mime-info">\n'
        f'  <mime-type type="{mime}">\n'
        f'    <comment>TerminalX file ({ext})</comment>\n'
        f'    <glob pattern="*{ext}"/>\n'
        '  </mime-type>\n'
        '</mime-info>\n'
    )
    xml_file.write_text(xml_content, encoding="utf-8")

    # ── 2. .desktop dla tego MIME ────────────────────────────────────────
    desktop_content = (
        "[Desktop Entry]\n"
        "Version=1.0\n"
        "Type=Application\n"
        f"Name=TerminalX ({ext})\n"
        f"Comment=Otwórz {ext} w TerminalX\n"
        f"Exec={exec_l} %f\n"
        "Icon=utilities-terminal\n"
        "Terminal=true\n"
        f"MimeType={mime};\n"
        "Categories=System;\n"
        "NoDisplay=false\n"
    )
    desktop.write_text(desktop_content, encoding="utf-8")
    desktop.chmod(0o755)

    msgs = [f"Plik MIME XML: {xml_file.name}", f"Desktop: {desktop.name}"]

    # ── 3. Aktualizacja baz MIME ─────────────────────────────────────────
    mime_db = home / ".local" / "share" / "mime"
    if shutil.which("update-mime-database"):
        r = subprocess.run(["update-mime-database", str(mime_db)],
                           capture_output=True, text=True)
        if r.returncode == 0:
            msgs.append("update-mime-database: OK")

    # ── 4. Ustaw domyślną aplikację przez xdg-mime ───────────────────────
    if shutil.which("xdg-mime"):
        r = subprocess.run(
            ["xdg-mime", "default", f"{app_id}.desktop", mime],
            capture_output=True, text=True)
        if r.returncode == 0:
            msgs.append(f"xdg-mime default: {app_id}.desktop → {mime}")

    # ── 5. Fallback: mimeapps.list ────────────────────────────────────────
    mimeapps = home / ".config" / "mimeapps.list"
    mimeapps.parent.mkdir(parents=True, exist_ok=True)
    _integ_append_block(mimeapps, f"ext-{ext.lstrip('.')}",
                        [f"[Default Applications]",
                         f"{mime}={app_id}.desktop"])
    msgs.append(f"mimeapps.list: {mime} → {app_id}.desktop")

    rollback = {
        "xml":     str(xml_file),
        "desktop": str(desktop),
        "mime":    mime,
        "app_id":  app_id,
    }
    return True, "  ".join(msgs), rollback

def _ext_linux_remove(ext: str, reg: dict) -> tuple[bool, str]:
    rb       = reg.get("rollback", {})
    removed  = []
    for key in ("xml", "desktop"):
        p = Path(rb[key]) if key in rb else None
        if p and p.exists():
            p.unlink()
            removed.append(p.name)
    # Usuń blok z mimeapps.list
    mimeapps = _integ_home() / ".config" / "mimeapps.list"
    _integ_remove_block(mimeapps, f"ext-{ext.lstrip('.')}")
    # Odśwież bazy
    mime_db = _integ_home() / ".local" / "share" / "mime"
    if shutil.which("update-mime-database"):
        subprocess.run(["update-mime-database", str(mime_db)], capture_output=True)
    if not removed:
        return False, "Brak plików do usunięcia."
    return True, f"Usunięto: {', '.join(removed)}"

# ── macOS: duti lub bezpośrednio LaunchServices ───────────────────────────────

def _ext_macos_install(ext: str, mime: str) -> tuple[bool, str, dict]:
    """Rejestruje rozszerzenie przez duti (jeśli zainstalowane) lub info.plist."""
    script    = _integ_script_path()
    bundle_id = "org.python3.minishell"
    # script używane w plist fallback i w komunikatach rollback
    _script_str = str(script)

    if shutil.which("duti"):
        # duti -s bundle_id .ext all
        r = subprocess.run(
            ["duti", "-s", bundle_id, ext, "all"],
            capture_output=True, text=True)
        if r.returncode == 0:
            rollback = {"method": "duti", "ext": ext, "bundle_id": bundle_id,
                            "script": _script_str}
            return True, f"duti: {ext} → {bundle_id}  ({_script_str})", rollback
        return False, f"duti błąd: {r.stderr[:80]}", {}

    # Fallback — plik ~/.TerminalX_ext_handlers.plist (informacyjny)
    plist_info = (
        f"# Aby zarejestrować {ext} na macOS bez duti:\n"
        f"# 1. Zainstaluj duti: brew install duti\n"
        f"# 2. Uruchom: integrate ext add {ext}\n"
        f"# LUB ręcznie: right-click → Get Info → Open With → Change All\n"
    )
    plist_f = _integ_home() / f".terminalx_macos_{ext.lstrip('.')}_info.txt"
    plist_f.write_text(plist_info, encoding="utf-8")
    rollback = {"method": "plist_info", "file": str(plist_f)}
    return True, (f"Brak duti — zapisano instrukcje: {plist_f.name}\n"
                  f"  Zainstaluj duti: brew install duti"), rollback

def _ext_macos_remove(ext: str, reg: dict) -> tuple[bool, str]:
    rb = reg.get("rollback", {})
    if rb.get("method") == "plist_info":
        p = Path(rb.get("file", ""))
        if p.exists():
            p.unlink()
            return True, f"Usunięto: {p.name}"
    return True, "Brak plików do usunięcia (duti nie zapisuje plików)."

# ── Windows: rejestr HKCU (bez praw admina) ──────────────────────────────────

def _ext_windows_install(ext: str, program: "str | None") -> tuple[bool, str, dict]:
    """
    Rejestruje rozszerzenie w rejestrze Windows HKCU (nie wymaga admina).
    Sciezki: HKCU/Software/Classes/.ext i HKCU/Software/Classes/TerminalX.ext
    """
    if not shutil.which("reg"):
        return False, "Brak narzędzia reg.exe — nieoczekiwane środowisko Windows.", {}

    py      = shutil.which("python") or shutil.which("python3") or sys.executable
    script  = _integ_script_path()
    prog_id = f"TerminalX{ext.replace('.', '_')}"
    cmd     = f'"{py}" "{script}" "%1"'

    rollback_keys = []

    def reg_add(key: str, name: str, val: str, kind: str = "REG_SZ") -> bool:
        r = subprocess.run(
            ["reg", "add", key, "/v", name, "/t", kind,
             "/d", val, "/f"],
            capture_output=True, text=True)
        if r.returncode == 0:
            rollback_keys.append(key)
        return r.returncode == 0

    base_ext = f"HKCU\\Software\\Classes\\{ext}"
    base_app = f"HKCU\\Software\\Classes\\{prog_id}"

    ok1 = reg_add(base_ext,              "",           prog_id)
    ok2 = reg_add(base_ext,              "PerceivedType", "text")
    ok3 = reg_add(f"{base_app}",         "",           f"TerminalX {ext} file")
    ok4 = reg_add(f"{base_app}\\shell\\open\\command", "", cmd)

    if not all([ok1, ok2, ok3, ok4]):
        return False, "Błąd zapisu do rejestru HKCU — sprawdź uprawnienia.", {}

    # Powiadom Explorer o zmianie
    subprocess.run(
        ["reg", "add",
         "HKCU\\Software\\Microsoft\\Windows\\CurrentVersion\\Explorer\\FileExts"
         f"\\{ext}\\UserChoice",
         "/v", "ProgId", "/t", "REG_SZ", "/d", prog_id, "/f"],
        capture_output=True)

    rollback = {"method": "registry", "keys": rollback_keys, "prog_id": prog_id}
    return True, f"Rejestr HKCU: {ext} → {prog_id}  ({cmd[:50]}…)", rollback

def _ext_windows_remove(ext: str, reg: dict) -> tuple[bool, str]:
    rb   = reg.get("rollback", {})
    keys = rb.get("keys", [])
    removed = []
    for key in keys:
        r = subprocess.run(["reg", "delete", key, "/f"],
                           capture_output=True, text=True)
        if r.returncode == 0:
            removed.append(key.split("\\")[-1])
    if not removed:
        return False, "Brak kluczy rejestru do usunięcia."
    return True, f"Usunięto z rejestru: {len(removed)} kluczy"

# ── Dispatcher ext ────────────────────────────────────────────────────────────

def _ext_add(ext: str, program: "str | None" = None) -> tuple[bool, str]:
    """Główna funkcja rejestracji rozszerzenia."""
    if not ext.startswith("."):
        ext = "." + ext
    ext   = ext.lower()
    mime  = _ext_mime_for(ext)
    sys_n = _ext_detect_system()

    reg   = _ext_load_registry()
    if ext in reg:
        return True, (f"Rozszerzenie {ext} już zarejestrowane "
                      f"(metoda: {reg[ext].get('method','?')}). "
                      f"Usuń najpierw: integrate ext remove {ext}")

    if sys_n == "linux":
        ok, msg, rb = _ext_linux_install(ext, mime)
    elif sys_n == "macos":
        ok, msg, rb = _ext_macos_install(ext, mime)
    elif sys_n == "windows":
        ok, msg, rb = _ext_windows_install(ext, program)
        mime = ""  # Windows nie używa MIME
    else:
        return False, f"Nieobsługiwany system: {sys_n}"

    if ok:
        reg[ext] = {
            "program":    program,
            "system":     sys_n,
            "mime":       mime,
            "method":     sys_n,
            "registered": datetime.datetime.now().isoformat(timespec="seconds"),
            "rollback":   rb,
        }
        _ext_save_registry(reg)

    return ok, msg

def _ext_remove(ext: str) -> tuple[bool, str]:
    if not ext.startswith("."):
        ext = "." + ext
    reg = _ext_load_registry()
    if ext not in reg:
        return False, f"Rozszerzenie {ext} nie jest zarejestrowane przez TerminalX."

    entry  = reg[ext]
    sys_n  = entry.get("system", _ext_detect_system())

    if sys_n == "linux":
        ok, msg = _ext_linux_remove(ext, entry)
    elif sys_n == "macos":
        ok, msg = _ext_macos_remove(ext, entry)
    elif sys_n == "windows":
        ok, msg = _ext_windows_remove(ext, entry)
    else:
        ok, msg = False, f"Nieobsługiwany system: {sys_n}"

    if ok:
        del reg[ext]
        _ext_save_registry(reg)

    return ok, msg

def _ext_open(filepath: str) -> tuple[bool, str]:
    """Otwiera plik zarejestrowanym handlerem TerminalXa lub domyślnym."""
    p   = Path(filepath).expanduser().resolve()
    ext = p.suffix.lower()
    reg = _ext_load_registry()

    if not p.exists():
        return False, f"Plik nie istnieje: {p}"

    if ext in reg:
        program = reg[ext].get("program")
        if program:
            subprocess.Popen([program, str(p)])
            return True, f"Otwarto {p.name} przez {program}"
        else:
            # Domyślnie: cat (podgląd w terminalu)
            import io, contextlib
            buf = io.StringIO()
            with contextlib.redirect_stdout(buf):
                execute_line(f"cat {shlex.quote(str(p))}")
            print(buf.getvalue(), end="")
            return True, f"Podgląd: {p.name}"

    # Brak rejestracji — spróbuj xdg-open / open / start
    for opener in (["xdg-open"], ["open"], ["start", ""]):
        if shutil.which(opener[0]):
            subprocess.Popen(opener + [str(p)])
            return True, f"Otwarto przez {opener[0]}: {p.name}"

    return False, f"Brak handlera dla {ext} — zarejestruj: integrate ext add {ext}"

# ── Context menu ──────────────────────────────────────────────────────────────
#
#   Linux (Nautilus / Thunar / Dolphin):
#     ~/.local/share/nautilus/scripts/  — skrypt wykonywalny
#     ~/.config/Thunar/uca.xml          — UserCustomActions
#     ~/.local/share/kservices5/        — KDE ServiceMenu .desktop
#   macOS:
#     ~/Library/Services/               — Automator quick action (.workflow)
#     Szybka akcja przez AppleScript
#   Windows:
#     HKCU\Software\Classes\*\shell\    — wpis dla wszystkich plików

_CONTEXT_REGISTRY_FILE = _BASE / ".terminalx_context_registry.json"

def _ctx_load() -> dict:
    if _CONTEXT_REGISTRY_FILE.exists():
        try:
            return json.loads(
                _CONTEXT_REGISTRY_FILE.read_text(encoding="utf-8"))
        except Exception:  # ignorowane celowo
            pass
    return {}

def _ctx_save(data: dict):
    _CONTEXT_REGISTRY_FILE.write_text(
        json.dumps(data, indent=2, ensure_ascii=False), encoding="utf-8")

def _ctx_linux_install() -> tuple[bool, list[str], dict]:
    """Instaluje pozycję menu kontekstowego na Linux (Nautilus + Thunar + KDE)."""
    home    = _integ_home()
    script  = _integ_script_path()
    py      = shutil.which("python3") or sys.executable
    cmd_run = f"{py} {script}"
    results = []
    rb      = {}

    # ── Nautilus scripts ──────────────────────────────────────────────────
    naut_d = home / ".local" / "share" / "nautilus" / "scripts"
    naut_d.mkdir(parents=True, exist_ok=True)
    naut_f = naut_d / "Otwórz w TerminalX"
    naut_content = (
        "#!/bin/bash\n"
        "# TerminalX Nautilus script\n"
        "# Otwiera zaznaczone pliki w TerminalX\n"
        f'for f in "$@"; do\n'
        f'  {cmd_run} "$f" &\n'
        f'done\n'
    )
    naut_f.write_text(naut_content, encoding="utf-8")
    naut_f.chmod(0o755)
    results.append(f"Nautilus: {naut_f}")
    rb["nautilus"] = str(naut_f)

    # ── Thunar Custom Actions ─────────────────────────────────────────────
    thunar_uca = home / ".config" / "Thunar" / "uca.xml"
    if thunar_uca.parent.exists():
        marker    = "TerminalX-open"
        action_id = f"TerminalX-open-{_integ_timestamp()}"
        if not _integ_block_present(thunar_uca, marker):
            uca_entry = (
                f'<action id="{action_id}">\n'
                f'  <icon>utilities-terminal</icon>\n'
                f'  <name>Otwórz w TerminalX</name>\n'
                f'  <command>{cmd_run} %f</command>\n'
                f'  <description>Otwiera plik w TerminalX</description>\n'
                f'  <patterns>*</patterns>\n'
                f'  <other-files/>\n'
                f'</action>\n'
            )
            # Dodaj przed </actions> lub utwórz plik
            if thunar_uca.exists():
                _integ_backup(thunar_uca)
                text = thunar_uca.read_text(encoding="utf-8")
                if "</actions>" in text:
                    text = text.replace("</actions>",
                                        f"  {uca_entry}</actions>")
                    thunar_uca.write_text(text, encoding="utf-8")
                    results.append(f"Thunar UCA: {thunar_uca.name}")
                    rb["thunar"] = str(thunar_uca)
            else:
                xml = (
                    '<?xml version="1.0" encoding="UTF-8"?>\n'
                    '<actions>\n'
                    f'  {uca_entry}'
                    '</actions>\n'
                )
                thunar_uca.write_text(xml, encoding="utf-8")
                results.append(f"Thunar UCA (nowy): {thunar_uca.name}")
                rb["thunar"] = str(thunar_uca)

    # ── KDE Dolphin ServiceMenu ───────────────────────────────────────────
    kde_srv = home / ".local" / "share" / "kservices5"
    if not kde_srv.exists():
        kde_srv = home / ".local" / "share" / "kio" / "servicemenus"
    kde_srv.mkdir(parents=True, exist_ok=True)
    kde_f = kde_srv / "TerminalX-open.desktop"
    kde_content = (
        "[Desktop Entry]\n"
        "Type=Service\n"
        "ServiceTypes=KonqPopupMenu/Plugin\n"
        "MimeType=all/all;\n"
        f"Actions=OpenInMiniShell\n\n"
        f"[Desktop Action OpenInMiniShell]\n"
        f"Name=Otwórz w TerminalX\n"
        f"Icon=utilities-terminal\n"
        f"Exec={cmd_run} %f\n"
    )
    kde_f.write_text(kde_content, encoding="utf-8")
    kde_f.chmod(0o755)
    results.append(f"KDE ServiceMenu: {kde_f.name}")
    rb["kde"] = str(kde_f)

    return True, results, rb

def _ctx_linux_remove(rb: dict) -> tuple[bool, str]:
    removed = []
    for key in ("nautilus", "kde"):
        p = Path(rb[key]) if key in rb else None
        if p and p.exists():
            p.unlink()
            removed.append(p.name)
    # Thunar — wymagałoby parsowania XML, więc tylko backup + info
    if "thunar" in rb:
        removed.append(f"Thunar: usuń ręcznie wpis z {rb['thunar']}")
    return bool(removed), "  ".join(removed) if removed else "Brak plików"

def _ctx_macos_install() -> tuple[bool, list[str], dict]:
    """Tworzy Automator quick action lub AppleScript service na macOS."""
    home    = _integ_home()
    script  = _integ_script_path()
    py      = shutil.which("python3") or sys.executable
    rb      = {}
    results = []

    services_d = home / "Library" / "Services"
    services_d.mkdir(parents=True, exist_ok=True)

    # Zapisz skrypt AppleScript (plik .scpt źródłowy + instrukcja)
    ascript_f = services_d / "Open in TerminalX.applescript"
    ascript_content = (
        '-- TerminalX macOS Service\n'
        '-- Umieść ten skrypt w: ~/Library/Services/\n'
        '-- Następnie skompiluj: osacompile -o "Open in TerminalX.workflow" tego_pliku\n'
        'on run {input, parameters}\n'
        '    repeat with fileItem in input\n'
        f'        set filePath to POSIX path of fileItem\n'
        f'        do shell script "{py} {script} " & quoted form of filePath\n'
        '    end repeat\n'
        'end run\n'
    )
    ascript_f.write_text(ascript_content, encoding="utf-8")
    results.append(f"AppleScript: {ascript_f.name}")
    rb["applescript"] = str(ascript_f)

    # Spróbuj skompilować przez osacompile
    workflow_f = services_d / "Open in TerminalX.workflow"
    if shutil.which("osacompile"):
        r = subprocess.run(
            ["osacompile", "-o", str(workflow_f), str(ascript_f)],
            capture_output=True, text=True)
        if r.returncode == 0:
            results.append(f"Workflow skompilowany: {workflow_f.name}")
            rb["workflow"] = str(workflow_f)

    return True, results, rb

def _ctx_macos_remove(rb: dict) -> tuple[bool, str]:
    removed = []
    for key in ("applescript", "workflow"):
        p = Path(rb[key]) if key in rb else None
        if p and p.exists():
            p.unlink()
            removed.append(p.name)
    return bool(removed), ", ".join(removed) if removed else "Brak plików"

def _ctx_windows_install() -> tuple[bool, list[str], dict]:
    """Dodaje 'Otwórz w TerminalX' do menu kontekstowego HKCU (bez admina)."""
    if not shutil.which("reg"):
        return False, ["Brak reg.exe"], {}

    script  = _integ_script_path()
    py      = shutil.which("python") or shutil.which("python3") or sys.executable
    cmd     = f'"{py}" "{script}" "%1"'
    results = []
    rb_keys = []

    # Dodaj do menu dla wszystkich plików (*)
    for key_path in [
        r"HKCU\Software\Classes\*\shell\OpenWithMiniShell",
        r"HKCU\Software\Classes\*\shell\OpenWithMiniShell\command",
    ]:
        val = "Otwórz w TerminalX" if "command" not in key_path else cmd
        r   = subprocess.run(
            ["reg", "add", key_path, "/ve", "/d", val, "/f"],
            capture_output=True, text=True)
        if r.returncode == 0:
            rb_keys.append(key_path)
            results.append(f"HKCU: {key_path.split(chr(92))[-1]}")

    # Dodaj ikonę terminala
    icon_key = r"HKCU\Software\Classes\*\shell\OpenWithMiniShell"
    subprocess.run(
        ["reg", "add", icon_key, "/v", "Icon", "/d",
         r"C:\Windows\System32\cmd.exe,0", "/f"],
        capture_output=True)

    rb = {"keys": rb_keys}
    return bool(rb_keys), results, rb

def _ctx_windows_remove(rb: dict) -> tuple[bool, str]:
    keys = rb.get("keys", [])
    # Usuń od najgłębszego klucza
    removed = []
    for key in reversed(keys):
        r = subprocess.run(["reg", "delete", key, "/f"],
                           capture_output=True, text=True)
        if r.returncode == 0:
            removed.append(key.split("\\")[-1])
    return bool(removed), f"Usunięto {len(removed)} kluczy rejestru"

def _ctx_install() -> tuple[bool, str]:
    sys_n = _ext_detect_system()
    data  = _ctx_load()

    if data.get("installed"):
        return True, f"Menu kontekstowe już zainstalowane ({data.get('system','?')})."

    if sys_n == "linux":
        ok, msgs, rb = _ctx_linux_install()
    elif sys_n == "macos":
        ok, msgs, rb = _ctx_macos_install()
    elif sys_n == "windows":
        ok, msgs, rb = _ctx_windows_install()
    else:
        return False, f"Nieobsługiwany system: {sys_n}"

    if ok:
        data = {
            "installed":  True,
            "system":     sys_n,
            "registered": datetime.datetime.now().isoformat(timespec="seconds"),
            "rollback":   rb,
        }
        _ctx_save(data)

    sep = "\n  "
    msg_str = sep.join(msgs) if isinstance(msgs, list) else msgs
    return ok, msg_str

def _ctx_remove() -> tuple[bool, str]:
    data  = _ctx_load()
    sys_n = data.get("system", _ext_detect_system())
    rb    = data.get("rollback", {})

    if not data.get("installed"):
        return False, "Menu kontekstowe nie jest zainstalowane przez TerminalX."

    if sys_n == "linux":
        ok, msg = _ctx_linux_remove(rb)
    elif sys_n == "macos":
        ok, msg = _ctx_macos_remove(rb)
    elif sys_n == "windows":
        ok, msg = _ctx_windows_remove(rb)
    else:
        ok, msg = False, f"Nieobsługiwany system: {sys_n}"

    if ok:
        _CONTEXT_REGISTRY_FILE.unlink(missing_ok=True)

    return ok, msg

def _ctx_status() -> dict:
    data  = _ctx_load()
    sys_n = _ext_detect_system()
    return {
        "installed": data.get("installed", False),
        "system":    sys_n,
        "detail":    (f"aktywne od {data.get('registered','?')}"
                      if data.get("installed") else "nie zainstalowane"),
        "rollback":  data.get("rollback", {}),
    }

# ── Drag & Drop ───────────────────────────────────────────────────────────────
#
#   Trzy tryby:
#   1. integrate drop              — uruchom shell z plikami z argv (drop target)
#   2. integrate drop daemon       — czytaj ścieżki z stdin (jedna na linię)
#   3. integrate drop test <f…>    — symuluj drop z podanymi plikami
#
#   Integracja z menadżerami plików:
#   - Linux/Nautilus: skrypt w ~/.local/share/nautilus/scripts/ już akceptuje %@
#   - Linux/xterm/konsole: xdrop — plik .desktop z Exec=... %F
#   - macOS: Automator "Run Shell Script" z "Pass input as arguments"
#   - Windows: przeciąganie na ikonę .bat (shell=true, %*)
#   - Każdy tryb: wypisuje co będzie zrobione, pyta użytkownika

_DROP_HANDLERS: dict[str, "callable"] = {}   # ext → fn(path)

def _drop_register_handler(ext: str, fn: "callable"):
    """Rejestruje handler dla danego rozszerzenia (do użycia z API)."""
    _DROP_HANDLERS[ext.lower()] = fn

def _drop_default_handler(path: Path) -> int:
    """Domyślny handler dla przeciągniętych plików."""
    ext = path.suffix.lower()
    reg = _ext_load_registry()

    print(f"\n  {C.INFO}📎 Plik:{C.RESET}  {C.PATH}{path}{C.RESET}")
    print(f"  {C.DIM}Rozmiar: {_nav_file_size(path)}  "
          f"Typ: {ext or '(brak rozszerzenia)'}{C.RESET}\n")

    # Znajdź akcję
    if ext in _DROP_HANDLERS:
        return _DROP_HANDLERS[ext](path)

    if ext in reg:
        program = reg[ext].get("program")
        if program:
            subprocess.Popen([program, str(path)])
            print_info(f"Otwarto przez {program}: {path.name}")
            return 0

    # Menu akcji dla nieznanych plików
    w = min(terminal_width() - 2, 60)
    actions = [
        ("cat",  f"📄  Podgląd (cat)"),
        ("nano", f"✏️   Edytuj (nano-lite)"),
        ("finfo",f"🔍  Metadane (finfo)"),
        ("hash", f"#️⃣   Suma kontrolna (sha256)"),
        ("skip", f"↩   Pomiń"),
    ]
    print(box_top(f"  Akcja dla: {path.name}  ", width=w, color=C.INFO))
    for i, (key, label) in enumerate(actions, 1):
        print(box_row(f"  {C.INFO}{i}{C.RESET}.  {label}", width=w, color=C.INFO))
    print(box_bottom(width=w, color=C.INFO))

    try:
        ans = input(f"  {C.PROMPT}Wybierz [1–{len(actions)}]: {C.RESET}").strip()
        idx = int(ans) - 1
        if 0 <= idx < len(actions):
            key, _ = actions[idx]
            if key == "skip":
                return 0
            import io, contextlib
            buf = io.StringIO()
            with contextlib.redirect_stdout(buf):
                execute_line(f"{key} {shlex.quote(str(path))}")
            print(buf.getvalue(), end="")
            return 0
    except (ValueError, EOFError, KeyboardInterrupt):
        pass

    return 0

def _drop_process_files(paths: list[str]) -> int:
    """Przetwarza listę przeciągniętych plików."""
    if not paths:
        print_info("Brak plików do przetworzenia.")
        return 0

    w = min(terminal_width() - 2, 72)
    print()
    print(box_top(f"  📥 drag & drop — {len(paths)} plik(ów)  ", width=w, color=C.PATH))
    for i, p in enumerate(paths, 1):
        name = Path(p).name if Path(p).exists() else p
        exists_mark = C.OK if Path(p).exists() else C.ERROR
        print(box_row(
            f"  {exists_mark}{i}.{C.RESET}  {C.PATH}{name}{C.RESET}"
            f"  {C.DIM}{p[:w-30]}{C.RESET}",
            width=w, color=C.PATH))
    print(box_bottom(width=w, color=C.PATH))

    errors = 0
    for p_str in paths:
        p = Path(p_str).expanduser().resolve()
        if not p.exists():
            print_error(f"Plik nie istnieje: {p_str}")
            errors += 1
            continue
        rc = _drop_default_handler(p)
        if rc != 0:
            errors += 1

    if errors:
        print(f"\n  {C.WARN}⚠ {errors} plik(ów) z błędem.{C.RESET}")
    else:
        print(f"\n  {C.OK}✔ Przetworzono {len(paths)} plik(ów).{C.RESET}")
    return errors

def _drop_daemon_mode():
    """
    Tryb daemon: czyta ścieżki plików z stdin (po jednej na linię).
    Użycie: echo '/path/to/file.py' | python3 TerminalX.py --drop
    lub:    integrate drop daemon
    """
    w = min(terminal_width() - 2, 72)
    print()
    print(box_top("  📡 drop daemon — nasłuchuję na stdin…  ", width=w, color=C.INFO))
    print(box_row(
        f"  {C.DIM}Wpisz ścieżkę pliku i naciśnij Enter.  "
        f"Ctrl+D / Ctrl+C = wyjście.{C.RESET}",
        width=w, color=C.INFO))
    print(box_bottom(width=w, color=C.INFO))

    try:
        for line in sys.stdin:
            path_str = line.strip()
            if not path_str:
                continue
            # Odfiltruj wielokrotne ścieżki (np. przeciągane z Nautilusa)
            paths = [p for p in _RE_DROP_SPLIT.split(path_str)
                     if p.strip()]
            if not paths:
                paths = [path_str]
            _drop_process_files(paths)
    except KeyboardInterrupt:
        pass
    print(f"\n  {C.DIM}drop daemon zakończony.{C.RESET}\n")

def _drop_create_target_desktop() -> tuple[bool, str]:
    """
    Tworzy plik .desktop który działa jako drop target (Linux).
    Przeciągnięcie pliku na ikonę na pulpicie uruchomi TerminalX z tym plikiem.
    """
    if sys.platform not in ("linux", "linux2"):
        return False, "Drop target .desktop jest tylko dla Linux."

    script  = _integ_script_path()
    py      = shutil.which("python3") or sys.executable
    home    = _integ_home()
    desktop = home / "Desktop"
    target  = (desktop if desktop.is_dir()
               else home / ".local" / "share" / "applications")
    target.mkdir(parents=True, exist_ok=True)

    # Znajdź terminal
    term = next((t for t in ("gnome-terminal","konsole","xterm","alacritty","kitty")
                 if shutil.which(t)), "xterm")

    drop_desktop = target / "TerminalX-drop.desktop"
    content = (
        "[Desktop Entry]\n"
        "Version=1.0\n"
        "Type=Application\n"
        "Name=TerminalX (drop tu pliki)\n"
        "Comment=Przeciągnij pliki na tę ikonę aby otworzyć je w TerminalX\n"
        f"Exec={term} -e {py} {script} %F\n"
        "Icon=utilities-terminal\n"
        "Terminal=false\n"
        "MimeType=all/all;\n"
        "Categories=System;\n"
        "StartupNotify=false\n"
    )
    drop_desktop.write_text(content, encoding="utf-8")
    drop_desktop.chmod(0o755)
    return True, f"Drop target stworzony: {drop_desktop}"

# ── Rozszerzenie komendy integrate ───────────────────────────────────────────
#   Podpinamy nowe podkomendy do istniejącego cmd_integrate.
#   Nie modyfikujemy oryginalnej funkcji — tworzymy nakładkę.

def _integrate_ext_handler(args: list):
    """Obsługa: integrate ext <sub> [args…]"""
    sub = args[0] if args else "list"
    w   = min(terminal_width() - 2, 72)

    if sub == "list":
        reg = _ext_load_registry()
        print()
        print(box_top("  🗂️  Zarejestrowane rozszerzenia plików  ", width=w, color=C.INFO))
        if not reg:
            print(box_row(f"  {C.DIM}Brak. Dodaj: integrate ext add .ext{C.RESET}",
                          width=w, color=C.INFO))
        else:
            for ext, info in sorted(reg.items()):
                row = (f"  {C.INFO}{ext:<10}{C.RESET}  "
                       f"{C.DIM}{info.get('mime',''):<35}  "
                       f"{info.get('system','?')}  "
                       f"{info.get('registered','?')[:16]}{C.RESET}")
                print(box_row(row, width=w, color=C.INFO))
        print(box_row(
            f"  {C.DIM}add .ext [program] | remove .ext | open <plik>{C.RESET}",
            width=w, color=C.INFO))
        print(box_bottom(width=w, color=C.INFO))
        print()

    elif sub == "add":
        ext     = args[1] if len(args) >= 2 else ""
        program = args[2] if len(args) >= 3 else None
        if not ext:
            print_error("Podaj rozszerzenie: integrate ext add .ext [program]")
            return
        ok, msg = _ext_add(ext, program)
        (print_info if ok else print_error)(msg)
        if ok:
            print(f"  {C.DIM}Cofnij: integrate ext remove {ext}{C.RESET}")

    elif sub == "remove":
        ext = args[1] if len(args) >= 2 else ""
        if not ext:
            print_error("Podaj rozszerzenie: integrate ext remove .ext")
            return
        ok, msg = _ext_remove(ext)
        (print_info if ok else print_error)(msg)

    elif sub == "open":
        filepath = args[1] if len(args) >= 2 else ""
        if not filepath:
            print_error("Podaj plik: integrate ext open <plik>")
            return
        ok, msg = _ext_open(filepath)
        (print_info if ok else print_error)(msg)

    elif sub == "status":
        reg = _ext_load_registry()
        sys_n = _ext_detect_system()
        print_info(f"System: {sys_n}  |  Zarejestrowanych rozszerzeń: {len(reg)}")
        for ext in sorted(reg):
            print(f"  {C.INFO}{ext}{C.RESET}  "
                  f"{C.DIM}{reg[ext].get('mime','')}{C.RESET}")
    else:
        print_error(f"Nieznana podkomenda: ext {sub}",
                    "Dostępne: list | add .ext [program] | remove .ext | open <plik> | status")

def _integrate_context_handler(args: list):
    """Obsługa: integrate context <sub>"""
    sub = args[0] if args else "status"

    if sub == "install":
        ok, msg = _ctx_install()
        (print_info if ok else print_error)(msg)
        if ok:
            print(f"  {C.DIM}Cofnij: integrate context remove{C.RESET}")
            if sys.platform.startswith("linux"):
                print(f"  {C.DIM}Może być potrzebne ponowne uruchomienie menadżera plików.{C.RESET}")

    elif sub == "remove":
        ok, msg = _ctx_remove()
        (print_info if ok else print_error)(msg)

    elif sub == "status":
        st = _ctx_status()
        icon = C.OK if st["installed"] else C.DIM
        print_info(
            f"Menu kontekstowe: {icon}{'aktywne' if st['installed'] else 'nieaktywne'}"
            f"{C.RESET}  ({st['detail']})")

    else:
        print_error(f"Nieznana podkomenda: context {sub}",
                    "Dostępne: install | remove | status")

def _integrate_drop_handler(args: list):
    """Obsługa: integrate drop [daemon|test|target|help]"""
    sub = args[0] if args else ""

    if sub == "daemon":
        _drop_daemon_mode()

    elif sub == "test":
        files = args[1:] if len(args) >= 2 else []
        if not files:
            print_error("Podaj pliki: integrate drop test <plik1> [plik2…]")
            return
        _drop_process_files(files)

    elif sub == "target":
        # Utwórz drop target .desktop na pulpicie
        ok, msg = _drop_create_target_desktop()
        (print_info if ok else print_error)(msg)

    elif sub in ("", "help"):
        w = min(terminal_width() - 2, 70)
        print()
        print(box_top("  📥 integrate drop — obsługa drag & drop  ", width=w, color=C.PATH))
        rows = [
            ("integrate drop test <plik…>",
             "Symuluj przeciągnięcie pliku — podgląd/akcja"),
            ("integrate drop daemon",
             "Czytaj ścieżki z stdin (potokowanie z menadżera)"),
            ("integrate drop target",
             "Stwórz ikonę drop target na pulpicie (Linux)"),
            ("integrate context install",
             "'Otwórz w TerminalX' w menu prawego przycisku"),
            ("integrate ext add .ext",
             "Zarejestruj obsługę rozszerzenia pliku"),
        ]
        for cmd_s, desc in rows:
            print(box_row(
                f"  {C.INFO}{cmd_s:<38}{C.RESET}  {C.DIM}{desc}{C.RESET}",
                width=w, color=C.PATH))
        print(box_row(
            f"  {C.DIM}Uruchom TerminalX z plikiem: "
            f"python3 TerminalX.py plik.py{C.RESET}",
            width=w, color=C.PATH))
        print(box_bottom(width=w, color=C.PATH))
        print()

    else:
        # Traktuj jako ścieżkę do pliku (bezpośrednie upuszczenie)
        files = [sub] + args[1:]
        _drop_process_files(files)

# ── Patch cmd_integrate o nowe podkomendy ────────────────────────────────────
# CommandDef używa .func (nie .fn) i nie jest namedtuple — przypisujemy bezpośrednio.

_orig_integrate_func = None
if "integrate" in BUILTINS:
    _orig_integrate_func = BUILTINS["integrate"].func

def _patched_integrate(args: list):
    """Rozszerzona wersja integrate z obsługą ext / context / drop."""
    sub = args[0] if args else "status"

    if sub == "ext":
        _integrate_ext_handler(args[1:])
        return

    if sub == "context":
        _integrate_context_handler(args[1:])
        return

    if sub == "drop":
        _integrate_drop_handler(args[1:])
        return

    # Przekaż do oryginalnej funkcji
    if _orig_integrate_func:
        _orig_integrate_func(args)

# Zastąp func w rejestrze BUILTINS (CommandDef jest klasą — można przypisać)
if "integrate" in BUILTINS:
    BUILTINS["integrate"].func = _patched_integrate
    for alias in ("install", "sysintegrate"):
        if alias in BUILTINS:
            BUILTINS[alias].func = _patched_integrate

# ── Obsługa pliku jako argumentu startowego (drag & drop z systemu) ──────────
#   Gdy TerminalX uruchomiono z argumentem będącym ścieżką pliku,
#   uruchom tryb drop zamiast normalnego shella.

def _startup_drop_check() -> bool:
    """
    Sprawdza czy TerminalX uruchomiono z plikiem jako argumentem
    (np. przez przeciągnięcie na ikonę lub podwójne kliknięcie).
    Zwraca True jeśli przechwycono drop — main() powinien wtedy nie startować.
    """
    # Filtruj znane flagi shella
    _KNOWN_FLAGS = {"--safe", "--recovery", "--rescue", "--drop", "--daemon"}
    file_args = [a for a in sys.argv[1:] if a not in _KNOWN_FLAGS
                 and not a.startswith("--") and Path(a).exists()]

    if "--drop" in sys.argv or "--daemon" in sys.argv:
        if "--daemon" in sys.argv:
            _drop_daemon_mode()
        else:
            _drop_process_files(file_args or [])
        return True

    if file_args:
        # Uruchomiono z plikami — tryb drop
        _drop_process_files(file_args)
        try:
            ans = input(
                f"\n  {C.DIM}Otwórz shell po przetworzeniu? [t/N]: {C.RESET}"
            ).strip().lower()
            return ans not in ("t", "y", "tak", "yes")
        except (EOFError, KeyboardInterrupt):
            return True

    return False

@command("recovery", "Tryb awaryjny — diagnostyka i naprawa TerminalXa",
         aliases=["safe", "rescue", "repair"],
         flags=["status","enter","exit","diagnose","fix","backup","log","health"])
def cmd_recovery(args):
    """
    recovery status           — stan trybu awaryjnego
    recovery enter            — wejdź w tryb awaryjny ręcznie
    recovery exit             — wyjdź z trybu awaryjnego
    recovery diagnose         — pełna diagnostyka: pliki + środowisko + terminal
    recovery health           — szybki test zdrowia shella
    recovery fix config       — inteligentna naprawa JSON (repair → rescue → reset)
    recovery fix aliases      — wyczyść aliasy
    recovery fix history      — wyczyść historię komend
    recovery fix plugins      — wyłącz wszystkie pluginy
    recovery fix all          — reset do stanu fabrycznego (z kopią zapasową!)
    recovery backup create [etykieta]  — utwórz kopię zapasową
    recovery backup list      — lista kopii zapasowych
    recovery backup restore <id>       — przywróć kopię zapasową
    recovery log              — ostatnie błędy z crashloga
    """
    sub = args[0] if args else "status"

    # ── status ────────────────────────────────────────────────────────────
    if sub == "status":
        w = min(terminal_width() - 2, 66)
        print()
        if _RECOVERY_ACTIVE:
            print(box_top("⚠  TRYB AWARYJNY AKTYWNY", width=w, color=C.ERROR))
            print(box_row(
                f"  {C.ERROR}Powód:{C.RESET} {_RECOVERY_REASON}",
                width=w, color=C.ERROR))
        else:
            print(box_top("Tryb awaryjny — stan normalny ✔", width=w, color=C.PATH))
            print(box_row(
                f"  {C.PATH}Shell działa w trybie normalnym.{C.RESET}",
                width=w, color=C.PATH))
        color = C.ERROR if _RECOVERY_ACTIVE else C.PATH

        # Ostatnie błędy
        if _RECOVERY_TRIGGERS:
            print(box_sep(width=w, color=color))
            print(box_row(f"  {C.BOLD}Ostatnie zdarzenia:{C.RESET}", width=w, color=color))
            for t in _RECOVERY_TRIGGERS[-6:]:
                print(box_row(f"  {C.DIM}{t[:w-6]}{C.RESET}", width=w, color=color))

        # Licznik błędów w oknie
        now = _time.time()
        recent = [t for t in _RECOVERY_CRASH_TIMES
                  if (now - t) <= _RECOVERY_CRASH_WINDOW]
        print(box_sep(width=w, color=color))
        print(box_row(
            kv_row("  Błędy (okno)",
                   f"{len(recent)} / {_RECOVERY_CRASH_THRESHOLD} "
                   f"(ostatnie {_RECOVERY_CRASH_WINDOW:.0f}s)",
                   key_w=16),
            width=w, color=color))
        print(box_row(
            kv_row("  Wersja", SHELL_VERSION, key_w=16),
            width=w, color=color))
        print(box_row(
            kv_row("  Dane", str(_BASE), key_w=16),
            width=w, color=color))

        if _RECOVERY_ACTIVE:
            print(box_sep(width=w, color=color))
            print(box_row(
                f"  {C.DIM}Dostępne komendy: "
                f"{', '.join(sorted(_RECOVERY_SAFE_COMMANDS))}{C.RESET}",
                width=w, color=color))
            print(box_row(
                f"  {C.DIM}Wyjście: recovery exit  |  "
                f"Naprawa: recovery fix all{C.RESET}",
                width=w, color=color))
        else:
            print(box_row(
                f"  {C.DIM}Ręczne wejście: recovery enter  |  "
                f"Diagnostyka: recovery diagnose{C.RESET}",
                width=w, color=color))
        print(box_bottom(width=w, color=color))
        print()
        return

    # ── enter ─────────────────────────────────────────────────────────────
    if sub == "enter":
        if _RECOVERY_ACTIVE:
            print_info("Tryb awaryjny już jest aktywny.")
            return
        try:
            ans = input(
                f"  {C.ERROR}Wejść w tryb awaryjny? "
                f"Większość funkcji zostanie wyłączona. [t/n]: {C.RESET}"
            ).strip().lower()
        except (EOFError, KeyboardInterrupt):
            print(); return
        if ans in ("t", "y", "tak", "yes"):
            recovery_enter(reason="ręczne (użytkownik)")
            print(f"\n  {C.ERROR}⚠  Tryb awaryjny aktywny.{C.RESET}")
            print(f"  {C.DIM}Prompt zmieni się na [SAFE].{C.RESET}")
            print(f"  {C.DIM}Wyjście: recovery exit{C.RESET}\n")
        return

    # ── exit ──────────────────────────────────────────────────────────────
    if sub == "exit":
        if not _RECOVERY_ACTIVE:
            print_info("Tryb awaryjny nie jest aktywny.")
            return
        recovery_exit()
        print_info("Wyjście z trybu awaryjnego — shell wraca do trybu normalnego.")
        print(f"  {C.DIM}Zalecany restart: exit + ponowne uruchomienie{C.RESET}")
        return

    # ── diagnose ──────────────────────────────────────────────────────────
    if sub == "diagnose":
        w       = min(terminal_width() - 2, 70)
        results = _recovery_diagnose()
        errors  = [r for r in results if not r["ok"]]
        print()
        title = (f"Diagnostyka shella  ({'⚠ ' + str(len(errors)) + ' błędów' if errors else '✔ wszystko OK'})")
        col   = C.ERROR if errors else C.PATH
        print(box_top(title, width=w, color=col))
        for r in results:
            icon = f"{C.PATH}✔{C.RESET}" if r["ok"] else f"{C.ERROR}✖{C.RESET}"
            note = r.get("note", "")
            if not r["ok"]:
                note_c = f"{C.ERROR}{note}{C.RESET}"
            else:
                note_c = f"{C.DIM}{note}{C.RESET}"
            print(box_row(
                f"  {icon}  {r['label']:<26} {note_c}",
                width=w, color=col))
        print(box_sep(width=w, color=col))
        if errors:
            print(box_row(
                f"  {C.ERROR}Znaleziono {len(errors)} problemy.{C.RESET}",
                width=w, color=col))
            print(box_row(
                f"  {C.DIM}Napraw: recovery fix all  |  "
                f"Kopia: recovery backup create{C.RESET}",
                width=w, color=col))
        else:
            print(box_row(
                f"  {C.PATH}Shell wygląda zdrowo.{C.RESET}  "
                f"{C.DIM}Jeśli masz problemy: recovery log{C.RESET}",
                width=w, color=col))
        print(box_bottom(width=w, color=col))
        print()
        return

    # ── health ────────────────────────────────────────────────────────────
    if sub == "health":
        results = _recovery_diagnose()
        errors  = [r for r in results if not r["ok"]]
        ok_cnt  = len(results) - len(errors)
        if errors:
            print(f"  {C.ERROR}✖ Health: {len(errors)} problem(y) — {ok_cnt}/{len(results)} OK{C.RESET}")
            for r in errors:
                print(f"    {C.ERROR}• {r['label']}: {r.get('note','')[:60]}{C.RESET}")
            print(f"  {C.DIM}Szczegóły: recovery diagnose  |  Naprawa: recovery fix all{C.RESET}")
        else:
            print(f"  {C.PATH}✔ Health: {ok_cnt}/{len(results)} — wszystko OK{C.RESET}")
        return

    # ── fix ───────────────────────────────────────────────────────────────
    if sub == "fix":
        target = args[1] if len(args) >= 2 else ""

        if target == "config":
            msg = _recovery_fix_config()
            print_info(msg)
            return

        if target == "aliases":
            msg = _recovery_fix_aliases()
            print_info(msg)
            return

        if target == "history":
            msg = _recovery_fix_history()
            print_info(msg)
            return

        if target == "plugins":
            msg = _recovery_fix_plugins()
            print_info(msg)
            return

        if target == "all":
            print(f"\n  {C.ERROR}⚠  RESET DO STANU FABRYCZNEGO{C.RESET}")
            print(f"  {C.DIM}Zostanie utworzona kopia zapasowa przed resetem.{C.RESET}")
            try:
                ans = input(
                    f"  {C.ERROR}Jesteś pewien? [tak/nie]: {C.RESET}"
                ).strip().lower()
            except (EOFError, KeyboardInterrupt):
                print(); return
            if ans not in ("tak", "yes"):
                print_info("Anulowano.")
                return
            msgs = _recovery_fix_all()
            print()
            for m in msgs:
                print(f"  {C.PATH}✔{C.RESET}  {m}")
            print()
            print_info("Reset zakończony. Uruchom ponownie shell: exit")
            if _RECOVERY_ACTIVE:
                recovery_exit()
            return

        print_error(
            f"Nieznany cel naprawy: '{target}'.",
            "Dostępne: config | aliases | history | plugins | all"
        )
        return

    # ── backup ────────────────────────────────────────────────────────────
    if sub == "backup":
        bsub = args[1] if len(args) >= 2 else "list"

        if bsub == "create":
            label = args[2] if len(args) >= 3 else "manual"
            bak = _recovery_backup_create(label=label)
            if bak:
                files_in = list(bak.iterdir())
                n = len([f for f in files_in if f.name != "meta.json"])
                print_info(f"Kopia zapasowa utworzona: {bak.name}  ({n} plików)")
            else:
                print_error("Nie udało się utworzyć kopii zapasowej.")
            return

        if bsub == "list":
            backups = _recovery_backup_list()
            w = min(terminal_width() - 2, 68)
            print()
            print(box_top("Kopie zapasowe TerminalXa", width=w, color=C.DIM))
            if not backups:
                print(box_row(
                    f"  {C.DIM}Brak kopii. Utwórz: recovery backup create{C.RESET}",
                    width=w, color=C.DIM))
            else:
                for b in backups:
                    files_str = ", ".join(b.get("files", []))[:40]
                    row1 = (f"  {C.BOLD}{b['id']}{C.RESET}  "
                            f"{C.DIM}{b.get('created','?')}{C.RESET}  "
                            f"{C.PATH}{b.get('label','')}{C.RESET}")
                    row2 = f"    {C.DIM}v{b.get('version','?')}  Pliki: {files_str}{C.RESET}"
                    print(box_row(row1, width=w, color=C.DIM))
                    print(box_row(row2, width=w, color=C.DIM))
                    print(box_sep(width=w, color=C.DIM))
            print(box_row(
                f"  {C.DIM}recovery backup create [etykieta] | "
                f"recovery backup restore <id>{C.RESET}",
                width=w, color=C.DIM))
            print(box_bottom(width=w, color=C.DIM))
            print()
            return

        if bsub == "restore":
            if len(args) < 3:
                print_error("Podaj ID kopii: recovery backup restore <id>")
                return
            bid = args[2]
            print(f"  {C.ERROR}Przywrócenie nadpisze obecne pliki konfiguracji.{C.RESET}")
            print(f"  {C.DIM}Automatyczna kopia obecnego stanu zostanie wykonana przed przywróceniem.{C.RESET}")
            try:
                ans = input(
                    f"  {C.ERROR}Przywrócić kopię '{bid}'? [t/n]: {C.RESET}"
                ).strip().lower()
            except (EOFError, KeyboardInterrupt):
                print(); return
            if ans not in ("t", "y", "tak", "yes"):
                print_info("Anulowano."); return
            ok, msg = _recovery_backup_restore(bid)
            if ok:
                print_info(f"Przywrócono: {msg}")
                print(f"  {C.DIM}Uruchom ponownie shell aby zmiany weszły w życie: exit{C.RESET}")
            else:
                print_error(f"Przywrócenie nieudane: {msg}")
            return

        print_error(f"Nieznana podkomenda: backup {bsub}",
                    "Dostępne: create | list | restore <id>")
        return

    # ── log ───────────────────────────────────────────────────────────────
    if sub == "log":
        if not CRASHLOG_FILE.exists():
            print_info("Brak crashlogu.")
            return
        try:
            raw   = CRASHLOG_FILE.read_text(encoding="utf-8", errors="replace")
            # Podziel na bloki (każdy zaczyna się od "TERMINALX CRASHLOG")
            blocks = [b.strip() for b in raw.split("TERMINALX CRASHLOG") if b.strip()]
        except Exception as e:
            print_error(f"Błąd odczytu crashlogu: {e}"); return

        w = min(terminal_width() - 2, 72)
        print()
        print(box_top(f"Crashlog — ostatnie {min(5, len(blocks))} z {len(blocks)} błędów",
                      width=w, color=C.ERROR))
        for block in blocks[-5:]:
            lines = block.splitlines()
            print(box_sep(width=w, color=C.ERROR))
            for ln in lines[:8]:
                c = C.ERROR if any(k in ln for k in ("Exception","Error","Traceback")) else C.DIM
                print(box_row(f"  {c}{ln[:w-6]}{C.RESET}", width=w, color=C.ERROR))
            if len(lines) > 8:
                print(box_row(
                    f"  {C.DIM}… (+{len(lines)-8} linii — crashlog show dla pełnej treści){C.RESET}",
                    width=w, color=C.ERROR))
        print(box_bottom(width=w, color=C.ERROR))
        print(f"\n  {C.DIM}Pełny raport: crashlog  |  Wyczyść: crashlog clear{C.RESET}\n")
        return

    print_error(
        f"Nieznana podkomenda: recovery {sub}",
        "Dostępne: status enter exit diagnose health fix backup log"
    )

# ── Integracja z pętlą główną: prompt + blokowanie komend ─────────────────────

def _recovery_main_prompt() -> str:
    """
    Zwraca prompt dla trybu awaryjnego (bez readline escape problemów).
    """
    cwd = Path.cwd().name or "/"
    return f"[SAFE:{cwd}] # "

def _recovery_block_msg(name: str):
    """Wyświetla komunikat o zablokowaniu komendy w trybie awaryjnym."""
    print(f"  {C.ERROR}⚠  Komenda '{name}' jest niedostępna w trybie awaryjnym.{C.RESET}")
    print(f"  {C.DIM}Dostępne: {', '.join(sorted(_RECOVERY_SAFE_COMMANDS))}{C.RESET}")
    print(f"  {C.DIM}Wyjście z trybu: recovery exit  |  "
          f"Naprawa: recovery fix all{C.RESET}")

# ENCODING — obsługa znaków i kodowania
#
#  Centralny moduł obsługi Unicode, ANSI, znaków specjalnych i konwersji
#  między kodowaniami (UTF-8, Windows-1250/cp1250, ISO-8859-2, ASCII).
#
#  Komendy:
#    encode info [plik]          — info o aktualnym środowisku i kodowaniu pliku
#    encode detect <plik>        — wykryj kodowanie pliku (BOM + heurystyka)
#    encode convert <plik> <do>  — konwertuj kodowanie pliku (in-place lub --out)
#    encode fix <plik>           — napraw typowe błędy (mojibake cp1252→utf-8)
#    encode show                 — tabela znaków specjalnych i skróty
#    encode ansi                 — demo kolorów ANSI + test terminala
#    encode unicode <tekst>      — wyświetl code-pointy Unicode dla tekstu
#    encode strip <plik>         — usuń kody ANSI z pliku (do pliku .clean)
#    encode test                 — pełny test obsługi znaków w bieżącym środowisku
#
#  Obsługiwane kodowania:
#    utf-8       — domyślne, zalecane (pełny Unicode)
#    utf-8-bom   — UTF-8 z BOM (Windows Notepad)
#    utf-16-le   — UTF-16 Little Endian (Windows)
#    utf-16-be   — UTF-16 Big Endian
#    cp1250      — Windows-1250 (Środkowa Europa, polskie znaki)
#    iso-8859-2  — Latin-2 (polskie znaki, Linux legacy)
#    iso-8859-1  — Latin-1 (zachodnioeuropejskie)
#    ascii       — tylko ASCII 0-127

# ── Stałe i mapy ─────────────────────────────────────────────────────────────

