# Wzorzec do usuwania ANSI ze stringa/pliku
_ANSI_ESCAPE_RE = re.compile(
    r"\033"          # ESC
    r"\["            # [
    r"[0-9;]*"       # parametry liczbowe
    r"[A-Za-z]"      # litera kończąca sekwencję
    r"|"
    r"\033[()][A-Z0-9]"   # G0/G1 charset
    r"|"
    r"\033[@-Z\\-_]"      # sekwencje 2-znakowe (Fe)
)

# ── Narzędzia kodowania ───────────────────────────────────────────────────────

def _enc_normalize(name: str) -> str:
    """Normalizuje nazwę kodowania do formy kanonicznej."""
    n = name.lower().replace("_", "-").strip()
    return _ENC_ALIASES.get(n, n)

def _enc_detect(raw: bytes) -> tuple[str, float]:
    """
    Wykrywa kodowanie pliku na podstawie BOM i heurystyki bajtowej.
    Zwraca (nazwa_kanoniczna, pewność_0_1).
    Nie wymaga zewnętrznych bibliotek.
    """
    # ── BOM (pewność 1.0) ────────────────────────────────────────────────────
    if raw[:4] == b"\x00\x00\xfe\xff": return ("utf-32-be",  1.0)
    if raw[:4] == b"\xff\xfe\x00\x00": return ("utf-32-le",  1.0)
    if raw[:3] == b"\xef\xbb\xbf":     return ("utf-8-bom",  1.0)
    if raw[:2] == b"\xff\xfe":         return ("utf-16-le",  1.0)
    if raw[:2] == b"\xfe\xff":         return ("utf-16-be",  1.0)

    # ── Próbuj UTF-8 (pewność wysoka jeśli ok) ───────────────────────────────
    try:
        raw.decode("utf-8", errors="strict")
        # Sprawdź czy ma znaki spoza ASCII — jeśli tak, to pewnie UTF-8
        has_non_ascii = any(b > 127 for b in raw[:4096])
        return ("utf-8", 0.95 if has_non_ascii else 0.80)
    except UnicodeDecodeError:
        pass

    # ── Czyste ASCII ─────────────────────────────────────────────────────────
    if all(b < 128 for b in raw[:4096]):
        return ("ascii", 0.99)

    # ── Heurystyka: cp1250 vs iso-8859-2 ─────────────────────────────────────
    # cp1250: polskie znaki w zakresach 0x8x i 0xBx-0xDx
    # iso-8859-2: polskie znaki w 0xB9-0xFF
    sample = raw[:8192]

    # Zakresy bajtów typowe dla cp1250 (polskie znaki)
    cp1250_polish = {0x8C, 0x9C, 0x8F, 0x9F,       # Ś ś Ź ź
                     0xA5, 0xB9,                      # Ą ą
                     0xC6, 0xE6,                      # Ć ć
                     0xCA, 0xEA,                      # Ę ę
                     0xD3, 0xF3,                      # Ó ó
                     0xD1, 0xF1,                      # Ń ń
                     0x8D, 0x9D,                      # Ź ź (alt)
                     0x9A, 0x9E,                      # Ż ż  Ź ź
                    }
    # Zakresy bajtów typowe dla iso-8859-2 (polskie znaki)
    iso2_polish   = {0xA1, 0xB1,                      # Ą ą
                     0xC6, 0xE6,                      # Ć ć
                     0xCA, 0xEA,                      # Ę ę
                     0xD3, 0xF3,                      # Ó ó
                     0xD1, 0xF1,                      # Ń ń
                     0xA6, 0xB6,                      # Ś ś
                     0xAC, 0xBC,                      # Ź ź
                     0xAF, 0xBF,                      # Ż ż
                     0xA3, 0xB3,                      # Ł ł
                    }

    cp_score  = sum(1 for b in sample if b in cp1250_polish)
    iso_score = sum(1 for b in sample if b in iso2_polish)

    if cp_score == 0 and iso_score == 0:
        return ("cp1250", 0.30)   # nieznane — cp1250 jako default Windows

    if cp_score >= iso_score:
        conf = min(0.85, 0.40 + cp_score * 0.05)
        return ("cp1250", conf)
    else:
        conf = min(0.85, 0.40 + iso_score * 0.05)
        return ("iso-8859-2", conf)

def _enc_read_auto(path: Path) -> tuple[str, str, str]:
    """
    Wczytuje plik automatycznie wykrywając kodowanie.
    Zwraca (tekst, kodowanie_wykryte, komunikat_błędu).
    """
    try:
        raw = path.read_bytes()
    except Exception as e:
        return ("", "?", str(e))

    if not raw:
        return ("", "utf-8", "")

    enc_name, _conf = _enc_detect(raw)
    py_enc = _ENC_SUPPORTED.get(enc_name, {}).get("py", enc_name)

    try:
        text = raw.decode(py_enc, errors="replace")
        return (text, enc_name, "")
    except (LookupError, UnicodeDecodeError) as e:
        # Fallback do UTF-8 z replace
        text = raw.decode("utf-8", errors="replace")
        return (text, "utf-8", f"fallback: {e}")

def _enc_convert_file(src: Path, from_enc: str, to_enc: str,
                      out: Path | None = None) -> tuple[bool, str]:
    """
    Konwertuje kodowanie pliku.
    Jeśli out=None, zapisuje in-place (z backupem .enc_bak).
    Zwraca (ok, komunikat).
    """
    from_py = _ENC_SUPPORTED.get(from_enc, {}).get("py", from_enc)
    to_py   = _ENC_SUPPORTED.get(to_enc,   {}).get("py", to_enc)

    try:
        raw  = src.read_bytes()
    except Exception as e:
        return (False, f"Błąd odczytu: {e}")

    # Usuń BOM źródłowy jeśli from_enc go ma
    bom_from = _ENC_SUPPORTED.get(from_enc, {}).get("bom", b"")
    if bom_from and raw.startswith(bom_from):
        raw = raw[len(bom_from):]

    try:
        text = raw.decode(from_py, errors="replace")
    except (LookupError, UnicodeDecodeError) as e:
        return (False, f"Błąd dekodowania ({from_enc}): {e}")

    try:
        out_raw = text.encode(to_py, errors="replace")
    except (LookupError, UnicodeEncodeError) as e:
        return (False, f"Błąd kodowania ({to_enc}): {e}")

    # Dodaj BOM docelowy jeśli wymagany
    bom_to = _ENC_SUPPORTED.get(to_enc, {}).get("bom", b"")
    if bom_to and not out_raw.startswith(bom_to):
        out_raw = bom_to + out_raw

    dest = out or src
    if dest == src:
        # Backup in-place
        bak = src.with_suffix(src.suffix + ".enc_bak")
        try:
            bak.write_bytes(raw if not bom_from else bom_from + raw)
        except Exception:
            pass  # brak backupu nie blokuje konwersji

    try:
        dest.write_bytes(out_raw)
    except Exception as e:
        return (False, f"Błąd zapisu: {e}")

    chars = len(text)
    return (True,
            f"{src.name} → {dest.name}  "
            f"[{from_enc} → {to_enc}]  "
            f"{len(raw)} B → {len(out_raw)} B  "
            f"({chars} znaków)")

def _enc_fix_mojibake(text: str) -> tuple[str, int]:
    """
    Naprawia typowy mojibake: tekst zdekodowany jako cp1252/latin-1
    zamiast UTF-8. Zwraca (naprawiony_tekst, liczba_poprawionych_fragmentów).
    """
    fixed   = 0
    result  = []
    i = 0
    while i < len(text):
        c = text[i]
        o = ord(c)
        # Szukaj sekwencji wielobajtowych UTF-8 zakodowanych jako latin-1/cp1252
        # Sekwencja 2-bajtowa: 0xC2-0xDF + 0x80-0xBF
        if 0xC2 <= o <= 0xDF and i + 1 < len(text):
            o2 = ord(text[i+1])
            if 0x80 <= o2 <= 0xBF:
                try:
                    decoded = bytes([o, o2]).decode("utf-8")
                    result.append(decoded)
                    i += 2
                    fixed += 1
                    continue
                except UnicodeDecodeError:
                    pass
        # Sekwencja 3-bajtowa: 0xE0-0xEF + 2×(0x80-0xBF)
        elif 0xE0 <= o <= 0xEF and i + 2 < len(text):
            o2, o3 = ord(text[i+1]), ord(text[i+2])
            if 0x80 <= o2 <= 0xBF and 0x80 <= o3 <= 0xBF:
                try:
                    decoded = bytes([o, o2, o3]).decode("utf-8")
                    result.append(decoded)
                    i += 3
                    fixed += 1
                    continue
                except UnicodeDecodeError:
                    pass
        result.append(c)
        i += 1
    return "".join(result), fixed

def _enc_strip_ansi(text: str) -> str:
    """Usuwa wszystkie sekwencje ANSI/VT100 ze stringa."""
    return _ANSI_ESCAPE_RE.sub("", text)

def _enc_visible_len(text: str) -> int:
    """Długość stringa bez sekwencji ANSI (widzialna szerokość)."""
    return len(_enc_strip_ansi(text))

def _enc_env_info() -> dict:
    """Zbiera info o środowisku kodowania."""
    import locale as _locale
    stdout_enc = getattr(sys.stdout, "encoding", None) or "?"
    stderr_enc = getattr(sys.stderr, "encoding", None) or "?"
    stdin_enc  = getattr(sys.stdin,  "encoding", None) or "?"
    fs_enc     = sys.getfilesystemencoding() or "?"
    try:
        locale_enc = _locale.getpreferredencoding(False) or "?"
    except Exception:
        locale_enc = "?"

    py_io_enc  = os.environ.get("PYTHONIOENCODING", "")
    term       = os.environ.get("TERM", "")
    colorterm  = os.environ.get("COLORTERM", "")
    lang       = os.environ.get("LANG", "")
    lc_all     = os.environ.get("LC_ALL", "")
    lc_ctype   = os.environ.get("LC_CTYPE", "")

    def _is_utf8(enc: str) -> bool:
        return enc.lower().replace("-", "").replace("_", "") in ("utf8", "utf8sig", "utf8bom")

    return {
        "stdout_enc":   stdout_enc,
        "stderr_enc":   stderr_enc,
        "stdin_enc":    stdin_enc,
        "fs_enc":       fs_enc,
        "locale_enc":   locale_enc,
        "py_io_enc":    py_io_enc,
        "TERM":         term,
        "COLORTERM":    colorterm,
        "LANG":         lang,
        "LC_ALL":       lc_all,
        "LC_CTYPE":     lc_ctype,
        "all_utf8":     all(_is_utf8(e) for e in
                            [stdout_enc, stderr_enc, fs_enc, locale_enc]
                            if e and e != "?"),
        "platform":     sys.platform,
        "python":       sys.version.split()[0],
    }

# ── Komenda encode ────────────────────────────────────────────────────────────

@command("encode", "Obsługa znaków i kodowania: Unicode, ANSI, UTF-8, cp1250",
         aliases=["charset", "enc"],
         flags=["info", "detect", "convert", "fix", "show",
                "ansi", "unicode", "strip", "test"])
def cmd_encode(args):
    """
    Użycie: encode <podkomenda> [argumenty]

    Podkomendy:
      info [plik]           Info o środowisku + opcjonalnie kodowanie pliku
      detect <plik>         Wykryj kodowanie pliku (bez zewnętrznych lib)
      convert <plik> <do>   Konwertuj kodowanie (--out <cel> lub in-place)
      fix <plik>            Napraw mojibake (utf-8 zdekodowane jako latin-1)
      show [kategoria]      Tabela: polish | box | ansi | all
      ansi                  Demo pełnej palety kolorów ANSI
      unicode <tekst>       Wyświetl code-pointy Unicode dla każdego znaku
      strip <plik>          Usuń kody ANSI z pliku (zapisz jako <plik>.clean)
      test                  Pełny test obsługi znaków w tym środowisku
    """
    sub = args[0].lower() if args else "info"

    # ── info ─────────────────────────────────────────────────────────────────
    if sub == "info":
        env = _enc_env_info()
        w   = min(terminal_width() - 2, 70)

        print()
        print(box_top("  🔤 Środowisko kodowania  ", width=w, color=C.PROMPT))

        status_clr = C.OK if env["all_utf8"] else C.WARN
        print(box_row(
            f"  {C.DIM}{'Stan:':<20}{C.RESET}  "
            f"{status_clr}{'UTF-8 wszędzie ✔' if env['all_utf8'] else 'UWAGA: nie wszędzie UTF-8'}{C.RESET}",
            width=w, color=C.PROMPT))
        rows = [
            ("stdout",        env["stdout_enc"]),
            ("stderr",        env["stderr_enc"]),
            ("stdin",         env["stdin_enc"]),
            ("filesystem",    env["fs_enc"]),
            ("locale",        env["locale_enc"]),
            ("PYTHONIOENCODING", env["py_io_enc"] or "(brak)"),
            ("LANG",          env["LANG"] or "(brak)"),
            ("TERM",          env["TERM"] or "(brak)"),
            ("COLORTERM",     env["COLORTERM"] or "(brak)"),
            ("platforma",     f"{env['platform']}  Python {env['python']}"),
        ]
        for label, val in rows:
            ok_mark = C.OK if "utf" in val.lower() else (
                      C.DIM if val in ("?", "(brak)") else C.WARN)
            print(box_row(
                f"  {C.DIM}{label:<20}{C.RESET}  {ok_mark}{val}{C.RESET}",
                width=w, color=C.PROMPT))

        # Ostrzeżenia
        if not env["all_utf8"]:
            print(box_sep(width=w, color=C.WARN))
            print(box_row(
                f"  {C.WARN}⚠  Nie wszystkie strumienie UTF-8.{C.RESET}",
                width=w, color=C.WARN))
            print(box_row(
                f"  {C.DIM}Napraw: export PYTHONIOENCODING=utf-8{C.RESET}",
                width=w, color=C.WARN))
            if env["platform"] == "win32":
                print(box_row(
                    f"  {C.DIM}Windows: chcp 65001 (w CMD) lub chcp 65001 w PowerShell{C.RESET}",
                    width=w, color=C.WARN))

        print(box_sep(width=w, color=C.PROMPT))

        # Opcjonalnie: info o pliku
        file_arg = args[1] if len(args) >= 2 else None
        if file_arg:
            fp = Path(file_arg).expanduser().resolve()
            if fp.exists():
                raw = fp.read_bytes()
                enc_name, conf = _enc_detect(raw)
                print(box_row(
                    f"  {C.BOLD}Plik: {fp.name}{C.RESET}",
                    width=w, color=C.PROMPT))
                print(box_row(
                    f"  {C.DIM}Kodowanie: {C.RESET}{C.INFO}{enc_name}{C.RESET}"
                    f"  {C.DIM}pewność: {conf*100:.0f}%{C.RESET}"
                    f"  {C.DIM}rozmiar: {len(raw)} B{C.RESET}",
                    width=w, color=C.PROMPT))
                desc = _ENC_SUPPORTED.get(enc_name, {}).get("desc", "")
                if desc:
                    print(box_row(
                        f"  {C.DIM}{desc}{C.RESET}",
                        width=w, color=C.PROMPT))
            else:
                print(box_row(
                    f"  {C.ERROR}Plik nie istnieje: {file_arg}{C.RESET}",
                    width=w, color=C.PROMPT))

        print(box_bottom(width=w, color=C.PROMPT))
        print(f"  {C.DIM}encode detect <plik> | encode test | encode ansi{C.RESET}\n")
        return

    # ── detect ───────────────────────────────────────────────────────────────
    if sub == "detect":
        if len(args) < 2:
            print_error("Podaj plik: encode detect <plik>")
            return
        fp = Path(args[1]).expanduser().resolve()
        if not fp.exists():
            print_error(f"Plik nie istnieje: {args[1]}")
            return
        raw = fp.read_bytes()
        if not raw:
            print_info(f"{fp.name}: pusty plik")
            return

        enc_name, conf = _enc_detect(raw)
        py_enc = _ENC_SUPPORTED.get(enc_name, {}).get("py", enc_name)
        desc   = _ENC_SUPPORTED.get(enc_name, {}).get("desc", enc_name)

        # Policz znaki w wykrytym kodowaniu
        try:
            text   = raw.decode(py_enc, errors="replace")
            lines  = text.count("\n")
            chars  = len(text)
            words  = len(text.split())
            pl_cnt = sum(1 for c in text if c in _PL_CHARS)
        except Exception:
            text, lines, chars, words, pl_cnt = "", 0, 0, 0, 0

        # Podgląd (pierwsze 3 linie)
        preview = "\n".join(text.splitlines()[:3])

        w = min(terminal_width() - 2, 70)
        print()
        print(box_top(f"  🔍 Wykrywanie kodowania: {fp.name}  ", width=w, color=C.INFO))
        conf_clr = C.OK if conf >= 0.8 else (C.WARN if conf >= 0.5 else C.ERROR)
        rows_d = [
            ("Wykryte kodowanie", f"{C.BOLD}{enc_name}{C.RESET}"),
            ("Pewność",           f"{conf_clr}{conf*100:.0f}%{C.RESET}"),
            ("Opis",              desc),
            ("Rozmiar",           f"{len(raw)} B"),
            ("Znaki / linie",     f"{chars} / {lines}"),
            ("Słowa",             str(words)),
            ("Polskie znaki",     str(pl_cnt) if pl_cnt > 0 else "brak"),
        ]
        for label, val in rows_d:
            print(box_row(
                f"  {C.DIM}{label:<22}{C.RESET}  {val}",
                width=w, color=C.INFO))

        if preview.strip():
            print(box_sep(width=w, color=C.INFO))
            print(box_row(f"  {C.DIM}Podgląd (3 linie):{C.RESET}", width=w, color=C.INFO))
            for ln in preview.splitlines()[:3]:
                safe = ln[:w - 6]
                print(box_row(f"    {safe}", width=w, color=C.INFO))

        print(box_bottom(width=w, color=C.INFO))
        print(f"  {C.DIM}Konwertuj: encode convert {fp.name} utf-8{C.RESET}\n")
        return

    # ── convert ──────────────────────────────────────────────────────────────
    if sub == "convert":
        if len(args) < 3:
            print_error(
                "Użycie: encode convert <plik> <kodowanie> [--out <cel>]",
                f"Dostępne: {', '.join(sorted(_ENC_SUPPORTED))}")
            return

        fp       = Path(args[1]).expanduser().resolve()
        to_enc   = _enc_normalize(args[2])
        out_flag = "--out" in args
        out_path = None

        if out_flag:
            idx = args.index("--out")
            if idx + 1 >= len(args):
                print_error("Podaj ścieżkę po --out")
                return
            out_path = Path(args[idx + 1]).expanduser().resolve()

        if not fp.exists():
            print_error(f"Plik nie istnieje: {args[1]}")
            return

        if to_enc not in _ENC_SUPPORTED:
            print_error(
                f"Nieznane kodowanie: '{to_enc}'",
                f"Dostępne: {', '.join(sorted(_ENC_SUPPORTED))}")
            return

        raw         = fp.read_bytes()
        from_enc, _ = _enc_detect(raw)

        if from_enc == to_enc and not out_path:
            print_info(f"Plik już jest w kodowaniu {to_enc} — brak zmian.")
            return

        try:
            ans = input(
                f"  {C.INFO}?{C.RESET}  "
                f"Konwertuj {C.BOLD}{fp.name}{C.RESET} "
                f"[{from_enc} → {to_enc}]"
                + (f" → {out_path.name}" if out_path else " (in-place + backup)")
                + f"? [t/n]: "
            ).strip().lower()
        except (EOFError, KeyboardInterrupt):
            print(); return

        if ans not in ("t", "y", "tak", "yes"):
            print_info("Anulowano.")
            return

        ok, msg = _enc_convert_file(fp, from_enc, to_enc, out_path)
        (print_info if ok else print_error)(msg)
        if ok and not out_path:
            print(f"  {C.DIM}Backup: {fp.name}.enc_bak{C.RESET}")
        return

    # ── fix ──────────────────────────────────────────────────────────────────
    if sub == "fix":
        if len(args) < 2:
            print_error("Podaj plik: encode fix <plik>")
            return
        fp = Path(args[1]).expanduser().resolve()
        if not fp.exists():
            print_error(f"Plik nie istnieje: {args[1]}")
            return

        text, enc, err = _enc_read_auto(fp)
        if err:
            print_warn(f"Odczyt z błędem: {err}")

        fixed_text, n_fixed = _enc_fix_mojibake(text)

        if n_fixed == 0:
            print_info(f"Brak mojibake w {fp.name} (kodowanie: {enc}).")
            return

        bak = fp.with_suffix(fp.suffix + ".fix_bak")
        try:
            bak.write_bytes(fp.read_bytes())
        except Exception:  # ignorowane celowo
            pass

        try:
            fp.write_text(fixed_text, encoding="utf-8")
        except Exception as e:
            print_error(f"Błąd zapisu: {e}")
            return

        print_info(f"Naprawiono {n_fixed} sekwencji mojibake w {fp.name}")
        print(f"  {C.DIM}Backup: {bak.name}{C.RESET}")
        return

    # ── show ─────────────────────────────────────────────────────────────────
    if sub == "show":
        cat = args[1].lower() if len(args) >= 2 else "all"
        w   = min(terminal_width() - 2, 72)
        print()

        if cat in ("ansi", "all"):
            print(box_top("  🎨 Kodowania ANSI  ", width=w, color=C.INFO))
            for code, label, example in _ANSI_COLORS[:8]:
                print(box_row(
                    f"  {C.DIM}{label:<18}{C.RESET}  "
                    f"{C.DIM}\\033[{code.lstrip(chr(27)+'['):<5}{C.RESET}  "
                    f"{code}{example}\033[0m",
                    width=w, color=C.INFO))
            print(box_row(
                f"  {C.DIM}Pełna paleta 256 kolorów: encode ansi{C.RESET}",
                width=w, color=C.INFO))
            print(box_bottom(width=w, color=C.INFO))
            print()

        if cat in ("polish", "pl", "all"):
            print(box_top("  🇵🇱 Polskie znaki (Unicode)  ", width=w, color=C.PATH))
            # Mała i wielka litera
            for pair in [("ą","Ą"),("ć","Ć"),("ę","Ę"),("ł","Ł"),
                          ("ń","Ń"),("ó","Ó"),("ś","Ś"),("ź","Ź"),("ż","Ż")]:
                lo, hi = pair
                lo_cp = f"U+{ord(lo):04X}"
                hi_cp = f"U+{ord(hi):04X}"
                # cp1250 bajty
                try:
                    lo_b = lo.encode("cp1250").hex().upper()
                    hi_b = hi.encode("cp1250").hex().upper()
                except Exception:
                    lo_b = hi_b = "??"
                try:
                    lo_i = lo.encode("iso-8859-2").hex().upper()
                    hi_i = hi.encode("iso-8859-2").hex().upper()
                except Exception:
                    lo_i = hi_i = "??"
                print(box_row(
                    f"  {C.BOLD}{lo}{C.RESET} {lo_cp}  "
                    f"{C.DIM}cp1250=0x{lo_b}  iso-2=0x{lo_i}{C.RESET}"
                    f"    {C.BOLD}{hi}{C.RESET} {hi_cp}  "
                    f"{C.DIM}cp1250=0x{hi_b}  iso-2=0x{hi_i}{C.RESET}",
                    width=w, color=C.PATH))
            print(box_bottom(width=w, color=C.PATH))
            print()

        if cat in ("box", "all"):
            print(box_top("  📦 Znaki ramkowe (box-drawing)  ", width=w, color=C.DIM))
            box_rows = [
                ("single",  "┌─┬─┐  ├─┼─┤  └─┴─┘  │"),
                ("double",  "╔═╦═╗  ╠═╬═╣  ╚═╩═╝  ║"),
                ("round",   "╭─┬─╮  ├─┼─┤  ╰─┴─╯  │"),
                ("heavy",   "┏━┳━┓  ┣━╋━┫  ┗━┻━┛  ┃"),
                ("arrows",  "→ ← ↑ ↓ ⇒ ⇐ ⇑ ⇓ ↔ ↕"),
                ("blocks",  "█ ▓ ▒ ░ ▄ ▀ ▌ ▐"),
                ("shapes",  "● ○ ◆ ◇ ▲ ▼ ▶ ◀ ★ ☆"),
                ("marks",   "✔ ✖ ✓ ✗ ✘ ☑ ☐ ⚠ ℹ ✎"),
                ("math",    "± × ÷ ≠ ≤ ≥ ∞ √ ∑ π α β γ"),
                ("currency","€ £ ¥ ¢ ₽ ₿ ₺ ₩"),
            ]
            for style, chars in box_rows:
                print(box_row(
                    f"  {C.DIM}{style:<10}{C.RESET}  {chars}",
                    width=w, color=C.DIM))
            print(box_bottom(width=w, color=C.DIM))
            print()

        if cat not in ("ansi", "polish", "pl", "box", "all"):
            print_error(
                f"Nieznana kategoria: '{cat}'",
                "Dostępne: polish | box | ansi | all")
        return

    # ── ansi ─────────────────────────────────────────────────────────────────
    if sub == "ansi":
        w = min(terminal_width() - 2, 74)
        print()
        print(box_top("  🎨 Paleta kolorów ANSI — pełne demo  ", width=w, color=C.PROMPT))

        # Style tekstu
        print(box_row(f"  {C.BOLD}── Style tekstu ──{C.RESET}", width=w, color=C.PROMPT))
        styles = [("\033[1m","bold"),("\033[2m","dim"),("\033[3m","italic"),
                  ("\033[4m","underline"),("\033[7m","reverse"),("\033[9m","strikethrough")]
        row_s = "  " + "  ".join(f"{c}{l}\033[0m" for c, l in styles)
        print(box_row(row_s, width=w, color=C.PROMPT))

        # Kolory FG 30-37 + 90-97
        print(box_row(f"  {C.BOLD}── Kolory tekstu (foreground) ──{C.RESET}", width=w, color=C.PROMPT))
        fg_row1 = "  " + " ".join(f"\033[{30+i}m ■ {30+i} \033[0m" for i in range(8))
        fg_row2 = "  " + " ".join(f"\033[{90+i}m ■ {90+i} \033[0m" for i in range(8))
        print(box_row(fg_row1, width=w, color=C.PROMPT))
        print(box_row(fg_row2, width=w, color=C.PROMPT))

        # Kolory BG 40-47
        print(box_row(f"  {C.BOLD}── Tła (background) ──{C.RESET}", width=w, color=C.PROMPT))
        bg_row = "  " + " ".join(f"\033[{40+i}m  {40+i}  \033[0m" for i in range(8))
        print(box_row(bg_row, width=w, color=C.PROMPT))

        # 256-kolorów — próbka (6×6 cube)
        print(box_row(f"  {C.BOLD}── 256 kolorów — próbka (cube 6×6) ──{C.RESET}", width=w, color=C.PROMPT))
        for row_base in range(0, 6):
            cubes = "  "
            for col in range(6):
                idx = 16 + row_base * 6 + col
                cubes += f"\033[48;5;{idx}m  {idx:3} \033[0m"
            print(box_row(cubes, width=w, color=C.PROMPT))

        # Polskie znaki test w kolorach
        print(box_sep(width=w, color=C.PROMPT))
        pl_colored = "  " + " ".join(
            f"\033[{31+i}m{c}\033[0m"
            for i, c in enumerate("ąćęłńóśźżĄĆĘŁŃÓŚŹŻ"))
        print(box_row(f"  {C.BOLD}Polskie znaki w kolorach:{C.RESET}", width=w, color=C.PROMPT))
        print(box_row(pl_colored, width=w, color=C.PROMPT))

        print(box_bottom(width=w, color=C.PROMPT))
        print(f"  {C.DIM}ANSI 256-kolorów: \\033[38;5;<n>m (FG)  \\033[48;5;<n>m (BG){C.RESET}\n")
        return

    # ── unicode ──────────────────────────────────────────────────────────────
    if sub == "unicode":
        if len(args) < 2:
            print_error("Podaj tekst: encode unicode <tekst>")
            return
        text = " ".join(args[1:])
        w = min(terminal_width() - 2, 72)
        print()
        print(box_top(f"  🔣 Unicode code-pointy: {text[:20]}  ", width=w, color=C.INFO))
        for ch in text:
            cp   = ord(ch)
            name = ""
            try:
                import unicodedata as _ud
                name = _ud.name(ch, "")
                cat  = _ud.category(ch)
            except Exception:
                cat = "?"
            # Bajty w UTF-8 i cp1250
            utf8_hex = ch.encode("utf-8").hex().upper()
            try:
                cp1250_hex = ch.encode("cp1250").hex().upper()
            except (UnicodeEncodeError, LookupError):
                cp1250_hex = "??"
            try:
                iso2_hex = ch.encode("iso-8859-2").hex().upper()
            except (UnicodeEncodeError, LookupError):
                iso2_hex = "??"

            clr = C.INFO if cp > 127 else C.DIM
            print(box_row(
                f"  {C.BOLD}{ch}{C.RESET}  "
                f"{clr}U+{cp:04X}{C.RESET}  "
                f"{C.DIM}UTF-8: {utf8_hex:<8}  "
                f"cp1250: {cp1250_hex:<4}  "
                f"iso-2: {iso2_hex:<4}  "
                f"[{cat}] {name[:25]}{C.RESET}",
                width=w, color=C.INFO))
        print(box_bottom(width=w, color=C.INFO))
        print()
        return

    # ── strip ─────────────────────────────────────────────────────────────────
    if sub == "strip":
        if len(args) < 2:
            print_error("Podaj plik: encode strip <plik> [--out <cel>]")
            return
        fp = Path(args[1]).expanduser().resolve()
        if not fp.exists():
            print_error(f"Plik nie istnieje: {args[1]}")
            return

        out_flag = "--out" in args
        if out_flag:
            idx = args.index("--out")
            dest = Path(args[idx + 1]).expanduser().resolve() if idx + 1 < len(args) \
                   else fp.with_suffix(fp.suffix + ".clean")
        else:
            dest = fp.with_suffix(fp.suffix + ".clean")

        try:
            raw  = fp.read_text(encoding="utf-8", errors="replace")
            clean = _enc_strip_ansi(raw)
            removed = len(raw) - len(clean)
            dest.write_text(clean, encoding="utf-8")
            print_info(
                f"Usunięto {removed} znaków ANSI  →  {dest.name}  "
                f"({len(raw.encode())} B → {len(clean.encode())} B)")
        except Exception as e:
            print_error(f"Błąd: {e}")
        return

    # ── test ─────────────────────────────────────────────────────────────────
    if sub == "test":
        w = min(terminal_width() - 2, 70)
        print()
        print(box_top("  🧪 Test obsługi znaków i kodowania  ", width=w, color=C.PROMPT))

        tests_results: list[tuple[bool, str, str]] = []

        def _t(ok: bool, label: str, detail: str = ""):
            tests_results.append((ok, label, detail))
            icon = f"{C.OK}✔{C.RESET}" if ok else f"{C.ERROR}✖{C.RESET}"
            d    = f"  {C.DIM}{detail}{C.RESET}" if detail else ""
            print(box_row(f"  {icon}  {label}{d}", width=w, color=C.PROMPT))

        # 1. stdout UTF-8
        enc = getattr(sys.stdout, "encoding", "") or ""
        _t(enc.lower().replace("-","") in ("utf8","utf8sig"),
           "stdout.encoding = UTF-8", enc)

        # 2. Polskie znaki roundtrip UTF-8
        try:
            b = _PL_CHARS.encode("utf-8")
            back = b.decode("utf-8")
            _t(back == _PL_CHARS, "Polskie znaki UTF-8 roundtrip",
               f"{len(b)} bajtów")
        except Exception as e:
            _t(False, "Polskie znaki UTF-8 roundtrip", str(e))

        # 3. cp1250 konwersja
        try:
            b1250 = "zażółć gęślą jaźń".encode("cp1250")
            back  = b1250.decode("cp1250")
            _t(True, "cp1250 encode/decode", f"{len(b1250)} B")
        except Exception as e:
            _t(False, "cp1250 encode/decode", str(e))

        # 4. iso-8859-2
        try:
            b_iso = "zażółć gęślą jaźń".encode("iso-8859-2")
            back  = b_iso.decode("iso-8859-2")
            _t(True, "iso-8859-2 encode/decode", f"{len(b_iso)} B")
        except Exception as e:
            _t(False, "iso-8859-2 encode/decode", str(e))

        # 5. ANSI strips
        sample = f"\033[1;32mTEST\033[0m normal"
        stripped = _enc_strip_ansi(sample)
        _t(stripped == "TEST normal", "ANSI strip działa",
           f"'{sample[:20]}' → '{stripped}'")

        # 6. visible_len
        ansi_text = f"\033[31mCzerwony\033[0m text"
        vlen = _enc_visible_len(ansi_text)
        _t(vlen == len("Czerwony text"),
           "Widzialna długość ANSI", f"vlen={vlen}")

        # 7. Znaki ramkowe wyświetlalne
        try:
            box_chars = "┌─┬┐├┼┤└┴┘│║═╔╗╚╝"
            benc = box_chars.encode(enc or "utf-8", errors="replace")
            _t(b"?" not in benc or enc.lower().replace("-","") == "utf8",
               "Znaki ramkowe Unicode", box_chars[:10])
        except Exception as e:
            _t(False, "Znaki ramkowe Unicode", str(e))

        # 8. Zapis/odczyt polskich znaków do pliku temp
        try:
            import tempfile
            pl_text = "Zażółć gęślą jaźń — test pliku UTF-8 🐍"
            with tempfile.NamedTemporaryFile(
                    mode="w", suffix=".txt",
                    encoding="utf-8", delete=False) as tf:
                tf.write(pl_text)
                tpath = Path(tf.name)
            back = tpath.read_text(encoding="utf-8")
            tpath.unlink(missing_ok=True)
            _t(back == pl_text, "Zapis/odczyt pliku UTF-8",
               f"{len(pl_text)} znaków")
        except Exception as e:
            _t(False, "Zapis/odczyt pliku UTF-8", str(e))

        # 9. Wykrywanie kodowania
        test_raw = "Zażółć".encode("cp1250")
        det_enc, det_conf = _enc_detect(test_raw)
        _t(det_enc == "cp1250", "Detekcja cp1250",
           f"wykryto: {det_enc} ({det_conf*100:.0f}%)")

        # 10. Mojibake fix
        mojibake = "ZaÅ¼Ã³Å\x82Ä\x87"   # "Zażółć" zdekodowane jako latin-1
        fixed, n = _enc_fix_mojibake(mojibake)
        _t(n > 0, "Naprawianie mojibake", f"naprawiono {n} sekwencji")

        # Podsumowanie
        passed = sum(1 for ok, *_ in tests_results if ok)
        total  = len(tests_results)
        ok_all = passed == total
        print(box_sep(width=w, color=C.OK if ok_all else C.ERROR))
        summary_clr = C.OK if ok_all else C.ERROR
        print(box_row(
            f"  {C.BOLD}{summary_clr}{'PASS' if ok_all else 'FAIL'}{C.RESET}"
            f"  ✔ {passed}/{total} testów",
            width=w, color=summary_clr))
        print(box_bottom(width=w, color=summary_clr))

        if not ok_all:
            print(f"\n  {C.DIM}Napraw środowisko:"
                  f"  export PYTHONIOENCODING=utf-8{C.RESET}")
            if sys.platform == "win32":
                print(f"  {C.DIM}Windows: chcp 65001{C.RESET}")
        print()
        return

    # ── fallback ──────────────────────────────────────────────────────────────
    print_error(
        f"Nieznana podkomenda: encode {sub}",
        "Dostępne: info | detect | convert | fix | show | ansi | unicode | strip | test"
    )

# ── Rozszerz istniejący cmd_cat o auto-detect kodowania ─────────────────────
# Gdy cat napotka UnicodeDecodeError, zamiast błędu:
# 1. Wykrywa kodowanie automatycznie
# 2. Wyświetla zawartość z właściwym kodowaniem + info

_orig_cat_func = None
if "cat" in BUILTINS:
    _orig_cat_func = BUILTINS["cat"].func

def _patched_cat_with_enc(args: list):
    """
    Rozszerzony cat z auto-detekcją kodowania.
    Gdy plik nie jest UTF-8, wykrywa kodowanie i wyświetla poprawnie.
    """
    if not args or args[0].startswith("-"):
        if _orig_cat_func:
            _orig_cat_func(args)
        return

    # Sprawdź czy któryś z argumentów to plik nie-UTF-8
    flags  = [a for a in args if a.startswith("-")]
    files  = [a for a in args if not a.startswith("-")]
    no_highlight = "-A" in flags or "--raw" in flags

    for fname in files:
        fp = Path(fname).expanduser().resolve()
        if not fp.exists():
            # Niech oryginalna funkcja obsłuży błąd (wyświetli komunikat)
            if _orig_cat_func:
                _orig_cat_func([fname] + flags)
            continue

        raw = fp.read_bytes()
        # Próbuj UTF-8 — jeśli OK, przekaż do oryginału
        try:
            raw.decode("utf-8", errors="strict")
            if _orig_cat_func:
                _orig_cat_func([fname] + flags)
            continue
        except UnicodeDecodeError:
            pass

        # Nie-UTF-8 — wykryj i wyświetl
        enc_name, conf = _enc_detect(raw)
        py_enc = _ENC_SUPPORTED.get(enc_name, {}).get("py", enc_name)
        print(f"  {C.DIM}[kodowanie: {enc_name} ({conf*100:.0f}% pewności)]{C.RESET}")
        try:
            text = raw.decode(py_enc, errors="replace")
        except Exception:
            text = raw.decode("utf-8", errors="replace")

        show_nums = "-n" in flags
        for i, line in enumerate(text.splitlines(), 1):
            prefix = f"{C.DIM}{i:4} │{C.RESET}  " if show_nums else ""
            if no_highlight:
                print(f"{prefix}{line}")
            else:
                print(f"{prefix}{C.DIM}{line}{C.RESET}")

if _orig_cat_func and "cat" in BUILTINS:
    BUILTINS["cat"].func = _patched_cat_with_enc

