@command("project", "Twórz i zarządzaj projektami terminala polsoft.ITS™",
         aliases=["proj"],
         flags=["new", "list", "open", "info"])
def cmd_project(args):
    """
    Użycie: project <podkomenda> [argumenty]

    Podkomendy:
      new <nazwa>                    — utwórz scaffold projektu w bieżącym katalogu
      new <nazwa> --path <ścieżka>   — utwórz w podanej ścieżce
      list                           — lista projektów (katalogi z main.py)
      open <nazwa>                   — przejdź cd do projektu
      info <nazwa>                   — pokaż strukturę projektu

    Struktura nowego projektu:
      src/        — kod źródłowy i komendy
      assets/     — logo ASCII, zasoby
      icons/      — ikony SVG / ICO
      themes/     — pliki motywów JSON (dark.json, neon.json)
      plugins/    — pluginy TerminalX
      docs/       — dokumentacja
      dist/       — pliki wynikowe (EXE, .pyz)
    """
    w = min(terminal_width() - 2, 68)
    sub = args[0].lower() if args else "list"

    # ── new ──────────────────────────────────────────────────────────────────
    if sub == "new":
        if len(args) < 2:
            print_error("Podaj nazwę projektu: project new <nazwa>")
            return
        name = args[1]
        # opcjonalne --path
        dest = Path.cwd()
        if "--path" in args:
            idx = args.index("--path")
            if idx + 1 < len(args):
                dest = Path(args[idx + 1]).expanduser().resolve()
        root = _project_create_scaffold(name, dest)
        if root is None:
            return
        safe = root.name
        print()
        print(box_top(f"Projekt '{name}' — utworzono", width=w, color=C.PATH))
        print(box_row(f"  {C.PATH}✔{C.RESET}  {root}", width=w, color=C.PATH))
        print(box_sep(width=w, color=C.PATH))
        for item in sorted(root.iterdir()):
            icon = "📁" if item.is_dir() else "📄"
            print(box_row(f"  {icon} {item.name}/".rstrip("/") + ("/" if item.is_dir() else ""),
                          width=w, color=C.PATH))
        print(box_sep(width=w, color=C.PATH))
        print(box_row(f"  {C.DIM}cd {root}{C.RESET}", width=w, color=C.PATH))
        print(box_row(f"  {C.DIM}Uruchom  : python main.py{C.RESET}", width=w, color=C.PATH))
        print(box_row(f"  {C.DIM}Build EXE: build exe {safe}{C.RESET}", width=w, color=C.PATH))
        print(box_bottom(width=w, color=C.PATH))
        print()
        return

    # ── list ─────────────────────────────────────────────────────────────────
    if sub in ("list", "ls", ""):
        cwd = Path.cwd()
        projects = [
            d for d in sorted(cwd.iterdir())
            if d.is_dir() and (d / "main.py").exists()
        ]
        print()
        print(box_top(f"Projekty w {cwd}  ({len(projects)})", width=w, color=C.PROMPT))
        if not projects:
            print(box_row(f"  {C.DIM}Brak projektów. Utwórz: project new <nazwa>{C.RESET}",
                          width=w, color=C.PROMPT))
        else:
            for p in projects:
                has_theme  = (p / "themes").exists()
                has_plugin = (p / "plugins").exists()
                tags = []
                if has_theme:  tags.append("themes")
                if has_plugin: tags.append("plugins")
                tag_str = f"  {C.DIM}[{', '.join(tags)}]{C.RESET}" if tags else ""
                print(box_row(f"  {C.BOLD}{p.name:24}{C.RESET}{tag_str}",
                              width=w, color=C.PROMPT))
        print(box_sep(width=w, color=C.PROMPT))
        print(box_row(f"  {C.DIM}project new <nazwa>  |  project open <nazwa>{C.RESET}",
                      width=w, color=C.PROMPT))
        print(box_bottom(width=w, color=C.PROMPT))
        print()
        return

    # ── open ─────────────────────────────────────────────────────────────────
    if sub == "open":
        if len(args) < 2:
            print_error("Podaj nazwę projektu: project open <nazwa>")
            return
        target = Path.cwd() / args[1]
        if not target.exists():
            print_error(f"Katalog projektu nie istnieje: {target}")
            return
        os.chdir(target)
        print_info(f"Przeszedłem do: {target}")
        return

    # ── info ─────────────────────────────────────────────────────────────────
    if sub == "info":
        name = args[1] if len(args) > 1 else "."
        root = Path.cwd() / name if name != "." else Path.cwd()
        if not root.exists():
            print_error(f"Katalog nie istnieje: {root}")
            return
        print()
        print(box_top(f"Projekt: {root.name}", width=w, color=C.INFO))
        for item in sorted(root.rglob("*")):
            rel = item.relative_to(root)
            depth = len(rel.parts) - 1
            indent = "  " + "  " * depth
            icon = "📁" if item.is_dir() else "📄"
            if depth <= 2:
                print(box_row(f"{indent}{icon} {item.name}{'/' if item.is_dir() else ''}",
                              width=w, color=C.INFO))
        print(box_bottom(width=w, color=C.INFO))
        print()
        return

    print_error(f"Nieznana podkomenda: project {sub}",
                "Dostępne: new | list | open | info")

@command("builder", "Tryb Builder — generuj i zarządzaj własnymi modułami shella",
         aliases=["build"], flags=["new", "list", "open", "run", "delete"])
def cmd_builder(args):
    """
    Użycie: builder <podkomenda> [argumenty]

    Podkomendy:
      new    <nazwa>   Wygeneruj szkielet nowego modułu
      list             Pokaż istniejące moduły buildera
      open   <nazwa>   Otwórz moduł w nano-lite
      run    <nazwa>   Załaduj/przeładuj moduł jako plugin
      delete <nazwa>   Usuń moduł
    """
    sub = args[0] if args else ""

    # ── new ──────────────────────────────────────────────────────────────────
    if sub == "new":
        if len(args) < 2:
            print_error("Podaj nazwę modułu: builder new <nazwa>")
            return
        name = args[1].strip()
        if not re.match(r"^[a-zA-Z][a-zA-Z0-9_]*$", name):
            print_error("Nazwa może zawierać tylko litery, cyfry i '_', musi zaczynać się literą.")
            return
        path = _builder_generate(name)
        if path:
            print_info(f"Wygenerowano: {path}")
            print(f"  {C.DIM}Edytuj  : builder open {name}{C.RESET}")
            print(f"  {C.DIM}Załaduj : builder run  {name}{C.RESET}")
        return

    # ── list ─────────────────────────────────────────────────────────────────
    if sub in ("list", "ls", ""):
        modules = _builder_list()
        w = min(terminal_width() - 2, 60)
        print()
        print(box_top("Moduły Builder", width=w, color=C.PATH))
        if not modules:
            print(box_row(f"  {C.DIM}Brak modułów. Utwórz: builder new <nazwa>{C.RESET}",
                          width=w, color=C.PATH))
        else:
            for p in modules:
                size = p.stat().st_size
                mtime = datetime.datetime.fromtimestamp(p.stat().st_mtime).strftime("%Y-%m-%d %H:%M")
                row = (f"  {C.BOLD}{p.stem:20}{C.RESET} "
                       f"{C.DIM}{size:>6} B   {mtime}{C.RESET}")
                print(box_row(row, width=w, color=C.PATH))
        print(box_bottom(width=w, color=C.PATH))
        print()
        return

    # ── open ─────────────────────────────────────────────────────────────────
    if sub == "open":
        if len(args) < 2:
            print_error("Podaj nazwę: builder open <nazwa>")
            return
        path = _builder_path(args[1])
        if not path.exists():
            print_error(f"Moduł '{args[1]}' nie istnieje.", f"Utwórz: builder new {args[1]}")
            return
        dispatch("nano", [str(path)])
        return

    # ── run ──────────────────────────────────────────────────────────────────
    if sub == "run":
        if len(args) < 2:
            print_error("Podaj nazwę: builder run <nazwa>")
            return
        path = _builder_path(args[1])
        if not path.exists():
            print_error(f"Moduł '{args[1]}' nie istnieje.")
            return
        dispatch("plugin", ["reload"])
        print_info(f"Moduł '{args[1]}' przeładowany.")
        return

    # ── delete ───────────────────────────────────────────────────────────────
    if sub in ("delete", "del", "rm"):
        if len(args) < 2:
            print_error("Podaj nazwę: builder delete <nazwa>")
            return
        path = _builder_path(args[1])
        if not path.exists():
            print_error(f"Moduł '{args[1]}' nie istnieje.")
            return
        try:
            ans = input(f"  {C.ERROR}Usunąć '{path.name}'? [t/n]: {C.RESET}").strip().lower()
        except (EOFError, KeyboardInterrupt):
            print(); return
        if ans in ("t", "y", "tak", "yes"):
            path.unlink()
            sig = path.with_suffix(".py.sig")
            if sig.exists():
                sig.unlink()
            print_info(f"Usunięto: {path.name}")
        else:
            print_info("Anulowano.")
        return

    print_error(
        f"Nieznana podkomenda: builder {sub}",
        "Dostępne: new | list | open | run | delete"
    )

# ADVANCED LOGGING — warstwowe logi + eksport
#
#  Rozszerza istniejący system logowania o:
#    • Poziomy: DEBUG / INFO / WARN / ERROR (filtrowanie)
#    • Eksport: JSON, CSV, HTML
#    • TUI: logview — interaktywna przeglądarka logów w terminalu
#
#  Komendy:
#    logs                     — pokaż ostatnie wpisy (TUI)
#    logs tail [N]            — ostatnie N wpisów (domyślnie 20)
#    logs level <poziom>      — filtruj: DEBUG | INFO | WARN | ERROR | ALL
#    logs export json [plik]  — eksport do JSON
#    logs export csv  [plik]  — eksport do CSV
#    logs export html [plik]  — eksport do HTML
#    logs clear               — wyczyść log

_LOG_LEVEL_ORDER = {lvl: i for i, lvl in enumerate(_LOG_LEVELS)}
_ACTIVE_LOG_LEVEL = _STATE.active_log_level

def log_debug(msg: str):
    """Loguje wiadomość na poziomie DEBUG."""
    _log("DEBUG", msg)

def log_warn(msg: str):
    """Loguje ostrzeżenie na poziomie WARN."""
    _log("WARN", msg)

def _adv_parse_log_file() -> list[dict]:
    """
    Parsuje LOG_FILE do listy słowników:
    [{ts, level, msg}, ...]
    """
    entries = []
    if not LOG_FILE.exists():
        return entries
    try:
        for line in LOG_FILE.read_text(encoding="utf-8", errors="replace").splitlines():
            # Format: [2025-01-01 12:00:00] [LEVEL] message
            m = _RE_LOG_LINE.match(line)
            if m:
                entries.append({"ts": m.group(1), "level": m.group(2), "msg": m.group(3)})
    except Exception:  # ignorowane celowo
        pass
    return entries

def _adv_filter_entries(entries: list[dict], level: str = "ALL") -> list[dict]:
    """Filtruje wpisy wg minimalnego poziomu."""
    if level == "ALL":
        return entries
    min_order = _LOG_LEVEL_ORDER.get(level, 0)
    return [e for e in entries if _LOG_LEVEL_ORDER.get(e["level"], 0) >= min_order]

def _adv_level_color(level: str) -> str:
    return {
        "DEBUG": C.DIM,
        "INFO":  C.PATH,
        "WARN":  C.INFO,
        "CMD":   C.BOLD,
        "ERROR": C.ERROR,
    }.get(level, C.RESET)

def _adv_export_json(entries: list[dict], path: Path):
    path.write_text(json.dumps(entries, ensure_ascii=False, indent=2), encoding="utf-8")

def _adv_export_csv(entries: list[dict], path: Path):
    import csv as _csv
    with path.open("w", newline="", encoding="utf-8") as f:
        w = _csv.DictWriter(f, fieldnames=["ts", "level", "msg"])
        w.writeheader()
        w.writerows(entries)

def _adv_export_html(entries: list[dict], path: Path):
    _LEVEL_CSS = {
        "DEBUG": "color:#888",
        "INFO":  "color:#4caf50",
        "WARN":  "color:#ff9800",
        "CMD":   "color:#2196f3;font-weight:bold",
        "ERROR": "color:#f44336;font-weight:bold",
    }
    rows = []
    for e in entries:
        style = _LEVEL_CSS.get(e["level"], "")
        ts_esc  = e["ts"].replace("&", "&amp;")
        lvl_esc = e["level"].replace("&", "&amp;")
        msg_esc = e["msg"].replace("&", "&amp;").replace("<", "&lt;").replace(">", "&gt;")
        rows.append(
            f'<tr><td class="ts">{ts_esc}</td>'
            f'<td style="{style}">{lvl_esc}</td>'
            f'<td>{msg_esc}</td></tr>'
        )
    html = f"""<!DOCTYPE html>
<html lang="pl"><head><meta charset="UTF-8">
<title>TerminalX log</title>
<style>
body{{font-family:monospace;background:#1e1e1e;color:#ddd;padding:1rem}}
table{{border-collapse:collapse;width:100%}}
th{{background:#333;color:#fff;padding:4px 8px;text-align:left}}
td{{padding:3px 8px;border-bottom:1px solid #333;font-size:.85rem}}
.ts{{color:#888;white-space:nowrap}}
tr:hover td{{background:#2a2a2a}}
</style></head><body>
<h2>TerminalX log — {datetime.datetime.now().strftime('%Y-%m-%d %H:%M')}</h2>
<p>{len(entries)} wpisów</p>
<table><tr><th>Czas</th><th>Poziom</th><th>Wiadomość</th></tr>
{"".join(rows)}
</table></body></html>"""
    path.write_text(html, encoding="utf-8")

@command("logs", "Zaawansowany podgląd i eksport logów shella",
         aliases=["log2"], flags=["tail", "level", "export", "clear"])
def cmd_logs(args):
    """
    Użycie: logs [podkomenda] [opcje]

    Podkomendy:
      (brak)              Pokaż ostatnie 30 wpisów
      tail [N]            Ostatnie N wpisów (domyślnie 20)
      level <POZIOM>      Filtruj: DEBUG | INFO | WARN | CMD | ERROR | ALL
      export json [plik]  Eksportuj do JSON
      export csv  [plik]  Eksportuj do CSV
      export html [plik]  Eksportuj do HTML
      clear               Wyczyść plik logu
    """
    sub = args[0] if args else ""

    entries = _adv_parse_log_file()

    # ── tail / (brak) ─────────────────────────────────────────────────────────
    if sub in ("", "tail"):
        n = 30
        if sub == "tail" and len(args) >= 2:
            try:
                n = int(args[1])
            except ValueError:
                print_error("Podaj liczbę: logs tail <N>"); return
        shown = _adv_filter_entries(entries, _ACTIVE_LOG_LEVEL)[-n:]
        w = min(terminal_width() - 2, 80)
        print()
        print(box_top(
            f"Logi TerminalX — ostatnie {len(shown)} z {len(entries)} wpisów "
            f"(filtr: {_ACTIVE_LOG_LEVEL})",
            width=w, color=C.PATH))
        if not shown:
            print(box_row(f"  {C.DIM}Brak wpisów.{C.RESET}", width=w, color=C.PATH))
        for e in shown:
            clr = _adv_level_color(e["level"])
            row = f"  {C.DIM}{e['ts']}{C.RESET}  {clr}{e['level']:5}{C.RESET}  {e['msg'][:60]}"
            print(box_row(row, width=w, color=C.PATH))
        print(box_bottom(width=w, color=C.PATH))
        print(f"  {C.DIM}logs level <POZIOM>  |  logs export json/csv/html{C.RESET}\n")
        return

    # ── level ─────────────────────────────────────────────────────────────────
    if sub == "level":
        if len(args) < 2:
            print_info(f"Aktywny filtr: {_ACTIVE_LOG_LEVEL}")
            print(f"  {C.DIM}Dostępne: {' | '.join(_LOG_LEVELS)} | ALL{C.RESET}")
            return
        lvl = args[1].upper()
        if lvl not in _LOG_LEVELS and lvl != "ALL":
            print_error(f"Nieznany poziom: {lvl}", f"Dostępne: {' | '.join(_LOG_LEVELS)} | ALL")
            return
        _STATE.active_log_level = lvl
        print_info(f"Filtr logów ustawiony na: {lvl}")
        return

    # ── export ────────────────────────────────────────────────────────────────
    if sub == "export":
        fmt = args[1].lower() if len(args) >= 2 else ""
        if fmt not in ("json", "csv", "html"):
            print_error("Podaj format: logs export json|csv|html [plik]"); return
        ts_str = datetime.datetime.now().strftime("%Y%m%d_%H%M%S")
        default_name = f"terminalx_log_{ts_str}.{fmt}"
        out_path = Path(args[2]) if len(args) >= 3 else Path.cwd() / default_name
        filtered = _adv_filter_entries(entries, _ACTIVE_LOG_LEVEL)
        try:
            if fmt == "json":
                _adv_export_json(filtered, out_path)
            elif fmt == "csv":
                _adv_export_csv(filtered, out_path)
            elif fmt == "html":
                _adv_export_html(filtered, out_path)
            print_info(f"Wyeksportowano {len(filtered)} wpisów → {out_path}")
        except Exception as e:
            print_error(f"Błąd eksportu: {e}")
        return

    # ── clear ─────────────────────────────────────────────────────────────────
    if sub == "clear":
        try:
            ans = input(f"  {C.ERROR}Wyczyścić plik logu? [t/n]: {C.RESET}").strip().lower()
        except (EOFError, KeyboardInterrupt):
            print(); return
        if ans in ("t", "y", "tak", "yes"):
            LOG_FILE.write_text("", encoding="utf-8")
            print_info("Log wyczyszczony.")
        else:
            print_info("Anulowano.")
        return

    print_error(
        f"Nieznana podkomenda: logs {sub}",
        "Dostępne: tail | level | export | clear"
    )

# CONFIG WIZARD — interaktywny kreator konfiguracji
#
#  Pierwsze uruchomienie (lub ręczne wywołanie) odpytuje użytkownika
#  o kluczowe ustawienia i zapisuje je do CONFIG_FILE.
#
#  Komenda: wizard
#  Auto-uruchomienie: gdy CONFIG_FILE nie istnieje przy starcie shella

_WIZARD_DONE_KEY = "_wizard_completed"

def _wizard_ask(prompt: str, default: str, choices: list[str] | None = None) -> str:
    """
    Pyta użytkownika z domyślną wartością i opcjonalną listą wyborów.
    Zwraca wpisaną wartość lub default przy pustym wejściu.
    """
    choices_str = f" [{'/'.join(choices)}]" if choices else ""
    try:
        raw = input(f"  {C.INFO}?{C.RESET}  {prompt}{choices_str} (domyślnie: {C.BOLD}{default}{C.RESET}): ").strip()
    except (EOFError, KeyboardInterrupt):
        print()
        return default
    if not raw:
        return default
    if choices and raw.lower() not in [c.lower() for c in choices]:
        print(f"  {C.DIM}Nieznana opcja — używam domyślnej: {default}{C.RESET}")
        return default
    return raw

def _wizard_section(title: str):
    w = min(terminal_width() - 4, 60)
    print()
    print(f"  {C.BOLD}{'─' * 3} {title} {'─' * max(0, w - len(title) - 6)}{C.RESET}")

def run_config_wizard(force: bool = False):
    """
    Interaktywny kreator konfiguracji TerminalXa.
    Uruchamiany automatycznie przy pierwszym starcie
    lub ręcznie: wizard
    """
    # Sprawdź czy wizard był już uruchomiony
    if not force and cfg(_WIZARD_DONE_KEY, False):
        print_info("Konfiguracja już istnieje. Użyj 'wizard' aby uruchomić ponownie.")
        return

    w = min(terminal_width() - 2, 66)
    print()
    print(box_top("Kreator konfiguracji TerminalX", width=w, color=C.PROMPT))
    print(box_row(
        f"  {C.DIM}Odpowiedz na pytania lub naciśnij Enter aby użyć domyślnych.{C.RESET}",
        width=w, color=C.PROMPT))
    print(box_row(
        f"  {C.DIM}Konfigurację możesz zmienić później: config set <klucz> <wartość>{C.RESET}",
        width=w, color=C.PROMPT))
    print(box_bottom(width=w, color=C.PROMPT))

    updates: dict = {}

    # ── Wygląd ───────────────────────────────────────────────────────────────
    _wizard_section("🎨 Wygląd")
    theme = _wizard_ask("Motyw kolorów", "dark", ["dark", "light"])
    updates["theme"] = theme

    prompt_style = _wizard_ask("Styl promptu", "full", ["full", "short", "minimal"])
    updates["prompt_style"] = prompt_style

    use_emoji = _wizard_ask("Ikony emoji w ls?", "tak", ["tak", "nie"])
    updates["use_emoji_icons"] = (use_emoji.lower() in ("tak", "t", "yes", "y"))

    status_bar = _wizard_ask("Pasek statusu nad promptem?", "tak", ["tak", "nie"])
    updates["status_bar"] = (status_bar.lower() in ("tak", "t", "yes", "y"))

    # ── Zachowanie ────────────────────────────────────────────────────────────
    _wizard_section("⚙️  Zachowanie")
    confirm_rm = _wizard_ask("Pytaj o potwierdzenie przed usunięciem pliku (rm)?", "tak", ["tak", "nie"])
    updates["confirm_rm"] = (confirm_rm.lower() in ("tak", "t", "yes", "y"))

    auto_cd = _wizard_ask("Wpisanie ścieżki = przejście do katalogu (auto-cd)?", "nie", ["tak", "nie"])
    updates["auto_cd"] = (auto_cd.lower() in ("tak", "t", "yes", "y"))

    syntax_hi = _wizard_ask("Podświetlanie składni w cat?", "tak", ["tak", "nie"])
    updates["syntax_highlight_cat"] = (syntax_hi.lower() in ("tak", "t", "yes", "y"))

    # ── Historia ─────────────────────────────────────────────────────────────
    _wizard_section("📜 Historia")
    hist_max_raw = _wizard_ask("Maksymalna liczba wpisów historii", "500")
    try:
        updates["history_max"] = int(hist_max_raw)
    except ValueError:
        updates["history_max"] = 500

    hist_dedup = _wizard_ask("Nie duplikuj ostatniego wpisu historii?", "tak", ["tak", "nie"])
    updates["history_dedup"] = (hist_dedup.lower() in ("tak", "t", "yes", "y"))

    # ── Pluginy ───────────────────────────────────────────────────────────────
    _wizard_section("🔌 Pluginy")
    autoload = _wizard_ask("Automatycznie ładuj pluginy przy starcie?", "tak", ["tak", "nie"])
    updates["autoload_plugins"] = (autoload.lower() in ("tak", "t", "yes", "y"))

    sandbox = _wizard_ask("Poziom sandbox dla pluginów", "warn", ["off", "warn", "strict"])
    updates["plugin_sandbox"] = sandbox.lower()

    # ── Logowanie ─────────────────────────────────────────────────────────────
    _wizard_section("📋 Logowanie")
    log_cmds = _wizard_ask("Loguj wykonywane komendy do pliku?", "tak", ["tak", "nie"])
    updates["log_commands"] = (log_cmds.lower() in ("tak", "t", "yes", "y"))

    log_mb_raw = _wizard_ask("Maksymalny rozmiar logu (MB)", "5")
    try:
        updates["log_max_mb"] = max(1, int(log_mb_raw))
    except ValueError:
        updates["log_max_mb"] = 5

    # ── Greeting ─────────────────────────────────────────────────────────────
    _wizard_section("👋 Powitanie")
    greeting = _wizard_ask("Własna wiadomość powitalna (pusta = domyślna)", "")
    updates["custom_greeting"] = greeting

    # ── Zapisz ────────────────────────────────────────────────────────────────
    updates[_WIZARD_DONE_KEY] = True

    print()
    try:
        ans = input(f"  {C.PATH}✔{C.RESET}  Zapisać konfigurację? [tak/nie]: ").strip().lower()
    except (EOFError, KeyboardInterrupt):
        print()
        print_info("Anulowano — konfiguracja nie została zapisana.")
        return

    if ans not in ("tak", "t", "yes", "y"):
        print_info("Anulowano.")
        return

    for k, v in updates.items():
        cfg_set(k, v)

    # Zastosuj motyw od razu
    if updates.get("theme") in _THEMES:
        _STATE.current_theme = updates["theme"]
        C._apply()

    print()
    print_info("Konfiguracja zapisana! Możesz ją zmienić w dowolnym momencie:")
    print(f"  {C.DIM}config set <klucz> <wartość>  |  config list{C.RESET}")
    print()

@command("wizard", "Interaktywny kreator konfiguracji TerminalXa",
         aliases=["setup"], flags=[])
def cmd_wizard(args):
    """
    Uruchamia krok-po-kroku kreator konfiguracji.
    Pyta o motyw, styl promptu, historię, pluginy i inne ustawienia.
    Wynik zapisywany do ~/.terminalx.json.
    """
    force = "--force" in args or "-f" in args
    run_config_wizard(force=True if force else True)

def _wizard_auto_run():
    """
    Sprawdza czy wizard powinien się uruchomić automatycznie
    (pierwsze uruchomienie = brak pliku konfiguracyjnego lub flaga _wizard_completed=False).
    Wywoływane z main() przy starcie shella.
    """
    if not CONFIG_FILE.exists() and not cfg(_WIZARD_DONE_KEY, False):
        print(f"\n  {C.INFO}★  Pierwsze uruchomienie TerminalXa!{C.RESET}")
        print(f"  {C.DIM}Uruchamiam kreator konfiguracji. Możesz go pominąć (Ctrl+C).{C.RESET}\n")
        try:
            run_config_wizard(force=True)
        except KeyboardInterrupt:
            print()
            print_info("Pominięto wizard. Uruchom go później: wizard")

# ── Patch main() — auto-uruchomienie wizarda przy starcie ────────────────────
# Przechwytujemy oryginalną funkcję main() i wstrzykujemy _wizard_auto_run()
# na początku, bez modyfikowania reszty kodu.

_orig_main = None

def _patched_main_with_wizard():
    """Wrapper dla main() z auto-uruchomieniem wizarda."""
    _wizard_auto_run()
    if _orig_main is not None:
        _orig_main()

try:
    _orig_main = BUILTINS.get("__main_func__")  # sprawdź czy już zarejestrowano
    # Nie możemy tu łatwo patchować main() bez jej deklaracji,
    # więc zamiast tego rejestrujemy hook w systemie pluginów
    if "before_cmd" not in PLUGIN_HOOKS:
        PLUGIN_HOOKS["before_cmd"] = []
except Exception:  # ignorowane celowo
    pass

# Zamiast patchować main(), auto-wizard uruchamiamy przez hook startowy
# gdy shell ładuje pierwsze polecenie. Flaga zapewnia jednorazowość.
_WIZARD_AUTO_TRIGGERED = _STATE.wizard_auto_triggered

def _hook_wizard_auto(cmd: str, args: list):
    """Hook before_cmd — uruchamia wizard raz przy pierwszej komendzie."""
    if _WIZARD_AUTO_TRIGGERED:
        return
    _STATE.wizard_auto_triggered = True
    if not CONFIG_FILE.exists() and not cfg(_WIZARD_DONE_KEY, False):
        print(f"\n  {C.INFO}★  Pierwsze uruchomienie — wpisz 'wizard' aby skonfigurować shell.{C.RESET}")
        print(f"  {C.DIM}Lub pomiń i zacznij korzystać od razu.{C.RESET}\n")

try:
    PLUGIN_HOOKS.setdefault("before_cmd", []).append(_hook_wizard_auto)
except Exception:  # ignorowane celowo
    pass

