# PYSH
#   Moduły .pysh — dynamicznie ładowane skrypty rozszerzające shell.
#   Format: plik .pysh to zwykły Python z opcjonalną sekcją metadanych
#   i funkcją register(api). Ładowany tak samo jak pluginy .py, ale z
#   dodatkową składnią skryptową (linia po linii jako komendy shella).
#
#   Komendy:
#     pysh load <plik.pysh>    — załaduj moduł
#     pysh run <plik.pysh>     — uruchom jako skrypt (jednorazowo)
#     pysh list                — lista załadowanych modułów .pysh
#     pysh reload [nazwa]      — hot-reload modułu
#     pysh unload <nazwa>      — wyładuj moduł
#     pysh info <nazwa>        — metadane modułu
#     pysh new <nazwa>         — utwórz szkielet nowego modułu .pysh
#
#   Ścieżka wyszukiwania: cwd → save_path_default → pysh_module_path (config)

PYSH_MODULES: dict = {}        # nazwa → moduł (załadowane .pysh)
PYSH_META:    dict = {}        # nazwa → metadane

# Nowe klucze w _CONFIG_DEFAULTS dla .pysh
_CONFIG_DEFAULTS.setdefault("pysh_module_path",  "")      # ścieżka wyszukiwania .pysh
_CONFIG_DEFAULTS.setdefault("pysh_autoload",     False)   # auto-ładuj .pysh przy starcie
_CONFIG_DEFAULTS.setdefault("pysh_autoload_dir", "")      # katalog auto-ładowania .pysh
_CONFIG_DEFAULTS.setdefault("pysh_verbose",      False)   # verbose przy ładowaniu .pysh

# ── Wykrywanie pliku .pysh ────────────────────────────────────

def _pysh_find(name: str) -> Path | None:
    """
    Szuka pliku .pysh o podanej nazwie (z lub bez rozszerzenia).
    Przeszukuje: cwd → pysh_module_path → save_path_default.
    """
    stem = name.removesuffix(".pysh")
    search_dirs = [Path(".")]
    for raw in cfg("pysh_module_path", "").split(os.pathsep):
        p = Path(raw).expanduser()
        if p.is_dir():
            search_dirs.append(p)
    default_save = cfg("save_path_default", "")
    if default_save:
        search_dirs.append(Path(default_save).expanduser())

    for d in search_dirs:
        candidate = d / f"{stem}.pysh"
        if candidate.exists():
            return candidate
        # Też spróbuj z pełną ścieżką
        full = Path(name).expanduser()
        if full.exists():
            return full
    return None

def _pysh_load_file(path: Path, api=None, silent: bool = False,
                    register: bool = True) -> bool:
    """
    Ładuje plik .pysh:
    - Jeśli zawiera funkcję register() → traktuje jak plugin (rejestruje komendy)
    - Jeśli nie → wykonuje linia po linii jako komendy shella (tryb skryptowy)
    Zwraca True jeśli sukces.
    """
    global _SHELL_VERBOSE
    if api is None:
        api = ShellAPI()

    name = path.stem
    verbose = cfg("pysh_verbose", False) or _SHELL_VERBOSE

    try:
        source = path.read_text(encoding="utf-8")
    except Exception as e:
        print_error(f"Nie można odczytać {path}: {e}")
        return False

    # ── Skan bezpieczeństwa (ten sam co dla pluginów .py) ────
    warnings = _sandbox_scan_source(source, name)
    if warnings and not silent:
        print(f"  {C.WARN}⚠ pysh:{C.RESET} {name}.pysh — potencjalnie ryzykowne wzorce:")
        for w in warnings:
            print(f"    {C.DIM}· {w}{C.RESET}")

    # ── Próba ładowania jako moduł Python ───────────────────
    spec   = importlib.util.spec_from_loader(
        f"_terminalx_pysh_{name}",
        importlib.util.LazyLoader if False else importlib.machinery.SourceFileLoader(
            f"_terminalx_pysh_{name}", str(path)
        ),
        origin=str(path)
    )
    module = importlib.util.module_from_spec(spec)
    module.__file__ = str(path.resolve())
    sys.modules[f"_terminalx_pysh_{name}"] = module

    try:
        spec.loader.exec_module(module)
    except Exception as e:
        print_error(f"Błąd ładowania {path.name}: {e}")
        write_crashlog(e, context=f"pysh_load: {path.name}")
        sys.modules.pop(f"_terminalx_pysh_{name}", None)
        return False

    # ── Metadane ─────────────────────────────────────────────
    meta = {}
    if hasattr(module, "PLUGIN_META"):
        meta = dict(module.PLUGIN_META)
    elif hasattr(module, "PYSH_META"):
        meta = dict(module.PYSH_META)
    meta.setdefault("name",        name)
    meta.setdefault("version",     getattr(module, "__version__", ""))
    meta.setdefault("author",      getattr(module, "__author__", ""))
    meta.setdefault("description", (module.__doc__ or "").strip().splitlines()[0]
                    if module.__doc__ else "")
    meta["_file"]   = str(path.resolve())
    meta["_loaded"] = datetime.datetime.now().isoformat(timespec="seconds")
    meta["_type"]   = "pysh"

    # ── register() jeśli istnieje → tryb pluginu ─────────────
    if register and hasattr(module, "register"):
        try:
            module.register(api)
        except Exception as e:
            print_error(f"Błąd register() w {path.name}: {e}")
            write_crashlog(e, context=f"pysh_register: {path.name}")
            sys.modules.pop(f"_terminalx_pysh_{name}", None)
            return False

    PYSH_MODULES[name] = module
    PYSH_META[name]    = meta

    if not silent:
        ver_s  = f" v{meta['version']}" if meta.get("version") else ""
        auth_s = f"  {C.DIM}by {meta['author']}{C.RESET}" if meta.get("author") else ""
        mode   = "plugin" if hasattr(module, "register") else "skrypt"
        if verbose:
            log_debug(f"pysh load: {path.name} [{mode}]{ver_s}")
        print_info(f"Załadowano .pysh: {path.name}{ver_s}{auth_s}  [{mode}]")

    return True

def _pysh_run_script(path: Path, args: list | None = None) -> int:
    """
    Uruchamia plik .pysh jako skrypt shella (linia po linii).
    Linie zaczynające się od # są komentarzami.
    Linie #!... (shebang) są pomijane.
    Zwraca kod wyjścia ostatniej komendy.
    """
    global _SHELL_VERBOSE, _SHELL_DEBUG
    verbose  = cfg("pysh_verbose", False) or _SHELL_VERBOSE
    debug    = _SHELL_DEBUG

    try:
        source = path.read_text(encoding="utf-8")
    except Exception as e:
        print_error(f"Nie można odczytać {path}: {e}")
        return 1

    lines = source.splitlines()
    exit_code = 0

    # Ustaw argumenty pozycyjne ($1 $2 ...) w SHELL_VARS
    if args:
        for i, a in enumerate(args, 1):
            SHELL_VARS[str(i)] = a
        SHELL_VARS["@"] = " ".join(args)
        SHELL_VARS["#"] = str(len(args))

    log_debug(f"pysh run: {path.name}  ({len(lines)} linii)")

    for lineno, raw_line in enumerate(lines, 1):
        line = raw_line.strip()
        if not line or line.startswith("#"):
            continue
        # Rozwinięcie zmiennych
        try:
            line = _var_expand(line)
        except Exception:  # ignorowane celowo
            pass

        if debug:
            print(f"{C.DIM}[pysh:{path.stem}:{lineno}]+ {line}{C.RESET}",
                  file=sys.stderr)
        elif verbose:
            print(f"  {C.DIM}→ {line}{C.RESET}")

        log_debug(f"  pysh:{path.stem}:{lineno}: {line}")

        try:
            ret = execute_line(line)
            if ret is not None:
                exit_code = int(ret)
        except SystemExit as e:
            exit_code = e.code if isinstance(e.code, int) else 0
            break
        except Exception as e:
            print_error(f"[pysh:{path.stem}:{lineno}] {e}")
            log_error(f"pysh:{path.stem}:{lineno}: {e}")
            exit_code = 1
            if debug:
                break   # w trybie debug zatrzymaj na błędzie

    SHELL_VARS["?"] = str(exit_code)
    return exit_code

_PYSH_SCAFFOLD = '''\
"""
Moduł .pysh: {name}
Opis: TODO
"""

# Metadane modułu (opcjonalne, ale zalecane)
PYSH_META = {{
    "name":        "{name}",
    "version":     "1.0.0",
    "author":      "",
    "description": "Opis modułu {name}",
    "tags":        [],
}}

def register(api):
    """
    Wywoływana przy ładowaniu modułu (tryb pluginu).
    Usuń tę funkcję jeśli chcesz tryb skryptowy (linia po linii).
    """

    @api.command("{name}", "Komenda z modułu {name}")
    def cmd_{name}(args):
        """
        {name}         - wykonaj główną akcję
        {name} help    - pomoc
        """
        if args and args[0] == "help":
            api.print_info(f"Użycie: {name} [argumenty]  —  komenda z modułu {name}")
            return
        api.print_info("Witaj z modułu {name}!")

    api.print_info("Moduł {name} załadowany. Komenda: {name}")

def unregister(api):
    api.unregister_command("{name}")
'''

@command("pysh", "Zarządzaj modułami .pysh (dynamiczne rozszerzenia shella)",
         aliases=["module"])
def cmd_pysh(args):
    """
    pysh load <plik.pysh>    - załaduj moduł .pysh
    pysh run <plik.pysh>     - uruchom .pysh jako skrypt (jednorazowo)
    pysh list                - lista załadowanych modułów .pysh
    pysh reload [nazwa]      - hot-reload modułu (lub wszystkich)
    pysh unload <nazwa>      - wyładuj moduł .pysh
    pysh info <nazwa>        - szczegóły i metadane modułu
    pysh new <nazwa>         - utwórz szkielet nowego pliku .pysh
    pysh path                - pokaż ścieżkę wyszukiwania .pysh

    Tryb skryptowy: pysh run skrypt.pysh [arg1 arg2 ...]
    Tryb modułu:    pysh load modul.pysh  (musi mieć funkcję register())

    Opcje:
      --verbose     - szczegółowe logi przy ładowaniu/uruchamianiu
      --debug       - tryb debugowania (wyświetla każdą linię skryptu)
      --no-sandbox  - wyłącz sandbox dla tego ładowania
    """
    global _SHELL_VERBOSE, _SHELL_DEBUG

    if not args:
        print_error("Uzycie: pysh load|run|list|reload|unload|info|new|path")
        return

    # Flagi globalne dla tej operacji
    verbose_flag = "--verbose" in args
    debug_flag   = "--debug"   in args
    args = [a for a in args if not a.startswith("--")]

    subcmd = args[0]
    api    = ShellAPI()

    # ── list ──────────────────────────────────────────────────
    if subcmd == "list":
        if not PYSH_MODULES:
            print_info("Brak załadowanych modułów .pysh.")
            return
        w = min(terminal_width() - 2, 72)
        print()
        print(box_top(f"Moduły .pysh  ({len(PYSH_MODULES)})", width=w, color=C.EXEC))
        for name, mod in PYSH_MODULES.items():
            meta  = PYSH_META.get(name, {})
            ver   = meta.get("version", "")
            ver_s = f" v{ver}" if ver else ""
            mode  = "plugin" if hasattr(mod, "register") else "skrypt"
            fpath = meta.get("_file", "?")
            print(box_row(
                f"  {C.EXEC}{name:<20}{C.RESET}{ver_s:<8}"
                f" {C.DIM}[{mode}]  {fpath}{C.RESET}",
                width=w, color=C.EXEC))
        print(box_bottom(width=w, color=C.EXEC))
        print()

    # ── load ──────────────────────────────────────────────────
    elif subcmd == "load":
        if len(args) < 2:
            print_error("Uzycie: pysh load <plik.pysh>"); return
        path = _pysh_find(args[1])
        if path is None:
            print_error(f"Nie znaleziono: {args[1]}.pysh",
                        f"Ścieżka: {cfg('pysh_module_path','(cwd)')}"); return
        old_v, old_d = _SHELL_VERBOSE, _SHELL_DEBUG
        if verbose_flag: _SHELL_VERBOSE = True
        if debug_flag:   _SHELL_DEBUG   = True
        _pysh_load_file(path, api)
        _SHELL_VERBOSE, _SHELL_DEBUG = old_v, old_d

    # ── run ───────────────────────────────────────────────────
    elif subcmd == "run":
        if len(args) < 2:
            print_error("Uzycie: pysh run <plik.pysh> [arg1 arg2 ...]"); return
        path = _pysh_find(args[1])
        if path is None:
            print_error(f"Nie znaleziono: {args[1]}.pysh"); return
        script_args = args[2:]
        old_v, old_d = _SHELL_VERBOSE, _SHELL_DEBUG
        if verbose_flag: _SHELL_VERBOSE = True
        if debug_flag:   _SHELL_DEBUG   = True
        ret = _pysh_run_script(path, script_args)
        _SHELL_VERBOSE, _SHELL_DEBUG = old_v, old_d
        if ret != 0:
            print(f"  {C.DIM}[pysh] Kod wyjścia: {ret}{C.RESET}")

    # ── reload ────────────────────────────────────────────────
    elif subcmd == "reload":
        targets = ([args[1]] if len(args) >= 2 else list(PYSH_MODULES.keys()))
        for name in targets:
            if name not in PYSH_MODULES:
                print_error(f"Moduł nie jest załadowany: {name}"); continue
            mod  = PYSH_MODULES.pop(name)
            meta = PYSH_META.pop(name, {})
            fpath = Path(meta.get("_file", ""))
            sys.modules.pop(f"_terminalx_pysh_{name}", None)
            if hasattr(mod, "unregister"):
                try: mod.unregister(api)
                except Exception:
                    pass  # ignorowane celowo
            if fpath.exists():
                _pysh_load_file(fpath, api)
            else:
                print_error(f"Plik nie istnieje: {fpath}")
        if len(targets) > 1:
            print_info("Przeładowano wszystkie moduły .pysh.")

    # ── unload ────────────────────────────────────────────────
    elif subcmd == "unload":
        if len(args) < 2:
            print_error("Uzycie: pysh unload <nazwa>"); return
        name = args[1].removesuffix(".pysh")
        if name not in PYSH_MODULES:
            print_error(f"Moduł nie jest załadowany: {name}"); return
        mod = PYSH_MODULES.pop(name)
        PYSH_META.pop(name, None)
        sys.modules.pop(f"_terminalx_pysh_{name}", None)
        if hasattr(mod, "unregister"):
            try: mod.unregister(api)
            except Exception as e: print_error(f"Błąd unregister {name}: {e}")
        print_info(f"Wyładowano moduł .pysh: {name}")

    # ── info ──────────────────────────────────────────────────
    elif subcmd == "info":
        if len(args) < 2:
            print_error("Uzycie: pysh info <nazwa>"); return
        name = args[1].removesuffix(".pysh")
        if name not in PYSH_META:
            print_error(f"Nieznany moduł: {name}"); return
        meta = PYSH_META[name]
        w    = min(terminal_width() - 2, 66)
        print()
        print(box_top(f"Moduł .pysh: {name}", width=w, color=C.EXEC))
        fields = [
            ("Nazwa",    meta.get("name", name)),
            ("Wersja",   meta.get("version", "?")),
            ("Autor",    meta.get("author", "")),
            ("Opis",     meta.get("description", "")),
            ("Tagi",     ", ".join(meta.get("tags", []))),
            ("Plik",     meta.get("_file", "?")),
            ("Załadowano", meta.get("_loaded", "?")),
            ("Tryb",     meta.get("_type", "pysh")),
        ]
        for label, val in fields:
            if val and str(val).strip():
                print(box_row(kv_row(label, str(val), key_color=C.DIM),
                              width=w, color=C.EXEC))
        print(box_bottom(width=w, color=C.EXEC))
        print()

    # ── new ───────────────────────────────────────────────────
    elif subcmd == "new":
        if len(args) < 2:
            print_error("Uzycie: pysh new <nazwa>"); return
        name = args[1].removesuffix(".pysh")
        save_dir = cfg("pysh_module_path", "").split(os.pathsep)[0] \
                   if cfg("pysh_module_path", "") else "."
        out_path = Path(save_dir).expanduser() / f"{name}.pysh"
        if out_path.exists():
            print_error(f"Plik już istnieje: {out_path}"); return
        try:
            out_path.write_text(
                _PYSH_SCAFFOLD.format(name=name),
                encoding="utf-8"
            )
            print_info(f"Utworzono: {out_path}")
            print(f"  {C.DIM}Edytuj: nano {out_path}  |  Załaduj: pysh load {name}.pysh{C.RESET}")
        except Exception as e:
            print_error(f"Błąd tworzenia pliku: {e}")

    # ── path ──────────────────────────────────────────────────
    elif subcmd == "path":
        raw = cfg("pysh_module_path", "")
        dirs = [Path(d).expanduser() for d in raw.split(os.pathsep) if d.strip()]
        dirs = [Path(".")] + dirs
        w = min(terminal_width() - 2, 66)
        print()
        print(box_top("Ścieżka wyszukiwania .pysh", width=w, color=C.INFO))
        for d in dirs:
            exists = d.exists() and d.is_dir()
            icon   = C.PATH if exists else C.ERROR
            print(box_row(f"  {icon}{'✔' if exists else '✖'}{C.RESET}  {d}",
                          width=w, color=C.INFO))
        print(box_sep(width=w, color=C.INFO))
        print(box_row(f"  {C.DIM}config set pysh_module_path /twoja/sciezka{C.RESET}",
                      width=w, color=C.INFO))
        print(box_bottom(width=w, color=C.INFO))
        print()
        # Pokaż też dostępne pliki .pysh
        pysh_files = list(Path(".").glob("*.pysh"))
        if pysh_files:
            print(f"  {C.DIM}Pliki .pysh w cwd: "
                  f"{', '.join(f.name for f in pysh_files)}{C.RESET}\n")

    else:
        print_error(f"Nieznana subkomenda: pysh {subcmd}",
                    "Dostępne: load run list reload unload info new path")

# ── Auto-ładowanie .pysh przy starcie ────────────────────────
def _pysh_autoload():
    """Ładuje moduły .pysh z katalogu pysh_autoload_dir jeśli skonfigurowano."""
    global _SHELL_VERBOSE, _SHELL_DEBUG
    if not cfg("pysh_autoload", False):
        return
    auto_dir = cfg("pysh_autoload_dir", "")
    if not auto_dir:
        return
    d = Path(auto_dir).expanduser()
    if not d.is_dir():
        return
    api    = ShellAPI()
    silent = not cfg("pysh_verbose", False)
    for f in sorted(d.glob("*.pysh")):
        _pysh_load_file(f, api, silent=silent)

# VERBOSE_DEBUG
#   Globalny tryb verbose i debug dla TerminalXa.
#
#   Stany:
#     _SHELL_VERBOSE  — True/False: drukuje każdą uruchamianą komendę
#     _SHELL_DEBUG    — True/False: drukuje szczegółowe trace (jak set -x + więcej)
#
#   Komendy:
#     verbose [on|off|status]   — przełącz tryb verbose
#     debug   [on|off|status]   — przełącz tryb debug (implikuje verbose)
#
#   Logowanie (rozszerzone poziomy):
#     log_debug(msg)  — poziom DEBUG (widoczny tylko przy --log-level debug)
#     log_info(msg)   — poziom INFO
#     log_warn(msg)   — poziom WARN
#     log_error(msg)  — poziom ERROR
#     log_cmd(cmd)    — poziom CMD (każda wykonana komenda)
#
#   Filtrowanie logów w czasie rzeczywistym:
#     logs level debug|info|warn|cmd|error  — ustaw minimalny poziom logów

_SHELL_VERBOSE: bool = _STATE.shell_verbose
_SHELL_DEBUG:   bool = _STATE.shell_debug

# Kolory trybu verbose/debug
_VB_PREFIX = "\033[2;36m"    # dim cyan
_DB_PREFIX = "\033[2;33m"    # dim yellow
_RS        = "\033[0m"

def _verbose_print(line: str, prefix: str = "+"):
    """Drukuje linię w trybie verbose na stderr."""
    sys.stderr.write(f"{_VB_PREFIX}{prefix} {line}{_RS}\n")
    sys.stderr.flush()

def _debug_print(msg: str, level: str = "DBG"):
    """Drukuje komunikat debugowania na stderr."""
    ts = datetime.datetime.now().strftime("%H:%M:%S.%f")[:12]
    sys.stderr.write(f"{_DB_PREFIX}[{level} {ts}] {msg}{_RS}\n")
    sys.stderr.flush()

@command("verbose", "Włącz/wyłącz tryb verbose (echo komend przed wykonaniem)",
         aliases=["verb"])
def cmd_verbose(args):
    """
    verbose          - pokaż aktualny status
    verbose on       - włącz tryb verbose
    verbose off      - wyłącz tryb verbose
    verbose status   - szczegółowy status verbose + debug
    """
    sub = args[0].lower() if args else "status"

    if sub in ("on", "1", "true", "tak"):
        _STATE.shell_verbose = True
        cfg_set("shell_verbose", True, save=True)
        print_info(f"Tryb verbose {C.PATH}włączony{C.RESET}  "
                   f"(każda komenda będzie wypisywana przed wykonaniem)")

    elif sub in ("off", "0", "false", "nie"):
        _STATE.shell_verbose = False
        cfg_set("shell_verbose", False, save=True)
        print_info(f"Tryb verbose {C.ERROR}wyłączony{C.RESET}")

    else:
        _print_verbose_status()

def _print_verbose_status():
    """Drukuje status trybów verbose i debug."""
    global _SHELL_VERBOSE, _SHELL_DEBUG
    w = min(terminal_width() - 2, 58)
    print()
    print(box_top("Tryb Verbose / Debug", width=w, color=C.INFO))
    vb_s = f"{C.PATH}ON{C.RESET}" if _SHELL_VERBOSE else f"{C.ERROR}OFF{C.RESET}"
    db_s = f"{C.PATH}ON{C.RESET}" if _SHELL_DEBUG   else f"{C.ERROR}OFF{C.RESET}"
    sx_s = f"{C.PATH}ON{C.RESET}" if SHELL_VARS.get("_DEBUG") else f"{C.ERROR}OFF{C.RESET}"
    ll   = getattr(sys.modules[__name__], "_ACTIVE_LOG_LEVEL", "DEBUG")
    print(box_row(kv_row("verbose",       vb_s,    key_color=C.DIM), width=w, color=C.INFO))
    print(box_row(kv_row("debug",         db_s,    key_color=C.DIM), width=w, color=C.INFO))
    print(box_row(kv_row("set -x",        sx_s,    key_color=C.DIM), width=w, color=C.INFO))
    print(box_row(kv_row("log_level",     ll,      key_color=C.DIM), width=w, color=C.INFO))
    print(box_row(kv_row("pysh_verbose",
                         str(cfg("pysh_verbose", False)), key_color=C.DIM),
                  width=w, color=C.INFO))
    print(box_sep(width=w, color=C.INFO))
    print(box_row(f"  {C.DIM}verbose on|off  |  debug on|off  |  set -x / +x{C.RESET}",
                  width=w, color=C.INFO))
    print(box_bottom(width=w, color=C.INFO))
    print()

@command("debug", "Włącz/wyłącz tryb debug (pełne trace wykonania)",
         aliases=["dbg"])
def cmd_debug_mode(args):
    """
    debug          - pokaż aktualny status
    debug on       - włącz tryb debug (implikuje verbose + set -x)
    debug off      - wyłącz tryb debug
    debug trace    - wymuś jeden krok trace (bez utrwalania)
    debug status   - szczegółowy status wszystkich trybów

    W trybie debug:
      · każda komenda jest wypisywana na stderr przed wykonaniem
      · każdy błąd kończy skrypt .pysh
      · logi na poziomie DEBUG są widoczne
      · format: [DBG HH:MM:SS.mmm] komenda
    """
    sub = args[0].lower() if args else "status"

    if sub in ("on", "1", "true", "tak"):
        _STATE.shell_debug = True
        _STATE.shell_verbose = True
        SHELL_VARS["_DEBUG"] = "1"
        cfg_set("shell_debug",   True, save=True)
        cfg_set("shell_verbose", True, save=True)
        print_info(f"Tryb debug {C.PATH}włączony{C.RESET}  "
                   f"(verbose + trace + set -x)")

    elif sub in ("off", "0", "false", "nie"):
        _STATE.shell_debug = False
        _STATE.shell_verbose = False
        SHELL_VARS.pop("_DEBUG", None)
        cfg_set("shell_debug",   False, save=True)
        cfg_set("shell_verbose", False, save=True)
        print_info(f"Tryb debug {C.ERROR}wyłączony{C.RESET}")

    elif sub == "trace":
        # Jednorazowy trace bez utrwalania
        line = " ".join(args[1:]) if len(args) > 1 else ""
        if line:
            _debug_print(f"TRACE: {line}")
        else:
            print_info("Uzycie: debug trace <komenda>")

    else:
        _print_verbose_status()

# ── Integracja verbose/debug z główną pętlą ──────────────────
# Rozszerzamy _log o obsługę verbose/debug bez monkey-patchingu.
# Zamiast zamieniać globalny _log (co narastałoby przy reload),
# używamy flagi _LOG_VERBOSE_PATCHED by upewnić się że patch
# aplikowany jest tylko raz w cyklu życia procesu.

_LOG_VERBOSE_PATCHED: bool = False

def _ensure_verbose_log_patch():
    """
    Aplikuje patch verbose/debug do _log dokładnie raz.
    Bezpieczne przy wielokrotnym wywołaniu (idempotent).
    """
    global _SHELL_DEBUG
    global _log, _LOG_VERBOSE_PATCHED
    if _LOG_VERBOSE_PATCHED:
        return
    _base_log = _log  # zachowaj referencję do oryginalnej funkcji

    def _verbose_aware_log(level: str, msg: str):
        """Rozszerzone _log — wyświetla DEBUG na stderr w trybie debug."""
        _base_log(level, msg)
        if _SHELL_DEBUG and level == "DEBUG":
            _debug_print(msg, level)
        # CMD jest widoczny bezpośrednio w main loop — brak dodatkowego echo

    _log = _verbose_aware_log
    _LOG_VERBOSE_PATCHED = True

_ensure_verbose_log_patch()

# ── Hook verbose do pętli głównej ────────────────────────────
# Rejestrujemy before_cmd hook który wypisuje komendę w trybie verbose

def _verbose_before_cmd(cmd: str, args_list: list):
    """Hook before_cmd — wypisuje komendę w trybie verbose/debug."""
    if _SHELL_DEBUG:
        _debug_print(f"{cmd} {' '.join(args_list)}", "CMD")
    elif _SHELL_VERBOSE:
        _verbose_print(f"{cmd} {' '.join(str(a) for a in args_list)}")

try:
    _before_hooks = PLUGIN_HOOKS.setdefault("before_cmd", [])
    if _verbose_before_cmd not in _before_hooks:
        _before_hooks.append(_verbose_before_cmd)
except Exception:  # ignorowane celowo
    pass

# ── Nowe klucze w _CONFIG_DEFAULTS ───────────────────────────
_CONFIG_DEFAULTS.setdefault("shell_verbose",    False)   # verbose tryb
_CONFIG_DEFAULTS.setdefault("shell_debug",      False)   # debug tryb

# ── Odczyt verbose/debug z config przy starcie ───────────────
def _init_verbose_debug():
    """Inicjalizuje tryby verbose/debug z konfiguracji."""
    _STATE.shell_verbose = bool(cfg("shell_verbose", False))
    _STATE.shell_debug = bool(cfg("shell_debug",   False))
    if _SHELL_DEBUG:
        SHELL_VARS["_DEBUG"] = "1"

