# ── sysmon — monitor zasobów systemowych ─────────────────────────────────────

@command("sysmon", "Monitor zasobów systemowych (CPU, RAM, dyski, procesy)",
         aliases=["top"],
         flags=[
             ("--watch", "-w", "Odświeżaj co sekundę (Ctrl+C aby zatrzymać)"),
             ("--procs", "-p", "Pokaż listę procesów"),
             ("--json",  "-j", "Wyjście w formacie JSON"),
         ])
def cmd_sysmon(args):
    """
    sysmon              — jednorazowy snapshot zasobów
    sysmon --watch      — odświeżanie co 1s (Ctrl+C = stop)
    sysmon --procs      — lista procesów (PID, CPU%, MEM, cmd)
    sysmon --json       — wyjście JSON (do pipeline'u)

    Wyświetla: CPU, RAM, swap, dyski, czas pracy, top procesy.
    Działa bez zewnętrznych zależności (tylko stdlib).
    """
    import time

    watch = "--watch" in args or "-w" in args
    show_procs = "--procs" in args or "-p" in args
    as_json = "--json" in args or "-j" in args

    def _read_cpu_times():
        """Odczytuje czasy CPU z /proc/stat (Linux) lub zwraca None."""
        try:
            with open("/proc/stat") as f:
                line = f.readline()
            vals = list(map(int, line.split()[1:]))
            idle = vals[3] + (vals[4] if len(vals) > 4 else 0)
            total = sum(vals)
            return total, idle
        except Exception:
            return None, None

    def _get_cpu_percent(interval=0.2):
        """Mierzy użycie CPU przez krótki interval."""
        t1, i1 = _read_cpu_times()
        if t1 is None:
            # Windows / brak /proc — użyj subprocess
            try:
                import subprocess
                if os.name == "nt":
                    out = subprocess.check_output(
                        ["wmic", "cpu", "get", "loadpercentage", "/value"],
                        text=True, timeout=3
                    )
                    for line in out.splitlines():
                        if "LoadPercentage=" in line:
                            return float(line.split("=")[1].strip())
            except Exception:
                pass
            return None
        time.sleep(interval)
        t2, i2 = _read_cpu_times()
        dt = t2 - t1
        di = i2 - i1
        return round(100.0 * (1.0 - di / dt), 1) if dt > 0 else 0.0

    def _get_mem():
        """Zwraca (total_mb, used_mb, free_mb, percent) lub None."""
        try:
            with open("/proc/meminfo") as f:
                info = {}
                for line in f:
                    k, v = line.split(":")
                    info[k.strip()] = int(v.strip().split()[0])
            total = info.get("MemTotal", 0)
            free  = info.get("MemFree", 0) + info.get("Buffers", 0) + info.get("Cached", 0)
            used  = total - free
            pct   = round(100.0 * used / total, 1) if total else 0
            return total // 1024, used // 1024, free // 1024, pct
        except Exception:
            pass
        # Windows fallback
        try:
            import subprocess
            out = subprocess.check_output(
                ["wmic", "OS", "get", "TotalVisibleMemorySize,FreePhysicalMemory", "/value"],
                text=True, timeout=3
            )
            vals = {}
            for line in out.splitlines():
                if "=" in line:
                    k, v = line.split("=", 1)
                    try:
                        vals[k.strip()] = int(v.strip())
                    except ValueError:
                        pass
            total = vals.get("TotalVisibleMemorySize", 0) // 1024
            free  = vals.get("FreePhysicalMemory", 0) // 1024
            used  = total - free
            pct   = round(100.0 * used / total, 1) if total else 0
            return total, used, free, pct
        except Exception:
            return None

    def _get_disks():
        """Zwraca listę (mount, total_gb, used_gb, free_gb, pct)."""
        disks = []
        try:
            import subprocess
            if os.name == "nt":
                drives = [f"{c}:\\" for c in "CDEFGHIJKLMNOPQRSTUVWXYZ" if os.path.exists(f"{c}:\\")]
                for d in drives:
                    try:
                        st = shutil.disk_usage(d)
                        disks.append((d, round(st.total/1e9,1), round(st.used/1e9,1),
                                      round(st.free/1e9,1), round(100*st.used/st.total,1)))
                    except Exception:
                        pass
            else:
                with open("/proc/mounts") as f:
                    for line in f:
                        parts = line.split()
                        if len(parts) < 2 or parts[1] in ("/proc", "/sys", "/dev", "/run"):
                            continue
                        mp = parts[1]
                        try:
                            st = shutil.disk_usage(mp)
                            if st.total > 0:
                                disks.append((mp, round(st.total/1e9,1), round(st.used/1e9,1),
                                              round(st.free/1e9,1), round(100*st.used/st.total,1)))
                        except Exception:
                            pass
        except Exception:
            try:
                st = shutil.disk_usage("/")
                disks = [("/", round(st.total/1e9,1), round(st.used/1e9,1),
                          round(st.free/1e9,1), round(100*st.used/st.total,1))]
            except Exception:
                pass
        return disks[:6]  # max 6 dysków

    def _get_uptime():
        """Zwraca uptime jako string."""
        try:
            with open("/proc/uptime") as f:
                secs = float(f.read().split()[0])
            h, rem = divmod(int(secs), 3600)
            m, s   = divmod(rem, 60)
            return f"{h}h {m}m {s}s"
        except Exception:
            try:
                if os.name == "nt":
                    import subprocess
                    out = subprocess.check_output(
                        ["net", "statistics", "server"], text=True, timeout=3
                    )
                    for line in out.splitlines():
                        if "since" in line.lower() or "Statistics since" in line:
                            return line.strip()
            except Exception:
                pass
            return "N/A"

    def _get_top_procs(n=8):
        """Zwraca n najcięższych procesów jako listę (pid, name, cpu%, mem_mb)."""
        procs = []
        try:
            proc_dir = "/proc"
            for entry in os.listdir(proc_dir):
                if not entry.isdigit():
                    continue
                pid = entry
                try:
                    with open(f"/proc/{pid}/comm") as f:
                        name = f.read().strip()
                    with open(f"/proc/{pid}/statm") as f:
                        pages = int(f.read().split()[1])
                    mem_mb = pages * 4096 // (1024 * 1024)
                    procs.append((int(pid), name, 0.0, mem_mb))
                except Exception:
                    pass
            procs.sort(key=lambda x: x[3], reverse=True)
        except Exception:
            # Windows
            try:
                import subprocess
                out = subprocess.check_output(
                    ["wmic", "process", "get", "ProcessId,Name,WorkingSetSize", "/format:csv"],
                    text=True, timeout=5
                )
                for line in out.splitlines()[2:]:
                    parts = line.strip().split(",")
                    if len(parts) >= 4:
                        try:
                            name = parts[2]
                            pid  = int(parts[3])
                            mem  = int(parts[1]) // (1024 * 1024)
                            procs.append((pid, name, 0.0, mem))
                        except (ValueError, IndexError):
                            pass
                procs.sort(key=lambda x: x[3], reverse=True)
            except Exception:
                pass
        return procs[:n]

    def _bar(pct, width=20, warn=70, crit=90):
        """Pasek postępu z kolorami."""
        filled = int(width * pct / 100)
        bar = "█" * filled + "░" * (width - filled)
        if pct >= crit:
            color = C.ERROR
        elif pct >= warn:
            color = C.WARN
        else:
            color = C.OK
        return f"{color}{bar}{C.RESET} {pct:5.1f}%"

    def _snapshot():
        cpu  = _get_cpu_percent()
        mem  = _get_mem()
        disks= _get_disks()
        up   = _get_uptime()
        now  = datetime.datetime.now().strftime("%H:%M:%S")
        return cpu, mem, disks, up, now

    def _print_snapshot(cpu, mem, disks, up, now):
        w = terminal_width() - 2
        print()
        print(box_top(f"  🖥️  sysmon  ·  {now}  ·  uptime: {up}  ", width=w, color=C.PROMPT))
        print(box_sep(width=w, color=C.PROMPT))

        # CPU
        if cpu is not None:
            print(box_row(f"  CPU          {_bar(cpu)}", width=w, color=C.PROMPT))
        else:
            print(box_row(f"  CPU          N/A", width=w, color=C.PROMPT))

        # RAM
        if mem:
            total, used, free, pct = mem
            print(box_row(
                f"  RAM          {_bar(pct)}   {used:,} / {total:,} MB  (wolne: {free:,} MB)",
                width=w, color=C.PROMPT
            ))
        else:
            print(box_row("  RAM          N/A", width=w, color=C.PROMPT))

        # Dyski
        if disks:
            print(box_sep(width=w, color=C.PROMPT))
            for mp, tot, used_g, free_g, pct in disks:
                label = f"  {mp:<12}"
                print(box_row(
                    f"{label} {_bar(pct)}   {used_g} / {tot} GB  (wolne: {free_g} GB)",
                    width=w, color=C.PROMPT
                ))

        # Procesy
        if show_procs:
            procs = _get_top_procs()
            if procs:
                print(box_sep(width=w, color=C.PROMPT))
                print(box_row(
                    f"  {'PID':<8} {'NAZWA':<22} {'RAM (MB)':>8}",
                    width=w, color=C.PROMPT
                ))
                for pid, name, cpu_p, mem_mb in procs:
                    print(box_row(
                        f"  {pid:<8} {name:<22} {mem_mb:>8}",
                        width=w, color=C.PROMPT
                    ))

        print(box_bottom(width=w, color=C.PROMPT))
        print()

    if as_json:
        import json as _json
        cpu, mem, disks, up, now = _snapshot()
        data = {
            "time": now, "uptime": up,
            "cpu_pct": cpu,
            "ram": {"total_mb": mem[0], "used_mb": mem[1], "free_mb": mem[2], "pct": mem[3]} if mem else None,
            "disks": [{"mount": m, "total_gb": t, "used_gb": u, "free_gb": f, "pct": p}
                      for m, t, u, f, p in disks],
        }
        print(_json.dumps(data, indent=2, ensure_ascii=False))
        return

    if watch:
        print_info("sysmon — tryb watch. Ctrl+C aby zatrzymać.")
        try:
            while True:
                # Wyczyść poprzednie linie (prosta metoda)
                cpu, mem, disks, up, now = _snapshot()
                _print_snapshot(cpu, mem, disks, up, now)
                time.sleep(1)
                # Przesuń kursor w górę by nadpisać
                lines_count = 5 + len(disks) + (len(_get_top_procs()) + 2 if show_procs else 0)
                sys.stdout.write(f"\033[{lines_count + 4}A")
        except KeyboardInterrupt:
            print_info("sysmon zatrzymany.")
        return

    cpu, mem, disks, up, now = _snapshot()
    _print_snapshot(cpu, mem, disks, up, now)


# ── timer — stoper i countdown ───────────────────────────────────────────────

@command("timer", "Stoper, odliczanie i alarm czasowy",
         flags=[
             ("--alarm", "-a", "Alarm po upływie czasu"),
         ])
def cmd_timer(args):
    """
    timer               — uruchom stoper (Ctrl+C = stop i wyświetl czas)
    timer 5m            — odliczanie 5 minut
    timer 1h30m         — odliczanie 1h 30min
    timer 90            — odliczanie 90 sekund
    timer --alarm 10m   — stoper + dźwięk po 10 minutach
    """
    import time, re as _re

    def _parse_duration(s):
        """Parsuje '5m', '1h30m', '90' → sekundy."""
        s = s.strip().lower()
        if _re.fullmatch(r'\d+', s):
            return int(s)
        total = 0
        for val, unit in _re.findall(r'(\d+)([hms])', s):
            if unit == 'h':   total += int(val) * 3600
            elif unit == 'm': total += int(val) * 60
            elif unit == 's': total += int(val)
        return total if total > 0 else None

    def _fmt(secs):
        h, r = divmod(int(secs), 3600)
        m, s = divmod(r, 60)
        if h:
            return f"{h:02d}:{m:02d}:{s:02d}"
        return f"{m:02d}:{s:02d}"

    def _beep():
        """Próbuje zagrać dźwięk alarmu."""
        try:
            if os.name == "nt":
                import winsound
                for _ in range(3):
                    winsound.Beep(880, 300)
            else:
                sys.stdout.write("\a")
                sys.stdout.flush()
        except Exception:
            pass

    # Filtruj flagi
    clean_args = [a for a in args if not a.startswith("-")]
    alarm_flag = "--alarm" in args or "-a" in args

    if not clean_args:
        # Tryb stopera
        print_info("⏱  Stoper uruchomiony. Naciśnij Ctrl+C aby zatrzymać.")
        start = time.time()
        try:
            while True:
                elapsed = time.time() - start
                sys.stdout.write(f"\r  ⏱  {_fmt(elapsed)}  ")
                sys.stdout.flush()
                time.sleep(0.1)
        except KeyboardInterrupt:
            elapsed = time.time() - start
            sys.stdout.write("\n")
            print_info(f"Czas: {_fmt(elapsed)}  ({elapsed:.2f}s)")
        return

    # Tryb odliczania
    duration = _parse_duration(clean_args[0])
    if duration is None or duration <= 0:
        print_error(f"Nieprawidłowy czas: {clean_args[0]}",
                    "Przykłady: 30  90  5m  1h30m  2h")
        return

    print_info(f"⏳ Odliczam {_fmt(duration)}... Ctrl+C = przerwij")
    start = time.time()
    end   = start + duration

    try:
        while True:
            remaining = end - time.time()
            if remaining <= 0:
                break
            bar_w = 30
            done  = int(bar_w * (1 - remaining / duration))
            bar   = "█" * done + "░" * (bar_w - done)
            color = C.ERROR if remaining < 10 else (C.WARN if remaining < 60 else C.OK)
            sys.stdout.write(
                f"\r  {color}{bar}{C.RESET}  {_fmt(remaining)} pozostało  "
            )
            sys.stdout.flush()
            time.sleep(0.1)
    except KeyboardInterrupt:
        sys.stdout.write("\n")
        print_warn("Odliczanie przerwane.")
        return

    sys.stdout.write("\n")
    print_info(f"✅ Czas minął! ({_fmt(duration)})")
    if alarm_flag:
        _beep()


# ── calc — kalkulator wyrażeń ─────────────────────────────────────────────────

@command("calc", "Kalkulator wyrażeń matematycznych",
         aliases=["math"],
         flags=[
             ("--deg", "-d", "Tryb stopni (zamiast radianów)"),
         ])
def cmd_calc(args):
    """
    calc 2+2            — wynik: 4
    calc "sqrt(2)"      — wynik: 1.4142...
    calc "sin(pi/2)"    — wynik: 1.0
    calc --deg "sin(90)"— w stopniach: 1.0
    calc                — tryb interaktywny (quit = wyjście)

    Dostępne funkcje: sqrt, sin, cos, tan, log, log2, log10,
                      abs, ceil, floor, round, pi, e, tau, inf
    """
    import math as _math

    use_deg = "--deg" in args or "-d" in args
    expr_args = [a for a in args if not a.startswith("-")]

    _ns = {
        "sqrt": _math.sqrt,   "sin": (lambda x: _math.sin(_math.radians(x))) if use_deg else _math.sin,
        "cos":  (lambda x: _math.cos(_math.radians(x))) if use_deg else _math.cos,
        "tan":  (lambda x: _math.tan(_math.radians(x))) if use_deg else _math.tan,
        "asin": (lambda x: _math.degrees(_math.asin(x))) if use_deg else _math.asin,
        "acos": (lambda x: _math.degrees(_math.acos(x))) if use_deg else _math.acos,
        "atan": (lambda x: _math.degrees(_math.atan(x))) if use_deg else _math.atan,
        "log":  _math.log,    "log2":  _math.log2,  "log10": _math.log10,
        "abs":  abs,           "ceil":  _math.ceil,  "floor": _math.floor,
        "round": round,        "pow":   pow,
        "pi":   _math.pi,     "e":     _math.e,     "tau":   _math.tau,
        "inf":  _math.inf,    "nan":   _math.nan,
        "hex":  hex,           "bin":   bin,          "oct":   oct,
        "__builtins__": {},
    }

    def _eval(expr):
        expr = expr.strip()
        if not expr:
            return None
        try:
            result = eval(expr, _ns)  # nosec — ograniczony namespace
            return result
        except ZeroDivisionError:
            return "Błąd: dzielenie przez zero"
        except (SyntaxError, NameError, TypeError) as exc:
            return f"Błąd: {exc}"

    def _fmt_result(result):
        if isinstance(result, float):
            if result == int(result) and abs(result) < 1e15:
                return f"{int(result)}"
            return f"{result:.10g}"
        return str(result)

    if expr_args:
        expr = " ".join(expr_args)
        result = _eval(expr)
        if result is not None:
            print(f"  {C.BOLD}{_fmt_result(result)}{C.RESET}")
        return

    # Tryb interaktywny
    w = terminal_width() - 2
    mode_str = "stopnie" if use_deg else "radiany"
    print()
    print(box_top(f"  🔢  calc  ·  tryb: {mode_str}  ·  quit = wyjście  ", width=w, color=C.INFO))
    history_calc = []
    while True:
        try:
            expr = input(f"  {C.PROMPT}calc>{C.RESET} ").strip()
        except (EOFError, KeyboardInterrupt):
            print()
            break
        if expr.lower() in ("quit", "exit", "q", "wyjście"):
            break
        if not expr:
            continue
        if expr.lower() in ("help", "?", "pomoc"):
            print(box_row("  Funkcje: sqrt sin cos tan asin acos atan log log2 log10", width=w, color=C.INFO))
            print(box_row("  Stałe:   pi  e  tau  inf  nan", width=w, color=C.INFO))
            print(box_row("  Tryb:    --deg (stopnie)  domyślnie: radiany", width=w, color=C.INFO))
            continue
        result = _eval(expr)
        if result is not None:
            r_str = _fmt_result(result)
            history_calc.append(f"{expr} = {r_str}")
            print(f"  {C.OK}={C.RESET} {C.BOLD}{r_str}{C.RESET}")
            # Zapisz wynik do zmiennej _ans w namespace
            try:
                _ns["ans"] = float(r_str)
            except (ValueError, TypeError):
                pass
    print(box_bottom(width=w, color=C.INFO))


# ── netmon — monitor sieci ────────────────────────────────────────────────────

@command("netmon", "Monitor połączeń sieciowych i interfejsów",
         flags=[
             ("--ports", "-p", "Pokaż otwarte porty"),
             ("--ping",  "-P", "Ping do popularnych hostów"),
         ])
def cmd_netmon(args):
    """
    netmon              — lista aktywnych interfejsów i ich adresów IP
    netmon --ports      — otwarte porty (nasłuchujące gniazda)
    netmon --ping       — szybki ping do 8.8.8.8, 1.1.1.1, google.com
    """
    import socket, subprocess as _sp

    show_ports = "--ports" in args or "-p" in args
    do_ping    = "--ping"  in args or "-P" in args
    w = terminal_width() - 2

    print()
    print(box_top("  🌐  netmon — Monitor sieci  ", width=w, color=C.INFO))

    # ── Interfejsy / IP ───────────────────────────────────────
    print(box_sep(width=w, color=C.INFO))
    print(box_row("  INTERFEJSY", width=w, color=C.INFO))
    try:
        hostname = socket.gethostname()
        print(box_row(f"  hostname       {hostname}", width=w, color=C.INFO))
        # Próbuj uzyskać lokalne IP
        try:
            s = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
            s.connect(("8.8.8.8", 80))
            local_ip = s.getsockname()[0]
            s.close()
            print(box_row(f"  IP lokalne     {local_ip}", width=w, color=C.INFO))
        except Exception:
            print(box_row(f"  IP lokalne     N/A (offline?)", width=w, color=C.INFO))

        # Linux: /proc/net/if_inet6 + /proc/net/fib_trie
        if os.path.exists("/proc/net/if_inet6"):
            try:
                with open("/proc/net/if_inet6") as f:
                    for line in f:
                        parts = line.split()
                        if len(parts) >= 6:
                            iface = parts[5]
                            # Pomiń loopback
                            if iface != "lo":
                                print(box_row(f"  IPv6 {iface:<10} (aktywny)", width=w, color=C.INFO))
            except Exception:
                pass
    except Exception as exc:
        print(box_row(f"  Błąd: {exc}", width=w, color=C.INFO))

    # ── Otwarte porty ─────────────────────────────────────────
    if show_ports:
        print(box_sep(width=w, color=C.INFO))
        print(box_row("  OTWARTE PORTY (nasłuchujące)", width=w, color=C.INFO))
        try:
            if os.name == "nt":
                out = _sp.check_output(["netstat", "-an"], text=True, timeout=5)
            else:
                out = _sp.check_output(["ss", "-tlnp"], text=True, timeout=5)
            ports_shown = 0
            for line in out.splitlines():
                if ("LISTEN" in line or "LISTENING" in line) and ports_shown < 15:
                    print(box_row(f"  {line.strip()[:w-6]}", width=w, color=C.INFO))
                    ports_shown += 1
            if ports_shown == 0:
                # Fallback: netstat
                try:
                    out2 = _sp.check_output(["netstat", "-tlnp"], text=True, timeout=5)
                    for line in out2.splitlines()[2:]:
                        if "LISTEN" in line and ports_shown < 15:
                            print(box_row(f"  {line.strip()[:w-6]}", width=w, color=C.INFO))
                            ports_shown += 1
                except Exception:
                    pass
        except Exception as exc:
            print(box_row(f"  Błąd odczytu portów: {exc}", width=w, color=C.INFO))

    # ── Ping ──────────────────────────────────────────────────
    if do_ping:
        print(box_sep(width=w, color=C.INFO))
        print(box_row("  PING", width=w, color=C.INFO))
        hosts = ["8.8.8.8", "1.1.1.1", "google.com", "github.com"]
        for host in hosts:
            try:
                import time as _time
                t0 = _time.time()
                s = socket.create_connection((host, 80), timeout=2)
                ms = round((_time.time() - t0) * 1000, 1)
                s.close()
                print(box_row(f"  {host:<20} {C.OK}✔ {ms}ms{C.RESET}", width=w, color=C.INFO))
            except Exception:
                print(box_row(f"  {host:<20} {C.ERROR}✖ niedostępny{C.RESET}", width=w, color=C.INFO))

    print(box_bottom(width=w, color=C.INFO))
    print()


# ── jq — przeglądarka i filtrowanie JSON ─────────────────────────────────────

@command("jsonview", "Przeglądarka i filtrowanie JSON",
         aliases=["jv"],
         flags=[
             ("--compact", "-c", "Wyjście kompaktowe (bez wcięć)"),
             ("--keys",    "-k", "Pokaż tylko klucze (obiekty)"),
             ("--raw",     "-r", "Surowy output (bez kolorów)"),
         ])
def cmd_jsonview(args):
    """
    jsonview plik.json              — podgląd pliku JSON z kolorowaniem
    jsonview plik.json .key         — wyciągnij wartość klucza
    jsonview plik.json .arr[0]      — pierwszy element tablicy
    jsonview plik.json --keys       — lista kluczy obiektu
    echo '{"a":1}' | jsonview       — z stdin
    cat data.json | jsonview .name  — pipeline

    Ścieżki: .key  .key.sub  .arr[0]  .arr[*]  (podstawowy JQ-like)
    """
    import json as _json

    compact = "--compact" in args or "-c" in args
    keys_only = "--keys" in args or "-k" in args
    raw = "--raw" in args or "-r" in args
    clean = [a for a in args if not a.startswith("-")]

    # Wczytaj dane: plik lub stdin
    data_str = None
    path_expr = None

    if clean:
        fname = clean[0]
        path_expr = clean[1] if len(clean) > 1 else None
        try:
            with open(fname, "r", encoding="utf-8") as f:
                data_str = f.read()
        except FileNotFoundError:
            # Może to wyrażenie ścieżki bez pliku (stdin)?
            if fname.startswith("."):
                path_expr = fname
                data_str = None
            else:
                print_error(f"Nie znaleziono pliku: {fname}"); return
        except Exception as exc:
            print_error(f"Błąd odczytu: {exc}"); return
    
    if data_str is None:
        # Spróbuj stdin
        if not sys.stdin.isatty():
            try:
                data_str = sys.stdin.read()
            except Exception:
                pass
        if not data_str:
            print_error("Podaj plik JSON lub dane przez stdin",
                        "Użycie: jsonview plik.json [.ścieżka]")
            return

    try:
        data = _json.loads(data_str)
    except _json.JSONDecodeError as exc:
        print_error(f"Nieprawidłowy JSON: {exc}")
        return

    def _extract(obj, expr):
        """Prosta ewaluacja wyrażeń: .key .key.sub .arr[0] .arr[*]"""
        if not expr or expr == ".":
            return obj
        parts = expr.lstrip(".")
        import re as _re
        tokens = _re.split(r'\.(?![^\[]*\])', parts)
        cur = obj
        for tok in tokens:
            if not tok:
                continue
            arr_m = _re.match(r'^(\w+)\[(\d+|\*)\]$', tok)
            if arr_m:
                key, idx = arr_m.groups()
                if key:
                    cur = cur[key] if isinstance(cur, dict) else cur
                if idx == "*":
                    cur = list(cur) if isinstance(cur, (list, tuple)) else cur
                else:
                    cur = cur[int(idx)]
            else:
                cur = cur[tok] if isinstance(cur, dict) else cur
        return cur

    try:
        result = _extract(data, path_expr) if path_expr else data
    except (KeyError, IndexError, TypeError) as exc:
        print_error(f"Błąd ścieżki '{path_expr}': {exc}"); return

    if keys_only:
        if isinstance(result, dict):
            for k in result.keys():
                print(f"  {C.INFO}{k}{C.RESET}")
        elif isinstance(result, list):
            print_info(f"Tablica {len(result)} elementów")
        else:
            print(str(result))
        return

    # Formatowanie
    if compact:
        out = _json.dumps(result, ensure_ascii=False, separators=(",", ":"))
    else:
        out = _json.dumps(result, ensure_ascii=False, indent=2)

    if raw or _ANSI_DISABLED:
        print(out)
        return

    # Kolorowanie
    def _colorize(text):
        lines_out = []
        for line in text.splitlines():
            line = _RE_JQ_KEY.sub(
                lambda m: f"{m.group(1)}{C.PATH}{m.group(2)}{C.RESET}{m.group(3)}{m.group(4)}", line
            )
            line = _RE_JQ_NUM.sub(
                lambda m: m.group(0).replace(m.group(1), f"{C.WARN}{m.group(1)}{C.RESET}"), line
            )
            line = line.replace('"true"',  f'{C.OK}"true"{C.RESET}')
            line = line.replace('"false"', f'{C.ERROR}"false"{C.RESET}')
            line = line.replace(': true',  f': {C.OK}true{C.RESET}')
            line = line.replace(': false', f': {C.ERROR}false{C.RESET}')
            line = line.replace(': null',  f': {C.DIM}null{C.RESET}')
            lines_out.append(line)
        return "\n".join(lines_out)

    print(_colorize(out))


# ── diffview — porównanie plików ──────────────────────────────────────────────

@command("diffview", "Porównanie dwóch plików z kolorowaniem",
         aliases=["diff"],
         flags=[
             ("--lines", "-n", "Liczba linii kontekstu (domyślnie 3)"),
             ("--brief", "-b", "Tylko czy pliki są różne"),
         ])
def cmd_diffview(args):
    """
    diffview plik1 plik2        — porównanie z kolorowaniem
    diffview plik1 plik2 -n 5   — z 5 liniami kontekstu
    diffview plik1 plik2 --brief— tylko informacja czy różne
    """
    import difflib

    brief = "--brief" in args or "-b" in args
    ctx_lines = 3
    clean = []
    i = 0
    while i < len(args):
        if args[i] in ("-n", "--lines") and i + 1 < len(args):
            try:
                ctx_lines = int(args[i + 1])
            except ValueError:
                pass
            i += 2
            continue
        if not args[i].startswith("-"):
            clean.append(args[i])
        i += 1

    if len(clean) < 2:
        print_error("Podaj dwa pliki do porównania",
                    "Użycie: diffview plik1 plik2 [-n linie]"); return

    f1, f2 = clean[0], clean[1]
    for fp in (f1, f2):
        if not os.path.exists(fp):
            print_error(f"Plik nie istnieje: {fp}"); return

    try:
        with open(f1, "r", encoding="utf-8", errors="replace") as f:
            lines1 = f.readlines()
        with open(f2, "r", encoding="utf-8", errors="replace") as f:
            lines2 = f.readlines()
    except Exception as exc:
        print_error(f"Błąd odczytu: {exc}"); return

    if brief:
        if lines1 == lines2:
            print_info(f"Pliki są identyczne: {f1}  ==  {f2}")
        else:
            diff_count = sum(1 for a, b in zip(lines1, lines2) if a != b)
            diff_count += abs(len(lines1) - len(lines2))
            print_warn(f"Pliki RÓŻNIĄ się: {f1}  !=  {f2}  ({diff_count} różnych linii)")
        return

    w = terminal_width() - 2
    diff = list(difflib.unified_diff(lines1, lines2, fromfile=f1, tofile=f2, n=ctx_lines))

    if not diff:
        print_info(f"Pliki są identyczne: {f1}  ==  {f2}")
        return

    print()
    print(box_top(f"  ⚖  diffview  {f1} ↔ {f2}  ", width=w, color=C.PROMPT))
    adds = dels = 0
    for line in diff:
        line = line.rstrip("\n")
        if line.startswith("+++") or line.startswith("---"):
            print(f"  {C.BOLD}{line}{C.RESET}")
        elif line.startswith("@@"):
            print(f"\n  {C.DIM}{line}{C.RESET}")
        elif line.startswith("+"):
            adds += 1
            print(f"  {C.OK}{line}{C.RESET}")
        elif line.startswith("-"):
            dels += 1
            print(f"  {C.ERROR}{line}{C.RESET}")
        else:
            print(f"  {C.DIM}{line}{C.RESET}")
    print()
    print(box_row(
        f"  Zmiany: {C.OK}+{adds} dodanych{C.RESET}  {C.ERROR}-{dels} usuniętych{C.RESET}",
        width=w, color=C.PROMPT
    ))
    print(box_bottom(width=w, color=C.PROMPT))
    print()


# ── base64 — kodowanie / dekodowanie ─────────────────────────────────────────

@command("b64", "Kodowanie i dekodowanie Base64",
         aliases=["base64"],
         flags=[
             ("--decode", "-d", "Dekoduj (domyślnie: koduj)"),
             ("--file",   "-f", "Operacja na pliku zamiast tekstu"),
         ])
def cmd_b64(args):
    """
    b64 "tekst"             — zakoduj tekst do Base64
    b64 -d "dGVrc3Q="       — dekoduj Base64
    b64 -f plik.bin         — zakoduj plik
    b64 -d -f plik.b64      — zdekoduj plik Base64
    echo "tekst" | b64      — z stdin
    """
    import base64 as _b64

    decode = "--decode" in args or "-d" in args
    use_file = "--file" in args or "-f" in args
    clean = [a for a in args if not a.startswith("-")]

    if use_file and clean:
        fname = clean[0]
        try:
            with open(fname, "rb") as f:
                data = f.read()
        except Exception as exc:
            print_error(f"Błąd odczytu pliku: {exc}"); return
        if decode:
            try:
                result = _b64.b64decode(data)
                sys.stdout.buffer.write(result)
            except Exception as exc:
                print_error(f"Błąd dekodowania: {exc}")
        else:
            result = _b64.b64encode(data).decode("ascii")
            # Wstawiaj łamania co 76 znaków
            for i in range(0, len(result), 76):
                print(result[i:i+76])
        return

    # Tekst lub stdin
    if clean:
        text = " ".join(clean)
    elif not sys.stdin.isatty():
        text = sys.stdin.read().rstrip("\n")
    else:
        print_error("Podaj tekst lub użyj -f dla pliku"); return

    if decode:
        try:
            result = _b64.b64decode(text.encode()).decode("utf-8", errors="replace")
            print(result)
        except Exception as exc:
            print_error(f"Błąd dekodowania Base64: {exc}")
    else:
        result = _b64.b64encode(text.encode("utf-8")).decode("ascii")
        print(result)


# ── hash — sumy kontrolne plików i tekstu ────────────────────────────────────

@command("hash", "Sumy kontrolne MD5, SHA1, SHA256, SHA512",
         flags=[
             ("--algo",  "-a", "Algorytm: md5 sha1 sha256 sha512 (domyślnie: sha256)"),
             ("--check", "-c", "Porównaj hash z podaną wartością"),
         ])
def cmd_hash(args):
    """
    hash plik.txt               — SHA256 pliku
    hash -a md5 plik            — MD5 pliku
    hash "tekst"                — SHA256 tekstu
    hash -a sha1 "tekst"        — SHA1 tekstu
    hash -c abc123 plik         — porównaj hash pliku z wartością
    echo "data" | hash          — hash ze stdin
    """
    algo   = "sha256"
    check  = None
    clean  = []
    i = 0
    while i < len(args):
        if args[i] in ("-a", "--algo") and i + 1 < len(args):
            algo = args[i + 1].lower()
            i += 2; continue
        if args[i] in ("-c", "--check") and i + 1 < len(args):
            check = args[i + 1].lower()
            i += 2; continue
        if not args[i].startswith("-"):
            clean.append(args[i])
        i += 1

    supported = {"md5", "sha1", "sha256", "sha512", "sha3_256"}
    if algo not in supported:
        print_error(f"Nieznany algorytm: {algo}",
                    f"Dostępne: {', '.join(sorted(supported))}"); return

    h = hashlib.new(algo)

    if clean and os.path.isfile(clean[0]):
        fname = clean[0]
        try:
            with open(fname, "rb") as f:
                while chunk := f.read(65536):
                    h.update(chunk)
        except Exception as exc:
            print_error(f"Błąd odczytu: {exc}"); return
        source = fname
    elif clean:
        text = " ".join(clean)
        h.update(text.encode("utf-8"))
        source = f'"{text}"'
    elif not sys.stdin.isatty():
        data = sys.stdin.buffer.read()
        h.update(data)
        source = "stdin"
    else:
        print_error("Podaj plik lub tekst"); return

    digest = h.hexdigest()
    if check:
        if digest.lower() == check.lower():
            print(f"  {C.OK}✔ ZGODNY{C.RESET}  {algo.upper()}: {digest}")
            print(f"  Źródło: {source}")
        else:
            print(f"  {C.ERROR}✖ NIEZGODNY{C.RESET}  {algo.upper()}")
            print(f"  Oczekiwano: {check}")
            print(f"  Otrzymano:  {digest}")
            print(f"  Źródło: {source}")
    else:
        print(f"  {C.BOLD}{digest}{C.RESET}  {C.DIM}({algo.upper()})  {source}{C.RESET}")


# ── serve test — podłącz _srv_test_all ───────────────────────────────────────
# (integracja istniejącej funkcji _srv_test_all z cmd_serve)
# Patch cmd_serve aby test subcommand używał pełnej _srv_test_all zamiast inline

def _patch_serve_test():
    """Podłącza _srv_test_all do obsługi 'serve test' w cmd_serve."""
    orig_serve = BUILTINS.get("serve")
    if orig_serve is None:
        return
    orig_func = orig_serve.func

    def _patched_serve(args):
        if args and args[0] == "test":
            w = terminal_width() - 2
            _srv_test_all(w)
            return
        orig_func(args)

    orig_serve.func = _patched_serve

_patch_serve_test()


