# ── http — klient HTTP ────────────────────────────────────────────────────────

@command("http", "Klient HTTP (curl-like): GET/POST/HEAD/PUT/DELETE",
         aliases=["curl2"],
         flags=[
             ("-X", "--method",  "Metoda HTTP: GET POST PUT DELETE HEAD PATCH"),
             ("-d", "--data",    "Ciało żądania (JSON lub form-urlencoded)"),
             ("-H", "--header",  "Dodaj nagłówek: 'Klucz: Wartość'"),
             ("-o", "--save",    "Zapisz odpowiedź do pliku"),
             ("--timeout",       "Limit czasu w sekundach (domyślnie: 10)"),
             ("--follow",        "Podążaj za przekierowaniami 3xx (maks. 5)"),
             ("--json",          "Parsuj i pokoloruj odpowiedź jako JSON"),
             ("--status",        "Pokaż tylko kod statusu HTTP"),
             ("--no-body",       "Pomiń ciało — tylko nagłówki odpowiedzi"),
             ("-v", "--verbose", "Drukuj nagłówki żądania i odpowiedzi"),
         ])
def cmd_http(args):
    """
    http GET https://httpbin.org/get
    http POST https://httpbin.org/post -d '{"name":"test"}' -H "Content-Type: application/json"
    http https://example.com --verbose --follow
    http https://example.com -o strona.html
    http HEAD https://example.com --status
    http PUT https://api.example.com/item/1 -d '{"val":42}'
    """
    import urllib.request as _ureq
    import urllib.error   as _uerr

    # ── parsowanie argumentów ──────────────────────────────────────────────
    method      = "GET"
    url         = None
    data_raw    = None
    headers     = {}
    save_to     = None
    timeout     = 10
    follow      = False
    fmt_json    = False
    status_only = False
    no_body     = False
    verbose     = False
    positional  = []

    i = 0
    while i < len(args):
        a = args[i]
        if a in ("-X", "--method") and i + 1 < len(args):
            method = args[i + 1].upper(); i += 2; continue
        if a in ("-d", "--data") and i + 1 < len(args):
            data_raw = args[i + 1]; i += 2; continue
        if a in ("-H", "--header") and i + 1 < len(args):
            raw = args[i + 1]
            if ":" in raw:
                k, _, v = raw.partition(":")
                headers[k.strip()] = v.strip()
            i += 2; continue
        if a in ("-o", "--save") and i + 1 < len(args):
            save_to = args[i + 1]; i += 2; continue
        if a == "--timeout" and i + 1 < len(args):
            try:    timeout = float(args[i + 1])
            except: pass
            i += 2; continue
        if a == "--follow":              follow      = True; i += 1; continue
        if a == "--json":                fmt_json    = True; i += 1; continue
        if a == "--status":              status_only = True; i += 1; continue
        if a == "--no-body":             no_body     = True; i += 1; continue
        if a in ("-v", "--verbose"):     verbose     = True; i += 1; continue
        if not a.startswith("-"):        positional.append(a)
        i += 1

    _HTTP_METHODS = {"GET", "POST", "PUT", "DELETE", "HEAD", "PATCH", "OPTIONS"}
    if positional and positional[0].upper() in _HTTP_METHODS:
        method = positional.pop(0).upper()
    if positional:
        url = positional[0]

    if not url:
        print_error("Brak URL",
                    "Użycie: http [METODA] <url> [opcje]\n"
                    "  Przykład: http GET https://httpbin.org/get")
        return

    if not url.startswith(("http://", "https://")):
        url = "https://" + url

    # ── ciało żądania ──────────────────────────────────────────────────────
    body_bytes = None
    if data_raw:
        body_bytes = data_raw.encode("utf-8")
        if "Content-Type" not in headers and "content-type" not in headers:
            s = data_raw.strip()
            if s.startswith(("{", "[")):
                headers["Content-Type"] = "application/json"
            else:
                headers["Content-Type"] = "application/x-www-form-urlencoded"
        if method == "GET":
            method = "POST"

    if "User-Agent" not in headers:
        headers["User-Agent"] = f"TerminalX/{SHELL_VERSION}"

    # ── verbose: nagłówki żądania ──────────────────────────────────────────
    w = terminal_width() - 2
    if verbose:
        print(box_top(f"➤  {method}  {url}", w, C.INFO))
        for k, v in headers.items():
            print(box_row(f"  {C.DIM}{k}:{C.RESET} {v}", w))
        if body_bytes:
            preview = body_bytes[:200].decode("utf-8", errors="replace")
            print(box_row(f"  {C.DIM}body ▶{C.RESET} {preview}", w))
        print(box_bottom(w))

    class _NoRedirect(_ureq.HTTPRedirectHandler):
        def redirect_request(self, req, fp, code, msg, hdrs, newurl):
            return None

    # ── wykonanie żądania ──────────────────────────────────────────────────
    try:
        req    = _ureq.Request(url, data=body_bytes, headers=headers, method=method)
        opener = _ureq.build_opener() if follow else _ureq.build_opener(_NoRedirect())
        with opener.open(req, timeout=timeout) as resp:
            status    = resp.status
            resp_hdrs = dict(resp.headers)
            raw_body  = resp.read()

    except _uerr.HTTPError as e:
        status    = e.code
        resp_hdrs = dict(e.headers) if e.headers else {}
        try:    raw_body = e.read()
        except: raw_body = b""
    except _uerr.URLError as e:
        print_error(f"Błąd połączenia: {e.reason}",
                    "Sprawdź URL, sieć i tryb online: mode check")
        return
    except OSError as e:
        if "timed out" in str(e).lower():
            print_error(f"Przekroczono limit czasu ({timeout}s)",
                        "Zwiększ --timeout lub sprawdź dostępność hosta")
        else:
            print_error(f"Błąd sieciowy: {e}")
        return
    except Exception as e:
        print_error(f"Błąd HTTP: {e}"); return

    # ── linia statusu ──────────────────────────────────────────────────────
    if status < 300:
        sc = C.OK
    elif status < 500:
        sc = C.WARN
    else:
        sc = C.ERROR

    if status_only:
        print(f"  HTTP  {sc}{status}{C.RESET}")
        return

    ct     = resp_hdrs.get("Content-Type",   resp_hdrs.get("content-type",   ""))
    cl     = resp_hdrs.get("Content-Length", resp_hdrs.get("content-length", ""))
    cl_str = f"  {C.DIM}{_human_size(int(cl))}{C.RESET}" if cl.isdigit() else ""
    print(box_top(
        f"HTTP {sc}{status}{C.RESET}  {C.DIM}{ct[:40]}{C.RESET}{cl_str}", w, sc))

    if verbose:
        for k, v in resp_hdrs.items():
            print(box_row(f"  {C.DIM}{k}:{C.RESET} {v[:w - len(k) - 6]}", w))
        print(box_row("", w))

    # ── ciało odpowiedzi ───────────────────────────────────────────────────
    if not no_body:
        body_str = raw_body.decode("utf-8", errors="replace")

        if save_to:
            try:
                Path(save_to).write_bytes(raw_body)
                print(box_row(
                    f"  {C.OK}✔ Zapisano{C.RESET}  {save_to}  "
                    f"({_human_size(len(raw_body))})", w))
            except Exception as exc:
                print_error(f"Błąd zapisu: {exc}")
        else:
            is_json = "json" in ct.lower() or fmt_json
            if is_json:
                try:
                    parsed = json.loads(body_str)
                    pretty = json.dumps(parsed, indent=2, ensure_ascii=False)
                    for line in pretty.splitlines()[:300]:
                        print(box_row("  " + _tk_colorize_json(line), w))
                except Exception:
                    for line in body_str.splitlines()[:200]:
                        print(box_row("  " + line[:w - 4], w))
            else:
                lines = body_str.splitlines()
                limit = 120
                for line in lines[:limit]:
                    print(box_row("  " + line[:w - 4], w))
                if len(lines) > limit:
                    print(box_row(
                        f"  {C.DIM}… {len(lines) - limit} linii pominięto "
                        f"— użyj -o <plik> aby zapisać całość{C.RESET}", w))

    print(box_bottom(w))


def _tk_colorize_json(line: str) -> str:
    """Koloruje jedną linię JSON do wyświetlenia w bloku http/jsonview."""
    line = _RE_JSON_KEY.sub(
        lambda m: f"{C.KEYWORD}{m.group(1)}{C.RESET}{m.group(2)}", line)
    line = _RE_JSON_STR.sub(
        lambda m: f"{m.group(1)}{C.STRING}{m.group(2)}{C.RESET}", line)
    line = _RE_JSON_NUM.sub(
        lambda m: f": {C.NUMBER}{m.group(1)}{C.RESET}", line)
    line = _RE_JSON_BOOL.sub(
        lambda m: f"{C.BUILTIN}{m.group(1)}{C.RESET}", line)
    return line


# ── portscan — wielowątkowy skaner portów TCP ─────────────────────────────────

@command("portscan", "Wielowątkowy skaner portów TCP",
         aliases=["pscan"],
         flags=[
             ("-r", "--range",    "Zakres portów: 1-1024  lub  80,443,8080"),
             ("--timeout",        "Timeout na port w sekundach (domyślnie: 0.5)"),
             ("--threads",        "Liczba równoległych wątków (domyślnie: 64)"),
             ("--open-only",      "Pokaż tylko otwarte porty"),
             ("--banner",         "Spróbuj pobrać banner usługi (wolniejsze)"),
         ])
def cmd_portscan(args):
    """
    portscan 192.168.1.1                    — popularne 25 portów
    portscan example.com 22 80 443 8080     — konkretne porty
    portscan 10.0.0.1 --range 1-1024        — zakres portów
    portscan host --range 80,443,8080,8443  — lista portów
    portscan host --banner --timeout 1      — z pobieraniem bannera
    portscan host --open-only               — tylko otwarte
    """
    import socket    as _sock
    import threading as _thr

    _TOP_PORTS = [
        21, 22, 23, 25, 53, 80, 110, 111, 135, 139,
        143, 443, 445, 993, 995, 1433, 1723, 3306, 3389,
        5432, 5900, 6379, 8080, 8443, 27017,
    ]
    _PORT_NAMES = {
        21:"FTP",    22:"SSH",       23:"Telnet",  25:"SMTP",
        53:"DNS",    80:"HTTP",     110:"POP3",   111:"RPC",
       135:"MSRPC", 139:"NetBIOS", 143:"IMAP",   443:"HTTPS",
       445:"SMB",   993:"IMAPS",   995:"POP3S", 1433:"MSSQL",
      1723:"PPTP", 3306:"MySQL",  3389:"RDP",  5432:"PostgreSQL",
      5900:"VNC",  6379:"Redis",  8080:"HTTP-alt", 8443:"HTTPS-alt",
     27017:"MongoDB",
    }

    host        = None
    port_list   = []
    timeout     = 0.5
    max_threads = 64
    open_only   = False
    get_banner  = False
    port_range  = None
    positional  = []

    i = 0
    while i < len(args):
        a = args[i]
        if a in ("-r", "--range") and i + 1 < len(args):
            port_range = args[i + 1]; i += 2; continue
        if a == "--timeout" and i + 1 < len(args):
            try:    timeout = float(args[i + 1])
            except: pass
            i += 2; continue
        if a == "--threads" and i + 1 < len(args):
            try:    max_threads = max(1, min(256, int(args[i + 1])))
            except: pass
            i += 2; continue
        if a == "--open-only": open_only  = True; i += 1; continue
        if a == "--banner":    get_banner = True; i += 1; continue
        if not a.startswith("-"): positional.append(a)
        i += 1

    if not positional:
        print_error("Brak hosta", "Użycie: portscan <host> [porty] [opcje]")
        return

    host = positional[0]
    for p in positional[1:]:
        try:    port_list.append(int(p))
        except: pass

    if port_range:
        for seg in port_range.split(","):
            seg = seg.strip()
            if "-" in seg:
                try:
                    lo, hi = seg.split("-", 1)
                    port_list.extend(range(int(lo), int(hi) + 1))
                except Exception:
                    pass
            else:
                try:    port_list.append(int(seg))
                except: pass

    if not port_list:
        port_list = _TOP_PORTS

    port_list = sorted(set(port_list))

    try:
        ip = _sock.gethostbyname(host)
    except _sock.gaierror as e:
        print_error(f"Nie można rozwiązać hosta: {host}", str(e))
        return

    w      = terminal_width() - 2
    ip_note = f"  {C.DIM}({ip}){C.RESET}" if ip != host else ""
    print(box_top(
        f"🔍 portscan  {C.BOLD}{host}{C.RESET}{ip_note}"
        f"  —  {len(port_list)} portów", w, C.INFO))
    print(box_row(
        f"  {C.DIM}timeout: {timeout}s  |  wątki: {max_threads}  |"
        f"  zakres: {min(port_list)}–{max(port_list)}{C.RESET}", w))

    results      = {}
    results_lock = _thr.Lock()
    sem          = _thr.Semaphore(max_threads)
    stop_ev      = _thr.Event()

    def _scan_port(port):
        with sem:
            if stop_ev.is_set():
                return
            open_  = False
            banner = ""
            try:
                s = _sock.socket(_sock.AF_INET, _sock.SOCK_STREAM)
                s.settimeout(timeout)
                if s.connect_ex((ip, port)) == 0:
                    open_ = True
                    if get_banner:
                        try:
                            s.settimeout(1.0)
                            raw    = s.recv(256)
                            banner = raw.decode("utf-8", errors="replace").strip()[:80]
                        except Exception:
                            pass
                s.close()
            except Exception:
                pass
            with results_lock:
                results[port] = (open_, banner)

    threads = [_thr.Thread(target=_scan_port, args=(p,), daemon=True)
               for p in port_list]
    try:
        for t in threads:
            t.start()
        for t in threads:
            t.join()
    except KeyboardInterrupt:
        stop_ev.set()
        print_warn("Skanowanie przerwane (Ctrl+C)")

    open_ports   = [(p, b) for p, (o, b) in sorted(results.items()) if o]
    closed_ports = [p      for p, (o, _) in sorted(results.items()) if not o]

    if open_ports:
        print(box_row(
            f"  {C.OK}● OTWARTE{C.RESET}  "
            f"{C.DIM}({len(open_ports)} z {len(port_list)}){C.RESET}", w))
        for port, banner in open_ports:
            svc = _PORT_NAMES.get(port, "?")
            bnr = f"  {C.DIM}{banner}{C.RESET}" if banner else ""
            print(box_row(
                f"    {C.OK}●{C.RESET} {C.BOLD}{port:5d}{C.RESET}"
                f"  {C.INFO}{svc:<14}{C.RESET}{bnr}", w))
    else:
        print(box_row(f"  {C.DIM}Brak otwartych portów{C.RESET}", w))

    if not open_only and closed_ports:
        chunks     = [closed_ports[j:j+15] for j in range(0, len(closed_ports), 15)]
        closed_hdr = f"  {C.DIM}Zamknięte:{C.RESET}  "
        for chunk in chunks[:3]:
            ports_str = "  ".join(
                f"{C.ERROR}{p}{C.RESET}" for p in chunk)
            print(box_row(f"{closed_hdr}{ports_str}", w))
            closed_hdr = "              "
        if len(chunks) > 3:
            remaining = sum(len(c) for c in chunks[3:])
            print(box_row(
                f"              {C.DIM}…i {remaining} kolejnych zamkniętych{C.RESET}", w))

    print(box_bottom(w))


# ── dns — odpytywanie DNS ──────────────────────────────────────────────────────

@command("dns", "Odpytywanie DNS: A, AAAA, PTR, MX, NS, ALL",
         aliases=["nslookup2", "dig2"],
         flags=[
             ("-t", "--type",  "Typ rekordu: A  AAAA  PTR  MX  NS  ALL"),
             ("--reverse",     "Odwrotne DNS (PTR): adres IP → hostname"),
             ("--short",       "Pokaż tylko wartości bez ramki"),
         ])
def cmd_dns(args):
    """
    dns example.com               — rekordy A (IPv4, domyślnie)
    dns example.com -t AAAA       — rekordy IPv6
    dns example.com -t MX         — serwery pocztowe (wymaga dig/nslookup)
    dns example.com -t ALL        — wszystkie dostępne typy
    dns 8.8.8.8 --reverse         — odwrotne DNS (IP → hostname)
    dns github.com --short        — tylko adresy, bez ramki
    """
    import socket as _sock

    rec_type   = "A"
    reverse    = False
    short      = False
    positional = []

    i = 0
    while i < len(args):
        a = args[i]
        if a in ("-t", "--type") and i + 1 < len(args):
            rec_type = args[i + 1].upper(); i += 2; continue
        if a == "--reverse": reverse = True; i += 1; continue
        if a == "--short":   short   = True; i += 1; continue
        if not a.startswith("-"): positional.append(a)
        i += 1

    if not positional:
        print_error("Brak domeny", "Użycie: dns <domena_lub_ip> [-t TYP]")
        return

    host = positional[0]
    if (len(positional) > 1
            and positional[1].upper() in ("A","AAAA","MX","NS","PTR","ALL","CNAME")):
        rec_type = positional[1].upper()

    w = terminal_width() - 2
    if not short:
        print(box_top(f"🌐 dns  {C.BOLD}{host}{C.RESET}  —  {rec_type}", w, C.INFO))

    def _row(label, value, color=""):
        col = color or C.OK
        if short:
            print(value)
        else:
            print(box_row(
                f"  {C.DIM}{label:<8}{C.RESET}  {col}{value}{C.RESET}", w))

    if reverse or rec_type == "PTR":
        try:
            hostname, aliases, _ = _sock.gethostbyaddr(host)
            _row("PTR", hostname, C.INFO)
            for alias in aliases:
                _row("alias", alias, C.DIM)
        except _sock.herror as e:
            if short:
                print(f"Brak PTR: {e}")
            else:
                print(box_row(f"  {C.ERROR}Brak rekordu PTR: {e}{C.RESET}", w))
        if not short:
            print(box_bottom(w))
        return

    if rec_type in ("A", "AAAA", "ALL"):
        fam = (_sock.AF_INET  if rec_type == "A"    else
               _sock.AF_INET6 if rec_type == "AAAA" else 0)
        try:
            infos = _sock.getaddrinfo(host, None, fam)
            seen  = set()
            for info in infos:
                ip = info[4][0]
                if ip in seen:
                    continue
                seen.add(ip)
                af = "A" if info[0] == _sock.AF_INET else "AAAA"
                _row(af, ip)
        except _sock.gaierror as e:
            if short:
                print(f"Błąd DNS: {e}")
            else:
                print(box_row(f"  {C.ERROR}Błąd DNS: {e}{C.RESET}", w))

    if rec_type in ("A", "ALL") and not short:
        try:
            cname = _sock.gethostbyname_ex(host)[0]
            if cname != host:
                _row("CNAME", cname, C.DIM)
        except Exception:
            pass

    if rec_type in ("MX", "NS", "CNAME", "ALL"):
        _dns_external(host, rec_type, w, short, _row)

    if not short:
        print(box_bottom(w))


def _dns_external(host, rec_type, w, short, _row_fn):
    """Wykonuje odpytanie MX/NS/CNAME przez dig lub nslookup."""
    types_to_query = (
        ["MX", "NS"] if rec_type == "ALL" else [rec_type]
    )
    for qt in types_to_query:
        resolved = False
        for tool, tcmd in [
            ("dig",      f"dig +short {qt} {host}"),
            ("nslookup", f"nslookup -type={qt} {host}"),
        ]:
            if shutil.which(tool):
                try:
                    out = subprocess.check_output(
                        shlex.split(tcmd),
                        stderr=subprocess.DEVNULL,
                        timeout=5, text=True)
                    for line in out.strip().splitlines():
                        line = line.strip()
                        if line and not line.startswith(";"):
                            _row_fn(qt, line, C.INFO)
                    resolved = True
                except Exception:
                    pass
                break
        if not resolved and not short:
            print(box_row(
                f"  {C.DIM}Rekord {qt}: brak narzędzia dig/nslookup w PATH"
                f" — zainstaluj dnsutils{C.RESET}", w))


# ── uuid — generator UUID ─────────────────────────────────────────────────────

@command("uuid", "Generator UUID v1/v4/v5 i krótkich ID",
         aliases=["uid", "uuidgen"],
         flags=[
             ("-n", "--count",   "Liczba generowanych UUID (domyślnie: 1)"),
             ("--v1",            "UUID wersja 1 (oparty na czasie i MAC)"),
             ("--v4",            "UUID wersja 4 (w pełni losowy — domyślny)"),
             ("--v5",            "UUID v5: --v5 <ns> <n>  (ns: dns url oid x500)"),
             ("--short",         "Krótki 8-znakowy ID (losowy hex, bezpieczny)"),
             ("--no-dash",       "Usuń myślniki z UUID"),
             ("--upper",         "Wielkie litery (uppercase)"),
         ])
def cmd_uuid(args):
    """
    uuid                          — UUID v4 (domyślnie)
    uuid -n 5                     — 5 losowych UUID v4
    uuid --v1                     — UUID v1 (czas + adres MAC)
    uuid --v5 dns python.org      — UUID v5 deterministyczny (DNS namespace)
    uuid --v5 url https://x.com   — UUID v5 z URL namespace
    uuid --short                  — krótki 8-znakowy hex ID
    uuid --no-dash --upper -n 3   — 3 UUID bez myślników, wielkie litery
    """
    import uuid as _uuid

    count   = 1
    version = 4
    v5_ns   = None
    short   = False
    no_dash = False
    upper   = False

    i = 0
    while i < len(args):
        a = args[i]
        if a in ("-n", "--count") and i + 1 < len(args):
            try:    count = max(1, min(10000, int(args[i + 1])))
            except: pass
            i += 2; continue
        if a == "--v1": version = 1; i += 1; continue
        if a == "--v4": version = 4; i += 1; continue
        if a == "--v5":
            version = 5
            if i + 2 < len(args):
                v5_ns = (args[i + 1], args[i + 2])
                i += 3
            else:
                print_error("--v5 wymaga dwóch argumentów: <namespace> <n>",
                            "Dostępne namespace: dns  url  oid  x500")
                return
            continue
        if a == "--short":   short   = True; i += 1; continue
        if a == "--no-dash": no_dash = True; i += 1; continue
        if a == "--upper":   upper   = True; i += 1; continue
        i += 1

    _NS = {
        "dns":  _uuid.NAMESPACE_DNS,
        "url":  _uuid.NAMESPACE_URL,
        "oid":  _uuid.NAMESPACE_OID,
        "x500": _uuid.NAMESPACE_X500,
    }

    def _gen():
        if short:
            import secrets as _sec
            return _sec.token_hex(4)
        if version == 1:
            u = str(_uuid.uuid1())
        elif version == 5:
            ns_key, name = v5_ns
            ns = _NS.get(ns_key.lower(), _uuid.NAMESPACE_DNS)
            u  = str(_uuid.uuid5(ns, name))
        else:
            u = str(_uuid.uuid4())
        if no_dash: u = u.replace("-", "")
        if upper:   u = u.upper()
        return u

    label = "short-id" if short else f"UUID v{version}"

    if count == 1:
        val = _gen()
        print(f"  {C.BOLD}{val}{C.RESET}  {C.DIM}({label}){C.RESET}")
    else:
        w = terminal_width() - 2
        print(box_top(f"🆔 {label}  ×{count}", w, C.INFO))
        for _ in range(count):
            print(box_row(f"  {C.BOLD}{_gen()}{C.RESET}", w))
        print(box_bottom(w))


# ── passgen — generator haseł, fraz i PIN-ów ─────────────────────────────────

@command("passgen", "Generator silnych haseł, fraz passphrase i PIN-ów",
         aliases=["pwgen", "genpass"],
         flags=[
             ("-l", "--length",  "Długość hasła w znakach (domyślnie: 20)"),
             ("-n", "--count",   "Liczba haseł do wygenerowania (domyślnie: 1)"),
             ("--no-sym",        "Bez znaków specjalnych (tylko litery + cyfry)"),
             ("--no-upper",      "Bez wielkich liter"),
             ("--no-digit",      "Bez cyfr"),
             ("--sym-only",      "Wyłącznie znaki specjalne"),
             ("--words",         "Fraza passphrase złożona z losowych słów"),
             ("--pin",           "Numeryczny PIN (podaj długość): --pin 6"),
             ("--entropy",       "Pokaż entropię bitową i ocenę siły"),
         ])
def cmd_passgen(args):
    """
    passgen                       — 20-znakowe hasło ze wszystkimi znakami
    passgen -l 32                 — 32-znakowe hasło
    passgen -n 5                  — 5 losowych haseł
    passgen --no-sym              — tylko litery i cyfry
    passgen --words               — fraza passphrase (4 słowa)
    passgen --words -l 6          — passphrase z 6 słów
    passgen --pin 6               — 6-cyfrowy PIN numeryczny
    passgen --entropy             — pokaż entropię i ocenę siły
    passgen -l 16 -n 3 --no-sym   — 3 hasła alfanumeryczne 16 znaków
    """
    import secrets as _sec
    import string  as _str
    import math    as _math

    length   = 20
    count    = 1
    no_sym   = False
    no_upper = False
    no_digit = False
    sym_only = False
    words    = False
    pin_len  = None
    entropy  = False

    i = 0
    while i < len(args):
        a = args[i]
        if a in ("-l", "--length") and i + 1 < len(args):
            try:    length = max(4, min(512, int(args[i + 1])))
            except: pass
            i += 2; continue
        if a in ("-n", "--count") and i + 1 < len(args):
            try:    count = max(1, min(200, int(args[i + 1])))
            except: pass
            i += 2; continue
        if a == "--no-sym":   no_sym   = True; i += 1; continue
        if a == "--no-upper": no_upper = True; i += 1; continue
        if a == "--no-digit": no_digit = True; i += 1; continue
        if a == "--sym-only": sym_only = True; i += 1; continue
        if a == "--words":    words    = True; i += 1; continue
        if a == "--entropy":  entropy  = True; i += 1; continue
        if a == "--pin" and i + 1 < len(args):
            try:    pin_len = max(4, min(20, int(args[i + 1])))
            except: pin_len = 6
            i += 2; continue
        if a == "--pin": pin_len = 6; i += 1; continue
        i += 1

    w = terminal_width() - 2
    _SYMBOLS = "!@#$%^&*()-_=+[]{}|;:,.<>?"

    # ── PIN numeryczny ─────────────────────────────────────────────────────
    if pin_len is not None:
        alph     = _str.digits
        ent_bits = _math.log2(len(alph)) * pin_len
        if count > 1:
            print(box_top(
                f"🔢 PIN  {pin_len} cyfr"
                + (f"  {C.DIM}({ent_bits:.1f} bit){C.RESET}" if entropy else ""),
                w, C.INFO))
        for _ in range(count):
            pin    = "".join(_sec.choice(alph) for _ in range(pin_len))
            groups = " ".join(pin[j:j+3] for j in range(0, len(pin), 3))
            if count == 1:
                print(f"  {C.BOLD}{groups}{C.RESET}  {C.DIM}(PIN {pin_len} cyfr){C.RESET}")
                if entropy:
                    print(f"  {C.DIM}↳ entropia: {ent_bits:.1f} bit  |  zestaw: {len(alph)} znaków{C.RESET}")
            else:
                print(box_row(f"  {C.BOLD}{groups}{C.RESET}", w))
        if count > 1:
            print(box_bottom(w))
        return

    # ── Passphrase (słowa) ─────────────────────────────────────────────────
    if words:
        _WL = [
            "ananas","banan","cebula","delta","echo","fasola","groch","herbata",
            "igla","jablon","kapusta","latarka","mango","natura","ocean","pietruszka",
            "rakieta","szpinak","trawa","ucho","wiatr","xenon","zebra","arbuz",
            "bocian","chmura","deszcz","elefant","flaga","gwiazda","huragan","iwan",
            "jelen","kaczka","lampart","motyl","norka","orzel","pingwin","robot",
            "slonce","tygrys","ulica","vulkan","woda","ryba","zorza","agat",
            "borsuk","cypres","delfin","feniks","gazela","heros","ibis","jaguar",
            "komet","morze","tukan","ursa","wiking","zamek","akacja","cukier",
            "drzewo","euler","farol","grzyb","halina","ikona","jasmin","koral",
        ]
        num_words = max(2, min(20, length)) if length != 20 else 4
        ent_bits  = _math.log2(len(_WL)) * num_words
        if count > 1:
            print(box_top(
                f"🔤 Passphrase  {num_words} słów"
                + (f"  {C.DIM}({ent_bits:.1f} bit){C.RESET}" if entropy else ""),
                w, C.INFO))
        for _ in range(count):
            phrase = "-".join(_sec.choice(_WL) for _ in range(num_words))
            if count == 1:
                print(f"  {C.BOLD}{phrase}{C.RESET}  {C.DIM}(passphrase){C.RESET}")
                if entropy:
                    print(f"  {C.DIM}↳ entropia: {ent_bits:.1f} bit  |  zestaw: {len(_WL)} słów{C.RESET}")
            else:
                print(box_row(f"  {C.BOLD}{phrase}{C.RESET}", w))
        if count > 1:
            print(box_bottom(w))
        return

    # ── Hasło z alfabetu ───────────────────────────────────────────────────
    alphabet = _str.ascii_lowercase
    if not no_upper and not sym_only: alphabet += _str.ascii_uppercase
    if not no_digit and not sym_only: alphabet += _str.digits
    if not no_sym   and not sym_only: alphabet += _SYMBOLS
    if sym_only:                      alphabet  = _SYMBOLS

    if not alphabet:
        print_error("Pusty alfabet — sprzeczne flagi")
        return

    ent_bits = _math.log2(len(alphabet)) * length
    strength = _passgen_strength(ent_bits)

    if count > 1:
        print(box_top(
            f"🔑 passgen  len={length}  alfabet={len(alphabet)}"
            + (f"  {C.DIM}({ent_bits:.1f} bit){C.RESET}" if entropy else ""),
            w, C.INFO))

    def _mkpass():
        pwd    = []
        groups = []
        if not no_upper and not sym_only: groups.append(_str.ascii_uppercase)
        if not no_digit and not sym_only: groups.append(_str.digits)
        if not no_sym   and not sym_only: groups.append(_SYMBOLS)
        if sym_only:                      groups.append(_SYMBOLS)
        for g in groups:
            pwd.append(_sec.choice(g))
        remaining = length - len(pwd)
        if remaining > 0:
            pwd += [_sec.choice(alphabet) for _ in range(remaining)]
        for j in range(len(pwd) - 1, 0, -1):
            k = _sec.randbelow(j + 1)
            pwd[j], pwd[k] = pwd[k], pwd[j]
        return "".join(pwd)

    for _ in range(count):
        p = _mkpass()
        if count == 1:
            print(f"  {C.BOLD}{p}{C.RESET}")
            print(f"  {C.DIM}siła: {strength}  |  "
                  f"entropia: {ent_bits:.1f} bit  |  "
                  f"alfabet: {len(alphabet)} znaków{C.RESET}")
        else:
            print(box_row(f"  {C.BOLD}{p}{C.RESET}", w))

    if count > 1:
        print(box_bottom(w))


def _passgen_strength(bits: float) -> str:
    if bits < 40:   return f"{C.ERROR}słabe{C.RESET}"
    if bits < 60:   return f"{C.WARN}umiarkowane{C.RESET}"
    if bits < 80:   return f"{C.OK}silne{C.RESET}"
    return f"{C.OK}{C.BOLD}bardzo silne{C.RESET}"


# ── weather — pogoda ASCII w terminalu ────────────────────────────────────────

@command("weather", "Pogoda ASCII w terminalu przez wttr.in",
         aliases=["pogoda"],
         flags=[
             ("-l", "--lang",  "Język: pl en de fr (domyślnie: pl)"),
             ("--days",        "Dni prognozy: 0/1/2/3 (domyślnie: 1)"),
             ("--short",       "Jednolinijkowy skrót: ikona + temp + wiatr"),
             ("--json",        "Surowe dane JSON z wttr.in"),
         ])
def cmd_weather(args):
    """
    weather                       — pogoda dla bieżącej lokalizacji (geo-IP)
    weather Warsaw                — pogoda dla Warszawy
    weather "New York" --days 3   — 3-dniowa prognoza NYC
    weather London --short        — skrócony widok jednolinijkowy
    weather Kraków --json         — surowe dane JSON
    """
    import urllib.request as _ureq
    import urllib.error   as _uerr
    import urllib.parse   as _uparse

    if not (_STATE.online_mode or _detect_network(1.5)):
        print_warn("Brak połączenia z internetem",
                   "weather wymaga dostępu do wttr.in  |  Sprawdź: mode check")
        return

    lang       = "pl"
    days       = 1
    short      = False
    fmt_json   = False
    positional = []

    i = 0
    while i < len(args):
        a = args[i]
        if a in ("-l", "--lang") and i + 1 < len(args):
            lang = args[i + 1]; i += 2; continue
        if a == "--days" and i + 1 < len(args):
            try:    days = max(0, min(3, int(args[i + 1])))
            except: pass
            i += 2; continue
        if a == "--short": short    = True; i += 1; continue
        if a == "--json":  fmt_json = True; i += 1; continue
        if not a.startswith("-"): positional.append(a)
        i += 1

    location = "+".join(positional)
    loc_enc  = _uparse.quote(location) if location else ""

    if fmt_json:
        url = f"https://wttr.in/{loc_enc}?format=j1&lang={lang}"
    elif short:
        url = f"https://wttr.in/{loc_enc}?format=%l:+%c+%t+%h+%w&lang={lang}"
    else:
        url = f"https://wttr.in/{loc_enc}?{days}&lang={lang}&A"

    headers = {
        "User-Agent":     f"curl/7.0 TerminalX/{SHELL_VERSION}",
        "Accept-Language": lang,
    }

    try:
        req = _ureq.Request(url, headers=headers)
        with _ureq.urlopen(req, timeout=10) as resp:
            raw = resp.read().decode("utf-8", errors="replace")
    except _uerr.URLError as e:
        print_error(f"Błąd pobierania pogody: {e.reason}",
                    "Sprawdź połączenie: mode check")
        return
    except OSError as e:
        if "timed out" in str(e).lower():
            print_error("Przekroczono limit czasu (10s)",
                        "Serwer wttr.in niedostępny — spróbuj później")
        else:
            print_error(f"Błąd sieciowy: {e}")
        return
    except Exception as e:
        print_error(f"Błąd weather: {e}")
        return

    w = terminal_width() - 2
    if fmt_json:
        loc_label = location or "auto (geo-IP)"
        print(box_top(f"🌤  weather  {loc_label}  (JSON)", w, C.INFO))
        try:
            parsed = json.loads(raw)
            pretty = json.dumps(parsed, indent=2, ensure_ascii=False)
            for line in pretty.splitlines()[:150]:
                print(box_row("  " + _tk_colorize_json(line), w))
        except Exception:
            for line in raw.splitlines()[:80]:
                print(box_row("  " + line[:w - 4], w))
        print(box_bottom(w))
    elif short:
        loc_label = location or "lokalizacja auto"
        print(f"  {C.INFO}☁  {loc_label}{C.RESET}  {raw.strip()}")
    else:
        print(raw)


# ── qr — kod QR w terminalu ───────────────────────────────────────────────────

@command("qr", "Kod QR w terminalu (Unicode bloki lub ASCII art)",
         aliases=["qrcode"],
         flags=[
             ("-o", "--save",  "Zapisz wygenerowany QR do pliku tekstowego"),
             ("--invert",      "Odwróć kolory (czarne ↔ białe bloki)"),
             ("--border",      "Rozmiar obramowania w modułach (domyślnie: 1)"),
         ])
def cmd_qr(args):
    """
    qr https://example.com              — QR z URL-a
    qr "Cześć, świecie!"                — QR z tekstu
    qr https://example.com -o qr.txt   — zapisz do pliku
    qr wifi:T:WPA;S:MojaSSID;P:haslo;; — QR konfiguracji Wi-Fi
    qr --invert "tekst"                 — odwrócona paleta

    Priorytety renderowania:
      1. pip install qrcode[pil]  — offline, Unicode bloki (najlepsze)
      2. qrenco.de (online)       — ASCII art przez HTTP
      3. Link do generatora       — fallback gdy brak obu powyższych
    """
    import urllib.request as _ureq
    import urllib.parse   as _uparse
    import urllib.error   as _uerr

    save_to    = None
    invert     = False
    border     = 1
    positional = []

    i = 0
    while i < len(args):
        a = args[i]
        if a in ("-o", "--save") and i + 1 < len(args):
            save_to = args[i + 1]; i += 2; continue
        if a == "--invert": invert = True; i += 1; continue
        if a == "--border" and i + 1 < len(args):
            try:    border = max(0, min(4, int(args[i + 1])))
            except: pass
            i += 2; continue
        if not a.startswith("-"): positional.append(a)
        i += 1

    if not positional:
        if not sys.stdin.isatty():
            text = sys.stdin.read().strip()
        else:
            print_error("Brak tekstu lub URL",
                        "Użycie: qr <tekst_lub_url>  [-o plik]")
            return
    else:
        text = " ".join(positional)

    # ── Próba 1: biblioteka qrcode (offline) ──────────────────────────────
    try:
        import qrcode as _qrc  # type: ignore
        qr = _qrc.QRCode(
            border=border,
            error_correction=_qrc.constants.ERROR_CORRECT_M,
        )
        qr.add_data(text)
        qr.make(fit=True)
        _qr_render_matrix(qr.get_matrix(), invert, save_to, text)
        return
    except ImportError:
        pass

    # ── Próba 2: qrenco.de (online ASCII art) ─────────────────────────────
    if _STATE.online_mode or _detect_network(1.5):
        encoded = _uparse.quote(text, safe="")
        url     = f"https://qrenco.de/{encoded}"
        try:
            req = _ureq.Request(url, headers={
                "User-Agent": "curl/7.0",
                "Accept":     "text/plain",
            })
            with _ureq.urlopen(req, timeout=10) as resp:
                art = resp.read().decode("utf-8", errors="replace")

            lines = art.splitlines()
            if invert:
                lines = [
                    l.replace("█", "\x00").replace(" ", "█").replace("\x00", " ")
                    for l in lines
                ]
            output = "\n".join(lines)
            if save_to:
                Path(save_to).write_text(output, encoding="utf-8")
                print(f"  {C.OK}✔ Zapisano QR do:{C.RESET}  {save_to}")
            else:
                print(output)
            trunc = text[:60] + ("…" if len(text) > 60 else "")
            print(f"\n  {C.DIM}Dane: {trunc}{C.RESET}")
            return
        except (_uerr.URLError, OSError):
            pass
        except Exception as e:
            print_warn(f"qrenco.de: {e}")

    # ── Fallback: link do generatora online ───────────────────────────────
    encoded    = _uparse.quote(text, safe="")
    online_url = (f"https://api.qrserver.com/v1/create-qr-code/"
                  f"?size=300x300&data={encoded}")
    w = terminal_width() - 2
    print(box_top("📷 QR Code — brak offline renderera", w, C.WARN))
    print(box_row(f"  {C.DIM}Dane:{C.RESET}        {text[:w - 14]}", w))
    print(box_row(
        f"  {C.DIM}Zainstaluj:{C.RESET}  pip install qrcode[pil]"
        f"  {C.DIM}(offline, najlepsze){C.RESET}", w))
    print(box_row(f"  {C.DIM}Online PNG:{C.RESET}  {online_url[:w - 14]}", w))
    print(box_bottom(w))


def _qr_render_matrix(matrix, invert, save_to, data):
    """Renderuje macierz QR jako bloki Unicode ▀▄█ (2 piksele na linię)."""
    B = True
    if invert:
        B = False
    rows = len(matrix)
    cols = len(matrix[0]) if rows else 0
    lines = []
    r = 0
    while r < rows:
        top_row = matrix[r]
        bot_row = matrix[r + 1] if r + 1 < rows else [False] * cols
        line    = ""
        for c in range(cols):
            t = (top_row[c] == B)
            b = (bot_row[c] == B)
            if   t and b:      line += "█"
            elif t and not b:  line += "▀"
            elif not t and b:  line += "▄"
            else:              line += " "
        lines.append(line)
        r += 2

    output = "\n".join(lines)
    if save_to:
        Path(save_to).write_text(output + "\n", encoding="utf-8")
        print(f"  {C.OK}✔ Zapisano QR do:{C.RESET}  {save_to}")
    else:
        print()
        for line in lines:
            print("  " + line)
        print()
    trunc = data[:60] + ("…" if len(data) > 60 else "")
    print(f"  {C.DIM}Dane: {trunc}{C.RESET}")


