# ── ps2 — lista procesów ──────────────────────────────────────────────────────

@command("ps2", "Lista procesów z filtrowaniem po nazwie / PID / użytkowniku",
         aliases=["procs"],
         flags=[
             ("-f", "--filter",  "Filtruj po nazwie lub fragmencie"),
             ("-u", "--user",    "Pokaż tylko procesy danego użytkownika"),
             ("-n", "--top",     "Pokaż N najbardziej zasobożernych (CPU)"),
             ("--pid",           "Filtruj po konkretnym PID"),
             ("--sort",          "Sortuj: cpu mem pid name (domyślnie: cpu)"),
             ("--no-header",     "Pomiń nagłówek tabeli"),
         ])
def cmd_ps2(args):
    """
    ps2                        — wszystkie procesy (sortowane wg CPU)
    ps2 -f python              — procesy z 'python' w nazwie
    ps2 -u max                 — procesy użytkownika 'max'
    ps2 -n 10                  — top 10 wg użycia CPU
    ps2 --pid 1234             — szczegóły konkretnego PID
    ps2 --sort mem             — sortuj wg pamięci RAM
    """
    # ── parsowanie ─────────────────────────────────────────────────────────
    filter_str = None
    user_str   = None
    top_n      = None
    pid_str    = None
    sort_by    = "cpu"
    no_header  = False

    i = 0
    while i < len(args):
        a = args[i]
        if a in ("-f", "--filter") and i + 1 < len(args):
            filter_str = args[i + 1].lower(); i += 2; continue
        if a in ("-u", "--user") and i + 1 < len(args):
            user_str = args[i + 1].lower(); i += 2; continue
        if a in ("-n", "--top") and i + 1 < len(args):
            try:    top_n = max(1, int(args[i + 1]))
            except: pass
            i += 2; continue
        if a == "--pid" and i + 1 < len(args):
            pid_str = args[i + 1]; i += 2; continue
        if a == "--sort" and i + 1 < len(args):
            sort_by = args[i + 1].lower(); i += 2; continue
        if a == "--no-header": no_header = True
        # pozycyjne bez flagi: traktuj jako filtr
        if not a.startswith("-") and filter_str is None:
            filter_str = a.lower()
        i += 1

    w = terminal_width() - 2

    # ── próba psutil (dokładniejsze dane) ─────────────────────────────────
    try:
        import psutil as _ps

        procs = []
        for p in _ps.process_iter(
                ["pid", "name", "username", "cpu_percent", "memory_percent",
                 "status", "cmdline"]):
            try:
                info = p.info
                # filtrowanie
                if pid_str and str(info["pid"]) != pid_str:
                    continue
                if filter_str:
                    name = (info.get("name") or "").lower()
                    cmd  = " ".join(info.get("cmdline") or []).lower()
                    if filter_str not in name and filter_str not in cmd:
                        continue
                if user_str:
                    u = (info.get("username") or "").lower()
                    if user_str not in u:
                        continue
                procs.append(info)
            except (_ps.NoSuchProcess, _ps.AccessDenied):
                pass

        # sortowanie
        sort_key = {
            "cpu":  lambda x: x.get("cpu_percent") or 0,
            "mem":  lambda x: x.get("memory_percent") or 0,
            "pid":  lambda x: x.get("pid") or 0,
            "name": lambda x: (x.get("name") or "").lower(),
        }.get(sort_by, lambda x: x.get("cpu_percent") or 0)
        procs.sort(key=sort_key, reverse=(sort_by != "name"))

        if top_n:
            procs = procs[:top_n]

        if not procs:
            print(box_top("ps2 — brak wyników", w, C.INFO))
            print(box_row(f"  {C.DIM}Brak procesów pasujących do filtra{C.RESET}", w))
            print(box_bottom(w))
            return

        label = f"ps2  —  {len(procs)} procesów"
        if filter_str: label += f"  [filtr: {filter_str}]"
        if user_str:   label += f"  [user: {user_str}]"
        print(box_top(f"⚙  {label}", w, C.INFO))

        if not no_header:
            hdr = (f"  {C.BOLD}{'PID':>7}  {'CPU%':>6}  {'MEM%':>6}  "
                   f"{'STATUS':<10}  {'USER':<12}  NAZWA{C.RESET}")
            print(box_row(hdr, w))
            print(box_row(f"  {C.DIM}{'─' * (w - 4)}{C.RESET}", w))

        for info in procs:
            pid  = info.get("pid", 0)
            name = (info.get("name") or "?")[:28]
            user = (info.get("username") or "?")[:12]
            cpu  = info.get("cpu_percent") or 0.0
            mem  = info.get("memory_percent") or 0.0
            stat = (info.get("status") or "?")[:10]

            cpu_c = C.ERROR if cpu > 50 else (C.WARN if cpu > 10 else C.OK)
            mem_c = C.ERROR if mem > 50 else (C.WARN if mem > 20 else C.RESET)
            print(box_row(
                f"  {C.DIM}{pid:>7}{C.RESET}  "
                f"{cpu_c}{cpu:>5.1f}%{C.RESET}  "
                f"{mem_c}{mem:>5.1f}%{C.RESET}  "
                f"{C.DIM}{stat:<10}{C.RESET}  "
                f"{C.DIM}{user:<12}{C.RESET}  "
                f"{C.BOLD}{name}{C.RESET}", w))

        print(box_bottom(w))
        return

    except ImportError:
        pass   # brak psutil — fallback do subprocess

    # ── fallback: ps/tasklist przez subprocess ────────────────────────────
    _ps2_fallback(filter_str, user_str, top_n, pid_str, no_header, w)


def _ps2_fallback(filter_str, user_str, top_n, pid_str, no_header, w):
    """Fallback ps2 bez psutil — używa ps (Unix) lub tasklist (Windows)."""
    import platform as _pl

    print(box_top("⚙  ps2", w, C.INFO))
    if not no_header:
        print(box_row(
            f"  {C.DIM}Tip: pip install psutil — dla lepszych danych{C.RESET}", w))

    if _pl.system() == "Windows":
        cmd = ["tasklist", "/FO", "CSV", "/NH"]
        try:
            out = subprocess.check_output(cmd, text=True,
                                          stderr=subprocess.DEVNULL, timeout=10)
        except Exception as e:
            print(box_row(f"  {C.ERROR}Błąd tasklist: {e}{C.RESET}", w))
            print(box_bottom(w)); return

        lines = []
        for raw in out.strip().splitlines():
            parts = [p.strip('"') for p in raw.split('","')]
            if len(parts) < 5:
                continue
            name, pid, _sess, _num, mem = parts[:5]
            if filter_str and filter_str not in name.lower():
                continue
            if pid_str and pid != pid_str:
                continue
            mem_kb = mem.replace("\xa0", "").replace(",", "").replace(" K", "").strip()
            try:    mem_h = _human_size(int(mem_kb) * 1024)
            except: mem_h = mem
            lines.append((name, pid, mem_h))

        if top_n: lines = lines[:top_n]
        for name, pid, mem_h in lines:
            print(box_row(
                f"  {C.DIM}{pid:>7}{C.RESET}  {mem_h:>8}  {C.BOLD}{name}{C.RESET}", w))
    else:
        cmd = ["ps", "aux"]
        try:
            out = subprocess.check_output(cmd, text=True,
                                          stderr=subprocess.DEVNULL, timeout=10)
        except Exception as e:
            print(box_row(f"  {C.ERROR}Błąd ps: {e}{C.RESET}", w))
            print(box_bottom(w)); return

        rows = out.strip().splitlines()
        header = rows[0] if rows else ""
        data   = rows[1:]

        if not no_header and header:
            print(box_row(f"  {C.DIM}{header[:w-4]}{C.RESET}", w))

        count = 0
        for row in data:
            parts = row.split()
            if len(parts) < 11: continue
            _user, pid, cpu, mem = parts[0], parts[1], parts[2], parts[3]
            cmd_name = " ".join(parts[10:])[:40]
            if filter_str and filter_str not in cmd_name.lower() and filter_str not in _user.lower():
                continue
            if user_str and user_str not in _user.lower():
                continue
            if pid_str and pid != pid_str:
                continue
            cpu_c = C.ERROR if float(cpu) > 50 else (C.WARN if float(cpu) > 10 else C.OK)
            print(box_row(
                f"  {C.DIM}{pid:>7}{C.RESET}  "
                f"{cpu_c}{cpu:>5}%{C.RESET}  "
                f"{C.DIM}{mem:>5}%  {_user:<12}{C.RESET}  "
                f"{C.BOLD}{cmd_name}{C.RESET}", w))
            count += 1
            if top_n and count >= top_n:
                break

    print(box_bottom(w))


# ── pkill2 — zabij proces ─────────────────────────────────────────────────────

@command("pkill2", "Zabij proces po nazwie lub PID (z potwierdzeniem)",
         aliases=["killp"],
         flags=[
             ("-f", "--force",  "Wymuś zabicie bez potwierdzenia (SIGKILL)"),
             ("--signal",       "Sygnał do wysłania (domyślnie: TERM/15)"),
             ("-a", "--all",    "Zabij wszystkie pasujące procesy (nie tylko pierwszy)"),
         ])
def cmd_pkill2(args):
    """
    pkill2 1234              — zabij PID 1234 (z potwierdzeniem)
    pkill2 python            — zabij pierwszy proces o nazwie 'python'
    pkill2 python -a         — zabij wszystkie procesy 'python'
    pkill2 1234 --force      — wymuś bez pytania (SIGKILL)
    pkill2 chrome --signal 9 — wyślij sygnał 9 (SIGKILL)
    """
    import platform as _pl
    import signal   as _sig

    # ── parsowanie ─────────────────────────────────────────────────────────
    force      = False
    kill_all   = False
    sig_num    = None
    target     = None

    i = 0
    while i < len(args):
        a = args[i]
        if a in ("-f", "--force"):   force    = True; i += 1; continue
        if a in ("-a", "--all"):     kill_all = True; i += 1; continue
        if a == "--signal" and i + 1 < len(args):
            try:    sig_num = int(args[i + 1])
            except: pass
            i += 2; continue
        if not a.startswith("-") and target is None:
            target = a
        i += 1

    if not target:
        print_error("Brak nazwy lub PID",
                    "Użycie: pkill2 <nazwa|PID> [opcje]")
        return

    # Sprawdź czy target to PID
    is_pid = target.isdigit()
    pids   = []      # lista (pid, name)

    # ── znajdź PIDs ───────────────────────────────────────────────────────
    try:
        import psutil as _ps

        for p in _ps.process_iter(["pid", "name", "username"]):
            try:
                info = p.info
                if is_pid:
                    if str(info["pid"]) == target:
                        pids.append((info["pid"], info.get("name", "?")))
                        break
                else:
                    if target.lower() in (info.get("name") or "").lower():
                        pids.append((info["pid"], info.get("name", "?")))
                        if not kill_all:
                            break
            except (_ps.NoSuchProcess, _ps.AccessDenied):
                pass

    except ImportError:
        # Fallback: pgrep (Unix) lub taskkill (Windows)
        if _pl.system() == "Windows":
            if is_pid:
                pids = [(int(target), target)]
            else:
                try:
                    out = subprocess.check_output(
                        ["tasklist", "/FI", f"IMAGENAME eq {target}*",
                         "/FO", "CSV", "/NH"],
                        text=True, stderr=subprocess.DEVNULL, timeout=5)
                    for row in out.strip().splitlines():
                        parts = [p.strip('"') for p in row.split('","')]
                        if len(parts) >= 2:
                            try:
                                pids.append((int(parts[1]), parts[0]))
                                if not kill_all: break
                            except ValueError:
                                pass
                except Exception:
                    pass
        else:
            try:
                flags = ["-a"] if kill_all else []
                out = subprocess.check_output(
                    ["pgrep"] + flags + ["-l", target],
                    text=True, stderr=subprocess.DEVNULL, timeout=5)
                for row in out.strip().splitlines():
                    parts = row.split(None, 1)
                    if parts:
                        try:
                            pids.append((int(parts[0]),
                                         parts[1] if len(parts) > 1 else target))
                            if not kill_all: break
                        except ValueError:
                            pass
            except Exception:
                pass

    if not pids:
        print_warn(f"Nie znaleziono procesu: {target}",
                   "Sprawdź nazwę: ps2 lub ps2 -f <fragment>")
        return

    # ── potwierdzenie ─────────────────────────────────────────────────────
    w = terminal_width() - 2
    print(box_top(f"💀 pkill2  —  znaleziono {len(pids)} proces(ów)", w, C.WARN))
    for pid, name in pids:
        print(box_row(
            f"  {C.WARN}●{C.RESET}  PID {C.BOLD}{pid}{C.RESET}  —  {name}", w))

    if not force:
        print(box_row(f"  {C.DIM}Użyj --force aby pominąć potwierdzenie{C.RESET}", w))
        print(box_bottom(w))
        try:
            ans = input(f"  {C.WARN}Zabić {len(pids)} proces(y)? [t/N]:{C.RESET} ").strip().lower()
        except (EOFError, KeyboardInterrupt):
            print_warn("Anulowano.")
            return
        if ans not in ("t", "tak", "y", "yes"):
            print_info("Anulowano.")
            return
        print()

    # ── wysyłanie sygnału ─────────────────────────────────────────────────
    if sig_num is None:
        sig_num = 9 if force else 15   # SIGKILL gdy --force, SIGTERM domyślnie

    killed = 0
    for pid, name in pids:
        try:
            if _pl.system() == "Windows":
                subprocess.run(
                    ["taskkill", "/F", "/PID", str(pid)],
                    capture_output=True, timeout=5)
            else:
                os.kill(pid, sig_num)
            print(f"  {C.OK}✔ Zabito{C.RESET}  PID {C.BOLD}{pid}{C.RESET}  {C.DIM}{name}{C.RESET}")
            killed += 1
        except ProcessLookupError:
            print_warn(f"PID {pid} już nie istnieje.")
        except PermissionError:
            print_error(f"Brak uprawnień do zabicia PID {pid}",
                        "Spróbuj uruchomić TerminalX jako administrator/sudo")
        except Exception as e:
            print_error(f"Błąd: {e}")

    if killed:
        print(f"\n  {C.OK}Zakończono:{C.RESET}  {killed}/{len(pids)} procesów zabitych  "
              f"{C.DIM}(sygnał {sig_num}){C.RESET}")


# ── uptime2 — czas działania systemu ─────────────────────────────────────────

@command("uptime2", "Czas działania systemu + load average + czas lokalny",
         aliases=["up"],
         flags=[
             ("--short", "Jednolinijkowy skrót"),
         ])
def cmd_uptime2(args):
    """
    uptime2           — pełny widok: czas działania, load, RAM
    uptime2 --short   — jednolinijkowy skrót
    """
    import platform  as _pl
    import time      as _time

    short = "--short" in args
    w     = terminal_width() - 2

    # ── czas uruchomienia systemu ──────────────────────────────────────────
    boot_time   = None
    uptime_secs = None

    try:
        import psutil as _ps
        boot_time   = _ps.boot_time()
        uptime_secs = _time.time() - boot_time
    except ImportError:
        pass

    if uptime_secs is None and _pl.system() == "Linux":
        try:
            with open("/proc/uptime") as f:
                uptime_secs = float(f.read().split()[0])
        except Exception:
            pass

    if uptime_secs is None and _pl.system() == "Darwin":
        try:
            out = subprocess.check_output(
                ["sysctl", "-n", "kern.boottime"],
                text=True, timeout=5)
            import re as _re
            m = _re.search(r"sec\s*=\s*(\d+)", out)
            if m:
                boot_time   = int(m.group(1))
                uptime_secs = _time.time() - boot_time
        except Exception:
            pass

    if uptime_secs is None and _pl.system() == "Windows":
        try:
            out = subprocess.check_output(
                ["net", "statistics", "workstation"],
                text=True, stderr=subprocess.DEVNULL, timeout=5)
            for line in out.splitlines():
                if "since" in line.lower() or "od" in line.lower():
                    print_info(line.strip())
                    break
        except Exception:
            pass

    # ── formatowanie uptime ────────────────────────────────────────────────
    def _fmt_uptime(secs):
        if secs is None:
            return "nieznany"
        secs = int(secs)
        d    = secs // 86400
        h    = (secs % 86400) // 3600
        m    = (secs % 3600) // 60
        s    = secs % 60
        parts = []
        if d: parts.append(f"{d}d")
        if h: parts.append(f"{h}h")
        if m: parts.append(f"{m}m")
        parts.append(f"{s}s")
        return " ".join(parts)

    uptime_str  = _fmt_uptime(uptime_secs)
    now_str     = datetime.datetime.now().strftime("%Y-%m-%d  %H:%M:%S")
    boot_str    = (datetime.datetime.fromtimestamp(boot_time).strftime("%Y-%m-%d  %H:%M:%S")
                   if boot_time else "?")

    # ── load average ──────────────────────────────────────────────────────
    load_str = "?"
    try:
        load = os.getloadavg()
        load_str = f"{load[0]:.2f}  {load[1]:.2f}  {load[2]:.2f}  (1/5/15 min)"
    except AttributeError:
        # Windows nie ma getloadavg — użyj psutil CPU
        try:
            import psutil as _ps
            cpu = _ps.cpu_percent(interval=0.3)
            load_str = f"CPU: {cpu:.1f}%  (Windows — brak load average)"
        except ImportError:
            load_str = "niedostępny (Windows)"

    # ── RAM ───────────────────────────────────────────────────────────────
    ram_str = "?"
    try:
        import psutil as _ps
        vm      = _ps.virtual_memory()
        used    = _human_size(vm.used)
        total   = _human_size(vm.total)
        pct     = vm.percent
        ram_c   = C.ERROR if pct > 80 else (C.WARN if pct > 60 else C.OK)
        ram_str = f"{ram_c}{used} / {total}  ({pct:.1f}%){C.RESET}"
    except ImportError:
        if _pl.system() == "Linux":
            try:
                with open("/proc/meminfo") as f:
                    lines = {l.split(":")[0]: l.split(":")[1].strip()
                             for l in f if ":" in l}
                total_kb = int(lines.get("MemTotal","0 kB").split()[0])
                avail_kb = int(lines.get("MemAvailable","0 kB").split()[0])
                used_kb  = total_kb - avail_kb
                pct      = used_kb / max(total_kb, 1) * 100
                ram_c    = C.ERROR if pct > 80 else (C.WARN if pct > 60 else C.OK)
                ram_str  = (f"{ram_c}{_human_size(used_kb*1024)} / "
                            f"{_human_size(total_kb*1024)}  ({pct:.1f}%){C.RESET}")
            except Exception:
                pass

    # ── wyświetlanie ──────────────────────────────────────────────────────
    if short:
        print(f"  {C.OK}⏱{C.RESET}  up {C.BOLD}{uptime_str}{C.RESET}  "
              f"{C.DIM}load: {load_str.split('(')[0].strip()}{C.RESET}  "
              f"{C.DIM}{now_str}{C.RESET}")
        return

    def kv(label, value):
        print(box_row(f"  {C.DIM}{label:<16}{C.RESET}  {value}", w))

    print(box_top("⏱  uptime2", w, C.INFO))
    kv("Czas lokalny",   f"{C.BOLD}{now_str}{C.RESET}")
    kv("Działanie",      f"{C.OK}{C.BOLD}{uptime_str}{C.RESET}")
    kv("Start systemu",  f"{C.DIM}{boot_str}{C.RESET}")
    kv("Load average",   f"{C.INFO}{load_str}{C.RESET}")
    kv("RAM",            ram_str)
    print(box_bottom(w))


# ── sysinfo — pełna diagnostyka systemu ──────────────────────────────────────

@command("sysinfo", "Pełna diagnostyka: OS, CPU, RAM, dysk, sieć, Python",
         aliases=["info", "about"],
         flags=[
             ("--disk",  "Pokaż szczegóły wszystkich dysków/partycji"),
             ("--net",   "Pokaż interfejsy sieciowe i adresy IP"),
             ("--all",   "Pokaż wszystkie sekcje (disk + net + env)"),
         ])
def cmd_sysinfo(args):
    """
    sysinfo          — OS, CPU, RAM, Python, dysk główny
    sysinfo --disk   — szczegółowe info o wszystkich partycjach
    sysinfo --net    — interfejsy sieciowe i adresy IP
    sysinfo --all    — wszystkie dostępne informacje
    """
    import platform  as _pl
    import socket    as _sock
    import time      as _time

    show_disk = "--disk" in args or "--all" in args
    show_net  = "--net"  in args or "--all" in args
    w         = terminal_width() - 2

    def kv(label, value, color=""):
        col = color or C.RESET
        print(box_row(f"  {C.DIM}{label:<20}{C.RESET}  {col}{value}{C.RESET}", w))

    def section(title):
        print(box_row(f"  {C.BOLD}{C.INFO}{title}{C.RESET}", w))
        print(box_row(f"  {C.DIM}{'─' * (w - 4)}{C.RESET}", w))

    print(box_top(f"💻  sysinfo  —  {_pl.node()}", w, C.INFO))

    # ── System operacyjny ──────────────────────────────────────────────────
    section("🖥  System operacyjny")
    kv("System",       _pl.system() + " " + _pl.release())
    kv("Wersja",       _pl.version()[:60])
    kv("Architektura", _pl.machine() + "  " + _pl.architecture()[0])
    kv("Hostname",     _pl.node())
    try:
        kv("Użytkownik", os.getlogin())
    except Exception:
        kv("Użytkownik", os.environ.get("USER", os.environ.get("USERNAME", "?")))

    # ── CPU ───────────────────────────────────────────────────────────────
    print(box_row("", w))
    section("🔧  CPU")
    kv("Procesor",    _pl.processor() or "?")

    try:
        import psutil as _ps
        kv("Rdzenie fizyczne", str(_ps.cpu_count(logical=False)))
        kv("Rdzenie logiczne", str(_ps.cpu_count(logical=True)))
        cpu_freq = _ps.cpu_freq()
        if cpu_freq:
            kv("Częstotliwość",
               f"{cpu_freq.current:.0f} MHz  "
               f"(max: {cpu_freq.max:.0f} MHz)")
        cpu_pct  = _ps.cpu_percent(interval=0.5)
        cpu_c    = C.ERROR if cpu_pct > 80 else (C.WARN if cpu_pct > 50 else C.OK)
        kv("Użycie CPU",  f"{cpu_pct:.1f}%", cpu_c)
        # Temperatura (jeśli dostępna)
        try:
            temps = _ps.sensors_temperatures()
            for chip, entries in temps.items():
                if entries:
                    t = entries[0].current
                    t_c = C.ERROR if t > 80 else (C.WARN if t > 65 else C.OK)
                    kv(f"Temp ({chip})", f"{t:.1f} °C", t_c)
                    break
        except (AttributeError, Exception):
            pass
    except ImportError:
        # Fallback: /proc/cpuinfo (Linux)
        if _pl.system() == "Linux":
            try:
                with open("/proc/cpuinfo") as f:
                    cpuinfo = f.read()
                cores = cpuinfo.count("processor")
                kv("Rdzenie logiczne", str(cores))
                for line in cpuinfo.splitlines():
                    if "model name" in line:
                        kv("Model", line.split(":")[1].strip()[:50])
                        break
            except Exception:
                pass

    # ── RAM ───────────────────────────────────────────────────────────────
    print(box_row("", w))
    section("🧠  Pamięć RAM")

    try:
        import psutil as _ps
        vm   = _ps.virtual_memory()
        sw   = _ps.swap_memory()
        pct  = vm.percent
        ram_c = C.ERROR if pct > 80 else (C.WARN if pct > 60 else C.OK)
        kv("Łącznie",    _human_size(vm.total))
        kv("Użyta",      f"{_human_size(vm.used)}  ({pct:.1f}%)", ram_c)
        kv("Dostępna",   _human_size(vm.available))
        if sw.total:
            sw_c = C.WARN if sw.percent > 20 else C.DIM
            kv("Swap",   f"{_human_size(sw.used)} / {_human_size(sw.total)}"
                         f"  ({sw.percent:.1f}%)", sw_c)
    except ImportError:
        if _pl.system() == "Linux":
            try:
                with open("/proc/meminfo") as f:
                    mi = {l.split(":")[0]: l.split(":")[1].strip()
                          for l in f if ":" in l}
                def _mk(key):
                    return int(mi.get(key, "0 kB").split()[0]) * 1024
                total = _mk("MemTotal"); avail = _mk("MemAvailable")
                used  = total - avail;   pct   = used / max(total, 1) * 100
                ram_c = C.ERROR if pct > 80 else (C.WARN if pct > 60 else C.OK)
                kv("Łącznie",  _human_size(total))
                kv("Użyta",    f"{_human_size(used)}  ({pct:.1f}%)", ram_c)
                kv("Dostępna", _human_size(avail))
            except Exception:
                kv("RAM", "niedostępne (zainstaluj psutil)")

    # ── Dysk ──────────────────────────────────────────────────────────────
    print(box_row("", w))
    section("💾  Dysk")

    try:
        import psutil as _ps
        partitions = _ps.disk_partitions(all=show_disk)
        for part in partitions:
            try:
                usage = _ps.disk_usage(part.mountpoint)
                pct   = usage.percent
                d_c   = C.ERROR if pct > 90 else (C.WARN if pct > 75 else C.OK)
                bar_w = 20
                filled = int(bar_w * pct / 100)
                bar   = f"[{'█' * filled}{'░' * (bar_w - filled)}]"
                kv(part.mountpoint[:18],
                   f"{d_c}{bar} {pct:.1f}%{C.RESET}  "
                   f"{C.DIM}{_human_size(usage.used)} / "
                   f"{_human_size(usage.total)}{C.RESET}")
                if not show_disk:
                    break   # tylko główna partycja bez --disk
            except PermissionError:
                kv(part.mountpoint[:18], f"{C.DIM}brak dostępu{C.RESET}")
    except ImportError:
        try:
            out = subprocess.check_output(
                ["df", "-h", "--output=target,pcent,used,size"],
                text=True, stderr=subprocess.DEVNULL, timeout=5)
            for line in out.strip().splitlines()[:6]:
                print(box_row(f"  {C.DIM}{line[:w-4]}{C.RESET}", w))
        except Exception:
            kv("Dysk", "niedostępne (zainstaluj psutil)")

    # ── Sieć ──────────────────────────────────────────────────────────────
    if show_net:
        print(box_row("", w))
        section("🌐  Sieć")
        try:
            hostname = _sock.gethostname()
            kv("Hostname", hostname)
            try:
                local_ip = _sock.gethostbyname(hostname)
                kv("IP lokalne", local_ip)
            except Exception:
                pass
        except Exception:
            pass

        try:
            import psutil as _ps
            addrs = _ps.net_if_addrs()
            stats = _ps.net_if_stats()
            for iface, addr_list in addrs.items():
                st   = stats.get(iface)
                up   = f"{C.OK}↑ UP{C.RESET}" if (st and st.isup) else f"{C.DIM}↓ DOWN{C.RESET}"
                spd  = f"  {C.DIM}{st.speed}Mbps{C.RESET}" if (st and st.speed) else ""
                print(box_row(f"  {C.BOLD}{iface:<16}{C.RESET}  {up}{spd}", w))
                for addr in addr_list:
                    import psutil as _ps2
                    fam = str(addr.family)
                    if "AF_INET" in fam and "6" not in fam:
                        print(box_row(f"    {C.DIM}IPv4:{C.RESET}  {addr.address}", w))
                    elif "AF_INET6" in fam:
                        print(box_row(f"    {C.DIM}IPv6:{C.RESET}  {addr.address}", w))
        except ImportError:
            try:
                out = subprocess.check_output(
                    ["ip", "addr"] if shutil.which("ip") else ["ifconfig"],
                    text=True, stderr=subprocess.DEVNULL, timeout=5)
                for line in out.strip().splitlines()[:20]:
                    print(box_row(f"  {C.DIM}{line[:w-4]}{C.RESET}", w))
            except Exception:
                kv("Sieć", "niedostępne (zainstaluj psutil)")

    # ── Python ────────────────────────────────────────────────────────────
    print(box_row("", w))
    section("🐍  Python")
    kv("Wersja",      sys.version.split()[0])
    kv("Executable",  sys.executable[:60])
    kv("Platform",    sys.platform)

    psutil_ver = "niezainstalowany  ↳ pip install psutil"
    try:
        import psutil as _ps
        psutil_ver = f"{C.OK}zainstalowany v{_ps.__version__}{C.RESET}"
    except ImportError:
        psutil_ver = f"{C.WARN}niezainstalowany{C.RESET}  {C.DIM}↳ pip install psutil{C.RESET}"
    kv("psutil",      psutil_ver)

    print(box_bottom(w))


# ── envs — zmienne środowiskowe ───────────────────────────────────────────────

@command("envs", "Zmienne środowiskowe z filtrowaniem i sortowaniem",
         aliases=["environ", "env2"],
         flags=[
             ("-f", "--filter",  "Filtruj po nazwie lub wartości (case-insensitive)"),
             ("--name-only",     "Pokaż tylko nazwy zmiennych"),
             ("--sort",          "Sortuj alfabetycznie (domyślnie: tak)"),
             ("--no-sort",       "Nie sortuj — zachowaj kolejność systemową"),
             ("-s", "--set",     "Ustaw zmienną: envs -s KLUCZ wartość"),
             ("--unset",         "Usuń zmienną: envs --unset KLUCZ"),
         ])
def cmd_envs(args):
    """
    envs                     — wszystkie zmienne środowiskowe
    envs PATH                — filtruj po 'PATH'
    envs -f python           — szukaj 'python' w nazwie lub wartości
    envs --name-only         — tylko nazwy (bez wartości)
    envs -s MOJA_ZM wartość  — ustaw zmienną w bieżącej sesji
    envs --unset MOJA_ZM     — usuń zmienną z bieżącej sesji
    """
    # ── parsowanie ─────────────────────────────────────────────────────────
    filter_str = None
    name_only  = False
    do_sort    = True
    set_key    = None
    set_val    = None
    unset_key  = None
    positional = []

    i = 0
    while i < len(args):
        a = args[i]
        if a in ("-f", "--filter") and i + 1 < len(args):
            filter_str = args[i + 1].lower(); i += 2; continue
        if a == "--name-only":  name_only = True;  i += 1; continue
        if a == "--sort":       do_sort   = True;  i += 1; continue
        if a == "--no-sort":    do_sort   = False; i += 1; continue
        if a in ("-s", "--set") and i + 2 < len(args):
            set_key = args[i + 1]
            set_val = args[i + 2]
            i += 3; continue
        if a == "--unset" and i + 1 < len(args):
            unset_key = args[i + 1]; i += 2; continue
        if not a.startswith("-"):
            positional.append(a)
        i += 1

    # Pozycyjny argument bez flagi = filtr
    if positional and filter_str is None:
        filter_str = positional[0].lower()

    w = terminal_width() - 2

    # ── set / unset ───────────────────────────────────────────────────────
    if set_key:
        os.environ[set_key] = set_val
        # Propaguj też do SHELL_VARS jeśli istnieje
        if "SHELL_VARS" in globals():
            SHELL_VARS[set_key] = set_val
        print(f"  {C.OK}✔ Ustawiono:{C.RESET}  "
              f"{C.BOLD}{set_key}{C.RESET} = {C.STRING}{set_val}{C.RESET}")
        return

    if unset_key:
        if unset_key in os.environ:
            del os.environ[unset_key]
            if "SHELL_VARS" in globals() and unset_key in SHELL_VARS:
                del SHELL_VARS[unset_key]
            print(f"  {C.OK}✔ Usunięto:{C.RESET}  {C.BOLD}{unset_key}{C.RESET}")
        else:
            print_warn(f"Zmienna nie istnieje: {unset_key}")
        return

    # ── pobierz i filtruj ─────────────────────────────────────────────────
    env_items = list(os.environ.items())

    if filter_str:
        env_items = [
            (k, v) for k, v in env_items
            if filter_str in k.lower() or filter_str in v.lower()
        ]

    if do_sort:
        env_items.sort(key=lambda x: x[0].lower())

    if not env_items:
        print(box_top("envs — brak wyników", w, C.WARN))
        print(box_row(
            f"  {C.DIM}Brak zmiennych pasujących do: {filter_str}{C.RESET}", w))
        print(box_bottom(w))
        return

    label = f"envs  —  {len(env_items)} zmiennych"
    if filter_str: label += f"  [filtr: {filter_str}]"
    print(box_top(f"🔧  {label}", w, C.INFO))

    for key, val in env_items:
        if name_only:
            print(box_row(f"  {C.BOLD}{key}{C.RESET}", w))
            continue

        # Skróć długie wartości — pełna wartość pokazywana z --filter
        display_val = val
        max_val_w   = w - len(key) - 8
        if max_val_w < 10:
            max_val_w = 10
        if len(val) > max_val_w:
            display_val = val[:max_val_w] + f"{C.DIM}…{C.RESET}"

        # Koloruj specjalne zmienne
        if key in ("PATH", "PYTHONPATH", "LD_LIBRARY_PATH"):
            # PATH: pokaż każdy segment w nowej linii
            print(box_row(f"  {C.KEYWORD}{key}{C.RESET}", w))
            for seg in val.split(os.pathsep)[:8]:
                exists = Path(seg).exists() if seg else False
                seg_c  = C.OK if exists else C.DIM
                print(box_row(f"    {seg_c}↳ {seg}{C.RESET}", w))
            if val.count(os.pathsep) >= 8:
                print(box_row(
                    f"    {C.DIM}… i więcej segmentów{C.RESET}", w))
        elif key in ("HOME", "USERPROFILE", "TEMP", "TMP"):
            print(box_row(
                f"  {C.KEYWORD}{key}{C.RESET}  =  {C.INFO}{display_val}{C.RESET}", w))
        elif key.startswith("TERMINALX_"):
            print(box_row(
                f"  {C.BUILTIN}{key}{C.RESET}  =  {C.STRING}{display_val}{C.RESET}", w))
        else:
            print(box_row(
                f"  {C.BOLD}{key}{C.RESET}  =  {C.DIM}{display_val}{C.RESET}", w))

    print(box_bottom(w))


