# ════════════════════════════════════════════════════════════════════════════
# CPUGRAPH v35.0 — Live wykres CPU/RAM w terminalu (ANSI, bez psutil)
# ════════════════════════════════════════════════════════════════════════════

@command("cpugraph", "Live wykres CPU i RAM w terminalu (odświeżanie co 1s)",
         aliases=["cgraph", "cpumon"],
         flags=[
             ("-i", "--interval", "Interwał odświeżania w sekundach (domyślnie: 1)"),
             ("-w", "--width",    "Szerokość wykresu (domyślnie: szerokość terminala)"),
             ("--cpu-only",       "Pokazuj tylko CPU"),
             ("--ram-only",       "Pokazuj tylko RAM"),
         ])
def cmd_cpugraph(args):
    """
    cpugraph              — live wykres CPU i RAM (Ctrl+C aby wyjść)
    cpugraph -i 2         — odświeżaj co 2 sekundy
    cpugraph --cpu-only   — tylko CPU
    cpugraph --ram-only   — tylko RAM
    """
    import time

    interval = 1.0
    graph_w  = None
    cpu_only = False
    ram_only = False
    i = 0
    while i < len(args):
        a = args[i]
        if a in ("-i", "--interval") and i + 1 < len(args):
            try: interval = max(0.2, float(args[i+1]))
            except ValueError: pass
            i += 2; continue
        if a in ("-w", "--width") and i + 1 < len(args):
            try: graph_w = max(20, int(args[i+1]))
            except ValueError: pass
            i += 2; continue
        if a == "--cpu-only": cpu_only = True
        if a == "--ram-only": ram_only = True
        i += 1

    w     = graph_w or max(40, terminal_width() - 4)
    BAR_W = w - 20

    def _read_cpu_percent() -> float:
        try:
            import psutil as _ps
            return _ps.cpu_percent(interval=None)
        except ImportError:
            pass
        try:
            with open("/proc/stat") as f:
                line = f.readline()
            vals = list(map(int, line.split()[1:]))
            idle, total = vals[3], sum(vals)
            if not hasattr(_read_cpu_percent, "_prev"):
                _read_cpu_percent._prev = (idle, total); return 0.0
            p_idle, p_total = _read_cpu_percent._prev
            _read_cpu_percent._prev = (idle, total)
            dt = total - p_total
            return 100.0 * (1 - (idle - p_idle) / dt) if dt else 0.0
        except Exception:
            return 0.0

    def _read_ram_percent() -> tuple:
        try:
            import psutil as _ps
            vm = _ps.virtual_memory()
            return vm.percent, f"{vm.used//1024**2}MB / {vm.total//1024**2}MB"
        except ImportError:
            pass
        try:
            info = {}
            with open("/proc/meminfo") as f:
                for line in f:
                    k, v = line.split(":")
                    info[k.strip()] = int(v.split()[0])
            total = info.get("MemTotal", 0)
            avail = info.get("MemAvailable", info.get("MemFree", 0))
            used  = total - avail
            pct   = 100.0 * used / total if total else 0.0
            return pct, f"{used//1024}MB / {total//1024}MB"
        except Exception:
            return 0.0, "N/A"

    def _bar(pct: float, width: int) -> str:
        filled = max(0, min(width, int(width * pct / 100)))
        color  = C.OK if pct < 50 else (C.WARN if pct < 80 else C.ERROR)
        return f"{color}{'█' * filled}{C.DIM}{'░' * (width - filled)}{C.RESET}"

    def _sparkline(history: list, width: int) -> str:
        blocks = " ▁▂▃▄▅▆▇█"
        return "".join(blocks[int(v / 100 * (len(blocks)-1))] for v in history[-width:])

    HIST = BAR_W
    cpu_hist: list = [0.0] * HIST
    ram_hist: list = [0.0] * HIST

    print(f"\n  \033[1m🖥️  cpugraph\033[0m  \033[2mCtrl+C aby wyjść  |  interwał: {interval}s\033[0m\n")

    lines_drawn = 0
    try:
        _read_cpu_percent()
        time.sleep(interval)
        while True:
            cpu = _read_cpu_percent()
            ram, ram_desc = _read_ram_percent()
            cpu_hist.append(cpu); ram_hist.append(ram)
            if len(cpu_hist) > HIST: cpu_hist.pop(0)
            if len(ram_hist) > HIST: ram_hist.pop(0)

            if lines_drawn:
                sys.stdout.write(f"\033[{lines_drawn}A\033[J")

            lines_drawn = 0
            def pr(s):
                global lines_drawn
                print(s); lines_drawn += 1

            print(f"  \033[2m{'─' * w}\033[0m"); lines_drawn += 1

            if not ram_only:
                print(f"  \033[1mCPU\033[0m  {_bar(cpu, BAR_W)}  \033[1m{cpu:5.1f}%\033[0m"); lines_drawn += 1
                print(f"  \033[2m{'':4} {_sparkline(cpu_hist, BAR_W)}\033[0m"); lines_drawn += 1
                print(); lines_drawn += 1

            if not cpu_only:
                print(f"  \033[1mRAM\033[0m  {_bar(ram, BAR_W)}  \033[1m{ram:5.1f}%\033[0m  \033[2m{ram_desc}\033[0m"); lines_drawn += 1
                print(f"  \033[2m{'':4} {_sparkline(ram_hist, BAR_W)}\033[0m"); lines_drawn += 1
                print(); lines_drawn += 1

            time.sleep(interval)
    except KeyboardInterrupt:
        print(f"\n  \033[2mcpugraph zatrzymany.\033[0m\n")


# ════════════════════════════════════════════════════════════════════════════
# AI v35.0 — Integracja z AI (OpenAI / Ollama / kompatybilne)
# ════════════════════════════════════════════════════════════════════════════

AI_CONFIG_FILE = _BASE / ".terminalx_ai.json"

def _ai_load_config() -> dict:
    defaults = {
        "api_key":  os.environ.get("OPENAI_API_KEY", ""),
        "base_url": os.environ.get("TERMINALX_AI_URL", "https://api.openai.com/v1"),
        "model":    os.environ.get("TERMINALX_AI_MODEL", "gpt-4o-mini"),
        "provider": "openai",
    }
    try:
        if AI_CONFIG_FILE.exists():
            defaults.update(json.loads(AI_CONFIG_FILE.read_text(encoding="utf-8")))
    except Exception:
        pass
    return defaults

def _ai_save_config(cfg: dict) -> None:
    try:
        AI_CONFIG_FILE.write_text(json.dumps(cfg, indent=2, ensure_ascii=False), encoding="utf-8")
    except Exception as e:
        print_warn(f"Nie udało się zapisać konfiguracji AI: {e}")

def _ai_request(messages: list, cfg: dict, stream: bool = True) -> str:
    import urllib.request, urllib.error
    base_url = cfg["base_url"].rstrip("/")
    model    = cfg["model"]
    api_key  = cfg.get("api_key", "")
    is_ollama = "11434" in base_url or cfg.get("provider") == "ollama"
    url      = f"{base_url}/api/chat" if is_ollama else f"{base_url}/chat/completions"
    payload  = {"model": model, "messages": messages, "stream": stream}
    headers  = {"Content-Type": "application/json"}
    if not is_ollama:
        headers["Authorization"] = f"Bearer {api_key}"
    req = urllib.request.Request(url, json.dumps(payload).encode(), headers, method="POST")
    parts: list = []
    try:
        with urllib.request.urlopen(req, timeout=30) as resp:
            if not stream:
                raw = json.loads(resp.read().decode())
                if "choices" in raw: return raw["choices"][0]["message"]["content"]
                if "message" in raw: return raw["message"]["content"]
                return str(raw)
            for raw_line in resp:
                line = raw_line.decode("utf-8").strip()
                if not line: continue
                if line.startswith("data:"):
                    chunk_str = line[5:].strip()
                    if chunk_str == "[DONE]": break
                    try:
                        tok = json.loads(chunk_str)["choices"][0]["delta"].get("content","")
                        if tok: sys.stdout.write(tok); sys.stdout.flush(); parts.append(tok)
                    except Exception: pass
                else:
                    try:
                        chunk = json.loads(line)
                        tok = chunk.get("message",{}).get("content","")
                        if tok: sys.stdout.write(tok); sys.stdout.flush(); parts.append(tok)
                        if chunk.get("done"): break
                    except Exception: pass
    except urllib.error.HTTPError as e:
        body = ""
        try: body = e.read().decode()[:200]
        except Exception: pass
        raise RuntimeError(f"HTTP {e.code}: {body}") from e
    except urllib.error.URLError as e:
        raise RuntimeError(f"Błąd połączenia ({url}): {e.reason}") from e
    return "".join(parts)

_AI_SYSTEM = (
    "Jesteś asystentem wbudowanym w terminal TerminalX — lekki shell w Pythonie. "
    "Odpowiadasz po polsku, zwięźle. Komendy otaczaj backtick-ami."
)

@command("ai", "Integracja z AI — pytania, podpowiedzi, wyjaśnienia komend",
         aliases=["ask"],
         flags=[
             ("ask",       "Zadaj pytanie: ai ask <pytanie>"),
             ("suggest",   "Podpowiedź komendy: ai suggest"),
             ("explain",   "Wyjaśnij komendę: ai explain <cmd>"),
             ("set-key",   "Klucz API: ai set-key <klucz>"),
             ("set-url",   "URL API: ai set-url <url>"),
             ("set-model", "Model: ai set-model <model>"),
             ("status",    "Konfiguracja AI"),
         ])
def cmd_ai(args):
    """
    ai ask Co to jest PATH?          — pytanie do AI
    ai suggest                       — podpowiedź na podstawie historii
    ai explain ls -la                — wyjaśnienie komendy po polsku
    ai set-key sk-...                — klucz OpenAI
    ai set-url http://localhost:11434 — użyj Ollama
    ai set-model llama3              — zmień model
    ai status                        — pokaż konfigurację
    """
    cfg = _ai_load_config()
    w   = terminal_width() - 2
    if not args: args = ["status"]
    sub = args[0].lower()

    if sub == "status":
        key = cfg.get("api_key","")
        key_d = ("*"*8 + key[-4:]) if len(key) > 8 else (key or f"{C.WARN}(nie ustawiony){C.RESET}")
        print(box_top("🤖  AI — konfiguracja", w, C.INFO))
        for label, val in [("Model", cfg["model"]), ("URL", cfg["base_url"]),
                           ("Provider", cfg.get("provider","openai")), ("API Key", key_d)]:
            print(box_row(f"  {label:<12} {C.BOLD}{val}{C.RESET}", w))
        print(box_row("", w))
        print(box_row(f"  {C.DIM}ai ask / suggest / explain / set-key / set-url / set-model{C.RESET}", w))
        print(box_bottom(w))
        return

    if sub == "set-key":
        if len(args) < 2: print_error("Podaj klucz: ai set-key <klucz>"); return
        cfg["api_key"] = args[1]; cfg["provider"] = "openai"
        _ai_save_config(cfg); print_ok(f"Klucz API zapisany ({args[1][:8]}…)")
        return

    if sub == "set-url":
        if len(args) < 2: print_error("Podaj URL: ai set-url <url>"); return
        cfg["base_url"] = args[1].rstrip("/")
        cfg["provider"] = "ollama" if "11434" in args[1] else "custom"
        _ai_save_config(cfg); print_ok(f"URL API: {cfg['base_url']}")
        return

    if sub == "set-model":
        if len(args) < 2: print_error("Podaj model: ai set-model <model>"); return
        cfg["model"] = args[1]; _ai_save_config(cfg); print_ok(f"Model: {cfg['model']}")
        return

    # Sprawdzenie klucza przed zapytaniem
    if cfg.get("provider","openai") == "openai" and not cfg.get("api_key"):
        print(box_top("🤖  AI — brak klucza API", w, C.WARN))
        print(box_row(f"  {C.WARN}Ustaw klucz OpenAI:{C.RESET}  ai set-key sk-...", w))
        print(box_row(f"  {C.DIM}Lub użyj Ollama: ai set-url http://localhost:11434{C.RESET}", w))
        print(box_bottom(w))
        return

    def _do_ai(prompt_text: str, title: str):
        messages = [{"role":"system","content":_AI_SYSTEM},{"role":"user","content":prompt_text}]
        print(f"\n  {C.BOLD}🤖  {title}{C.RESET}  {C.DIM}({cfg['model']}){C.RESET}\n")
        print(f"  {C.DIM}{'─'*(w-2)}{C.RESET}")
        sys.stdout.write("  ")
        try:
            _ai_request(messages, cfg, stream=True)
            print(f"\n  {C.DIM}{'─'*(w-2)}{C.RESET}\n")
        except RuntimeError as e:
            print(f"\n  {C.ERROR}✖ {e}{C.RESET}\n")

    if sub in ("ask", "a"):
        q = " ".join(args[1:]).strip()
        if not q: print_error("Podaj pytanie: ai ask <pytanie>"); return
        _do_ai(q, "AI ask")

    elif sub in ("suggest", "s", "hint"):
        recent: list = []
        try:
            if HISTORY_FILE.exists():
                recent = [l.strip() for l in HISTORY_FILE.read_text(encoding="utf-8",errors="ignore").splitlines() if l.strip()][-10:]
        except Exception: pass
        ctx = "\n".join(recent) if recent else "(brak historii)"
        _do_ai(
            f"Ostatnio użyte komendy:\n{ctx}\n\n"
            "Zaproponuj 3 komendy do wykonania. Każda w nowej linii: `komenda` — wyjaśnienie (max 8 słów). Bez numeracji.",
            "AI suggest"
        )

    elif sub in ("explain", "e", "co"):
        cmd_str = " ".join(args[1:]).strip()
        if not cmd_str: print_error("Podaj komendę: ai explain <komenda>"); return
        _do_ai(
            f"Wyjaśnij po polsku komendę (max 6 zdań, opisz każdą flagę):\n{cmd_str}",
            f"AI explain: {cmd_str}"
        )

    else:
        # Traktuj całość jako pytanie
        _do_ai(" ".join(args), "AI ask")


