# ════════════════════════════════════════════════════════════════════════════
# FMAN v35.2 — Menedżer plików: kopiowanie, przenoszenie, podgląd, drzewo
# ════════════════════════════════════════════════════════════════════════════

WEATHER_CONFIG_FILE = _BASE / ".terminalx_weather.json"

def _weather_load_config() -> dict:
    try:
        if WEATHER_CONFIG_FILE.exists():
            return json.loads(WEATHER_CONFIG_FILE.read_text(encoding="utf-8"))
    except Exception:
        pass
    return {"default_location": "", "lang": "pl", "days": 1}

def _weather_save_config(cfg: dict) -> None:
    try:
        WEATHER_CONFIG_FILE.write_text(json.dumps(cfg, indent=2, ensure_ascii=False), encoding="utf-8")
    except Exception as e:
        print_warn(f"Nie udało się zapisać konfiguracji pogody: {e}")


@command("fman", "Menedżer plików — kopiowanie, przenoszenie, podgląd, drzewo",
         aliases=["filemanager", "files2"],
         flags=[
             ("copy",    "Kopiuj plik/katalog:  fman copy <src> <dst>"),
             ("move",    "Przenieś:             fman move <src> <dst>"),
             ("rename",  "Zmień nazwę:          fman rename <src> <nowa_nazwa>"),
             ("preview", "Podgląd pliku:        fman preview <plik>"),
             ("info",    "Informacje o pliku:   fman info <plik>"),
             ("tree",    "Drzewo katalogów:     fman tree [ścieżka] [-d głębokość]"),
             ("find",    "Szukaj pliku:         fman find <wzorzec> [ścieżka]"),
             ("size",    "Rozmiar katalogu:     fman size [ścieżka]"),
         ])
def cmd_fman(args):
    """
    fman copy plik.txt kopia.txt      — kopiuj plik
    fman copy katalog/ backup/        — kopiuj katalog rekurencyjnie
    fman move stary.txt nowy.txt      — przenieś / zmień nazwę
    fman rename plik.txt nowa.txt     — zmień nazwę w tym samym katalogu
    fman preview plik.txt             — podgląd pliku (pierwsze 50 linii)
    fman info plik.txt                — rozmiar, daty, uprawnienia
    fman tree [ścieżka] [-d 3]        — drzewo katalogów (domyślnie głęb. 2)
    fman find *.py [ścieżka]          — szukaj plików po wzorcu
    fman size [ścieżka]               — łączny rozmiar katalogu
    """
    w = terminal_width() - 2

    if not args:
        print(box_top("📁  fman — menedżer plików", w, C.INFO))
        for cmd_line, desc in [
            ("fman copy <src> <dst>",         "kopiuj plik lub katalog"),
            ("fman move <src> <dst>",         "przenieś / zmień nazwę"),
            ("fman rename <plik> <nowa>",     "zmień nazwę w miejscu"),
            ("fman preview <plik>",           "podgląd zawartości pliku"),
            ("fman info <plik|katalog>",      "szczegółowe informacje"),
            ("fman tree [ścieżka] [-d N]",    "drzewo katalogów"),
            ("fman find <wzorzec> [gdzie]",   "szukaj plików"),
            ("fman size [ścieżka]",           "rozmiar katalogu"),
        ]:
            print(box_row(f"  {C.BOLD}{cmd_line:<32}{C.RESET}  {C.DIM}{desc}{C.RESET}", w))
        print(box_bottom(w))
        return

    sub = args[0].lower()

    # ── copy ──────────────────────────────────────────────────────────────
    if sub in ("copy", "cp", "kopiuj"):
        if len(args) < 3:
            print_error("Użycie: fman copy <src> <dst>"); return
        src = Path(args[1]).expanduser()
        dst = Path(args[2]).expanduser()
        if not src.exists():
            print_error(f"Źródło nie istnieje: {src}"); return
        try:
            if src.is_dir():
                import shutil as _sh
                if dst.exists() and dst.is_dir():
                    dst = dst / src.name
                _sh.copytree(str(src), str(dst))
                print_ok(f"Skopiowano katalog: {src}  →  {dst}")
            else:
                import shutil as _sh
                if dst.is_dir():
                    dst = dst / src.name
                _sh.copy2(str(src), str(dst))
                size = dst.stat().st_size
                print_ok(f"Skopiowano: {src.name}  →  {dst}  ({_fmt_size(size)})")
        except Exception as e:
            print_error(f"Błąd kopiowania: {e}")
        return

    # ── move ──────────────────────────────────────────────────────────────
    if sub in ("move", "mv", "przenieś", "przesun"):
        if len(args) < 3:
            print_error("Użycie: fman move <src> <dst>"); return
        src = Path(args[1]).expanduser()
        dst = Path(args[2]).expanduser()
        if not src.exists():
            print_error(f"Źródło nie istnieje: {src}"); return
        try:
            import shutil as _sh
            _sh.move(str(src), str(dst))
            print_ok(f"Przeniesiono: {src}  →  {dst}")
        except Exception as e:
            print_error(f"Błąd przenoszenia: {e}")
        return

    # ── rename ────────────────────────────────────────────────────────────
    if sub in ("rename", "ren", "zmień"):
        if len(args) < 3:
            print_error("Użycie: fman rename <src> <nowa_nazwa>"); return
        src = Path(args[1]).expanduser()
        if not src.exists():
            print_error(f"Plik nie istnieje: {src}"); return
        dst = src.parent / args[2]
        try:
            src.rename(dst)
            print_ok(f"Zmieniono nazwę: {src.name}  →  {dst.name}")
        except Exception as e:
            print_error(f"Błąd zmiany nazwy: {e}")
        return

    # ── preview ───────────────────────────────────────────────────────────
    if sub in ("preview", "view", "cat2", "peek", "podgląd"):
        if len(args) < 2:
            print_error("Użycie: fman preview <plik>"); return
        path = Path(args[1]).expanduser()
        if not path.exists():
            print_error(f"Plik nie istnieje: {path}"); return
        if path.is_dir():
            print_error(f"To katalog — użyj: fman tree {path}"); return

        # Limit linii
        max_lines = 60
        size = path.stat().st_size
        ext  = path.suffix.lower()

        # Binarne — pokaż hex
        binary_exts = {".exe",".bin",".zip",".tar",".gz",".bz2",".7z",
                       ".jpg",".jpeg",".png",".gif",".pdf",".mp3",".mp4"}
        print(box_top(f"👁  preview  {path.name}  ({_fmt_size(size)})", w, C.INFO))

        if ext in binary_exts or size == 0:
            print(box_row(f"  {C.DIM}Plik binarny lub pusty — podgląd niedostępny{C.RESET}", w))
        else:
            try:
                text = path.read_text(encoding="utf-8", errors="replace")
                lines = text.splitlines()
                total = len(lines)
                shown = lines[:max_lines]
                for i, line in enumerate(shown, 1):
                    trunc = line[:w-8]
                    num   = f"{C.DIM}{i:>4}{C.RESET}"
                    print(box_row(f"  {num}  {trunc}", w))
                if total > max_lines:
                    print(box_row(f"  {C.DIM}… i jeszcze {total - max_lines} linii (łącznie: {total}){C.RESET}", w))
            except Exception as e:
                print(box_row(f"  {C.ERROR}Błąd odczytu: {e}{C.RESET}", w))
        print(box_bottom(w))
        return

    # ── info ──────────────────────────────────────────────────────────────
    if sub in ("info", "stat", "details", "szczegóły"):
        if len(args) < 2:
            print_error("Użycie: fman info <plik|katalog>"); return
        path = Path(args[1]).expanduser()
        if not path.exists():
            print_error(f"Ścieżka nie istnieje: {path}"); return
        st   = path.stat()
        mtime = datetime.datetime.fromtimestamp(st.st_mtime).strftime("%Y-%m-%d %H:%M:%S")
        ctime = datetime.datetime.fromtimestamp(st.st_ctime).strftime("%Y-%m-%d %H:%M:%S")
        kind  = "Katalog" if path.is_dir() else "Plik"
        print(box_top(f"ℹ  info  {path.name}", w, C.INFO))
        def kv(k, v): print(box_row(f"  {C.DIM}{k:<18}{C.RESET}{v}", w))
        kv("Typ:",           kind)
        kv("Pełna ścieżka:", str(path.resolve()))
        kv("Rozmiar:",       _fmt_size(st.st_size))
        kv("Modyfikacja:",   mtime)
        kv("Utworzony:",     ctime)
        if not path.is_dir():
            kv("Rozszerzenie:",  path.suffix or "(brak)")
        # Uprawnienia (Unix)
        if os.name != "nt":
            import stat as _stat
            mode = oct(st.st_mode)[-3:]
            kv("Uprawnienia:", mode)
        if path.is_dir():
            try:
                items = list(path.iterdir())
                dirs  = sum(1 for p in items if p.is_dir())
                files = sum(1 for p in items if p.is_file())
                kv("Zawartość:", f"{files} plików, {dirs} katalogów")
            except PermissionError:
                kv("Zawartość:", f"{C.WARN}brak dostępu{C.RESET}")
        print(box_bottom(w))
        return

    # ── tree ──────────────────────────────────────────────────────────────
    if sub in ("tree", "drzewo"):
        path = Path(args[1]).expanduser() if len(args) > 1 and not args[1].startswith("-") else Path.cwd()
        max_depth = 2
        if "-d" in args:
            di = args.index("-d")
            if di + 1 < len(args):
                try: max_depth = int(args[di+1])
                except ValueError: pass

        if not path.exists() or not path.is_dir():
            print_error(f"Katalog nie istnieje: {path}"); return

        lines_out: list = []
        file_count = [0]
        dir_count  = [0]

        def _tree_walk(p: Path, prefix: str, depth: int):
            if depth > max_depth: return
            try:
                entries = sorted(p.iterdir(), key=lambda e: (e.is_file(), e.name.lower()))
            except PermissionError:
                lines_out.append(f"{prefix}  {C.WARN}[brak dostępu]{C.RESET}")
                return
            for i, entry in enumerate(entries):
                is_last   = (i == len(entries) - 1)
                connector = "└── " if is_last else "├── "
                child_pre = "    " if is_last else "│   "
                if entry.is_dir():
                    dir_count[0] += 1
                    lines_out.append(f"{prefix}{connector}{C.BOLD}{C.PATH}{entry.name}/{C.RESET}")
                    _tree_walk(entry, prefix + child_pre, depth + 1)
                else:
                    file_count[0] += 1
                    size_s = _fmt_size(entry.stat().st_size)
                    lines_out.append(f"{prefix}{connector}{entry.name}  {C.DIM}{size_s}{C.RESET}")

        print(box_top(f"🌲  tree  {path}  (głębokość: {max_depth})", w, C.INFO))
        print(box_row(f"  {C.BOLD}{path.name}/{C.RESET}", w))
        _tree_walk(path, "  ", 1)
        for line in lines_out[:200]:
            print(box_row(f"  {line}", w))
        if len(lines_out) > 200:
            print(box_row(f"  {C.DIM}… i więcej (użyj -d aby zmienić głębokość){C.RESET}", w))
        print(box_row("", w))
        print(box_row(f"  {C.DIM}{dir_count[0]} katalogów, {file_count[0]} plików{C.RESET}", w))
        print(box_bottom(w))
        return

    # ── find ──────────────────────────────────────────────────────────────
    if sub in ("find", "search", "szukaj"):
        if len(args) < 2:
            print_error("Użycie: fman find <wzorzec> [ścieżka]"); return
        pattern = args[1]
        root    = Path(args[2]).expanduser() if len(args) > 2 else Path.cwd()
        if not root.exists():
            print_error(f"Ścieżka nie istnieje: {root}"); return

        results: list = []
        try:
            for p in root.rglob(pattern):
                results.append(p)
                if len(results) >= 100: break
        except Exception as e:
            print_error(f"Błąd wyszukiwania: {e}"); return

        print(box_top(f"🔍  find  '{pattern}'  w  {root}", w, C.INFO))
        if not results:
            print(box_row(f"  {C.DIM}Brak wyników dla: {pattern}{C.RESET}", w))
        else:
            for p in results:
                rel  = p.relative_to(root)
                kind = f"{C.PATH}" if p.is_dir() else ""
                size_s = _fmt_size(p.stat().st_size) if p.is_file() else "katalog"
                print(box_row(f"  {kind}{rel}{C.RESET}  {C.DIM}{size_s}{C.RESET}", w))
            if len(results) == 100:
                print(box_row(f"  {C.WARN}Wyniki ograniczone do 100{C.RESET}", w))
        print(box_bottom(w))
        return

    # ── size ──────────────────────────────────────────────────────────────
    if sub in ("size", "du", "rozmiar"):
        path = Path(args[1]).expanduser() if len(args) > 1 else Path.cwd()
        if not path.exists():
            print_error(f"Ścieżka nie istnieje: {path}"); return

        total = 0
        count = 0
        try:
            if path.is_file():
                total = path.stat().st_size
                count = 1
            else:
                for p in path.rglob("*"):
                    if p.is_file():
                        try: total += p.stat().st_size
                        except Exception: pass
                        count += 1
        except Exception as e:
            print_error(f"Błąd: {e}"); return

        print(box_top(f"📦  size  {path}", w, C.INFO))
        print(box_row(f"  {C.DIM}Łączny rozmiar:  {C.RESET}{C.BOLD}{_fmt_size(total)}{C.RESET}", w))
        print(box_row(f"  {C.DIM}Liczba plików:   {C.RESET}{C.BOLD}{count}{C.RESET}", w))
        print(box_bottom(w))
        return

    print_error(f"Nieznana subkomenda: {sub}",
                "Dostępne: copy move rename preview info tree find size")


def _fmt_size(n: int) -> str:
    """Formatuje rozmiar w bajtach do czytelnej postaci."""
    for unit in ("B","KB","MB","GB","TB"):
        if n < 1024:
            return f"{n:.1f} {unit}" if unit != "B" else f"{n} B"
        n /= 1024
    return f"{n:.1f} PB"


# ════════════════════════════════════════════════════════════════════════════
# WEATHER SAVE — domyślna lokalizacja + weather save/reset
# ════════════════════════════════════════════════════════════════════════════

@command("wset", "Ustaw domyślną lokalizację dla komendy weather",
         aliases=["weather-set"],
         flags=[
             ("save",  "Zapisz domyślną lokalizację: wset save <miasto>"),
             ("reset", "Usuń domyślną lokalizację: wset reset"),
             ("show",  "Pokaż aktualną konfigurację: wset show"),
         ])
def cmd_wset(args):
    """
    wset save Warsaw          — ustaw Warszawę jako domyślną lokalizację
    wset save \"Kraków\"        — lokalizacja z polskimi znakami
    wset reset                — wróć do auto-detekcji (geo-IP)
    wset show                 — pokaż aktualną konfigurację
    wset save Warsaw --lang en --days 2   — ustaw też język i liczbę dni
    """
    cfg = _weather_load_config()
    w   = terminal_width() - 2

    if not args or args[0] in ("show", "status", "info"):
        loc  = cfg.get("default_location") or f"{C.DIM}(auto geo-IP){C.RESET}"
        lang = cfg.get("lang", "pl")
        days = cfg.get("days", 1)
        print(box_top("🌤  weather — konfiguracja", w, C.INFO))
        print(box_row(f"  {'Lokalizacja:':<16} {C.BOLD}{loc}{C.RESET}", w))
        print(box_row(f"  {'Język:':<16} {C.BOLD}{lang}{C.RESET}", w))
        print(box_row(f"  {'Dni prognozy:':<16} {C.BOLD}{days}{C.RESET}", w))
        print(box_row("", w))
        print(box_row(f"  {C.DIM}wset save <miasto>   — ustaw domyślną lokalizację{C.RESET}", w))
        print(box_row(f"  {C.DIM}weather              — użyj zapisanej lokalizacji{C.RESET}", w))
        print(box_bottom(w))
        return

    sub = args[0].lower()

    if sub in ("save", "set", "+"):
        rest = args[1:]
        lang = cfg.get("lang", "pl")
        days = cfg.get("days", 1)
        # Parsuj opcjonalne --lang i --days
        loc_parts = []
        i = 0
        while i < len(rest):
            if rest[i] == "--lang" and i+1 < len(rest):
                lang = rest[i+1]; i += 2; continue
            if rest[i] == "--days" and i+1 < len(rest):
                try: days = int(rest[i+1])
                except ValueError: pass
                i += 2; continue
            loc_parts.append(rest[i]); i += 1
        location = " ".join(loc_parts).strip()
        if not location:
            print_error("Podaj miasto: wset save <miasto>"); return
        cfg["default_location"] = location
        cfg["lang"] = lang
        cfg["days"] = days
        _weather_save_config(cfg)
        print_ok(f"Domyślna lokalizacja: {C.BOLD}{location}{C.RESET}  "
                 f"{C.DIM}(lang: {lang}, dni: {days}){C.RESET}")
        print_info("Teraz wpisz 'weather' aby zobaczyć pogodę dla tej lokalizacji.")
        return

    if sub in ("reset", "clear", "auto"):
        cfg["default_location"] = ""
        _weather_save_config(cfg)
        print_ok("Lokalizacja zresetowana — weather użyje auto geo-IP.")
        return

    print_error(f"Nieznana subkomenda: {sub}", "Dostępne: save reset show")


