if __name__ == "__main__":
    # Ochrona przed przypadkowym Ctrl+C podczas ładowania (Windows/antywirus delay)
    signal.signal(signal.SIGINT, signal.SIG_IGN)   # ignoruj SIGINT podczas init

    if "--safe" in sys.argv or "--recovery" in sys.argv or "--rescue" in sys.argv:
        recovery_enter(reason="flaga --safe przy uruchomieniu")
        print("\033[1;33m⚠ UWAGA\033[0m  TerminalX uruchomiony w trybie awaryjnym (--safe).")
        print("  \033[2mWyjście: recovery exit  |  Diagnostyka: recovery diagnose\033[0m\n")

    # Sprawdź czy uruchomiono z plikami (drag & drop z menadżera plików)
    if _startup_drop_check():
        sys.exit(0)

    # Przywróć domyślną obsługę Ctrl+C przed wejściem do pętli głównej
    signal.signal(signal.SIGINT, signal.default_int_handler)

    try:
        main()
    except KeyboardInterrupt:
        print("\n  Przerwano (Ctrl+C).")
    except SystemExit:
        pass
    except Exception as _fatal:
        _path = write_crashlog(_fatal, context="__main__ — krytyczny blad")
        print(f"\n\033[1;31m✖ KRYTYCZNY BŁĄD\033[0m  {type(_fatal).__name__}: {_fatal}")
        print(f"  Raport zapisano : {_path}")
        print(f"  Aby przejrzec   : crashlog")
        print(f"  Tryb awaryjny   : python TerminalX.py --safe")
        recovery_enter(reason=f"fatal: {type(_fatal).__name__}")
        try:
            main()
        except Exception:
            sys.exit(1)